prompt
prompt Creating function MM_USF_PROG_COSECHA
prompt =====================================
prompt
create or replace function cantabria.mm_usf_prog_cosecha(
      ad_fec_ini in date,
      an_dias_proy in number
   ) return char is

   ls_cadena char(96);

   ls_mes     char(2) ;
   ld_proceso date ;
   ld_fec_fin date ;
 --ls_dias_por_mes char(50)  ;
   ls_dias_por_mes char(50)  ;
   ln_dias_en_mes  number(2) ;
   ln_numero_meses number(2) ;
   ls_porc_por_mes char(96)  ;
   ln_dias_acu     number(3) ;
   ln_pos          number(2) ;
   ln_porc         number(8,4) ;
   ls_porc         char(8) ;
   ls_contador     char(2) ;
begin
   -- 1) Obtener: Meses Mes_Dias Mes_Dias Mes_Dias ...
   --               99   99   99
   -- longitud Meses(2) + Mes=12(2) + Dias=12(2)    = 50
   -- determinando los dmas por mes
   ld_proceso := ad_fec_ini ;
   ld_fec_fin := ad_fec_ini + an_dias_proy - 1 ;
   ls_mes := to_char( ld_proceso, 'MM') ;
   ls_dias_por_mes := ls_mes ;
   ln_dias_en_mes  := 0 ;
   ln_numero_meses := 1 ;
   While ld_proceso <= ld_fec_fin
   Loop
     if to_char( ld_proceso, 'MM') <> ls_mes Then
        If ln_numero_meses = 1 Then
           ls_dias_por_mes :=
              Substr( to_char( ln_numero_meses, '00' ),2,2) ||
              ls_mes ||
              Substr( to_char( ln_dias_en_mes, '00'  ),2,2)  ;
        Else
           ls_dias_por_mes :=
              Substr( to_char( ln_numero_meses, '00' ),2,2) ||
              substr( ls_dias_por_mes, 3,
                 (ln_numero_meses - 1 ) * 4 ) ||
              ls_mes ||
              Substr( to_char( ln_dias_en_mes, '00'  ),2,2)  ;
        End if ;
        ln_dias_en_mes  := 0 ;
        ln_numero_meses := ln_numero_meses + 1 ;
        ls_mes := to_char( ld_proceso, 'MM') ;
     End If ;
     ln_dias_en_mes := ln_dias_en_mes + 1 ;
     ld_proceso := ld_proceso + 1 ;
   end loop;
   -- asegurandose de colocar el zltimo mes
   If ln_numero_meses = 1 Then
      ls_dias_por_mes :=
          Substr( to_char( ln_numero_meses, '00' ),2,2) ||
          ls_mes ||
          Substr( to_char( ln_dias_en_mes, '00'  ),2,2)  ;
   Else
      ls_dias_por_mes :=
          Substr( to_char( ln_numero_meses, '00' ),2,2) ||
          substr( ls_dias_por_mes, 3,
             (ln_numero_meses - 1 ) * 4 ) ||
          ls_mes ||
          Substr( to_char( ln_dias_en_mes, '00'  ),2,2)  ;
   End if ;

   -- 2) Obtener: Meses Mes_%          Mes_% Mes_% ...
   --               99  99_999.9999
   -- longitud Meses(2) + Mes=12(2) + Dias=12(8)    = 96

   -- Acumulando total de dmas
   ln_dias_acu :=0 ;
   For i in 1..to_number( substr( ls_dias_por_mes , 1, 2) )
   Loop
       ln_pos := ((i - 1) * 4 ) + 3 ;
       ln_dias_acu := ln_dias_acu +
          to_number( substr( ls_dias_por_mes, ln_pos+2, 2) ) ;
   End Loop ;
   -- Distribuyendo el total de dmas
   For i in 1..to_number( substr( ls_dias_por_mes , 1, 2) )
   Loop
       ln_pos := ((i - 1) * 4 ) + 3 ;
       ls_mes := substr( ls_dias_por_mes, ln_pos, 2) ;
       ln_dias_en_mes :=
          to_number( substr( ls_dias_por_mes, ln_pos+2, 2) ) ;
       if ln_dias_acu > 0 then
          ln_porc := ln_dias_en_mes * 100 / ln_dias_acu ;
       else
          ln_porc := 0 ;
       end if ;
       ls_porc := substr( to_char( ln_porc, '000.0000'), 2, 8) ;
       ls_contador := Substr( to_char( i, '00' ),2,2) ;
       If i = 1 Then
          ls_porc_por_mes :=
             ls_contador || ls_mes || ls_porc ;
       Else
          ls_porc_por_mes :=  ls_contador ||
          substr( ls_porc_por_mes, 3,
             (i - 1 ) * 10 ) ||
          ls_mes || ls_porc ;
       End if ;

   End Loop ;

   return(ls_porc_por_mes);
end mm_usf_prog_cosecha;
/

prompt
prompt Creating function SPLIT
prompt =======================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.split (p_list VARCHAR2, p_del VARCHAR2 := ',')
   RETURN split_tbl
   PIPELINED IS
   l_idx PLS_INTEGER;
   l_list VARCHAR2 (32767) := p_list;
   l_value VARCHAR2 (32767);
BEGIN
   LOOP
      l_idx := INSTR (l_list, p_del);

      IF l_idx > 0 THEN
         PIPE ROW (SUBSTR (l_list, 1, l_idx - 1));
         l_list := SUBSTR (l_list, l_idx + LENGTH (p_del));
      ELSE
         PIPE ROW (l_list);
         EXIT;
      END IF;
   END LOOP;

   RETURN;
END split;
/

prompt
prompt Creating function USF_AF_WARRANT_LIB_DET
prompt ========================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_AF_WARRANT_LIB_DET(
          AS_NRO_WARRANT IN WARRANT_DET.NRO_WARRANT%TYPE,
          AN_ITEM_PROD   IN WARRANT_DET.ITEM_PROD%TYPE,
          AS_OPCION IN CHAR)
  RETURN NUMBER IS
  LN_RESULT   NUMBER;
  LN_CANT_DET NUMBER;
  LN_CANT_LIB NUMBER;
BEGIN
  -- funcion para devolver la cantidad que falta por liberar del warrant

    SELECT  WD.CANTIDAD
      INTO  LN_CANT_DET
    FROM    WARRANT_DET   WD
    WHERE   WD.NRO_WARRANT = AS_NRO_WARRANT
      AND   WD.ITEM_PROD   = AN_ITEM_PROD;

    SELECT  SUM(WLD.CANTIDAD_LIBERADO)
      INTO  LN_CANT_LIB
    FROM    WARRANT_LIBERADO_DET  WLD
    WHERE   WLD.NRO_WARRANT = AS_NRO_WARRANT
      AND   WLD.ITEM_PROD   = AN_ITEM_PROD;

    CASE AS_OPCION
      WHEN '1' THEN
          LN_RESULT := LN_CANT_DET - LN_CANT_LIB;
      WHEN '2' THEN
          LN_RESULT := LN_CANT_LIB;
      ELSE
          LN_RESULT := 0.00;
     END CASE;

  RETURN(LN_RESULT);
END USF_AF_WARRANT_LIB_DET;
/

prompt
prompt Creating function USF_ALM_ARTICULO_SINIGV
prompt =========================================
prompt
create or replace function cantabria.USF_ALM_ARTICULO_SINIGV
(as_origen   in char,
 as_nro_vale in char) return integer Is

  Result integer;
  ls_grp_sinigv   articulo_grupo.grupo_art%Type;

Begin

ls_grp_sinigv := 'SINIGV'; -- Establecer como parametro

/*
Verifica si dentro del detalle del vale de salida hay un articulo que sea UREA
De acuerdo a lo establecido para generar las guias de remision en automatico
el articulo UREA, debe de generarse sin IGV, es por eso que se genera una unica
guia de remision para la UREA, otro punto es que solo se genera un movimiento de
articulo para un vale de salida cuando el articulo es UREA.
*/

  Select Count(*)
    Into Result
    From articulo_mov a
   Where a.cod_origen = as_origen
     And a.nro_vale = as_nro_vale
     And a.cod_art In (Select r.cod_art From rel_articulo_grupo r Where r.grupo_art = ls_grp_sinigv);

  return(Result);

end USF_ALM_ARTICULO_SINIGV;
/

prompt
prompt Creating function USF_ALM_ATENCION_VALES_ALMACEN
prompt ================================================
prompt
create or replace function cantabria.usf_alm_atencion_vales_almacen(
 as_tipo_mov_alm  in articulo_mov_tipo.tipo_mov%type,
 as_cod_origen    in origen.cod_origen%type,
 as_cod_art       in articulo.cod_art%type,
 ad_fecha_ini     in date,
 ad_fecha_fin     in date ) return number is

  ln_cantidad   number;
  ln_count      number;

BEGIN

SELECT count(*)
  INTO ln_count
  FROM vale_mov vm, articulo_mov am, almacen a
 WHERE ( vm.cod_origen=am.cod_origen and
         vm.nro_vale=am.nro_vale )
   AND ( vm.almacen=a.almacen )
   AND ( vm.tipo_mov = as_tipo_mov_alm and
         vm.flag_estado<>'0' and
         vm.cod_origen = as_cod_origen )
   AND ( vm.fec_registro between ad_fecha_ini and ad_fecha_fin )
   AND ( am.flag_estado<>'0' and
         am.cod_art=as_cod_art) ;

ln_cantidad := 0 ;

IF ln_count > 0 THEN
    SELECT sum(nvl(cant_procesada,0)) as cantidad
      INTO ln_cantidad
      FROM vale_mov vm, articulo_mov am, almacen a
     WHERE ( vm.cod_origen=am.cod_origen and
             vm.nro_vale=am.nro_vale )
       AND ( vm.almacen=a.almacen )
       AND ( vm.tipo_mov = as_tipo_mov_alm and
             vm.flag_estado<>'0' and
             vm.cod_origen = as_cod_origen )
       AND ( vm.fec_registro between ad_fecha_ini and ad_fecha_fin )
       AND ( am.flag_estado<>'0' and
             am.cod_art=as_cod_art) ;
END IF ;

return(ln_cantidad);

END usf_alm_atencion_vales_almacen ;
/

prompt
prompt Creating function USF_ALM_CANT_LIBRE_OT
prompt =======================================
prompt
create or replace function cantabria.USF_ALM_CANT_LIBRE_OT(
       asi_org_amp      in articulo_mov_proy.cod_origen%TYPE,
       ani_nro_amp      in articulo_mov_proy.nro_mov%TYPE
) return number is

  ln_Result          number;
  ln_cant_proyect    articulo_mov_proy.cant_proyect%TYPE;
  ln_cant_procesada  articulo_mov_proy.cant_procesada%TYPE;
  ln_cant_reservada  articulo_mov_proy.cant_proyect%TYPE;
  ln_pend_ingreso    articulo_mov_proy.cant_proyect%TYPE;
  ls_doc_oc          logparam.doc_oc%TYPE;

begin

  select doc_oc
    into ls_doc_oc
    from logparam
   where reckey = '1';

  -- Saldos
    Select NVL(cant_proyect, 0), NVL(cant_procesada, 0), NVL(cant_reservado, 0)
      into ln_cant_proyect, ln_cant_procesada, ln_cant_reservada
      from articulo_mov_proy
     where cod_origen = asi_org_amp
       and nro_mov    = ani_nro_amp;

  -- Cantidad Pendiente de Ingreso
  Select Sum(NVL(cant_proyect, 0) - NVL(cant_procesada,0))
    into ln_pend_ingreso
    from articulo_mov_proy amp
   where amp.org_amp_ref = asi_org_amp
     and amp.nro_amp_ref = ani_nro_amp
     and amp.tipo_doc = ls_doc_oc
     and amp.flag_estado in ('1', '3');

  IF (ln_cant_proyect IS NULL) OR
     (ln_cant_procesada IS NULL) OR
     (ln_cant_reservada IS NULL) OR
     (ln_pend_ingreso IS NULL) THEN

     ln_cant_proyect   := NVL(ln_cant_proyect,0) ;
     ln_cant_procesada := NVL(ln_cant_procesada,0) ;
     ln_cant_reservada := NVL(ln_cant_reservada,0) ;
     ln_pend_ingreso   := NVL(ln_pend_ingreso,0) ;
  END IF ;

  -- Total Libre x OT
  ln_Result := NVL(ln_cant_proyect, 0) - NVL(ln_cant_procesada, 0)
             - NVL(ln_cant_reservada, 0); -- - NVL(ln_pend_ingreso, 0);

  return(ln_Result);
end USF_ALM_CANT_LIBRE_OT;
/

prompt
prompt Creating function USF_ALM_CANT_LIBRE_OT_OLD
prompt ===========================================
prompt
create or replace function cantabria.USF_ALM_CANT_LIBRE_OT_OLD(
       asi_nro_amp      in articulo_mov_proy.cod_origen%TYPE,
       ani_nro_amp      in articulo_mov_proy.nro_mov%TYPE
) return number is

  ln_Result          number;
  ln_cant_comprada   articulo_mov_proy.cant_proyect%TYPE;
  ln_cant_ingresada  articulo_mov_proy.cant_procesada%TYPE;
  ln_salida_libre    articulo_mov_proy.cant_proyect%TYPE;
  ln_cant_proyect    articulo_mov_proy.cant_proyect%TYPE;
  ls_doc_oc          logparam.doc_oc%TYPE;
  ls_oper_cons_int   logparam.oper_cons_interno%TYPE;

begin

  select doc_oc, oper_cons_interno
    into ls_doc_oc, ls_oper_cons_int
    from logparam
   where reckey = '1';

  -- Cantidad Solicitada
  Select NVL(cant_proyect,0)
    into ln_cant_proyect
    from articulo_mov_proy
   where cod_origen = asi_nro_amp
     and nro_mov    = ani_nro_amp;

  -- Cantidad Comprada
  Select Sum(NVL(cant_proyect,0))
    into ln_cant_comprada
    from articulo_mov_proy amp
   where amp.org_amp_ref = asi_nro_amp
     and amp.nro_amp_ref = ani_nro_amp
     and amp.tipo_doc = ls_doc_oc
     and amp.flag_estado = '1';

  -- Cantidad Ingresada (de las OC cerradas)
  Select Sum(NVL(cant_procesada,0))
    into ln_cant_ingresada
    from articulo_mov_proy amp
   where amp.org_amp_ref = asi_nro_amp
     and amp.nro_amp_ref = ani_nro_amp
     and amp.tipo_doc = ls_doc_oc
     and amp.flag_estado = '2';

  -- Cantidad Salida x Saldo Libre
  Select Sum(NVL(cant_procesada,0))
    into ln_salida_libre
    from articulo_mov am,
         vale_mov     vm
   where am.nro_vale = vm.nro_vale
     and vm.tipo_mov = ls_oper_cons_int
     and am.origen_mov_proy = asi_nro_amp
     and am.nro_mov_proy    = ani_nro_amp
     and am.flag_estado <> '0'
     and vm.flag_Estado <> '0'
     and am.flag_saldo_libre = '1';

  -- Total Libre x OT
  ln_Result := NVL(ln_cant_proyect, 0) - NVL(ln_cant_comprada, 0)
            - NVL(ln_cant_ingresada, 0) - NVL(ln_salida_libre, 0);

  return(ln_Result);
end USF_ALM_CANT_LIBRE_OT_OLD;
/

prompt
prompt Creating function USF_ALM_CANT_PROC_AM
prompt ======================================
prompt
create or replace function cantabria.usf_alm_cant_proc_am(
       asi_origen       in articulo_mov.cod_origen%TYPE,
       ani_nro_mov      in articulo_mov.nro_mov%TYPE
) return number is
  ln_Result             number;
  ln_cant_procesada     articulo_mov.cant_procesada%TYPE;
  ln_cant_devuelta      articulo_mov.cant_procesada%TYPE;
  ln_count              number;

begin

  select count(*)
    into ln_count
    from articulo_mov
   where cod_origen = asi_origen
     and nro_mov    = ani_nro_mov
     and flag_estado <> '0';

  if ln_count > 0 then
      -- La cantidad procesada de articulo_mov
      select cant_procesada
        into ln_cant_procesada
        from articulo_mov
       where cod_origen = asi_origen
         and nro_mov    = ani_nro_mov
         and flag_estado <> '0';

      if ln_Cant_procesada is null then ln_Cant_procesada := 0; end if;
  else
      ln_cant_procesada := 0;
  end if;

  select count(*)
    into ln_count
    from articulo_mov
   where cod_origen = asi_origen
     and nro_mov_dev = to_char(ani_nro_mov)
     and flag_estado <> '0';

  if ln_count > 0 then
      -- La cantidad devuelta de articulo_mov
      select SUM(NVL(cant_procesada,0))
        into ln_cant_devuelta
        from articulo_mov
       where cod_origen = asi_origen
         and nro_mov_dev = to_char(ani_nro_mov)
         and flag_estado <> '0';

      if ln_Cant_devuelta is null then ln_Cant_devuelta := 0; end if;
  else
      ln_cant_devuelta := 0;
  end if;

  ln_Result := ln_cant_procesada - ln_cant_devuelta;

  return(ln_Result);
end usf_alm_cant_proc_am;
/

prompt
prompt Creating function USF_ALM_CANT_PROCESADA
prompt ========================================
prompt
create or replace function cantabria.USF_ALM_CANT_PROCESADA(
       asi_origen_mov_proy   in articulo_mov_proy.cod_origen%TYPE,
       ani_nro_mov_proy      in articulo_mov_proy.nro_mov%TYPE
) return number is
  ln_Result     number;
  ln_cantidad1  number;
  ln_cantidad2  number;
begin

  select sum(NVL(am.cant_procesada,0))
    into ln_cantidad1
   from articulo_mov       am,
        vale_mov           vm,
        articulo_mov_tipo  amt
   where am.nro_vale = vm.nro_vale
     and amt.tipo_mov = vm.tipo_mov
     and amt.tipo_mov_dev is null
     and am.flag_estado <> '0'
     and vm.flag_estado <> '0'
     and am.origen_mov_proy = asi_origen_mov_proy
     and am.nro_mov_proy    = ani_nro_mov_proy;

  select sum(NVL(am.cant_procesada,0))
    into ln_cantidad2
   from articulo_mov       am,
        vale_mov           vm,
        articulo_mov_tipo  amt
   where am.nro_vale = vm.nro_vale
     and amt.tipo_mov = vm.tipo_mov
     and amt.tipo_mov_dev is not null
     and am.flag_estado <> '0'
     and vm.flag_estado <> '0'
     and am.origen_mov_proy = asi_origen_mov_proy
     and am.nro_mov_proy    = ani_nro_mov_proy;

  ln_result := NVL(ln_cantidad1,0) - NVL(ln_cantidad2,0);

  return(ln_Result);
end USF_ALM_CANT_PROCESADA;
/

