prompt Creating function USF_ALM_CANT_PROG_PEND
prompt ========================================
prompt
create or replace function cantabria.USF_ALM_CANT_PROG_PEND(
       asi_org_amp      in articulo_mov_proy.cod_origen%TYPE,
       ani_nro_amp      in articulo_mov_proy.nro_mov%TYPE
) return number is

  ln_Result          number;

begin

  -- Saldos
    Select sum(NVL(cant_proyect, 0) - NVL(cant_procesada, 0))
      into ln_Result
      from prog_compras_det pcd
     where pcd.org_amp_ot_ref = asi_org_amp
       and pcd.nro_amp_ot_ref = ani_nro_amp
       and pcd.flag_estado = '1';

  return( NVL(ln_Result,0) );
end USF_ALM_CANT_PROG_PEND;
