prompt Creating function USF_ALM_CIERRE_PERIODO
prompt ========================================
prompt
create or replace function cantabria.usf_alm_cierre_periodo(
       adi_fecha  in date
) return number is
  Result        number;
  ll_count      number;
begin
  select count(*)
    into ll_count
    from cntbl_cierre
   where ano = to_number(to_char(adi_fecha, 'yyyy'))
     and mes = to_number(to_char(adi_fecha, 'mm'));

  if ll_count = 0 then
     Result := 1;
  else
    Select NVL( flag_gen_asnt_autom,0)
  	  into Result
      from cntbl_cierre
     where ano = to_number(to_char(adi_fecha, 'yyyy'))
       and mes = to_number(to_char(adi_fecha, 'mm'));
  end if;

  return(Result);
end usf_alm_cierre_periodo;
/

prompt
prompt Creating function USF_ALM_CNTRL_LOTE
prompt ====================================
prompt
create or replace function cantabria.usf_alm_cntrl_lote(
       asi_cntrl_lote_alm  in almacen.flag_cntrl_lote%TYPE,
       asi_cntrl_lote_art  in articulo.flag_cntrl_lote%TYPE
) return integer is
  Result integer;
begin
  if asi_cntrl_lote_art = '5' then
     Result := 1;
  elsif asi_cntrl_lote_art = '0' then
     Result := 0;
  elsif asi_cntrl_lote_art = '1' and asi_cntrl_lote_alm = '1' then
     Result := 1;
  elsif asi_cntrl_lote_art = '2' and asi_cntrl_lote_alm = '1' then
     Result := 1;
  elsif asi_cntrl_lote_art = '2' and asi_cntrl_lote_alm = '2' then
     Result := 1;
  else
     Result := 0;
  end if;
  return(Result);
end usf_alm_cntrl_lote;
/

