prompt
create or replace function cantabria.usf_alm_fec_ult_ing(
       asi_cod_art in articulo_almacen.cod_art%TYPE,
       asi_almacen in articulo_almacen.almacen%TYPE
) return date is

  ld_Result date;

  begin


  select max(vm.fec_registro)
  into ld_Result
  from articulo_mov am,
       vale_mov     vm,
       articulo_mov_tipo amt
  where vm.nro_vale = am.nro_vale
    and vm.tipo_mov = amt.tipo_mov
    and NVL(amt.factor_sldo_total, 0) = 1 -- Solo ingresos
    and vm.flag_estado <> '0'
