prompt
prompt Creating function USF_ALM_GENERA_NUM_GUIA_REM
prompt =============================================
prompt
create or replace function cantabria.USF_ALM_GENERA_NUM_GUIA_REM
(as_doc_tipo In doc_tipo.tipo_doc%Type,
 an_serie    In num_doc_tipo.nro_serie%Type) return guia.nro_guia%Type Is

 Result guia.nro_guia%Type;

 ln_contador Number;
 ln_numero   Number(9);
 ls_serie    Char(3);
 ls_numero   Char(6);

Begin

  Select nvl(Count(*),0)
    Into ln_contador
    From num_doc_tipo
   Where tipo_doc  = as_doc_tipo
	And nro_serie = an_serie;

  If ln_contador = 0 Then
     raise_application_error(-20000,'Error, Defina la numeracion de Numero de Serie y Tipo de Documento');
     Rollback;
  End If;

  Select nvl(ultimo_numero,0)
    Into ln_numero
    From num_doc_tipo
   Where tipo_doc  = as_doc_tipo
	And nro_serie = an_serie;

  ls_serie  := lpad(to_char(an_serie) ,3,'0');
  ls_numero := lpad(to_char(ln_numero),6,'0');
  Result   := ls_serie||'-'||ls_numero;

  Update num_doc_tipo
	Set ultimo_numero = ultimo_numero + 1
   Where tipo_doc  = as_doc_tipo
	And nro_serie = an_serie;

  return(Result);

end USF_ALM_GENERA_NUM_GUIA_REM;
/

prompt
prompt Creating function USF_ALM_GENERA_NUM_GUIA_REM_TT
prompt ================================================
prompt
create or replace function cantabria.USF_ALM_GENERA_NUM_GUIA_REM_TT
(as_doc_tipo In doc_tipo.tipo_doc%Type,
 an_serie    In num_doc_tipo.nro_serie%Type) return guia.nro_guia%Type Is

 Result guia.nro_guia%Type;

 ln_contador Number;
 ln_numero   Number(9);
 ls_serie    Char(3);
 ls_numero   Char(6);

Begin

  Select nvl(numerador,0)
    Into ln_numero
    From TT_NUMERADOR;

  ls_serie  := lpad(to_char(an_serie) ,3,'0');
  ls_numero := lpad(to_char(ln_numero),6,'0');
  Result   := ls_serie||'-'||ls_numero;

  Update TT_NUMERADOR
	Set numerador = numerador + 1;

  return(Result);

end USF_ALM_GENERA_NUM_GUIA_REM_TT;
/

