prompt
prompt Creating function USF_ALM_MATRIZ_CONTABLE
prompt =========================================
prompt
create or replace function cantabria.USF_ALM_MATRIZ_CONTABLE(
   asi_tipo_mov    articulo_mov_tipo.tipo_mov%type,
   asi_cencos      centros_costo.cencos%type,
   asi_cnta_prsp   presupuesto_cuenta.cnta_prsp%type,
   asi_sub_categ   articulo.sub_cat_art%TYPE
) return string is

  ls_matriz              articulo_mov.matriz%type ;
  ls_grp_cntbl           centros_costo.grp_cntbl%type ;
  ln_count               number ;
  ls_flag_matriz_contab  logparam.flag_matriz_contab%TYPE;
  ln_factor_presup       articulo_mov_tipo.factor_presup%TYPE;
  ls_flag_contabiliza    articulo_mov_tipo.flag_contabiliza%TYPE;

begin
  --Parametros de Logparam
  select flag_matriz_contab
    into ls_flag_matriz_contab
    from logparam
   where reckey = '1';

  -- Capturando dato de factor_sldo_total
  select count(*)
    into ln_count
    from articulo_mov_tipo a
   where a.tipo_mov = asi_tipo_mov;

  if ln_count = 0 then return null; end if;

  select NVL(a.factor_presup,0), NVL(a.flag_contabiliza, '0')
    into ln_factor_presup, ls_flag_contabiliza
    from articulo_mov_tipo a
   where a.tipo_mov = asi_tipo_mov;

  if ls_flag_contabiliza = '0' then return null; end if;

  IF ls_flag_matriz_contab = 'P' then
      -- Calculando matriz contable
      if ln_factor_presup = 0 then
          -- No afecta presupuesto
          select min(t.matriz)
            into ls_matriz
            from tipo_mov_matriz t
           where t.tipo_mov = asi_tipo_mov ;

      else
          -- Afecta presupuesto
          if asi_cencos is null then return null; end if;

          select c.grp_cntbl
            into ls_grp_cntbl
            from centros_costo c
           where c.cencos = asi_cencos ;

          -- Encontrando matriz contable
          select count(*)
            into ln_count
            from tipo_mov_matriz t
          where t.tipo_mov  = asi_tipo_mov
            and t.grp_cntbl = ls_grp_cntbl
            and t.cnta_prsp = asi_cnta_prsp ;

          IF ln_count > 0 then
             select min(t.matriz)
               into ls_matriz
               from tipo_mov_matriz t
              where t.tipo_mov = asi_tipo_mov
                and t.grp_cntbl = ls_grp_cntbl
                and t.cnta_prsp = asi_cnta_prsp ;
          else
             return null;
          END IF ;
      END IF ;
  ELSIF ls_flag_matriz_contab = 'S' then
      -- Calculando matriz contable
      if ln_factor_presup = 0 then
          -- No afecta presupuesto
          select count(*)
            into ln_count
          from tipo_mov_matriz_subcat t
          where t.tipo_mov    = asi_tipo_mov
            and t.cod_sub_cat = asi_sub_categ;

          if ln_Count = 0 then return null; end if;

          select min(t.matriz)
            into ls_matriz
          from tipo_mov_matriz_subcat t
          where t.tipo_mov    = asi_tipo_mov
            and t.cod_sub_cat = asi_sub_categ;

      else
          -- Afecta presupuesto
          if asi_cencos is null then return null; end if;

          select c.grp_cntbl
            into ls_grp_cntbl
            from centros_costo c
           where c.cencos = asi_cencos ;

          -- Encontrando matriz contable
          select count(*)
            into ln_count
            from tipo_mov_matriz_subcat t
          where t.tipo_mov    = asi_tipo_mov
            and t.grp_cntbl   = ls_grp_cntbl
            and t.cod_sub_cat = asi_sub_Categ;

          IF ln_count > 0 then
             select min(t.matriz)
               into ls_matriz
               from tipo_mov_matriz_subcat t
              where t.tipo_mov    = asi_tipo_mov
                and t.grp_cntbl   = ls_grp_cntbl
                and t.cod_sub_cat = asi_sub_Categ;
          else
             return null;
          END IF ;
      END IF ;
  ELSE
      return null;
  END IF;

  return(ls_matriz);
end USF_ALM_MATRIZ_CONTABLE;
/

prompt
prompt Creating function USF_ALM_MOVALM_OC_OT
prompt ======================================
prompt
create or replace function cantabria.usf_alm_movalm_oc_ot(
       ani_nro_mov_proy    in articulo_mov_proy.nro_mov%TYPE,
       asi_org_mov_proy    in articulo_mov_proy.cod_origen%TYPE
) return varchar2 is

  ls_Result       varchar2(20);
  ls_doc_oc       logparam.doc_oc%TYPE;
  ls_doc_ot       logparam.doc_ot%TYPE;
  ls_doc_prog     logparam.tipo_doc_prog_cmp%TYPE;
  ls_doc_ref      articulo_mov_proy.tipo_ref%TYPE;
  ls_nro_ref      articulo_mov_proy.referencia%TYPE;
  ls_nro_doc      articulo_mov_proy.nro_doc%TYPE;
  ls_org_amp_ot   articulo_mov_proy.cod_origen%TYPE;
  ln_nro_amp_ot   articulo_mov_proy.nro_mov%TYPE;

begin

    -- Si alguno de los parametros de Mov_proy es nulo no retorno nada
    if asi_org_mov_proy is null or NVL(asi_org_mov_proy, '') = '' then
       return '';
    end if;

    if ani_nro_mov_proy is null then
       return '';
    end if;

    -- Obtengo los parametros para doc_oc y doc_prog
    select doc_oc, tipo_doc_prog_cmp
      into ls_doc_oc, ls_doc_prog
      from logparam
     where reckey = '1';

   -- Obtengo los datos de Articulo Mov Proy
   select NVL(amp.tipo_ref, ''), NVL(amp.referencia,''), amp.nro_doc,
          amp.Org_Amp_Ref, amp.nro_amp_ref
     into ls_doc_ref, ls_nro_ref, ls_nro_doc, ls_org_amp_ot, ln_nro_amp_ot
     from articulo_mov_proy amp
    where amp.nro_mov    = ani_nro_mov_proy
      and amp.cod_origen = asi_org_mov_proy;

   IF ls_doc_ref = ls_doc_prog THEN
      IF ln_nro_amp_ot IS NULL OR ls_org_amp_ot IS NULL THEN
         -- Si tiene referencia a un programa de compras y este no tiene
         -- referencia a una OT, entonces simplemente pongo esa referencia
         ls_Result := rtrim(ls_doc_ref) || ' - ' || rtrim(ls_nro_ref) ;
      ELSE

         SELECT amp.nro_doc
           INTO ls_nro_ref
           FROM articulo_mov_proy amp
          WHERE amp.cod_origen = ls_org_amp_ot
            AND amp.nro_mov    = ln_nro_amp_ot;

         ls_Result := rtrim(ls_doc_ot) || ' - ' || rtrim(ls_nro_ref) ;

      END IF;
   ELSE
      ls_Result := rtrim(ls_doc_ref) || ' - ' || rtrim(ls_nro_ref) ;
   END IF;

   Return(ls_Result);
end usf_alm_movalm_oc_ot;
/

