prompt
prompt Creating function USF_ALM_NUM_OTR
prompt =================================
prompt
create or replace function cantabria.USF_ALM_NUM_OTR
(
       asi_origen origen.cod_origen%type

) return varchar2 is

  lc_ult_nro_ot     orden_traslado.nro_otr%TYPE;
  ln_ult_nro        number(8) ;
  ll_count          number;

begin

  select count(*)
    into ll_count
  from num_ord_traslado
  where origen = asi_origen;

  if ll_count = 0 then
     insert into num_ord_traslado(origen, ult_nro)
     values (asi_origen, 2);

     ln_ult_nro := 1;
  else
     select ult_nro
       into ln_ult_nro
     from num_ord_traslado
     where origen = asi_origen
       for update;

     update num_ord_traslado
        set ult_nro = ult_nro + 1
      where origen = asi_origen;

  end if;

  --se concatena con origen
  lc_ult_nro_ot := trim(asi_origen) || trim(to_char(ln_ult_nro,'00000000')) ;

  return trim(lc_ult_nro_ot);
end USF_ALM_NUM_OTR;
/

prompt
prompt Creating function USF_FL_CONV_MON
prompt =================================
prompt
create or replace function cantabria.usf_fl_conv_mon(
      	ani_importe in number,
        asi_mon1		in varchar2,
        asi_mon2		in varchar2,
        adi_fecha		in date
) return number is

  Result 			     number;
  ln_cambio 	     number;
  ln_count		     number;
  ln_cmp_dol_prom  calendario.cmp_dol_prom%TYPE;
  ln_vta_dol_prom  calendario.vta_dol_prom%TYPE;
  ls_flag_tc_vta   cntblparam.flag_tc_vta%TYPE;
  ln_vta_euro      calendario.vta_eur_bnc%TYPE;
  ln_cmp_euro      calendario.cmp_eur_bnc%TYPE;

begin
  -- Esta funcion convierte el importe ingresado con el tipo de moneda
  -- asi_mon1 a tipo de moneda asi_mon2
  Result      := 0;

  if asi_mon1 = asi_mon2 then
  	Result := ani_importe;
    return Result;
  end if;

  -- Obtengo el flag_tc_vta

  select NVL(flag_tc_vta, '0')
    into ls_flag_tc_vta
    from cntblparam
   where reckey = '1';

 	select count(*), MAX(c.cmp_dol_prom), MAX(c.vta_dol_prom), MAX(c.vta_eur_bnc), MAX(c.cmp_eur_bnc)
   	into ln_count, ln_cmp_dol_prom, ln_vta_dol_prom, ln_vta_euro, ln_cmp_euro
  from calendario c
  where fecha = trunc(adi_fecha);

  if ln_count = 0 then
     select l.ult_tipo_cam
       into ln_cambio
       from logparam l
      where reckey = '1';

     if ln_cambio = 0 then
     	 ln_cambio := 0;
        RAISE_APPLICATION_ERROR(-20000, 'No ha definido el tipo de cambio para el dia'
                                         || to_char(adi_fecha, 'dd/mm/yyyy') );
        return 0;
     end if;
  end if;

  if asi_mon1 = pkg_logistica.is_dolares then
  	if asi_mon2 = pkg_logistica.is_soles then

      if ln_count <> 0 then
         if ls_flag_tc_vta = '0' then
            ln_cambio := ln_cmp_dol_prom;
         else
            ln_cambio := ln_vta_dol_prom;
         end if;

      end if;

      if ln_cambio <> 0 then
      	Result := ani_importe * ln_cambio;
      ELSE
      	Result := 0;
      end if;

    end if;
  elsif asi_mon1 = pkg_logistica.is_soles then
  	if asi_mon2 = pkg_logistica.is_dolares then

      if ln_count <> 0 then
      	 ln_cambio := ln_vta_dol_prom;
      end if;

      if ln_cambio <> 0 then
      	Result := ani_importe / ln_cambio;
      else
      	Result := 0;
      end if;

    end if;
  elsif asi_mon1 = pkg_logistica.is_euros then
    ln_cambio := ani_importe * ln_vta_euro;
    
    if asi_mon2 = pkg_logistica.is_dolares then
       Result := ln_cambio / ln_vta_dol_prom;
    else
       Result := ln_cambio ;
    end if;
     
  end if;
  return(Result);

end usf_fl_conv_mon;
/

prompt
prompt Creating function USF_ALM_PRECIO_OC_FAP
prompt =======================================
prompt
create or replace function cantabria.usf_alm_precio_oc_fap(
       asi_org_am          in articulo_mov.cod_origen%TYPE,
       ani_nro_am          in articulo_mov.nro_mov%TYPE,
       asi_moneda          in moneda.cod_moneda%TYPE
       ) return number is
  ln_Result            number(18,8);

  ln_count             number;
  ln_importe           number;
  ln_Cant_facturada    articulo_mov_proy.cant_facturada%TYPE;
  ln_cant_procesada    articulo_mov_proy.cant_procesada%TYPE;
  ld_fec_movimiento    vale_mov.fec_registro%TYPE;
  ln_imp_flete         number;


begin
  -- Datos del movimiento de almacen
  select vm.fec_registro, amp.cant_procesada
    into ld_fec_movimiento, ln_cant_procesada
    from vale_mov           vm,
         articulo_mov       am,
         articulo_mov_proy  amp
   where vm.nro_vale    = am.nro_vale
     and amp.cod_origen = am.origen_mov_proy
     and amp.nro_mov    = am.nro_mov_proy
     and am.cod_origen  = asi_org_am
     and am.nro_mov     = ani_nro_am;

  -- Primero verifico si el nro_am tiene movimiento de factura
  select count(*)
    into ln_count
    from cntas_pagar_det cpd
   where cpd.org_am      = asi_org_am
     and cpd.nro_am      = ani_nro_am;

  if ln_count > 0 then
     -- Obtengo el importe total en soles de toda(s) la(s) factura(s) amarradas con la NI
     select NVL(sum(case
                      when cp.cod_moneda = asi_moneda then
                        cpd.importe * dt.factor * -1
                      when asi_moneda = PKG_LOGISTICA.of_soles(null) then
                        cpd.importe * cp.tasa_cambio * dt.factor * -1
                      when asi_moneda =  PKG_LOGISTICA.of_dolares(null) then
                        cpd.importe / cp.tasa_cambio * dt.factor * -1
                     end
                ),0), nvl(sum(case
                                 when trim(cpd.tipo_doc) not in ('NCP', 'NDP') then cpd.cantidad
                                 else 0
                               end ),0)
       into ln_importe, ln_Cant_facturada
       from cntas_pagar_det cpd,
            cntas_pagar     cp,
            doc_tipo        dt
      where cp.cod_relacion = cpd.cod_relacion
        and cp.tipo_doc     = cpd.tipo_doc
        and cp.nro_doc      = cpd.nro_doc
        and cp.tipo_doc     = dt.tipo_doc
        and ((cp.tipo_doc = 'NCP' and cp.motivo <> 'NCP02') or cp.tipo_doc <> 'NCP')
        and cpd.org_am      = asi_org_am
        and cpd.nro_am      = ani_nro_am;

     -- El precio viene a ser el resultado de dividir el importe por la cantidad ingresada
     if ln_Cant_facturada > 0 then
        ln_Result := ln_importe / ln_Cant_facturada;
     else
        ln_Result := 0;
     end if;
  else
     -- En caso que no hubiera una factura amarrada a la ni lo busco entonces por el item de la factura
     select count(*)
       into ln_count
       from cntas_pagar_det   cpd,
            articulo_mov_proy amp,
            articulo_mov      am
      where cpd.org_amp_ref  = amp.cod_origen
        and cpd.nro_amp_ref  = amp.nro_mov
        and amp.cod_origen   = am.origen_mov_proy
        and amp.nro_mov      = am.nro_mov_proy
        and am.cod_origen    = asi_org_am
        and am.nro_mov       = ani_nro_am;

     if ln_count > 0 then
        -- Sumo el importe de todas las facturas amarradas al item de la OC
        select NVL(sum(case
                      when cp.cod_moneda = asi_moneda then
                        cpd.importe * dt.factor * -1
                      when asi_moneda = PKG_LOGISTICA.of_soles(null) then
                        cpd.importe * cp.tasa_cambio * dt.factor * -1
                      when asi_moneda = PKG_LOGISTICA.of_dolares(null) then
                        cpd.importe / cp.tasa_cambio * dt.factor * -1
                     end
                ),0), nvl(sum(cpd.cantidad), 0)
          into ln_importe, ln_Cant_facturada
          from cntas_pagar_det   cpd,
               cntas_pagar       cp,
               articulo_mov_proy amp,
               articulo_mov      am,
               doc_tipo          dt
         where cp.cod_relacion = cpd.cod_relacion
           and cp.tipo_doc     = cpd.tipo_doc
           and cp.nro_doc      = cpd.nro_doc
           and cpd.org_amp_ref  = amp.cod_origen
           and cpd.nro_amp_ref  = amp.nro_mov
           and amp.cod_origen   = am.origen_mov_proy
           and amp.nro_mov      = am.nro_mov_proy
           and cp.tipo_doc      = dt.tipo_doc
           and ((cp.tipo_doc = 'NCP' and cp.motivo <> 'NCP02') or cp.tipo_doc <> 'NCP')
           and am.cod_origen    = asi_org_am
           and am.nro_mov       = ani_nro_am;

        if ln_Cant_facturada = 0 then
           RAISE_APPLICATION_ERROR(-20000, 'Cantidad Facturada de Item es cero, Item: ' || asi_org_am || ' ' || to_char(ani_nro_am));
        end if;
        ln_Result := ln_importe / ln_Cant_facturada;

     else
        -- En caso que no hubiera una factura amarrada a la ni lo busco entonces por el item de la factura
        select count(*)
          into ln_count
          from articulo_mov_proy amp,
               articulo_mov      am
         where amp.cod_origen   = am.origen_mov_proy
           and amp.nro_mov      = am.nro_mov_proy
           and am.cod_origen    = asi_org_am
           and am.nro_mov       = ani_nro_am;

        if ln_count = 0 then return -1; end if;

        select usf_fl_conv_mon(amp.precio_unit, oc.cod_moneda, asi_moneda, ld_fec_movimiento)
          into ln_REsult
          from orden_compra      oc,
               articulo_mov_proy amp,
               articulo_mov      am
         where oc.nro_oc        = amp.nro_doc
           and amp.tipo_doc     = (select doc_oc from logparam where reckey = '1')
           and amp.cod_origen   = am.origen_mov_proy
           and amp.nro_mov      = am.nro_mov_proy
           and am.cod_origen    = asi_org_am
           and am.nro_mov       = ani_nro_am;


     end if;
  end if;


  -- Ahora busco si hay costo por Servicios asociados a la compra
    select nvl(sum(
                 case
                    when decode(cp.cod_moneda,null, os.cod_moneda, cp.cod_moneda) = asi_moneda then
                      a.importe
                    when decode(cp.cod_moneda,null, os.cod_moneda, cp.cod_moneda) = PKG_LOGISTICA.of_soles(null) then
                      a.importe / decode(cp.tasa_cambio, null, usf_fl_conv_mon(1, PKG_LOGISTICA.of_soles(null), PKG_LOGISTICA.of_dolares(null), osd.fec_proyect), cp.tasa_cambio)
                    when decode(cp.cod_moneda,null, os.cod_moneda, cp.cod_moneda) = PKG_LOGISTICA.of_dolares(null) then
                      a.importe * decode(cp.tasa_cambio, null, usf_fl_conv_mon(1, PKG_LOGISTICA.of_dolares(null), PKG_LOGISTICA.of_soles(null), osd.fec_proyect), cp.tasa_cambio)
                 end ),0)
      into ln_imp_flete

  from oc_det_os_det       a,
       orden_servicio_det  osd,
       orden_servicio      os,
       cntas_pagar_det     cpd,
       cntas_pagar         cp,
       articulo_mov_proy   amp,
       articulo_mov        am
  where a.org_amp          = amp.cod_origen
    and a.nro_amp          = amp.nro_mov
    and amp.cod_origen     = am.origen_mov_proy
    and amp.nro_mov        = am.nro_mov_proy
    and a.org_os           = osd.cod_origen
    and a.nro_os           = osd.nro_os
    and a.item_os          = osd.nro_item
    and os.nro_os          = osd.nro_os
    and osd.cod_origen     = cpd.org_os (+)
    and osd.nro_os         = cpd.nro_os (+)
    and osd.nro_item       = cpd.item_os (+)
    and cpd.cod_relacion   = cp.cod_relacion (+)
    and cpd.tipo_doc       = cp.tipo_doc (+)
    and cpd.nro_doc        = cp.nro_doc (+)
    and am.cod_origen      = asi_org_am
    and am.nro_mov         = ani_nro_am;

  if ln_imp_flete > 0 and ln_cant_procesada > 0 then
     ln_Result := ln_Result + ln_imp_flete / ln_cant_procesada;
  end if;

  return(ln_Result);
end usf_alm_precio_oc_fap;
/

prompt
prompt Creating function USF_ALM_PRECIO_PROM_ART
prompt =========================================
prompt
create or replace function cantabria.usf_alm_precio_prom_art(
       asi_cod_Art      in articulo.cod_art%TYPE
) return number is

  Result number;

  -- Precios Promedios
  ln_saldo                 number(15,4);
  ln_precio_unit           articulo_mov.precio_unit%TYPE;

  --  Lectura del movimiento de ingresos y salidas
  CURSOR c_movimiento is
  SELECT vm.tipo_mov,
         vm.almacen,
         NVL(am.cant_procesada,0) as cant_procesada,
         NVL(am.precio_unit,0) as precio_unit,
         NVL(am.decuento,0) as descuento,
         NVL(am.impuesto,0) as impuesto,
         am.cod_moneda,
         NVL(amt.flag_ajuste_valorizacion, '0') as flag_ajuste_valorizacion,
         amt.factor_sldo_total,
         am.cod_origen,
         am.nro_mov,
         vm.fec_registro
    FROM vale_mov          vm,
         articulo_mov      am,
         almacen           a,
         articulo_mov_tipo amt
   WHERE vm.cod_origen = am.cod_origen
     and vm.nro_vale   = am.nro_vale
     and vm.almacen    = a.almacen
     and vm.flag_estado <> '0'
     and vm.tipo_mov    = amt.tipo_mov
     and am.cod_art     = asi_cod_art
     AND am.flag_estado <> '0'
     and amt.factor_sldo_total <> 0
     and am.cod_moneda = (select cod_soles from logparam where reckey = '1')
  ORDER BY vm.fec_registro, vm.tipo_mov ;

  BEGIN

  -- Parametros de Logistica
  ln_saldo            := 0;
  Result              := 0;

  FOR lc_reg IN c_movimiento LOOP

      IF substr(lc_Reg.tipo_mov, 1,1) = 'I' and lc_reg.flag_ajuste_valorizacion = '0' THEN

         if ln_saldo + lc_reg.cant_procesada <> 0 then
            if lc_reg.precio_unit <> 0 then
               ln_precio_unit := lc_reg.precio_unit;
            else
               ln_precio_unit := Result;
            end if;

            if ln_saldo + lc_reg.cant_procesada > 0 then
               Result := round((ln_saldo * Result + ln_precio_unit * lc_reg.cant_procesada) /(ln_saldo + lc_reg.cant_procesada),4);
            end if;
         end if;
         ln_saldo:= ln_saldo + lc_reg.cant_procesada ;

      ELSIF lc_reg.flag_ajuste_valorizacion = '1' THEN
         if ln_saldo > 0 then
             result := Round((Result*ln_saldo
                                + NVL(lc_reg.precio_unit,0) * lc_reg.factor_sldo_total)/ln_Saldo,4);
         end if;
      ELSIF substr(lc_reg.tipo_mov,1,1) = 'S' then
         ln_saldo := round(ln_saldo - lc_reg.cant_procesada,4);

      END IF ;
  END LOOP ;

  return(Result);

end usf_alm_precio_prom_art;
/

prompt
prompt Creating function USF_ALM_REFERENCIAS_GR
prompt ========================================
prompt
create or replace function cantabria.USF_ALM_REFERENCIAS_GR
(ac_nro_ref in orden_venta.nro_ov%type )
return  varchar2 is
Result varchar2 (1000);

lc_doc_ov doc_tipo.tipo_doc%type ;

Cursor c_referencias is
select gv.origen_guia,gv.nro_guia
 from vale_mov vm ,guia_vale gv
 where (vm.cod_origen   = gv.origen_vale ) and
       (vm.nro_vale     =  gv.nro_vale   ) and
       (vm.flag_estado  <> '0'           ) and
       (vm.tipo_refer = lc_doc_ov        ) and
       (vm.nro_refer  = ac_nro_ref       )
group by gv.origen_guia,gv.nro_guia      ;



begin


select l.doc_ov into lc_doc_ov from logparam l where l.reckey = '1' ;

For rc_ref in c_referencias Loop
    result := result||' '||rtrim(ltrim(rc_ref.origen_guia))||'-'||rtrim(ltrim(rc_ref.nro_guia)) ;
End Loop ;


return(Result);

end USF_ALM_REFERENCIAS_GR;
/

