prompt
prompt Creating function USF_ALM_SALDO_ANTERIOR_CONSIG
prompt ===============================================
prompt
create or replace function cantabria.USF_ALM_SALDO_ANTERIOR_CONSIG(
        adi_fecha   in date,
        asi_almacen in almacen.almacen%TYPE,
        asi_cod_art in articulo.cod_art%TYPE,
        asi_val_ret in char,
        asi_moneda  in moneda.cod_moneda%TYPE
) return number is

  ln_sldo_total   articulo_almacen.sldo_total%TYPE;
  ln_ret          number;   -- Valor de retorno
  ln_pus          number;   -- Precio Unitario en Soles
  ln_cps          articulo_almacen.costo_prom_sol%TYPE;   -- Precio Promedio Dolares

/*
   funcion que retorna un dato referente al saldo de un mes.
   Parametros:  mes anterior
                cod. articulo
                valor retorno ( S = Saldo
                                L = Soles
                                2UND = Saldo Total en 2Und
*/

  Cursor c1 is
    Select ac.fecha_registro,
           ac.tipo_mov,
           ac.cod_art,
           ac.cantidad as cant_procesada,
           usf_fl_conv_mon(ac.precio_unitario, ac.cod_moneda, asi_moneda, ac.fecha_registro) as precio_unit,
           ac.cod_moneda ,
           NVL(amt.flag_ajuste_valorizacion, '0') as flag_ajuste_valorizacion,
           NVL(amt.factor_sldo_consig, 0) as factor_sldo_consig
      from articulo_consignacion ac,
           articulo_mov_tipo amt
     Where amt.tipo_mov  = ac.tipo_mov
       and ac.flag_estado <> '0'
       and ac.cod_art = asi_cod_art
       and ac.almacen = asi_almacen
       and trunc( ac.fecha_registro) <= trunc(adi_fecha)
    order by ac.fecha_registro;


begin
  -- encuentra el saldo de acuerdo los movimientos
  ln_sldo_total := 0;
  ln_cps        := 0;

  for rc1 in c1 loop
      if rc1.factor_sldo_consig = 1 and rc1.flag_ajuste_valorizacion = '0' then
         -- Ingresos, Costo promedio
         ln_pus := rc1.precio_unit;

         -- Calculo del costo promedio
         if (ln_sldo_total + NVL(rc1.cant_procesada,0)) <> 0 then
              ln_cps := ((abs(ln_sldo_total) * ln_cps) + (NVL(rc1.cant_procesada,0) * ln_pus))/
                        (abs(ln_sldo_total) + NVL(rc1.cant_procesada,0));
         end if;
         ln_sldo_total := ln_sldo_total + NVL(rc1.cant_procesada,0);

      elsif rc1.flag_ajuste_valorizacion = '1' then

         if ln_sldo_total <> 0 then
            ln_cps := (abs(ln_sldo_total) * ln_cps + ln_pus * rc1.factor_sldo_consig )/abs(ln_sldo_total);
         end if;

      elsif rc1.factor_sldo_consig = -1 and rc1.flag_ajuste_valorizacion = '0' then
         -- Salidas
         ln_sldo_total := ln_sldo_total - NVL(rc1.cant_procesada,0);
      end if;
  end loop;

  if asi_val_ret = 'S' then         -- saldo Total
     ln_ret := ln_sldo_total;
  elsif asi_val_ret = 'L' then   --Soles
     ln_ret := ln_cps;
  else
     ln_ret := 0;
  end if;

  return(ln_ret);
end USF_ALM_SALDO_ANTERIOR_CONSIG;
/

