prompt
prompt Creating function USF_ALM_SALDO_SUGERIDO
prompt ========================================
prompt
create or replace function cantabria.USF_ALM_SALDO_SUGERIDO(
       asi_cod_art in articulo.cod_art%TYPE,
       adi_hasta   in date
)return number is

  Result number;

Cursor c_mov is
  SELECT ap.tipo_mov, ap.cant_proyect
    FROM ARTICULO_MOV_PROY ap
   Where ap.cod_art      = asi_cod_art
     and NVL(ap.cant_proyect, 0) > NVL(ap.cant_procesada, 0)
     and ap.flag_estado = '1'
     and TRUNC(ap.fec_proyect) <= TRUNC( adi_hasta);

  ln_saldo   number;
begin
  ln_saldo := 0;
  For rc1 in c_mov loop
      IF SUBSTR( rc1.tipo_mov,1,1) = 'I' then
         ln_saldo := ln_saldo + rc1.cant_proyect;

      ELSIF SUBSTR( rc1.tipo_mov,1,1) = 'S' then

         ln_saldo := ln_saldo - rc1.cant_proyect;
      END IF;
  End Loop;

  return(ln_saldo);
end USF_ALM_SALDO_SUGERIDO;
/

