prompt
prompt Creating function USF_ALM_SDO_ANTERIOR
prompt ======================================
prompt
create or replace function cantabria.USF_ALM_SDO_ANTERIOR(
        ad_fecha   in date,
        as_almacen in almacen.almacen%TYPE,
        as_cod_art in articulo.cod_art%TYPE,
        as_val_ret in char
) return number is

  ln_sldo_total   articulo_almacen.sldo_total%TYPE;
  ln_ret          number;   -- Valor de retorno
  ln_cps          number;   -- Precio Promedio Dolares
  ln_sldo_und2    articulo_almacen.sldo_total_und2%TYPE;   -- Saldo Total 2 Unidad

/*
   funcion que retorna un dato referente al saldo de un mes.
   Parametros:  mes anterior
                cod. articulo
                valor retorno ( S = Saldo
                                L = Soles
                                2UND = Saldo Total en 2Und
*/



begin
  -- encuentra el saldo de acuerdo los movimientos
  ln_sldo_total := 0;
  ln_cps        := 0;
  ln_sldo_und2  := 0;
  
  Select nvl(sum(am.cant_procesada * amt.factor_sldo_total), 0),
         nvl(sum(am.cant_proc_und2 * amt.factor_sldo_total), 0),
         nvl(sum(
            case
               when NVL(amt.flag_ajuste_valorizacion, '0') = '0' then
                  am.cant_procesada * am.precio_unit * amt.factor_sldo_total
               else
                  am.precio_unit * amt.factor_sldo_total
            end
         ), 0)
    into ln_sldo_total, ln_sldo_und2, ln_cps
    from vale_mov          vm,
         articulo_mov      am,
         articulo_mov_tipo amt
   Where vm.cod_origen = am.cod_origen
     and vm.nro_vale   = am.nro_vale
     and amt.tipo_mov  = vm.tipo_mov
     and vm.flag_estado <> '0'
     and am.flag_estado <> '0'
     and am.cod_art = as_cod_art
     and vm.almacen = as_almacen
     and trunc( vm.fec_registro) <= trunc(ad_fecha);

  if as_val_ret = 'S' then         -- saldo Total
     ln_ret := ln_sldo_total;
  elsif as_val_ret = '2UND' then   -- Saldo en Segunda Unidad
     ln_ret := ln_sldo_und2;
  elsif as_val_ret = 'L' then   --Soles
     ln_ret := ln_cps;
  else
     ln_ret := 0;
  end if;

  return(ln_ret);
end USF_ALM_SDO_ANTERIOR;
/

prompt
prompt Creating function USF_ALM_SDO_ANT_KARDEX
prompt ========================================
prompt
create or replace function cantabria.USF_ALM_SDO_ANT_KARDEX(
        ad_fecha           in date,
        as_almacen         in almacen.almacen%TYPE,
        as_cod_art         in articulo.cod_art%TYPE,
        an_sldo_und        out number,
        an_sldo_und2       out number,
        an_precio_prom     out number
) return number is
  
  ln_costo_total    number;
  
  Cursor c_mov_alm is
    Select vm.fec_registro,
           vm.tipo_mov,
           am.cod_art,
           am.cant_procesada,
           am.precio_unit,
           am.cod_moneda ,
           am.decuento,
           am.cant_proc_und2,
           NVL(amt.flag_ajuste_valorizacion, '0') as flag_ajuste_valorizacion,
           NVL(amt.factor_sldo_total, 0) as factor_sldo_total
      from vale_mov          vm,
           articulo_mov      am,
           articulo_mov_tipo amt
     Where vm.cod_origen = am.cod_origen
       and vm.nro_vale   = am.nro_vale
       and amt.tipo_mov  = vm.tipo_mov
       and vm.flag_estado <> '0'
       and am.flag_estado <> '0'
       and am.cod_art = as_cod_art
       and vm.almacen = as_almacen
       and trunc( vm.fec_registro) < trunc(ad_fecha)
    order by vm.fec_registro, vm.nro_vale;


begin
  -- encuentra el saldo de acuerdo los movimientos
  an_sldo_und  := 0;
  an_precio_prom := 0;
  an_sldo_und2   := 0;
  ln_costo_total := 0;
  
  for rc1 in c_mov_alm loop
      if rc1.factor_sldo_total = 1 and rc1.flag_ajuste_valorizacion = '0' then
         -- Calculo del costo promedio
         if (an_sldo_und + NVL(rc1.cant_procesada,0)) <> 0 then
              /*an_precio_prom := (abs(an_sldo_und) * an_precio_prom + NVL(rc1.cant_procesada,0) * rc1.precio_unit)/
                             (abs(an_sldo_und) + NVL(rc1.cant_procesada,0));*/
              
              ln_costo_total := ln_costo_total + NVL(rc1.cant_procesada,0) * rc1.precio_unit;
         end if;
         an_sldo_und := an_sldo_und + NVL(rc1.cant_procesada,0);
         an_sldo_und2  := an_sldo_und2 + NVL(rc1.cant_proc_und2, 0);

      elsif rc1.flag_ajuste_valorizacion = '1' then

         if an_sldo_und <> 0 then
            /*an_precio_prom := (abs(an_sldo_und) * an_precio_prom + rc1.precio_unit * rc1.factor_sldo_total )/
                      abs(an_sldo_und);*/
            ln_costo_total := ln_costo_total + rc1.precio_unit * rc1.factor_sldo_total;
                      
         end if;

      elsif rc1.factor_sldo_total = -1 and rc1.flag_ajuste_valorizacion = '0' then
         -- Salidas
         an_sldo_und := an_sldo_und - NVL(rc1.cant_procesada,0);
         an_sldo_und2  := an_sldo_und2 - NVL(rc1.cant_proc_und2,0);
         
         ln_costo_total := ln_costo_total - NVL(rc1.cant_procesada,0) * rc1.precio_unit;

      end if;
      
      if an_sldo_und > 0 then
         an_precio_prom := ln_costo_total / an_sldo_und;
      else
         an_precio_prom := 0;
      end if; 
  end loop;

  return(1);

end USF_ALM_SDO_ANT_KARDEX;
/

prompt
prompt Creating function USF_ALM_SDO_ANT_TRANS
prompt =======================================
prompt
create or replace function cantabria.USF_ALM_SDO_ANT_TRANS(
        adi_fecha      in date,
        asi_almacen    in almacen.almacen%TYPE,
        asi_cod_art    in articulo.cod_art%TYPE,
        asi_val_ret in char
) return number is

  ln_sldo_total   articulo_almacen.sldo_total%TYPE;
  ln_ret          number;   -- Valor de retorno

/*
   funcion que retorna un dato referente al saldo de un mes.
   Parametros:  mes anterior
                cod. articulo
                valor retorno ( S = Saldo
                                2UND = Saldo Total en 2Und
*/

  Cursor c1 is
    Select v1.fec_documento,
           v1.tipo_mov,
           v2.cod_art,
           v2.cant_procesada,
           NVL(amt.factor_sldo_total, 0) as factor_sldo_total
      from vale_mov_trans     v1,
           vale_mov_trans_det v2,
           articulo_mov_tipo  amt
     Where v1.nro_vale   = v2.nro_vale
       and amt.tipo_mov  = v1.tipo_mov
       and v1.flag_estado <> '0'
       and v2.flag_estado <> '0'
       and v2.cod_art = asi_cod_art
       and v1.almacen = asi_almacen
       and trunc( v1.fec_documento) <= trunc(adi_fecha)
    order by v1.fec_documento, v1.nro_vale;


begin
  -- encuentra el saldo de acuerdo los movimientos
  ln_sldo_total := 0;

  for rc1 in c1 loop
      if rc1.factor_sldo_total = 1 then
         -- caLculo lso saldos
         ln_sldo_total := ln_sldo_total + NVL(rc1.cant_procesada,0);

      elsif rc1.factor_sldo_total = -1 then
         -- Salidas
         ln_sldo_total := ln_sldo_total - NVL(rc1.cant_procesada,0);

      end if;
  end loop;

  if asi_val_ret = 'S' then         -- saldo Total
     ln_ret := ln_sldo_total;
  ELSE
     ln_ret := 0;
  end if;

  return(ln_ret);
end USF_ALM_SDO_ANT_TRANS;
/

