prompt Creating function USF_ALM_TACITO
prompt ================================
prompt
create or replace function cantabria.usf_alm_tacito(
       asi_origen        in origen.cod_origen%TYPE,
       asi_clase         in articulo_clase.cod_clase%TYPE
) return varchar2 is

  ls_almacen      almacen.almacen%TYPE;
  ll_Count        number;
begin

   select count(*)
     into ll_count
     from almacen_tacito at
    where at.cod_origen = asi_origen
      and at.cod_clase  = asi_clase;

   if ll_count = 0 then
      RAISE_APPLICATION_ERROR(-20000, 'No existe almacen Tacito, por favor verifique! '
          || chr(13) || 'Origen: ' || asi_origen
          || chr(13) || 'Clase : ' || asi_clase);

   else
       select almacen
         into ls_almacen
         from almacen_tacito at
        where at.cod_origen = asi_origen
          and at.cod_clase  = asi_clase;
   end if;


  return(ls_almacen);
end usf_alm_tacito;
/

prompt
prompt Creating function USF_CMP_ULT_PREC_COTIZ
prompt ========================================
prompt
create or replace function cantabria.USF_CMP_ULT_PREC_COTIZ(
       asi_cod_art IN articulo.cod_art%TYPE
) return number IS

  ln_Result           number;
  ln_count            NUMBER;
  ln_precio_cmp_ref   logparam.precio_cmp_ref%TYPE;
  ls_moneda           cotizacion_provee.cod_moneda%TYPE;
  ls_dolares          logparam.cod_dolares%TYPE;
  ln_precio_unit      cotizacion_provee_bien_det.precio_unit%TYPE;
  ln_costo_ult_cmp    articulo.costo_ult_compra%TYPE;

 PRAGMA AUTONOMOUS_TRANSACTION;

begin

  SELECT cod_dolares, NVL(precio_cmp_ref, -1)
    INTO ls_dolares, ln_precio_cmp_ref
    FROM logparam
   WHERE reckey = '1';

  SELECT COUNT(*)
    INTO ln_count
    FROM cotizacion                 a,
         cotizacion_provee          b,
         cotizacion_provee_bien_det c
   WHERE a.nro_cotiza = b.nro_cotiza
     AND b.nro_cotiza = c.nro_cotiza
     AND b.proveedor  = c.proveedor
     AND c.cod_art    = asi_cod_art
     AND NVL(c.precio_unit, 0) > 0
     AND NVL(b.cotizo,'0') = '1'
     AND NVL(a.flag_estado, '0' ) ='1';

  IF ln_count > 0 THEN
     SELECT precio_unit, cod_moneda
       INTO ln_precio_unit, ls_moneda
       FROM (SELECT c.precio_unit, b.cod_moneda
               FROM cotizacion                 a,
                    cotizacion_provee          b,
                    cotizacion_provee_bien_det c
              WHERE a.nro_cotiza = b.nro_cotiza
                AND b.nro_cotiza = c.nro_cotiza
                AND b.proveedor  = c.proveedor
                AND c.cod_art    = asi_cod_art
                AND NVL(c.precio_unit, 0) > 0
                AND NVL(b.cotizo,'0') = '1'
                AND NVL(a.flag_estado, '0') ='1'
              ORDER BY b.fec_registro DESC )
      WHERE ROWNUM = '1';

      ln_Result := usf_fl_conv_mon(ln_precio_unit, ls_moneda, ls_dolares, SYSDATE);

  ELSE

     ln_Result := ln_precio_cmp_ref;

  END IF;

  -- Ahora actualizo el articulo en caso que el precio sea el que esta por defecto
  SELECT costo_ult_compra
    INTO ln_costo_ult_cmp
    FROM articulo
   WHERE cod_art = asi_cod_art;

  IF ln_costo_ult_cmp <> ln_result AND ln_costo_ult_cmp = ln_precio_cmp_ref AND
     ln_Result <> ln_precio_cmp_ref THEN

     UPDATE articulo
        SET costo_ult_compra = ln_costo_ult_cmp
      WHERE cod_art = asi_cod_art;

     COMMIT;

  END IF;

  return(ln_Result);
end USF_CMP_ULT_PREC_COTIZ;
/

prompt
prompt Creating function USF_ALM_ULT_COMP
prompt ==================================
prompt
create or replace function cantabria.USF_ALM_ULT_COMP(
       asi_cod_Art in articulo.cod_Art%TYPE
) return number is

  ln_Result                number;
  ls_dolares               logparam.cod_soles%TYPE;
  ls_doc_oc                logparam.doc_oc%TYPE;
  ln_costo_ult_comp        articulo.costo_ult_compra%TYPE;
  ld_fec_ult_comp          date;
  ln_Count                 number;
  ls_moneda                moneda.cod_moneda%TYPE;
  ls_oper_ing_cdir         logparam.oper_ing_cdir%TYPE;

begin

     select cod_dolares, doc_oc, oper_ing_cdir
       into ls_dolares, ls_doc_oc, ls_oper_ing_cdir
       from logparam
      where reckey = '1';

     -- Verifico si existen movimientos en Articulo_mov_proy para verificar
     -- que si tiene OC
     select count(*)
       into ln_count
       from articulo_mov_proy amp,
            orden_compra      oc
      where oc.nro_oc       = amp.nro_doc
        and amp.tipo_doc    = ls_doc_oc
        and amp.cod_art     = asi_cod_art
        and amp.flag_estado <> '0'
        and oc.flag_estado  <> '0';

     if ln_count > 0 then
         select precio, fec_registro, cod_moneda
           into ln_costo_ult_comp, ld_fec_ult_comp, ls_moneda
           from (select (amp.precio_unit - amp.precio_unit * NVL(amp.decuento,0)/100) as precio,
                        oc.fec_registro, amp.cod_moneda
                   from articulo_mov_proy amp,
                        orden_compra      oc
                  where oc.nro_oc        = amp.nro_doc
                    and amp.tipo_doc     = ls_doc_oc
                    and amp.cod_art      = asi_cod_art
                    and amp.flag_estado  <> '0'
                    and oc.flag_estado   <> '0'
                  order by oc.fec_registro desc)
         where rownum = 1;

         ln_costo_ult_comp := usf_fl_conv_mon(ln_costo_ult_comp, ls_moneda, ls_dolares, ld_fec_ult_comp);
     else
        -- En caso que no tenga OC, entonces lo obtengo a partir del ultimo movimiento
        -- de Almacen que tenga compra Directa

        select count(*)
          into ln_count
          from articulo_mov am,
               vale_mov     vm
         where vm.cod_origen  = am.cod_origen
           and vm.nro_vale    = am.nro_vale
           and am.cod_art     = asi_cod_art
           and vm.tipo_mov    = ls_oper_ing_cdir
           and am.flag_estado <> '0'
           and vm.flag_estado <> '0';

        if ln_count > 0 then
           select precio, fec_registro, cod_moneda
             into ln_costo_ult_comp, ld_fec_ult_comp, ls_moneda
             from  (select (NVL(am.precio_unit,0) - NVL(am.precio_unit,0) * NVL(am.decuento,0)/100) as precio,
                           vm.fec_registro, am.cod_moneda
                      from articulo_mov am,
                           vale_mov     vm
                     where vm.cod_origen  = am.cod_origen
                       and vm.nro_vale    = am.nro_vale
                       and am.cod_art     = asi_cod_art
                       and vm.tipo_mov    = ls_oper_ing_cdir
                       and am.flag_estado <> '0'
                       and vm.flag_estado <> '0'
                     order by vm.fec_registro desc)
            where rownum = 1;

            ln_costo_ult_comp := usf_fl_conv_mon(ln_costo_ult_comp, ls_moneda, ls_dolares, ld_fec_ult_comp);

        else
           -- En caso contario busco el ultimo precio de la cotizacion
           ln_costo_ult_comp := USF_CMP_ULT_PREC_COTIZ(asi_cod_art);
        end if;

     end if;

     ln_Result := ln_costo_ult_comp;

     return(ln_Result);
end USF_ALM_ULT_COMP;
/

prompt
prompt Creating function USF_AP_COD_PRODUCE
prompt ====================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.usf_ap_cod_produce(
      as_especie  IN tg_especies.especie%TYPE
) return varchar2 is
  ls_Result       varchar2(50);
  ls_cod_produce  varchar2(2);
   ls_desc_especie VARCHAR2(50);

BEGIN
     -- devuelve el campo 'cod_produce' de la especie  de tipo H
     -- cuando el campo esta vacio devuelve por defecto el valor '08'
     SELECT E.COD_PRODUCE, E.DESCR_ESPECIE
       INTO ls_cod_produce, ls_desc_especie
       FROM TG_ESPECIES E
       WHERE E.ESPECIE = as_especie
       AND FLAG_TIPO_MATPRIM = 'H';

     IF ls_cod_produce Is Null OR ls_cod_produce = '' THEN
        ls_Result :=  ls_desc_especie;
     ELSE
         ls_Result := ls_cod_produce;
     END IF;

     RETURN(Trim(ls_Result));

END usf_ap_cod_produce;
/

prompt
prompt Creating function USF_AP_CONV_PRECIO
prompt ====================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_AP_CONV_PRECIO(
       as_und_ing    IN ap_pd_descarga_det.und%TYPE,
       as_und_conv   IN ap_param.und_tm%TYPE,
       an_precio     IN ap_guia_recepcion_det.precio_unitario%TYPE

) RETURN number is
  ln_Result number;
  ln_factor number;
  ln_conta  number;

BEGIN

  -- funcion para convertir los PRECIOS de acuerdo a sus
  -- unidades segun factor establecido en la tabla unidad_conv

    IF as_und_ing <> as_und_conv THEN
       SELECT count(*)
        INTO ln_conta
        FROM unidad_conv uc
        WHERE uc.und_ingr = as_und_ing
          AND uc.und_conv = as_und_conv;

       IF ln_conta <> 0 THEN
         SELECT uc.factor_conv
          INTO ln_factor
          FROM unidad_conv uc
          WHERE uc.und_ingr = as_und_ing
             AND uc.und_conv = as_und_conv;

          ln_Result := Round(an_precio / ln_factor,4);

       ELSE
          IF ln_result is null or ln_result = 0 THEN
             RAISE_APPLICATION_ERROR(-20000, 'Factor no definido en unidad_conv para convertir ' ||
                                     as_und_ing || ' a ' || as_und_conv );
             RETURN -1;
          END IF;
       END IF;

    ELSE
        ln_Result := an_precio;
    END IF;

    RETURN (ln_Result);
END USF_AP_CONV_PRECIO;
/

prompt
prompt Creating function USF_AP_CONV_UND
prompt =================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_AP_CONV_UND(
       as_und_ing    IN ap_pd_descarga_det.und%TYPE,
       as_und_conv   IN ap_param.und_tm%TYPE,
       an_peso_bruto IN ap_pd_descarga_det.peso_bruto%TYPE
) RETURN number is
  ln_Result number;
  ln_factor number;
  ln_conta  number;
BEGIN
  -- funcion para convertir a unidades de Toneladas Metricas

    IF as_und_ing <> as_und_conv THEN
       SELECT count(*)
        INTO ln_conta
        FROM unidad_conv uc
        WHERE uc.und_ingr = as_und_ing
          AND uc.und_conv = as_und_conv;

      IF ln_conta <> 0 THEN
         SELECT uc.factor_conv
          INTO ln_factor
          FROM unidad_conv uc
          WHERE uc.und_ingr = as_und_ing
             AND uc.und_conv = as_und_conv;

          ln_Result := Round(an_peso_bruto * ln_factor,3);
      ELSE
          ln_Result := 0;
      END IF;

    ELSE
        ln_Result := an_peso_bruto;
    END IF;

    RETURN (ln_Result);
END USF_AP_CONV_UND;
/

prompt
prompt Creating function USF_AP_DIREC_PROV
prompt ===================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_AP_DIREC_PROV(
    as_codprov in PROVEEDOR.PROVEEDOR%TYPE,
    as_tipo in char  )
    return varchar2 is
  ls_dir   varchar2(250);

BEGIN

    SELECT NVL(TRIM(DIR_DIRECCION),'') ||
           DECODE(NVL(DIR_NUMERO,''),'','',' # '||TRIM(DIR_NUMERO))  ||
           DECODE(NVL(DIR_LOTE, ''),'','',' LOTE '|| TRIM(DIR_LOTE)) ||
           DECODE(NVL(DIR_MNZ, ''),'','', ' MZN ' || TRIM(DIR_MNZ))  ||
           DECODE(NVL(DIR_URBANIZACION, ''),'','',' URB '||TRIM(DIR_URBANIZACION)) ||
           DECODE(NVL(DIR_DISTRITO,''),'','', ' - ' || TRIM(DIR_DISTRITO) || ' - ') ||
           DECODE(NVL(DIR_PROVINCIA,''),'','', TRIM(DIR_PROVINCIA) || ' - ') ||
           DECODE(NVL(DIR_DEP_ESTADO,''),'','', TRIM(DIR_DEP_ESTADO))
     INTO  ls_dir
    FROM   DIRECCIONES
    WHERE  codigo   = as_codprov
      AND  FLAG_USO = as_tipo;

    RETURN(ls_dir);

    EXCEPTION
        WHEN NO_DATA_FOUND THEN
         RETURN ('');

END USF_AP_DIREC_PROV;
/

