prompt Creating function USF_AP_NOM_PROVEEDOR
prompt ======================================
prompt
create or replace function cantabria.usf_ap_nom_proveedor(
       asi_proveedor  in proveedor.proveedor%TYPE
) return varchar2 is
    ls_Result    varchar2(100);
    ln_count     number;

BEGIN
   -- devuelve el nombre de la embarcacion y si no existe devuelve el
   -- nombre del proveedor

    Select count(*)
      into ln_count
      from tg_naves t
      where t.proveedor = asi_proveedor;

    if ln_count = 0 then
       select nom_proveedor
        into ls_Result
        from proveedor
        where proveedor = asi_proveedor;
    else
       Select t.nomb_nave
        into ls_Result
        from tg_naves t
        where t.proveedor = asi_proveedor;
    end if;

    ls_Result := '  '||Trim(ls_Result);
    return(ls_Result);

end usf_ap_nom_proveedor;
/

prompt
prompt Creating function USF_AP_PESCA_MAT
prompt ==================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_AP_PESCA_MAT(
          asi_flag         in   char,
          adi_fecha_ini    ap_pd_descarga_det.inicio_descarga%TYPE,
          adi_fecha_fin    ap_pd_descarga_det.inicio_descarga%TYPE,
          asi_proveedor    proveedor.proveedor%TYPE

) return number is
  ls_Result  number;

BEGIN
    /* Devuelve los valores de ingreso de pesca, importe por ingreso,
       Salidas de almacen, y su importe de salida de almacen de acuerdo
       a codigo de proveedor*/

   /* valores de asi_flag
      1 = para calcular el monto de pesca
      2 = para calcular el importe de pesca
      3 = para calcular la cantidad de materiales que han salido de almacen
      4 = para calcular el monto por concepto de materiales */

   ls_Result := 0.000;

   -- Para la pesca
   IF asi_flag = '1' THEN
     SELECT  ROUND(SUM((USF_AP_CONV_UND(PDD.UND, (SELECT UND_TM FROM AP_PARAM WHERE
                  ORIGEN = 'XX'), GRD.PESO_VENTA))),4)
          INTO ls_result
     FROM   AP_PD_DESCARGA_DET      PDD,
            AP_GUIA_RECEPCION       GR,
            AP_GUIA_RECEPCION_DET   GRD
     WHERE  PDD.NRO_PARTE                 = GRD.NRO_PARTE
       AND  PDD.ITEM                      = GRD.ITEM_PARTE
       AND  GRD.COD_GUIA_REC              = GR.COD_GUIA_REC
       AND  TRUNC(PDD.INICIO_DESCARGA) BETWEEN TRUNC(adi_fecha_ini) AND
                                               TRUNC(adi_fecha_fin)
       AND  GR.PROVEEDOR = asi_proveedor;

   ELSIF asi_flag = '2' THEN
     SELECT  ROUND(SUM(GRD.PESO_VENTA * USF_FL_CONV_MON(GRD.PRECIO_UNITARIO ,
                   GR.COD_MONEDA, (SELECT COD_SOLES FROM LOGPARAM WHERE
                   RECKEY = '1'),PDD.INICIO_DESCARGA)),2)
          INTO ls_result
     FROM   AP_PD_DESCARGA_DET      PDD,
            AP_GUIA_RECEPCION       GR,
            AP_GUIA_RECEPCION_DET   GRD
     WHERE  PDD.NRO_PARTE                 = GRD.NRO_PARTE
       AND  PDD.ITEM                      = GRD.ITEM_PARTE
       AND  GRD.COD_GUIA_REC              = GR.COD_GUIA_REC
       AND  TRUNC(PDD.INICIO_DESCARGA) BETWEEN TRUNC(adi_fecha_ini) AND
                                               TRUNC(adi_fecha_fin)
       AND  GR.PROVEEDOR = asi_proveedor ;

   -- Para los articulos de almacen
   ELSIF asi_flag = '3' THEN
     SELECT  ROUND(SUM(AM.CANT_PROCESADA),3)
          INTO ls_result
     FROM   VALE_MOV                VM,
            ARTICULO_MOV            AM,
            ARTICULO_MOV_TIPO       AMT
     WHERE  VM.COD_ORIGEN                 = AM.COD_ORIGEN
       AND  VM.NRO_VALE                   = AM.NRO_VALE
       AND  VM.TIPO_MOV                   = AMT.TIPO_MOV
       AND  NVL(AMT.FACTOR_SLDO_TOTAL, 0) = -1
       AND  TRUNC(VM.FEC_REGISTRO) BETWEEN TRUNC(adi_fecha_ini) AND
                                           TRUNC(adi_fecha_fin)
       AND  VM.PROVEEDOR = asi_proveedor;

   ELSIF asi_flag = '4' THEN
     SELECT ROUND(SUM(AM.CANT_PROCESADA * USF_FL_CONV_MON(AM.PRECIO_UNIT,
                  AM.COD_MONEDA, (SELECT COD_SOLES FROM LOGPARAM WHERE
                 RECKEY = '1'),VM.FEC_REGISTRO)),2) AS IMPOR_CANT
           INTO ls_result
     FROM   VALE_MOV                VM,
            ARTICULO_MOV            AM,
            ARTICULO_MOV_TIPO       AMT
     WHERE  VM.COD_ORIGEN                 = AM.COD_ORIGEN
       AND  VM.NRO_VALE                   = AM.NRO_VALE
       AND  VM.TIPO_MOV                   = AMT.TIPO_MOV
       AND  NVL(AMT.FACTOR_SLDO_TOTAL, 0) = -1
       AND  TRUNC(VM.FEC_REGISTRO) BETWEEN TRUNC(adi_fecha_ini) AND
                                           TRUNC(adi_fecha_fin)
       AND  VM.PROVEEDOR = asi_proveedor;

   END IF;

   RETURN NVL(ls_Result,0);

END USF_AP_PESCA_MAT;
/

prompt
prompt Creating function USF_AP_SEMANA
prompt ===============================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_AP_SEMANA (
       asi_fecha  in semanas.fecha_inicio%TYPE
) return number is
    ls_Result    number;

BEGIN
   -- devuelve el numero de semana al que corresponde la fecha indicada

   SELECT s.semana
      INTO ls_Result
    FROM SEMANAS S
    WHERE asi_fecha >= s.fecha_inicio
      AND asi_fecha <= s.fecha_fin;

    return(ls_Result);

END USF_AP_SEMANA;
/

