prompt
create or replace function cantabria.USF_ASIST_HINGRESO_TRAB
(ad_fecha          in date,
 ac_cod_trabajador in maestro.cod_trabajador%type ,
 ac_turno          in rrhh_turno_asistencia.turno%type )

return varchar2 is
  Result varchar2(10);
begin



select to_char(a.fec_desde,'hh24:mi:ss') into result  from asistencia a
 where (trunc(a.fec_movim) = ad_fecha          ) and
       (a.cod_trabajador   = ac_cod_trabajador ) and
       (a.turno            = ac_turno          ) and
       (a.cod_tipo_mov     <> '03'             ) ;



if result is null then
   Result := '00:00:00' ;
end if ;

  return(Result);
end USF_ASIST_HINGRESO_TRAB;
