prompt
prompt Creating function USF_CALC_EDAD_APLIC_NITROG
prompt ============================================
prompt
create or replace function cantabria.USF_CALC_EDAD_APLIC_NITROG(as_corr_corte in char) return integer is
 ln_edad number(4,2);
 ls_labor_siembra varchar2(8);
 ld_fec_inicio date;
begin

  --Leemos nombre del parametro de siembra
  Select labor_siembra
  into ls_labor_siembra
  from prod_param
  where reckey = '1';

  --Leemos fecha de inicio de corte
  Select o.fec_inicio
  into ld_fec_inicio
  from operaciones o, campo_ciclo cc
  where o.tipo_orden = (select l.doc_ot from logparam l where reckey='1') AND
        o.nro_orden = cc.nro_orden AND
        cc.corr_corte = as_corr_corte and o.cod_labor = ls_labor_siembra;
  --Calculamos edad del campo
  --  ln_edad := ROUND( ( SYSDATE - ld_fec_inicio)/(365/12),2);
  ln_edad := ROUND( ( SYSDATE - ld_fec_inicio)/30,2);
  return(ln_edad);

end USF_CALC_EDAD_APLIC_NITROG;
/

prompt
prompt Creating function USF_CALC_INS_OPE
prompt ==================================
prompt
create or replace function cantabria.usf_calc_ins_ope(
an_oper_sec      in operaciones.oper_sec%type,
as_cod_plantilla in campo_ciclo.cod_plantilla%type,
as_cod_labor     in labor.cod_labor%type,
as_cod_ejecutor  in labor_ejecutor.cod_ejecutor%type,
as_cant_total    in Number,
as_dias_dur      in operaciones.dias_duracion_proy%type,
as_dias_proc     in operaciones.dias_duracion_proy%type,
as_mes           in Char,
as_corr_corte    in campo_ciclo.corr_corte%type,
as_proceso       in Char,
as_actividad     in Char,
as_labor         in Char,
as_ejecutor      in Char,
as_desc_proceso  in Char )

Return number is
  ln_cant_cal_art number;
  ln_total_c_art  number;

CURSOR c_art is
SELECT artmp.cod_art,
       artmp.cant_proyect
FROM   articulo_mov_proy artmp
WHERE  artmp.oper_sec = an_oper_sec ;


CURSOR c_costo_art (as_cod_art articulo.cod_art%type) is
SELECT costo_ult_compra,
       art.cod_art
FROM   articulo art
WHERE  (art.cod_art = as_cod_art );

begin
  ln_total_c_art := 0 ;
  For rc_art in c_art Loop

      ln_cant_cal_art := 0 ;
      ln_cant_cal_art := Round(((Nvl(as_dias_proc,0) * Nvl(rc_art.cant_proyect,0)) / Nvl(as_dias_dur,0)),2);

          For rc_costo_art in c_costo_art (rc_art.cod_art) Loop
              /* Insercion de Detalle de Insumos*/
              Insert Into tt_ppto_recursos_det
              (cod_art, oper_sec,   corr_corte,  proceso,  actividad,
               labor,   ejecutor, desc_proceso, cantidad, valor_unit, mes )
              Values
               (rc_costo_art.cod_art ,an_oper_sec, as_corr_corte, as_proceso,
                as_actividad, as_labor, as_ejecutor, as_desc_proceso, ln_cant_cal_art,
                ROUND(Nvl(rc_costo_art.costo_ult_compra,0),2), as_mes )  ;
               /**/
              /*Acumulador de Costo Por Insumos*/
              ln_total_c_art := round(ln_total_c_art + (Nvl(ln_cant_cal_art,0) * Round(Nvl(rc_costo_art.costo_ult_compra,0),2)),2) ;

          End Loop;
  End Loop;

  Return(ln_total_c_art);
end usf_calc_ins_ope;
/

prompt
prompt Creating function USF_CALCULO_EDAD_CAMPO
prompt ========================================
prompt
create or replace function cantabria.usf_calculo_edad_campo
(as_nro_orden in char) return integer is
 ln_edad number(4,2);
 ls_labor_siembra prod_param.labor_siembra%type;
 ls_labor_cosecha prod_param.labor_cosecha%type;
 ld_fec_inicio    date;
 ld_fec_cosecha   date;
 ls_flag_estado   varchar2(1);
 ln_count         Number ;

begin
  --Leemos nombre del parametro de siembra
  Select labor_cosecha
  into  ls_labor_cosecha
  from prod_param
  where reckey = '1';


  --Leemos fecha de nac. planta
  Select cc.fec_nac_plnt
    into ld_fec_inicio
    from campo_ciclo cc
   where (cc.nro_orden = as_nro_orden ) ;


  --Leemos fecha de cosecha para campos cerrados
  IF ls_flag_estado <>'2' THEN
     ld_fec_cosecha := SYSDATE ;
  ELSE
     select Count(*)
       into ln_count
       from operaciones
      where ((nro_orden  = as_nro_orden     ) AND
             (cod_labor  = ls_labor_cosecha )) ;

     IF ln_count > 0 THEN
        select fec_inicio, flag_estado
          into ld_fec_cosecha, ls_flag_estado
          from operaciones
         where ((nro_orden  = as_nro_orden     ) AND
                (cod_labor  = ls_labor_cosecha )) ;
     END IF ;

  END IF ;

  --Calculamos edad del campo
  IF ln_count > 0 THEN
     ln_edad := ROUND( ( ld_fec_cosecha - ld_fec_inicio)/30,2);
  ELSE
     ln_edad := 0 ;
  END IF ;

  RETURN(ln_edad);
end usf_calculo_edad_campo;
/

prompt
prompt Creating function USF_CALCULO_UNIDADES_BALANZA
prompt ==============================================
prompt
create or replace function cantabria.usf_calculo_unidades_balanza(
 as_tipo in char, as_tara_pesada in char,
 ad_fdesde in date, ad_fhasta in date)
 return number is
 ln_und_pesada number(6,0);
-- as_tipo puede ser: C=Ca?a, P=Productos terminados,
--                    M=Materiales

-- as_tara_pesada puede ser: P=Pesada, T=Tara
BEGIN

IF as_tipo='C' THEN -- Unidades de ca?a
   IF as_tara_pesada='P' THEN   -- Pesada
       SELECT count(*)
       INTO ln_und_pesada
       FROM campo_pesaje
       WHERE pesada > 0 and hora_pesada>=ad_fdesde
       and hora_pesada<=ad_fhasta ;
   ELSE                         -- Tara
       SELECT count(*)
       INTO ln_und_pesada
       FROM campo_pesaje
       WHERE tara > 0 and hora_pesada>=ad_fdesde
       and hora_pesada<=ad_fhasta ;
   END IF;
END IF;
IF as_tipo='P' THEN -- Unidades de productos terminados
   IF as_tara_pesada='P' THEN   -- Pesada
       SELECT count(*)
       INTO ln_und_pesada
       FROM salida_pesada
       WHERE pesada > 0 and fecha_pesada>=ad_fdesde
       and fecha_pesada<=ad_fhasta ;
   END IF;
END IF;
IF as_tipo='M' THEN -- Unidades de materiales
    IF as_tara_pesada='P' THEN
       SELECT count(*)
       INTO ln_und_pesada
       FROM externo_pesaje
       WHERE pesada > 0 and fecha_pesada>=ad_fdesde
       and fecha_pesada<=ad_fhasta ;
    END IF;
END IF;

  RETURN(ln_und_pesada);
END usf_calculo_unidades_balanza;
/

prompt
prompt Creating function USF_CAL_INS_OPE_OT
prompt ====================================
prompt
create or replace function cantabria.usf_cal_ins_ope_ot(
ac_tipo_orden    in Char ,
an_nro_orden     in Number,
an_oper_sec      in operaciones.oper_sec%type,
an_operacion     in operaciones.nro_operacion%type,
an_dias_dur      in operaciones.dias_duracion_proy%type,
an_dias_proc     in operaciones.dias_duracion_proy%type,
ac_tipo_ot       in Char,
ac_flag          in Char,
ac_cod_maquina   in Char,
ac_cod_origen    in Char)

Return number is
  ln_cant_cal_art number;
  ln_total_c_art  number (13,2) ;

CURSOR c_art is
SELECT artmp.cod_art,
       decode(ac_flag,'P',artmp.cant_proyect,'R',artmp.cant_procesada) as cantidad
FROM   articulo_mov_proy artmp
WHERE  artmp.oper_sec = an_oper_sec ;


CURSOR c_costo_art (as_cod_art articulo.cod_art%type) is
SELECT costo_ult_compra,
       art.cod_art
FROM   articulo art
WHERE  (art.cod_art = as_cod_art );

begin
  ln_total_c_art := 0 ;
  For rc_art in c_art Loop

      ln_cant_cal_art := 0 ;
      ln_cant_cal_art := Round(((Nvl(an_dias_proc,0) * Nvl(rc_art.cantidad,0)) / Nvl(an_dias_dur,0)),2);

          For rc_costo_art in c_costo_art (rc_art.cod_art) Loop
              /* Insercion de Detalle de Insumos*/
              INSERT INTO tt_oper_orden_trabajo_ins
              (tipo_orden,
               cod_origen,
               nro_orden,
               tipo_ot,
               oper_sec,
               nro_operacion,
               cod_art,
               cantidad,
               costo_unitario,
               cod_maquina)
              VALUES
              (ac_tipo_orden,
               ac_cod_origen,
               an_nro_orden,
               ac_tipo_ot,
               an_oper_sec,
               an_operacion,
               rc_art.cod_art,
               ln_cant_cal_art,
               Round(Nvl(rc_costo_art.costo_ult_compra,0),2),
               ac_cod_maquina);
              /*Acumulador de Costo Por Insumos*/
              ln_total_c_art := round(ln_total_c_art + (Nvl(ln_cant_cal_art,0) * Round(Nvl(rc_costo_art.costo_ult_compra,0),2)),2) ;

          End Loop;
  End Loop;

  Return(ln_total_c_art);
end usf_cal_ins_ope_ot;
/

prompt
prompt Creating function USF_CAM_AVANCE_X_LOTE
prompt =======================================
prompt
create or replace function cantabria.usf_cam_avance_x_lote(
       asi_campana   in campanas.campana%TYPE,
       asi_lote      in lote_campo.nro_lote%TYPE,
       asi_labor     in labor.cod_labor%TYPE,
       adi_fecha     in date
) return number is

  
  ln_tplantas        lote_campo.total_plantas%TYPE;
  ln_cant_procesada  number;
  adi_fecha1         date;
  adi_Fecha2         date;
  ln_Result          number;
begin
  
  select total_plantas
    into ln_tplantas
    from lote_campo lc
   where lc.nro_lote = asi_lote;
  
  select c.fec_inicio, c.fec_fin
    into adi_fecha1, adi_fecha2
    from campanas c
   where c.campana = asi_campana;
  
  -- Total en el periodo hasta antes de fecha
  select sum(p.rendimiento) 
    into ln_cant_procesada
  from pd_jornal_campo p,
       labor           l,
       pd_jornal_campo_lote pd
  where p.fecha          = pd.fecha
    and p.cod_trabajador = pd.cod_trabajador
    and p.nro_item       = pd.nro_item
    and p.cod_labor      = l.cod_labor
    and pd.nro_lote      = asi_lote
    and p.rendimiento    > 0
    and p.cod_labor      = asi_labor
    and trunc(p.fecha)   = adi_fecha
    and trunc(p.fecha)   between adi_Fecha1 and adi_fecha2;
  
  if ln_tplantas <> 0 then
     ln_Result := ln_cant_procesada / ln_tplantas;
  else
     ln_Result := 0;
  end if;
  
  return ln_Result;
end usf_cam_avance_x_lote;
/

