prompt Creating function USF_CAM_REND_CANA
prompt ===================================
prompt
create or replace function cantabria.USF_CAM_REND_CANA
(correlativo in campo_ciclo.corr_corte%type, ad_fecha in date, flg_quemado IN campo_pesaje.flag_campo_sin_qm%TYPE)
return number is
Result number;
ld_fch_ini date;
ld_fch_fin date;

begin

SELECT del_dia, al_dia
  INTO ld_fch_ini, ld_fch_fin
  FROM calendario_produccion
 WHERE del_dia <= ad_fecha AND
       al_dia >= ad_fecha;

select sum(lcc.dia)
into Result
from lab_calculo_campo lcc
where lcc.flag_campo_sin_qm = flg_quemado
and lcc.corr_corte = correlativo
and lcc.fecha >= ld_fch_ini
and lcc.fecha <= ld_fch_fin
and lcc.cod_calculo = 'C063';
--C063: Rendimiento Teorico
--Este codigo de calculo, se utiliza para obtener las tn. Azucar x Tn. Ca?a
  return(Result);

end USF_CAM_REND_CANA;
/

