prompt Creating function USF_CAM_FECHA_PROD
prompt ====================================
prompt
create or replace function cantabria.usf_cam_fecha_prod(ad_fecha campo_pesaje.hora_tara%type)
return date is
  li_count INTEGER;
  ld_fecha_prod            calendario_produccion.fecha_prod%type ;
BEGIN

  -- Capturando la fecha de produccion
SELECT COUNT(*)
  INTO li_count
  FROM calendario_produccion
 WHERE del_dia <= ad_fecha AND
       al_dia >= ad_fecha;

  IF li_count > 0 THEN
    SELECT fecha_prod
      INTO ld_fecha_prod
      FROM calendario_produccion
     WHERE del_dia <= ad_fecha AND
           al_dia >= ad_fecha;
  END IF ;

  RETURN(ld_fecha_prod) ;

END usf_cam_fecha_prod ;
/

prompt
prompt Creating function USF_CAM_CALC_AZ
prompt =================================
prompt
create or replace function cantabria.USF_CAM_CALC_AZ
(ad_fec_ini in date,
 ad_fec_fin in date) return number is

ls_tipo_dato        char(1);
ls_valor_dato       varchar2(100);
Result              number(20,7);
ln_ano              number(4);
ln_mes_ini_his      number(2);
ln_mes_fin_his      number(2);
lb_ini              boolean;
lb_fin              boolean;
ld_fec_ini          date;
ld_fec_fin          date;
ln_mes_ini_req      number(2);
ln_mes_fin_req      number(2);
ln_mes_calc         number(2);
ln_azucar_mes       number(20,7);
ln_azucar_tot       number(20,7);

begin

--hardcode de costomovhist para toneladas de azucar por frente de cosecha
ls_tipo_dato := 'D';
ls_valor_dato := 'AZUCAR';

ln_ano := to_number(to_char(ad_fec_ini,'yyyy'));
-- Meses Requeridos
ln_mes_ini_req := TO_NUMBER(TO_CHAR(USF_CAM_FECHA_PROD(ad_fec_ini),'MM'));
ln_mes_fin_req := TO_NUMBER(TO_CHAR(USF_CAM_FECHA_PROD(ad_fec_fin),'MM'));

--verificando meses procesados
SELECT MIN(cmh.mes), MAX(cmh.mes)
INTO ln_mes_ini_his, ln_mes_fin_his
FROM cmp_cosecha_costo_mov_hist cmh
WHERE cmh.ano = ln_ano AND cos_tipo_dato = ls_tipo_dato AND valor_dato = ls_valor_dato;

lb_ini := False; lb_fin := False;
IF ln_mes_ini_req >= ln_mes_ini_his AND  ln_mes_ini_req <= ln_mes_fin_his THEN
   lb_ini := True;
END IF;
IF ln_mes_fin_req >= ln_mes_ini_his AND  ln_mes_fin_req <= ln_mes_fin_his THEN
   lb_fin := True;
END IF;

if lb_ini = true and lb_fin = true then

    --obteniendo el tonelada de azucar procesada
    select sum(tn_azucar)
      into Result
      from cmp_cosecha_costo_mov_hist
     where ano = ln_ano
       and mes >= ln_mes_ini_req
       and mes <= ln_mes_fin_req
       and cos_tipo_dato = ls_tipo_dato
       and valor_dato = ls_valor_dato
       and frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

elsif lb_ini = true and lb_fin = false then

      ln_azucar_tot := 0;

      for ln_mes in (ln_mes_fin_his + 1)..ln_mes_fin_req loop

          ln_azucar_mes := 0;

          -- Rango del Mes Actual
          SELECT MIN(cp.del_dia), MAX(cp.al_dia)
            INTO ld_fec_ini, ld_fec_fin
            FROM calendario_produccion cp
           WHERE TO_CHAR(cp.fecha_prod,'YYYY') = TO_CHAR(ln_ano)
          AND TO_NUMBER(TO_CHAR(cp.fecha_prod,'MM'))= ln_mes;

         Begin
          select to_number(to_char(usf_cam_fecha_prod(cp.hora_tara),'MM')),
                 sum(((cp.pesada - cp.tara)/1000) *
                 usf_cam_factor_sac_x_rec(cp.hora_tara,cp.corr_corte,cp.flag_campo_sin_qm))
            into ln_mes_calc, ln_azucar_mes
            from campo_pesaje cp, campo_ciclo cc, campo c
           where cp.corr_corte = cc.corr_corte
             and cc.cod_campo = c.cod_campo
             and cp.hora_tara >= ld_fec_ini
             and cp.hora_tara <= ld_fec_fin
             and cp.flag_impurezas = '0'
             and c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha)
           group by to_number(to_char(usf_cam_fecha_prod(cp.hora_tara),'MM'));
       EXCEPTION
         WHEN NO_DATA_FOUND THEN
             ln_mes_calc := 0; ln_azucar_mes := 0;
       END;

           ln_azucar_tot := ln_azucar_tot + ln_azucar_mes;

    end loop;

    --obteniendo el tonelada de azucar procesada
    select sum(tn_azucar)
      into Result
      from cmp_cosecha_costo_mov_hist
     where ano = ln_ano
       and mes >= ln_mes_ini_req
       and mes <= ln_mes_fin_req
       and cos_tipo_dato = ls_tipo_dato
       and valor_dato = ls_valor_dato
       and frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

    Result := Result + ln_azucar_tot;

elsif lb_ini = false and lb_fin = false then

      ln_azucar_tot := 0;

      for ln_mes in ln_mes_ini_req..ln_mes_fin_req loop

          ln_azucar_mes := 0;

          -- Rango del Mes Actual
          SELECT MIN(cp.del_dia), MAX(cp.al_dia)
            INTO ld_fec_ini, ld_fec_fin
            FROM calendario_produccion cp
           WHERE TO_CHAR(cp.fecha_prod,'YYYY') = TO_CHAR(ln_ano)
          AND TO_NUMBER(TO_CHAR(cp.fecha_prod,'MM'))= ln_mes;

          select to_number(to_char(usf_cam_fecha_prod(cp.hora_tara),'MM')),
                 sum(((cp.pesada - cp.tara)/1000) *
                 usf_cam_factor_sac_x_rec(cp.hora_tara,cp.corr_corte,cp.flag_campo_sin_qm))
            into ln_mes_calc, ln_azucar_mes
            from campo_pesaje cp, campo_ciclo cc, campo c
           where cp.corr_corte = cc.corr_corte
             and cc.cod_campo = c.cod_campo
             and cp.hora_tara >= ld_fec_ini
             and cp.hora_tara <= ld_fec_fin
             and cp.flag_impurezas = '0'
             and c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha)
           group by to_number(to_char(usf_cam_fecha_prod(cp.hora_tara),'MM'));

           ln_azucar_tot := ln_azucar_tot + ln_azucar_mes;

    end loop;

    Result := ln_azucar_tot;

end if;

return(Result);

end USF_CAM_CALC_AZ;
/

prompt
prompt Creating function USF_CAM_CALC_CANA
prompt ===================================
prompt
create or replace function cantabria.USF_CAM_CALC_CANA
(ad_fec_ini in date,
 ad_fec_fin in date) return number is

Result                   number(20,7);
ln_ano                   number(4);
ln_importe               number(20,7);
ln_costo                 number(20,7);
ln_costo_fijo            number(20,7);
ln_monto_his number(15,7);
ln_cana            number(15,3);
ln_cana_sucia            number(15,3);
ln_cana_his            number(15,3);
lb_ini Boolean;
lb_fin Boolean;
ln_mes_ini number(2);
ln_mes_fin NUMBER(2);
ln_mes_ini_req number(2);
ln_mes_fin_req number(2);
ln_mes_ini_his number(2);
ln_mes_fin_his number(2);
ld_fec_ini DATE;
ld_fec_fin DATE;

BEGIN
INSERT INTO tt_frente_cosecha(frente_cosecha) values('A1');
INSERT INTO tt_frente_cosecha(frente_cosecha) values('A2');
INSERT INTO tt_frente_cosecha(frente_cosecha) values('AA');
ln_ano := to_number(to_char(ad_fec_ini,'yyyy'));

-- Meses Requeridos
ln_mes_ini_req := TO_NUMBER(TO_CHAR(USF_CAM_FECHA_PROD(ad_fec_ini),'MM'));
ln_mes_fin_req := TO_NUMBER(TO_CHAR(USF_CAM_FECHA_PROD(ad_fec_fin),'MM'));

-- Meses procesados en costo_mov_hist
SELECT MIN(cmh.mes), MAX(cmh.mes)
  INTO ln_mes_ini_his, ln_mes_fin_his
  FROM cmp_cosecha_costo_mov_hist cmh
 WHERE cmh.ano = ln_ano AND cos_tipo_dato = 'D' AND valor_dato = 'CFIJO';

-- Validacion para identificar que meses Obtener de costo_mov_hist
-- y cuales calcular. Generalmente se deberia calcular el mes actual
-- pues no se ha corrido el proceso que actualiza costo_mov_hist pues el mes no ha terminado

-- Verificacion de que el rango de meses requeridos se encuentran en el rango de meses
--de costo_mov_hist
lb_ini := False; lb_fin := False;
IF ln_mes_ini_req >= ln_mes_ini_his AND  ln_mes_ini_req <= ln_mes_fin_his THEN
   lb_ini := True;
END IF;
IF ln_mes_fin_req >= ln_mes_ini_his AND  ln_mes_fin_req <= ln_mes_fin_his THEN
   lb_fin := True;
END IF;

-- *********************************************************************
-- [1] Caso Meses Requeridos No se Encuentran Guardados en costo_mov_his
-- *********************************************************************
IF lb_ini = False AND lb_fin = False THEN
   --Calculo Total
   ln_mes_ini := ln_mes_ini_req; ln_mes_fin := ln_mes_fin_req;

   SELECT MIN(cp.del_dia), MAX(cp.al_dia)
   INTO ld_fec_ini, ld_fec_fin
   FROM calendario_produccion cp
   WHERE ano = ln_ano
   AND TO_NUMBER(TO_CHAR(cp.fecha_prod,'MM'))>= ln_mes_ini
   AND TO_NUMBER(TO_CHAR(cp.fecha_prod,'MM'))<= ln_mes_fin;

  select round(sum(((cp.pesada - cp.tara)/1000)),3)
    into ln_cana_sucia
    from campo_pesaje cp, campo_ciclo cc, campo c
   where cp.corr_corte = cc.corr_corte
     and cc.cod_campo = c.cod_campo
     and cp.hora_tara >= ld_fec_ini
     and cp.hora_tara <= ld_fec_fin
     and cp.flag_impurezas = '0'
     and c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

    --ln_costo_fijo := (NVL(ln_importe,0) + NVL(ln_costo,0))/ln_cana_sucia;
    ln_cana := NVL(ln_cana_sucia,0);
END IF;

-- *********************************************************************
-- [2] Mes Inicio Requerido pertene al Rango
-- *********************************************************************
IF lb_ini = True AND lb_fin = False THEN
   --Recuperar de Costo_Mov_Hist
   ln_mes_ini := ln_mes_ini_req; ln_mes_fin := ln_mes_fin_his;

   SELECT SUM(tm_cana_sucia)
   INTO ln_cana_his
   FROM cmp_cosecha_costo_mov_hist
   WHERE ano = ln_ano
   AND mes >= ln_mes_ini
   AND mes <= ln_mes_fin
   AND cos_tipo_dato = 'D' AND valor_dato IN ('CSQ','CSC')
   AND frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

   -- Calcular
   ln_mes_ini := ln_mes_fin_his + 1; ln_mes_fin := ln_mes_fin_req;

   SELECT MIN(cp.del_dia), MAX(cp.al_dia)
   INTO ld_fec_ini, ld_fec_fin
   FROM calendario_produccion cp
   WHERE ano = ln_ano
   AND TO_NUMBER(TO_CHAR(cp.fecha_prod,'MM'))>= ln_mes_ini
   AND TO_NUMBER(TO_CHAR(cp.fecha_prod,'MM'))<= ln_mes_fin;

  --calcula la tonelada de ca?a
  select round(sum(((cp.pesada - cp.tara)/1000)),3)
    into ln_cana_sucia
    from campo_pesaje cp, campo_ciclo cc, campo c
   where cp.corr_corte = cc.corr_corte
     and cc.cod_campo = c.cod_campo
     and cp.hora_tara >= ld_fec_ini
     and cp.hora_tara <= ld_fec_fin
     and cp.flag_impurezas = '0'
     and c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

    ln_cana := NVL(ln_cana_sucia,0) + NVL(ln_cana_his,0);
END IF;

-- *********************************************************************
-- [3] Mes Inicio y Final Requerido pertene al Rango
-- *********************************************************************
IF lb_ini = True AND lb_fin = True THEN
   --Recuperar de Costo_Mov_Hist
   ln_mes_ini := ln_mes_ini_req; ln_mes_fin := ln_mes_fin_req;

   SELECT SUM(tm_cana_sucia)
   INTO ln_cana_his
   FROM cmp_cosecha_costo_mov_hist
   WHERE ano = ln_ano
   AND mes >= ln_mes_ini
   AND mes <= ln_mes_fin
   AND cos_tipo_dato = 'D' AND valor_dato IN ('CSQ','CSC')
   AND frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

    ln_cana :=  NVL(ln_cana_his,0);
END IF;

--calcula el valor fijo en US$ de total de ca?a
--ln_costo_fijo := NVL(ln_importe,0) + NVL(ln_costo,0);--/ln_cana_sucia;
--ln_importe    := ln_importe + ln_costo;


--calcula el valor fijo en US$ de total de ca?a
Result := ln_cana;--(ln_importe + ln_costo)/ln_cana_sucia;

return(Result);

end USF_CAM_CALC_CANA;
/

prompt
prompt Creating function USF_CAM_RECUPERADO_CC
prompt =======================================
prompt
create or replace function cantabria.USF_CAM_RECUPERADO_CC
(correlativo in campo_ciclo.corr_corte%type, ad_fecha in date, flg_quemado IN campo_pesaje.flag_campo_sin_qm%TYPE)
return number is
Result number;
ld_fch_ini date;
ld_fch_fin date;

begin

SELECT del_dia, al_dia
  INTO ld_fch_ini, ld_fch_fin
  FROM calendario_produccion
 WHERE del_dia <= ad_fecha AND
       al_dia >= ad_fecha;

select CASE
       WHEN SUM(nvl(DECODE(flg_quemado,0,ccd.cana_sucia_qmd,1,ccd.cana_sucia_cruda),0))=0 THEN 0
       ELSE SUM(nvl(DECODE(flg_quemado,0,ccd.cana_sucia_qmd,1,ccd.cana_sucia_cruda),0) * nvl(DECODE(flg_quemado,0,ccd.rec_az_cana_qmd,1,ccd.rec_az_cana_cruda),0)) /
            SUM(nvl(DECODE(flg_quemado,0,ccd.cana_sucia_qmd,1,ccd.cana_sucia_cruda),0))
       END
  into result
  from campo_ciclo_diario ccd
 where corr_corte = correlativo
   and fecha >= ld_fch_ini
   and fecha <= ld_fch_fin;

return(Result);

end USF_CAM_RECUPERADO_CC;
/

