prompt
prompt Creating function USF_CAM_CALC_COSECHA_US_TA
prompt ============================================
prompt
create or replace function cantabria.USF_CAM_CALC_COSECHA_US_TA
(ad_fec_ini in date,
 ad_fec_fin in date ) return number is

ln_sacarosa    number(15,7);
ln_recuperado  number(15,7);
Result         number(10,7);
ln_cana_sucia  number(15,3);
begin

--calcula la sacarosa anual x frente de cosecha
select case
           WHEN SUM((cp.pesada - cp.tara)/1000) = 0 THEN 0
           ELSE SUM(((cp.pesada - cp.tara)/1000) * USF_CAM_SACAROSA_CC(cp.corr_corte,cp.hora_pesada,cp.flag_campo_sin_qm))/SUM((cp.pesada - cp.tara)/1000)
       END as monto
  into ln_sacarosa
  from campo_pesaje cp, campo_ciclo cc, campo c
 where cp.corr_corte = cc.corr_corte
   and cc.cod_campo = c.cod_campo
   and cp.hora_tara >= ad_fec_ini
   and cp.hora_tara <= ad_fec_fin
   and cp.flag_campo_sin_qm = '0'
   and c.frente_cosecha in ('A1','A2','AA');
--   and c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

--calcula el recuperado anual x frente de cosecha
select case
           WHEN SUM((cp.pesada - cp.tara)/1000)= 0 THEN 0
           ELSE SUM(((cp.pesada - cp.tara)/1000) * USF_CAM_RECUPERADO_CC(cp.corr_corte,cp.hora_pesada,cp.flag_campo_sin_qm))/SUM((cp.pesada - cp.tara)/1000)
       END
  into ln_recuperado
  from campo_pesaje cp, campo_ciclo cc, campo c
 where cp.corr_corte = cc.corr_corte
   and cc.cod_campo = c.cod_campo
   and cp.hora_tara >= ad_fec_ini
   and cp.hora_tara <= ad_fec_fin
   and cp.flag_campo_sin_qm = '0'
   and c.frente_cosecha in ('A1','A2','AA');
--   and c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

--calcula la tonelada de ca?a anual x frente de cosecha
select round(sum(((cp.pesada - cp.tara)/1000)),3)
  into ln_cana_sucia
  from campo_pesaje cp, campo_ciclo cc, campo c
 where cp.corr_corte = cc.corr_corte
   and cc.cod_campo = c.cod_campo
   and cp.hora_tara >= ad_fec_ini
   and cp.hora_tara <= ad_fec_fin
   and cp.flag_impurezas <> '1'
   and c.frente_cosecha in ('A1','A2','AA');
--   and c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

  Result := round(((ln_cana_sucia * ln_sacarosa * ln_recuperado) / 10000),9);

  return(Result);

end USF_CAM_CALC_COSECHA_US_TA;
/

prompt
prompt Creating function USF_CAM_CALCULO_COS_X_MAQ
prompt ===========================================
prompt
create or replace function cantabria.USF_CAM_CALCULO_COS_X_MAQ
(an_fecha in date,
 an_categoria in char)
 return  number is

 Result number(13,2);
 ln_ano number(4);
 ln_mes number(2);

begin

 ln_ano := to_number(to_char(an_fecha,'yyyy'));
 ln_mes := to_number(to_char(an_fecha,'mm'));

if an_categoria is null then

   Result := 0;

else

  --determina el precio de acuerdo a la categoria
  select mccv.costo_x_und
    into Result
    from maq_cat_costeo_valorizacion mccv
   where mccv.categoria = an_categoria
     and mccv.ano = ln_ano
     and mccv.mes = ln_mes;

end if;

return(Result);

end USF_CAM_CALCULO_COS_X_MAQ;
/

prompt
prompt Creating function USF_CAM_CALC_COSTO_FIJO
prompt =========================================
prompt
create or replace function cantabria.USF_CAM_CALC_COSTO_FIJO
(as_cencos in centros_costo.cencos%type,
 ad_fec_ini in date,
 ad_fec_fin in date) return number is

Result                   number(20,7);
ln_ano                   number(4);
ln_importe               number(20,7);
ln_costo                 number(20,7);
ln_costo_fijo            number(20,7);
ln_monto_his number(15,7);
ln_cana_sucia            number(15,3);
ln_cana_his            number(15,3);
lb_ini Boolean;
lb_fin Boolean;
ln_mes_ini number(2);
ln_mes_fin NUMBER(2);
ln_mes_ini_req number(2);
ln_mes_fin_req number(2);
ln_mes_ini_his number(2);
ln_mes_fin_his number(2);
ld_fec_ini DATE;
ld_fec_fin DATE;

BEGIN
--INSERT INTO tt_frente_cosecha(frente_cosecha) values('A1');
--INSERT INTO tt_frente_cosecha(frente_cosecha) values('A2');
--INSERT INTO tt_frente_cosecha(frente_cosecha) values('AA');
ln_ano := to_number(to_char(ad_fec_ini,'yyyy'));

-- Meses Requeridos
ln_mes_ini_req := TO_NUMBER(TO_CHAR(USF_CAM_FECHA_PROD(ad_fec_ini),'MM'));
ln_mes_fin_req := TO_NUMBER(TO_CHAR(USF_CAM_FECHA_PROD(ad_fec_fin),'MM'));

-- Meses procesados en costo_mov_hist
SELECT MIN(cmh.mes), MAX(cmh.mes)
  INTO ln_mes_ini_his, ln_mes_fin_his
  FROM cmp_cosecha_costo_mov_hist cmh
 WHERE cmh.ano = ln_ano AND cos_tipo_dato = 'D' AND valor_dato = 'CFIJO';

-- Validacion para identificar que meses Obtener de costo_mov_hist
-- y cuales calcular. Generalmente se deberia calcular el mes actual
-- pues no se ha corrido el proceso que actualiza costo_mov_hist pues el mes no ha terminado

-- Verificacion de que el rango de meses requeridos se encuentran en el rango de meses
--de costo_mov_hist
lb_ini := False; lb_fin := False;
IF ln_mes_ini_req >= ln_mes_ini_his AND  ln_mes_ini_req <= ln_mes_fin_his THEN
   lb_ini := True;
END IF;
IF ln_mes_fin_req >= ln_mes_ini_his AND  ln_mes_fin_req <= ln_mes_fin_his THEN
   lb_fin := True;
END IF;

-- *********************************************************************
-- [1] Caso Meses Requeridos No se Encuentran Guardados en costo_mov_his
-- *********************************************************************
IF lb_ini = False AND lb_fin = False THEN
   --Calculo Total
   ln_mes_ini := ln_mes_ini_req; ln_mes_fin := ln_mes_fin_req;

   SELECT MIN(cp.del_dia), MAX(cp.al_dia)
   INTO ld_fec_ini, ld_fec_fin
   FROM calendario_produccion cp
   WHERE ano = ln_ano
   AND TO_NUMBER(TO_CHAR(cp.fecha_prod,'MM'))>= ln_mes_ini
   AND TO_NUMBER(TO_CHAR(cp.fecha_prod,'MM'))<= ln_mes_fin;

  select round(sum(((cp.pesada - cp.tara)/1000)),3)
    into ln_cana_sucia
    from campo_pesaje cp, campo_ciclo cc, campo c
   where cp.corr_corte = cc.corr_corte
     and cc.cod_campo = c.cod_campo
     and cp.hora_tara >= ld_fec_ini
     and cp.hora_tara <= ld_fec_fin
     and cp.flag_impurezas = '0'
     and c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

    --calcula el costo de ejecucion presupuestal
    select sum(nvl(pe.importe,0)) * -1
      into ln_importe
      from presupuesto_ejec pe
     where cencos = as_cencos
       and ano = ln_ano
       and fecha >= ld_fec_ini
       and fecha <= ld_fec_fin
       and pe.cnta_prsp not in (select descripcion from rpt_grupo where reporte = 'CPRESOBR');

    --calcula el costo por maquina anual que dan servicio al CC de campo 36100
    select sum((USF_CAM_CALCULO_COS_X_MAQ(po.fecha,mccd.categoria)/
           (select tipo_cambio from calendario_periodo cp
           where cp.flag_tipo = 'A' and nro = ln_ano)) *
           (sum ( nvl(pod.cant_labor,0)) - sum( nvl(pod.horas_inciden,0)))) as importe
      into ln_costo
      from orden_trabajo ot, operaciones o, pd_ot_det pod, pd_ot po,
           maq_categoria_costeo_det mccd, labor_ejecutor le, labor l
     where ot.nro_orden = o.nro_orden
       and o.oper_sec = pod.oper_sec
       and pod.nro_parte = po.nro_parte
       and pod.cod_maquina = mccd.cod_maquina (+)
       and o.cod_labor = le.cod_labor
       and o.cod_ejecutor = le.cod_ejecutor
       and le.cod_labor = l.cod_labor
       and pod.cencos = as_cencos
       and pod.cod_maquina is not null
       and po.fecha >= ld_fec_ini
       and po.fecha <= ld_fec_fin
       and l.flag_maq_mo = 'M'
    group by pod.cod_maquina, mccd.categoria, USF_CAM_CALCULO_COS_X_MAQ(po.fecha,mccd.categoria);

    If nvl(ln_cana_sucia,0) > 0 then
       ln_costo_fijo := (NVL(ln_importe,0) + NVL(ln_costo,0))/ln_cana_sucia;
    end if;

END IF;

-- *********************************************************************
-- [2] Mes Inicio Requerido pertene al Rango
-- *********************************************************************
IF lb_ini = True AND lb_fin = False THEN
   --Recuperar de Costo_Mov_Hist
   ln_mes_ini := ln_mes_ini_req; ln_mes_fin := ln_mes_fin_his;
   SELECT SUM(monto)
   INTO ln_monto_his
   FROM cmp_cosecha_costo_mov_hist
   WHERE ano = ln_ano
   AND mes >= ln_mes_ini
   AND mes <= ln_mes_fin
   AND cos_tipo_dato = 'D' AND valor_dato = 'CFIJO';

   SELECT SUM(tm_cana_sucia)
   INTO ln_cana_his
   FROM cmp_cosecha_costo_mov_hist
   WHERE ano = ln_ano
   AND mes >= ln_mes_ini
   AND mes <= ln_mes_fin
   AND cos_tipo_dato = 'D' AND valor_dato IN ('CSQ','CSC')
   AND frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

   -- Calcular
   ln_mes_ini := ln_mes_fin_his + 1; ln_mes_fin := ln_mes_fin_req;

   SELECT MIN(cp.del_dia), MAX(cp.al_dia)
   INTO ld_fec_ini, ld_fec_fin
   FROM calendario_produccion cp
   WHERE ano = ln_ano
   AND TO_NUMBER(TO_CHAR(cp.fecha_prod,'MM'))>= ln_mes_ini
   AND TO_NUMBER(TO_CHAR(cp.fecha_prod,'MM'))<= ln_mes_fin;

  --calcula la tonelada de ca?a
  select round(sum(((cp.pesada - cp.tara)/1000)),3)
    into ln_cana_sucia
    from campo_pesaje cp, campo_ciclo cc, campo c
   where cp.corr_corte = cc.corr_corte
     and cc.cod_campo = c.cod_campo
     and cp.hora_tara >= ld_fec_ini
     and cp.hora_tara <= ld_fec_fin
     and cp.flag_impurezas = '0'
     and c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

    --calcula el costo de ejecucion presupuestal
    select sum(nvl(pe.importe,0)) * -1
      into ln_importe
      from presupuesto_ejec pe
     where cencos = as_cencos
       and ano = ln_ano
       and fecha >= ld_fec_ini
       and fecha <= ld_fec_fin
       and pe.cnta_prsp not in (select descripcion from rpt_grupo where reporte = 'CPRESOBR');

    --calcula el costo por maquina anual que dan servicio al CC de campo 36100
    select sum((USF_CAM_CALCULO_COS_X_MAQ(po.fecha,mccd.categoria)/
           (select tipo_cambio from calendario_periodo cp
           where cp.flag_tipo = 'A' and nro = ln_ano)) *
           (sum ( nvl(pod.cant_labor,0)) - sum( nvl(pod.horas_inciden,0)))) as importe
      into ln_costo
      from orden_trabajo ot, operaciones o, pd_ot_det pod, pd_ot po,
           maq_categoria_costeo_det mccd, labor_ejecutor le, labor l
     where ot.nro_orden = o.nro_orden
       and o.oper_sec = pod.oper_sec
       and pod.nro_parte = po.nro_parte
       and pod.cod_maquina = mccd.cod_maquina (+)
       and o.cod_labor = le.cod_labor
       and o.cod_ejecutor = le.cod_ejecutor
       and le.cod_labor = l.cod_labor
       and pod.cencos = as_cencos
       and pod.cod_maquina is not null
       and po.fecha >= ld_fec_ini
       and po.fecha <= ld_fec_fin
       and l.flag_maq_mo = 'M'
    group by pod.cod_maquina, mccd.categoria, USF_CAM_CALCULO_COS_X_MAQ(po.fecha,mccd.categoria);

    If (NVL(ln_cana_sucia,0) + NVL(ln_cana_his,0)) > 0 then
       ln_costo_fijo := (NVL(ln_importe,0) + NVL(ln_costo,0)+ NVL(ln_monto_his,0))/(NVL(ln_cana_sucia,0) + NVL(ln_cana_his,0));
    end if;
END IF;

-- *********************************************************************
-- [3] Mes Inicio y Final Requerido pertene al Rango
-- *********************************************************************
IF lb_ini = True AND lb_fin = True THEN
   --Recuperar de Costo_Mov_Hist
   ln_mes_ini := ln_mes_ini_req; ln_mes_fin := ln_mes_fin_req;
   SELECT SUM(monto)
   INTO ln_monto_his
   FROM cmp_cosecha_costo_mov_hist
   WHERE ano = ln_ano
   AND mes >= ln_mes_ini
   AND mes <= ln_mes_fin
   AND cos_tipo_dato = 'D' AND valor_dato = 'CFIJO';

   SELECT SUM(tm_cana_sucia)
   INTO ln_cana_his
   FROM cmp_cosecha_costo_mov_hist
   WHERE ano = ln_ano
   AND mes >= ln_mes_ini
   AND mes <= ln_mes_fin
   AND cos_tipo_dato = 'D' AND valor_dato IN ('CSQ','CSC')
   AND frente_cosecha in (select frente_cosecha from tt_frente_cosecha);

   If NVL(ln_cana_his,0) > 0 then
      ln_costo_fijo := NVL(ln_monto_his,0) / NVL(ln_cana_his,0);
   end if;
END IF;

Result := ln_costo_fijo;

return(Result);

end USF_CAM_CALC_COSTO_FIJO;
/

prompt
prompt Creating function USF_VTA_DOL_PROM_X_MES
prompt ========================================
prompt
create or replace function cantabria.USF_VTA_DOL_PROM_X_MES
(an_ano in number,
 an_mes in number) return number is

Result calendario.vta_dol_prom%type;
ld_fec_fin date;
ln_count number(1);
ln_ano  number(4);
ln_mes number(2);
lb_exception boolean;
-- Esta funcion devuelve el maximo tipo de cambio utilizado en un a?o y un mes determinado
Begin
  ln_count := 0;
  ln_ano := an_ano;
  ln_mes := an_mes;
  lb_exception := false;
  --Busca hasta en 6 meses anteriores sino encuentra en el a?o y mes solicitado
  While ln_count <= 6 and lb_exception = false loop
      lb_exception := true;
      Select max(vta_dol_prom)
        into Result
        from calendario
       where to_number(to_char(fecha,'yyyy'))=ln_ano and
             to_number(to_char(fecha,'mm')) = ln_mes;
        If Result is null then
           --Se busca en el mes anterior
           lb_exception := false;
           If ln_mes = 1 then
              ln_mes := 12; ln_ano := ln_ano - 1;
           else
              ln_mes := ln_mes - 1;
           end if;
        end if;
        ln_count := ln_count + 1;
  end loop;

  Return(Result);

end USF_VTA_DOL_PROM_X_MES;
/

prompt
prompt Creating function USF_CAM_CALC_COSTO_MAQ
prompt ========================================
prompt
create or replace function cantabria.USF_CAM_CALC_COSTO_MAQ(
 an_ano number,
 an_mes number,
 as_maquina maquina.cod_maquina%type)

 Return  number is

 Result number(13,2);
 ln_ano number(4);
 ln_mes number(2);
 ls_categoria maq_categoria_costeo.categoria%type;
 ln_count number(2);

Begin
 Select count(*)
   into ln_count
   from maq_categoria_costeo_det
   where cod_maquina = as_maquina;
 If ln_count = 1 then
   Select categoria
     into ls_categoria
     from maq_categoria_costeo_det
    where cod_maquina = as_maquina;
 Elsif ln_count = 0 then
   Raise_Application_Error(-20000,'NO SE ENCONTRO CATEGORIA PARA MAQUINA '||as_maquina||' A?O '||To_Char(an_ano)||' MES '||To_Char(an_mes));
 Elsif ln_count > 0 then
   Raise_Application_Error(-20000,'SE ENCONTRO MAS DE UNA CATEGORIA PARA MAQUINA '||as_maquina||' A?O '||To_Char(an_ano)||' MES '||To_Char(an_mes));
 End if;
 --Costo de la categoria encontrada
 Select count(*)
   into ln_count
   from maq_cat_costeo_valorizacion mcv
  where categoria = ls_categoria and
        mcv.ano = an_ano and
        mcv.mes = an_mes;
 If ln_count = 1 then
   Select costo_x_und
     into result
     from maq_cat_costeo_valorizacion mcv
    where categoria = ls_categoria and
          mcv.ano = an_ano and
          mcv.mes = an_mes;
 Elsif ln_count = 0 then
   Raise_Application_Error(-20000,'NO SE ENCONTRO COSTO POR UNIDAD PARA CATEGORIA MAQ :'||ls_categoria||' MAQ '||as_maquina||' A?O '||To_Char(an_ano)||' MES '||To_Char(an_mes));
 Elsif ln_count > 0 then
   Raise_Application_Error(-20000,'SE ENCONTRO MAS DE UN COSTO POR UNIDAD PARA CATEGORIA MAQ '||ls_categoria||' MAQ '||as_maquina||' A?O '||To_Char(an_ano)||' MES '||To_Char(an_mes));
 End if;
 -- Dolarizo
 result := result/USF_VTA_DOL_PROM_X_MES(an_ano, an_mes);

 If result is null then
   Result := 0;
 end if;

 return(Result);

end USF_CAM_CALC_COSTO_MAQ;
/

prompt
prompt Creating function USF_CAM_CALC_COSTO_MAQ_CAMPO
prompt ==============================================
prompt
create or replace function cantabria.usf_cam_calc_costo_maq_campo(
  as_corr_corte in campo_ciclo.corr_corte%type,
  as_labor in labor.cod_labor%type,
  as_ejecutor in ejecutor.cod_ejecutor%type
  ) return number is

  Result number;
begin
      Select Sum(sum( Nvl(pod.cant_labor,0)- Nvl(pod.horas_inciden,0)) * USF_CAM_CALC_COSTO_MAQ(To_Number(To_Char(po.fecha,'yyyy')), To_Number(To_Char(po.fecha,'mm')), pod.cod_maquina)) /Sum(sum( Nvl(pod.cant_labor,0)- Nvl(pod.horas_inciden,0)))
        into Result
        from orden_trabajo ot, operaciones o, pd_ot_det pod, pd_ot po, labor_ejecutor le, labor l,
             campo_ciclo cc, campo c
       where ot.nro_orden     = o.nro_orden     and
             o.oper_sec       = pod.oper_sec    and
             pod.nro_parte    = po.nro_parte    and
             pod.cod_labor    = le.cod_labor    and
             pod.cod_ejecutor = le.cod_ejecutor and
             le.cod_labor     = l.cod_labor     and
             ot.nro_orden     = cc.nro_orden    and
             cc.cod_campo     = c.cod_campo     and
             pod.cod_labor    = as_labor        and
             pod.cod_ejecutor = as_ejecutor     and
             cc.corr_corte    = as_corr_corte
    group by To_Number(To_Char(po.fecha,'yyyy')), To_Number(To_Char(po.fecha,'mm')), pod.cod_maquina  ;

  RETURN(Result);
 exception
   when others then
       Raise_Application_error(-20000,'ERror en '||as_corr_corte||' labor '||as_labor||' ejecutro'||as_ejecutor);
END usf_cam_calc_costo_maq_campo;
/

prompt
prompt Creating function USF_CAM_CALC_COSTO_MAQ_LABOR
prompt ==============================================
prompt
create or replace function cantabria.usf_cam_calc_costo_maq_labor(
  an_ano in number,
  an_mes in number,
  as_labor in labor.cod_labor%type,
  as_ejecutor in ejecutor.cod_ejecutor%type
  ) return number is

  Result number;
begin
      Select Sum(sum( Nvl(pod.cant_labor,0)- Nvl(pod.horas_inciden,0)) * USF_CAM_CALC_COSTO_MAQ(an_ano, an_mes, pod.cod_maquina)) /Sum(sum( Nvl(pod.cant_labor,0)- Nvl(pod.horas_inciden,0)))
        into Result
        from orden_trabajo ot, operaciones o, pd_ot_det pod, pd_ot po, labor_ejecutor le, labor l,
             campo_ciclo cc, campo c
       where ot.nro_orden     = o.nro_orden     and
             o.oper_sec       = pod.oper_sec    and
             pod.nro_parte    = po.nro_parte    and
             pod.cod_labor    = le.cod_labor    and
             pod.cod_ejecutor = le.cod_ejecutor and
             le.cod_labor     = l.cod_labor     and
             pod.cod_labor    = as_labor        and
             pod.cod_ejecutor = as_ejecutor     and
             ot.nro_orden     = cc.nro_orden    and
             cc.cod_campo     = c.cod_campo     and
             To_Number(To_Char(po.fecha,'yyyy'))         = an_ano     and
             To_Number(To_Char(po.fecha,'mm'))         = an_mes
    group by To_Number(To_Char(po.fecha,'mm')), pod.cod_maquina  ;

  RETURN(Result);
END usf_cam_calc_costo_maq_labor;
/

prompt
prompt Creating function USF_CAM_CAMPO_CENCOS
prompt ======================================
prompt
create or replace function cantabria.USF_CAM_CAMPO_CENCOS
(as_cencos centros_costo.cencos%type
)
 return  char is
 --Variables
 ln_count number(3);
 ls_campo campo.cod_campo%type;

Begin
 -- Verificar si la labor esta en la Lista de Labores de control quimico
 Select count(*)
   into ln_count
   from campo c
  where c.cencos = as_cencos and c.flag_estado = 1;

 If ln_count = 1 then
