prompt Creating function USF_CAM_CANT_AVANCE
prompt =====================================
prompt
create or replace function cantabria.USF_CAM_CANT_AVANCE
(as_corr_corte in campo_ciclo.corr_corte%type,
 as_labor      in labor.cod_labor%type,
 ad_fecha      in date) return number is

Result number(7,3);

begin

 select nvl(sum(nvl(cant_avance,0)),0)
   into Result
   from campo_ciclo cc, orden_trabajo ot, pd_ot_det pod, pd_ot po
  where cc.nro_orden = ot.nro_orden
    and ot.nro_orden = pod.nro_orden
    and pod.nro_parte = po.nro_parte
    and cc.corr_corte = as_corr_corte
    and pod.cod_labor = as_labor
    and po.fecha <= ad_fecha;

  return(Result);

end USF_CAM_CANT_AVANCE;
/

