prompt
prompt Creating function USF_CAM_CONFIN_OS_CAMPO
prompt =========================================
prompt
create or replace function cantabria.usf_cam_confin_os_campo(
       as_labor in labor.cod_labor%type,
       as_frente_cosecha in frente_cosecha.frente_cosecha%type
) return concepto_financiero.confin%type is
  ls_confin concepto_financiero.confin%type;
Begin
  If as_frente_cosecha in ('PAP','PAA') or as_frente_cosecha is null then--Servicio para Campos Propios
     Select l.confin
     into ls_confin
     from labor l
     where l.cod_labor = as_labor;
  else --Servicio Para Sembradores
     Select l.confin_3ro
     into ls_confin
     from labor l
     where l.cod_labor = as_labor;
  end if;
  return(ls_confin);
end usf_cam_confin_os_campo;
/

prompt
prompt Creating function USF_CAM_CORR_CORTE_FEC_AGOSTE
prompt ===============================================
prompt
create or replace function cantabria.usf_cam_corr_corte_fec_agoste(as_corr_corte campo_ciclo.corr_corte%type)
return date is
  ln_count                 number(1) ;
  ls_labor_agoste          prod_param.labor_agoste%type ;
  ld_fec_agoste            operaciones.fec_inicio%type ;
BEGIN

  -- Capturando labor de cosecha
  SELECT p.labor_agoste
  INTO ls_labor_agoste
  FROM prod_param p
  WHERE p.reckey='1' ;

  -- Capturando fecha de cosecha
  SELECT count(*)
    INTO ln_count
    FROM operaciones o, campo_ciclo cc
   WHERE o.nro_orden = cc.nro_orden AND
         o.cod_labor  = ls_labor_agoste AND
         cc.corr_corte = as_corr_corte ;

  IF ln_count > 0 THEN
     SELECT o.fec_inicio
       INTO ld_fec_agoste
       FROM operaciones o, campo_ciclo cc
      WHERE o.nro_orden = cc.nro_orden AND
            o.cod_labor  = ls_labor_agoste AND
            cc.corr_corte = as_corr_corte ;
  END IF ;

  RETURN(ld_fec_agoste) ;

END usf_cam_corr_corte_fec_agoste ;
/

prompt
prompt Creating function USF_CAM_CORR_CORTE_FEC_COSECH
prompt ===============================================
prompt
create or replace function cantabria.usf_cam_corr_corte_fec_cosech(as_corr_corte campo_ciclo.corr_corte%type)
return date is
  ln_count                 number(1) ;
  ls_labor_cosecha         prod_param.labor_cosecha%type ;
  ld_fec_cosecha           operaciones.fec_inicio%type ;
BEGIN

  -- Capturando labor de cosecha
  SELECT p.labor_cosecha
  INTO ls_labor_cosecha
  FROM prod_param p
  WHERE p.reckey='1' ;

  -- Capturando fecha de cosecha
  SELECT count(*)
    INTO ln_count
    FROM operaciones o, campo_ciclo cc
   WHERE o.nro_orden = cc.nro_orden AND
         o.cod_labor  = ls_labor_cosecha AND
         cc.corr_corte = as_corr_corte ;

  IF ln_count > 0 THEN
     SELECT o.fec_inicio
       INTO ld_fec_cosecha
       FROM operaciones o, campo_ciclo cc
      WHERE o.nro_orden = cc.nro_orden AND
            o.cod_labor  = ls_labor_cosecha AND
            cc.corr_corte = as_corr_corte ;
  END IF ;

  RETURN(ld_fec_cosecha) ;

END usf_cam_corr_corte_fec_cosech ;
/

prompt
prompt Creating function USF_CAM_CORR_CORTE_MES_COSECH
prompt ===============================================
prompt
create or replace function cantabria.usf_cam_corr_corte_mes_cosech(as_corr_corte campo_ciclo.corr_corte%type)
return number is
  ln_count                 number(1) ;
  ln_result                number(6,2);
  ls_labor_cosecha         prod_param.labor_cosecha%type ;
  ld_fec_nac_plnt          campo_ciclo.fec_nac_plnt%type ;
  ld_fec_cosecha           operaciones.fec_inicio%type ;
BEGIN

  -- Capturando labor de cosecha
  SELECT p.labor_cosecha
  INTO ls_labor_cosecha
  FROM prod_param p
  WHERE p.reckey='1' ;

  -- Capturando fecha de inicio de cultivo
  SELECT cc.fec_nac_plnt
  INTO ld_fec_nac_plnt
  FROM campo_ciclo cc
  WHERE cc.corr_corte = as_corr_corte ;

  -- Capturando fecha de cosecha
  SELECT count(*)
    INTO ln_count
    FROM operaciones o, campo_ciclo cc
   WHERE o.nro_orden = cc.nro_orden AND
         o.cod_labor  = ls_labor_cosecha AND
         cc.corr_corte = as_corr_corte ;

  IF ln_count > 0 THEN
     SELECT o.fec_inicio
       INTO ld_fec_cosecha
       FROM operaciones o, campo_ciclo cc
      WHERE o.nro_orden = cc.nro_orden AND
            o.cod_labor  = ls_labor_cosecha AND
            cc.corr_corte = as_corr_corte ;
  END IF ;

  IF (ld_fec_nac_plnt is null) OR (ld_fec_cosecha is null) THEN
     RETURN(0) ;
  END IF ;

  -- Dias de cosecha
  ln_result := ld_fec_cosecha - ld_fec_nac_plnt ;
  -- Mes de cosecha
  ln_result := ROUND( ln_result / 30.416666, 2 ) ;

  RETURN(ln_result);

END usf_cam_corr_corte_mes_cosech;
/

prompt
prompt Creating function USF_CAM_COSTO_ANO
prompt ===================================
prompt
create or replace function cantabria.USF_CAM_COSTO_ANO
(as_grupo in char,
 as_valor_dato varchar2,
 as_ejecutor ejecutor.cod_ejecutor%type,
 an_ano number,
 as_tipo_dato char)

return number is

Result number(20,7);
ln_precio number(20,7);
ld_fec_ini date;
ld_fec_fin date;
ls_labor labor.cod_labor%type;
ls_articulo articulo.cod_art%type;
ln_ratio number(20,7);
ln_fijo number(20,7);

begin

if as_grupo <> 'FIJO' then

    -- 1) PRECIO
    IF as_tipo_dato = 'L' THEN
       ls_labor := as_valor_dato;
       BEGIN
         SELECT costo_unitario
           INTO ln_precio
           FROM labor_ejecutor le
          WHERE le.cod_labor = ls_labor AND
                le.cod_ejecutor = as_ejecutor;
       EXCEPTION
         WHEN NO_DATA_FOUND THEN
             ln_precio := 0;
       END;
    ELSIF as_tipo_dato = 'A' THEN

      --calculando fechas anuales
      SELECT MIN(cp.del_dia), MAX(cp.al_dia)
        INTO ld_fec_ini, ld_fec_fin
        FROM calendario_produccion cp
       WHERE TO_CHAR(cp.fecha_prod,'YYYY') = TO_CHAR(an_ano);

       ls_labor      := SUBSTR(as_valor_dato,1,INSTR(as_valor_dato,'@')-1);
       ls_articulo   := SUBSTR(as_valor_dato,INSTR(as_valor_dato,'@')+1,LENGTH(as_valor_dato));
       usp_cam_calculo_art_pre(ls_labor, ls_articulo, ld_fec_ini, ld_fec_fin, ln_precio);
    END IF;

   --2) RATIO. (Para el caso de articulo no se utiliza Ejecutor)
   IF as_tipo_dato = 'L' THEN
      SELECT SUM(monto)/SUM(tm_cana_sucia)
        INTO ln_ratio
        FROM cmp_cosecha_costo_mov_hist cm
       WHERE ano = an_ano AND
             frente_cosecha IN (SELECT frente_cosecha FROM tt_frente_cosecha) AND
             cm.cos_tipo_dato = as_tipo_dato AND
             cm.valor_dato = as_valor_dato AND
             cm.cod_ejecutor = as_ejecutor;
    ELSIF as_tipo_dato = 'A' THEN
      SELECT SUM(monto)/SUM(tm_cana_sucia)
        INTO ln_ratio
        FROM cmp_cosecha_costo_mov_hist cm
       WHERE ano = an_ano AND
             frente_cosecha IN (SELECT frente_cosecha FROM tt_frente_cosecha) AND
             cm.cos_tipo_dato = as_tipo_dato AND
             cm.valor_dato = as_valor_dato;
    ELSIF as_tipo_dato = 'B' THEN
      SELECT SUM(monto)/SUM(tm_cana_sucia)
        INTO ln_ratio
        FROM cmp_cosecha_costo_mov_hist cm
       WHERE ano = an_ano AND
             frente_cosecha IN (SELECT frente_cosecha FROM tt_frente_cosecha) AND
             cm.cos_tipo_dato = as_tipo_dato AND
             cm.valor_dato = as_valor_dato;
    END IF;

   -- 3) COSTO
   --Si tipo dato = 'BALANZA' ratio = 1.000, precio = ratio
   if as_tipo_dato <> 'B' then

      Result := NVL(ln_precio,0) * NVL(ln_ratio,0);

   elsif as_tipo_dato = 'B' then

      Result := nvl(ln_ratio,0);

   end if;

ELSE

    --calculando fechas anuales
    SELECT MIN(cp.del_dia), MAX(cp.al_dia)
      INTO ld_fec_ini, ld_fec_fin
      FROM calendario_produccion cp
     WHERE TO_CHAR(cp.fecha_prod,'YYYY') = TO_CHAR(an_ano);

   usp_cam_calc_costo_fijo('36100', ld_fec_ini, ld_fec_fin, Result, ln_fijo);

end if;

return(Result);

end USF_CAM_COSTO_ANO;
/

prompt
prompt Creating function USF_CAM_COSTO_ART_STAND
prompt =========================================
prompt
create or replace function cantabria.usf_cam_costo_art_stand(as_nro_parte in pd_ot_det.nro_parte%type,
                  an_nro_item in pd_ot_det.nro_item%type, as_tipo in char) return number is
  Result number;

  CURSOR c_insumos IS
  SELECT pi.cantidad, pi.costo_insumo, a.costo_ult_compra
  FROM pd_ot_insumos pi, articulo a
  WHERE pi.cod_art = a.cod_art AND
        pi.nro_parte = as_nro_parte AND
        pi.nro_item = an_nro_item ;

BEGIN
  result := 0 ;
  FOR c_i IN C_INSUMOS LOOP
      IF as_tipo='S' THEN
         result := result + NVL(c_i.cantidad,0) * NVL(c_i.costo_ult_compra,0) ;
      ELSE
         result := result + NVL(c_i.cantidad,0) * NVL(c_i.costo_insumo,0) ;
      END IF ;
  END LOOP ;

  RETURN(Result);
END usf_cam_costo_art_stand;
/

prompt
prompt Creating function USF_CAM_HAS_AVANCE
prompt ====================================
prompt
create or replace function cantabria.USF_CAM_HAS_AVANCE
(an_ano number,
 an_mes number,
 as_reporte reportes.reporte%type)
 return  number is

 ln_has number(8,3);

Begin


 Select sum(pod.cant_avance)
   into ln_has
   from campo_ciclo cc, campo c, orden_trabajo ot, pd_ot_det pod, pd_ot po
  where cc.nro_orden = ot.nro_orden and
        ot.nro_orden = pod.nro_orden and
        pod.nro_parte = po.nro_parte and
        cc.cod_campo = c.cod_campo and
        c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha) and
        To_Number(To_Char(po.fecha,'yyyy')) = an_ano and
        To_Number(To_Char(po.fecha,'mm')) = an_mes and
        pod.cod_labor in (select descripcion from rpt_grupo where reporte = as_reporte) and
        pod.und_avance = 'HAS';

return(ln_has);

end USF_CAM_HAS_AVANCE;
/

prompt
prompt Creating function USF_CAM_COSTO_FIJO_CTRL_MLZA
prompt ==============================================
prompt
create or replace function cantabria.USF_CAM_COSTO_FIJO_CTRL_MLZA
(as_cencos in centros_costo.cencos%type,
 an_ano in number,
 an_mes_ini in number,
 an_mes_fin in number
) return number is

Result number(20,7);
ln_mes number(2);
ln_cfijo number(15,5);
ln_count number(2);
ls_flag_cierre char(1);
ln_importe number(8,3);
ln_precio number(8,3);
ln_has number(8,3);
ln_cfijo_acum number(12,3);
ln_has_acum number(12,3);
ls_reporte reportes.reporte%type;

BEGIN
ls_reporte := 'CtrMalQm';
ln_cfijo_acum := 0; ln_has_acum := 0;
Delete from tt_cntbl_centros_costo;
Insert into tt_cntbl_centros_costo(cencos) values (as_cencos);
-- Test
--Insert into tt_frente_cosecha(frente_cosecha) values('PAA');
--Insert into tt_frente_cosecha(frente_cosecha) values('PAP');
-- Fin Test
For ln_mes in an_mes_ini..an_mes_fin loop

    -- Gastos del Mes
    ln_precio := null; ln_importe := null; ln_cfijo := null;
    ln_count := 0; ls_flag_cierre := null; ln_has := null;
    -- Flag Cierre>> -- 0: cerrado 1:abierto
    Select count(cc.flag_cierre_mes)
      into ln_count
      from cntbl_cierre cc
     where cc.ano = an_ano and cc.mes = ln_mes;

    ls_flag_cierre := 1;
    If ln_count = 1 then
      Select cc.flag_cierre_mes
      into ls_flag_cierre
      from cntbl_cierre cc
      where cc.ano = an_ano and cc.mes = ln_mes;
    End if;

    If ls_flag_cierre = '0' then
        -- Devuelve costo fijo de Contabilidad
        USP_CNTBL_DET_GASTOS_DOL(to_char(an_ano), lpad(to_char(ln_mes),2,'0'), ln_cfijo);
    Else
    --Si el Mes contable no esta cerrado
        -- Ejecucion Presupuestal
        Select sum(nvl(pe.importe,0)) * -1
           into ln_importe
           from presupuesto_ejec pe
          where cencos = as_cencos
            and ano = an_ano
            and To_Number(To_Char(fecha,'mm')) = ln_mes;
            --and pe.cnta_prsp not in (select descripcion from rpt_grupo where reporte = 'CPRESOBR');

        -- Maquinaria:
         Select sum( sum(nvl(pd.cant_labor,0) - nvl(pd.horas_inciden,0)) * USF_CAM_CALC_COSTO_MAQ(an_ano, ln_mes, pd.cod_maquina))
           into ln_precio
           from pd_ot p, pd_ot_det pd,
                operaciones o,
                maquina m
          where p.nro_parte     = pd.nro_parte         and
                p.ot_adm        IN ('CAMPO','DMA_OT')  and
                pd.oper_sec     = o.oper_sec           and
                pd.cod_maquina  = m.cod_maquina        and
                pd.cencos       = as_cencos and
                to_number(to_char(p.fecha,'mm')) = ln_mes    and
                to_number(to_char(p.fecha,'yyyy'))= an_ano
       group by pd.cod_maquina;


        ln_cfijo := nvl(ln_importe,0) + nvl(ln_precio,0);
    end if;
    ln_cfijo_acum := ln_cfijo_acum + ln_cfijo;
    -- Has del Mes. (Utiliza tt_frente_cosecha)
    ln_has := USF_CAM_HAS_AVANCE(an_ano, ln_mes, ls_reporte);
    ln_has_acum := ln_has_acum + nvl(ln_has,0);

end loop;


Result := ln_cfijo_acum/ln_has_acum;


return(Result);

end USF_CAM_COSTO_FIJO_CTRL_MLZA;
/

prompt
prompt Creating function USF_CAM_COSTO_FIJO_HNETA
prompt ==========================================
prompt
create or replace function cantabria.USF_CAM_COSTO_FIJO_HNETA
(as_cencos in centros_costo.cencos%type,
 an_ano in number,
 an_mes_ini in number,
 an_mes_fin in number
) return number is
-- Costo Fijo x Ha. Neta
Result number(20,7);
ln_mes number(2);
ln_count number(2);
ls_flag_cierre char(1);
ln_imp_dol_acum number(12,3);
ln_has number(8,3);
ln_cfijo_acum number(12,3);
ln_has_acum number(12,3);
ls_aux varchar(10);
ls_frente varchar2(100);
ln_imp_dol number(12,3);
ln_costo_fijo number(12,3);--no se utiliza solo xq es variable de salida de usp_cam_costo_fijo_ctrl_maleza
--Cursor
  Cursor c_frente is
  select frente_cosecha from tt_frente_cosecha
order by frente_cosecha;

BEGIN
-- Test
--Insert into tt_frente_cosecha(frente_cosecha) values('PAA');
--Insert into tt_frente_cosecha(frente_cosecha) values('PAP');
-- Fin Test
for c_f in c_frente loop
    ls_aux    := trim(c_f.frente_cosecha);
    ls_frente := ls_frente||'@'||trim(ls_aux);
end loop;
ln_imp_dol_acum := 0; ln_has_acum := 0;
For ln_mes in an_mes_ini..an_mes_fin loop
    ln_imp_dol := null; ln_has := null;
    Select count(*) into ln_count
      from cmp_cosecha_costo_mov_hist c
     where ano = an_ano and mes = ln_mes and c.valor_dato= 'CF_CtrlMaleza'||ls_frente;
    --ln_count := 0;
    If ln_count = 1 then
      Select c.monto, c.tm_cana_sucia into ln_imp_dol, ln_has
        from cmp_cosecha_costo_mov_hist c
       where ano = an_ano and mes = ln_mes and c.valor_dato= 'CF_CtrlMaleza'||ls_frente;
    else
        USP_CAM_COSTO_FIJO_CTRL_MALEZA(an_ano, ln_mes,ln_costo_fijo,ln_imp_dol,ln_has);
    end if;
    ln_imp_dol_acum := ln_imp_dol_acum + ln_imp_dol;
    ln_has_acum := ln_has_acum + ln_has;

end loop;


Result := ln_imp_dol_acum/ln_has_acum;


return(Result);

end USF_CAM_COSTO_FIJO_HNETA;
/

prompt
prompt Creating function USF_PLA_CAL_TIPO_CAMBIO
prompt =========================================
prompt
create or replace function cantabria.USF_PLA_CAL_TIPO_CAMBIO(
       adi_fec_proceso  in date
) return number is

  ln_tipcam   calendario.vta_dol_prom%type ;
  ln_contador number(2) ;

BEGIN

-- Determina el tipo de cambio del dolar
Select count(*)
  into ln_contador
  from calendario c
  where trunc(c.fecha) = trunc(adi_fec_proceso);

IF ln_contador > 0 THEN
   SELECT c.vta_dol_prom
     INTO ln_tipcam
     FROM calendario c
    WHERE trunc(c.fecha) = TRUNC(adi_fec_proceso);
else
   ln_tipcam := 0;
END IF ;

RETURN(ln_tipcam) ;

END USF_PLA_CAL_TIPO_CAMBIO ;
/

prompt
prompt Creating function USF_CAM_COSTO_MANO_OBRA
prompt =========================================
prompt
create or replace function cantabria.usf_cam_costo_mano_obra(
       as_nro_parte in pd_ot_det.nro_parte%type,
       an_nro_item in pd_ot_det.nro_item%type) return number is
  Result number;

  CURSOR c_mano_obra IS
  SELECT pa.nro_horas, pa.costo_horas, pa.factor
    FROM pd_ot_asistencia pa
   WHERE pa.no_parte=as_nro_parte AND
         pa.nro_item=an_nro_item ;

  ln_tipo_cambio       calendario.vta_dol_prom%type ;
  ld_fecha             pd_ot.fecha%type ;
  ln_count             Number(2) ;
BEGIN

  Result := 0 ;

  -- Busca fecha de parte diario y tipo de cambio
  SELECT pd.fecha
    INTO ld_fecha
    FROM pd_ot pd
   WHERE pd.nro_parte = as_nro_parte ;

  ln_tipo_cambio := usf_pla_cal_tipo_cambio( trunc( ld_fecha ) ) ;

  SELECT count(*)
    INTO ln_count
    FROM pd_ot_asistencia pa
  WHERE pa.no_parte=as_nro_parte AND
        pa.nro_item=an_nro_item ;

  IF ln_count > 0 THEN
     FOR c_m IN c_mano_obra LOOP
         Result := Result + NVL(c_m.nro_horas,0) * NVL(c_m.costo_horas,0) * NVL(c_m.factor,0) ;
     END LOOP ;
  ELSE
     SELECT NVL(le.costo_unitario,0)* NVL(pl.cant_labor,0)
       INTO result
       FROM pd_ot_det pl, labor_ejecutor le
      WHERE pl.cod_labor = le.cod_labor AND
            pl.cod_ejecutor = le.cod_ejecutor AND
            pl.nro_parte=as_nro_parte AND
            pl.nro_item=an_nro_item ;
  END IF ;

  IF ln_tipo_cambio IS NULL OR ln_tipo_cambio = 0 THEN
     Result:= Result / 3.5 ;
  ELSE
     Result:= Result / ln_tipo_cambio ;
  END IF ;

  RETURN(Result);

END usf_cam_costo_mano_obra;
/

