prompt
prompt Creating function USF_CAM_EDAD_PPTO_X_CAMPO
prompt ===========================================
prompt
create or replace function cantabria.USF_CAM_EDAD_PPTO_X_CAMPO
(correlativo in campo_ciclo.corr_corte%type) return number is
  Result number;

ls_valor         char(8);
ld_nac_plnt      date;
ld_fec_cosecha   date;
ln_nro_orden     char(10);

begin

--obteniendo codigo final
select labor_cosecha into ls_valor from prod_param where reckey = 1;

--obteniendo el numero de orden
select nro_orden, fec_nac_plnt
  into ln_nro_orden, ld_nac_plnt
  from campo_ciclo cc
 where cc.corr_corte = correlativo ;

--obteniendo la fecha de inicio
select fec_inicio
  into ld_fec_cosecha
  from operaciones
 where ( nro_orden  = ln_nro_orden )
   and ( cod_labor  = ls_valor ) ;

--obteniendo edad
result := round(( ( ld_fec_cosecha - ld_nac_plnt ) / 30.416667 ),2);

  return(Result);

end USF_CAM_EDAD_PPTO_X_CAMPO;
/

prompt
prompt Creating function USF_CAM_EDAD_X_FRENTE
prompt =======================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_CAM_EDAD_X_FRENTE
(ac_frente_cosecha IN frente_cosecha.frente_cosecha%TYPE, ad_fecha IN DATE)
RETURN NUMBER IS
ln_result NUMBER(5,2);

BEGIN
    SELECT ROUND(AVG((ad_fecha - cc.fec_nac_plnt)/30.416667),2)
      INTO ln_result
      FROM campo_ciclo cc, campo c
     WHERE cc.cod_campo = c.cod_campo AND
           c.frente_cosecha = ac_frente_cosecha;

  RETURN(ln_result);

END USF_CAM_EDAD_X_FRENTE;
/

