prompt Creating function USF_CAM_ESTA_PROD_CAMP_DIA
prompt ============================================
prompt
create or replace function cantabria.usf_cam_esta_prod_camp_dia
(correlativo in campo_ciclo.corr_corte%type, fec_ini in date)
return number is
Result number;

begin
     select round(SUM((nvl(ccd.cana_sucia_qmd,0) * nvl(ccd.sacar_cana_qmd,0))
              + (nvl(ccd.cana_sucia_cruda,0) * nvl(ccd.sacar_cana_cruda,0))) /
              SUM((nvl(ccd.cana_sucia_qmd,0) + nvl(ccd.cana_sucia_cruda,0))) , 2 )
         into result
         from campo_ciclo_diario ccd
        where ccd.corr_corte = correlativo
          and fecha = fec_ini;


