prompt
prompt Creating function USF_CAM_FERTILIZACION
prompt =======================================
prompt
create or replace function cantabria.USF_CAM_FERTILIZACION
(as_nro_orden campo_ciclo.nro_orden%type ,
 as_subgrupo   rpt_subgrupo.subgrupo%type  )

 return varchar2 is
  lc_cadena varchar2 (25);


 ld_hora_inicio date ;
 ln_cantidad   Number (12,4) ;
 ln_formula    Number (13,2) ;

begin

IF as_subgrupo = '3' THEN
   SELECT Min(pl.hora_inicio),Sum(pl.cant_labor)
     INTO ld_hora_inicio,ln_cantidad
     FROM operaciones op,pd_ot_det pl,rpt_subgrupo rsg
    WHERE (op.oper_sec   = pl.oper_sec  )  AND
         ((op.nro_orden  = as_nro_orden )) AND
         ((rsg.reporte   = 'RPTINV'     )  AND
          (rsg.grupo     = 'FERTI'      )  AND
          (rsg.subgrupo  = as_subgrupo  )) AND
          (RTRIM(LTRIM(pl.cod_labor)) = LTRIM(RTRIM(rsg.descripcion)) )
   GROUP BY op.nro_orden      ;

   --CALCULAR NITROGENO
   IF ln_cantidad > 0 THEN
      ln_formula := Round((ln_cantidad * 0.035) * 1000 ,2) ;
   ELSE
      ln_formula := Round(ln_cantidad,2) ;
   END IF;

ELSE
   SELECT Min(pl.hora_inicio),Sum(pi.cantidad)
     INTO ld_hora_inicio,ln_cantidad
     FROM operaciones op,pd_ot_det pl,pd_ot_insumos pi,rpt_subgrupo rsg
    WHERE (op.oper_sec   = pl.oper_sec  )  AND
         ((pl.nro_parte  = pi.nro_parte )  AND
          (pl.nro_item   = pi.nro_item  )) AND
         ((op.nro_orden  = as_nro_orden )) AND
         ((rsg.reporte   = 'RPTINV'     )  AND
          (rsg.grupo     = 'FERTI'      )  AND
          (rsg.subgrupo  = as_subgrupo  )) AND
          (RTRIM(LTRIM(pl.cod_labor)) = LTRIM(RTRIM(rsg.descripcion)) ) AND
         ((pi.cod_art   = '8209.0001'))
   GROUP BY op.nro_orden      ;

   --CALCULAR NITROGENO
   IF ln_cantidad > 0 THEN
      ln_formula := Round((ln_cantidad * 0.46) * 1000 ,2) ;
   ELSE
      ln_formula := Round(ln_cantidad,2) ;
   END IF;

END IF;



lc_cadena := to_char(ld_hora_inicio,'dd/mm/yyyy')||to_char(ln_formula) ;

  return(lc_cadena);
end USF_CAM_FERTILIZACION;
/

