prompt
prompt Creating function USF_CAM_IMPUREZA
prompt ==================================
prompt
create or replace function cantabria.usf_cam_impureza(as_corr_corte in char, ad_fec_ini in date, ad_fec_fin in date) return number is
  Result number;

  ln_total             number(13,6) ;
  ln_cana_limpia       number(12,3) ;
  ls_cod_calc_impureza lab_calculo.cod_calculo%type ;
  ls_cod_cana_limpia   lab_calculo.cod_calculo%type ;

  CURSOR c_movimiento IS
  SELECT lcc.fecha,
         sum( decode(lcc.cod_calculo, 'C003', NVL(lcc.dia,0), 0) ) as impureza,
         sum( decode(lcc.cod_calculo, 'C007', NVL(lcc.dia,0), 0) ) as cana_limpia
  FROM lab_calculo_campo lcc
  WHERE lcc.corr_corte=as_corr_corte and
        lcc.fecha between TRUNC(ad_fec_ini) and TRUNC(ad_fec_fin)+0.999
  GROUP by lcc.fecha ;
BEGIN
  result := 0 ;
  ln_total := 0 ;
  ln_cana_limpia := 0 ;

  FOR c_m IN c_movimiento LOOP
      ln_cana_limpia := ln_cana_limpia + c_m.cana_limpia ;
      ln_total := ln_total + c_m.impureza * c_m.cana_limpia ;
  END LOOP ;

  IF ln_cana_limpia > 0 THEN
     Result := ln_total / ln_cana_limpia ;
  ELSE
     Result := 0 ;
  END IF ;

  RETURN(Result);

END usf_cam_impureza;

