 SUM(decode( t.cod_calculo, 'C013', t.dia, 0)) as ton_pol_apar,
 SUM(decode( t.cod_calculo, 'C015', t.dia, 0)) as ton_pol_cana,
 SUM(decode( t.cod_calculo, 'C017', t.dia, 0)) as pol_porc_cana,
 SUM(decode( t.cod_calculo, 'C019', t.dia, 0)) as extrac,
