prompt
prompt Creating function USF_CAM_LAB_X_PROC
prompt ====================================
prompt
create or replace function cantabria.usf_cam_lab_x_proc (an_campo campo.cod_campo%type,
    an_cencos1 campo.cencos%type, an_cencos2 campo.cencos%type)
return char is

  ls_cencos campo.cencos%type;
  ls_result    char(60);
begin
  --Calculamos Total de Costo de Insumos Por Operacisn
  if an_campo is null then
     ls_cencos := an_cencos1;
  else
     ls_cencos := an_cencos2;
  end if;

  Select cc.desc_cencos into ls_result
    from centros_costo cc where cc.cencos = ls_cencos;

  ls_result := ls_cencos || ' ' || TRIM(ls_result);

  return(ls_result);
end usf_cam_lab_x_proc;
/

prompt
prompt Creating function USF_CAM_MES_COSECH
prompt ====================================
prompt
create or replace function cantabria.usf_cam_mes_cosech(as_nro_orden operaciones.nro_orden%type)
return number is
  ln_result                number(6,2);
  ls_labor_cosecha         prod_param.labor_cosecha%type ;
  ld_fec_nac_plnt          campo_ciclo.fec_nac_plnt%type ;
  ld_fec_cosecha           operaciones.fec_inicio%type ;
BEGIN

  -- Capturando labor de cosecha
  SELECT p.labor_cosecha
  INTO ls_labor_cosecha
  FROM prod_param p
  WHERE p.reckey='1' ;

  -- Capturando fecha de inicio de cultivo
  SELECT cc.fec_nac_plnt
  INTO ld_fec_nac_plnt
  FROM campo_ciclo cc
  WHERE cc.nro_orden = as_nro_orden ;

  -- Capturando fecha de cosecha
  SELECT o.fec_inicio
    INTO ld_fec_cosecha
    FROM operaciones o
   WHERE o.nro_orden = as_nro_orden    AND
         o.cod_labor  = ls_labor_cosecha ;

  IF (ld_fec_nac_plnt is null) OR (ld_fec_cosecha is null) THEN
     RETURN(0) ;
  END IF ;

  -- Dias de cosecha
  ln_result := ld_fec_cosecha - ld_fec_nac_plnt ;
  -- Mes de cosecha
  ln_result := ROUND( ln_result / 30.416666, 2 ) ;

  RETURN(ln_result);

END usf_cam_mes_cosech;
/

prompt
prompt Creating function USF_CAM_NRO_LIBRO
prompt ===================================
prompt
create or replace function cantabria.usf_cam_nro_libro(
as_nro_os in orden_servicio.nro_os%type,
as_origen in origen.cod_origen%type
) return cntbl_libro.nro_libro%type is
  ln_nro_libro cntbl_libro.nro_libro%type;
begin
  Begin
    select f.nro_libro
    into ln_nro_libro
    from orden_servicio_det_cana osd, campo_ciclo cc, campo c, frente_cosecha f
    where osd.corr_corte = cc.corr_corte and
    cc.cod_campo = c.cod_campo and
    c.frente_cosecha = f.frente_cosecha and
    osd.nro_os = as_nro_os and
    osd.cod_origen = as_origen
    group by f.nro_libro;
  EXCEPTION
     WHEN NO_DATA_FOUND THEN
          RAISE_APPLICATION_ERROR(-20000,'NO SE PUDO ESTABLECER UN LIBRO CONTABLE PARA O/S NRO '||as_nro_os||'. REVISE LIBRO EN MAESTRO DE FRENTES DE COSECHA');
          return(0);
     WHEN TOO_MANY_ROWS THEN
          RAISE_APPLICATION_ERROR(-20000,'SE ENCONTRO MAS DE UN LIBRO CONTABLE PARA O/S NRO '||as_nro_os||'. REVISE LIBRO EN MAESTRO DE FRENTES DE COSECHA');
          return(0);
     WHEN OTHERS THEN
          RAISE_APPLICATION_ERROR(-20000,'ERROR NO DETERMINADO PARA O/S NRO '||as_nro_os||'. REVISE LIBRO EN MAESTRO DE FRENTES DE COSECHA');
          return(0);
  END;

  return(ln_nro_libro);
end usf_cam_nro_libro;
/

prompt
prompt Creating function USF_CAM_NRO_LIBRO_LABOR
prompt =========================================
prompt
create or replace function cantabria.usf_cam_nro_libro_labor(
as_labor in labor.cod_labor%type,
as_corr_corte campo_ciclo.corr_corte%type
) return cntbl_libro.nro_libro%type is
--Funcion recupera el numero de libro para un asiento de provision
--de os de servicios varios en funcion de labor y corr_corte
  ln_nro_libro cntbl_libro.nro_libro%type;
  ls_frente    frente_cosecha.frente_cosecha%type;
  ln_count     number;
  ls_corr_corte campo_ciclo.corr_corte%type;
begin
    ls_corr_corte := '';
    --Si no tiene corr_corte(caso operaciones de labores de ccosto de gerencia)
    If as_corr_corte is null or as_corr_corte = ls_corr_corte then
       Select count(*)
         into ln_count
         from labor l
        where l.cod_labor = as_labor;

       If ln_count = 1 then
         Select l.nro_libro
           into ln_nro_libro
           from labor l
          where l.cod_labor = as_labor;
       else
         Raise_Application_Error(-20000,'No existe la labor '||as_labor);
         return(0);
       end if;

       If ln_nro_libro is null then
          Raise_Application_Error(-20000,'No tiene asignado un libro contable la labor '||as_labor);
          return(0);
       end if;
    --end if;
    else
        -- Determinacion del Frente de Cosecha del Corr. Corte
        Select count(*)
          into ln_count
          from campo_ciclo cc, campo c, frente_cosecha f
         where cc.cod_campo = c.cod_campo
           and c.frente_cosecha = f.frente_cosecha
           and cc.corr_corte = as_corr_corte;

        If ln_count = 1 then
          select f.frente_cosecha
            into ls_frente
            from campo_ciclo cc, campo c, frente_cosecha f
           where cc.cod_campo = c.cod_campo
             and c.frente_cosecha = f.frente_cosecha
             and cc.corr_corte = as_corr_corte;
        else
          --Si el corr_corte no tiene asignado un frente, entonces es un caso
          --de corr_corte forzado como FITO02 0101, se convino utilizar el libro
          --de la labor para campos propios
           Select count(*)
             into ln_count
             from labor l
            where l.cod_labor = as_labor;

           If ln_count = 1 then
             Select l.nro_libro
               into ln_nro_libro
               from labor l
              where l.cod_labor = as_labor;
           else
             Raise_Application_Error(-20000,'No existe la labor '||as_labor);
             return(0);
           end if;

           If ln_nro_libro is null then
              Raise_Application_Error(-20000,'No tiene asignado un libro contable la labor '||as_labor);
              return(0);
           end if;
           GOTO NROLIBRO;
           --Raise_Application_Error(-20000,'No se pudo determinar frente de cosecha para corr corte '||as_corr_corte);
           --return(0);
        end if;

        If ls_frente is null then
           Raise_Application_Error(-20000,'No tiene frente de cosecha el corr corte '||as_corr_corte);
           return(0);
        end if;

        If ls_frente in ('PAP','PAA') then
           Select count(*)
             into ln_count
             from labor l
            where l.cod_labor = as_labor;

           If ln_count = 1 then
             Select l.nro_libro
               into ln_nro_libro
               from labor l
              where l.cod_labor = as_labor;
           else
             Raise_Application_Error(-20000,'No existe la labor '||as_labor);
             return(0);
           end if;

           If ln_nro_libro is null then
              Raise_Application_Error(-20000,'No tiene asignado un libro contable la labor '||as_labor);
              return(0);
           end if;
        else
           Select count(*)
             into ln_count
             from labor l
            where l.cod_labor = as_labor;

           If ln_count = 1 then
             Select l.nro_libro_3ro
               into ln_nro_libro
               from labor l
              where l.cod_labor = as_labor;
           else
             Raise_Application_Error(-20000,'No existe la labor '||as_labor);
             return(0);
           end if;

           If ln_nro_libro is null then
              Raise_Application_Error(-20000,'No tiene asignado un libro contable la labor '||as_labor);
              return(0);
           end if;

      end if;
end if;
<<NROLIBRO>>
  return(ln_nro_libro);
end usf_cam_nro_libro_labor;
/

