prompt
prompt Creating function USF_CAM_NUM_COSECHA_TAJO
prompt ==========================================
prompt
create or replace function cantabria.USF_CAM_NUM_COSECHA_TAJO
(as_origen origen.cod_origen%type,
 al_num_cosecha cosecha_tajo.nro_orden%type)

 return varchar2 is
  ln_ult_nro_cos cosecha_tajo.nro_cosecha_tajo%type ;
  ln_count       number ;
begin
  --numerador de operaciones
  select count(*)
    into ln_count
    from num_cosecha_tajo nct
   where (nct.origen = as_origen ) ;

  -- Verifica si existe items
  IF ln_count = 0 then
     insert into num_cosecha_tajo(origen, ult_nro)
     values (as_origen, 2) ;
     return(1) ;
  END IF ;

  -- Calcula ultimo numero
  select nct.ult_nro
    into ln_ult_nro_cos
    from num_cosecha_tajo nct
   where (nct.origen = as_origen)
   for update nowait;

  --actualiza informacion e numeradores
  update num_cosecha_tajo nct
     set nct.ult_nro = Nvl(nct.ult_nro,0) + 1
   where (nct.origen = as_origen ) ;

  return(ln_ult_nro_cos);

end  USF_CAM_NUM_COSECHA_TAJO ;
/

prompt
prompt Creating function USF_CAM_NUM_DETRACCION
prompt ========================================
prompt
create or replace function cantabria.USF_CAM_NUM_DETRACCION(
       asi_origen origen.cod_origen%type
)return varchar2 is
  lc_ult_nro_op detraccion.nro_detraccion%type ;

ln_ult_nro num_detraccion.ult_nro%type ;
ln_count   number;

begin
  --numerador de detraccion
  select count(*)
    into ln_count
    from num_detraccion no
   where (no.origen = asi_origen);

  if ln_count = 0 then
    insert into num_detraccion(origen, ult_nro)
    values(asi_origen, 1);
  end if;

  select no.ult_nro
    into ln_ult_nro
    from num_detraccion no
   where (no.origen = asi_origen)
   for update;

  --se concatena con origen
  lc_ult_nro_op := rtrim(ltrim(asi_origen))||LPAD(rtrim(ltrim(to_char(ln_ult_nro))),8,'0') ;

  --actualiza informacion e numeradores
  update num_detraccion no
     set no.ult_nro = Nvl(no.ult_nro,0) + 1
   where (no.origen = asi_origen ) ;

  return(lc_ult_nro_op);
end USF_CAM_NUM_DETRACCION ;
/

