prompt
prompt Creating function USF_CAM_NUM_OPERACIONES
prompt =========================================
prompt
create or replace function cantabria.USF_CAM_NUM_OPERACIONES(
       asi_cod_origen in origen.cod_origen%type
) return varchar2 is

  ls_next_nro operaciones.oper_sec%type ;
  ln_ult_nro  num_operaciones.ult_nro%type ;
  ln_count    number;

begin
  select count(*)
    into ln_count
    from num_operaciones no
   where no.origen = asi_cod_origen;

   if ln_count = 0 then
     insert into num_operaciones(
            ult_nro, origen
     )values(
            1, asi_cod_origen);
       
      
   end if;

  --numerador de operaciones
  select no.ult_nro
    into ln_ult_nro
    from num_operaciones no
   where no.origen = asi_cod_origen for update ;

  --se concatena con origen
  ls_next_nro := rtrim(ltrim(asi_cod_origen))||LPAD(rtrim(ltrim(to_char(ln_ult_nro))),8,'0') ;

  --actualiza informacion e numeradores
  update num_operaciones no
     set no.ult_nro = Nvl(no.ult_nro,0) + 1
   where (no.origen = asi_cod_origen ) ;

  return(ls_next_nro);
end USF_CAM_NUM_OPERACIONES;
/

