prompt
prompt Creating function USF_CAM_PRECIO_PROM_ART_LABOR
prompt ===============================================
prompt
create or replace function cantabria.USF_CAM_PRECIO_PROM_ART_LABOR(
 an_ano number,
 an_mes_ini number,
 an_mes_fin number,
 as_labor labor.cod_labor%type,
 as_articulo articulo.cod_art%type)

 Return  number is

 Result number;

Begin
select sum ( nvl(am.cant_procesada,0) * (nvl(am.precio_unit,0) / USF_VTA_DOL_PROM_X_MES(to_number(to_char(vm.fec_registro,'yyyy')), to_number(to_char(vm.fec_registro,'mm')))) )/sum ( nvl(am.cant_procesada,0))
       into Result
  from campo_ciclo cc, orden_trabajo ot, operaciones o, articulo_mov am,
       vale_mov vm, articulo a
 where cc.nro_orden = ot.nro_orden
   and ot.nro_orden = o.nro_orden
   and o.oper_sec = am.oper_sec
   and am.cod_origen = vm.cod_origen
   and am.nro_vale = vm.nro_vale
   and am.cod_art = a.cod_art
   and o.cod_labor = as_labor
   AND a.cod_art = as_articulo
   and To_Number(To_Char(vm.fec_registro,'yyyy'))=an_ano
   and To_Number(To_Char(vm.fec_registro,'mm')) >= an_mes_ini
   and To_Number(To_Char(vm.fec_registro,'mm')) <= an_mes_fin
   and am.flag_estado <> '0'
   and vm.flag_estado <> '0'
   and substr(vm.tipo_mov,1,1) = 'S';
 Return(Result);

end USF_CAM_PRECIO_PROM_ART_LABOR;
/

prompt
prompt Creating function USF_CAM_PRECIO_PROM_MAQ_LABOR
prompt ===============================================
prompt
create or replace function cantabria.USF_CAM_PRECIO_PROM_MAQ_LABOR(
 an_ano number,
 an_mes_ini number,
 an_mes_fin number,
 as_labor labor.cod_labor%type)

 Return  number is

 Result number(13,2);
 ln_ano number(4);
 ln_mes number(2);
 ls_categoria maq_categoria_costeo.categoria%type;
 ln_count number(2);

Begin
/* Ejemplo: Obtener el precio ponderado de la maquinaria utilizada para ejecutar la labor
            2do Post Emergente
      Select pod.cod_maquina, To_Number(To_Char(USF_CAM_FECHA_PROD(po.fecha),'mm')) AS MES,
             sum( Nvl(pod.cant_labor,0)- Nvl(pod.horas_inciden,0)) AS HORAS,
             USF_CAM_CALC_COSTO_MAQ(2004, To_Number(To_Char(USF_CAM_FECHA_PROD(po.fecha),'mm')),pod.cod_maquina) AS COSTO,
        from orden_trabajo ot, operaciones o, pd_ot_det pod, pd_ot po, labor_ejecutor le, labor l,
             campo_ciclo cc, campo c
       where ot.nro_orden     = o.nro_orden     and
             o.oper_sec       = pod.oper_sec    and
             pod.nro_parte    = po.nro_parte    and
             pod.cod_labor    = le.cod_labor    and
             pod.cod_ejecutor = le.cod_ejecutor and
             le.cod_labor     = l.cod_labor     and
             pod.cod_labor    = 'CCQQ02MC'        and
             --pod.cod_ejecutor = as_ejecutor     and
             ot.nro_orden     = cc.nro_orden    and
             cc.cod_campo     = c.cod_campo     and
             To_Number(To_Char(po.fecha,'yyyy'))         = 2004     and
             To_Number(To_Char(po.fecha,'mm'))         >= 9     and
             To_Number(To_Char(po.fecha,'mm'))         <= 9
      group by To_Number(To_Char(USF_CAM_FECHA_PROD(po.fecha),'mm')), pod.cod_maquina;

  La Seleccion devuelve :
  MAQUINA | MES |  HORAS | COSTO
  ------------------------------
  TRA-226 |	 9	|  27.92 | 14.49
  TRA-228 |	 9	|  45.91 | 14.49
  TRA-229 |	 9	|   1.00 | 14.49

  Nota : La informacion se agrupa por Mes y Maquina, se agrupa las horas efectivas del
         parte diario, de contabilidad se obtiene el costo unitario de la maquinaria
         en un mes determinado.

  El Precio promedio es Sum(horas * costo)/Sum(horas), que es el resultado de esta funcion.
*/
    Select Sum(sum( Nvl(pod.cant_labor,0)- Nvl(pod.horas_inciden,0)) * USF_CAM_CALC_COSTO_MAQ(an_ano, To_Number(To_Char(USF_CAM_FECHA_PROD(po.fecha),'mm')),pod.cod_maquina))/sum(sum( Nvl(pod.cant_labor,0)- Nvl(pod.horas_inciden,0)))
      into Result
      from orden_trabajo ot, operaciones o, pd_ot_det pod, pd_ot po, labor_ejecutor le, labor l,
           campo_ciclo cc, campo c
     where ot.nro_orden     = o.nro_orden     and
           o.oper_sec       = pod.oper_sec    and
           pod.nro_parte    = po.nro_parte    and
           pod.cod_labor    = le.cod_labor    and
           pod.cod_ejecutor = le.cod_ejecutor and
           le.cod_labor     = l.cod_labor     and
           pod.cod_labor    = as_labor        and
           --pod.cod_ejecutor = as_ejecutor     and
           ot.nro_orden     = cc.nro_orden    and
           cc.cod_campo     = c.cod_campo     and
           c.frente_cosecha in (select frente_cosecha from tt_frente_cosecha) and
           To_Number(To_Char(po.fecha,'yyyy'))        = an_ano     and
           To_Number(To_Char(po.fecha,'mm'))         >= an_mes_ini and
           To_Number(To_Char(po.fecha,'mm'))         <= an_mes_fin
    group by To_Number(To_Char(USF_CAM_FECHA_PROD(po.fecha),'mm')), pod.cod_maquina  ;

 Return(Result);

end USF_CAM_PRECIO_PROM_MAQ_LABOR;
/

prompt
prompt Creating function USF_CAM_RECUPERADO_X_CAMPO
prompt ============================================
prompt
create or replace function cantabria.USF_CAM_RECUPERADO_X_CAMPO
(correlativo in campo_ciclo.corr_corte%type, fec_ini in date, fec_fin in date)
return number is
Result number;

begin

select round(SUM((nvl(ccd.cana_sucia_qmd,0) * nvl(ccd.rec_az_cana_qmd,0))
       + (nvl(ccd.cana_sucia_cruda,0) * nvl(ccd.rec_az_cana_cruda,0))) /
       SUM((nvl(ccd.cana_sucia_qmd,0) + nvl(ccd.cana_sucia_cruda,0))) , 2 )
  into result
  from campo_ciclo_diario ccd
 where corr_corte = correlativo
   and fecha >= fec_ini
   and fecha <= fec_fin;

  return(Result);

end USF_CAM_RECUPERADO_X_CAMPO;
/

prompt
prompt Creating function USF_CAM_RGS_HUMEDAD
prompt =====================================
prompt
create or replace function cantabria.usf_cam_rgs_humedad(
ln_humedo rgs_pd_muestra_suelo.mst_humedad%type,
ln_seco rgs_pd_muestra_suelo.mst_seca%type,
ln_tarro rgs_pd_muestra_suelo.nro_tarro%type )
 return number is
  ln_Result rgs_pd_muestra_suelo.mst_humedad%type;
  ln_peso rgs_tara_tarros.peso%type;
begin

select peso into ln_peso from rgs_tara_tarros where nro_tarro = ln_tarro ;

 ln_Result := ((ln_humedo - ln_seco) / (ln_seco - ln_peso)) * 100  ;

  return(ln_Result);
end usf_cam_rgs_humedad;
/

prompt
prompt Creating function USF_CAM_RGS_TEXTURA
prompt =====================================
prompt
create or replace function cantabria.USF_CAM_RGS_TEXTURA(
ls_corr campo_ciclo.corr_corte%type,
ls_cuartel rgs_pd_muestra_suelo.cuartel%type,
ls_estrato rgs_pd_muestra_suelo.estrato%type)
 return varchar2 is
  Result   campo_suelo.desc_suelo%type;
ln_arany1  number(5,2) ;

begin

select ca.valor into ln_arany1
  from rgs_cuartel_cifra_arany ca
 where ca.cod_campo = (select cc.cod_campo from campo_ciclo cc where cc.corr_corte = ls_corr)
   and ca.cod_cuartel = ls_cuartel
   and ca.estrato = ls_estrato ;

select cs.desc_suelo
  into Result
  from campo_suelo cs
 where ROUND(ln_arany1,0) >= cs.profundidad_ini
   and ROUND(ln_arany1,0) <= cs.profundidad_fin ;


  return(Result);
end USF_CAM_RGS_TEXTURA;
/

prompt
prompt Creating function USF_CAM_RGS_TIPO_RIEGO
prompt ========================================
prompt
create or replace function cantabria.USF_CAM_RGS_TIPO_RIEGO(
ln_edad in number,
ln_nro_corte in number) return varchar2 is
  Result varchar2(60);
  ls_labor char(8) ;
  ls_desc_labor varchar2(40) ;
begin


   if ln_edad < 1.1 and ln_nro_corte = 1 then
    select p.enseno , l.desc_labor into ls_labor, ls_desc_labor from rgsparam p, labor l where p.enseno = l.cod_labor ;
    Result := ls_labor||'  '||ls_desc_labor ;
   --end if ;

   elsif ln_edad < 1.1 and ln_nro_corte > 1 then
    select p.remojo , l.desc_labor into ls_labor, ls_desc_labor from rgsparam p, labor l where p.remojo = l.cod_labor ;
    Result := ls_labor||'  '||ls_desc_labor ;
   --end if ;
   elsif ln_edad >=  1.1 and ln_edad < 5 then
     select t.cod_labor , l.desc_labor into ls_labor, ls_desc_labor
       from rgs_tipo_riego t, labor l
      where t.cod_labor = (select p.entable from rgsparam p where p.reckey = '1')
        and t.cod_labor = l.cod_labor
        and round(ln_edad) >= t.edad_ini
        and round(ln_edad) <= t.edad_fin ;

     Result := ls_labor||'  '||ls_desc_labor ;
   elsif ln_edad  >= 5  then

     select t.cod_labor , l.desc_labor into ls_labor, ls_desc_labor
       from rgs_tipo_riego t, labor l
      where t.cod_labor = (select p.general from rgsparam p where p.reckey = '1')
        and t.cod_labor = l.cod_labor
        and round(ln_edad) >= t.edad_ini ;

     Result := ls_labor||'  '||ls_desc_labor ;
   elsE
     Result := 'S/TIPO  SIN TIPO';
   end if ;


  return(Result);
end USF_CAM_RGS_TIPO_RIEGO;
/

prompt
prompt Creating function USF_CAM_RIEGO_FECHA_INICIO
prompt ============================================
prompt
create or replace function cantabria.USF_CAM_RIEGO_FECHA_INICIO
(ac_nro_orden in  campo_ciclo.nro_orden%type )


return varchar2 is
lc_cadena varchar2 (25) ;

ld_hora_inicio Date ;
ln_nro_riego   pd_ot_riego.nro_riego%type ;


begin

select Min(pl.hora_inicio) as f_inicio,max(pr.nro_riego) as riego
  into ld_hora_inicio, ln_nro_riego
  from operaciones op,pd_ot_det pl,pd_ot_riego pr
 where ((op.oper_sec   = pl.oper_sec   )) and
       ((op.nro_orden  = ac_nro_orden  )) and
       ((pl.cod_labor  = 'CRIRIEGO'    )) and
       ((pl.nro_parte  = pr.nro_parte  )  and
        (pl.nro_item   = pr.nro_item   )) and
       ((pr.nro_riego  = (select max(nro_riego)
                             from operaciones op,pd_ot_det pl,pd_ot_riego pr
                             where (op.oper_sec   = pl.oper_sec   ) and
                                   (pl.cod_labor  = 'CRIRIEGO'    ) and
                                   (op.nro_orden  = ac_nro_orden  ) and
                                   (pl.nro_parte  = pr.nro_parte  ) and
                                   (pl.nro_item   = pr.nro_item   )) )) ;

lc_cadena := Nvl(to_char(ld_hora_inicio,'dd/mm/yyyy'),'00/00/0000')||Nvl(to_char(ln_nro_riego),'') ;

  return(lc_cadena);
end USF_CAM_RIEGO_FECHA_INICIO;
/

