prompt Creating function USF_CAM_SACAROSA_X_FRENTE
prompt ===========================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_CAM_SACAROSA_X_FRENTE
(ac_frente_cosecha IN frente_cosecha.frente_cosecha%TYPE, ad_fch_ini IN DATE, ad_fch_fin IN DATE)
RETURN NUMBER IS
ln_result NUMBER;

BEGIN
    SELECT ROUND(SUM((nvl(ccd.cana_sucia_qmd,0) * nvl(ccd.sacar_cana_qmd,0))+ (nvl(ccd.cana_sucia_cruda,0) * nvl(ccd.sacar_cana_cruda,0))) /SUM((nvl(ccd.cana_sucia_qmd,0) + nvl(ccd.cana_sucia_cruda,0))) , 2 )
