prompt Creating function USF_CAM_SERVICIO_OS_CAMPO
prompt ===========================================
prompt
create or replace function cantabria.usf_cam_servicio_os_campo(
       as_labor in labor.cod_labor%type,
       as_frente_cosecha in frente_cosecha.frente_cosecha%type
) return servicios.servicio%type is
  ls_serv servicios.servicio%type;
Begin
  If as_frente_cosecha in ('PAP','PAA') then--Servicio para Campos Propios
     Select l.servicio
     into ls_serv
     from labor l
     where l.cod_labor = as_labor;
  else --Servicio Para Sembradores
     Select l.servicio_3ro
     into ls_serv
     from labor l
     where l.cod_labor = as_labor;
  end if;
  return(ls_serv);
end usf_cam_servicio_os_campo;
