prompt
prompt Creating function USF_CAM_TARIFA_ALCE
prompt =====================================
prompt
create or replace function cantabria.usf_cam_tarifa_alce(
       as_tipo_alce      alce_cana_tipo.alce_tipo%TYPE,
       an_cana_limpia      campo_pesaje.pesada%type) return number is

   ln_factor       alce_cana_tipo.tarifa_sol%type ;
   ln_tarifa        tt_cam_cosecha_x_fecha.tarifa%type ;
   ln_count         number(3) ;
   --Creada por Roberth Garcia 10 Feb.2005
begin

    ln_factor := 0 ;
    ln_tarifa  := 0 ;


--     ln_cana_limpia := ROUND((100-c_m.impureza_porc)/100 * (c_m.pesada - c_m.tara)/1000,2) ;


    SELECT count(*)
      INTO ln_count
      FROM alce_cana_tipo
     WHERE alce_tipo = as_tipo_alce ;

    IF ln_count>0 THEN
       SELECT NVL(act.tarifa_sol,0)
         INTO ln_factor
         FROM alce_cana_tipo act
        WHERE act.alce_tipo = as_tipo_alce ;
    END IF ;

    ln_tarifa := ROUND( ln_factor * an_cana_limpia, 2) ;
    -- ln_tarifa := ROUND(ln_cana_limpia*ln_factor,2) ;

   RETURN(ln_tarifa);
END usf_cam_tarifa_alce;
/

prompt
prompt Creating function USF_CAM_TARIFA_CORTE
prompt ======================================
prompt
create or replace function cantabria.usf_cam_tarifa_corte(
       as_tipo_corte1      corte_cana_tipo.corte_tipo%type,
       as_tipo_corte2      corte_cana_tipo.corte_tipo%type,
       an_cana_limpia      campo_pesaje.pesada%type) return number is

   ln_factor1       corte_cana_tipo.tarifa_sol%type ;
   ln_factor2       corte_cana_tipo.tarifa_sol%type ;
   ln_factorg       corte_cana_tipo.tarifa_sol%type ;
   ln_tarifa        tt_cam_cosecha_x_fecha.tarifa%type ;
   ln_count         number(3) ;
begin

    ln_factor1 := 0 ;
    ln_factor2 := 0 ;
    ln_factorg := 0 ;
    ln_tarifa  := 0 ;

    SELECT count(*)
      INTO ln_count
      FROM corte_cana_tipo cct
     WHERE cct.corte_tipo = as_tipo_corte1 ;

    IF ln_count>0 THEN
       SELECT NVL(cct.tarifa_sol,0)
         INTO ln_factor1
         FROM corte_cana_tipo cct
        WHERE cct.corte_tipo = as_tipo_corte1 ;
    END IF ;
    IF as_tipo_corte2 is not null then
        -- Verificando corte de ca?a 2
        SELECT count(*)
          INTO ln_count
          FROM corte_cana_tipo cct
         WHERE cct.corte_tipo = as_tipo_corte2 ;

        IF ln_count>0 THEN
           SELECT NVL(cct.tarifa_sol,0)
             INTO ln_factor2
             FROM corte_cana_tipo cct
            WHERE cct.corte_tipo = as_tipo_corte2 ;
        END IF ;
    END IF ;

    ln_factorg := nvl(ln_factor1,0) + nvl(ln_factor2,0) ;
    ln_tarifa := ROUND( ln_factorg * an_cana_limpia, 2) ;

   RETURN(ln_tarifa);
END usf_cam_tarifa_corte;
/

prompt
prompt Creating function USF_CAM_TARIFA_COSECHA
prompt ========================================
prompt
create or replace function cantabria.usf_cam_tarifa_cosecha(an_distancia in number) return number is
  ln_distancia     campo.distancia_fabrica%type ;
  ln_factor_tm_sol number;
begin

  IF an_distancia > 12 THEN
     ln_distancia := an_distancia ;
  ELSIF an_distancia >0 and an_distancia <= 12 THEN
       ln_distancia := 12 ;
  ELSE
     ln_distancia := 0 ;
  END IF ;

  SELECT MAX(tc.factor_tm_sol)
    INTO ln_factor_tm_sol
    FROM tarifa_transp_cana tc
   WHERE ln_distancia BETWEEN tc.de AND tc.hasta ;

  RETURN(ln_factor_tm_sol);
END usf_cam_tarifa_cosecha;
/

