prompt Creating function USF_CAM_TIENE_CTRL_PARTIDA
prompt ============================================
prompt
create or replace function cantabria.USF_CAM_TIENE_CTRL_PARTIDA
(an_ano in number,
as_cencos in presupuesto_partida.cencos%type,
as_cnta_prsp in presupuesto_partida.cnta_prsp%type)

return number is
ln_ctrl presupuesto_partida.flag_ctrl%type;
