prompt
prompt Creating function USF_CAM_TIPO_CTRL_MLZA
prompt ========================================
prompt
create or replace function cantabria.USF_CAM_TIPO_CTRL_MLZA
(as_labor in labor.cod_labor%type
)
 return  char is
 --Variables
 ln_count number(2);
 ls_tipo char(1);
 result char(1);
Begin
 -- Verificar si la labor esta en la Lista de Labores de control quimico
 Select count(*)
   into ln_count
   from rpt_grupo g, labor l
  where g.descripcion = l.cod_labor and reporte = 'CtrMalQm' and l.cod_labor = as_labor;

 If ln_count = 1 then
    Return 'Q';
 End if;

 -- Verificar si la labor esta en la Lista de Labores de control manual
 Select count(*)
   into ln_count
   from rpt_grupo g, labor l
  where g.descripcion = l.cod_labor and reporte = 'CtrMalMa' and l.cod_labor = as_labor;

 If ln_count = 1 then
    Return 'M';
 End if;


return(ls_tipo);

end USF_CAM_TIPO_CTRL_MLZA;
/

prompt
prompt Creating function USF_CAM_TON_CANA_SUCIA
prompt ========================================
prompt
create or replace function cantabria.usf_cam_ton_cana_sucia
(as_corr_corte in char, ad_fec_ini in date, ad_fec_fin in date) return number is
  Result number;

  CURSOR c_cana_sucia IS
  SELECT cp.pesada, cp.tara
   FROM campo_pesaje cp, orden_cosecha oc, orden_cos_viajes ocv,
        guia_cana gc, proveedor p, campo_ciclo cc, campo c
   WHERE cp.corr_corte = cc.corr_corte AND
         cp.corr_corte = oc.corr_corte AND
         cp.nro_orden = oc.nro_orden AND
         cp.nro_orden = ocv.nro_orden AND
         cp.nro_viaje = ocv.nro_viaje AND
         cp.flag_impurezas = '0' AND
         cc.cod_campo = c.cod_campo AND
         ocv.proveedor = gc.proveedor AND
         ocv.nro_guia = gc.nro_guia AND
         gc.prov_transp = p.proveedor AND
         cp.corr_corte = as_corr_corte AND
         cp.hora_tara BETWEEN ad_fec_ini AND ad_fec_fin ;
BEGIN
  Result := 0 ;
  FOR c_c IN c_cana_sucia LOOP
      Result := Result + NVL(c_c.pesada,0) - NVL( c_c.tara,0) ;
  END LOOP ;

  -- Convirtiendolo a TM
  Result := ROUND( Result / 1000, 2) ;
  RETURN(Result);
END usf_cam_ton_cana_sucia;
/

