prompt Creating function USF_CAM_ULT_OPER
prompt ==================================
prompt
create or replace function cantabria.usf_cam_ult_oper(as_corr_corte campo_ciclo.corr_corte%type)
return number is
  ln_result    operaciones.nro_operacion%type;
begin

  Select max(op.nro_operacion)
  into ln_result
  from operaciones op, campo_ciclo cc
  where op.tipo_orden = (select l.doc_ot from logparam l where reckey='1') AND
        op.nro_orden = cc.nro_orden AND
        cc.corr_corte = as_corr_corte ;

  return(ln_result);
end usf_cam_ult_oper;
/

prompt
prompt Creating function USF_CAM_VARIEDAD_X_CORR
prompt =========================================
prompt
create or replace function cantabria.usf_cam_variedad_x_corr(as_corr_corte campo_ciclo.corr_corte%type)
return char Is

ls_variedad              variedad.variedad%type ;

Cursor c_variedad Is
Select variedad, Sum(c.has_sembrada)
  From campo_ciclo_cuartel c
 Where c.corr_corte = as_corr_corte
 Group By c.variedad
 Order By Sum(c.has_sembrada) Desc;

BEGIN

FOR c_s IN c_variedad LOOP
    ls_variedad := c_s.variedad ;
    EXIT ;
END LOOP ;

RETURN( ls_variedad ) ;

END usf_cam_variedad_x_corr ;
/

prompt
prompt Creating function USF_CARGA_ETAPAS
prompt ==================================
prompt
create or replace function cantabria.usf_carga_etapas(
   ad_fecini_ran in date, ad_fecfin_ran in date,
   ad_fecini_ope in date, ad_fecfin_ope in date) return number is
  ln_factor number;
  ln_dias_inicial   int; --(z)
  ln_dias_final     int;
begin
  ln_dias_inicial := ad_fecfin_ope - ad_fecini_ope + 1;
  ln_dias_final   := ln_dias_inicial;
  if ad_fecini_ope < ad_fecini_ran then
     ln_dias_final := ln_dias_final -
        ( ad_fecini_ran - ad_fecini_ope );
  end if;
  if ad_fecfin_ope > ad_fecfin_ran then
     ln_dias_final := ln_dias_final -
        ( ad_fecfin_ran - ad_fecfin_ope );
  end if;
  ln_factor := ln_dias_final / ln_dias_inicial;

  return(ln_factor);
end usf_carga_etapas;
-- el propssito de esta funcisn es calcular el factor para el usp_
-- trabaja como
--       10(a).............. 20(b)     rango de fechas
--  9(c),10,11 .......... 19,20,21(d)  operaciones =3dmas(z)
--  z-(a-c)               z-(d-b)
--  3-(10-9)=2            3-(21-20)=2
--
-- if c<a y luego si d>a
/

