prompt Creating function USF_CLASE_PROV_TRANSP
prompt =======================================
prompt
create or replace function cantabria.usf_clase_prov_transp(
an_nro_libro in cntbl_pre_asiento.nro_libro%type,
an_nro_prov in cntbl_pre_asiento.nro_provisional%type
) return frente_cosecha.clase%type is
  ls_clase frente_cosecha.clase%type;
begin
    select f.clase
    into ls_clase
    from orden_servicio_det_cana osd, campo_ciclo cc, campo c, frente_cosecha f
    where osd.corr_corte = cc.corr_corte and
    cc.cod_campo = c.cod_campo and
    c.frente_cosecha = f.frente_cosecha and
    osd.nro_os = (select max(p.nro_docref1) from cntbl_pre_asiento_det p where p.nro_provisional=an_nro_prov and p.nro_libro = an_nro_libro) and
    osd.cod_origen = 'PR'
    group by f.clase;
    Return ls_clase;
end usf_clase_prov_transp;
