prompt
prompt Creating function USF_CMP_CANT_CMP_AMP_OT
prompt =========================================
prompt
create or replace function cantabria.usf_cmp_cant_cmp_AMP_OT(
       asi_org_amp_ot      in articulo_mov_proy.cod_origen%TYPE,
       ani_nro_amp_ot      in articulo_mov_proy.nro_mov%TYPE
) return number is
 PRAGMA AUTONOMOUS_TRANSACTION;

  ln_Result     number;
  ln_temp1      NUMBER;
  ln_temp2      NUMBER;
  ls_doc_oc     logparam.doc_oc%TYPE;

begin

  select doc_oc
    into ls_doc_oc
    from logparam
   where reckey = '1';

  select NVL(SUM(amp.cant_proyect),0)
    into ln_temp1
    from articulo_mov_proy amp
   where amp.org_amp_ref = asi_org_amp_ot
     and amp.nro_amp_ref = ani_nro_amp_ot
     AND amp.tipo_doc = ls_doc_oc
     and amp.flag_estado = '1';

  select NVL(SUM(amp.cant_procesada),0)
    into ln_temp2
    from articulo_mov_proy amp
   where amp.org_amp_ref = asi_org_amp_ot
     and amp.nro_amp_ref = ani_nro_amp_ot
     AND amp.tipo_doc = ls_doc_oc
     and amp.flag_estado = '2';

  ln_Result := ln_temp1 + ln_temp2;

  return(ln_Result);
end usf_cmp_cant_cmp_AMP_OT;
/

prompt
prompt Creating function USF_CMP_CANT_COMP_PROG
prompt ========================================
prompt
create or replace function cantabria.usf_cmp_cant_comp_prog
(as_origen articulo_mov_proy.cod_origen%type,
 an_nro_mov articulo_mov_proy.nro_mov%type    ) return number is

  Result        number;
  ls_doc_oc     logparam.doc_oc%TYPE;
  ls_doc_prog   logparam.tipo_doc_prog_cmp%TYPE;

begin

  select doc_oc, tipo_doc_prog_cmp into ls_doc_oc, ls_doc_prog
    from logparam  where reckey = '1';

   Result := 0;

   select sum(amp.cant_proyect) into Result
     from articulo_mov_proy amp
    where amp.org_amp_ref = as_origen   and amp.nro_amp_ref = an_nro_mov and tipo_doc = ls_doc_oc and
          Nvl(amp.tipo_ref,'') = ls_doc_prog and amp.flag_estado <> '0'
    group by amp.org_amp_ref ,amp.nro_amp_ref ;





  return(Result);

 end usf_cmp_cant_comp_prog;
/

prompt
prompt Creating function USF_CMP_CANT_COMPRADA
prompt =======================================
prompt
create or replace function cantabria.usf_cmp_cant_comprada(
       asi_opersec         in operaciones.oper_sec%TYPE,
       asi_cod_art         in articulo.cod_art%TYPE,
       asi_almacen         in almacen.almacen%TYPE
) return number is

  Result        number;
  ln_count      number;
  ls_doc_oc     logparam.doc_oc%TYPE;
begin

  select doc_oc
    into ls_doc_oc
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
    from articulo_mov_proy amp
   where amp.oper_sec = asi_opersec
     and amp.cod_art  = asi_cod_art
     and tipo_doc     = ls_doc_oc
     and almacen      = asi_almacen
     and amp.flag_estado <> '0';

  if ln_count = 0 then
      Result := 0;
  else
      select sum(amp.cant_proyect)
        into Result
        from articulo_mov_proy amp
       where amp.oper_sec = asi_opersec
         and amp.cod_art  = asi_cod_art
         and amp.almacen  = asi_almacen
         and tipo_doc     = ls_doc_oc
         and amp.flag_estado <> '0';

  end if;

  return(Result);
end usf_cmp_cant_comprada;
/

prompt
prompt Creating function USF_CMP_CANT_COMPRADA_OT
prompt ==========================================
prompt
create or replace function cantabria.usf_cmp_cant_comprada_OT(
       as_nro_ot           in orden_trabajo.nro_orden%type
) return char is

  Result            articulo.cod_art%type;
  ls_doc_ot         doc_tipo.tipo_doc%type ;
  ls_oper_cons_int   articulo_mov_tipo.tipo_mov%type;

BEGIN

SELECT l.doc_ot, l.oper_ing_prod
  INTO ls_doc_ot, ls_oper_cons_int
  FROM logparam l
 WHERE l.reckey='1' ;

SELECT min(cod_art)
  INTO result
  FROM articulo_mov_proy amp
 WHERE amp.tipo_doc = ls_doc_ot and
       amp.tipo_mov = ls_oper_cons_int and
       amp.nro_doc  = as_nro_ot ;

  return(Result);

END usf_cmp_cant_comprada_OT;
/

