prompt Creating function USF_CMP_CANT_COMP_SPROG
prompt =========================================
prompt
create or replace function cantabria.usf_cmp_cant_comp_sprog(
       as_origen articulo_mov_proy.cod_origen%type,
       an_nro_mov articulo_mov_proy.nro_mov%type
) return number is

  Result        number;
  ln_count      number;
  ls_doc_oc     logparam.doc_oc%TYPE;
  ls_doc_prog   logparam.tipo_doc_prog_cmp%TYPE;
begin

  select doc_oc, tipo_doc_prog_cmp into ls_doc_oc, ls_doc_prog
    from logparam where reckey = '1';

  Result := 0;

  select sum(amp.cant_proyect) into Result
    from articulo_mov_proy amp
    where amp.org_amp_ref = as_origen and amp.nro_amp_ref       = an_nro_mov  and
          tipo_doc        = ls_doc_oc and NVL(amp.tipo_ref,'') <> ls_doc_prog and
          amp.flag_estado <> '0'
 group by amp.org_amp_ref,amp.nro_amp_ref ;



  return(Result);
end usf_cmp_cant_comp_sprog;
/

