prompt
prompt Creating function USF_CMP_CANT_INGRESADA_MM
prompt ===========================================
prompt
create or replace function cantabria.usf_cmp_cant_ingresada_mm(
       asi_opersec         in operaciones.oper_sec%TYPE,
       asi_cod_art         in articulo.cod_art%TYPE,
       asi_almacen         in almacen.almacen%TYPE
) return number is

  Result        number;
  ln_count      number;
  ls_doc_oc     logparam.doc_oc%TYPE;
begin

  select doc_oc
    into ls_doc_oc
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
    from articulo_mov_proy amp,
         articulo_mov      am, vale_mov vm
   where (am.nro_mov_proy    = amp.nro_mov
     and  am.origen_mov_proy = amp.cod_origen)
     and (am.cod_origen=vm.cod_origen and
          am.nro_vale=vm.nro_vale)
     and (vm.tipo_mov = (select l.oper_ing_oc from logparam l where reckey='1') )
     and amp.cod_art  = asi_cod_art
     and amp.tipo_doc     = ls_doc_oc
     and amp.almacen      = asi_almacen
     and amp.flag_estado <> '0'
     and am.flag_estado <> '0';

  if ln_count = 0 then
      Result := 0;
  else
      select sum(am.cant_procesada)
        into Result
    from articulo_mov_proy amp,
         articulo_mov      am, vale_mov vm
   where (am.nro_mov_proy    = amp.nro_mov
     and  am.origen_mov_proy = amp.cod_origen)
     and (am.cod_origen=vm.cod_origen and
          am.nro_vale=vm.nro_vale)
     and (vm.tipo_mov = (select l.oper_ing_oc from logparam l where reckey='1') )
     and amp.cod_art  = asi_cod_art
     and amp.tipo_doc     = ls_doc_oc
     and amp.almacen      = asi_almacen
     and amp.flag_estado <> '0'
     and am.flag_estado <> '0';
  end if;

  return(Result);
end usf_cmp_cant_ingresada_mm;
/

prompt
prompt Creating function USF_CMP_CANT_PEN_D_COMPRA
prompt ===========================================
prompt
create or replace function cantabria.usf_cmp_cant_pen_d_compra(

   as_origen     in articulo_mov_proy.cod_origen%type,
   an_nro_mov    in articulo_mov_proy.nro_mov%TYPE,
   asi_almacen   in almacen.almacen%TYPE

) return number is
  Result        number;
  ll_count      number;
  ln_cant_req   number;          -- Cantidad requerida
  ln_cant_ing   number;          -- CAntidad Ingresada al almacen
  ls_doc_ot     logparam.doc_ot%type;
  ls_doc_oc     logparam.doc_oc%type;

begin
  Select doc_ot, doc_oc
    into ls_doc_ot, ls_doc_oc
    from logparam
   where reckey = '1'  ;

     select count(*)
    into ll_count
    from articulo_mov_proy amp
   where amp.cod_origen    = as_origen
     and amp.nro_mov       = an_nro_mov
     and tipo_doc          = ls_doc_ot
     and almacen           = asi_almacen
     and amp.flag_estado   <> '0';

  if ll_count = 0 then
      ln_cant_req := 0;
  else
      select nvl(sum(amp.cant_proyect),0)
        into ln_cant_req
        from articulo_mov_proy amp
       where amp.cod_origen = as_origen
         and amp.nro_mov = an_nro_mov
         and amp.almacen  = asi_almacen
         and tipo_doc     = ls_doc_ot
         and amp.flag_estado <> '0';
   end if;

  select count(*)
    into ll_count
    from articulo_mov_proy amp
   where amp.origen_ref    = as_origen
     and amp.nro_amp_ref   = an_nro_mov
     and tipo_doc          = ls_doc_oc
     and almacen           = asi_almacen
     and amp.flag_estado   <> '0';

  if ll_count = 0 then
      ln_cant_ing := 0;
  else
      select nvl(sum(amp.cant_proyect),0)
        into ln_cant_ing
        from articulo_mov_proy amp
       where amp.origen_ref    = as_origen
         and amp.nro_amp_ref   = an_nro_mov
         and amp.almacen       = asi_almacen
         and amp.tipo_doc      = ls_doc_oc
         and amp.flag_estado   <> '0';
   end if;

   Result := ln_cant_req - ln_cant_ing;

  return(Result);

end usf_cmp_cant_pen_d_compra;
/

