prompt Creating function USF_CMP_CANT_PENDIENTE
prompt ========================================
prompt
create or replace function cantabria.usf_cmp_cant_pendiente(

       as_origen           in articulo_mov_proy.cod_origen%type,
       an_nro_mov          in articulo_mov_proy.nro_mov%TYPE,
       as_almacen          IN almacen.almacen%TYPE

) return number is

  Result        number;
  ln_count      number;
  ls_doc_oc     logparam.doc_oc%TYPE;

begin

  select doc_oc
    into ls_doc_oc
    from logparam
   where reckey = '1';


  select count(*)
    into ln_count
    from articulo_mov_proy amp
   where amp.cod_origen    = as_origen
     and amp.nro_mov       = an_nro_mov
     and amp.tipo_doc      = ls_doc_oc
     AND amp.almacen       = as_almacen
     and amp.flag_estado   <> '0';

  if ln_count = 0 then
      Result := 0;

  ELSE

      select NVL(AMP.CANT_PROYECT,0) - NVL(AMP.CANT_PROCESADA,0) as pend_recib
        into Result
        from articulo_mov_proy amp
       where amp.cod_origen    = as_origen
         and amp.nro_mov       = an_nro_mov
         and AMP.tipo_doc      = ls_doc_oc
         AND amp.almacen       = as_almacen
         and amp.flag_estado    <> '0';

    end if;

  return(Result);

end usf_cmp_cant_pendiente;
/

