prompt
prompt Creating function USF_CMP_CANT_REQUERIDA
prompt ========================================
prompt
create or replace function cantabria.usf_cmp_cant_requerida(
       asi_oper_sec  in operaciones.oper_sec%TYPE,
       asi_cod_art   in articulo.cod_art%TYPE
) return number is
  Result        number;
  ll_count      number;
  ln_cant_req   number;          -- Cantidad requerida
  ln_cant_cmp   number;          -- Cantidad Comprada
  ln_cant_ing   number;          -- CAntidad Ingresada al almacen
  ls_doc_ot     logparam.doc_ot%type;
  ls_doc_oc     logparam.doc_oc%type;
  ln_temp       number;

begin
  Select doc_ot, doc_oc
    into ls_doc_ot, ls_doc_oc
    from logparam
   where reckey = '1'  ;

   -- Cant Solicitada
   select count(*), sum(NVL(amp.cant_proyect,0)) -- - NVL(cant_procesada,0))
     into ll_count, ln_temp
     from articulo_mov_proy amp
    where amp.oper_sec = asi_oper_sec
      and amp.cod_art  = asi_cod_Art
      and amp.flag_estado = '1'
      and NVL(amp.cant_proyect,0) > NVL(cant_procesada,0)
      and amp.tipo_doc = ls_doc_ot ;

   if ll_count = 0 then
      ln_cant_req := 0;
   else
      ln_cant_req := ln_temp;
   end if;

   -- Ahora viene la cant Ingresada
   select count(*), sum(NVL(amp.cant_procesada,0))
     into ll_count, ln_temp
     from articulo_mov_proy amp
    where amp.oper_sec = asi_oper_sec
      and amp.cod_art  = asi_cod_Art
      and amp.flag_estado in ('1', '2')
      and amp.tipo_doc = ls_doc_oc;

   if ll_count = 0 then
      ln_cant_ing := 0;
   else
      ln_cant_ing := ln_temp;
   end if;

   -- Ahora viene la cant Comprada en transito
   select count(*), sum(NVL(amp.cant_proyect,0) - NVL(amp.cant_procesada,0))
     into ll_count, ln_temp
     from articulo_mov_proy amp
    where amp.oper_sec = asi_oper_sec
      and amp.cod_art  = asi_cod_Art
      and amp.flag_estado = '1'
      and amp.tipo_doc = ls_doc_oc;

   if ll_count = 0 then
      ln_cant_cmp := 0;
   else
      ln_cant_cmp := ln_temp;
   end if;

   Result := ln_cant_req - ln_cant_cmp - ln_cant_ing;
  return(Result);
end usf_cmp_cant_requerida;
/

prompt
prompt Creating function USF_CMP_CANT_REQUERIDA_L
prompt ==========================================
prompt
create or replace function cantabria.usf_cmp_cant_requerida_l(

