prompt Creating function USF_CMP_CONTEO_DET_PROG
prompt =========================================
prompt
create or replace function cantabria.usf_cmp_conteo_det_prog(
       asi_nro_programa    in prog_compras_det.nro_programa%TYPE,
       ani_nro_item        in prog_compras_det.nro_item%TYPE
) return number is
  Result number;
begin

  -- Encuentra el numero Total de registros del detalle del programa de compras

  select count(*)
    into Result
    from prog_compras_amp
   where nro_item = ani_nro_item
     and nro_programa = asi_nro_programa;

  return(Result);
end usf_cmp_conteo_det_prog;
/

prompt
prompt Creating function USF_CMP_COSTO_OC_FAP
prompt ======================================
prompt
create or replace function cantabria.usf_cmp_costo_oc_fap(
       asi_org_amp         in articulo_mov_proy.cod_origen%TYPE,
       ani_nro_amp         in articulo_mov_proy.nro_mov%TYPE,
       asi_moneda          in moneda.cod_moneda%TYPE
) return number is
  ln_Result            number(18,8);

  ln_count             number;
  ls_soles             logparam.cod_soles%TYPE;
  ls_dolares           logparam.cod_dolares%TYPE;
  ln_cant_ingresada    articulo_mov.cant_procesada%TYPE;


begin
  select cod_soles, cod_dolares
    into ls_soles, ls_dolares
    from logparam
   where reckey = '1';
  
  -- Cantidad Ingresada
  select NVL(sum(am.cant_procesada * amt.factor_sldo_total),0)
    into ln_cant_ingresada
    from vale_mov vm,
         articulo_mov am,
         articulo_mov_tipo amt
    where vm.nro_vale = am.nro_vale
      and vm.tipo_mov = amt.tipo_mov
      and vm.flag_estado <> '0'
      and am.flag_estado <> '0'
      and am.origen_mov_proy = asi_org_amp
      and am.nro_mov_proy    = ani_nro_amp;
  
  -- Primero verifico si el nro_am tiene movimiento de factura
  select count(*)
    into ln_count
    from cntas_pagar_det   cpd,
         articulo_mov_proy amp
   where cpd.org_amp_ref  = amp.cod_origen
     and cpd.nro_amp_ref  = amp.nro_mov
     and amp.cod_origen   = asi_org_amp
     and amp.nro_mov      = ani_nro_amp;

   if ln_count > 0 then
      -- Sumo el importe de todas las facturas amarradas al item de la OC
      select NVL(sum(case
                    when cp.cod_moneda = asi_moneda then
                      cpd.importe
                    when asi_moneda = ls_soles then
                      cpd.importe * cp.tasa_cambio
                    when asi_moneda = ls_dolares then
                      cpd.importe / cp.tasa_cambio
                   end
              ) / sum(cpd.cantidad) * ln_cant_ingresada ,0)
        into ln_Result
        from cntas_pagar_det   cpd,
             cntas_pagar       cp,
             articulo_mov_proy amp
       where cp.cod_relacion = cpd.cod_relacion
         and cp.tipo_doc     = cpd.tipo_doc
         and cp.nro_doc      = cpd.nro_doc
         and cpd.org_amp_ref  = amp.cod_origen
         and cpd.nro_amp_ref  = amp.nro_mov
         and amp.cod_origen   = asi_org_amp
         and amp.nro_mov      = ani_nro_amp;

   else
      -- En caso que no hubiera una factura amarrada a la ni lo busco entonces por el item de la factura
      select count(*)
        into ln_count
        from articulo_mov_proy amp
       where amp.cod_origen   = asi_org_amp
         and amp.nro_mov      = ani_nro_amp;

      if ln_count = 0 then return -1; end if;

      select nvl(sum(usf_fl_conv_mon(amp.precio_unit * am.cant_procesada, oc.cod_moneda, asi_moneda, vm.fec_registro)),0)
        into ln_Result
        from orden_compra      oc,
             articulo_mov_proy amp,
             articulo_mov      am,
             vale_mov          vm
       where oc.nro_oc        = amp.nro_doc
         and amp.tipo_doc     = (select doc_oc from logparam where reckey = '1')
         and amp.cod_origen   = am.origen_mov_proy
         and amp.nro_mov      = am.nro_mov_proy
         and am.nro_Vale      = vm.nro_vale
         and amp.cod_origen   = asi_org_amp
         and amp.nro_mov      = ani_nro_amp;


   end if;

  return(ln_Result);
end usf_cmp_costo_oc_fap;
/

prompt
prompt Creating function USF_CMP_COSTO_SERV
prompt ====================================
prompt
create or replace function cantabria.usf_cmp_costo_serv(
       asi_org_am          in articulo_mov.cod_origen%TYPE,
       ani_nro_am          in articulo_mov.nro_mov%TYPE,
       asi_moneda          in moneda.cod_moneda%TYPE
) return number is
  ln_Result            number(18,8);

  ls_soles             logparam.cod_soles%TYPE;
  ls_dolares           logparam.cod_dolares%TYPE;

begin
  select cod_soles, cod_dolares
    into ls_soles, ls_dolares
    from logparam
   where reckey = '1';

  -- Ahora busco si hay costo por Servicios asociados a la compra
    select nvl(sum(
                 case
                    when decode(cp.cod_moneda,null, os.cod_moneda, cp.cod_moneda) = asi_moneda then
                      a.importe
                    when decode(cp.cod_moneda,null, os.cod_moneda, cp.cod_moneda) = ls_soles then
                      a.importe / decode(cp.tasa_cambio, null, usf_fl_conv_mon(1, ls_dolares, ls_soles, osd.fec_proyect), cp.tasa_cambio)
                    when decode(cp.cod_moneda,null, os.cod_moneda, cp.cod_moneda) = ls_dolares then
                      a.importe * decode(cp.tasa_cambio, null, usf_fl_conv_mon(1, ls_dolares, ls_soles, osd.fec_proyect), cp.tasa_cambio)
                 end ),0)
      into ln_Result

  from oc_det_os_det       a,
       orden_servicio_det  osd,
       orden_servicio      os,
       cntas_pagar_det     cpd,
       cntas_pagar         cp
  where a.org_os           = osd.cod_origen
    and a.nro_os           = osd.nro_os
    and a.item_os          = osd.nro_item
    and os.nro_os          = osd.nro_os
    and osd.cod_origen     = cpd.org_os (+)
    and osd.nro_os         = cpd.nro_os (+)
    and osd.nro_item       = cpd.item_os (+)
    and cpd.cod_relacion   = cp.cod_relacion (+)
    and cpd.tipo_doc       = cp.tipo_doc (+)
    and cpd.nro_doc        = cp.nro_doc (+)
    and a.org_amp          = asi_org_am
    and a.nro_amp          = ani_nro_am;

  return(ln_Result);
end usf_cmp_costo_serv;
/

prompt
prompt Creating function USF_CMP_TIPO_CAMBIO
prompt =====================================
prompt
create or replace function cantabria.USF_CMP_TIPO_CAMBIO(ad_fecha in date)
    return number is

  ln_count     number;
  ln_cambio    number  := 0;
begin

  -- Busco tipo de cambio a la fecha
  Select count(vta_dol_prom) into ln_count from calendario
       Where to_char(fecha,'DD/MM/YYYY') = TO_CHAR(ad_fecha,'DD/MM/YYYY');
  if ln_count = 1 then
     Select NVL(vta_dol_prom,0) into ln_cambio from calendario
         Where to_char(fecha,'DD/MM/YYYY') = TO_CHAR(ad_fecha,'DD/MM/YYYY');
     if ln_cambio = 0 then
         Raise_application_error( -20001, 'Defina el tipo de cambio del ' ||
            TO_CHAR(ad_fecha, 'DD/MM/YYYY'));
     end if;
  else
     Raise_application_error( -20002, 'No existe tipo de cambio para el ' ||
           TO_CHAR(ad_fecha,'DD/MM/YYYY'));
  end if;

  return(ln_cambio);
end USF_CMP_TIPO_CAMBIO;
/

prompt
prompt Creating function USF_CMP_DESAPROBAR_DOC_COMPRA
prompt ===============================================
prompt
create or replace function cantabria.usf_cmp_desaprobar_doc_compra(
       as_tipo_doc         in doc_tipo.tipo_doc%type,
       as_origen           in orden_compra.cod_origen%type,
       as_nro_doc          in orden_compra.nro_oc%type,
       as_cod_usr          in usuario.cod_usr%type
) return number is

  Result                number;
  ln_count              number;
 -- ln_monto              orden_compra.monto_total%type ;
  ls_doc_oc             logparam.doc_oc%type ;
  ls_doc_os             logparam.doc_os%type ;
  ls_tipo_doc           doc_tipo.tipo_doc%type ;
  ls_cod_dolares        logparam.cod_dolares%type ;
 -- ln_nivel_aprob        logistica_aprobador.nivel_aprob%type;
--  ln_imp_max_doc        logistica_aprobador.imp_max_aprob_oc%type ;
--  ln_imp_max_aprob_item logistica_aprobador.imp_max_aprob_item_oc%type ;
--  ln_imp_max_mensual    logistica_aprobador.imp_max_mensual_oc%type ;
--  ln_saldo_aprob_mes    logistica_aprobador.saldo_aprob_mes_oc%type ;
  ln_tipo_cambio        calendario.cmp_dol_prom%type ;
  ls_cod_moneda         orden_compra.cod_moneda%type ;
  ls_aprobador          orden_compra.aprobador%type ;
--  ln_mes                cntbl_asiento.mes%type ;
--  ln_mes_aprob          logistica_aprobador.mes_aprob%type ;
  ld_fecha_doc          date ;
--  lb_desaprueba         boolean ;

begin

  --lb_desaprueba := FALSE ;
  Result := 0 ;

  SELECT l.doc_oc, l.cod_dolares, l.doc_oc, l.doc_os
    INTO ls_doc_oc, ls_cod_dolares, ls_doc_oc, ls_doc_os
    FROM logparam l
   WHERE reckey='1' ;


  -- Verifica que estados de items no esten en '3'
  IF as_tipo_doc = ls_doc_oc THEN
     ls_tipo_doc := ls_doc_oc ;

     SELECT count(*)
       INTO ln_count
       FROM articulo_mov_proy amp
      WHERE amp.cod_origen = as_origen
        AND amp.tipo_doc = ls_doc_oc
        AND amp.nro_doc = as_nro_doc
        AND amp.flag_estado <> '1';
  ELSE
     ls_tipo_doc := ls_doc_os ;

     SELECT count(*)
       INTO ln_count
       FROM orden_servicio_det osd
      WHERE osd.cod_origen = as_origen
        AND osd.nro_os = as_nro_doc
        AND osd.flag_estado <> '1';
  END IF ;

  IF ln_count>0 THEN
  		RAISE_APPLICATION_ERROR( -20001, 'Documento :'||as_nro_doc||' tiene items con estados diferentes de activo') ;
	  	return(result) ;
  END IF ;

  -- Verifica que no tengan ningun adelanto de cntas por pagar
  SELECT count(*)
    INTO ln_count
    FROM doc_referencias d
   WHERE d.tipo_ref = ls_tipo_doc
     AND d.nro_ref = as_nro_doc ;

  IF ln_count > 0 THEN
 		 RAISE_APPLICATION_ERROR( -20002, 'Documento :'||as_nro_doc||' tiene referencias DOC_REFERENCIAS') ;
	   return(result) ;
  END IF ;

  -- Verifica que items (OC) no haya sido atendido
  IF as_tipo_doc = ls_doc_oc THEN
     SELECT count(*)
       INTO ln_count
       FROM articulo_mov_proy amp
      WHERE amp.cod_origen = as_origen
        AND amp.tipo_doc = ls_doc_oc
        AND amp.nro_doc = as_nro_doc
        AND amp.cant_procesada > 0 ;

     IF ln_count > 0 THEN
   	    RAISE_APPLICATION_ERROR( -20002, 'Documento :'||as_nro_doc||' tiene cantidades procesadas') ;
  	    return(result) ;
     END IF ;
  END IF ;

	-- Verificando si usuario es aprobador
	SELECT count(*)
    INTO ln_count
    FROM logistica_aprobador l
   WHERE l.cod_usr=as_cod_usr ;

	IF ln_count=0 THEN
		RAISE_APPLICATION_ERROR( -20001, 'Usuario :'||as_cod_usr||' no es aprobador de documento de compra') ;
		return(result) ;
	END IF ;

  -- Verificando si es del mismo mes para devolver dinero
  IF to_char( ld_fecha_doc,'mm') = to_char(sysdate, 'mm') THEN
      -- Verificando datos de anterior aprobacion
      IF as_tipo_doc = ls_doc_oc THEN
         SELECT o.cod_moneda, o.fecha_aprob, NVL(o.aprobador,'A')
           INTO ls_cod_moneda, ld_fecha_doc, ls_aprobador
           FROM orden_compra o
          WHERE o.cod_origen=as_origen AND
                o.nro_oc = as_nro_doc ;
      ELSE
         SELECT o.cod_moneda, o.fecha_aprob, NVL(o.aprobador,'A')
           INTO ls_cod_moneda, ld_fecha_doc, ls_aprobador
           FROM orden_servicio o
          WHERE o.cod_origen=as_origen AND
                o.nro_os = as_nro_doc ;
      END IF ;

      IF ls_aprobador = 'A' THEN
    		RAISE_APPLICATION_ERROR( -20002, 'Documento :'||as_nro_doc ||' no puede desaprobarse' );
    		return(result) ;
      END IF ;

      ln_tipo_cambio := USF_CMP_TIPO_CAMBIO(ld_fecha_doc) ;

  END IF ;

  -- Actualizar tablas de desactualizacion
  IF as_tipo_doc=ls_doc_oc THEN
      insert into oc_desaprobacion(org_oc, nro_oc, fecha, cod_usr, flag_replicacion)
      values (as_origen, as_nro_doc, sysdate, as_cod_usr, '0') ;
  ELSE
      insert into oc_desaprobacion(org_oc, nro_oc, fecha, cod_usr, flag_replicacion)
      values (as_origen, as_nro_doc, sysdate, as_cod_usr, '0') ;
  END IF ;


/*
  -- Verificando si documento ya esta aprobado
  IF as_tipo_doc = ls_doc_oc THEN

     -- Capturando parametros del aprobador
     SELECT l.nivel_aprob, l.imp_max_aprob_oc, l.imp_max_aprob_item_oc,
            l.imp_max_mensual_oc, l.saldo_aprob_mes_oc, l.mes_aprob
       INTO ln_nivel_aprob, ln_imp_max_doc, ln_imp_max_aprob_item,
            ln_imp_max_mensual, ln_saldo_aprob_mes, ln_mes_aprob
       FROM logistica_aprobador l
      WHERE l.cod_usr = as_cod_usr ;

     IF ls_cod_moneda = ls_cod_dolares THEN
       -- Verificando que los items no pasen importe maximo
       SELECT count(*)
         INTO ln_count
         FROM articulo_mov_proy amp
        WHERE amp.tipo_doc = as_tipo_doc  AND
              amp.nro_doc = as_nro_doc AND
              amp.flag_estado = '3' AND
              amp.precio_unit > ln_imp_max_aprob_item ;
     ELSE
       SELECT count(*)
         INTO ln_count
         FROM articulo_mov_proy amp
        WHERE amp.tipo_doc = as_tipo_doc AND
              amp.nro_doc = as_nro_doc AND
              amp.flag_estado = '3' AND
              amp.precio_unit/ln_tipo_cambio > ln_imp_max_aprob_item ;
     END IF ;

     IF ln_count>0 THEN
        RAISE_APPLICATION_ERROR(-20003, 'Item de documento supera monto permitido') ;
        Return(result) ;
     END IF ;

     -- Verificando que sea el tipo de articulo permitido
     SELECT count(*)
       INTO ln_count
       FROM articulo_mov_proy amp, articulo a
      WHERE amp.cod_art = a.cod_art AND
            amp.tipo_doc = as_tipo_doc AND
            amp.nro_doc = as_nro_doc AND
            amp.flag_estado = '3' AND
            a.nivel_aprob > ln_nivel_aprob ;

     IF ln_count > 0 THEN
         RAISE_APPLICATION_ERROR(20003, 'Usuario no tiene nivel apropiado') ;
        Return(result) ;
     END IF ;

     -- Calculando monto a aprobar
     SELECT SUM(NVL(amp.cant_proyect,0) * (NVL(amp.precio_unit,0) - NVL(amp.decuento,0)))
       INTO ln_monto
       FROM articulo_mov_proy amp
      WHERE amp.tipo_doc = as_tipo_doc AND
            amp.nro_doc = as_nro_doc AND
            amp.flag_estado = '3' ;

  ELSE

     SELECT o.cod_moneda, o.fec_registro, NVL(o.aprobador,'A')
       INTO ls_cod_moneda, ld_fecha_doc, ls_aprobador
       FROM orden_servicio o
      WHERE o.cod_origen=as_origen AND
            o.nro_os = as_nro_doc AND
            o.aprobador IS null ;

     IF ls_aprobador <> 'A' THEN
    		RAISE_APPLICATION_ERROR( -20002, 'Orden servicio :'||as_nro_doc ||' ya esta aprobada' );
    		return(result) ;
     END IF ;

     -- Capturando parametros del aprobador
     SELECT l.nivel_aprob, l.imp_max_aprob_os, l.imp_max_aprob_item_os,
            l.imp_max_mensual_os, l.saldo_aprob_mes_os
       INTO ln_nivel_aprob, ln_imp_max_doc, ln_imp_max_aprob_item,
            ln_imp_max_mensual, ln_saldo_aprob_mes
       FROM logistica_aprobador l
      WHERE l.cod_usr = as_cod_usr ;

     IF ls_cod_moneda = ls_cod_dolares THEN
       -- Verificando que los items no pasen importe maximo
       SELECT count(*)
         INTO ln_count
         FROM orden_servicio_det osd
        WHERE osd.cod_origen = as_origen AND
              osd.nro_os = as_nro_doc AND
              ( NVL(osd.importe,0) - NVL(osd.decuento,0)) > ln_imp_max_aprob_item ;
     ELSE
       -- Verificando que los items no pasen importe maximo
       SELECT count(*)
         INTO ln_count
         FROM orden_servicio_det osd
        WHERE osd.cod_origen = as_origen AND
              osd.nro_os = as_nro_doc AND
              ( NVL(osd.importe,0) - NVL(osd.decuento,0)) / ln_tipo_cambio > ln_imp_max_aprob_item ;
     END IF ;

     IF ln_count>0 THEN
        RAISE_APPLICATION_ERROR(-20003, 'Item de documento supera monto permitido') ;
        Return(result) ;
     END IF ;


     -- Calculando monto a aprobar
     SELECT SUM( NVL(osd.importe,0) - NVL(osd.decuento,0) )
       INTO ln_monto
       FROM orden_servicio_det osd
      WHERE osd.cod_origen = as_origen AND
            osd.nro_os = as_nro_doc AND
            osd.flag_estado = '3' ;

  END IF ;

  -- Verificando montos mensuales
  IF ln_monto > ln_imp_max_doc THEN
     RAISE_APPLICATION_ERROR(-20004, 'Importe supera monto permitido por documento') ;
     Return(result) ;
  END IF ;

  IF ln_mes = ln_mes_aprob THEN
     IF (ln_saldo_aprob_mes + ln_monto) >= ln_imp_max_mensual THEN
        RAISE_APPLICATION_ERROR(-20004, 'Importe supera monto permitido mensual ') ;
        Return(result) ;
     END IF ;
  ELSE
     IF ln_monto >= ln_imp_max_mensual THEN
        RAISE_APPLICATION_ERROR(-20004, 'Importe supera monto permitido mensual') ;
        Return(result) ;
     END IF ;
  END IF ;

  result := 1 ;

  UPDATE logistica_aprobador l
    SET l.mes_aprob = ln_mes,
        l.saldo_aprob_mes_oc = NVL(l.saldo_aprob_mes_oc,0) + ln_monto
  WHERE l.cod_usr = as_cod_usr ;
  */
  return(Result);
end usf_cmp_desaprobar_doc_compra;
/

prompt
prompt Creating function USF_CMP_DIRECCION_CODREL
prompt ==========================================
prompt
create or replace function cantabria.USF_CMP_DIRECCION_CODREL(as_codrel in char,as_tipo in char  )
 return varchar2 is

  ls_dir   varchar2(250);
begin

  Select NVL(dir_direccion,'') || ' ' || NVL(dir_numero,'') || ' ' ||
     NVL(dir_lote, '') || ' ' || NVL(dir_mnz, '') || ' ' ||
     NVL(dir_urbanizacion, '') || ' ' || NVL(dir_distrito,'') || ' ' ||
	   NVL(dir_provincia,'') || ' ' || NVL(dir_dep_estado,'') || ' ' ||
     NVL(dir_cod_postal,'')
  INTO ls_dir
	from direcciones where (codigo   = as_codrel )and
                         (flag_uso = as_tipo   );

  return(ls_dir);
  EXCEPTION
    WHEN NO_DATA_FOUND THEN
     RETURN ('');
end USF_CMP_DIRECCION_CODREL;
/

prompt
prompt Creating function USF_CMP_DIRECCION_EMPRESA
prompt ===========================================
prompt
create or replace function cantabria.USF_CMP_DIRECCION_EMPRESA(
       as_origen in origen.cod_origen%TYPE
)
 return varchar2 is

  ls_dir         varchar2(250);
  ls_calle       origen.dir_calle%TYPE;
  ls_numero      origen.dir_numero%TYPE;
  ls_lote        origen.dir_lote%TYPE;
  ls_mnz         origen.dir_mnz%TYPE;
  ls_urb         origen.dir_urbanizacion%TYPE;
  ls_distrito    origen.dir_distrito%TYPE;
  ls_provincia   origen.dir_provincia%TYPE;
  ls_dpto        origen.dir_departamento%TYPE;
  ls_cod_postal  origen.dir_cod_postal%TYPE;
begin

  Select NVL(dir_calle,''),     NVL(dir_numero,''),        NVL(dir_lote, ''),
         NVL(dir_mnz, '') ,     NVL(dir_urbanizacion, ''), NVL(dir_distrito,''),
	       NVL(dir_provincia,''), NVL(dir_departamento,''),  NVL(dir_cod_postal,'')
    INTO ls_calle,              ls_numero,                 ls_lote,
         ls_mnz,                ls_urb,                    ls_distrito,
         ls_provincia,          ls_dpto,                   ls_cod_postal
	from origen
  where cod_origen = as_origen;

  ls_dir := '';
  if length(ls_calle)      <> 0 then ls_dir := ls_dir || ls_calle || ' '; end if;
  if length(ls_numero)     <> 0 then ls_dir := ls_dir || ls_numero || ' '; end if;
  if length(ls_lote)       <> 0 then ls_dir := ls_dir || ls_lote || ' ';   end if;
  if length(ls_mnz)        <> 0 then ls_dir := ls_dir || ls_mnz || ' ';    end if;
  if length(ls_urb)        <> 0 then ls_dir := ls_dir || ls_urb || ' ';    end if;
  if length(ls_distrito)   <> 0 then ls_dir := ls_dir || ls_distrito || ' '; end if;
  if length(ls_provincia)  <> 0 then ls_dir := ls_dir || ls_provincia || ' '; end if;
  if length(ls_dpto)       <> 0 then ls_dir := ls_dir || ls_dpto || ' '; end if;
  if length(ls_cod_postal) <> 0 then ls_dir := ls_dir || ls_cod_postal || ' '; end if;

  return(ls_dir);
end USF_CMP_DIRECCION_EMPRESA;
/

prompt
prompt Creating function USF_CMP_FECHA_ULT_COMPRA
prompt ==========================================
prompt
create or replace function cantabria.usf_cmp_fecha_ult_compra(
       asi_cod_art         in articulo.cod_art%TYPE,
       asi_almacen         in almacen.almacen%TYPE,
       asi_tipo            in articulo.flag_estado%type
) return date is

  -- Retorna fecha de ultima compra
  --asi_tipo ==> G=General, A=Almacen

  Result   date;
  ll_count number;

begin
   -- Todos los almacenes
   IF asi_tipo='G' THEN
      select count(*)
        into ll_count
        from articulo
       where cod_art = asi_cod_art;

      if ll_count = 0 then
         result := null ;
      else
         select a.fec_ult_compra
           into result
           from articulo a
          where cod_art = asi_cod_art;
      end if;
   ELSE
   -- Fecha ultima de un almacen
     select count(*)
       into ll_count
       from articulo_almacen aa
      where aa.cod_art = asi_cod_art
        and aa.almacen = asi_almacen;

     IF ll_count=0 THEN
        result := null ;
     ELSE
      select aa.fec_ult_compra
        into result
        from articulo_almacen aa
       where aa.cod_art = asi_cod_art
         and aa.almacen = asi_almacen;
     END IF ;

   END IF ;

  return(Result);
end usf_cmp_fecha_ult_compra;
/

prompt
prompt Creating function USF_CMP_FEC_PROYECT
prompt =====================================
prompt
create or replace function cantabria.usf_cmp_fec_proyect(
       --asi_opersec         in operaciones.oper_sec%TYPE,
       as_origen           in articulo_mov_proy.cod_origen%type,
       an_nro_mov          in articulo_mov_proy.nro_mov%type--,
       --asi_cod_art         in articulo.cod_art%TYPE,
       --asi_almacen         in almacen.almacen%TYPE
) return date is

  Result        date;
  ls_doc_ot     logparam.doc_ot%TYPE;
begin

  select doc_ot
    into ls_doc_ot
    from logparam
   where reckey = '1';

  select min(amp.fec_proyect)
    into Result
    from articulo_mov_proy amp
   --where amp.oper_sec = asi_opersec
   where amp.cod_origen = as_origen
     and amp.nro_mov = an_nro_mov
     --and amp.cod_art  = asi_cod_art
     and tipo_doc     = ls_doc_ot
     --and almacen      = asi_almacen
     and amp.flag_estado <> '0';

  return(Result);
end usf_cmp_fec_proyect;
/

prompt
prompt Creating function USF_CMP_PREC_ULT_COMPRA
prompt =========================================
prompt
create or replace function cantabria.usf_cmp_prec_ult_compra(
       asi_cod_art         in articulo.cod_art%TYPE,
       asi_almacen         in almacen.almacen%TYPE
) return number is

  -- Retorna el precio unitario en dolares

  ln_Result            number;
  ll_count             number;
  ln_prc_cmp_ref       logparam.precio_cmp_ref%TYPE;

BEGIN

   SELECT precio_cmp_ref
     INTO ln_prc_cmp_ref
     FROM logparam
    WHERE reckey = '1';

   select count(*)
     into ll_count
    from articulo_almacen aa
    where aa.cod_art = asi_cod_art
      and aa.almacen = asi_almacen;

   if ll_count = 0 then
      select count(*)
        into ll_count
        from articulo
       where cod_art = asi_cod_art;

      if ll_count = 0 then
         ln_result := ln_prc_cmp_ref;
      else
         select nvl(costo_ult_compra,0)
           into ln_Result
           from articulo
          where cod_art = asi_cod_art;
      end if;
   else
      select nvl(costo_ult_compra,0)
       into ln_Result
      from articulo_almacen aa
      where aa.cod_art = asi_cod_art
        and aa.almacen = asi_almacen;

      if ln_Result = 0 then
         select nvl(costo_ult_compra,0)
           into ln_Result
           from articulo
          where cod_art = asi_cod_art;
      end if;
   end if;

   -- Si el precio de ultima compra es el mismo que en Parametros entonces
   -- Busco el ultimo precio de cotizacion
   IF ln_Result = ln_prc_cmp_ref OR ln_Result <= 0 THEN
      ln_Result := usf_cmp_ult_prec_cotiz(asi_cod_art);
   END IF;

  return(ln_Result);
end usf_cmp_prec_ult_compra;
/

prompt
prompt Creating function USF_CMP_GASTOS_PROY_AMP
prompt =========================================
prompt
create or replace function cantabria.USF_CMP_GASTOS_PROY_AMP(
    asi_cencos     in centros_costo.cencos%type,
    asi_cnta_prsp  in presupuesto_cuenta.cnta_prsp%type,
    adi_fecha      in date
) return number is

  ln_ctrl        presupuesto_partida.flag_ctrl%type;
  ll_count       number;
  ln_return      number;
  ln_year        number(4);
  ln_mes         number(2);
  ls_doc_ot      logparam.doc_ot%TYPE;

begin
    ln_return := 0 ;
    ln_year := to_number(to_char(adi_fecha, 'yyyy'));
    ln_mes  := to_number(to_char(adi_fecha, 'mm'));

    -- Documento de Orden de Trabajo
    select doc_ot
      into ls_doc_ot
      from logparam
     where reckey = '1';

    -- Busca si existe partida, caso contrario devuelve error
    Select Count(*)
       into ll_count
       from presupuesto_partida
      Where ano       = ln_year
        and cencos    = asi_cencos
        and cnta_prsp = asi_cnta_prsp ;

    if ll_count = 0 then  -- No existe partida
/*      RAISE_APPLICATION_ERROR( -20000, 'No existe Partida presupuestal '||
              'Para: ' || trim(asi_cencos) || ', ' || trim(asi_cnta_prsp)
              || ', A?o: ' || ln_year ) ;*/
       return 0;
    end if;

    -- Evalua si tiene presupuesto segun flag de control
    -- Segun Partida presupuestal, halla la forma de procesar
    Select NVL(p.flag_ctrl, '0')
      into ln_ctrl
      from presupuesto_partida p
     where p.ano       = ln_year
       and p.cencos    = asi_cencos
       and p.cnta_prsp = asi_cnta_prsp;

    --==========================
     -- Sin control
    --==========================
    if ln_ctrl = '0' then
       ln_return := 0;
        return ln_return ;
    end if;

    --==========================
    -- Acumulado Anual
    --==========================
    if ln_ctrl = '1' then
       select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
         into ln_return
         from articulo_mov_proy amp,
              articulo          a
        where a.cod_art = amp.cod_art
          and amp.flag_estado <> '0'
          and NVL(a.flag_inventariable, '0') <> '0'
          and amp.cencos      = asi_cencos
          and amp.cnta_prsp   = asi_cnta_prsp
          and amp.tipo_doc    = ls_doc_ot
          and to_char(amp.fec_proyect, 'yyyy') = to_char(ln_year);

       Return ln_return;
    end if;

    --==========================
    -- Acumulado a la Fecha
    --==========================
    if ln_ctrl = '2' then
       select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
         into ln_return
         from articulo_mov_proy amp,
              articulo          a
        where a.cod_art = amp.cod_art
          and amp.flag_estado <> '0'
          and NVL(a.flag_inventariable, '0') <> '0'
          and amp.cencos      = asi_cencos
          and amp.cnta_prsp   = asi_cnta_prsp
          and amp.tipo_doc    = ls_doc_ot
          and to_char(amp.fec_proyect, 'yyyymm') <= to_char(adi_fecha, 'yyyymm');

       Return ln_return;
    end if;

    --==========================
    -- Mensual
    --==========================
    if ln_ctrl = '3' then
       select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
         into ln_return
         from articulo_mov_proy amp,
              articulo          a
        where a.cod_art = amp.cod_art
          and amp.flag_estado = '1'
          and NVL(a.flag_inventariable, '0') <> '0'
          and amp.cencos      = asi_cencos
          and amp.cnta_prsp   = asi_cnta_prsp
          and amp.tipo_doc    = ls_doc_ot
          and to_char(amp.fec_proyect, 'yyyymm') = to_char(adi_fecha, 'yyyymm');

       Return ln_return;
    end if;

    --==========================
    -- Ultimo Trimestre Acumulado
    --==========================
    if ln_ctrl = '4' then
       if ln_mes = 1 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') = to_char(ln_year) || '01';

       elsif ln_mes = 2 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '01', to_char(ln_year) || '02') ;

       elsif ln_mes = 3 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '01', to_char(ln_year) || '02', to_char(ln_year) || '03') ;

       elsif ln_mes = 4 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '02', to_char(ln_year) || '03', to_char(ln_year) || '04') ;

       elsif ln_mes = 5 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '03', to_char(ln_year) || '04', to_char(ln_year) || '05') ;

       elsif ln_mes = 6 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '04', to_char(ln_year) || '05', to_char(ln_year) || '06') ;

       elsif ln_mes = 7 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '05', to_char(ln_year) || '06', to_char(ln_year) || '07') ;

       elsif ln_mes = 8 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '06', to_char(ln_year) || '07', to_char(ln_year) || '08') ;

       elsif ln_mes = 9 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '07', to_char(ln_year) || '08', to_char(ln_year) || '09') ;

       elsif ln_mes = 10 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
