           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.nro_doc     = asi_nro_orden
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '01', to_char(ln_year) || '02', to_char(ln_year) || '03') ;

       elsif ln_mes = 4 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.nro_doc     = asi_nro_orden
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '02', to_char(ln_year) || '03', to_char(ln_year) || '04') ;

       elsif ln_mes = 5 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.nro_doc     = asi_nro_orden
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '03', to_char(ln_year) || '04', to_char(ln_year) || '05') ;

       elsif ln_mes = 6 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.nro_doc     = asi_nro_orden
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '04', to_char(ln_year) || '05', to_char(ln_year) || '06') ;

       elsif ln_mes = 7 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.nro_doc     = asi_nro_orden
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '05', to_char(ln_year) || '06', to_char(ln_year) || '07') ;

       elsif ln_mes = 8 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.nro_doc     = asi_nro_orden
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '06', to_char(ln_year) || '07', to_char(ln_year) || '08') ;

       elsif ln_mes = 9 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.nro_doc     = asi_nro_orden
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '07', to_char(ln_year) || '08', to_char(ln_year) || '09') ;

       elsif ln_mes = 10 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.nro_doc     = asi_nro_orden
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '08', to_char(ln_year) || '09', to_char(ln_year) || '10') ;

       elsif ln_mes = 11 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
            from articulo_mov_proy amp,
                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.nro_doc     = asi_nro_orden
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '09', to_char(ln_year) || '10', to_char(ln_year) || '11') ;

       elsif ln_mes = 12 then

          select Sum((amp.cant_proyect - NVL(amp.cant_procesada,0)) * usf_cmp_prec_ult_compra(amp.cod_art, amp.almacen))
            into ln_return
