                 articulo          a
           where a.cod_art = amp.cod_art
             and amp.flag_estado = '1'
             and NVL(a.flag_inventariable, '0') <> '0'
             and amp.cencos      = asi_cencos
             and amp.cnta_prsp   = asi_cnta_prsp
             and amp.nro_doc     = asi_nro_orden
             and amp.tipo_doc    = ls_doc_ot
             and to_char(amp.fec_proyect, 'yyyymm') in(to_char(ln_year) || '10', to_char(ln_year) || '11', to_char(ln_year) || '12') ;

       end if;

       Return ln_return;
    end if;

    return(ln_Return);
end USF_CMP_GASTOS_PROY_X_OT;
/

prompt
prompt Creating function USF_CMP_ITEMS_NI
prompt ==================================
prompt
create or replace function cantabria.usf_cmp_items_ni(
as_tipo_doc articulo_mov_proy.tipo_doc%type,
as_nro_doc articulo_mov_proy.nro_doc%type,
as_cod_origen articulo_mov_proy.cod_origen%type,
as_nro_mov articulo_mov_proy.nro_mov%type
) return number is
  Result number;
begin

  -- Indica si hay algun ingreso de material para un item de la OC

  select count(*)
    into Result
    from vale_mov vm, articulo_mov am
   where vm.nro_vale = am.nro_vale;

  return(Result);
end usf_cmp_items_ni;
/

prompt
prompt Creating function USF_CMP_ITEMS_OC
prompt ==================================
prompt
create or replace function cantabria.usf_cmp_items_oc(
       as_origen         in orden_compra.cod_origen%type,
       as_nro         in orden_compra.nro_oc%type
) return number is

  Result        number;
  ls_doc_oc     logparam.doc_oc%type;

Begin

  select doc_oc
    into ls_doc_oc
    from logparam
   where reckey = '1';

  select count(*)
    into Result
    from articulo_mov_proy amp
   where amp.cod_origen = as_origen
     and amp.nro_doc = as_nro
     and tipo_doc     = ls_doc_oc
     and amp.flag_estado <> '0';

  return(Result);
end usf_cmp_items_oc;
/

prompt
prompt Creating function USF_CMP_LOG_VAR_OC
prompt ====================================
prompt
create or replace function cantabria.usf_cmp_log_var_oc
(ac_org_amp in articulo_mov_proy.cod_origen%type,
 an_nro_amp in articulo_mov_proy.nro_mov%type     )



  return  number is
  ln_cant_original articulo_mov_proy.cant_proyect%type;

 ln_count Number ;

begin

select count(*) into ln_count
  from log_var_amp_oc l
 where (l.org_amp = ac_org_amp ) and
       (l.nro_amp = an_nro_amp) ;

if ln_count > 0 then
   select cant_original into ln_cant_original
     from  log_var_amp_oc
    where  (org_amp = ac_org_amp) and
           (nro_amp = an_nro_amp) and
           (fecha   in (select min(fecha)
                         from log_var_amp_oc
                        where (org_amp = ac_org_amp ) and
                              (nro_amp = an_nro_amp )  ) );
else
    select amp.cant_proyect
      into ln_cant_original
      from articulo_mov_proy amp
     where (amp.cod_origen = ac_org_amp ) and
           (amp.nro_mov    = an_nro_amp ) ;

end if;

  return(ln_cant_original);
end usf_cmp_log_var_oc;
/

prompt
prompt Creating function USF_CMP_OPER_SEC_ACTIVO
prompt =========================================
prompt
create or replace function cantabria.USF_CMP_OPER_SEC_ACTIVO(
       asi_oper_sec  in operaciones.oper_sec%TYPE
) return number is
  ln_Result              number;
  ls_estado_op           operaciones.flag_Estado%TYPE;
  ls_flag_ctrl_aprt_ot   ot_administracion.flag_ctrl_aprt_ot%TYPE;
begin

  select NVL(ot2.flag_ctrl_aprt_ot, '0'), op.flag_estado
    into ls_flag_ctrl_aprt_ot, ls_estado_op
    from operaciones   op,
         orden_trabajo ot,
         ot_administracion  ot2
   where ot.nro_orden = op.nro_orden
     and ot2.ot_adm   = ot.ot_adm
     and op.oper_sec  = asi_oper_sec;

  if ls_flag_ctrl_aprt_ot = '1' and ls_estado_op = '1' then return 1; end if;
  if ls_flag_ctrl_aprt_ot = '0' and ls_estado_op in ('1', '3') then return 1; end if;
  return 0;

end USF_CMP_OPER_SEC_ACTIVO;
/

prompt
prompt Creating function USF_CMP_OPER_SEC_PROG
prompt =======================================
prompt
create or replace function cantabria.usf_cmp_oper_sec_prog(
       asi_nro_programa    in prog_compras_det.nro_programa%TYPE,
       ani_nro_item        in prog_compras_det.nro_item%TYPE
) return varchar2 is
  ln_Result varchar2(10);
begin

  select min(oper_sec)
    into ln_Result
    from articulo_mov_proy amp,
         prog_compras_det  pcd
   where pcd.org_amp_ot_ref   = amp.cod_origen
     and pcd.nro_amp_ot_ref   = amp.nro_mov
     and pcd.nro_programa     = asi_nro_programa
     and pcd.nro_item         = ani_nro_item;

  return(ln_Result);
end usf_cmp_oper_sec_prog;
/

prompt
prompt Creating function USF_CMP_OT_ADM
prompt ================================
prompt
create or replace function cantabria.usf_cmp_ot_adm(
       asi_org_amp  in articulo_mov_proy.cod_origen%TYPE,
       ani_nro_amp  in articulo_mov_proy.nro_mov%TYPE
) return varchar2 is

  ls_Result varchar2(10);
  ln_count  number;
  ls_doc_ot logparam.doc_ot%TYPE;

begin
  select doc_ot
    into ls_doc_ot
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
    from articulo_mov_proy amp,
         orden_trabajo     ot
   where ot.nro_orden   = amp.nro_doc
     and amp.tipo_doc   = ls_doc_ot
     and amp.cod_origen = asi_org_amp
     and amp.nro_mov    = ani_nro_amp;

  if ln_count = 0 then
     ls_Result := null;
  else
     select ot.ot_adm
      into ls_Result
      from articulo_mov_proy amp,
           orden_trabajo     ot
     where ot.nro_orden   = amp.nro_doc
       and amp.tipo_doc   = ls_doc_ot
       and amp.cod_origen = asi_org_amp
       and amp.nro_mov    = ani_nro_amp;
  end if;

  return(ls_Result);
end usf_cmp_ot_adm;
/

prompt
prompt Creating function USF_CMP_OT_PEN_ATENDER
prompt ========================================
prompt
create or replace function cantabria.usf_cmp_ot_pen_atender(

       as_origen           in articulo_mov_proy.cod_origen%type,
       an_nro_mov          in articulo_mov_proy.nro_mov%TYPE,
       asi_almacen         IN almacen.almacen%TYPE

) return number is

  Result        number;
  ln_count      number;
  ls_doc_ot     logparam.doc_ot%TYPE;

begin

  select doc_ot
    into ls_doc_ot
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
    from articulo_mov_proy amp
   where amp.cod_origen    = as_origen
     and amp.nro_mov       = an_nro_mov
     and amp.tipo_doc      = ls_doc_ot
     AND amp.almacen       = asi_almacen
     and amp.flag_estado   <> '0';

  if ln_count = 0 then
      Result := 0;
  else
      select nvl(sum(amp.cant_proyect),0) - nvl(SUM(amp.cant_procesada),0)
        into Result
        from articulo_mov_proy amp
       where amp.cod_origen = as_origen
         and amp.nro_mov    = an_nro_mov
         and amp.tipo_doc   = ls_doc_ot
         AND amp.almacen    = asi_almacen
         and amp.flag_estado <> '0';

  end if;

  return(Result);

end usf_cmp_ot_pen_atender;
/

prompt
prompt Creating function USF_CMP_PREC_ULT_CMP_PROV
prompt ===========================================
prompt
create or replace function cantabria.usf_cmp_prec_ult_cmp_prov(
       asi_cod_art         in articulo.cod_art%TYPE,
       asi_proveedor       in proveedor.proveedor%TYPE,
       asi_almacen         in almacen.almacen%TYPE,
       asi_moneda          in moneda.cod_moneda%type,
       adi_Fecha           in date
) return number is

  ln_Result        number;
  ll_count         number;
  ls_moneda        moneda.cod_moneda%type ;
  ls_doc_oc        logparam.doc_oc%TYPE;
  ln_precio_unit   articulo_mov_proy.precio_unit%TYPE;

BEGIN
   -- Esta funcion te busca el precio de ultima compra del ariculo
   -- por un determinado proveedor y lo decuelve al tipo de cambio
   -- Correspondiente por el codigo de moneda asi_moneda

   select doc_oc
     into ls_doc_oc
   from logparam
   where reckey = '1';

   -- Buscando el ultimo precio de compra
   select count(*)
     into ll_count
    from articulo_mov_proy amp,
         orden_Compra      oc
    where oc.nro_oc        = amp.nro_doc
      and amp.tipo_doc     = ls_doc_oc
      and amp.almacen      = asi_almacen
      and amp.flag_estado  <> '0'
      and oc.flag_estado   <> '0'
      and amp.cod_art      = asi_cod_art
      and oc.proveedor     = asi_proveedor;

   if ll_count = 0 then
      ln_Result := 0;
   else
       select precio_unit, cod_moneda
         into ln_precio_unit, ls_moneda
       from ( select amp.precio_unit, oc.cod_moneda
                from articulo_mov_proy amp,
                     orden_Compra      oc
                where oc.nro_oc        = amp.nro_doc
                  and amp.tipo_doc     = ls_doc_oc
                  and amp.flag_estado  <> '0'
                  and oc.flag_estado   <> '0'
                  and amp.cod_art      = asi_cod_art
                  and oc.proveedor     = asi_proveedor
                  and amp.almacen      = asi_almacen
                order by oc.fec_registro desc)
         where rownum = 1 ;

       ln_Result := NVL(usf_fl_conv_mon(ln_precio_unit, ls_moneda, asi_moneda, adi_fecha), 0);

   end if;

  return(ln_Result);
end usf_cmp_prec_ult_cmp_prov;
/

prompt
prompt Creating function USF_CMP_PREC_COMPRA_ARTIC
prompt ===========================================
prompt
create or replace function cantabria.usf_cmp_prec_compra_artic(
       asi_cod_art         in articulo.cod_art%TYPE,
       asi_proveedor       in proveedor.proveedor%type,
       adi_fec_reg         in orden_compra.fec_registro%type,
       asi_almacen         in almacen.almacen%TYPE,
       asi_moneda          in moneda.cod_moneda%type
) return number is

  ln_Result        number;
  ll_count         number;
  ls_moneda        moneda.cod_moneda%TYPE;

BEGIN


   -- Primero busco el precio del articulo por el precio pactado
		select count(*)
		  into ll_count
		from articulo_precio_pactado
		where cod_art 		= asi_cod_art
		  and proveedor 	= asi_proveedor
		  and trunc(fecha_inicio) <= trunc(adi_fec_reg)
		  and trunc(fecha_fin) >= trunc(adi_fec_reg)
		  and flag_estado = '1';

		IF ll_count > 0 THEN
			 select NVL(precio_compra,0), app.cod_moneda
				 into ln_Result, ls_moneda
			   from articulo_precio_pactado app
			  where cod_art 		= asi_cod_art
			    and proveedor 	= asi_proveedor
			    and trunc(fecha_inicio) <= trunc(adi_fec_reg)
			    and trunc(fecha_fin) >= trunc(adi_fec_reg)
			    and flag_estado = '1';

       ln_Result := usf_fl_conv_mon(ln_Result, ls_moneda, asi_moneda, adi_fec_reg);

		ELSE
			ln_Result := nvl(usf_cmp_prec_ult_cmp_prov(asi_cod_art, asi_proveedor, asi_almacen, asi_moneda, adi_fec_reg),0);
		END IF ;

  return( ln_Result );

end usf_cmp_prec_compra_artic;
/

prompt
prompt Creating function USF_CMP_PRECIO_UNITARIO
prompt =========================================
prompt
create or replace function cantabria.USF_CMP_PRECIO_UNITARIO (
    an_descuento   in articulo_mov.decuento%TYPE,
    an_precio_unit in articulo_mov.precio_unit%TYPE,
    as_mon_ori     in moneda.cod_moneda%TYPE,
    ad_fecha       in date,
    as_mon_dev     in moneda.cod_moneda%TYPE
)return number is

/*
   funcion que retorna el precio unitario
   param.:
      an_descuento   = descuento  En porcentaje
      an_precio_unit = precio unitario
      as_mon_ori     = moneda original
      ad_fecha       = fecha del registro
      as_mon_dev     = tipo de moneda a devolver el precio
*/
  ln_precio    number;
  ln_descuento number;
  ln_cmp_prom  number;
  ln_vta_prom  number;
  ls_sol       logparam.cod_soles%type;
  ln_count     number;
begin

  -- Busca codigo de monedas
  Select l.cod_soles
    into ls_sol
    from logparam l
   Where reckey = '1';

  -- aplica el descuento
     ln_descuento := Nvl((an_precio_unit * (Nvl(an_descuento,0)/100) ),0) ;
     ln_precio    := an_precio_unit - ln_descuento ;

     if as_mon_ori <> as_mon_dev then
        -- Busca tipo de cambio
        SELECT count(*) INTO ln_count
          FROM   calendario
          WHERE  to_char(fecha,'yyyymmdd') = to_char(ad_fecha,'yyyymmdd') ;

        if ln_count > 0 then  -- existe tipo cambio
           SELECT Nvl(cmp_dol_prom,0), NVL(vta_dol_prom,0)
             INTO   ln_cmp_prom, ln_vta_prom
             FROM   calendario
             WHERE  to_char(fecha,'yyyymmdd') = to_char(ad_fecha,'yyyymmdd') ;

             if as_mon_dev = ls_sol then
                ln_precio := ln_precio * ln_vta_prom; -- convierte dol -> sol
             else
                ln_precio := ln_precio / ln_cmp_prom; -- convierte sol -> dol
             end if;
        else
           RAISE_APPLICATION_ERROR( -20000, 'tipo cambio no definido' || ad_fecha);
        end if;
     end if;
  return(ln_precio);
end USF_CMP_PRECIO_UNITARIO;
/

prompt
prompt Creating function USF_CMP_PREC_ULT_COMPRA_MONEDA
prompt ================================================
prompt
create or replace function cantabria.usf_cmp_prec_ult_compra_moneda(
       asi_cod_art         in articulo.cod_art%TYPE,
       asi_almacen         in almacen.almacen%TYPE,
       asi_moneda          in moneda.cod_moneda%type
) return number is

  Result           number;
  ll_count         number;
  ls_dolar         moneda.cod_moneda%type ;

BEGIN
   -- Hallando la moneda dolares
   select l.cod_dolares
     into ls_dolar
     from logparam l
    where reckey='1' ;

   -- Calculando el precio de ultima compra (que se encuentra en dolares)
   select count(*)
     into ll_count
    from articulo_almacen aa
    where aa.cod_art = asi_cod_art
      and aa.almacen = asi_almacen;

   if ll_count = 0 then
      select count(*)
        into ll_count
        from articulo
       where cod_art = asi_cod_art;

      if ll_count = 0 then
         result := 0;
      else
         select NVL(costo_ult_compra,0)
           into result
           from articulo
          where cod_art = asi_cod_art;
      end if;
   else
      select NVL(costo_ult_compra,0)
       into result
      from articulo_almacen aa
      where aa.cod_art = asi_cod_art
        and aa.almacen = asi_almacen;
   end if;

   RESULT := usf_fl_conv_mon(RESULT, ls_dolar, asi_moneda, SYSDATE);

   return(Result);
end usf_cmp_prec_ult_compra_moneda;
/

prompt
prompt Creating function USF_CMP_PREC_ULT_COMPRA_V2
prompt ============================================
prompt
create or replace function cantabria.usf_cmp_prec_ult_compra_v2(
       asi_cod_art         in articulo.cod_art%TYPE,
       asi_almacen         in almacen.almacen%TYPE
) return number is

  Result            number;
  ln_count          number;
  ln_costo_ult_oc   articulo_almacen.costo_ult_compra%TYPE;
  ls_doc_oc         logparam.doc_oc%TYPE;
  ls_dolares        logparam.cod_dolares%TYPE;
  ls_moneda         moneda.cod_moneda%TYPE;
  ld_fec_registro   date;

begin

    select doc_oc, cod_dolares
      into ls_doc_oc, ls_dolares
      from logparam
     where reckey = '1';

    select count(*)
      into ln_count
    from articulo_mov_proy amp,
         orden_compra      oc
    where oc.nro_oc       = amp.nro_doc
      and amp.tipo_doc    = ls_doc_oc
      and amp.cod_art     = asi_cod_art
      and amp.almacen     = asi_almacen
      and amp.flag_estado <> '0'
      and oc.flag_estado  <> '0';

    if ln_count > 0 then
       select precio, fec_registro, cod_moneda
         into ln_costo_ult_oc, ld_fec_registro, ls_moneda
         from  (select (amp.precio_unit - amp.precio_unit * NVL(amp.decuento,0)/100) as precio,
                       oc.fec_registro, amp.cod_moneda
                  from articulo_mov_proy amp,
                       orden_compra      oc
                 where oc.nro_oc        = amp.nro_doc
                   and amp.tipo_doc     = ls_doc_oc
                   and amp.cod_art      = asi_cod_art
                   and amp.almacen      = asi_almacen
                   and amp.flag_estado  <> '0'
                   and oc.flag_estado   <> '0'
                 order by oc.fec_registro desc)
        where rownum = 1;
       ln_costo_ult_oc := usf_fl_conv_mon(ln_costo_ult_oc, ls_moneda, ls_dolares, ld_fec_registro);
    else
       ln_costo_ult_oc := 0;
    end if;

  return(Result);
end usf_cmp_prec_ult_compra_v2;
/

prompt
prompt Creating function USF_CMP_TT_OPER_SEC_ART
prompt =========================================
prompt
create or replace function cantabria.USF_CMP_TT_OPER_SEC_ART(
       ac_cod_art in articulo.cod_art%type
)return varchar2 is

  Result  varchar2 (1);


begin

delete from tt_cmp_art_osec ;

Insert Into tt_cmp_art_osec
select amp.cod_origen,
		   amp.nro_mov,
		   amp.cod_art,
		   amp.oper_sec,
		   ot.cod_origen, ot.nro_orden,
       (select doc_ot from logparam where reckey = '1') as tipo_doc,
       (NVL(amp.cant_proyect,0) - NVL(amp.cant_procesada,0) - usf_cmp_cant_comprada(amp.oper_sec, amp.cod_art, amp.almacen)) as cant_pendiente,
		   a.desc_art,
		   amp.almacen
  from articulo_mov_proy amp,
       orden_trabajo      ot,
       articulo		 a
 where amp.nro_doc  = ot.nro_orden
   and amp.tipo_doc = (select doc_ot from logparam where reckey = '1')
   and a.cod_art	  = amp.cod_art
   and amp.flag_estado = '1'
   and (NVL(amp.cant_proyect,0) - NVL(amp.cant_procesada, 0) - usf_cmp_cant_comprada(amp.oper_sec, amp.cod_art, amp.almacen)) > 0
   and amp.cod_art = ac_cod_art ;

  return(Result);


end USF_CMP_TT_OPER_SEC_ART;
/

prompt
prompt Creating function USF_TIPO_CAMBIO
prompt =================================
prompt
create or replace function cantabria.usf_tipo_cambio(
   ad_fecha in date
   ) return number is
  ld_fecha_par date ; -- fecha de parametro truncadad
  ln_tipo_de_cambio number;
  ln_reg number;
  ld_fecha date ;
begin
  ld_fecha_par := trunc( ad_fecha ) ;
  Select count( * )
    into ln_reg
    from calendario
   where trunc( fecha ) <= ld_fecha_par
     and vta_dol_prom >= 0 ;

  if nvl( ln_reg, 0 ) = 0 or ln_reg = 0 then
     ln_tipo_de_cambio := -999  ; -- no encontrs ningun tipo de cambio <= fecha
  else
     Select vta_dol_prom
       into ln_tipo_de_cambio
       from calendario
      where trunc(fecha) = ld_fecha_par ;
  end if ;
  return( ln_tipo_de_cambio );
end usf_tipo_cambio;
/

prompt
prompt Creating function USF_CMP_VAL_VENTA_COMPRAS
prompt ===========================================
prompt
create or replace function cantabria.USF_CMP_VAL_VENTA_COMPRAS(
      as_tipo_origen      orden_compra.flag_estado%type,
      as_cod_origen       origen.cod_origen%type,
      ad_fecha_ini        date,
      ad_fecha_fin        date
 ) return number is

  -- as_tipo_origen : T=todos, O=origen
  -- as_cod_origen : Origen a evaluar
  -- ad_fecha_ini y ad_fecha_fin, rango de fecha a evaluar.

  Result   number;
  ln_count number;
  ln_tipo_cambio  calendario.vnt_dol_libre%type ;
  ls_soles logparam.cod_soles%type;

CURSOR vv_oc_todos_origen is
-----------------------------
select oc.nro_oc, oc.cod_moneda, oc.fec_registro,
       round( sum( nvl(amp.cant_proyect,0)*
                   nvl(amp.precio_unit,0)*
                  (100-nvl(amp.decuento,0))/100),2) as valor_venta
from orden_compra oc, articulo_mov_proy amp
where oc.cod_origen=amp.cod_origen and
      oc.nro_oc=amp.nro_doc and
      amp.tipo_doc='OC' and
      amp.flag_estado<>'0' and
      oc.fec_registro between trunc(ad_fecha_ini) and trunc(ad_fecha_fin)+0.999
group by oc.nro_oc, oc.cod_moneda, oc.fec_registro
order by nro_oc ;

CURSOR vv_oc_x_origen is
------------------------
select oc.nro_oc, oc.cod_moneda, oc.fec_registro,
       round( sum( nvl(amp.cant_proyect,0)*
                   nvl(amp.precio_unit,0)*
                  (100-nvl(amp.decuento,0))/100),2) as valor_venta
from orden_compra oc, articulo_mov_proy amp
where oc.cod_origen=amp.cod_origen AND
      oc.nro_oc=amp.nro_doc AND
      oc.cod_origen=as_cod_origen AND
      amp.tipo_doc='OC' and
      amp.flag_estado<>'0' and
      oc.fec_registro between trunc(ad_fecha_ini) and trunc(ad_fecha_fin)+0.999
group by oc.nro_oc, oc.cod_moneda, oc.fec_registro
order by nro_oc ;

BEGIN

Result := 0 ;

SELECT l.cod_soles INTO ls_soles FROM logparam l WHERE l.reckey='1' ;

IF as_tipo_origen='T' THEN
   FOR c_t IN vv_oc_todos_origen LOOP
       ln_tipo_cambio := usf_tipo_cambio( c_t.fec_registro ) ;
       IF ln_tipo_cambio = 0 THEN
          RAISE_APPLICATION_ERROR( -20001, 'Tipo cambio errado en '||to_char(c_t.fec_registro,'dd/mm/yyyy') ) ;
       END IF ;
       IF c_t.cod_moneda=ls_soles THEN
          result := result + round( c_t.valor_venta / ln_tipo_cambio, 2)  ;
       ELSE
          result := result + round( c_t.valor_venta, 2) ;
       END IF ;
   END LOOP ;
ELSE
   FOR c_o IN vv_oc_x_origen LOOP
       ln_tipo_cambio := usf_tipo_cambio( c_o.fec_registro ) ;
       IF ln_tipo_cambio = 0 THEN
          RAISE_APPLICATION_ERROR( -20001, 'Tipo cambio errado en '||to_char(c_o.fec_registro,'dd/mm/yyyy') ) ;
       END IF ;
       IF c_o.cod_moneda=ls_soles THEN
          result := result + round( c_o.valor_venta / ln_tipo_cambio, 2)  ;
       ELSE
          result := result + round( c_o.valor_venta, 2) ;
       END IF ;
   END LOOP ;
END IF ;

RETURN(Result);

END USF_CMP_VAL_VENTA_COMPRAS;
/

prompt
prompt Creating function USF_CNT_ACT_CTACTE
prompt ====================================
prompt
create or replace function cantabria.USF_CNT_ACT_CTACTE(
  as_old_cod_relacion in doc_pendientes_cta_cte.cod_relacion%type,
  as_old_tipo_doc     in doc_pendientes_cta_cte.tipo_doc%type,
  as_old_nro_doc      in doc_pendientes_cta_cte.nro_doc%type,
  as_old_cod_moneda   in doc_pendientes_cta_cte.cod_moneda%type,
  as_old_flag_debhab  in doc_pendientes_cta_cte.flag_debhab%type,
  an_old_imp_movsol   in cntbl_asiento_det.imp_movsol%type,
  an_old_imp_movdol   in cntbl_asiento_det.imp_movdol%type,
  as_new_cod_relacion in doc_pendientes_cta_cte.cod_relacion%type,
  as_new_tipo_doc     in doc_pendientes_cta_cte.tipo_doc%type,
  as_new_nro_doc      in doc_pendientes_cta_cte.nro_doc%type,
  ad_new_fecha_doc    in doc_pendientes_cta_cte.fecha_doc%type,
  as_new_flag_tabla   in doc_pendientes_cta_cte.flag_tabla%type,
  as_new_cnta_ctbl    in doc_pendientes_cta_cte.cnta_ctbl%type,
  as_new_cod_moneda   in doc_pendientes_cta_cte.cod_moneda%type,
  as_new_flag_debhab  in doc_pendientes_cta_cte.flag_debhab%type,
  an_new_imp_movsol   in cntbl_asiento_det.imp_movsol%type,
  an_new_imp_movdol   in cntbl_asiento_det.imp_movdol%type
   )
 return boolean is
  ln_saldo_sol           doc_pendientes_cta_cte.sldo_sol%type ;
  ln_saldo_dol           doc_pendientes_cta_cte.saldo_dol%type ;
  ls_saldo_flag_debhab   doc_pendientes_cta_cte.flag_debhab%type ;
  ls_flag_debhab         doc_pendientes_cta_cte.flag_debhab%type ;
  ls_soles               logparam.cod_soles%type ;

  Result boolean;
begin

-- Edgar Morante Miercoles 10Jul2002, replicacion
If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
    return(false);
end if;

  -- Capturando datos a utilizar
  select cod_soles into ls_soles from logparam where reckey='1' ;

  select sldo_sol, saldo_dol, flag_debhab
  into   ln_saldo_sol, ln_saldo_dol, ls_saldo_flag_debhab
  from   doc_pendientes_cta_cte
  where cod_relacion = as_old_cod_relacion and
        tipo_doc     = as_old_tipo_doc and
        nro_doc      = as_old_nro_doc ;

  -- Si datos del pk son iguales
  IF as_old_cod_relacion = as_new_cod_relacion and
     as_old_tipo_doc     = as_new_tipo_doc     and
     as_old_nro_doc      = as_new_nro_doc      then

     -- Cuando el flag debhab es igual para todos los casos
     IF ( as_old_flag_debhab = as_new_flag_debhab ) and
        ( as_old_flag_debhab = ls_saldo_flag_debhab ) then

        ln_saldo_sol := ln_saldo_sol - an_old_imp_movsol + an_new_imp_movsol ;
        ln_saldo_dol := ln_saldo_dol - an_old_imp_movdol + an_new_imp_movdol ;

        IF ( as_old_cod_moneda = ls_soles and ln_saldo_sol > 0 ) or
           ( as_old_cod_moneda <> ls_soles and ln_saldo_dol > 0 ) then

              UPDATE doc_pendientes_cta_cte
              SET sldo_sol  = ln_saldo_sol ,
                  saldo_dol = ln_saldo_dol
              WHERE  cod_relacion = as_new_cod_relacion and
                     tipo_doc     = as_new_tipo_doc     and
                     nro_doc      = as_new_nro_doc ;
        ELSE

              UPDATE doc_pendientes_cta_cte
              SET sldo_sol    = abs( ln_saldo_sol ),
                  saldo_dol   = abs( ln_saldo_dol ),
                  flag_debhab = decode( ls_flag_debhab, 'D', 'H',
                                                        'H', 'D' )
              WHERE  cod_relacion = as_new_cod_relacion and
                     tipo_doc     = as_new_tipo_doc     and
                     nro_doc      = as_new_nro_doc ;
        END IF;
    ELSIF ( as_old_flag_debhab = as_new_flag_debhab ) and
          ( as_old_flag_debhab <> ls_saldo_flag_debhab ) then

        ln_saldo_sol := ln_saldo_sol + an_old_imp_movsol - an_new_imp_movsol ;
        ln_saldo_dol := ln_saldo_dol + an_old_imp_movdol - an_new_imp_movdol ;

        IF ( as_old_cod_moneda = ls_soles and ln_saldo_sol > 0 ) or
           ( as_old_cod_moneda <> ls_soles and ln_saldo_dol > 0 ) then

              UPDATE doc_pendientes_cta_cte
              SET sldo_sol  = ln_saldo_sol ,
                  saldo_dol = ln_saldo_dol
              WHERE  cod_relacion = as_new_cod_relacion and
                     tipo_doc     = as_new_tipo_doc     and
                     nro_doc      = as_new_nro_doc ;
        ELSE

              UPDATE doc_pendientes_cta_cte
              SET sldo_sol    = abs( ln_saldo_sol ),
                  saldo_dol   = abs( ln_saldo_dol ),
                  flag_debhab = decode( ls_flag_debhab, 'D', 'H',
                                                        'H', 'D' )
              WHERE  cod_relacion = as_new_cod_relacion and
                     tipo_doc     = as_new_tipo_doc     and
                     nro_doc      = as_new_nro_doc ;
        END IF;

    ELSIF ( as_old_flag_debhab <> as_new_flag_debhab ) and
          ( as_old_flag_debhab = ls_saldo_flag_debhab ) then
        -- Cuando el flag debhab es diferente
        ln_saldo_sol := ln_saldo_sol - an_old_imp_movsol - an_new_imp_movsol ;
        ln_saldo_dol := ln_saldo_dol - an_old_imp_movdol - an_new_imp_movdol ;

        IF ( as_old_cod_moneda = ls_soles and ln_saldo_sol > 0 ) or
           ( as_old_cod_moneda <> ls_soles and ln_saldo_dol > 0 ) then

              UPDATE doc_pendientes_cta_cte
              SET sldo_sol  = ln_saldo_sol ,
                  saldo_dol = ln_saldo_dol
              WHERE  cod_relacion = as_new_cod_relacion and
                     tipo_doc     = as_new_tipo_doc     and
                     nro_doc      = as_new_nro_doc ;
        ELSE

              UPDATE doc_pendientes_cta_cte
              SET sldo_sol    = abs( ln_saldo_sol ),
                  saldo_dol   = abs( ln_saldo_dol ),
                  flag_debhab = decode( ls_flag_debhab, 'D', 'H',
                                                        'H', 'D' )
              WHERE  cod_relacion = as_new_cod_relacion and
                     tipo_doc     = as_new_tipo_doc     and
                     nro_doc      = as_new_nro_doc ;
        END IF;

    /*
    ELSIF ( as_old_flag_debhab <> as_new_flag_debhab ) and
          ( as_old_flag_debhab <> ls_saldo_flag_debhab ) then
          */

     END IF ;
  ELSE
  -- Datos del pk son diferentes
     ls_flag_debhab := 'D';

     -- Eliminar el antiguo codigo
     -- Adicionar el nuevo codigo
  END IF;
  return(Result);
end USF_CNT_ACT_CTACTE;
/

prompt
prompt Creating function USF_CNT_ASIENTO_DETALLE
prompt =========================================
prompt
create or replace function cantabria.usf_cnt_asiento_detalle(
  as_origen          in cntbl_asiento_det.origen%type,
  an_ano             in cntbl_asiento_det.ano%type,
  an_mes             in cntbl_asiento_det.mes%type,
  an_nro_libro       in cntbl_asiento_det.nro_libro%type,
  an_nro_asiento     in cntbl_asiento_det.nro_asiento%type,
  as_cnta_ctbl       in cntbl_asiento_det.cnta_ctbl%type,
  ad_fec_cntbl       in cntbl_asiento_det.fec_cntbl%type,
  as_det_glosa       in cntbl_asiento_det.det_glosa%type,
  as_flag_gen_aut    in cntbl_asiento_det.flag_gen_aut%type,
  as_flag_debhab     in cntbl_asiento_det.flag_debhab%type,
  as_cod_segui       in cntbl_asiento_det.cod_segui%type,
  as_cencos          in cntbl_asiento_det.cencos%type,
  as_cod_ctabco      in cntbl_asiento_det.cod_ctabco%type,
  as_tipo_docref1    in cntbl_asiento_det.tipo_docref1%type,
  as_nro_docref1     in cntbl_asiento_det.nro_docref1%type,
  as_nro_docref2     in cntbl_asiento_det.nro_docref2%type,
  as_cod_relacion    in cntbl_asiento_det.cod_relacion%type,
  an_imp_movsol      in cntbl_asiento_det.imp_movsol%type,
  an_imp_movdol      in cntbl_asiento_det.imp_movdol%type,
  an_imp_movaju      in cntbl_asiento_det.imp_movaju%type )
RETURN BOOLEAN IS

  ln_item            cntbl_pre_asiento_det.item%type;
  ls_flag_mov        cntbl_cnta.flag_permite_mov%type;
  ls_flag_cencos     cntbl_cnta.flag_cencos%type;
  ls_flag_doc_ref   cntbl_cnta.flag_doc_ref%type;
  ls_flag_codrel     cntbl_cnta.flag_codrel%type;
  LN_COUNT           NUMBER ;
  Result boolean;
BEGIN

-- Funciona que permite actualizar un registro en CNTBL_PRE_ASIENTO_DET
result := true ;

-- Verificando si datos a grabar son correctos
select flag_permite_mov, flag_cencos, flag_doc_ref, flag_codrel
into ls_flag_mov, ls_flag_cencos, ls_flag_doc_ref, ls_flag_codrel
from cntbl_cnta
where cnta_ctbl = as_cnta_ctbl ;

IF ls_flag_mov='0' then
   RAISE_APPLICATION_ERROR( -20000, 'Cuenta contable ' ||
   as_cnta_ctbl || ' no permite movimiento' ) ;
END IF;

IF ls_flag_cencos='1' and (as_cencos is null) then
   RAISE_APPLICATION_ERROR( -20001, 'Cuenta contable ' ||
   as_cnta_ctbl || ' necesita centro de costo' ) ;
END IF;

IF ls_flag_doc_ref='1' and (as_nro_docref1 is null) then
   RAISE_APPLICATION_ERROR( -20001, 'Cuenta contable ' ||
   as_cnta_ctbl || ' necesita documento' ) ;
END IF;

IF ls_flag_codrel='1' and (as_cod_relacion is null) then
   RAISE_APPLICATION_ERROR( -20001, 'Cuenta contable ' ||
   as_cnta_ctbl || ' necesita codigo de relacion' ) ;
END IF;

-- Acutalizacion de cntbl_pre_asiento_det segun sea el caso
IF (ls_flag_cencos='0' and
    ls_flag_doc_ref='0' and
    ls_flag_codrel='0') then

    UPDATE cntbl_asiento_det
       SET fec_cntbl     = ad_fec_cntbl,
           det_glosa     = as_det_glosa,
           flag_gen_aut  = as_flag_gen_aut,
           flag_debhab   = as_flag_debhab,
           cencos        = as_cencos,
           cod_ctabco    = as_cod_ctabco,
           tipo_docref1  = as_tipo_docref1,
           nro_docref1   = as_nro_docref1,
           nro_docref2   = as_nro_docref2,
           cod_relacion  = as_cod_relacion,
           imp_movsol    = nvl(imp_movsol,0) + an_imp_movsol,
           imp_movdol    = nvl(imp_movdol,0) + an_imp_movdol,
           imp_movaju    = nvl(imp_movaju,0) + an_imp_movaju
     WHERE origen      = as_origen and
           ano         = an_ano    and
           mes         = an_mes    and
           nro_libro   = an_nro_libro and
           nro_asiento = an_nro_asiento and
           cnta_ctbl   = as_cnta_ctbl and
           flag_debhab = as_flag_debhab ;

   -- Caso de centro de costo
ELSIF (ls_flag_cencos='1' and
       ls_flag_doc_ref='0' and
       ls_flag_codrel='0') then

    update cntbl_asiento_det
       set fec_cntbl     = ad_fec_cntbl,
           det_glosa     = as_det_glosa,
           flag_gen_aut  = as_flag_gen_aut,
           flag_debhab   = as_flag_debhab,
           cencos        = as_cencos,
           cod_ctabco    = as_cod_ctabco,
           tipo_docref1  = as_tipo_docref1,
           nro_docref1   = as_nro_docref1,
           nro_docref2   = as_nro_docref2,
           cod_relacion  = as_cod_relacion,
           imp_movsol    = nvl(imp_movsol,0) + an_imp_movsol,
           imp_movdol    = nvl(imp_movdol,0) + an_imp_movdol,
           imp_movaju    = nvl(imp_movaju,0) + an_imp_movaju
     where origen        = as_origen and
           ano           = an_ano    and
           mes           = an_mes    and
           nro_libro     = an_nro_libro and
           nro_asiento   = an_nro_asiento and
           cnta_ctbl     = as_cnta_ctbl and
           flag_debhab   = as_flag_debhab and
           cencos        = as_cencos;

   -- Caso codigo de relacion
   ELSIF (ls_flag_cencos='0' and
          ls_flag_doc_ref='1' and
          ls_flag_codrel='1') then

    update cntbl_asiento_det
       set fec_cntbl     = ad_fec_cntbl,
           det_glosa     = as_det_glosa,
           flag_gen_aut  = as_flag_gen_aut,
           flag_debhab   = as_flag_debhab,
           cencos        = as_cencos,
           cod_ctabco    = as_cod_ctabco,
           tipo_docref1  = as_tipo_docref1,
           nro_docref1   = as_nro_docref1,
           nro_docref2   = as_nro_docref2,
           cod_relacion  = as_cod_relacion,
           imp_movsol    = nvl(imp_movsol,0) + an_imp_movsol,
           imp_movdol    = nvl(imp_movdol,0) + an_imp_movdol,
           imp_movaju    = nvl(imp_movaju,0) + an_imp_movaju
     where origen        = as_origen and
           ano           = an_ano    and
           mes           = an_mes    and
           nro_libro     = an_nro_libro and
           nro_asiento   = an_nro_asiento and
           cnta_ctbl     = as_cnta_ctbl and
           flag_debhab   = as_flag_debhab and
           tipo_docref1  = as_tipo_docref1 and
           cod_relacion  = as_cod_relacion;
   -- Otros casos
ELSE
    update cntbl_asiento_det
       set cnta_ctbl     = as_cnta_ctbl,
           fec_cntbl     = ad_fec_cntbl,
           det_glosa     = as_det_glosa,
           flag_gen_aut  = as_flag_gen_aut,
           flag_debhab   = as_flag_debhab,
           cencos        = as_cencos,
           cod_ctabco    = as_cod_ctabco,
           tipo_docref1  = as_tipo_docref1,
           nro_docref1   = as_nro_docref1,
           nro_docref2   = as_nro_docref2,
           cod_relacion  = as_cod_relacion,
           imp_movsol    = nvl(imp_movsol,0) + an_imp_movsol,
           imp_movdol    = nvl(imp_movdol,0) + an_imp_movdol,
           imp_movaju    = nvl(imp_movaju,0) + an_imp_movaju
     where origen        = as_origen and
           ano           = an_ano    and
           an_mes        = an_mes    and
           nro_libro     = an_nro_libro and
           nro_asiento   = an_nro_asiento and
           cnta_ctbl     = as_cnta_ctbl and
           flag_debhab   = as_flag_debhab and
           cencos        = as_cencos and
           tipo_docref1  = as_tipo_docref1 and
           nro_docref1   = as_nro_docref1 and
           nro_docref2   = as_nro_docref2 and
           cod_relacion  = as_cod_relacion ;
END IF;

IF sql%notfound then
   -- Capturando el item
    select max(item) into ln_item
      from cntbl_asiento_det
     where origen      = as_origen and
           ano         = an_ano   and
           mes         = an_mes   and
           nro_libro   = an_nro_libro and
           nro_asiento = an_nro_asiento ;

    -- Insertando registro
    insert into cntbl_asiento_det
      ( origen,       ano,         mes,
        nro_libro,    nro_asiento, item,
        cnta_ctbl,    fec_cntbl,   det_glosa,
        flag_gen_aut, flag_debhab, cod_segui,
        cencos,       cod_ctabco,  tipo_docref1,
        nro_docref1,  nro_docref2, cod_relacion,
        imp_movsol,   imp_movdol,  imp_movaju )
    values
      ( as_origen, an_ano, an_mes,
        an_nro_libro,           an_nro_asiento,         nvl(ln_item,0) + 1,
        as_cnta_ctbl,           ad_fec_cntbl,           as_det_glosa,
        as_flag_gen_aut,        as_flag_debhab,         as_cod_segui,
        as_cencos,              as_cod_ctabco,          as_tipo_docref1,
        as_nro_docref1,         as_nro_docref2,         as_cod_relacion,
        nvl( an_imp_movsol, 0), nvl( an_imp_movdol, 0), nvl( an_imp_movaju, 0 ) ) ;


--    SELECT COUNT(*) INTO LN_COUNT FROM VERIFICA ;

--    INSERT INTO VERIFICA
--    (COD_RELACION,TIPO_DOC,NRO_DOC,ITEM,CNTACNTBL,FLAG)
--    VALUES
--    (as_cod_relacion,as_tipo_docref1,as_nro_docref1,LN_COUNT + 1,as_cnta_ctbl,as_flag_debhab);


end if;

return(Result);

END usf_cnt_asiento_detalle;
/

prompt
prompt Creating function USF_CNT_ASNT_TALLERES_TEMPORAL
prompt ================================================
prompt
create or replace function cantabria.USF_CNT_ASNT_TALLERES_TEMPORAL(
  an_nro_libro             in cntbl_asiento_det.nro_libro%type,
  as_cnta_ctbl_debe        in cntbl_asiento_det.cnta_ctbl%type,
  as_cnta_ctbl_haber       in cntbl_asiento_det.cnta_ctbl%type,
  as_glosa                 in cntbl_asiento_det.det_glosa%type,
  as_cencos                in cntbl_asiento_det.cencos%type,
  as_tipo_doc              in cntbl_asiento_det.tipo_docref1%type,
  as_nro_doc               in cntbl_asiento_det.nro_docref1%type,
  as_cod_rel               in cntbl_asiento_det.cod_relacion%type,
  an_cantidad              in cntbl_asiento_det.imp_movsol%type,
  as_cencos_destino        in cntbl_asiento_det_aux.cencos%type,
  as_centro_benef          IN cntbl_asiento_det.centro_benef%TYPE
  ) return boolean is

  Result boolean;
begin
  result := true ;
  if NVL(as_cod_rel,'') = '' then
     update tt_cnt_asnt_talleres
        set cantidad = cantidad + an_cantidad
     where nro_libro       = an_nro_libro and
           cnta_ctbl_debe  = as_cnta_ctbl_debe  and
           cnta_ctbl_haber = as_cnta_ctbl_haber and
           cencos          = as_cencos and
           cencos_destino  = as_cencos_destino ;
  else
     update tt_cnt_asnt_talleres
        set cantidad = cantidad + an_cantidad
     where nro_libro       = an_nro_libro and
           cnta_ctbl_debe  = as_cnta_ctbl_debe  and
           cnta_ctbl_haber = as_cnta_ctbl_haber and
           cod_rel         = as_cod_rel and
           tipo_doc        = as_tipo_doc and
           nro_doc         = as_nro_doc ;
  end if;

  if sql%notfound then
     insert into tt_cnt_asnt_talleres
     ( nro_libro,
       cnta_ctbl_debe,
       cnta_ctbl_haber,
       glosa,
       cencos,
       tipo_doc,
       nro_doc,
       cod_rel,
       cantidad,
       cencos_destino,
       centro_benef )
     values
     ( an_nro_libro,
       as_cnta_ctbl_debe,
       as_cnta_ctbl_haber,
       as_glosa,
       as_cencos,
       as_tipo_doc,
       as_nro_doc,
       as_cod_rel,
       an_cantidad,
       as_cencos_destino,
       as_centro_benef ) ;
  end if;

  return(Result);

end USF_CNT_ASNT_TALLERES_TEMPORAL;
