prompt
prompt Creating function USF_CNTBL_CP_COSTO_CANA_VAR
prompt =============================================
prompt
create or replace function cantabria.usf_cntbl_cp_costo_cana_var (
  an_ano in number, an_mes in number, as_cuenta in char ) return number is

ln_importe       number(12,3) ;
ln_contador      integer ;
ls_cuenta        char(10) ;
ln_impdeb        number(13,2) ;
ln_imphab        number(13,2) ;

begin

ls_cuenta  := substr(as_cuenta,1,10) ;
ln_importe := 0 ; ln_impdeb := 0 ; ln_imphab := 0 ;

ln_contador := 0 ;
select count(*)
  into ln_contador from cntbl_asiento_det d
  where d.ano = an_ano and d.mes = an_mes and d.cnta_ctbl = ls_cuenta and
        d.flag_debhab = 'D' ;
if ln_contador > 0 then
  select sum(nvl(d.imp_movsol,0))
    into ln_impdeb from cntbl_asiento_det d
    where d.ano = an_ano and d.mes = an_mes and d.cnta_ctbl = ls_cuenta and
          d.flag_debhab = 'D' ;
end if ;

ln_contador := 0 ;
select count(*)
  into ln_contador from cntbl_asiento_det d
  where d.ano = an_ano and d.mes = an_mes and d.cnta_ctbl = ls_cuenta and
        d.flag_debhab = 'H' ;
if ln_contador > 0 then
  select sum(nvl(d.imp_movsol,0))
    into ln_imphab from cntbl_asiento_det d
    where d.ano = an_ano and d.mes = an_mes and d.cnta_ctbl = ls_cuenta and
          d.flag_debhab = 'H' ;
end if ;

ln_importe := ln_impdeb - ln_imphab ;

return (ln_importe) ;

end usf_cntbl_cp_costo_cana_var ;
/

