prompt Creating function USF_CNTBL_CP_CUENTA_CENCOS
prompt ============================================
prompt
create or replace function cantabria.usf_cntbl_cp_cuenta_cencos (
  an_ano in number, an_mes in number, as_cuenta in char,
  as_cencos in char ) return number is

ln_importe       number(12,3) ;
ln_valor         number(12,3) ;
ln_contador      integer ;
ln_impdeb        number(13,2) ;
ln_imphab        number(13,2) ;

begin

ln_importe := 0 ; ln_impdeb := 0 ; ln_imphab := 0 ;

ln_contador := 0 ;
select count(*)
  into ln_contador from cntbl_asiento_det d
  where d.ano = an_ano and d.mes = an_mes and d.cnta_ctbl = as_cuenta and
        d.cencos = as_cencos and d.flag_debhab = 'D' ;
if ln_contador > 0 then
  select sum(nvl(d.imp_movsol,0))
    into ln_impdeb from cntbl_asiento_det d
    where d.ano = an_ano and d.mes = an_mes and d.cnta_ctbl = as_cuenta and
          d.cencos = as_cencos and d.flag_debhab = 'D' ;
end if ;

ln_contador := 0 ;
select count(*)
  into ln_contador from cntbl_asiento_det d
  where d.ano = an_ano and d.mes = an_mes and d.cnta_ctbl = as_cuenta and
        d.cencos = as_cencos and d.flag_debhab = 'H' ;
if ln_contador > 0 then
  select sum(nvl(d.imp_movsol,0))
    into ln_imphab from cntbl_asiento_det d
    where d.ano = an_ano and d.mes = an_mes and d.cnta_ctbl = as_cuenta and
          d.cencos = as_cencos and d.flag_debhab = 'H' ;
end if ;

ln_importe := ln_impdeb - ln_imphab ;

--  *******************************************************************
--  ***  RUTINA ESPECIAL PARA LA PAGINA P04 CENTRO DE COSTO 41400   ***
--  *******************************************************************
if as_cuenta = '92100217' and as_cencos = '41400' then

  ln_contador := 0 ; ln_valor := 0 ;
  select count(*) into ln_contador from cntbl_cp_movimiento_manual m
  where m.tipo_operacion = 'CPA' and m.cod_frmt = 'P04' and m.item = 115 ;
  if ln_contador > 0 then
    select nvl(m.valor,0) into ln_valor from cntbl_cp_movimiento_manual m
    where m.tipo_operacion = 'CPA' and m.cod_frmt = 'P04' and m.item = 115 ;
    ln_importe := ln_importe + (ln_valor * -1) ;
  end if ;

  ln_contador := 0 ; ln_valor := 0 ;
  select count(*) into ln_contador from cntbl_cp_movimiento_manual m
  where m.tipo_operacion = 'CPA' and m.cod_frmt = 'P04' and m.item = 120 ;
  if ln_contador > 0 then
    select nvl(m.valor,0) into ln_valor from cntbl_cp_movimiento_manual m
    where m.tipo_operacion = 'CPA' and m.cod_frmt = 'P04' and m.item = 120 ;
    ln_importe := ln_importe + (ln_valor * -1) ;
  end if ;

end if ;

return (ln_importe) ;

end usf_cntbl_cp_cuenta_cencos ;
/

