prompt
prompt Creating function USF_CNTBL_CV_CALCULA
prompt ======================================
prompt
create or replace function cantabria.usf_cntbl_cv_calcula (
  an_ano in number, an_mes in number, as_tipo in char,
  as_descripcion in char ) return number is

ln_imp_calculo   number(12,3) ;
ln_contador      integer ;
ln_importe       number ;
ln_valor         number ;
ln_valor_1       number ;
ln_valor_2       number ;
ls_formula       varchar2(200) ;
ls_cadena        varchar2(200) ;
ls_dato          varchar2(20) ;
ls_operador      char(1) ;
ls_operador_1    char(1) ;
ln_y             integer ;
ln_sw            integer ;
ln_menos         integer ;

ls_pagina        char(3) ;
ln_linea         number(4) ;
ln_columna       number(2) ;

begin

ls_formula := rtrim(ltrim(as_descripcion)) ;
ln_importe := 0 ; ln_y := 0 ; ls_cadena := null ;

--  ****************************************************
--  ***   Realiza captura de valores de la formula   ***
--  ****************************************************
for x in 1 .. length(ls_formula) loop

  ln_menos := 0 ;
  if substr(ls_formula,x,1) <> '+' and substr(ls_formula,x,1) <> '-' and
     substr(ls_formula,x,1) <> '*' and substr(ls_formula,x,1) <> '/' then

    ln_y := ln_y + 1 ;
    ls_dato := ls_dato||substr(ls_formula,x,1) ;

    if substr(ls_formula,x,1) = ']' then
      ls_pagina := null ; ln_linea := 0 ; ln_columna := 0 ;
      if length(ls_dato) = 11 then
        ls_pagina  := substr(ls_dato,2,3) ;
        ln_linea   := to_number(substr(ls_dato,6,2)) ;
        ln_columna := to_number(substr(ls_dato,9,2)) ;
      elsif length(ls_dato) = 12 then
        ls_pagina  := substr(ls_dato,2,3) ;
        ln_linea   := to_number(substr(ls_dato,6,3)) ;
        ln_columna := to_number(substr(ls_dato,10,2)) ;
      end if ;
      ln_contador := 0 ;
      select count(*)
        into ln_contador from cntbl_cv_movimiento_hist m
        where m.ano = an_ano and m.mes = an_mes and
              rtrim(ltrim(m.tipo_operacion)) = as_tipo and
              rtrim(ltrim(m.cod_frmt)) = ls_pagina and m.linea = ln_linea and
              m.columna = ln_columna ;
      if ln_contador > 0 then
        select nvl(m.valor,0)
          into ln_valor from cntbl_cv_movimiento_hist m
          where m.ano = an_ano and m.mes = an_mes and
                rtrim(ltrim(m.tipo_operacion)) = as_tipo and
                rtrim(ltrim(m.cod_frmt)) = ls_pagina and m.linea = ln_linea and
                m.columna = ln_columna ;
        if ln_valor < 0 then
          ln_valor := ln_valor * -1 ;
          ln_menos := 1 ;
        end if ;
      else
        ln_valor := 0 ;
      end if ;
      if ln_menos = 1 then
        ls_cadena := ls_cadena||to_char(ln_valor)||'%' ;
      else
        ls_cadena := ls_cadena||to_char(ln_valor) ;
      end if ;
      ln_y := 0 ; ls_dato := null ;
    end if ;

    if substr(ls_formula,x,1) = ')' then
      ln_valor := to_number(substr(ls_dato,2,(ln_y-2))) ;
      ls_cadena := ls_cadena||to_char(ln_valor) ;
      ln_y := 0 ; ls_dato := null ;
    end if ;

  else

    ls_cadena := ls_cadena||substr(ls_formula,x,1) ;

  end if ;

end loop ;

--  *****************************************************
--  ***   Realiza calculo de los valores capturados   ***
--  *****************************************************
ln_valor := 0 ; ln_valor_1 := 0 ; ln_valor_2 := 0 ; ln_y := 0 ;
ln_contador := 0 ; ln_sw := 0 ; ls_operador := null ; ls_operador_1 := null ;
for x in 1 .. length(ls_cadena) loop

  if ln_sw = 0 then

    ln_y := ln_y + 1 ;
    ls_dato := ls_dato||substr(ls_cadena,x,1) ;
    if substr(ls_cadena,x,1) = '+' or substr(ls_cadena,x,1) = '-' or
       substr(ls_cadena,x,1) = '*' or substr(ls_cadena,x,1) = '/' then
      ln_contador := ln_contador + 1 ;
      if ln_contador = 1 then
        ls_operador := substr(ls_cadena,x,1) ;
        if substr(ls_dato,(ln_y-1),1) = '%' then
          ln_valor_1 := to_number(substr(ls_dato,1,(ln_y-2))) ;
          ln_valor_1 := ln_valor_1 * -1 ;
        else
          ln_valor_1 := to_number(substr(ls_dato,1,(ln_y-1))) ;
        end if ;
      else
        if substr(ls_dato,(ln_y-1),1) = '%' then
          ln_valor_2 := to_number(substr(ls_dato,1,(ln_y-2))) ;
          ln_valor_2 := ln_valor_2 * -1 ;
        else
          ln_valor_2 := to_number(substr(ls_dato,1,(ln_y-1))) ;
        end if ;
        ln_sw := 1 ;
        ls_operador_1 := substr(ls_cadena,x,1) ;
        if ls_operador = '+' then
          ln_importe := ln_valor_1 + ln_valor_2 ;
        elsif ls_operador = '-' then
          ln_importe := ln_valor_1 - ln_valor_2 ;
        elsif ls_operador = '*' then
          ln_importe := ln_valor_1 * ln_valor_2 ;
        elsif ls_operador = '/' then
          if ln_valor_2 <> 0 then
            ln_importe := ln_valor_1 / ln_valor_2 ;
          end if ;
        end if ;
      end if ;
      ln_y := 0 ; ls_dato := null ;
    end if ;

  else

    ln_y := ln_y + 1 ;
    ls_dato := ls_dato||substr(ls_cadena,x,1) ;
    if substr(ls_cadena,x,1) = '+' or substr(ls_cadena,x,1) = '-' or
       substr(ls_cadena,x,1) = '*' or substr(ls_cadena,x,1) = '/' then
      if substr(ls_dato,(ln_y-1),1) = '%' then
        ln_valor := to_number(substr(ls_dato,1,(ln_y-2))) ;
        ln_valor := ln_valor * -1 ;
      else
        ln_valor := to_number(substr(ls_dato,1,(ln_y-1))) ;
      end if ;
      ln_y := 0 ; ls_dato := null ;
      if ls_operador_1 = '+' then
        ln_importe := ln_importe + ln_valor ;
      elsif ls_operador_1 = '-' then
        ln_importe := ln_importe - ln_valor ;
      elsif ls_operador_1 = '*' then
        ln_importe := ln_importe * ln_valor ;
      elsif ls_operador_1 = '/' then
        if ln_valor <> 0 then
          ln_importe := ln_importe / ln_valor ;
        end if ;
      end if ;
      ls_operador_1 := substr(ls_cadena,x,1) ;
    end if ;

  end if ;

end loop ;

--  ******************************************************
--  ***   Calcula dato del ultimo valor de la cadena   ***
--  ******************************************************
if substr(ls_dato,ln_y,1) = '%' then
  ln_valor := to_number(substr(ls_dato,1,(ln_y-1))) ;
  ln_valor := ln_valor * -1 ;
else
  ln_valor := to_number(ls_dato) ;
end if ;

if ln_sw = 0 then

  if ls_operador = '+' then
    ln_importe := ln_valor_1 + ln_valor ;
  elsif ls_operador = '-' then
    ln_importe := ln_valor_1 - ln_valor ;
  elsif ls_operador = '*' then
    ln_importe := ln_valor_1 * ln_valor ;
  elsif ls_operador = '/' then
    if ln_valor <> 0 then
      ln_importe := ln_valor_1 / ln_valor ;
    end if ;
  elsif ls_operador is null then
    ln_importe := ln_valor ;
  end if ;

else

  if ls_operador_1 = '+' then
    ln_importe := ln_importe + ln_valor ;
  elsif ls_operador_1 = '-' then
    ln_importe := ln_importe - ln_valor ;
  elsif ls_operador_1 = '*' then
    ln_importe := ln_importe * ln_valor ;
  elsif ls_operador_1 = '/' then
    if ln_valor <> 0 then
      ln_importe := ln_importe / ln_valor ;
    end if ;
  elsif ls_operador_1 is null then
    ln_importe := ln_valor ;
  end if ;

end if ;

ln_imp_calculo := ln_importe ;

return (ln_imp_calculo) ;

end usf_cntbl_cv_calcula ;
/

prompt
prompt Creating function USF_CNT_NUMERO_ASIENTO
prompt ========================================
prompt
create or replace function cantabria.USF_CNT_NUMERO_ASIENTO(
    as_origen    in cntbl_asiento.origen%type,
    an_ano       in cntbl_asiento.ano%type,
    an_mes       in cntbl_asiento.mes%type,
    an_nro_libro in cntbl_asiento.nro_libro%type) return Integer is

  ln_nro_asiento Integer ;
  ln_count Number(2) ;
BEGIN

  ln_nro_asiento := 1 ;
  -- Verifica si existe correlativo
  SELECT count(*)
  INTO ln_count
  FROM cntbl_libro_mes clm
  WHERE clm.origen    = as_origen AND
        clm.nro_libro = an_nro_libro AND
        clm.ano       = an_ano AND
        clm.mes       = an_mes ;

  IF ln_count > 0 THEN
     SELECT nro_asiento
       INTO ln_nro_asiento
       FROM cntbl_libro_mes clm
      WHERE clm.origen      = as_origen AND
            clm.nro_libro   = an_nro_libro AND
            clm.ano         = an_ano AND
            clm.mes         = an_mes ;

     -- Actualiza numero provisional
     UPDATE cntbl_libro_mes
        SET nro_asiento = ln_nro_asiento + 1
      WHERE origen      = as_origen AND
            nro_libro   = an_nro_libro AND
            ano         = an_ano AND
            mes         = an_mes ;

  ELSE
     INSERT INTO cntbl_libro_mes(origen, nro_libro, ano, mes, nro_asiento)
     VALUES( as_origen, an_nro_libro, an_ano, an_mes, ln_nro_asiento+1 ) ;
  END IF ;

  RETURN(ln_nro_asiento);

end USF_CNT_NUMERO_ASIENTO;
/

prompt
prompt Creating function USF_CNT_CAB_ASIENTO
prompt =====================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.usf_cnt_cab_asiento
(as_origen in cntbl_asiento.origen%type,
 an_ano    in cntbl_asiento.ano%type,
 an_mes    in cntbl_asiento.mes%type,
 an_nro_libro in cntbl_asiento.nro_libro%type,
 as_cod_moneda in cntbl_asiento.cod_moneda%type,
 an_tasa_cambio in cntbl_asiento.tasa_cambio%type,
 as_tipo_nota in cntbl_asiento.tipo_nota%type,
 an_nro_proceso in cntbl_asiento.nro_proceso%type,
 as_desc_glosa in cntbl_asiento.desc_glosa%type,
 ad_fecha_cntbl in cntbl_asiento.fecha_cntbl%type,
 ad_fec_registro in cntbl_asiento.fec_registro%type,
 as_cod_usr in cntbl_asiento.cod_usr%type,
 as_flag_estado in cntbl_asiento.flag_estado%type,
 as_flag_tabla  in cntbl_asiento.flag_tabla%type,
 an_tot_soldeb in cntbl_asiento.tot_soldeb%type,
 an_tot_solhab in cntbl_asiento.tot_solhab%type,
 an_tot_doldeb in cntbl_asiento.tot_doldeb%type,
 an_tot_dolhab in cntbl_asiento.tot_dolhab%type  )

 return Integer
is
  ln_nro_asiento     cntbl_asiento.nro_asiento%type;

BEGIN

  ln_nro_asiento := USF_CNT_NUMERO_ASIENTO(as_origen, an_ano, an_mes, an_nro_libro) ;

  -- Ingresa cabecera de pre asiento
  INSERT INTO cntbl_asiento
  (origen , ano, mes, nro_libro,
   nro_asiento, cod_moneda, tasa_cambio, tipo_nota,
   nro_proceso, desc_glosa, fecha_cntbl, fec_registro,
   cod_usr, flag_estado, flag_tabla, tot_soldeb,
   tot_solhab, tot_doldeb, tot_dolhab )
   VALUES
  (as_origen , an_ano, an_mes, an_nro_libro,
   ln_nro_asiento, as_cod_moneda, an_tasa_cambio, as_tipo_nota,
   an_nro_proceso, as_desc_glosa, ad_fecha_cntbl, ad_fec_registro,
   as_cod_usr, as_flag_estado, as_flag_tabla, an_tot_soldeb,
   an_tot_solhab, an_tot_doldeb, an_tot_dolhab ) ;

  IF sqlcode = -1 THEN
     RETURN -1 ;
  ELSE
     return ln_nro_asiento ;
  END IF ;

END usf_cnt_cab_asiento;
/

prompt
prompt Creating function USF_CNT_CAB_PRE_ASIENTO
prompt =========================================
prompt
create or replace function cantabria.usf_cnt_cab_pre_asiento
(      asi_origen          in origen.cod_origen%TYPE,
       ani_nro_libro       in cntbl_libro.nro_libro%TYPE,
       asi_moneda          in moneda.cod_moneda%TYPE,
       ani_tasa_cambio     in number,
       asi_tipo_nota       in char,
       ani_nro_proceso     in number,
       asi_desc_glosa      in varchar2,
       adi_fec_cntbl       in date,
       adi_fec_registro    in date,
       asi_usuario         in usuario.cod_usr%TYPE,
       asi_flag_estado     in char,
       asi_flag_mayoriz    in char,
       asi_flag_tabla      in char,
       ani_tot_soldeb      in number,
       ani_tot_solhab      in number,
       ani_tot_doldeb      in number,
       ani_tot_dolhab      in number
) return number
is

  ln_nro_provisional     cntbl_pre_asiento.nro_provisional%type;

begin

  -- Captura correlativo
  select num_provisional
    into ln_nro_provisional
    from cntbl_libro
  where nro_libro = ani_nro_libro for update ;

  ln_nro_provisional := NVL(ln_nro_provisional,0) + 1 ;

  -- Actualiza numero provisional
  update cntbl_libro
     set num_provisional = ln_nro_provisional
   where nro_libro = ani_nro_libro ;

  -- Ingresa cabecera de pre asiento
  insert into cntbl_pre_asiento(
         origen , nro_libro , nro_provisional, cod_moneda,
         tasa_cambio, tipo_nota, nro_proceso, desc_glosa,
         fec_cntbl, fec_registro, cod_usr, flag_estado,
         flag_mayoriz, flag_tabla, tot_soldeb, tot_solhab,
         tot_doldeb, tot_dolhab
   )values(
         asi_origen, ani_nro_libro, ln_nro_provisional, asi_moneda,
         ani_tasa_cambio, asi_tipo_nota, ani_nro_proceso, asi_desc_glosa,
         adi_fec_cntbl, sysdate, asi_usuario, '1', '0', asi_flag_tabla, 0, 0,
         0, 0 ) ;

  return(ln_nro_provisional);

end usf_cnt_cab_pre_asiento;
/

prompt
prompt Creating function USF_CNT_CIERRE_CNTBL
prompt ======================================
prompt
create or replace function cantabria.USF_CNT_CIERRE_CNTBL(
       ani_year in cntbl_asiento.ano%type,
       ani_mes  in cntbl_asiento.mes%type,
       asi_tipo in string
) return varchar2 is

  Result varchar2(1) ;
  ls_flag_reg_cntbl          cntbl_cierre.flag_reg_cntbl%type ;
  ls_flag_mov_banco          cntbl_cierre.flag_mov_banco%type ;
  ls_flag_gen_asnt_autom     cntbl_cierre.flag_gen_asnt_autom%type ;
  ls_flag_cierre_mes         cntbl_cierre.flag_cierre_mes%type ;
  ls_pd_campo                cntbl_cierre.pd_campo%type ;
  ls_pd_dma                  cntbl_cierre.pd_dma%type ;
  ls_pd_mtto_fab             cntbl_cierre.pd_mtto_fab%type ;
  ls_pd_mtto_maq             cntbl_cierre.pd_mtto_maq%type ;
  ln_count                   number(2) ;
BEGIN
  /* Retorna 0, no debe grabar asiento,
     retorna 1, debe grabar asiento */

  /* as_tipo tiene los siguientes valores, para los siguientes casos:
     R = caso registros de compras y ventas,
     B = caso movimiento bancario (tesoreria),
     M = cualquier asiento contable (por contabilidad) y
     A = para asientos contables por proceso
     C = caso de inventarios -almacenes-
     D = ????????
     F = partes diarios relacionados a OT
     P = parte diario de mantenimiento de maquinarias
  */

  Result := '1';

  SELECT count(*)
  INTO   ln_count
  FROM   cntbl_cierre
  WHERE  ano = ani_year
    and  mes = ani_mes ;

  IF ln_count > 0 then
     SELECT flag_reg_cntbl,    flag_mov_banco,    flag_cierre_mes,     flag_gen_asnt_autom,
            pd_campo,          pd_dma,            pd_mtto_fab,         pd_mtto_maq
     INTO   ls_flag_reg_cntbl, ls_flag_mov_banco, ls_flag_cierre_mes,  ls_flag_gen_asnt_autom,
            ls_pd_campo,       ls_pd_dma,         ls_pd_mtto_fab,      ls_pd_mtto_maq
     FROM   cntbl_cierre
     WHERE  ano = ani_year
       and  mes = ani_mes ;

     /* Registros contables, libros 3 y 4 */
     IF asi_tipo='R' and
        ( NVL(ls_flag_reg_cntbl,'')='0' OR
          NVL(ls_flag_cierre_mes,'')='0' ) then

        Result := '0' ;

     /* Movimientos bancarios, libros 7 y 8 */
     ELSIF asi_tipo='B' and
          ( NVL(ls_flag_mov_banco,'')='0' OR
            NVL(ls_flag_cierre_mes,'')='0' ) then

           Result := '0' ;

     /* Asientos contables, todos */
     ELSIF asi_tipo='M' and NVL(ls_flag_cierre_mes,'')='0' then

           Result := '0' ;

     /* Asientos contables generados por procesos */
     ELSIF asi_tipo='A' and
           ( NVL(ls_flag_gen_asnt_autom,'')='0' OR
             NVL(ls_flag_cierre_mes,'')='0' ) then

           Result := '0' ;

     /* Asientos contables generados por almacen */
     ELSIF asi_tipo='C' and
           ( NVL(ls_pd_campo,'')='0' OR
             NVL(ls_flag_cierre_mes,'')='0' ) then

           Result := '0' ;

     /* Asientos contables generados por parte diario de dma */
     ELSIF asi_tipo='D' and
           ( NVL(ls_pd_dma,'')='0' OR
             NVL(ls_flag_cierre_mes,'')='0' ) then

           Result := '0' ;

     /* Asientos contables generados por parte diario de mantenimiento de fabrica */
     ELSIF asi_tipo='F' and
           ( NVL(ls_pd_mtto_fab,'')='0' OR
             NVL(ls_flag_cierre_mes,'')='0' ) then

           Result := '0' ;

     /* Asientos contables generados por parte diario de mantenimiento de maquinaria */
     ELSIF asi_tipo='P' and
           ( NVL(ls_pd_mtto_maq,'')='0' OR
             NVL(ls_flag_cierre_mes,'')='0' ) then

           Result := '0' ;

     END IF ;
  END IF ;

 RETURN(Result);

END USF_CNT_CIERRE_CNTBL;
/

prompt
prompt Creating function USF_CNT_CNTA_EQUIVALENTE
prompt ==========================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.usf_cnt_cnta_equivalente
  (as_cnta        cntbl_cnta.cnta_ctbl%type) RETURN STRING is

   ls_Result      cntbl_cnta.cnta_ctbl%type ;
   ln_count       number ;
BEGIN

  ls_result := ' ' ;

  SELECT count(*)
    INTO ln_count
    FROM cntbl_ctas_aut c
   WHERE c.cnta_cntbl = as_cnta ;

  if ln_count > 0 then
    SELECT c.cnta_debe
      INTO ls_result
      FROM cntbl_ctas_aut c
     WHERE c.cnta_cntbl = as_cnta ;
  end if ;

 RETURN(ls_Result);

END usf_cnt_cnta_equivalente;
/

prompt
prompt Creating function USF_CNT_CNTA_MATRIZ
prompt =====================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.usf_cnt_cnta_matriz(
   as_matriz      matriz_cntbl_finan_det.matriz%type ) RETURN STRING is

   CURSOR c_matriz is
   SELECT mf.flag_debhab, mf.cnta_ctbl
   FROM matriz_cntbl_finan_det mf
   WHERE mf.matriz = as_matriz ;

   ls_Result Varchar2(30) ;

BEGIN
  ls_result := '' ;
  FOR c_m in c_matriz LOOP
      ls_result := ls_result || c_m.flag_debhab || '-' || c_m.cnta_ctbl || ';' ;
  END LOOP ;

  RETURN(ls_Result);

END usf_cnt_cnta_matriz;
/

