prompt
prompt Creating function USF_CNT_DATOS_CTACTE
prompt ======================================
prompt
create or replace function cantabria.USF_CNT_DATOS_CTACTE(
  as_cod_relacion in doc_pendientes_cta_cte.cod_relacion%type,
  as_tipo_doc     in doc_pendientes_cta_cte.tipo_doc%type,
  as_nro_doc      in cntbl_asiento_det.nro_docref1%type,
  as_cnta_ctbl    in cntbl_asiento_det.cnta_ctbl%type,
  as_tipo         in cntbl_asiento.flag_estado%type
   )
 return varchar is

 -- as_tipo: T= Tabla, O=Origen, F=Fecha, G=Glosa, M=Moneda, V=Voucher
  ln_count               number ;
  ls_glosa               cntas_pagar.descripcion%type ;
  ls_moneda              moneda.cod_moneda%type ;
  ls_origen              cntbl_asiento.origen%type ;
  ll_ano                 cntbl_asiento.ano%type ;
  ll_mes                 cntbl_asiento.mes%type ;
  ll_nro_libro           cntbl_asiento.nro_libro%type ;
  ll_nro_asiento         cntbl_asiento.nro_asiento%type ;

  ls_tabla         varchar2(1) ;
  ls_fecha         varchar2(10) ;
  ls_voucher       varchar2(25) ;


  CURSOR c_vouche is
  SELECT ca.flag_tabla, ca.origen, ca.ano, ca.mes, ca.nro_libro, ca.nro_asiento,
         trim(to_char(ca.fecha_cntbl,'dd/mm/yyyy')) as fecha, ca.cod_moneda, cad.det_glosa
    FROM cntbl_asiento ca, cntbl_asiento_det cad
  WHERE (ca.origen = cad.origen
    AND  ca.ano = cad.ano
    AND  ca.mes = cad.mes
    AND  ca.nro_libro = cad.nro_libro
    AND  ca.nro_asiento = cad.nro_asiento)
    AND (ca.flag_estado <> '0')
    AND (cad.cod_relacion = as_cod_relacion
    AND  cad.nro_docref1 = as_nro_doc
    AND  cad.tipo_docref1 = as_tipo_doc
    AND  cad.cnta_ctbl = as_cnta_ctbl)
  ORDER BY ca.ano, ca.mes, ca.nro_libro, ca.nro_asiento ;



  --Result  cntas_cobrar.observacion%type;

BEGIN

-- Edgar Morante Miercoles 10Jul2002, replicacion
If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
    return('');
end if;

-- Capturando de cuentas por cobrar
SELECT count(*)
  INTO ln_count
  FROM cntas_cobrar cc
 WHERE cc.tipo_doc     = as_tipo_doc
   AND cc.nro_doc      = SUBSTR(as_nro_doc,1,10) ;

IF ln_count > 0 THEN
  SELECT trim(to_char(cc.fecha_documento,'dd/mm/yyyy')), cc.observacion, cc.cod_moneda, cc.origen, cc.ano, cc.mes, NVL(cc.nro_libro,0),
         cc.nro_asiento
    INTO ls_fecha, ls_glosa, ls_moneda, ls_origen, ll_ano, ll_mes, ll_nro_libro,
         ll_nro_asiento
    FROM cntas_cobrar cc
   WHERE cc.tipo_doc     = as_tipo_doc
     AND cc.nro_doc      = SUBSTR(as_nro_doc,1,10) ;

  ls_tabla :='1' ;
  -- Voucher
  IF ll_nro_libro > 0 THEN
     ls_voucher := ls_origen||'-'||to_char(ll_ano) || '-' ||to_char(ll_mes,'00')||'-'||
                   trim(to_char(ll_nro_libro))||'-'||trim(to_char(ll_nro_asiento)) ;
  ELSE
    FOR c_v IN c_vouche() LOOP
        ls_origen := c_v.origen ;
        ls_fecha := trim(c_v.fecha) ;
        ls_glosa := c_v.det_glosa ;
        ls_moneda := c_v.cod_moneda ;
        ls_voucher := c_v.origen||'-'||to_char(c_v.ano) || '-' ||to_char(c_v.mes,'00')||'-'||trim(to_char(c_v.nro_libro))||'-'||trim(to_char(c_v.nro_asiento)) ;
        EXIT ;
    END LOOP ;
  END IF ;

ELSE
-- Capturando de cuentas por pagar
  SELECT count(*)
    INTO ln_count
    FROM cntas_pagar cp
   WHERE cp.cod_relacion = as_cod_relacion
     AND cp.tipo_doc = as_tipo_doc
     AND cp.nro_doc = SUBSTR(as_nro_doc,1,10) ;

  IF ln_count > 0 THEN
    SELECT trim(to_char(cp.fecha_emision,'dd/mm/yyyy')), cp.descripcion, cp.cod_moneda, cp.origen, cp.ano, cp.mes, cp.nro_libro,
           cp.nro_asiento
      INTO ls_fecha, ls_glosa, ls_moneda, ls_origen, ll_ano, ll_mes, ll_nro_libro,
           ll_nro_asiento
      FROM cntas_pagar cp
     WHERE cp.cod_relacion = as_cod_relacion
       AND cp.tipo_doc     = as_tipo_doc
       AND cp.nro_doc      = SUBSTR(as_nro_doc,1,10) ;

    ls_tabla :='3' ;
    -- Voucher
    IF ll_nro_libro > 0 THEN
       ls_voucher := ls_origen||'-'||to_char(ll_ano) || '-' ||to_char(ll_mes,'00')||'-'||
                     trim(to_char(ll_nro_libro))||'-'||trim(to_char(ll_nro_asiento)) ;
    ELSE
       FOR c_v IN c_vouche() LOOP
           ls_origen := c_v.origen ;
           ls_fecha := trim(c_v.fecha) ;
           ls_glosa := c_v.det_glosa ;
           ls_moneda := c_v.cod_moneda ;
           ls_voucher := c_v.origen||'-'||to_char(c_v.ano) || '-' ||to_char(c_v.mes,'00')||'-'||trim(to_char(c_v.nro_libro))||'-'||trim(to_char(c_v.nro_asiento)) ;
           EXIT ;
       END LOOP ;
    END IF ;

  ELSE
    -- Para asientos contables
    FOR c_v IN c_vouche() LOOP
        ls_tabla := 'V' ;
        ls_origen := c_v.origen ;
        ls_fecha := trim(c_v.fecha) ;
        ls_glosa := c_v.det_glosa ;
        ls_moneda := c_v.cod_moneda ;
        ls_voucher := c_v.origen||'-'||to_char(c_v.ano) || '-' ||to_char(c_v.mes,'00')||'-'||trim(to_char(c_v.nro_libro))||'-'||trim(to_char(c_v.nro_asiento)) ;
        EXIT ;
    END LOOP ;

  END IF ;

END IF ;

IF as_tipo = 'T' THEN
      RETURN(ls_tabla) ;
ELSIF as_tipo = 'O' THEN
      RETURN(ls_origen) ;
ELSIF as_tipo = 'F' THEN
      RETURN(ls_fecha) ;
ELSIF as_tipo = 'G' THEN
      RETURN(ls_glosa) ;
ELSIF as_tipo = 'M' THEN
      RETURN(ls_moneda) ;
ELSIF as_tipo = 'V' THEN
      RETURN(ls_voucher) ;
ELSE
      RETURN(' ') ;
END IF ;

END USF_CNT_DATOS_CTACTE;
/

prompt
prompt Creating function USF_CNT_EXISTE_CNTA_CNTBL
prompt ===========================================
prompt
create or replace function cantabria.USF_CNT_EXISTE_CNTA_CNTBL(as_cnta_cntbl in char) return boolean is
  Result          boolean;
  ln_existe       number(2) ;
begin
  result := false ;
  if as_cnta_cntbl is null then
     return( false) ;
  else
     select count(*)
     into ln_existe
     from cntbl_cnta
     where cnta_ctbl = as_cnta_cntbl ;
     if ln_existe = 0 then
        return false ;
     else
        return true ;
     end if;
  end if ;

  return(Result);
end USF_CNT_EXISTE_CNTA_CNTBL;
/

prompt
prompt Creating function USF_CNT_GRABAR_PROCESO
prompt ========================================
prompt
create or replace function cantabria.usf_cnt_grabar_proceso(
  ad_fecha_proceso   in oper_procesos.fecha_proceso%type,
  ad_fecha_inicial   in oper_procesos.fecha_obj_inicial%type,
  ad_fecha_final     in oper_procesos.fecha_obj_final%type,
  as_cod_proceso     in oper_procesos.cod_proceso%type,
  as_window          in oper_procesos.window%type,
  as_desc_proceso    in oper_procesos.desc_proceso%type,
  as_flag_reversion  in oper_procesos.flag_reversion%type,
  as_flag_mayoriz    in oper_procesos.flag_mayoriz%type,
  as_cod_usr         in oper_procesos.cod_usr%type )
return number is

  ln_nro_proceso     oper_procesos.nro_proceso%type ;
begin
-- Capturar ultimo nro_proceso
select max(nro_proceso) into ln_nro_proceso from oper_procesos ;
ln_nro_proceso := nvl(ln_nro_proceso,0) + 1 ;

-- Insertando registro
insert into oper_procesos
( nro_proceso, fecha_proceso, fecha_obj_inicial,
  fecha_obj_final, cod_proceso, window,
  desc_proceso, flag_reversion, flag_mayoriz,
  cod_usr )
values
( ln_nro_proceso, ad_fecha_proceso, ad_fecha_inicial,
  ad_fecha_final, as_cod_proceso, as_window,
  as_desc_proceso, '0', '0',
  as_cod_usr ) ;

return(ln_nro_proceso);

end usf_cnt_grabar_proceso;
/

prompt
prompt Creating function USF_CNT_GRABA_TEMPORAL
prompt ========================================
prompt
create or replace function cantabria.usf_cnt_graba_temporal(
  as_cencos_origen      in tt_cnt_asnt_maquinaria.cencos_origen%type,
  as_cencos_destino     in tt_cnt_asnt_maquinaria.cencos_destino%type,
  as_cnta_prsp          in tt_cnt_asnt_maquinaria.cnta_prsp%type,
  as_proveedor          in tt_cnt_asnt_maquinaria.proveedor%type,
  as_cod_maquina        in tt_cnt_asnt_maquinaria.cod_maquina%type,
  as_campo              in tt_cnt_asnt_maquinaria.campo%type,
  an_cantidad           in tt_cnt_asnt_maquinaria.cantidad%type,
  as_cod_labor          in tt_cnt_asnt_maquinaria.cod_labor%type,
  as_cod_ejecutor       in tt_cnt_asnt_maquinaria.cod_ejecutor%type,
  as_cnta_ctbl_debe     in tt_cnt_asnt_maquinaria.cnta_ctbl_debe%type,
  as_cnta_ctbl_haber    in tt_cnt_asnt_maquinaria.cnta_ctbl_haber%type,
  as_flag_trabajo_curso in tt_cnt_asnt_maquinaria.flag_trabajo_curso%type,
  an_nro_parte          in tt_cnt_asnt_maquinaria.nro_parte%type,
  as_centro_benef       IN tt_cnt_asnt_maquinaria.centro_benef%TYPE
   )
return boolean is
  Result boolean;
begin
-- Funciona que permite actualizar un registro en CNTBL_PRE_ASIENTO_DET
result := true ;
update tt_cnt_asnt_maquinaria
set cod_maquina              = as_cod_maquina,
    campo                    = as_campo,
    cantidad                 = nvl(cantidad,0) + an_cantidad,
    cod_labor                = as_cod_labor,
    cod_ejecutor             = as_cod_ejecutor,
    cnta_ctbl_debe           = as_cnta_ctbl_debe,
    cnta_ctbl_haber          = as_cnta_ctbl_haber,
    flag_trabajo_curso       = as_flag_trabajo_curso,
    centro_benef             = as_centro_benef
where cencos_origen          = as_cencos_origen and
      cencos_destino         = as_cencos_destino and
      proveedor              = as_proveedor and
      nro_parte              = an_nro_parte and
      cnta_prsp              = as_cnta_prsp and
      flag_trabajo_curso     = as_flag_trabajo_curso ;

if sql%notfound then
  -- Insertando registro
  insert into tt_cnt_asnt_maquinaria
  ( cencos_origen, cencos_destino, cnta_prsp,
    proveedor, cod_maquina, campo,
    cantidad, cod_labor, cod_ejecutor,
    cnta_ctbl_debe, cnta_ctbl_haber, flag_trabajo_curso,
    nro_parte, centro_benef )
  values
  ( as_cencos_origen, as_cencos_destino, as_cnta_prsp,
    as_proveedor, as_cod_maquina, as_campo,
    nvl(an_cantidad,0), as_cod_labor, as_cod_ejecutor,
    as_cnta_ctbl_debe, as_cnta_ctbl_haber, as_flag_trabajo_curso,
    an_nro_parte, as_centro_benef ) ;
end if;

return(Result);

end usf_cnt_graba_temporal;
/

prompt
prompt Creating function USF_CNT_ING_CTACTE
prompt ====================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_CNT_ING_CTACTE(
  as_cod_relacion in doc_pendientes_cta_cte.cod_relacion%type,
  as_tipo_doc     in doc_pendientes_cta_cte.tipo_doc%type,
  as_nro_doc      in doc_pendientes_cta_cte.nro_doc%type,
  ad_fecha_doc    in doc_pendientes_cta_cte.fecha_doc%type,
  as_flag_tabla   in doc_pendientes_cta_cte.flag_tabla%type,
  as_cnta_ctbl    in doc_pendientes_cta_cte.cnta_ctbl%type,
  as_cod_moneda   in doc_pendientes_cta_cte.cod_moneda%type,
  as_flag_debhab  in doc_pendientes_cta_cte.flag_debhab%type,
  an_sldo_sol     in doc_pendientes_cta_cte.sldo_sol%type,
  an_saldo_dol    in doc_pendientes_cta_cte.saldo_dol%type )
return boolean is

  Result              boolean;
  ln_count            number(2) ;
  ls_cnta_ctbl        doc_pendientes_cta_cte.cnta_ctbl%type;
  ls_cod_moneda       doc_pendientes_cta_cte.cod_moneda%type;
  ls_flag_debhab      doc_pendientes_cta_cte.flag_debhab%type;
  ls_cod_soles        logparam.cod_soles%type;
  ls_cod_dolares      logparam.cod_dolares%type;
  ln_sldo_sol         doc_pendientes_cta_cte.sldo_sol%type;
  ln_saldo_dol        doc_pendientes_cta_cte.saldo_dol%type;
  ln_dato_sol         doc_pendientes_cta_cte.sldo_sol%type;
  ln_dato_dol         doc_pendientes_cta_cte.saldo_dol%type;


BEGIN

-- Edgar Morante Miercoles 10Jul2002, replicacion
If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
    return(false);
end if;

  -- Captura moneda soles
  select cod_soles
  into ls_cod_soles
  from logparam
  where reckey='1' ;

  -- Verifica cuantos registros hay de cuenta corriente
  select count(*)
  into ln_count
  from doc_pendientes_cta_cte
  where cod_relacion = as_cod_relacion and
        tipo_doc     = as_tipo_doc and
        nro_doc      = as_nro_doc ;

  -- Registra un item en caso sea nuevo
  IF nvl(ln_count,0) = 0 then
     insert into doc_pendientes_cta_cte(
            cod_relacion,
            tipo_doc,
            nro_doc,
            fecha_doc,
            flag_tabla,
            cnta_ctbl,
            cod_moneda,
            flag_debhab,
            sldo_sol,
            saldo_dol )
     values (as_cod_relacion,
             as_tipo_doc,
             as_nro_doc,
             ad_fecha_doc,
             as_flag_tabla,
             as_cnta_ctbl,
             as_cod_moneda,
             as_flag_debhab,
             an_sldo_sol,
             an_saldo_dol ) ;

  ELSE
    -- Como existe registro de cuenta corriente, captura datos originales
    -- en doc_pendientes_cta_cte
    select cnta_ctbl, cod_moneda, flag_debhab,
           sldo_sol, saldo_dol
      into ls_cnta_ctbl, ls_cod_moneda, ls_flag_debhab,
           ln_sldo_sol, ln_saldo_dol
      from doc_pendientes_cta_cte
     where cod_relacion = as_cod_relacion and
           tipo_doc     = as_tipo_doc and
           nro_doc      = as_nro_doc ;

    /*
    -- No debe permitir registrar items con mismo flag de movimiento
    IF ls_flag_debhab = as_flag_debhab then
       RAISE_APPLICATION_ERROR( -20000, 'Existe cuenta corriente con '||
       'mismo tipo de movimiento' || as_flag_debhab ) ;
    ELSE
       ln_dato_sol := ln_sldo_sol - an_sldo_sol ;
       ln_dato_dol := ln_saldo_dol - an_saldo_dol ;
       IF ls_cod_moneda = as_cod_moneda then
          IF ln_dato_sol < 0 then
             RAISE_APPLICATION_ERROR( -20001, 'Saldo soles no puede ser negativo' ) ;
          end if;
       ELSE
          IF ln_dato_dol < 0 then
             RAISE_APPLICATION_ERROR( -20002, 'Saldo dolares no puede ser negativo' ) ;
          end if;
       END IF ;
       -- Actualizando registro
       update doc_pendientes_cta_cte
          set sldo_sol  = ln_sldo_sol,
              saldo_dol = ln_saldo_dol
        where cod_relacion = as_cod_relacion and
              tipo_doc     = as_tipo_doc and
              nro_doc      = as_nro_doc ;
    END IF;
    */

    -- Actualizando registro de saldo de cuenta corriente

    -- Si tienen el mismo flag (Debe / Haber), debe sumar
    IF ls_flag_debhab = as_flag_debhab then
       update doc_pendientes_cta_cte
       set    sldo_sol  = ln_sldo_sol + an_sldo_sol,
              saldo_dol = ln_saldo_dol + an_saldo_dol
       where  cod_relacion = as_cod_relacion and
              tipo_doc     = as_tipo_doc and
              nro_doc      = as_nro_doc ;
    ELSE
       -- Si tienen diferente flag (Debe / Haber), debe restar
      update doc_pendientes_cta_cte
      set    sldo_sol  = ln_sldo_sol - an_sldo_sol,
             saldo_dol = ln_saldo_dol - an_saldo_dol
      where  cod_relacion = as_cod_relacion and
             tipo_doc     = as_tipo_doc and
             nro_doc      = as_nro_doc ;
    END IF ;
  END IF ;

RETURN(Result);

END USF_CNT_ING_CTACTE;
/

prompt
prompt Creating function USF_CNT_INGRESO_PROCESO
prompt =========================================
prompt
create or replace function cantabria.usf_cnt_ingreso_proceso
(ad_fecha_proceso in date, ad_fecha_obj_inicial in date,
 ad_fecha_obj_final in date, as_cod_proceso in char,
 as_window in varchar2, as_desc_proceso in varchar2,
 as_flag_reversion in char, as_flag_mayoriz in char,
 as_cod_usr in char)

 return number is
  ln_nro_proceso number;

begin

     -- Nro de proceso
     select max(to_number(nro_proceso)) into ln_nro_proceso from oper_procesos ;
     ln_nro_proceso := nvl(ln_nro_proceso,0) + 1 ;
     -- Ingreso
     insert into oper_procesos
     (nro_proceso , fecha_proceso , fecha_obj_inicial,
     fecha_obj_final, cod_proceso, window,
     desc_proceso, flag_reversion, flag_mayoriz,
     cod_usr )
     values
     (ln_nro_proceso, ad_fecha_proceso, ad_fecha_obj_inicial,
      ad_fecha_obj_final, as_cod_proceso, as_window,
      as_desc_proceso, as_flag_reversion, as_flag_mayoriz,
      as_cod_usr ) ;

  return(ln_nro_proceso);

end usf_cnt_ingreso_proceso;
/

prompt
prompt Creating function USF_CNT_MES_TEXTO
prompt ===================================
prompt
create or replace function cantabria.USF_CNT_MES_TEXTO(an_mes in number)
  return char is

  ls_mes_texto char(20);
  ld_fecha    date ;

BEGIN

IF an_mes = 0 THEN
   ls_mes_texto := 'Apertura' ;
ELSE
   ld_fecha := to_date( '01/'|| to_char(an_mes,'99') ||'/2000' ,'dd/mm/yyyy');

   SELECT InitCap(to_char(ld_fecha, 'month', 'NLS_DATE_LANGUAGE = Spanish'))
     INTO ls_mes_texto
     FROM dual ;
END IF ;

RETURN(TRIM(ls_mes_texto));

END USF_CNT_MES_TEXTO;
/

prompt
prompt Creating function USF_CNT_PRE_ASIENTO_DET
prompt =========================================
prompt
create or replace function cantabria.usf_cnt_pre_asiento_det(
  as_origen          in cntbl_pre_asiento_det.origen%type,
  al_nro_libro       in cntbl_pre_asiento_det.nro_libro%type,
  al_nro_provisional in cntbl_pre_asiento_det.nro_provisional%type,
  as_cnta_ctbl       in cntbl_pre_asiento_det.cnta_ctbl%type,
  ad_fec_cntbl       in cntbl_pre_asiento_det.fec_cntbl%type,
  as_det_glosa       in cntbl_pre_asiento_det.det_glosa%type,
  as_flag_gen_aut    in cntbl_pre_asiento_det.flag_gen_aut%type,
  as_flag_debhab     in cntbl_pre_asiento_det.flag_debhab%type,
  as_cencos          in cntbl_pre_asiento_det.cencos%type,
  as_cod_ctabco      in cntbl_pre_asiento_det.cod_ctabco%type,
  as_tipo_docref     in cntbl_pre_asiento_det.tipo_docref%type,
  as_nro_docref1     in cntbl_pre_asiento_det.nro_docref1%type,
  as_nro_docref2     in cntbl_pre_asiento_det.nro_docref2%type,
  as_cod_relacion    in cntbl_pre_asiento_det.cod_relacion%type,
  al_imp_movsol      in cntbl_pre_asiento_det.imp_movsol%type,
  al_imp_movdol      in cntbl_pre_asiento_det.imp_movdol%type,
  al_imp_movaju      in cntbl_pre_asiento_det.imp_movaju%type,
  as_centro_benef    IN cntbl_pre_asiento_det.centro_benef%TYPE,
  as_org_am          in cntbl_pre_asiento_Det.org_am%TYPE,
  ani_nro_am         in cntbl_pre_asiento_det.nro_am%TYPE
)return boolean is

  ln_item            cntbl_pre_asiento_det.item%type;
  ls_flag_mov        cntbl_cnta.flag_permite_mov%type;
  ls_flag_cencos     cntbl_cnta.flag_cencos%type;
  ls_flag_doc_ref    cntbl_cnta.flag_doc_ref%type;
  ls_flag_codrel     cntbl_cnta.flag_codrel%type;
  ls_flag_cenbef     cntbl_cnta.flag_centro_benef%TYPE;

  Result boolean;

BEGIN

-- Funciona que permite actualizar un registro en CNTBL_PRE_ASIENTO_DET
result := true ;
-- Verificando si datos a grabar son correctos
select flag_permite_mov, flag_cencos, flag_doc_ref, flag_codrel, flag_centro_benef
into ls_flag_mov, ls_flag_cencos, ls_flag_doc_ref, ls_flag_codrel, ls_flag_cenbef
from cntbl_cnta
where cnta_ctbl = as_cnta_ctbl ;

IF ls_flag_mov='0' then
   RAISE_APPLICATION_ERROR( -20000, 'Cuenta contable ' ||
   as_cnta_ctbl || ' no permite movimiento' ) ;
END IF;

IF ls_flag_cencos='1' and (as_cencos is null) then
   RAISE_APPLICATION_ERROR( -20001, 'Cuenta contable ' ||
   as_cnta_ctbl || ' necesita centro de costo' ) ;
END IF;

IF ls_flag_cenbef='1' AND (as_centro_benef IS NULL) then
   RAISE_APPLICATION_ERROR( -20001, 'Cuenta contable ' ||
   as_cnta_ctbl || ' necesita Centro Beneficio' ) ;
END IF;

IF ls_flag_doc_ref='1' and (as_nro_docref1 is null) then
   RAISE_APPLICATION_ERROR( -20001, 'Cuenta contable ' ||
   as_cnta_ctbl || ' necesita documento' ) ;
END IF;

IF ls_flag_codrel='1' and (as_cod_relacion is null) then
   RAISE_APPLICATION_ERROR( -20001, 'Cuenta contable ' ||
   as_cnta_ctbl || ' necesita codigo de relacion' ) ;
END IF;

 -- Acutalizacion de cntbl_pre_asiento_det segun sea el caso
 update cntbl_pre_asiento_det
    set origen                   = as_origen,
        nro_libro                = al_nro_libro,
        nro_provisional          = al_nro_provisional,
        cnta_ctbl                = as_cnta_ctbl,
        fec_cntbl                = ad_fec_cntbl,
        det_glosa                = as_det_glosa,
        flag_gen_aut             = as_flag_gen_aut,
        flag_debhab              = as_flag_debhab,
        cencos                   = as_cencos,
        cod_ctabco               = as_cod_ctabco,
        tipo_docref              = as_tipo_docref,
        nro_docref1              = as_nro_docref1,
        nro_docref2              = as_nro_docref2,
        cod_relacion             = as_cod_relacion,
        imp_movsol               = nvl(imp_movsol,0) + al_imp_movsol,
        imp_movdol               = nvl(imp_movdol,0) + al_imp_movdol,
        imp_movaju               = nvl(imp_movaju,0) + al_imp_movaju,
        centro_benef             = as_centro_benef,
        org_am                   = as_org_am,
        nro_am                   = ani_nro_am
 where origen                 = as_origen
   and nro_libro              = al_nro_libro
   and nro_provisional        = al_nro_provisional
   and cnta_ctbl              = as_cnta_ctbl
   and flag_debhab            = as_flag_debhab
   and NVL(cencos, ' ')       = NVL(as_cencos, ' ')
   and NVL(tipo_docref, ' ')  = NVL(as_tipo_docref, ' ')
   and NVL(nro_docref1, ' ')  = NVL(as_nro_docref1, ' ')
   and NVL(nro_docref2, ' ')  = NVL(as_nro_docref2, ' ')
   and NVL(cod_relacion, ' ') = NVL(as_cod_relacion, ' ')
   AND NVL(centro_benef, ' ') = NVL(as_centro_benef, ' ')
   and nvl(org_am, ' ')       = NVL(as_org_am      , ' ')
   and NVL(nro_am, -1)        = NVL(ani_nro_am, -1)
   and det_glosa              = NVL(as_det_glosa, ' ');


 IF sql%notfound then
    -- Capturando el item
    select max(item)
      into ln_item
    from cntbl_pre_asiento_det
    where origen          = as_origen
      and nro_libro       = al_nro_libro
      and nro_provisional = al_nro_provisional ;

   ln_item := Nvl(ln_item,0) + 1 ;

    -- Insertando registro
    insert into cntbl_pre_asiento_det(
           origen, nro_libro, nro_provisional,
           item, cnta_ctbl, fec_cntbl,
           det_glosa, flag_gen_aut, flag_debhab,
           cencos, cod_ctabco, tipo_docref,
           nro_docref1, nro_docref2, cod_relacion,
           imp_movsol, imp_movdol, imp_movaju, centro_benef,
           org_am, nro_am)
    values(
           as_origen, al_nro_libro, al_nro_provisional,
           ln_item , as_cnta_ctbl, ad_fec_cntbl,
           as_det_glosa, as_flag_gen_aut, as_flag_debhab,
           as_cencos, as_cod_ctabco, as_tipo_docref,
           as_nro_docref1, as_nro_docref2, as_cod_relacion,
           nvl( al_imp_movsol, 0), nvl( al_imp_movdol, 0), nvl( al_imp_movaju, 0 ), as_centro_benef,
           as_org_am, ani_nro_am) ;
 end if;


return(Result);

end usf_cnt_pre_asiento_det;
/

prompt
prompt Creating function USF_CNT_PRE_CAB_ASIENTO
prompt =========================================
prompt
create or replace function cantabria.usf_cnt_pre_cab_asiento
(as_origen in char, an_nro_libro in number,
 as_cod_moneda in char, an_tasa_cambio in number,
 as_tipo_nota in char, an_nro_proceso in number,
 as_desc_glosa in varchar2, ad_fec_cntbl in date,
 ad_fec_registro in date, as_cod_usr in char,
 as_flag_estado in char, as_flag_mayoriz in char,
 as_flag_tabla in char, an_tot_soldeb in number,
 an_tot_solhab in number, an_tot_doldeb in number,
 an_tot_dolhab in number )

 return number
is
  ln_nro_provisional     cntbl_pre_asiento.nro_provisional%type;
  ln_tipo_cambio         cntbl_pre_asiento.tasa_cambio%type;
begin
  --ln_tipo_cambio := usf_pla_cal_tipo_cambio( trunc(r_cm.fec_registro) ) ;

  -- Captura correlativo
  select num_provisional into ln_nro_provisional
  from cntbl_libro
  where nro_libro = an_nro_libro ;

  ln_nro_provisional := NVL(ln_nro_provisional,0) + 1 ;
  -- Actualiza numero provisional
  update cntbl_libro set num_provisional = ln_nro_provisional
  where nro_libro = an_nro_libro ;

  -- Ingresa cabecera de pre asiento
  insert into cntbl_pre_asiento
  (origen , nro_libro , nro_provisional, cod_moneda,
   tasa_cambio, tipo_nota, nro_proceso, desc_glosa,
   fec_cntbl, fec_registro, cod_usr, flag_estado,
   flag_mayoriz, flag_tabla, tot_soldeb, tot_solhab,
   tot_doldeb, tot_dolhab )
   values
  (as_origen, an_nro_libro, ln_nro_provisional, as_cod_moneda,
   an_tasa_cambio, as_tipo_nota, an_nro_proceso, as_desc_glosa,
   ad_fec_cntbl, sysdate, as_cod_usr, '1',
   '0', as_flag_tabla, 0, 0, 0, 0 ) ;

  return(ln_nro_provisional);
end usf_cnt_pre_cab_asiento;
/

prompt
prompt Creating function USF_CNT_PROCESO_EXISTE
prompt ========================================
prompt
create or replace function cantabria.USF_CNT_PROCESO_EXISTE(as_cod_proceso in char, ad_fecha_proceso in date)
  return number
is

  Result         number ;
  ln_count       Number ;
begin
  -- Verifica si existe un proceso que no halla sido revertido en la fecha a procesar
  select count(*)
  into ln_count
  from oper_procesos o
  where cod_proceso = as_cod_proceso and
        trunc(fecha_proceso) = ad_fecha_proceso and
        flag_reversion <> '1' ;

  ln_count := nvl(ln_count,0) ;
  -- Retorna 0 si proceso ya existe
  if ln_count > 0 then
     result := 0 ;
  else
     result := 1 ;
  end if ;

  return(Result);

end USF_CNT_PROCESO_EXISTE;
/

prompt
prompt Creating function USF_CNT_RESTAR_CTA_CTE
prompt ========================================
prompt
create or replace function cantabria.usf_cnt_restar_cta_cte(
     an_ano       in cntbl_asiento_det.ano%type,
     an_mes       in cntbl_asiento_det.mes%type,
     as_origen    in cntbl_asiento_det.origen%type,
     as_codrel    in cntbl_asiento_det.cod_relacion%type,
     as_cuenta    in cntbl_asiento_det.cnta_ctbl%type,
     as_tipo_doc  in cntbl_asiento_det.tipo_docref1%type,
     as_nro_doc   in cntbl_asiento_det.nro_docref1%type,
     as_debhab    in cntbl_asiento_det.flag_debhab%type,
     an_impsol    in cntbl_asiento_det.imp_movsol%type,
     an_impdol    in cntbl_asiento_det.imp_movdol%type )
return number is

 ln_rc number := 0;

begin
-------------------------------------
-- Edgar Morante Miercoles 10Jul2002, replicacion
If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
    return 0;
end if;


/*****************************************************
**** REPLICACION PARA CNTA_CNTBL_CUENTA_CORRIENTE
*****************************************************/
Update cnta_cntbl_cuenta_corriente c
  set c.sol_debel = nvl(c.sol_debel,0) - decode(as_debhab,'D', an_impsol, 0),
      c.sol_haber = nvl(c.sol_haber,0) - decode(as_debhab,'H', an_impsol, 0),
      c.dol_debe  = nvl(c.dol_debe,0)  - decode(as_debhab,'D', an_impdol, 0),
      c.dol_haber = nvl(c.dol_haber,0) - decode(as_debhab,'H', an_impdol, 0),
      c.flag_replicacion = '0'
where c.ano          = an_ano AND
      c.mes          = an_mes AND
      c.cnta_ctbl    = as_cuenta AND
      c.cod_relacion = as_codrel AND
      c.tipo_doc     = as_tipo_doc AND
      c.nro_doc      = as_nro_doc ;

/*****************************************************
**** REPLICACION PARA CNTA_CNTBL_ORG_CNTA_CORR
*****************************************************/
Update cnta_cntbl_org_cnta_corr o
  set o.sol_debel = nvl(o.sol_debel,0) - decode(as_debhab,'D', an_impsol, 0),
      o.sol_haber = nvl(o.sol_haber,0) - decode(as_debhab,'H', an_impsol, 0),
      o.dol_debe  = nvl(o.dol_debe,0)  - decode(as_debhab,'D', an_impdol, 0),
      o.dol_haber = nvl(o.dol_haber,0) - decode(as_debhab,'H', an_impdol, 0),
      o.flag_replicacion = '0'
where o.cod_origen   = as_origen AND
      o.ano          = an_ano AND
      o.mes          = an_mes AND
      o.cnta_ctbl    = as_cuenta AND
      o.cod_relacion = as_codrel AND
      o.tipo_doc     = as_tipo_doc AND
      o.nro_doc      = as_nro_doc ;

return( ln_rc );

end usf_cnt_restar_cta_cte;
/

prompt
prompt Creating function USF_CNT_SUMAR_CTA_CTE
prompt =======================================
prompt
create or replace function cantabria.usf_cnt_sumar_cta_cte(
     an_ano       in cntbl_asiento_det.ano%type,
     an_mes       in cntbl_asiento_det.mes%type,
     as_origen    in cntbl_asiento_det.origen%type,
     as_codrel    in cntbl_asiento_det.cod_relacion%type,
     as_cuenta    in cntbl_asiento_det.cnta_ctbl%type,
     as_tipo_doc  in cntbl_asiento_det.tipo_docref1%type,
     as_nro_doc   in cntbl_asiento_det.nro_docref1%type,
     as_debhab    in cntbl_asiento_det.flag_debhab%type,
     an_impsol    in cntbl_asiento_det.imp_movsol%type,
     an_impdol    in cntbl_asiento_det.imp_movdol%type
)
return number is

 ln_rc number := 0;

begin
-------------------------------------
-- Edgar Morante Miercoles 10Jul2002, replicacion
If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
    return 0;
end if;

/*****************************************************
**** REPLICACION PARA CNTA_CNTBL_CUENTA_CORRIENTE
*****************************************************/
Update cnta_cntbl_cuenta_corriente c
  set c.sol_debel = NVL(c.sol_debel,0) + decode(as_debhab,'D', an_impsol, 0),
      c.sol_haber = NVL(c.sol_haber,0) + decode(as_debhab,'H', an_impsol, 0),
      c.dol_debe  = NVL(c.dol_debe,0)  + decode(as_debhab,'D', an_impdol, 0),
      c.dol_haber = NVL(c.dol_haber,0) + decode(as_debhab,'H', an_impdol, 0),
      c.flag_replicacion = '0'
where c.ano           =  an_ano 
  AND c.mes           = an_mes 
  AND c.cnta_ctbl     = as_cuenta 
  AND c.cod_relacion  = as_codrel 
  AND c.tipo_doc      = as_tipo_doc 
  AND trim(c.nro_doc) = trim(as_nro_doc) ;
/*****************************************************/

IF SQL%NOTFOUND THEN
    INSERT INTO cnta_cntbl_cuenta_corriente(
           ano, mes,
           cnta_ctbl, cod_relacion,
           tipo_doc, nro_doc,
           sol_debel, sol_haber,
           dol_debe, dol_haber,
           flag_replicacion)
    VALUES(
           an_ano, an_mes,
           as_cuenta, as_codrel,
           as_tipo_doc, as_nro_doc,
           decode(as_debhab,'D', an_impsol, 0), decode(as_debhab,'H', an_impsol, 0),
           decode(as_debhab,'D', an_impdol, 0), decode(as_debhab,'H', an_impdol, 0),
           '0' );
END IF ;

/*****************************************************
**** REPLICACION PARA CNTA_CNTBL_CUENTA_CORRIENTE
*****************************************************/
Update cnta_cntbl_org_cnta_corr o
  set o.sol_debel = NVL(o.sol_debel,0) + decode(as_debhab,'D', an_impsol, 0),
      o.sol_haber = NVL(o.sol_haber,0) + decode(as_debhab,'H', an_impsol, 0),
      o.dol_debe  = NVL(o.dol_debe,0)  + decode(as_debhab,'D', an_impdol, 0),
      o.dol_haber = NVL(o.dol_haber,0) + decode(as_debhab,'H', an_impdol, 0),
      o.flag_replicacion = '0'
where o.cod_origen    = as_origen 
  AND o.ano           = an_ano 
  AND o.mes           = an_mes 
  AND o.cnta_ctbl     = as_cuenta 
  AND o.cod_relacion  = as_codrel 
  AND o.tipo_doc      = as_tipo_doc 
  AND trim(o.nro_doc) = trim(as_nro_doc) ;
/*****************************************************/
IF SQL%NOTFOUND THEN
    INSERT INTO cnta_cntbl_org_cnta_corr(
           cod_origen, ano, mes,
           cnta_ctbl, cod_relacion,
           tipo_doc, nro_doc,
           sol_debel, sol_haber,
           dol_debe, dol_haber,
           flag_replicacion)
    VALUES(
           as_origen, an_ano, an_mes,
           as_cuenta, as_codrel,
           as_tipo_doc, as_nro_doc,
           decode(as_debhab,'D', an_impsol, 0), decode(as_debhab,'H', an_impsol, 0),
           decode(as_debhab,'D', an_impdol, 0), decode(as_debhab,'H', an_impdol, 0),
           '0' );
END IF ;

return( ln_rc );

end usf_cnt_sumar_cta_cte;
/

prompt
prompt Creating function USF_CNT_TIPO_CAMBIO
prompt =====================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.usf_cnt_tipo_cambio(
   ad_fecha in date
   ) return number is
  ld_fecha_par date ; -- fecha de parametro truncadad
  ln_tipo_de_cambio number;
  ln_reg number;
BEGIN
  ld_fecha_par := trunc( ad_fecha ) ;
  Select count(*)
    into ln_reg
    from calendario
   where trunc( fecha ) = ld_fecha_par
     and vta_dol_prom >= 0 ;

  IF nvl( ln_reg, 0 ) = 0 OR ln_reg = 0 THEN
     -- Si no existe tipo de cambio tomo el tipo de cambio de logparam
     SELECT l.ult_tipo_cam
       INTO ln_tipo_de_cambio
       FROM logparam l
      WHERE l.reckey = '1';

  ELSE
     Select vta_dol_prom
       into ln_tipo_de_cambio
       from calendario
      where trunc(fecha) = ld_fecha_par ;
  END IF ;
  RETURN( ln_tipo_de_cambio );
END usf_cnt_tipo_cambio;
/

prompt
prompt Creating function USF_COM_CENTRO_BENEFICIO_ART
prompt ==============================================
prompt
create or replace function cantabria.USF_COM_CENTRO_BENEFICIO_ART
(ac_cod_origen origen.cod_origen%type,
 ac_cod_art    articulo.cod_art%type  )

return varchar2 is
  Result varchar2 (12);

begin

  select min(cba.centro_benef) into result
  from centro_benef_articulo cba,centro_beneficio cb
 where (cba.centro_benef =  cb.centro_benef ) and
       (cb.cod_origen    = ac_cod_origen    ) and
       (cba.cod_art      = ac_cod_art       ) and
       (cb.flag_ventas   = '1'              ) ;

  return(Result);
end USF_COM_CENTRO_BENEFICIO_ART;
/

prompt
prompt Creating function USF_COM_COSTO_RACION
prompt ======================================
prompt
create or replace function cantabria.usf_com_costo_racion(
       asi_parte_racion    in com_parte_rac.parte_racion%TYPE,
       asi_tipo_racion     in com_parte_rac_det.flag_tipo_racion%TYPE
) return number is
  Result          number;
  ln_count        number;
begin
     select count(*)
        into ln_count
     from com_part_rac_costo a
     where a.parte_racion      = asi_parte_Racion
       and a.flag_tipo_racion  = asi_tipo_Racion;

     if ln_count = 0 then
         Result := 0;
     else
         select Nvl(a.costo_unit,0)
            into Result
         from com_part_rac_costo a
         where a.parte_racion      = asi_parte_Racion
           and a.flag_tipo_racion  = asi_tipo_Racion;
     end if;
  return(Result);
end usf_com_costo_racion;
/

prompt
prompt Creating function USF_COM_CUR_NRO_PARTE_COSTO
prompt =============================================
prompt
create or replace function cantabria.USF_COM_CUR_NRO_PARTE_COSTO(
       asi_origen  origen.cod_origen%type
 ) return number is

  ln_ult_nro    number ;

begin

  select npcp.ult_nro
    into ln_ult_nro
  from num_parte_compr_pago npcp
  where origen = asi_origen;

  return ln_ult_nro;

  EXCEPTION
     WHEN OTHERS THEN
       RAISE_APPLICATION_ERROR(-20000, 'ERROR EN FUNCION USF_COM_NUM_PARTE_COSTO'
                   || CHR(13) || 'ORIGEN: ' || ASI_ORIGEN
                   || CHR(13) || SQLERRM );
       rollback;

end USF_COM_CUR_NRO_PARTE_COSTO;
/

