prompt
prompt Creating function USF_COM_DIAS_PER_X_CLIENTE
prompt ============================================
prompt
create or replace function cantabria.USF_COM_DIAS_PER_X_CLIENTE
(ac_cod_cliente proveedor.proveedor%type ) return varchar2 is
  Result Varchar2(150);


ln_count Number ;

Cursor c_parametros is
SELECT fecha,cod_moneda,monto_max_cxc,pcc.limite_credito_cxc
  FROM prov_creditos_cxc pcc
 WHERE (pcc.cliente     = ac_cod_cliente ) and
       (pcc.flag_estado = '1'            ) ;


begin



For rc_par in c_parametros Loop




    /*Buscra monto pendiente*/
    select Count(*) into ln_count
      from cntas_cobrar cc,doc_pendientes_cta_cte dp
     where (cc.cod_relacion = dp.cod_relacion   ) and
           (cc.tipo_doc     = dp.tipo_doc       ) and
           (cc.nro_doc      = dp.nro_doc        ) and
           (cc.flag_provisionado = 'R'          ) and
           (cc.cod_relacion = ac_cod_cliente    ) and
           (Round(sysdate - cc.fecha_vencimiento) > rc_par.limite_credito_cxc );



      if ln_count > 0 then
         Result := 'Tiene Documentos Pendientes con  mas de '|| Trim(To_char(rc_par.limite_credito_cxc)) || ' Dias de Atrazo !' ;
      else
         Result := null ;
      end if ;


End Loop ;

  return(Result);
end USF_COM_DIAS_PER_X_CLIENTE;
/

prompt
prompt Creating function USF_COM_MONTO_PER_X_CLIENTE
prompt =============================================
prompt
create or replace function cantabria.USF_COM_MONTO_PER_X_CLIENTE
(ac_cod_cliente proveedor.proveedor%type ) return varchar2 is
  Result Varchar2(150);


ln_saldo_sol       doc_pendientes_cta_cte.sldo_sol%type ;
ln_saldo_dol       doc_pendientes_cta_cte.sldo_sol%type ;
ln_monto_pendiente doc_pendientes_cta_cte.sldo_sol%type ;
lc_soles           moneda.cod_moneda%type               ;
lc_dolares         moneda.cod_moneda%type               ;


Cursor c_parametros is
SELECT fecha,cod_moneda,monto_max_cxc,pcc.limite_credito_cxc
  FROM prov_creditos_cxc pcc
 WHERE (pcc.cliente     = ac_cod_cliente ) and
       (pcc.flag_estado = '1'            ) ;


begin

select l.cod_soles,l.cod_dolares into lc_soles,lc_dolares from logparam l where l.reckey = '1' ;

For rc_par in c_parametros Loop

    ln_saldo_sol := 0.00 ;
    ln_saldo_dol := 0.00 ;


    /*Buscra monto pendiente*/
    select Sum(dp.sldo_sol * dp.factor) as saldo_sol ,Sum(dp.saldo_dol * dp.factor) as saldo_dol
      into ln_saldo_sol,ln_saldo_dol
      from cntas_cobrar cc,doc_pendientes_cta_cte dp
     where (cc.cod_relacion = dp.cod_relacion   ) and
           (cc.tipo_doc     = dp.tipo_doc       ) and
           (cc.nro_doc      = dp.nro_doc        ) and
           (cc.flag_provisionado = 'R'          ) and
           (cc.cod_relacion = ac_cod_cliente    ) ;

      if rc_par.cod_moneda = lc_soles then
         ln_monto_pendiente := ln_saldo_sol ;
      else
         ln_monto_pendiente := ln_saldo_dol ;
      end if ;


      if ln_monto_pendiente > rc_par.monto_max_cxc then
         Result := 'Tiene Deudas Mayores a lo Establecido en su Cta Cte Monto Pendiente : '||to_char(ln_monto_pendiente) ;
      else
         Result := null ;
      end if ;


End Loop ;

  return(Result);
end USF_COM_MONTO_PER_X_CLIENTE;
/

prompt
prompt Creating function USF_COM_MONTO_SIN_IGV
prompt =======================================
prompt
create or replace function cantabria.USF_COM_MONTO_SIN_IGV(
       asi_proveedor in proveedor.proveedor%TYPE,
       asi_tipo_doc  in doc_tipo.tipo_doc%TYPE,
       asi_nro_doc   in cntas_pagar.nro_doc%TYPE
) return number is
  ln_Result number;
  ln_count  number;
begin

  select count(*)
    into ln_count
    from cntas_pagar_det t
   where t.cod_relacion = asi_proveedor
     and t.tipo_doc     = asi_tipo_doc
     and t.nro_doc      = asi_nro_doc;

  if ln_count = 0 then
     ln_result := 0;
  else
     select sum(t.importe * t.cantidad)
       into ln_result
       from cntas_pagar_det t
      where t.cod_relacion = asi_proveedor
        and t.tipo_doc     = asi_tipo_doc
        and t.nro_doc      = asi_nro_doc;
  end if;

  return(ln_Result);
end USF_COM_MONTO_SIN_IGV;
/

