prompt Creating function USF_COM_NUM_PARTE_COSTO
prompt =========================================
prompt
create or replace function cantabria.USF_COM_NUM_PARTE_COSTO(
       asi_origen origen.cod_origen%type
) return varchar2 is

  ls_ult_nro    COM_COMPR_PAGO.PARTE_COSTO%TYPE;
  ln_ult_nro    number ;

begin

  select ult_nro
    into ln_ult_nro
    from num_parte_compr_pago
   where origen = asi_origen
   for update nowait;

  --se concatena con origen
  ls_ult_nro := asi_origen || LPAD(to_char(ln_ult_nro),8,'0');

  --actualiza informacion de numeradores
  update num_parte_compr_pago
     set ult_nro = Nvl(ult_nro,0) + 1
   where origen = asi_origen;

  commit;

  return trim(ls_ult_nro);

  EXCEPTION
     WHEN OTHERS THEN
       RAISE_APPLICATION_ERROR(-20000, 'ERROR EN FUNCION USF_COM_NUM_PARTE_COSTO'
                   || CHR(13) || 'ORIGEN: ' || ASI_ORIGEN
                   || CHR(13) || SQLERRM );
       rollback;

end USF_COM_NUM_PARTE_COSTO;
/

