prompt
prompt Creating function USF_COMPHR_COMPENSA
prompt =====================================
prompt
create or replace function cantabria.usf_comphr_compensa (
   ani_inasis_sabado in number, --considera inasistncia en sabado
   ani_inasis_doming in number, --considera inasistncia en domingo
   ani_inasis_feriado in number, --considera inasistncia en feriado
   ani_sobret_sabado in number, --considera sobretirmpos en sabado
   ani_sobret_domingo in number, --considera sobretirmpos en domingo
   ani_sobret_feriado in number, --considera sobretirmpos en feriado
   asi_sobret_sabado in string, --concepto de sobretirmpos en sabado
   asi_sobret_domingo in string, --concepto de sobretirmpos en domingo
   asi_sobret_feriado in string, --concepto de sobretirmpos en feriado
   adi_ini_periodo in date,
   adi_fin_periodo in date,
   asi_doc_cmps in string

) return integer is ano_msg integer;

  ln_horas_inasist number;
  ln_horas_sobret number;
  ln_horas_compens number;

  ld_fec_movim date;

  ls_concep concepto.concep%type;
  ls_cod_trabajador maestro.cod_trabajador%type;
  ls_sabado char(1);
  ls_domingo char(1);
  ls_feriado char(1);

  cursor lc_trabajador is
     select i.cod_trabajador, i.fec_movim, i.fec_desde, i.fec_hasta
        from inasistencia i
        where trunc(i.fec_movim) between trunc(adi_ini_periodo) and trunc(adi_fin_periodo)
        and i.tipo_doc = asi_doc_cmps
        order by i.cod_trabajador, i.fec_movim;

   cursor lc_concep_sobret is
      select chd.concep
         from rh_grp_cmp_hrs_det chd
         where chd.grp_cmps_hrs = (
            select cht.grp_cmps_hrs
               from rh_grp_cmp_hrs_trab cht
               where cht.cod_trabajador = ls_cod_trabajador )
         order by chd.item;

    cursor lc_sobretiempo is
       select st.horas_sobret
          from sobretiempo_turno st
          where st.cod_trabajador = ls_cod_trabajador
             and trunc(st.fec_movim) between trunc(adi_ini_periodo) and trunc(adi_fin_periodo)
             and st.concep = ls_concep
          order by st.fec_movim;

begin
   ano_msg := 0;

   for rs_ti in lc_trabajador loop
      ld_fec_movim := rs_ti.fec_movim;
      ls_cod_trabajador := rs_ti.cod_trabajador;
      ln_horas_inasist := to_number(rs_ti.fec_desde - rs_ti.fec_hasta);

      select rch.sabado, rch.domingo, rch.feriado
         into ls_sabado, ls_domingo, ls_feriado
         from tt_rh_comp_hora rch
         where trunc(rch.fecha) = trunc(ld_fec_movim);

--      if trim(ls_sabado) = '1' and ani_inasis_sabado = 1 then --el pata falto en sabado
         for rs_cs in lc_concep_sobret loop
            ls_concep := rs_cs.concep;
            for rs_st in lc_sobretiempo loop
               ln_horas_sobret := rs_st.horas_sobret;
               if ln_horas_sobret < ln_horas_inasist then
                  ln_horas_compens := ln_horas_sobret;
               else
                  ln_horas_compens := ln_horas_inasist;
               end if;
            end loop;
         end loop;
--      end if;

   end loop;
   return(ano_msg);
end usf_comphr_compensa;
/

prompt
prompt Creating function USF_CONS_OPER
prompt ===============================
prompt
create or replace function cantabria.usf_cons_oper(
   as_corr_corte IN campo_ciclo.corr_corte%type)
   return integer is
----------------------------------------------------------
-- <*> Elimina al usf_cons_operacion
----------------------------------------------------------

ln_result         integer;
ln_cant_real      number;
ln_cant_procesada number;

begin
   --Suma de cantidad real de operaciones
   Select sum ( nvl( o.cant_real, 0) )
     Into ln_cant_real
     From operaciones o, campo_ciclo cc
    Where o.tipo_orden = (select doc_ot from logparam where reckey='1') AND
          o.nro_orden = cc.nro_orden AND
          cc.corr_corte = as_corr_corte ;

   --Consistencia en caso que sea nulo
   IF ln_cant_real IS NULL THEN
      ln_cant_real:=0;
   END IF;
   --Suma de cantidad real de movimientos
   SELECT SUM(am.cant_procesada)
     INTO ln_cant_procesada
     FROM operaciones op, campo_ciclo cc, articulo_mov_proy am
    WHERE op.tipo_orden = (select doc_ot from logparam where reckey='1') AND
          op.nro_orden = cc.nro_orden AND
          cc.corr_corte = as_corr_corte AND
          am.oper_sec = op.oper_sec;

   --Consistencia en caso que sea nulo
   IF ln_cant_procesada IS NULL THEN
      ln_cant_procesada:=0;
   END IF;
   --Si cantidad real contiene informacion no debe pasar
   IF ln_cant_real > 0 THEN
      ln_result:= 1;
      return(ln_result);
   END IF;
   --Si cantidad procesada contiene informacion no debe pasar
   IF ln_cant_procesada > 0 THEN
      ln_result:= 1;
      return(ln_result);
   END IF;
   ln_result:=0;
   return(ln_result);
end usf_cons_oper;
/

prompt
prompt Creating function USF_CONS_OPERACION
prompt ====================================
prompt
create or replace function cantabria.usf_cons_operacion(
ai_oper_sec IN operaciones.oper_sec%type)
------------------------------------------
--<*> Eliminado por usf_cons_oper
------------------------------------------
return integer is
ln_result integer;
ln_cant_real number;
ln_cant_procesada number;

begin
--Suma de cantidad real de operaciones
SELECT SUM( nvl( o.cant_real, 0 ) )
  INTO ln_cant_real
  FROM operaciones o, campo_ciclo cc
 WHERE o.tipo_orden=(select l.doc_ot from logparam l where reckey='1') AND
       o.nro_orden= cc.nro_orden AND
       cc.corr_corte = ai_oper_sec ;

--Consistencia en caso que sea nulo
IF ln_cant_real IS NULL THEN
   ln_cant_real:=0;
END IF;

--Suma de cantidad real de movimientos
SELECT SUM(am.cant_procesada)
INTO ln_cant_procesada
FROM operaciones op, campo_ciclo cc, articulo_mov_proy am
WHERE op.tipo_orden = (select l.doc_ot from logparam l where reckey='1') AND
      op.nro_orden = cc.nro_orden AND
      cc.corr_corte = ai_oper_sec AND
      am.oper_sec = op.oper_sec;

--Consistencia en caso que sea nulo
IF ln_cant_procesada IS NULL THEN
   ln_cant_procesada:=0;
END IF;

--Si cantidad real contiene informacion no debe pasar
IF ln_cant_real > 0 THEN
   ln_result:= 1;
   return(ln_result);
END IF;

--Si cantidad procesada contiene informacion no debe pasar
IF ln_cant_procesada > 0 THEN
   ln_result:= 1;
   return(ln_result);
END IF;

ln_result:=0;
return(ln_result);

end usf_cons_operacion;
/

prompt
prompt Creating function USF_CONS_OPERACION_OT
prompt =======================================
prompt
create or replace function cantabria.usf_cons_operacion_ot(
an_nro_orden IN operaciones.nro_orden%type)
return integer is
ln_result integer;
ln_cant_real number;
ln_cant_procesada number;
begin
--Suma de cantidad real de operaciones
SELECT SUM(cant_real)
INTO ln_cant_real
FROM operaciones
WHERE nro_orden = an_nro_orden;
--Consistencia en caso que sea nulo
IF ln_cant_real IS NULL THEN
   ln_cant_real:=0;
END IF;
--Suma de cantidad real de movimientos
SELECT SUM(am.cant_procesada)
INTO ln_cant_procesada
FROM operaciones op, articulo_mov_proy am
WHERE op.nro_orden = an_nro_orden
      and am.oper_sec = op.oper_sec;
--Consistencia en caso que sea nulo
IF ln_cant_procesada IS NULL THEN
   ln_cant_procesada:=0;
END IF;
--Si cantidad real contiene informacion no debe pasar
IF ln_cant_real > 0 THEN
   ln_result:= 1;
   return(ln_result);
END IF;
--Si cantidad procesada contiene informacion no debe pasar
IF ln_cant_procesada > 0 THEN
   ln_result:= 1;
   return(ln_result);
END IF;
ln_result:=0;
return(ln_result);
end usf_cons_operacion_ot;
/

prompt
prompt Creating function USF_CONS_SOLI_ORD_TRA
prompt =======================================
prompt
create or replace function cantabria.usf_cons_soli_ord_tra
   ( an_nro_solicitud in number )
   return number is

   Cursor c_orden_trabajo_sol is
      Select ot.nro_orden, ot.flag_estado
        from orden_trabajo ot
       where ot.nro_solicitud = an_nro_solicitud
         and ( ot.flag_estado = '1' or ot.flag_estado='2' ) ;

   ln_tot_ot       integer ;   -- total de o/t de dicha solicitud
   ln_ot_activas   integer ;  -- registros activos
   ln_ot_cerradas  integer ;  -- reg

   -- determina el estado de solicitud de ordenes de trabajo
   -- Pendiente si a) no existe o/t   b) existe xlo- 1=activo
   -- Ejecutado si las 'n' ot estan 2=cerradas
begin

   ln_tot_ot := 0 ;
   ln_ot_activas := 0 ;
   ln_ot_cerradas := 0 ;

   For rc_s in c_orden_trabajo_sol
   Loop
      ln_tot_ot := ln_tot_ot + 1 ;
      if rc_s.flag_estado = '1' Then
         ln_ot_activas := ln_ot_activas + 1 ;
      else -- se asume cerradas segun select del cursor
         ln_ot_cerradas := ln_ot_cerradas + 1 ;
      end if ;
   End Loop ;

   If ln_tot_ot = ln_ot_cerradas and ln_tot_ot > 0 Then
      return 2 ;
   Else
      return 1 ;
   End if ;

End usf_cons_soli_ord_tra ;
/

