prompt
prompt Creating function USF_COSTO_INSUMO_ESTIMADO
prompt ===========================================
prompt
create or replace function cantabria.usf_costo_insumo_estimado (an_oper_sec operaciones.oper_sec%type)
return number is
  ln_result number;
begin
  --Calculamos Total de Costo de Insumos Por Operacisn
   SELECT ROUND(SUM(NVL(art_m_p.CANT_PROYECT,0) * NVL(art.COSTO_ULT_COMPRA,0)),2)
   INTO   ln_result
   FROM   ARTICULO art    ,
          ARTICULO_MOV_PROY art_m_p
   WHERE ( art.cod_art       = art_m_p.cod_art)    and
         ( art_m_p.oper_sec = an_oper_sec)  ;

   IF ln_result IS NULL THEN
      ln_result:= 0;
   END IF;

  return(ln_result);
end usf_costo_insumo_estimado;
/

prompt
prompt Creating function USF_COSTO_INSUMO_REAL
prompt =======================================
prompt
create or replace function cantabria.usf_costo_insumo_real (an_oper_sec operaciones.oper_sec%type)
return number is
  ln_result number;

begin
  --Calculamos Total de Costo de Insumos Por Operacion
  SELECT ROUND(SUM(NVL(pd_ins.CANTIDAD,0) * NVL(art.COSTO_ULT_COMPRA,0)),2)
  INTO   ln_result
  FROM   PD_ot_INSUMOS pd_ins,
         PD_ot_det pd_lab,
         ARTICULO   art
   WHERE ( pd_lab.nro_parte  = pd_ins.nro_parte) and
         ( pd_lab.nro_item  = pd_ins.nro_item    ) and
         ( pd_ins.cod_art   = art.cod_art        ) and
         ( ( pd_lab.oper_sec = an_oper_sec ));

   IF ln_result IS NULL THEN
      ln_result:= 0;
   END IF;
  return(ln_result);
end usf_costo_insumo_real;
/

prompt
prompt Creating function USF_COSTO_TOTAL
prompt =================================
prompt
create or replace function cantabria.usf_costo_total(as_corr_corte in char )
  return number is

  ln_total number;
  ln_operaciones number;
  ln_insumos number;
  ln_otros number;
begin
  SELECT SUM(O.CANT_REAL*LE.COSTO_UNITARIO)
  INTO ln_operaciones
  FROM operaciones O, campo_ciclo cc, LABOR_EJECUTOR LE, LABOR LB, LABOR_ETAPA LT
  WHERE o.tipo_orden = (SELECT l.doc_ot FROM logparam l where reckey='1') AND
        o.nro_orden = cc.nro_orden AND
        cc.CORR_CORTE = as_corr_corte AND
        o.cod_labor =le.cod_labor AND
        o.cod_ejecutor = le.cod_ejecutor AND
        o.cod_labor = lb.cod_labor and lb.cod_etapa = lt.cod_etapa ;

  IF ln_operaciones IS NULL THEN
     ln_operaciones:= 0;
  END IF;

--Calculamos Total de insumos por Fase
  SELECT SUM( A.CANT_PROCESADA * A.PRECIO_UNIT)
  INTO ln_insumos
  FROM articulo_mov A, OPERACIONES O, campo_ciclo cc, LABOR L, LABOR_ETAPA LE
  WHERE o.tipo_orden = (SELECT l.doc_ot FROM logparam l where reckey='1')
    AND o.nro_orden = cc.nro_orden
    AND cc.corr_corte = as_corr_corte
    AND O.OPER_SEC = A.OPER_SEC
    AND O.COD_LABOR = L.COD_LABOR
    AND L.COD_ETAPA = LE.COD_ETAPA;

  IF ln_insumos IS NULL THEN
     ln_insumos:= 0;
  END IF ;
--Calculamos Total otros gastos por Fase
  SELECT SUM(C.IMPORTE)
  INTO ln_otros
  FROM costo_x_centro C, LABOR_ETAPA LE
  WHERE C.CORR_CORTE = as_corr_corte AND C.COD_ETAPA = LE.COD_ETAPA;
  IF ln_otros IS NULL THEN
     ln_otros:= 0;
  END IF;
  ln_total := ln_operaciones + ln_insumos + ln_otros;
  return(ln_total);
end usf_costo_total;
/

