prompt Creating function USF_CTRL_EFI_OPE_MAQ_LAB_EJE
prompt ==============================================
prompt
create or replace function cantabria.usf_ctrl_efi_ope_maq_lab_eje(
   an_oper_sec  in number,
   as_cod_labor in string   ) return number is

   ln_costo_unitario number;
begin

  ln_costo_unitario := 0 ;
  select avg(le.costo_unitario)
    into ln_costo_unitario
    from operaciones o, labor_ejecutor le
   where o.oper_sec = an_oper_sec
     and o.cod_ejecutor = le.cod_ejecutor
     and le.costo_unitario is not null
     and le.flag_estado= 1
     and le.cod_labor = as_cod_labor ;

  ln_costo_unitario := nvl( ln_costo_unitario, 0) ;

  return( ln_costo_unitario );
end usf_ctrl_efi_ope_maq_lab_eje;
/

