prompt Creating function USF_CTRL_EFI_OPE_MAQ_RATIO
prompt ============================================
prompt
create or replace function cantabria.usf_ctrl_efi_ope_maq_ratio(
   an_oper_sec in number,
   as_cod_labor in string ) return number is

   ln_cantidad number;
Begin

   ln_cantidad := 0;

   select avg(pro.cantidad)
     into ln_cantidad
     from operaciones o, campo_ciclo cc, prod_ratio_oper pro
    where o.oper_sec = an_oper_sec
      and cc.cod_plantilla is not null
      and o.tipo_orden = (select doc_ot from logparam where reckey='1')
      and o.nro_orden = cc.nro_orden
      and pro.cantidad is not null
      and o.cod_ejecutor = pro.cod_ejecutor
      and pro.cod_labor = as_cod_labor;

  ln_cantidad := nvl( ln_cantidad, 0);
  return( ln_cantidad );
end usf_ctrl_efi_ope_maq_ratio;
