prompt Creating function USF_DIAS_A_HORAS
prompt ==================================
prompt
create or replace function cantabria.usf_dias_a_horas(ad_dia_may in date, ad_dia_men in date) return number is
  Result number(5);
begin
  Result := 24 * (ad_dia_may - ad_dia_men ) ;
  -- Solo considera dif. fechas de 10 anos como maximo
  return(Result);
end usf_dias_a_horas;
/

prompt
prompt Creating function USF_DIAS_A_HORAS_LAB_INCID
prompt ============================================
prompt
create or replace function cantabria.usf_dias_a_horas_lab_incid(
  ad_dia_may in date, ad_dia_men in date,
  as_opcion in char) return number is

  ln_horas_totales   number(10,4) ;
  ln_horas_program   number(10,4) ;
  ln_horas_perdidas  number(10,4) ;

  Result number(10,4);

  /* as_opcion:
     T = tiempo total (P175)
     G = horas programadas  (P177)
     H = tiempo habil
     P = tiempo perdido
     M = tiempo de molienda
     D = dias de molienda
  */
begin

  -- Horas totales
  ln_horas_totales := 24 * (ad_dia_may - ad_dia_men ) ;

  -- horas programadas
  SELECT sum(nvl(inf.dia,0))
    INTO ln_horas_program
    FROM incidencias_fabrica inf, incidencias_dma ind
   WHERE inf.cod_incidencia = ind.cod_incidencia and
         ind.flag_grupo <> '1' and
         trunc(inf.fecha) = trunc(ad_dia_men) ;

  -- horas perdidas
  SELECT sum(nvl(inf.dia,0))
    INTO ln_horas_perdidas
    FROM incidencias_fabrica inf, incidencias_dma ind
   WHERE inf.cod_incidencia = ind.cod_incidencia and
         ind.flag_grupo = '1' and
         trunc(inf.fecha) = trunc(ad_dia_men) ;

  ln_horas_totales  := nvl(ln_horas_totales,0) ;
  ln_horas_program  := nvl(ln_horas_program,0) ;
  ln_horas_perdidas := nvl(ln_horas_perdidas,0) ;

  IF as_opcion='T' then
     -- tiempo total
     Return(ln_horas_totales);
  ELSIF as_opcion='G' then
     -- tiempo programado
     RETURN( ln_horas_program ) ;
  ELSIF as_opcion='H' then
     -- tiempo habil
     RETURN( ln_horas_totales - ln_horas_program ) ;
  ELSIF as_opcion='P' then
     -- tiempo perdido
     RETURN( ln_horas_perdidas ) ;
  ELSIF as_opcion='M' then
     -- tiempo molienda
     RETURN( ln_horas_totales - ln_horas_program - ln_horas_perdidas ) ;
  ELSIF as_opcion='D' then
     -- dias de molienda
     RETURN((ln_horas_totales - ln_horas_program)/24) ;
  END IF ;
  -- Solo considera dif. fechas de 10 anos como maximo
  --return(Result);
end usf_dias_a_horas_lab_incid;
/

prompt
prompt Creating function USF_DIAS_EN_MES
prompt =================================
prompt
create or replace function cantabria.usf_dias_en_mes(
   ad_fec_ini in date,            ad_fec_fin in date,
   an_dias_para_inicio in number, an_dias_duracion_proy in number,
   an_mes in number
   ) return number is

   ld_fec_fin date;
   ld_fec_pro date;
   ln_dias_tot number;
   ln_dias_mes number;
   ln_dia_parcial number;
   ln_Result number;

begin
  -- Jueves 22 de Marzo, Edgar Morante
  -- Eliminacion del an_dias_para_inicio por ya estar consideradas
  -- al momento de la generacion de la fecha.

  -- determinando fecha final
  if ad_fec_fin is null then
     ld_fec_fin := nvl(ad_fec_ini, sysdate) +
                 --nvl(an_dias_para_inicio, 0) +
                   nvl(an_dias_duracion_proy, 0) - 1 ;
  else
     ld_fec_fin := ad_fec_fin ;
  end if;
  ld_fec_pro := nvl(ad_fec_ini, sysdate) ;
           -- + nvl(an_dias_para_inicio, 0) ;


  ln_dia_parcial := nvl(an_dias_duracion_proy, 0) ;
  ln_dia_parcial := ln_dia_parcial - trunc( ln_dia_parcial ) ;
  ln_dias_mes := 0 ;
  ln_dias_tot := ln_dia_parcial ;

  Loop
     if to_number( to_char( ld_fec_pro, 'MM') ) = an_mes Then
        ln_dias_mes := ln_dias_mes + 1;
     end if ;
     ln_dias_tot := ln_dias_tot + 1;
     ld_fec_pro := ld_fec_pro + 1;
     exit when ld_fec_pro > ld_fec_fin ;
  End Loop;
  If to_char( ld_fec_fin, 'MM' ) = an_mes then
     ln_dias_mes := ln_dias_mes + ln_dia_parcial ;
  End if ;
  ln_result := ln_dias_mes / ln_dias_tot ;

  return(ln_Result);
end usf_dias_en_mes;
/

prompt
prompt Creating function USF_DISTR_NORM_ESTAND_INV
prompt ===========================================
prompt
create or replace function cantabria.USF_DISTR_NORM_ESTAND_INV
(as_probabilidad in number) return number Is

/*
Esta funcion retorna un aproximado de la Distribucion normal
estandar inversa.  Por ejemplo, dando P [as_probabilidad], retorna
un aproximado de X [Result] satisfaciendo asi la relacion
P = p * r [redondeo] ( Z <= X ), donde Z es un numero aleatorio de la
distribucion normal estandar.  Este algoritmo usa un minimo y maximo
de aproximation por funciones racionales y el resultado tienen un error
relativo cuyo valor absoluto es menor que 1.15e-9
J. Pomalaza
*/

Result       Number;
ln_prob_baja Number;
--ln_prob_alta Number;
ln_var       Number; -- Varianza
ln_r         Number; -- Media
--ln_e         Constant Number := 2.71828182845904;

--Variables de aproximaciones racionales

-- Primer Bloque
ln_a_0  Constant Number := -3.969683028665376e+01;
ln_a_1  Constant Number :=  2.209460984245205e+02;
ln_a_2  Constant Number := -2.759285104469687e+02;
ln_a_3  Constant Number :=  1.383577518672690e+02;
ln_a_4  Constant Number := -3.066479806614716e+01;
ln_a_5  Constant Number :=  2.506628277459239e+00;

-- Segundo Bloque
ln_b_0  Constant Number := -5.447609879822406e+01;
ln_b_1  Constant Number :=  1.615858368580409e+02;
ln_b_2  Constant Number := -1.556989798598866e+02;
ln_b_3  Constant Number :=  6.680131188771972e+01;
ln_b_4  Constant Number := -1.328068155288572e+01;

-- Tercer Bloque
ln_c_0  Constant Number := -7.784894002430293e-03;
ln_c_1  Constant Number := -3.223964580411365e-01;
ln_c_2  Constant Number := -2.400758277161838e+00;
ln_c_3  Constant Number := -2.549732539343734e+00;
ln_c_4  Constant Number :=  4.374664141464968e+00;
ln_c_5  Constant Number :=  2.938163982698783e+00;

-- Tercer Bloque
ln_d_0  Constant Number :=  7.784695709041462e-03;
ln_d_1  Constant Number :=  3.224671290700398e-01;
ln_d_2  Constant Number :=  2.445134137142996e+00;
ln_d_3  Constant Number :=  3.754408661907416e+00;

Begin

-- Definiendo parametros
ln_prob_baja := 0.00902;
--ln_prob_alta := 1 - ln_prob_baja;

-- Aproximacion para la region baja
If (as_probabilidad < ln_prob_baja) Then

   ln_var := sqrt(-2 * log(as_probabilidad,10));
   Result := (((((ln_c_0 * ln_var + ln_c_1 ) * ln_var + ln_c_2) * ln_var + ln_c_3) *
             ln_var + ln_c_4) * ln_var + ln_c_5) /
             ((((ln_d_0 * ln_var + ln_d_1) * ln_var + ln_d_2) * ln_var + ln_d_3) * ln_var + 1);

   Return(Round(Result,4));

End If;
-- Aproximacion para la region alta
/*If ( ln_prob_alta < as_probabilidad ) Then

   ln_var := sqrt(-2 * log( (1-as_probabilidad) ,10));
   Result := -(((((ln_c_0 * ln_var + ln_c_1 ) * ln_var + ln_c_2) * ln_var + ln_c_3) *
              ln_var + ln_c_4) * ln_var + ln_c_5) /
              ((((ln_d_0 * ln_var + ln_d_1) * ln_var + ln_d_2) * ln_var + ln_d_3) * ln_var + 1);

   Return(Round(Result,4));

End If;*/
-- Aproximacion para la region central
ln_var := as_probabilidad - 0.5;
ln_r   := ln_var * ln_var;

Result := (((((ln_a_0 * ln_r + ln_a_1) * ln_r + ln_a_2) * ln_r + ln_a_3) * ln_r + ln_a_4) * ln_r + ln_a_5) * ln_var
          / (((((ln_b_0 * ln_r + ln_b_1) * ln_r + ln_b_2)* ln_r + ln_b_3)* ln_r + ln_b_4) * ln_r + 1);

return(Result);

end USF_DISTR_NORM_ESTAND_INV;
/

prompt
prompt Creating function USF_DIV_ZERO
prompt ==============================
prompt
create or replace function cantabria.usf_div_zero(
   an_dividendo in number,
   an_divisor   in number ) return number is

  ln_Result number;
  -- dividendo / divisor
begin

  if an_divisor is null then
     ln_result := 0 ;
  else

     if an_divisor = 0 Then
        ln_result := 0 ;
     else
        ln_result := an_dividendo / an_divisor ;
     end if;

  end if ;

  return( ln_Result );
end usf_div_zero;
/

prompt
prompt Creating function USF_ENCUENTRA_TASA_CAMBIO
prompt ===========================================
prompt
create or replace function cantabria.usf_encuentra_tasa_cambio(
  ad_fecha DATE
)
return number is

ln_Result number;
ln_count number ;

begin

 select NVL(count(*),0) 
   into ln_count 
   from calendario 
  where trunc(fecha) = trunc(ad_fecha);

 if ln_count = 0 then
    -- Si no lo encuentro entonces busco el ultimo que esta en logparam
    select count(*)
      into ln_count
      from logparam
     where reckey = '1';
    
    if ln_count = 0 then
       raise_application_error(-20000,'nO HA ESPECIFICADO PARAMETROS EN LOGPARAM, POR FAVOR VERIFIQUE');  
    end if;
    
    select l.ult_tipo_cam
      into ln_Result
      from logparam l
     where reckey = '1';
    
    if ln_Result = 0 then
       raise_application_error(-20000,'Aviso: No se ha encontrado Tasa de Cambio para la fecha: '||
                                    to_char(ad_fecha, 'dd/mm/yyyy'));
    end if; 
    
 else
    select NVL(c.vta_dol_prom,0)
      into ln_Result
      from calendario  c
     where TRUNC(fecha) = TRUNC(ad_fecha) ;
 end if ;


  return(ln_Result);

end usf_encuentra_tasa_cambio;
/

