prompt Creating function USF_EXP_PRECIO_REF
prompt ====================================
prompt
create or replace function cantabria.usf_exp_precio_ref(
       adi_fecha     in date,
       asi_incoterm  in incoterm.incoterm%TYPE,
       asi_cod_art   in articulo.cod_art%TYPE,
       asi_moneda    in moneda.cod_moneda%TYPE
) return number is
  ln_Result number;
  ln_count  number;
  ln_year   number;
  ln_mes    number;
  ln_precio precio_referencial_mercado.precio_ref%TYPE;
  ls_moneda precio_referencial_mercado.precio_ref_mon%TYPE;

begin
  ln_year := to_number(to_char(adi_fecha, 'yyyy'));
  ln_mes  := to_number(to_char(adi_fecha, 'mm'));

  select count(*)
    into ln_count
    from precio_referencial_mercado
   where ano      = ln_year
     and mes      = ln_mes
     and cod_art  = asi_cod_Art
     and incoterm = asi_incoterm;

  if ln_count = 0 then
     ln_result := 0;
  else
     select precio_ref, precio_ref_mon
       into ln_precio, ls_moneda
       from precio_referencial_mercado
       where ano      = ln_year
         and mes      = ln_mes
         and cod_art  = asi_cod_Art
         and incoterm = asi_incoterm;

     ln_result := usf_fl_conv_mon(ln_precio, ls_moneda, asi_moneda, adi_fecha);
  end if;
  return(ln_Result);
end usf_exp_precio_ref;
/

