prompt Creating function USF_FECHA_INICIO_COMISION
prompt ===========================================
prompt
create or replace function cantabria.USF_FECHA_INICIO_COMISION return date Is

ld_fecha Date;
Result   Date;
ls_fecha Char(10);

Begin

  Select Max(vc.fecha_ini)
    Into ld_fecha
    From vendedor_cuota vc;

  If ld_fecha Is Null Then
     ls_fecha := to_char('01/')||to_char(Sysdate,'MM')||'/'||to_char(Sysdate,'yyyy');
     Result := to_date(ls_fecha,'dd/mm/yyyy');
  Else
     Select add_months(ld_fecha,1)
       Into Result
       From dual;
  End If;

  return(Result);
end USF_FECHA_INICIO_COMISION;
/

prompt
prompt Creating function USF_FECHA_X_ANO_MES
prompt =====================================
prompt
create or replace function cantabria.usf_fecha_x_ano_mes
(an_ano  in number,
 an_mes  in number,
 an_flag in char) return date is

Result date;

begin

--========================================
--FLag de retorno D = Del dia ; A = al dia
--========================================

if an_flag = 'D' then

    SELECT MIN(cp.del_dia)
      INTO Result
      FROM calendario_produccion cp
     WHERE cp.ano = an_ano
       AND cp.mes = an_mes;

elsif an_flag = 'A' then

    SELECT MIN(cp.al_dia)
      INTO Result
      FROM calendario_produccion cp
     WHERE cp.ano = an_ano
       AND cp.mes = an_mes;

end if;

return(Result);

end usf_fecha_x_ano_mes;
/

