create or replace function cantabria.usf_fin_cencos_cp_det
(ac_cod_relacion cntas_pagar.cod_relacion%type ,
 ac_tipo_doc     cntas_pagar.tipo_doc%type     ,
 ac_nro_doc      cntas_pagar.nro_doc%type       )

 return varchar2 is
  Result cntas_pagar_det.cencos%type ;

begin

select cencos
  into result
  from cntas_pagar_det
 where (cod_relacion = ac_cod_relacion ) and
       (tipo_doc     = ac_tipo_doc     ) and
       (nro_doc      = ac_nro_doc      ) and
       (item         in (select Min(item)
                           from cntas_pagar_det
                          where (cod_relacion = ac_cod_relacion ) AND
                                (tipo_doc     = ac_tipo_doc     ) AND
                                (nro_doc      = ac_nro_doc      ))) ;

  return(Result);
end usf_fin_cencos_cp_det;
