prompt
prompt Creating function USF_FIN_CENCOS_VENTA_GASTO
prompt ============================================
prompt
create or replace function cantabria.USF_FIN_CENCOS_VENTA_GASTO
(ac_nro_ov in orden_venta.nro_ov%type)

return centros_costo.cencos%type is
  Result centros_costo.cencos%type;

lc_doc_ov doc_tipo.tipo_doc%type ;

Cursor c_cencos_gasto is
select ov.cod_origen,amp.cod_art,amp.cencos_gasto
  from orden_venta ov,articulo_mov_proy amp
 where (amp.tipo_doc   = lc_doc_ov     ) and
        (amp.nro_doc    = ac_nro_ov     ) and
        (ov.nro_ov      = amp.nro_doc   )
group by ov.cod_origen,amp.cod_art,amp.cencos_gasto  ;



ln_count number ;


Begin

select l.doc_ov into lc_doc_ov  from logparam l where l.reckey = '1' ;

For rc_cencos in c_cencos_gasto Loop
    Result := rc_cencos.cencos_gasto ;

    if result is null then
       select count(*) into ln_count from articulo_ccosto_gasto acg
        where (acg.cod_origen  = rc_cencos.cod_origen ) and
              (acg.cod_art     = rc_cencos.cod_art    ) and
              (acg.flag_estado = '1'                  ) ;

       if ln_count > 0 then
          select acg.cencos into result from articulo_ccosto_gasto acg
           where (acg.cod_origen  = rc_cencos.cod_origen ) and
                 (acg.cod_art     = rc_cencos.cod_art    ) and
                 (acg.flag_estado = '1'                  ) ;
       end if  ;
    end if ;
End Loop ;


  return(Result);

end USF_FIN_CENCOS_VENTA_GASTO ;
/

prompt
prompt Creating function USF_FIN_CENTRO_BENEFICIO_ART
prompt ==============================================
prompt
create or replace function cantabria.USF_FIN_CENTRO_BENEFICIO_ART
(ac_cod_origen origen.cod_origen%type         ,
 an_nro_mov    articulo_mov_proy.nro_mov%type  )

return varchar2 is
  Result varchar2 (12);

lc_doc_ot logparam.doc_ot%type ;

begin

select l.doc_ot into lc_doc_ot from logparam l where l.RECKEY = '1' ;

IF ac_cod_origen is not null THEN
   select ot.centro_benef into result
     from articulo_mov_proy amp,orden_trabajo ot
    where (amp.tipo_doc   = lc_doc_ot     ) and
          (amp.nro_doc    = ot.nro_orden  ) and
          (amp.cod_origen = ac_cod_origen ) and
          (amp.nro_mov    = an_nro_mov    )
   group by ot.centro_benef ;
END IF   ;

  return(Result);
end USF_FIN_CENTRO_BENEFICIO_ART;
/

