prompt
create or replace function cantabria.USF_FIN_CENTRO_BENEFICIO_SERV
(ac_oper_sec origen.cod_origen%type           )

return varchar2 is
  Result varchar2 (12);

lc_doc_ot logparam.doc_ot%type ;

begin

select l.doc_ot into lc_doc_ot from logparam l where l.doc_ot = '1' ;

IF ac_oper_sec is not null THEN
   select ot.centro_benef into result
     from operaciones ope,orden_trabajo ot
    where (ope.nro_orden  = ot.nro_orden ) and
          (ope.tipo_orden = lc_doc_ot    ) and
          (ope.oper_sec   = ac_oper_sec  )
  group by ot.centro_benef ;
END IF   ;

  return(Result);
end USF_FIN_CENTRO_BENEFICIO_SERV ;
/

prompt
prompt Creating function USF_FIN_CHEQUE_REFERENCIA
prompt ===========================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.usf_fin_cheque_referencia(
       as_cod_rel      in proveedor.proveedor%type,
       as_tipo_doc     in doc_tipo.tipo_doc%type,
       as_nro_doc      in cntas_pagar.nro_doc%type
) RETURN varchar2 IS

   ls_result   varchar2(200) ;

   CURSOR c_cheque IS
   select to_char(cb.fecha_emision,'dd/mm/yyyy')||', '||to_char(ch.nro_cheque)||' / ' as cheque
     from caja_bancos cb, caja_bancos_det cbd, cntas_pagar cp, cheque_emitir ch
    where (cb.origen = cbd.origen and cb.nro_registro = cbd.nro_registro and cb.flag_estado<>'0') and
          (cb.reg_cheque = ch.nro_registro ) and
          (cbd.cod_relacion=cp.cod_relacion and cbd.tipo_doc=cp.tipo_doc and cbd.nro_doc=cp.nro_doc) and
          (cbd.cod_relacion = as_cod_rel and cbd.tipo_doc=as_tipo_doc and cbd.nro_doc = as_nro_doc) ;

BEGIN

ls_result := ' ' ;

FOR c_ch IN c_cheque() LOOP
    ls_result := ls_result || c_ch.cheque ;
END LOOP ;

RETURN(substr(ls_result,1,60));

END usf_fin_cheque_referencia;
/

prompt
prompt Creating function USF_FIN_CIERRA_CONTROL_DOC
prompt ============================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.usf_fin_cierra_control_doc(
       as_cod_rel      in proveedor.proveedor%type,
       as_tipo_doc     in doc_tipo.tipo_doc%type,
       as_nro_doc      in cntas_pagar.nro_doc%type
) RETURN number IS

   Result   Number(1);
   ln_count Number(1) ;

BEGIN

Result := 0 ;

SELECT count(*)
  INTO ln_count
  FROM cd_doc_recibido c
 WHERE c.cod_relacion = as_cod_rel
   AND c.tipo_doc = as_tipo_doc
   AND SUBSTR(c.nro_doc,1,10) = as_nro_doc  ;

IF ln_count>0 THEN
   UPDATE cd_doc_recibido c
      SET c.flag_estado = '2',
          c.flag_provisionado = 'C',
          c.flag_transfer = '1'
    WHERE c.cod_relacion = as_cod_rel
      AND c.tipo_doc = as_tipo_doc
      AND SUBSTR(c.nro_doc,1,10) = as_nro_doc ;
    Result := 1 ;
END IF ;

RETURN(Result);

END usf_fin_cierra_control_doc;
/

