prompt
prompt Creating function USF_FIN_DOC_DESC_LIQ
prompt ======================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.usf_fin_doc_desc_liq(
       as_cod_rel_cp      in proveedor.proveedor%type,
       as_tipo_doc_cp     in doc_tipo.tipo_doc%type,
       as_nro_doc_cp      in cntas_pagar.nro_doc%type,
       as_tipo_doc_cc     in doc_tipo.tipo_doc%type,
       as_nro_doc_cc      in cntas_pagar.nro_doc%type,
       an_factor_signo    in liquidacion_det.factor_signo%type,
       as_caso            in char
) RETURN varchar2 IS
   Result  varchar2(4000);
   ls_paso varchar2(180);

  CURSOR C_CXC IS
      SELECT descripcion
       FROM cntas_cobrar_det cc
       WHERE (as_tipo_doc_cc = cc.tipo_doc AND
           as_nro_doc_cc = cc.nro_doc) ;

   CURSOR C_CXP IS
      SELECT cp.descripcion
        FROM cntas_pagar cp
        WHERE   as_cod_rel_cp  = cp.cod_relacion
          AND as_tipo_doc_cp = cp.tipo_doc
          AND as_nro_doc_cp  = cp.nro_doc;
BEGIN
-- Esta funcion retorna el numero de documento y la descripcion de cuentas por pagar o
-- cuentas por cobrar de acuerdo al factor de signo

    IF as_caso = '1' THEN -- devuelve el numero de documento
       IF as_tipo_doc_cc is Null Or Trim(as_tipo_doc_cc) = ''  AND as_nro_doc_cc is Null Or Trim(as_nro_doc_cc) = '' THEN
          Result := as_tipo_doc_cp || ' ' || as_nro_doc_cp;
       ELSE
          Result := as_tipo_doc_cc || ' ' || as_nro_doc_cc;
       END IF;

    ELSE
        --devuelve la descripbion de cuentas por pagar
           FOR c_reg IN c_cxp LOOP
               Result := c_reg.descripcion;
           END LOOP;
           -- concatena la descripcion del detalle de cuentas por pagar
           IF as_tipo_doc_cc is Null Or Trim(as_tipo_doc_cc) = '' AND as_nro_doc_cc is Null Or Trim(as_nro_doc_cc) = '' THEN
                 FOR c_reg IN c_cxp LOOP
                    Result := c_reg.descripcion;
                 END LOOP;

            ELSE
                FOR c_reg IN c_cxc LOOP
                    Result := Trim(Result)|| ' ' || Trim(c_reg.descripcion);
                END LOOP;
            END IF;
     END IF;

   RETURN(Trim(Result));

END usf_fin_doc_desc_liq;
/

prompt
prompt Creating function USF_FIN_GENERA_NUM_FACT
prompt =========================================
prompt
create or replace function cantabria.USF_FIN_GENERA_NUM_FACT
(as_doc_tipo In doc_tipo.tipo_doc%Type,
 an_serie    In num_doc_tipo.nro_serie%Type) return cntas_cobrar.nro_doc%Type Is

 Result cntas_cobrar.nro_doc%Type;

 ln_contador Number;
 ln_numero   Number(9);
 ls_serie    Char(3);
 ls_numero   Char(6);

Begin

  Select nvl(Count(*),0)
    Into ln_contador
    From num_doc_tipo
   Where tipo_doc  = as_doc_tipo
	And nro_serie = an_serie;

  If ln_contador = 0 Then
     raise_application_error(-20000,'Error, Defina la numeracion de Numero de Serie y Tipo de Documento');
     Rollback;
  End If;

  Select nvl(ultimo_numero,0)
    Into ln_numero
    From num_doc_tipo
   Where tipo_doc  = as_doc_tipo
	And nro_serie = an_serie;

  ls_serie  := lpad(to_char(an_serie) ,3,'0');
  ls_numero := lpad(to_char(ln_numero),6,'0');
  Result   := ls_serie||'-'||ls_numero;

  Update num_doc_tipo
	Set ultimo_numero = ultimo_numero + 1
   Where tipo_doc  = as_doc_tipo
	And nro_serie = an_serie;

  return(Result);

end USF_FIN_GENERA_NUM_FACT;
/

prompt
prompt Creating function USF_FIN_IMPORT_IMP
prompt ====================================
prompt
create or replace function cantabria.USF_FIN_IMPORT_IMP
(lc_cod_relacion  in solicitud_giro_liq_det.proveedor%type,
 lc_tipo_doc      in solicitud_giro_liq_det.tipo_doc%type ,
 lc_nro_doc       in solicitud_giro_liq_det.nro_doc%type   )
 return number is
  ln_Result Number(13,2);

  ln_impor_pos Number(13,2);
  ln_impor_neg Number(13,2) ;

Cursor c_import_imp is
SELECT it.signo  ,
       Sum(cp.importe)  as importe
  FROM cp_doc_det_imp cp,
       impuestos_tipo it
  WHERE  (cp.tipo_impuesto = it.tipo_impuesto ) AND
        ((cp.cod_relacion  = lc_cod_relacion  ) AND
         (cp.tipo_doc      = lc_tipo_doc      ) AND
         (cp.nro_doc       = lc_nro_doc       ))
GROUP BY it.signo   ;

begin


  ln_impor_pos := 0.00 ;
  ln_impor_neg := 0.00 ;

  For rc_import in c_import_imp Loop
      IF rc_import.signo = '+' THEN
         ln_impor_pos := ln_impor_pos + Nvl(rc_import.importe,0.00) ;
      ELSIF rc_import.signo = '-' THEN
         ln_impor_neg := ln_impor_neg + Nvl(rc_import.importe,0.00) ;
      END IF ;
  End Loop ;

  ln_result := Round(Nvl(ln_impor_pos,0) - Nvl(ln_impor_neg,0),2) ;

  Return(ln_result);

end USF_FIN_IMPORT_IMP;
/

prompt
prompt Creating function USF_FIN_IMPORT_IMP_CC
prompt =======================================
prompt
create or replace function cantabria.USF_FIN_IMPORT_IMP_CC
(lc_tipo_doc      in cntas_cobrar.tipo_doc%type ,
 lc_nro_doc       in cntas_cobrar.nro_doc%type   )
 return number is
  ln_Result Number(13,2);


Cursor c_import_imp is
SELECT Sum(cc.importe)  as importe
  FROM cc_doc_det_imp cc,
       impuestos_tipo it
 WHERE  (cc.tipo_impuesto = it.tipo_impuesto ) AND
       ((cc.tipo_doc      = lc_tipo_doc      ) AND
        (cc.nro_doc       = lc_nro_doc       ))
GROUP BY cc.tipo_doc     ,
         cc.nro_doc ;

begin

  ln_result := 0 ;

  For rc_import in c_import_imp Loop
      ln_result := ln_result + Nvl(rc_import.importe,0.00) ;
  End Loop ;


  Return(ln_result);

end USF_FIN_IMPORT_IMP_CC ;
/

prompt
prompt Creating function USF_FIN_MON_ASIENTO_EDIRECTOS
prompt ===============================================
prompt
create or replace function cantabria.USF_FIN_MON_ASIENTO_EDIRECTOS
(ac_cod_relacion codigo_relacion.cod_relacion%type ,
 ac_tipo_doc     doc_tipo.tipo_doc%type            ,
 ac_nro_doc      doc_pendientes_cta_cte.nro_doc%type)

return varchar2 is
  Result moneda.cod_moneda%type ;


lc_cegreso doc_tipo.tipo_doc%type ;

begin

/*Tipo de Documento de Comprobante de Egreso*/
SELECT comprobante_egr INTO lc_cegreso FROM finparam  WHERE reckey = '1' ;
/********************************************************/

 IF ac_tipo_doc  = lc_cegreso   THEN --comprobante de egreso

    SELECT cod_moneda
      INTO result
      FROM cntas_pagar
     WHERE ((cod_relacion = ac_cod_relacion) AND
            (tipo_doc     = ac_tipo_doc    ) AND
            (nro_doc      = ac_nro_doc     )) ;

 ELSE --asiento diario
    SELECT cod_moneda
      INTO result
      FROM cntbl_asiento c ,cntbl_asiento_det d
     WHERE ((c.origen       = d.origen       )  AND
            (c.ano          = d.ano          )  AND
            (c.mes          = d.mes          )  AND
            (c.nro_libro    = d.nro_libro    )  AND
            (c.nro_asiento  = d.nro_asiento  )) AND
           ((c.flag_tabla   = 'V'            )) AND
           ((d.flag_debhab  = 'H'            )) AND
           ((d.cod_relacion = ac_cod_relacion)  AND
            (d.tipo_docref1 = ac_tipo_doc    )  AND
            (Substr(d.nro_docref1,1,10) = ac_nro_doc )) ;
  END IF;

  return(Result);
end USF_FIN_MON_ASIENTO_EDIRECTOS;
/

prompt
prompt Creating function USF_FIN_MONEDA_FACTURA
prompt ========================================
prompt
create or replace function cantabria.USF_FIN_MONEDA_FACTURA
(as_origen In origen.cod_origen%type,
 as_guia   In guia.nro_guia%type) return cntas_cobrar.cod_moneda%type Is

  Result cntas_cobrar.cod_moneda%type;
  ls_cod_moneda_sol moneda.cod_moneda%Type;
  ls_cod_moneda_dol moneda.cod_moneda%Type;
  ln_verifica       Number;

Begin

Select l.cod_soles, l.cod_dolares
  Into ls_cod_moneda_sol, ls_cod_moneda_dol
  From logparam l
 Where l.reckey = '1';

Select Count(*)
  Into ln_verifica
  From guia_vale gv, vale_mov vm, articulo_mov am,
       articulo_venta av
 Where gv.Origen_Vale = vm.cod_origen
   And gv.nro_vale    = vm.nro_vale
   And vm.cod_origen  = am.cod_origen
   And vm.nro_vale    = am.nro_vale
   And am.cod_art     = av.cod_art
   And gv.Origen_Guia = as_origen
   And gv.nro_guia    = as_guia
   And av.cod_moneda  = ls_cod_moneda_sol;

  If ln_verifica > 0 Then
     Result := ls_cod_moneda_sol;
  Else
     Result := ls_cod_moneda_dol;
  End If;

  return(Result);

End USF_FIN_MONEDA_FACTURA;
/

