prompt
prompt Creating function USF_FIN_NUM_DEUDA
prompt ===================================
prompt
create or replace function cantabria.USF_FIN_NUM_DEUDA
(ac_cod_origen origen.cod_origen%type)

 return varchar2 is
  lc_ult_nro_deuda deuda_financiera.nro_registro%type ;

ln_ult_nro num_detraccion.ult_nro%type ;

begin
  --numerador de detraccion
  select no.ult_nro
    into ln_ult_nro
    from num_deuda_financiera no
   where (no.origen = ac_cod_origen)
   for update nowait;

  --se concatena con origen
  lc_ult_nro_deuda := rtrim(ltrim(ac_cod_origen))||LPAD(rtrim(ltrim(to_char(ln_ult_nro))),8,'0') ;

  --actualiza informacion e numeradores
  update num_deuda_financiera no
     set no.ult_nro = Nvl(no.ult_nro,0) + 1
   where (no.origen = ac_cod_origen ) ;

  return(lc_ult_nro_deuda);

end USF_FIN_NUM_DEUDA ;
/

