prompt
prompt Creating function USF_FIN_REFERENCIA_GASTOS_OV
prompt ==============================================
prompt
create or replace function cantabria.usf_fin_referencia_gastos_ov
(ac_cod_rel  in cntas_pagar.cod_relacion%type ,
 ac_tipo_doc in cntas_pagar.tipo_doc%type     ,
 ac_nro_doc  in cntas_pagar.nro_doc%Type      )
 return  varchar2 is
  Result varchar2 (10) ;

lc_tipo_doc doc_tipo.tipo_doc%type ;

Cursor c_referencias is
select dr.nro_ref
  from doc_referencias dr
 where (dr.cod_relacion = ac_cod_rel  ) and
       (dr.tipo_doc     = ac_tipo_doc ) and
       (dr.nro_doc      = ac_nro_doc  ) and
       (dr.tipo_mov     = 'R'         ) and
       (dr.tipo_ref     = lc_tipo_doc )  ;

begin

select l.doc_ov into lc_tipo_doc from logparam l where l.reckey = '1' ;

For rc_ov in c_referencias Loop
    result := rc_ov.nro_ref ;
End Loop ;

  return(Result);
end usf_fin_referencia_gastos_ov;
/

prompt
prompt Creating function USF_FIN_REFER_FACTURAS
prompt ========================================
prompt
create or replace function cantabria.USF_FIN_REFER_FACTURAS
(ac_cod_relacion in cntas_cobrar.cod_relacion%type,
 ac_tipo_doc     in cntas_cobrar.tipo_doc%type,
 ac_nro_doc      in cntas_cobrar.nro_doc%type )

return varchar2 is


CURSOR c_referencias is
SELECT dr.tipo_ref, dr.nro_ref
  FROM cntas_cobrar cc, doc_referencias dr
 WHERE cc.tipo_doc      = dr.tipo_doc and
       cc.nro_doc       = dr.nro_doc and
       cc.cod_relacion  = dr.cod_relacion and
       cc.cod_relacion  = ac_cod_relacion and
       cc.tipo_doc      = ac_tipo_doc and
       cc.nro_doc       = ac_nro_doc  ;

Result        varchar2(2500) ;
lb_ok         Boolean ;
ls_glosa      varchar2(100) ;

BEGIN

  lb_ok := FALSE ;
  FOR rc_ref in c_referencias LOOP
      IF lb_ok = FALSE THEN
         Result := rc_ref.tipo_ref ||' ' ;
         lb_ok := TRUE ;
      END IF ;
      result := result|| '-'||rtrim(ltrim(rc_ref.nro_ref)) || ',' ;

  END LOOP ;

  ls_glosa :=  Substr(result,1,100);

  RETURN(ls_glosa);

END usf_fin_refer_facturas;
/

prompt
prompt Creating function USF_FIN_REFER_FACTURAS_OC
prompt ===========================================
prompt
create or replace function cantabria.USF_FIN_REFER_FACTURAS_oc
(ac_origen_oc in orden_compra.cod_origen%type,
 ac_nro_doc   in orden_compra.nro_oc%type )

return varchar2 is


CURSOR c_referencias is
SELECT dr.tipo_doc||'-'||dr.cod_relacion||'-'||dr.nro_doc as referencia
  FROM doc_referencias dr
 WHERE dr.tipo_mov   = 'P'          and
       dr.tipo_ref   = (select doc_oc from logparam where reckey = '1') and
       dr.nro_ref    = ac_nro_doc   and
       dr.origen_ref = ac_origen_oc  ;

Result        varchar2(2500) ;

BEGIN

  FOR rc_ref in c_referencias LOOP
      result := nvl(result,'') ||' '||rc_ref.referencia ;

  END LOOP ;



  RETURN(result);

END usf_fin_refer_facturas_oc;
/

