prompt
prompt Creating function USF_FIN_TASA_CAMBIO
prompt =====================================
prompt
create or replace function cantabria.usf_fin_tasa_cambio
(ad_fecha calendario.fecha%type) return number is
  Result number;
  
  ln_count number ;
begin


 select count(*) into ln_count from calendario where trunc(fecha) = trunc(ad_fecha) ;
  
  
  if ln_count = 0 then
     select l.ult_tipo_cam
       into Result
       from logparam l
      where l.reckey = '1';
  else
      select c.vta_dol_prom
      into RESULT
      from calendario  c
      where TRUNC(fecha) = TRUNC(ad_fecha) ;
  end if ;
  
  if Result = 0 then
     RAISE_APPLICATION_ERROR(-20000, 'No se ha definido tipo de cambio para la fecha: ' || to_char(ad_fecha, 'dd/mm/yyyy'));
  end if;
  

  return(Result);
end usf_FIN_tasa_cambio;
/

prompt
prompt Creating function USF_FIN_WARRANT_LIB_DET
prompt =========================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_FIN_WARRANT_LIB_DET(
          AS_NRO_WARRANT IN WARRANT_DET.NRO_WARRANT%TYPE,
          AN_ITEM_PROD   IN WARRANT_DET.ITEM_PROD%TYPE,
          AS_OPCION IN CHAR)
  RETURN NUMBER IS
  LN_RESULT   NUMBER;
  LN_CANT_DET NUMBER;
  LN_CANT_LIB NUMBER;
BEGIN
  -- funcion para devolver la cantidad que falta por liberar del warrant

    SELECT  NVL(WD.CANTIDAD,0)
      INTO  LN_CANT_DET
    FROM    WARRANT_DET   WD
    WHERE   WD.NRO_WARRANT = AS_NRO_WARRANT
      AND   WD.ITEM_PROD   = AN_ITEM_PROD;

    SELECT  SUM(NVL(WLD.CANTIDAD_LIBERADO,0))
      INTO  LN_CANT_LIB
    FROM    WARRANT_LIBERADO_DET  WLD
    WHERE   WLD.NRO_WARRANT = AS_NRO_WARRANT
      AND   WLD.ITEM_PROD   = AN_ITEM_PROD;

    CASE AS_OPCION
      WHEN '1' THEN
          LN_RESULT := NVL(LN_CANT_DET,0) - NVL(LN_CANT_LIB,0);
      WHEN '2' THEN
          LN_RESULT := LN_CANT_LIB;
      ELSE
          LN_RESULT := 0.00;
     END CASE;

  RETURN(LN_RESULT);
END USF_FIN_WARRANT_LIB_DET;
/

prompt
prompt Creating function USF_FIRST_DAY
prompt ===============================
prompt
create or replace function cantabria.usf_first_day(
 ad_fecha in date ) return date is

ls_semana varchar2(2);
ld_fecha date;

BEGIN
     if ad_fecha is null then
        Return ld_fecha;
     end if;
    ls_semana := To_Char(ad_fecha,'iw');
    ld_fecha := ad_fecha;

    While (True) loop
          If ls_semana <> To_Char(ld_fecha - 1,'iw') then
             Exit;
          end if;
          ld_fecha := ld_fecha - 1;
    End loop;
    Return ld_fecha;

END usf_first_day ;
/

prompt
prompt Creating function USF_FL_BONIF_ADM_ANUAL
prompt ========================================
prompt
create or replace function cantabria.USF_FL_BONIF_ADM_ANUAL(
       adi_fecha  date,
       asi_nave   tg_naves.nave%TYPE,
       asi_moneda moneda.cod_moneda%TYPE
) return number is

  ln_Result number;
  ln_temp   number;

  cursor c_datos is
      select to_char(b.hora_inicio_descarga, 'mm') as mes,
           sum( b.cantidad_real - b.cantidad_castigada) as cantidad
      from fl_parte_de_pesca a,
           fl_venta          b
     where a.parte_pesca = b.parte_pesca
       and to_char(b.hora_inicio_descarga, 'yyyy') = to_char(adi_fecha, 'yyyy')
       and trunc(b.hora_inicio_descarga) <= trunc(adi_fecha)
    group by  to_char(b.hora_inicio_descarga, 'mm');

  cursor c_datos_x_nave is
      select to_char(b.hora_inicio_descarga, 'mm') as mes,
           sum( b.cantidad_real - b.cantidad_castigada) as cantidad
      from fl_parte_de_pesca a,
           fl_venta          b
     where a.parte_pesca = b.parte_pesca
       and to_char(b.hora_inicio_descarga, 'yyyy') = to_char(adi_fecha, 'yyyy')
       and trunc(b.hora_inicio_descarga) <= trunc(adi_fecha)
       and a.nave_real = asi_nave
    group by  to_char(b.hora_inicio_descarga, 'mm');

begin

  ln_Result := 0;

  for lc_reg in c_datos loop
      for lc_reg2 in c_datos_x_nave loop
          select NVL(sum( usf_fl_conv_mon(
                  CASE WHEN lc_reg.cantidad > t.pesca_considerar THEN
                       t.ratio_max * lc_reg2.cantidad
                  ELSE
                       t.ratio_min * lc_reg2.cantidad
                  END , t.cod_moneda, asi_moneda, adi_fecha)), 0)
            into ln_temp
            from fl_incentivo_pers_adm t;

            ln_Result := ln_Result + ln_temp;
      end loop;
  end loop;

  return(ln_Result);
end USF_FL_BONIF_ADM_ANUAL;
/

