prompt Creating function USF_FL_CONV_MON_EDG_CHK
prompt =========================================
prompt
create or replace function cantabria.usf_fl_conv_mon_edg_chk
 return number is
  ls_cod_soles     logparam.cod_soles%TYPE;
  ls_cod_dolares   logparam.cod_dolares%TYPE;
begin

  Select l.cod_soles, l.cod_dolares
     into ls_cod_soles, ls_cod_dolares
  from logparam l
  where reckey = '1';

  if ls_cod_soles = '' or ls_cod_soles is null then
