     RAISE_APPLICATION_ERROR(-20000, 'Debe indicar tipo de moneda Dolares en Logparam');
     Return 0;
  end if;

end usf_fl_conv_mon_edg_chk;
/

prompt
prompt Creating function USF_FL_COSTO_VAR_X_NAVE
prompt =========================================
prompt
create or replace function cantabria.USF_FL_COSTO_VAR_X_NAVE(
       asi_nave   IN tg_naves.nave%TYPE,
       adi_fecha1 IN DATE,
       adi_fecha2 IN DATE
) return number is

  --===============
  -- PARAMETROS
  --===============
  ls_soles          logparam.cod_soles%TYPE;
  ls_dolares        logparam.cod_dolares%TYPE;
  ls_doc_ot         logparam.doc_ot%TYPE;
  ls_cencos_adm     centros_costo.cencos%TYPE;    -- Centro de Costo Administracion Flota
  ls_petroleo       fl_paramcosto.petroleo_d2%TYPE;
  ls_viveres        fl_paramcosto.art_viveres%TYPE;
  ls_seguros        fl_paramcosto.seguros%TYPE;
  ls_leasing        fl_paramcosto.leasing%TYPE;
  ls_overhall       fl_paramcosto.ot_tipo_overhall%TYPE;
  ls_redes          fl_paramcosto.ot_tipo_redes%TYPE;
  ls_varadero       fl_paramcosto.ot_tipo_varadero%TYPE;
  ln_tasa_dp        fl_param.tasa_derecho_pesca%TYPE;
  ln_tasa_pago      fl_param.tasa_sicosat%TYPE;

  --===============
  -- OTROS
  --===============
  ln_count         NUMBER;
  ln_pesca         NUMBER;
  ln_mes1          NUMBER;
  ln_mes2          NUMBER;
  ln_year          NUMBER;
  ln_temp          NUMBER;
  ld_fecha1        DATE;
  ld_fecha2        DATE;
  ln_pescat        NUMBER;     -- Pesca Temporal

  cursor c_datos is
    select to_char(b.hora_inicio_descarga, 'mm') as mes,
         sum( b.cantidad_real - b.cantidad_castigada) as cantidad
    from fl_parte_de_pesca a,
         fl_venta          b
   where a.parte_pesca = b.parte_pesca
     and to_number(to_char(b.hora_inicio_descarga, 'yyyy')) = ln_year
     AND to_number(to_char(b.hora_inicio_descarga, 'mm')) BETWEEN ln_mes1 AND ln_mes2
  group by  to_char(b.hora_inicio_descarga, 'mm');


  --==========================
  -- Costos Variables
  --==========================
  -- Tripulantes
  ln_ctrip		  number;			-- Costo de la tripulacion

  -- Bonificacion Tripulantes
  ln_bontrip    number;     -- Bonificacion Tripulante

  -- Bonificacion Administrativos
  ln_bonadm        number;     -- Bonificacion Administrativo diario

  -- Costo del Petroleo
  ln_cpetd2        number;     -- Costo Diario del Petroleo Diesel 2

  -- Derecho de Pesca
  ln_pagdp         number;     -- Pago de Derecho de Pesca Diario

  -- Total Costo Variable
  ln_tcostov       number;     -- Total Costo Variable Diarion

  -- Pesca Mensual
  ln_pescam        NUMBER;

BEGIN

  -- Elimino los datos de la tabla temporal
  DELETE tt_CG_COSTO_VAR_FLOTA
    WHERE nave = asi_nave;

  -- Centro de Costo Administrativo
  select f.cencos_admflo, f.tasa_derecho_pesca, f.tasa_sicosat
    into ls_cencos_adm, ln_tasa_dp, ln_tasa_pago
    from fl_param f
   where f.reckey = '1';

  -- Obtencion de los parametros
  select cod_soles, cod_dolares, doc_ot
    into ls_soles, ls_dolares, ls_doc_ot
    from logparam
   where reckey = '1';

	-- Obtengo los parametros que necesito de FL_PARAMCOSTO
	select count(*)
   	into ln_count
  from fl_paramcosto
  where reckey = '1';

  if ln_count = 0 then
  	 RAISE_APPLICATION_ERROR(-20000, 'No ha definido parametros en FL_PARAMCOSTO');
  END IF;

  select t.petroleo_d2, t.art_viveres, t.seguros, t.leasing, t.ot_tipo_overhall,
         t.ot_tipo_redes, t.ot_tipo_varadero
    into ls_petroleo, ls_viveres, ls_seguros, ls_leasing, ls_overhall,
         ls_redes, ls_varadero
    from fl_paramcosto t
   where t.reckey = '1';

    --=========================================================
    -- Primero lleno la data de Captura de Pesca
    --=========================================================
  	select nvl(Sum(nvl(flv.cantidad_real,0) - nvl(flv.cantidad_castigada,0)),0)
    	into ln_pesca
    from 	fl_venta flv,
    			fl_parte_de_pesca flpp
    where flpp.parte_pesca = flv.parte_pesca
    	and flpp.nave_real   = asi_nave
      AND flpp.flag_arribo_aprobado = '1'
      and trunc(flv.hora_inicio_descarga) BETWEEN trunc(adi_fecha1) AND trunc(adi_fecha2);

    --=========================================
    -- PAGO DE LOS TRIPULANTES
    --=========================================
    select NVL(sum( usf_fl_conv_mon( NVL(flpp.participacion_pesca,0) +
                 NVL(flpp.gratificacion,0)       +
                 NVL(flpp.cts,0)                 +
                 NVL(flpp.vacaciones, 0)         +
                 NVL(flpp.aportaciones, 0)       +
                 NVL(flpp.bonificacion_pesca, 0), flpp.cod_moneda, ls_dolares, flpp.fecha) ),0)
   	 into ln_ctrip
  	   from fl_participacion_pesca flpp
     where trunc(flpp.fecha) BETWEEN trunc(adi_fecha1) AND trunc(adi_fecha2)
        and flpp.nave         = asi_nave
        and flpp.sueldo_fijo  = 0;

    INSERT INTO TT_CG_COSTO_VAR_FLOTA(NAVE, DESC_RUBRO, COSTO, PESCA)
    VALUES(asi_nave, 'PAGO DE PARTICIPACION DE TRIPULANTES', ln_ctrip, ln_pesca);

    --=========================================
    -- BONIFICACION DE LOS TRIPULANTES
    --=========================================
    select NVL(sum( usf_fl_conv_mon( NVL(flpp.bonificacion_extra_pln, 0) +
                NVL(flpp.bonif_especial, 0), flpp.cod_moneda, ls_dolares, flpp.fecha) ),0)
   	 into ln_bontrip
  	   from fl_participacion_pesca flpp
     where trunc(flpp.fecha) BETWEEN trunc(adi_fecha1) AND trunc(adi_fecha2)
        and flpp.nave         = asi_nave
        and flpp.sueldo_fijo  = 0;

    INSERT INTO TT_CG_COSTO_VAR_FLOTA(NAVE, DESC_RUBRO, COSTO, PESCA)
    VALUES(asi_nave, 'BONIFICACION DE TRIPULANTES', ln_bontrip, ln_pesca);

    --=========================================
    -- BONIFICACION DE LOS ADMINISTRATIVOS
    --=========================================
    ln_mes1 := to_number(to_char(adi_fecha1, 'mm'));
    ln_mes2 := to_number(to_char(adi_fecha2, 'mm'));
    ln_year := to_number(to_char(adi_fecha2, 'yyyy'));
    ln_bonadm := 0;

    IF ln_mes1 = ln_mes2 THEN
  		 select NVL(Sum(nvl(flv.cantidad_real,0) - nvl(flv.cantidad_castigada,0)),0)
        	into ln_pescam
          from fl_venta flv,
      			   fl_parte_de_pesca flpp
         where flpp.parte_pesca = flv.parte_pesca
      	   and flpp.nave_real = asi_nave
           AND flpp.flag_arribo_aprobado = '1'
           and to_char(flv.hora_inicio_descarga, 'mmyyyy') = to_char(adi_fecha1, 'mmyyyy');

        select NVL(sum( usf_fl_conv_mon( (CASE WHEN ln_pescam > f.pesca_considerar THEN
                                           f.ratio_max * ln_pesca
                                      ELSE
                                           f.ratio_min * ln_pesca
                                      END) , f.cod_moneda, ls_dolares, adi_fecha2)) ,0)
       	  into ln_bonadm
      	  from fl_incentivo_pers_adm f;
    ELSE
        FOR lc_reg IN c_datos LOOP
            IF lc_reg.mes = ln_mes1 THEN
               ld_fecha1 := adi_fecha1;
               ld_fecha2 := Last_day(to_date('01/' || to_char(ln_mes1, '00') || '/'
                            || to_char(ln_year, '0000'), 'dd/mm/yyyy'));
            ELSIF lc_reg.mes = ln_mes2 THEN
               ld_fecha1 := to_date('01/' || to_char(ln_mes2, '00') || '/'
                            || to_char(ln_year, '0000'), 'dd/mm/yyyy');
               ld_fecha2 := adi_fecha2;
            ELSE
               ld_fecha1 := to_date('01/' || lc_reg.mes || '/'
                            || to_char(ln_year, '0000'), 'dd/mm/yyyy');
               ld_fecha2 := Last_day(to_date('01/' || lc_reg.mes || '/'
                            || to_char(ln_year, '0000'), 'dd/mm/yyyy'));
            END IF;

          	select nvl(Sum(nvl(flv.cantidad_real,0) - nvl(flv.cantidad_castigada,0)),0)
            	into ln_pescat
            from 	fl_venta flv,
            			fl_parte_de_pesca flpp
            where flpp.parte_pesca = flv.parte_pesca
            	and flpp.nave_real   = asi_nave
              and trunc(flv.hora_inicio_descarga) BETWEEN trunc(ld_fecha1) AND trunc(ld_fecha2);

            select NVL(sum( usf_fl_conv_mon(
                   CASE WHEN lc_reg.cantidad > f.pesca_considerar THEN
                        f.ratio_max * ln_pescat
                   ELSE
                        f.ratio_min * ln_pescat
                   END , f.cod_moneda, ls_dolares, adi_fecha2)) ,0)
           	  into ln_temp
          	  from fl_incentivo_pers_adm f;

            ln_bonadm := ln_bonadm + ln_temp;

        END LOOP;
    END IF;

    INSERT INTO TT_CG_COSTO_VAR_FLOTA(NAVE, DESC_RUBRO, COSTO, PESCA)
    VALUES(asi_nave, 'BONIFICACION DE ADMINISTRATIVOS', ln_bonadm, ln_pesca);

    --=========================================
    -- Petroleo Diesel # 2
    --=========================================
    select NVL(sum(usf_fl_conv_mon(am.cant_procesada * am.precio_unit,
           am.cod_moneda, ls_dolares, vm.fec_registro)),0)
      into ln_cpetd2
  	  from vale_mov           vm,
           articulo_mov       am,
           articulo_mov_proy  amp,
           fl_ot_nave         flon,
           orden_trabajo      ot
     where vm.nro_vale        = am.nro_vale
       and am.origen_mov_proy = amp.cod_origen
       and am.nro_mov_proy    = amp.nro_mov
       and flon.nro_orden     = amp.nro_doc
       and ot.nro_orden       = flon.nro_orden
       and vm.flag_estado     <> '0'
       and am.flag_estado     <> '0'
       and amp.tipo_doc       = ls_doc_ot
       and am.cod_art         = ls_petroleo
       and flon.nave          = asi_nave
       and trunc(vm.fec_registro) BETWEEN trunc(adi_fecha1) AND trunc(adi_fecha2);

    INSERT INTO TT_CG_COSTO_VAR_FLOTA(NAVE, DESC_RUBRO, COSTO, PESCA)
    VALUES(asi_nave, 'CONSUMO PETROLEO DIESEL # 2', ln_cpetd2, ln_pesca);

    --=========================================
    -- Pago Diario de Derecho de Pesca
    --=========================================
    ln_pagdp := usf_fl_conv_mon((ln_pesca * ln_tasa_dp) * (1 - ln_tasa_pago / 100 ), ls_soles, ls_dolares, adi_fecha2);

    INSERT INTO TT_CG_COSTO_VAR_FLOTA(NAVE, DESC_RUBRO, COSTO, PESCA)
    VALUES(asi_nave, 'PAGO DE DERECHO DE PESCA', ln_pagdp, ln_pesca);

    ln_tcostov := ln_ctrip + ln_bontrip + ln_bonadm + ln_cpetd2 + ln_pagdp;

  return(ln_tcostov);
end USF_FL_COSTO_VAR_X_NAVE;
/

prompt
prompt Creating function USF_FL_FECHA_FIN
prompt ==================================
prompt
create or replace function cantabria.usf_fl_fecha_fin(
	adi_fecha_inicio in date)
  return date is

  ld_fecha_fin date;
  li_day       number;
  li_after		 number;
  li_dia_ini   genparam.dia_inicio_semana%TYPE;
  li_dia_fin   number;
  ln_count     number;

begin

	li_day := to_number(to_char( adi_fecha_inicio, 'D' ));
  
  if li_day = 1 then
     li_day := 7;
  else
     li_day := li_day - 1;
  end if;

  select count(*)
     into ln_count
  from genparam g
  where g.reckey = '1';

  if ln_count = 0 then
     RAISE_APPLICATION_ERROR( -20001, 'NO EXISTEN REGISTROS EN GEN_PARAM, FUNCION USF_FL_FECHA_FIN');
     ld_fecha_fin := null;
     return ld_fecha_fin;
  end if;

  select g.dia_inicio_semana
      into li_dia_ini
  from genparam g
  where g.reckey = '1';

  if li_dia_ini is null or li_dia_ini = 0 then
     RAISE_APPLICATION_ERROR( -20002, 'NO HA ESPECIFICADO DIA_INICIO_SEMANA EN GEN_PARAM, FUNCION USF_FL_FECHA_FIN');
     ld_fecha_fin := null;
     return ld_fecha_fin;
  end if;
  
  li_dia_fin := li_dia_ini + 6;
  
  if li_dia_fin > 7 then
     li_dia_fin := li_dia_fin - 7;
  end if;
  
	-- Buscando la fecha de fin
  if li_day <> li_dia_fin then

		If li_day < li_dia_fin then
			li_after := li_dia_fin - li_day;
		elsif li_day > li_dia_fin then
			li_after := 7 - li_day + li_dia_fin;
		end if;

		ld_fecha_fin := adi_fecha_inicio + li_after;

	else
		ld_fecha_fin := adi_fecha_inicio + 6;

	end if;

  -- la fecha final depende de la ultima semana y es el ultimo dia del a?o
	if to_char(adi_fecha_inicio, 'yyyy') <> to_char( ld_fecha_fin, 'yyyy' ) then
			ld_fecha_fin := to_date('31/12/' || to_char( adi_fecha_inicio ,' yyyy'), 'dd/mm/yyyy');
	end if;

  return ld_fecha_fin;
end usf_fl_fecha_fin;
/

prompt
prompt Creating function USF_FL_GET_TASA_DP
prompt ====================================
prompt
create or replace function cantabria.USF_FL_GET_TASA_DP(
       adi_fecha  IN DATE,
       asi_moneda IN moneda.cod_moneda%TYPE
) return number IS

  ln_Result     number;
  ln_count      NUMBER;

begin

  SELECT COUNT(*)
    INTO ln_count
    FROM fl_derecho_pesca t
   WHERE t.ano = to_number(to_char(adi_fecha, 'yyyy'))
     AND t.mes = to_number(to_char(adi_fecha, 'mm'));

  IF ln_count = 0 THEN
     RAISE_APPLICATION_ERROR(-20000, 'No existe tasa de Pago para el periodo '
                            || to_char(adi_fecha, 'yyyy') || ' - ' || to_char(adi_fecha, 'mm'));
  END IF;

  SELECT usf_fl_conv_mon(t.tasa_pago, t.cod_moneda, asi_moneda, DECODE(fecha_pago, NULL, adi_fecha, fecha_pago))
    INTO ln_Result
    FROM fl_derecho_pesca t
   WHERE t.ano = to_number(to_char(adi_fecha, 'yyyy'))
     AND t.mes = to_number(to_char(adi_fecha, 'mm'));

  return(ln_Result);
end USF_FL_GET_TASA_DP;
/

