prompt
create or replace function cantabria.usf_fl_nomb_mes(ai_mes in integer)
return varchar2 is
  Result varchar2(50);
begin

  if ai_mes = 1 then
     Result := 'Enero';
  elsif ai_mes = 2 then
     Result := 'Febrero';
  elsif ai_mes = 3 then
     Result := 'Marzo';
  elsif ai_mes = 4 then
     Result := 'Abril';
  elsif ai_mes = 5 then
     Result := 'Mayo';
  elsif ai_mes = 6 then
     Result := 'Junio';
  elsif ai_mes = 7 then
     Result := 'Julio';
  elsif ai_mes = 8 then
     Result := 'Agosto';
  elsif ai_mes = 9 then
     Result := 'Setiembre';
  elsif ai_mes = 10 then
     Result := 'Octubre';
  elsif ai_mes = 11 then
     Result := 'Noviembre';
  elsif ai_mes = 12 then
     Result := 'Diciembre';
  end if;

  return(Result);
end usf_fl_nomb_mes;
/

