create or replace function cantabria.usf_fl_numera_bitacora (
       as_origen in string) return varchar2
is
       ls_codigo fl_bitacora.registro_bitacora%TYPE;
       ll_number number;
begin

  select ult_nro
  	into ll_number
  from num_fl_bitacora
  where cod_origen = as_origen
  	for update nowait;

  update num_fl_bitacora
         set ult_nro = ult_nro + 1
         where cod_origen= as_origen;

  commit;

  ls_codigo := as_origen || LPAD(to_char(ll_number), 8, '0');

  return(ls_codigo);

end usf_fl_numera_bitacora;
