prompt Creating function USF_FL_NUM_PARTE_PESCA
prompt ========================================
prompt
create or replace function cantabria.USF_FL_NUM_PARTE_PESCA
(ac_cod_origen origen.cod_origen%type)
 return varchar2 is
  lc_ult_nro_ot fl_parte_de_pesca.parte_pesca%type;
  ln_ult_nro num_fl_parte_pesca.ult_nro%type ;

begin
  --numerador de Partes de Pesca
  select npp.ult_nro
    into ln_ult_nro
    from num_fl_parte_pesca npp
   where (npp.cod_origen = ac_cod_origen)
   for update nowait;

  --se concatena con origen
  lc_ult_nro_ot := ac_cod_origen || LPAD(to_char(ln_ult_nro),8,'0');

  --actualiza informacion de numeradores
  update num_fl_parte_pesca npp
     set npp.ult_nro = Nvl(npp.ult_nro,0) + 1
   where (npp.cod_origen = ac_cod_origen );

  commit;

  return trim(lc_ult_nro_ot);

  EXCEPTION
     WHEN OTHERS THEN
       RAISE_APPLICATION_ERROR(ABS(SQLCODE), 'ERROR EN FUNCION USF_FL_NUM_PARTE_PESCA'
                   || CHR(13) || 'ORIGEN: ' || AC_COD_ORIGEN
                   || CHR(13) || SQLERRM );
       rollback;

end USF_FL_NUM_PARTE_PESCA;
/

