prompt Creating function USF_FL_PROM_PSNP
prompt ==================================
prompt
create or replace function cantabria.usf_fl_prom_psnp(
    asi_especie     in tg_especies.especie%TYPE,
		adi_Fecha 			in date
) return number is

  Result 			number;
  ls_soles    logparam.cod_soles%TYPE;
  ln_count    number;
begin
	-- Esta funcion obtiene el precio promedio diario del SNP de acuerdo a una fecha dada
  -- En Soles

  select cod_soles
    into ls_Soles
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
  from fl_precio_snp flps
  where trunc(flps.fecha) = trunc(adi_fecha)
    and flps.especie = asi_especie;

  if ln_count= 0 then
     RAISE_APPLICATION_ERROR(-20000, 'no ha especificado un precio de la SNP para el dia '
                               || to_char(adi_fecha, 'dd/mm/yyyy') );
     return Result;
  end if;

  select avg(usf_fl_conv_mon(flps.precio_snp, flps.cod_moneda, ls_soles, flps.fecha))
    into Result
  from fl_precio_snp flps
  where trunc(flps.fecha) = trunc(adi_fecha)
    and flps.especie = asi_especie;

  return(Result);
end usf_fl_prom_psnp;
/

