prompt
prompt Creating function USF_FL_TIPO_CAMBIO
prompt ====================================
prompt
create or replace function cantabria.usf_fl_tipo_cambio(
        asi_mon1		in varchar2,
        asi_mon2		in varchar2,
        adi_fecha		in date
) return number is

  Result 			   number;
  ln_cambio 	   number;
  ln_count		   number;
  ls_cod_soles   logparam.cod_soles%TYPE;
  ls_cod_dolares logparam.cod_dolares%TYPE;
begin
  -- Esta funcion convierte el importe ingresado con el tipo de moneda
  -- asi_mon1 a tipo de moneda asi_mon2
  Result := 0;

  if asi_mon1 = asi_mon2 then
  	Result := 0;
  end if;

  Select l.cod_soles, l.cod_dolares
     into ls_cod_soles, ls_cod_dolares
  from logparam l
  where reckey = '1';

  if ls_cod_soles = '' or ls_cod_soles is null then
     Return 0;
  end if;

  if ls_cod_dolares = '' or ls_cod_dolares is null then
     Return 0;
  end if;

 	select count(*)
   	into ln_count
  from calendario
  where to_char(fecha, 'yyyymmdd') = to_char(adi_fecha, 'yyyymmdd');

  if ln_count = 0 then
  	ln_cambio := 0;
    RAISE_APPLICATION_ERROR(-20000, 'No ha definido el tipo de cambio para el dia'
                                     || to_char(adi_fecha, 'dd/mm/yyyy') );
    return 0;
  end if;

  if asi_mon1 = ls_cod_dolares then
  	if asi_mon2 = ls_cod_soles then

      if ln_count <> 0 then
      	select nvl(c.vta_dol_prom,0)
      		into ln_cambio
	      from calendario c
  	    where to_char(c.fecha, 'yyyymmdd') = to_char(adi_fecha, 'yyyymmdd');
      end if;

      if ln_cambio <> 0 then
      	Result := ln_cambio;
      else
      	Result := 0;
      end if;

    end if;
  elsif asi_mon1 = ls_cod_soles then
  	if asi_mon2 = ls_cod_dolares then

      if ln_count <> 0 then
      	select nvl(c.cmp_dol_prom,0)
      		into ln_cambio
	      from calendario c
  	    where to_char(c.fecha, 'yyyymmdd') = to_char(adi_fecha, 'yyyymmdd');
      end if;

      if ln_cambio <> 0 then
      	Result :=  ln_cambio;
      else
      	Result := 0;
      end if;

    end if;
  end if;
  return(Result);

end usf_fl_tipo_cambio;
/

