prompt Creating function USF_FL_TOTAL_PESCA_DIA
prompt ========================================
prompt
create or replace function cantabria.usf_fl_total_pesca_dia(
		adi_fecha in date) return number is

  Result 		number;
  ln_count 	number;

begin

	select count(*)
		into ln_count
	from 	fl_venta flv,
				fl_parte_de_pesca flpp
	where flv.parte_pesca = flpp.Parte_pesca
  	and to_char(flpp.fecha_hora_arribo, 'yyyymmdd') = to_char(adi_fecha, 'yyyymmdd');

  if ln_count = 0 then
  	Result := 0;
  else
		select sum(flv.cantidad_real - flv.cantidad_castigada)
			into Result
		from 	fl_venta flv,
					fl_parte_de_pesca flpp
		where flv.parte_pesca = flpp.Parte_pesca
  		and to_char(flpp.fecha_hora_arribo, 'yyyymmdd') = to_char(adi_fecha, 'yyyymmdd');
	end if;

  return(Result);
end usf_fl_total_pesca_dia;
/

