prompt Creating function USF_FL_VERF_NAV_ZARPE
prompt =======================================
prompt
create or replace function cantabria.usf_fl_verf_nav_zarpe( as_nave in tg_naves.nave%TYPE )
return varchar2 is
  Result   varchar2(300);
  ln_count number;
  ls_parte fl_parte_de_pesca.parte_pesca%type;
begin
  -- Esta funcion valida si una nave que se ingrese en el zarpe no tenga arribos
  -- Pendientes
  select count(*)
    into ln_count
  from fl_parte_de_pesca
  where registro_arribo is null
    and nave_real = as_nave;

 Result := '';

  if ln_count > 0 then
     select parte_pesca
        into ls_parte
     from fl_parte_de_pesca
     where registro_arribo is null
       and nave_real = as_nave;
     Result := 'ORACLE: NO PUEDE INGRESAR EL ZARPE DE LA EMBARCACION '
                || chr(13) || 'YA TIENE UN ARRIBO PENDIENTE'
                || chr(13) || 'NUMERO DE PARTE: ' || ls_parte;
  end if;

  return(Result);
end usf_fl_verf_nav_zarpe;
/

