  if ln_count > 0 then
     select parte_pesca
        into ls_parte
     from fl_parte_de_pesca
     where registro_arribo = as_registro;

     Result := 'ORACLE: REGISTRO DE ARRIBO: ' || as_registro
                   || ' YA HA SIDO INGRESADO'
                   || CHR(13) || 'PARTE DE PESCA: ' || ls_parte;
