prompt Creating function USF_FTS_IND_COSTO_LAB_ART
prompt ===========================================
prompt
create or replace function cantabria.USF_FTS_IND_COSTO_LAB_ART
(as_labor      in labor.cod_labor%type,
 an_ano        in number,
 as_mes        in char)
 return number is

Result           Number(9,3);

Begin

  Select sum(poi.cantidad)
    into Result
    from campo_ciclo cc, orden_trabajo ot, pd_ot_det pod, pd_ot_insumos poi
   where cc.nro_orden = ot.nro_orden
     and ot.nro_orden = pod.nro_orden
     and pod.nro_parte = poi.nro_parte
     and pod.nro_item = poi.nro_item
     and cc.corr_corte in (select tt.corr_corte
                              from tt_campos_cosechados tt
                             where to_char(tt.mes) like as_mes
                               and tt.ano = an_ano)
     and pod.cod_labor = as_labor;

return(Result);

end USF_FTS_IND_COSTO_LAB_ART;
/

