prompt
prompt Creating function USF_GET_COLINVARCHAR
prompt ======================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.usf_get_colinvarchar(
    p_select IN CLOB)
  RETURN VARCHAR2
IS
  p_cursor SYS_REFCURSOR;
  sql_stmt CLOB;
  rpta CLOB;
  rpta_return CLOB;
BEGIN
  IF p_select IS NULL THEN
    RETURN NULL;
  END IF;
sql_stmt := p_select;
OPEN p_cursor FOR sql_stmt;
LOOP
  FETCH p_cursor INTO rpta;
  EXIT
WHEN p_cursor%NOTFOUND;
  IF rpta_return IS NULL THEN
    rpta_return  := rpta;
  ELSE
    rpta_return := rpta_return ||'/ '|| rpta;
  END IF;
END LOOP;
CLOSE p_cursor;
return rpta_return;
END;
/

prompt
prompt Creating function USF_GET_NAME_MONTH
prompt ====================================
prompt
create or replace function cantabria.usf_get_name_month(
       ani_mes in number
) return varchar2 is
  ls_Result varchar2(100);
begin
  
  case 
    when ani_mes = 1 then
      ls_Result := 'Enero';
    when ani_mes = 2 then
      ls_Result := 'Febrero';
    when ani_mes = 3 then
      ls_Result := 'Marzo';
    when ani_mes = 4 then
      ls_Result := 'Abril';
    when ani_mes = 5 then
      ls_Result := 'Mayo';
    when ani_mes = 6 then
      ls_Result := 'Junio';
    when ani_mes = 7 then
      ls_Result := 'Julio';
    when ani_mes = 8 then
      ls_Result := 'Agosto';
    when ani_mes = 9 then
      ls_Result := 'Setiembre';
    when ani_mes = 10 then
      ls_Result := 'Octubre';
    when ani_mes = 11 then
      ls_Result := 'Noviembre';
    when ani_mes = 12 then
      ls_Result := 'Diciembre';
  end case;     
       

  return(ls_Result);
end usf_get_name_month;
/

