prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_GET_TT_CANA_PERIODO(
       as_periodo in char,
       as_labor IN CHAR
) RETURN NUMBER IS
  Result NUMBER;

BEGIN
SELECT SUM(cana_sucia)
  INTO Result
  FROM tt_cam_cana_periodo
 WHERE periodo = as_periodo
   AND flg_calculo = DECODE(as_labor,'QTRTRA','TT', --CA?A DE TRACTORES
                                     'QTRCAM','TC', --CA?A DE CAMIONES
                                     'QACARR','AP', --CA?A ALCE PROPIA
                                     'QACARRT','AT',--CA?A ALCE DE TERCEROS
                                     'GE');         --CA?A GENERAL
