prompt Creating function USF_HAS
prompt =========================
prompt
create or replace function cantabria.usf_has(
   an_netas in number, an_totales in number,
   an_rastrojo in number, an_avance in number,
   as_tipo in char
   ) return number is

  ln_Result number;
begin
  if as_tipo='N' then
     ln_result := an_netas;
  end if;
  if as_tipo='R' then
     ln_result := an_rastrojo;
  end if;
  if as_tipo='T' then
     ln_result := an_totales;
  end if;
  if as_tipo='A' then
     ln_result := an_avance;
  end if;
  return(NVL(ln_Result,0));
end usf_has;
/

prompt
prompt Creating function USF_HH2HHMM
prompt =============================
prompt
create or replace function cantabria.usf_hh2hhmm(an_horas in number)
  return string is

  -- se recepciona un nzmnero de hora,
  -- se devuelve en formato 'hhhh:mm'
  ls_hhmm char(7);
  ln_horas integer ;
  ln_minutos integer ;

begin

  ln_horas := trunc( an_horas ) ;
  ln_minutos := round ( ( ln_horas - an_horas ) * 60 ) ;
  ls_hhmm := substr( to_char( ln_horas , '9990' ), 2, 4) || ':' ||
             substr( to_char( ln_minutos, '00' ), 2, 2) ;

  return( ls_hhmm );
end usf_hh2hhmm;
/

prompt
prompt Creating function USF_IMPORTE_COMISION_FIJA
prompt ===========================================
prompt
create or replace function cantabria.USF_IMPORTE_COMISION_FIJA
(as_canal      In canal_distribucion.canal%Type,
 ad_fec_ini    In Date,
 an_porc_venta In comision_fija.porc_cuota%Type) return number Is

Result comision_fija.importe%Type;

Cursor c_comision Is
Select cf.porc_cuota, cf.importe
  From comision_fija cf
 Where cf.canal      = as_canal
   And cf.fecha_ini  = ad_fec_ini
 Order By cf.porc_cuota Asc;

begin

   For c_c In c_comision Loop

       If c_c.porc_cuota <= an_porc_venta Then
          Result := c_c.importe;
       End If;

   End Loop;

   return(Result);

end USF_IMPORTE_COMISION_FIJA;
/

