prompt Creating function USF_INSERT_OPERACIONES
prompt ========================================
prompt
create or replace function cantabria.usf_insert_operaciones (
ln_oper_sec    in number, lc_mes        in char,
lc_corr_corte  in char  , lc_proceso    in char,
lc_actividad   in char  , lc_labor      in char,
lc_ejecutor    in char  , ln_has        in number,
ln_cantidad    in number, ln_valor_unit in number,
lc_flag_maq_mo in char  , ln_costo_ins  in number,
lc_desc_fase   in char)
return number is
ln_ind      Number(1);
ln_cant_man Number(13,2);
ln_cant_mec Number(13,2);

begin

  IF lc_flag_maq_mo = 'M'THEN
     ln_cant_mec := ln_cantidad ;
     ln_cant_man := 0 ;
  ELSE
     ln_cant_man := ln_cantidad  ;
     ln_cant_mec := 0 ;
  END IF;

  INSERT INTO tt_ppto_recursos
 (oper_sec ,        mes,  corr_corte,
  proceso  ,  actividad,       labor,
  ejecutor ,        has,    cant_man,
  cant_mec , valor_unit,   costo_ins,
  desc_proceso )
  VALUES
 (ln_oper_sec,        lc_mes, lc_corr_corte,
  lc_proceso ,  lc_actividad,      lc_labor,
  lc_ejecutor,        ln_has,   ln_cant_man,
  ln_cant_mec, ln_valor_unit,  ln_costo_ins,
  lc_desc_fase);

  Return (ln_ind);
END ;
/

