prompt
prompt Creating function USF_LAB_ANALISIS_CAMPO
prompt ========================================
prompt
create or replace function cantabria.USF_LAB_ANALISIS_CAMPO
  ( ad_fecha1 in date, ad_fecha2 in date, as_caract in char,
  as_corr_corte in char, as_mensaje in char, as_quema in char)
  return number is

  ln_resultado        number(17,7) := 0;
  ln_count            number;
begin

  Select COUNT(u.fecha) into ln_count
        from resultados_campo_det u, resultados_campo r
        where u.cod_caract = as_caract and
        (u.fecha between ad_fecha1 and ad_fecha2) and
        u.corr_corte = as_corr_corte and u.fecha = r.fecha and
        u.corr_corte = r.corr_corte and r.flag_campo_sin_qm = as_quema;
  if ln_count > 0 then
--     Select ROUND(AVG(u.resultado),2) into ln_resultado
     Select AVG(u.resultado) into ln_resultado
           from resultados_campo_det u, resultados_campo r
           where u.cod_caract = as_caract and
           (u.fecha between ad_fecha1 and ad_fecha2) and
           u.corr_corte = as_corr_corte and u.fecha = r.fecha and
        u.corr_corte = r.corr_corte and r.flag_campo_sin_qm = as_quema;
  else
     insert into tt_lab_resul_proceso(fecha, observacion)
       values(ad_fecha1, 'No existe resultados de ' || as_mensaje);
--     Raise_application_error( -20002, 'No existe resultado de ' || as_mensaje || ' para corr. ' || as_corr_corte);
  end if;

  return(ln_resultado);
end USF_LAB_ANALISIS_CAMPO;
/

prompt
prompt Creating function USF_LAB_ANALISIS_PROD
prompt =======================================
prompt
create or replace function cantabria.USF_LAB_ANALISIS_PROD
  ( ad_fecha1 in date, ad_fecha2 in date, as_caract in char,
  as_analisis in char, as_tipo in char, as_mensaje in char)
  return number is

  /*
    as_tipo = P, Promedio, S= Suma
  */

  ln_resultado number(17,7) := 0;
  ln_count            number;
begin

  Select COUNT(*) into ln_count from resultados_producto_det u
    where u.cod_caract = as_caract and u.tipo_analisis = as_analisis and
        u.fecha >= ad_fecha1 and u.fecha <= ad_fecha2;
  if ln_count > 0 then
     if as_tipo = 'P' then
        Select AVG(u.resultado) into ln_resultado
           from resultados_producto_det u
           where u.cod_caract = as_caract and u.tipo_analisis = as_analisis and
           u.fecha between ad_fecha1 and ad_fecha2;
     end if;
     if as_tipo = 'S' then
        Select SUM(u.resultado) into ln_resultado
           from resultados_producto_det u
           where u.cod_caract = as_caract and u.tipo_analisis = as_analisis and
           u.fecha between ad_fecha1 and ad_fecha2;
     end if;
  else
     insert into tt_lab_resul_proceso(fecha, observacion)
       values(ad_fecha1, 'No existe resultados de ' || as_mensaje );
--     Raise_application_error( -20002, 'No existe resultados de ' || as_mensaje);
  end if;

  return(ln_resultado);
end USF_LAB_ANALISIS_PROD;
/

