prompt
prompt Creating function USF_LAB_AVG_CALC_PROD
prompt =======================================
prompt
create or replace function cantabria.USF_LAB_AVG_CALC_PROD(
   ad_fecha1 in date, ad_fecha2 in date,
   as_calculo in char) return number is

  ln_dia     number(17,7);
begin

  -- Funcion que acumula los resultados de un calculo para
  -- un rango de fecha especificado.

  Select AVG( lcp.dia) into ln_dia
     from lab_calculo_prod lcp
     where lcp.cod_calculo = as_calculo and
     lcp.fecha between ad_fecha1 and ad_fecha2;
  return(NVL(ln_dia,0));
end USF_LAB_AVG_CALC_PROD;
/

prompt
prompt Creating function USF_LAB_INSERT_CALCULO_PROD
prompt =============================================
prompt
create or replace function cantabria.USF_LAB_INSERT_CALCULO_PROD(
   ad_fecha in date, as_cod in char, an_dia in number ) return integer is


  ln_dia       lab_calculo_prod.dia%type;
begin

  ln_dia := NVL( an_dia,0);
  UPDATE lab_calculo_prod l set dia = NVL( dia,0) + ln_dia
     where TRUNC( fecha) = TRUNC( ad_fecha) and l.cod_calculo = as_cod and
     l.flag_tipo = 'P';
  IF SQL%NOTFOUND THEN
  insert into lab_calculo_prod(fecha, cod_calculo, dia, flag_tipo)
        values( ad_fecha, as_cod, ln_dia, 'P');
  END IF;
  return(1);
end USF_LAB_INSERT_CALCULO_PROD;
/

prompt
prompt Creating function USF_LAB_AZUCAR_CALCULO
prompt ========================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_LAB_AZUCAR_CALCULO(
   ad_fecha_ini in date, ad_fecha_fin in date ) return number is

-- Funcion que permite hacer los calculos relacionados al azucar
CURSOR c_reporte is
select rsd.grupo, rsd.subgrupo, rsd.item, rsd.codigo, a.cod_art, a.nom_articulo,
       a.und, a.peso_und
from rpt_subgrupo_det rsd, articulo a
where rsd.subgrupo=a.sub_cat_art and
      rsd.cnta_ctbl=a.cod_art and
      rsd.reporte='KGAZURES' and
      rsd.codigo is not null
order by rsd.grupo, rsd.subgrupo, rsd.item ;

CURSOR c_und(as_cod_art  articulo.cod_art%type,
             as_almacen  almacen.almacen%type,
             as_tipo_mov articulo_mov_tipo.tipo_mov%type) is
Select SUM( am.cant_procesada) as bolsas,
       SUM( am.cant_procesada) * a.peso_und as kilos
  from vale_mov vm, articulo_mov am, articulo a
 where vm.cod_origen = am.cod_origen and
       vm.nro_vale = am.nro_vale and
       vm.tipo_mov = as_tipo_mov and
       vm.almacen = as_almacen and
       (vm.fec_registro between ad_fecha_ini and ad_fecha_fin) and
       am.flag_estado <> '0' and
       am.cod_art = a.cod_art and
       a.cod_art = as_cod_art
group by a.peso_und ;

CURSOR c_und_kgr is
SELECT tt.cod_calculo_und, tt.cod_calculo_kgr, tt.cod_calculo_kgr_pol,
       tt.cantidad_und, tt.cantidad_kgr, tt.cod_calculo_porc_pol
FROM tt_lab_calculo_dia_azucar tt ;

ls_almacen               labparam.almacen_pptt%type ;
ls_tipo_mov              labparam.ingreso_pptt%type ;
ln_cant_und              articulo_mov.cant_procesada%type ;
ln_cant_kgr              articulo_mov.cant_procesada%type ;
ln_cant_kgp              lab_calculo_prod.dia%type ;
ln_porc_pol              lab_calculo_prod.dia%type ;
ls_cod_calc_und          lab_calculo.cod_calculo%type ;
ls_cod_calc_kgr          lab_calculo.cod_calculo%type ;
ls_cod_calc_kgp          lab_calculo.cod_calculo%type ;
ls_cod_calc_tpo          lab_calculo.cod_calculo%type ;
ls_cod_porc_pol          lab_calculo.cod_calculo%type ;
ln_count                 number(3) ;
ln_val                   number(1) ;

BEGIN

delete from tt_lab_calculo_dia_azucar ;

SELECT l.almacen_pptt, l.ingreso_pptt
  INTO ls_almacen, ls_tipo_mov
  FROM labparam l
 WHERE l.reckey='1' ;

-- Calculando la produccion de los productos terminados
FOR c_r IN c_reporte LOOP
    ls_cod_calc_und := SUBSTR(c_r.codigo,1,4) ;  -- Codigo calculo unidad
    ls_cod_calc_kgr := SUBSTR(c_r.codigo,6,4) ;  -- Codigo de calculo kg
    ls_cod_calc_kgp := SUBSTR(c_r.codigo,11,4) ; -- Codigo de calculo kg pol
    ls_cod_calc_tpo := SUBSTR(c_r.codigo,16,4) ; -- Codigo de calculo ton pol
    ls_cod_porc_pol := SUBSTR(c_r.grupo,1,4) ;   -- Codigo de calculo porcentaje pol
    ln_cant_und := 0 ;
    ln_cant_kgr := 0 ;
    FOR c_u IN c_und(c_r.cod_art, ls_almacen, ls_tipo_mov) LOOP
        ln_cant_und := ln_cant_und + c_u.bolsas ;
        ln_cant_kgr := ln_cant_kgr + c_u.kilos ;
    END LOOP ;

    IF ln_cant_und = 0 THEN
       insert into tt_lab_resul_proceso(observacion)
       values('Producto no tiene ingreso' || c_r.cod_art);
    END IF ;

    -- Actuliza datos si existe
    UPDATE tt_lab_calculo_dia_azucar tt
    SET tt.cantidad_und = nvl(tt.cantidad_und,0) + ln_cant_und,
        tt.cantidad_kgr = nvl(tt.cantidad_kgr,0) + ln_cant_kgr
    WHERE tt.cod_calculo_und = ls_cod_calc_und ;
    -- Inserta registro en caso no exista
    IF SQL%NOTFOUND THEN
       INSERT INTO tt_lab_calculo_dia_azucar(
       cod_calculo_und,      cod_calculo_kgr, cod_calculo_kgr_pol, cod_calculo_ton_pol,
       cod_calculo_porc_pol, cantidad_und,    cantidad_kgr)
       VALUES(
       ls_cod_calc_und,      ls_cod_calc_kgr, ls_cod_calc_kgp,     ls_cod_calc_tpo,
       ls_cod_porc_pol,      ln_cant_und,     ln_cant_kgr) ;
    END IF ;
END LOOP ;

-- Registrando informacion de azucar, segun und y kgr
FOR c_uk IN c_und_kgr LOOP

    -- Registrando unidades
    ln_val := USF_LAB_INSERT_CALCULO_PROD(ad_fecha_ini, c_uk.cod_calculo_und, c_uk.cantidad_und);

    -- Registrando kilos
    ln_val := USF_LAB_INSERT_CALCULO_PROD(ad_fecha_ini, c_uk.cod_calculo_kgr, c_uk.cantidad_kgr);

    -- Registrando kg pol
    SELECT count(*) INTO ln_count
    FROM lab_calculo_prod l
    WHERE l.fecha = ad_fecha_ini AND l.cod_calculo = c_uk.cod_calculo_porc_pol ;

    IF ln_count > 0 THEN
       SELECT l.dia INTO ln_porc_pol
       FROM lab_calculo_prod l
       WHERE l.fecha = ad_fecha_ini AND l.cod_calculo = c_uk.cod_calculo_porc_pol ;
    ELSE
        ln_porc_pol:= 0 ;
    END IF ;

    ln_cant_kgp := c_uk.cantidad_kgr * ln_porc_pol / 100 ;

    ln_val := USF_LAB_INSERT_CALCULO_PROD(ad_fecha_ini, c_uk.cod_calculo_kgr_pol, ln_cant_kgp);

END LOOP ;

RETURN(1);

END USF_LAB_AZUCAR_CALCULO;
/

prompt
prompt Creating function USF_LAB_AZUCAR_KILOS
prompt ======================================
prompt
create or replace function cantabria.USF_LAB_AZUCAR_KILOS (ad_fecha1 in date,
  ad_fecha2 in date, as_cod in char)
  return number is

  /*
    Funcion que encuentra los kilos de azucar segun almacen de productos terminados

    ad_fecha1, fecha inicio
    ad_fecha2, fecha final
    as_cod, codigo del producto a evaluar
    as_periodo, 'D'=Diario, 'S'=Semanal, 'M'=Mensual, 'A'=Anual
  */

  ls_almacen           almacen.almacen%type;
  ln_kilos             number;

begin

  -- Parametros
  Select l.almacen_pptt into ls_almacen
    from labparam l where reckey = '1';


   Select nvl(SUM( am.cant_procesada),0) * max(a.peso_und) into ln_kilos
    from vale_mov vm, articulo_mov am, articulo a, articulo_producto ap
    where vm.cod_origen = am.cod_origen and
          vm.nro_vale = am.nro_vale and
          vm.tipo_mov = (select oper_ing_prod from logparam where reckey='1') and
          vm.almacen = ls_almacen and
          am.flag_estado <> '0' and
          ( vm.fec_registro between ad_fecha1 and ad_fecha2) and
          am.cod_art = a.cod_art and
          am.cod_art = ap.cod_art and ap.cod_prod = as_cod;

   return(ln_kilos);

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      return (0);


end USF_LAB_AZUCAR_KILOS;
/

prompt
prompt Creating function USF_LAB_AZUCAR_KILOS_DET
prompt ==========================================
prompt
create or replace function cantabria.USF_LAB_AZUCAR_KILOS_DET(ad_fecha1 in date,
  ad_fecha2 in date, as_cod_art in articulo.cod_art%type)
  return number is

  /*
    Funcion que encuentra los kilos de azucar segun almacen de productos terminados

    ad_fecha1, fecha inicio
    ad_fecha2, fecha final
    as_cod, codigo del producto a evaluar
    as_periodo, 'D'=Diario, 'S'=Semanal, 'M'=Mensual, 'A'=Anual
  */

  ls_almacen           almacen.almacen%type;
  ls_ing_pptt          labparam.ingreso_pptt%type ;
  ln_kilos             number;

begin

  -- Parametros
  Select l.almacen_pptt, l.ingreso_pptt
    into ls_almacen, ls_ing_pptt
    from labparam l
   where reckey = '1';

   Select SUM( am.cant_procesada) * a.peso_und into ln_kilos
    from vale_mov vm, articulo_mov am, articulo a
    where vm.cod_origen = am.cod_origen and
          vm.nro_vale = am.nro_vale and
          vm.almacen = ls_almacen and
          vm.flag_estado <> '0' and
          vm.tipo_mov = ls_ing_pptt and
          ( vm.fec_registro between ad_fecha1 and ad_fecha2) and
          am.cod_art = a.cod_art and
          am.cod_art = as_cod_art and
          am.flag_estado <> '0'
 group by a.peso_und ;

   return(nvl(ln_kilos,0));

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      return (0);


end USF_LAB_AZUCAR_KILOS_DET;
/

prompt
prompt Creating function USF_LAB_RESUMEN_MF
prompt ====================================
prompt
create or replace function cantabria.USF_LAB_RESUMEN_MF(
     as_tipo_ana in tipo_analisis.tipo_analisis%type,
     as_caract in caracteristicas.cod_caract%type,
     as_cod_calc in char,
     as_tipo_proc in tipo_analisis.flag_tipo%type,
     ad_fecha1 in date, ad_fecha2 in date, as_cod_prod in char)
    return number is
  Result number;

  ln_count  number;
  ls_formula          char(40);
  ln_dec              number;
  ls_pureza           caracteristicas.cod_caract%type;
   ls_brix             caracteristicas.cod_caract%type;
   ls_pol              caracteristicas.cod_caract%type;
   ln_brix             number(16,7);
   ln_pol              number(16,7);
   ln_avg              number(16,7);

begin
   -- Pureza
  Select l.cod_pureza, l.cod_brix_cor, l.cod_pol
     into ls_pureza, ls_brix, ls_pol
     from labparam l
     where l.reckey = '1';

  -- Busca calculo segun codigo
  Select count(l.formula)  into ln_count from lab_calculo l
        where l.cod_calculo = as_cod_calc;
  if ln_count > 0 then
     Select l.formula into ls_formula from lab_calculo l
           where l.cod_calculo = as_cod_calc;
     -- Busca decimales
     Select NVL(c.nro_decimales,0) into ln_dec from caracteristicas c
        where c.cod_caract = as_caract;
     if TRIM( ls_formula) = 'AVG' then
        if TRIM( ls_pureza) = TRIM( as_caract) then
               -- Resultados para analisis sin templas
               if as_tipo_proc = '1' then
                  Select AVG(u.resultado) into ln_brix
                     from resultados_producto_det u
                     where u.cod_caract = ls_brix and u.tipo_analisis = as_tipo_ana and
                     u.fecha between ad_fecha1 and ad_fecha2;
                  Select AVG(u.resultado) into ln_pol
                     from resultados_producto_det u
                     where u.cod_caract = ls_pol and u.tipo_analisis = as_tipo_ana and
                     u.fecha between ad_fecha1 and ad_fecha2;
                  ln_avg := ROUND(((ln_pol/ ln_brix) *100),ln_dec);
               end if;
               -- Resultados para analisis con templas
               if as_tipo_proc = '2' then
                  Select AVG(u.resultado) into ln_brix
                     from resultados_templa_det u
                     where u.cod_caract = ls_brix and u.tipo_analisis = as_tipo_ana and
                     u.fecha between ad_fecha1 and ad_fecha2;
                  Select AVG(u.resultado) into ln_pol
                     from resultados_templa_det u
                     where u.cod_caract = ls_pol and u.tipo_analisis = as_tipo_ana and
                     u.fecha between ad_fecha1 and ad_fecha2;
                  ln_avg := ROUND(((ln_pol/ ln_brix) *100),ln_dec);
               end if;
        else
           if as_cod_prod is not null then
              -- Resultados para analisis con templas
              if as_tipo_proc = '2' then
                 Select AVG(u.resultado) into ln_avg
                     from resultados_templa_det u, templas t
                     where u.cod_templa = t.cod_templa and
                     t.cod_prod = as_cod_prod and
                     u.cod_caract = as_caract and u.tipo_analisis = as_tipo_ana and
                     u.fecha between ad_fecha1 and ad_fecha2;
              end if;
           else
              -- Resultados para analisis sin templas
              if as_tipo_proc = '1' then
                 Select AVG(u.resultado) into ln_avg
                     from resultados_producto_det u
                     where u.cod_caract = as_caract and u.tipo_analisis = as_tipo_ana and
                     u.fecha between ad_fecha1 and ad_fecha2;
              end if;
              -- Resultados para analisis con templas
              if as_tipo_proc = '2' then
                 Select AVG(u.resultado) into ln_avg
                     from resultados_templa_det u
                     where u.cod_caract = as_caract and u.tipo_analisis = as_tipo_ana and
                     u.fecha between ad_fecha1 and ad_fecha2;
              end if;
           end if;
        end if;
     end if;
     if TRIM( ls_formula) = 'COUNT' then
          select count(*) into ln_avg
              from resultados_templa t where TRIM(tipo_analisis) = TRIM(as_tipo_ana)
              AND fecha between ad_fecha1 and ad_fecha2;
     end if;
  else
     ln_avg := 0;
  end if;

  ln_avg := NVL( ROUND( ln_avg,ln_dec),0);

  return(ln_avg);
end USF_LAB_RESUMEN_MF;
/

prompt
prompt Creating function USF_LAB_TON_X_PRODUCTO
prompt ========================================
prompt
create or replace function cantabria.USF_LAB_TON_X_PRODUCTO
(ad_fecha_ini in Date,
 ad_fecha_fin in Date,
 as_articulo  In articulo.cod_art%Type) return integer Is

 Result Number(17,7);

Begin

  Select sum(round( (sp.pesada - sp.tara),2)) As neto
    Into Result
    From salida_pesada sp
   Where sp.fecha_pesada >= ad_fecha_ini
     And sp.fecha_pesada <= ad_fecha_fin
     And sp.cod_art = as_articulo;

  return(Result);

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      return (0);

end USF_LAB_TON_X_PRODUCTO;
/

prompt
prompt Creating function USF_LAB_AZUCAR_RUBIA_MIELB
prompt ============================================
prompt
create or replace function cantabria.USF_LAB_AZUCAR_RUBIA_MIELB
(ad_fec_ini in Date,
 ad_fec_fin in Date,
 ls_flag_return In Char)
return Number Is

Result                  Number(17,7);
Result_aux              Number(17,7);

ln_prza_mlza            Number(12,7);
ln_pola_mielb           Number(12,7);
ln_prza_mielb           Number(12,7);
ln_pola_rubia           Number(12,7);
ln_brix_mlza            Number(12,7);
ln_ton_mielb            Number(8,2);
ln_ton_pol_mielb        Number(12,7);
ln_ton_pol_azucar_mielb Number(12,7);
ln_ton_pol_melaza       Number(12,7);
ln_ton_brix_melaza      Number(12,7);
ln_recuperado           Number(12,7);

--caracteristicas
ls_pola     caracteristicas.cod_caract%Type;
ls_prza     caracteristicas.cod_caract%Type;
ls_brix_cor caracteristicas.cod_caract%Type;
--analisis
ls_ana_mielb tipo_analisis.tipo_analisis%Type;
ls_ana_mlza  tipo_analisis.tipo_analisis%Type;
ls_ana_rubia tipo_analisis.tipo_analisis%Type;
--formulas
ls_formula lab_calculo.cod_calculo%Type;

Cursor c_fechas Is
Select * From tt_lab_rango_fechas;

Begin

Delete From tt_lab_rango_fechas;

Select l.cod_pol, l.cod_pureza, l.ana_melaza, l.ana_arubia, l.cod_brix_cor
  Into ls_pola, ls_prza, ls_ana_mlza, ls_ana_rubia, ls_brix_cor
  From labparam l;

  ls_ana_mielb := 'A15';
  ls_formula   := 'F10';

  -- Insertando rango de fechas a procesar
  Insert Into tt_lab_rango_fechas ( fecha_prod, del_dia, al_dia )
  Select cp.fecha_prod, cp.del_dia, cp.al_dia
    From calendario_produccion cp
   Where cp.fecha_prod >= trunc(ad_fec_ini)
     And cp.fecha_prod < trunc(ad_fec_fin);

  Result := 0;

  For c_f In c_fechas Loop

       ln_prza_mlza             := 0;
       ln_pola_mielb            := 0;
       ln_prza_mielb            := 0;
       ln_pola_rubia            := 0;
       ln_brix_mlza             := 0;
       ln_ton_mielb             := 0;
       ln_ton_pol_mielb         := 0;
       ln_ton_pol_azucar_mielb  := 0;
       ln_ton_pol_melaza        := 0;
       ln_ton_brix_melaza       := 0;
       ln_recuperado            := 0;
       Result_Aux               := 0;

       -- BALANZA
       ln_ton_mielb := nvl(USF_LAB_TON_X_PRODUCTO ( c_f.del_dia, c_f.al_dia, '7944.0001'),0);

       If ln_ton_mielb > 0 Then

            -- ANALISIS (DATOS OBTENIDOS DEL MISMO REPORTE DIARIO [LB701])
            ln_prza_mlza  := USF_LAB_RESUMEN_MF( ls_ana_mlza,  ls_prza, ls_formula, '1', c_f.del_dia, c_f.al_dia, Null);
            ln_pola_mielb := USF_LAB_RESUMEN_MF( ls_ana_mielb, ls_pola, ls_formula, '2', c_f.del_dia, c_f.al_dia, Null);
            ln_prza_mielb := USF_LAB_RESUMEN_MF( ls_ana_mielb, ls_prza, ls_formula, '2', c_f.del_dia, c_f.al_dia, Null);
            ln_pola_rubia := USF_LAB_RESUMEN_MF( ls_ana_rubia, ls_pola, ls_formula, '2', c_f.del_dia, c_f.al_dia, Null);
            ln_brix_mlza  := USF_LAB_RESUMEN_MF( ls_ana_mlza,  ls_brix_cor, ls_formula, '1', c_f.del_dia, c_f.al_dia, Null);

            -- 1? calculo
            If (ln_prza_mielb*(100-ln_prza_mlza)) > 0 Then
               ln_recuperado := (100*(ln_prza_mielb - ln_prza_mlza)) / (ln_prza_mielb*(100-ln_prza_mlza));
            Else
               ln_recuperado := 0;
            End If;
            -- 2? calculo
            ln_ton_pol_mielb := ((ln_pola_mielb)/100) * (ln_ton_mielb/1000);
            -- 3? calculo
            ln_ton_pol_azucar_mielb := (ln_ton_pol_mielb * ln_recuperado);
            -- 4? calculo
            ln_ton_pol_melaza := ln_ton_pol_mielb - ln_ton_pol_azucar_mielb;
            -- 5? calculo
            If (ln_prza_mlza/100) > 0 Then
               ln_ton_brix_melaza := ln_ton_pol_melaza / (ln_prza_mlza/100);
            Else
               ln_ton_brix_melaza := 0;
            End If;

            If ls_flag_return = 'P292' Then
               If (ln_pola_rubia/100) > 0 Then
                  Result_aux := (ln_ton_pol_azucar_mielb*1000)/(ln_pola_rubia/100);
               Else
                  Result_Aux := 0;
               End If;
            Elsif ls_flag_return = 'P092' Then
               If (ln_brix_mlza) > 0 Then
                  Result_aux := ln_ton_brix_melaza / (ln_brix_mlza/100);
               Else
                  Result_aux := 0;
               End If;
            Elsif ls_flag_return = 'P100' Then
               Result_aux := ln_ton_pol_melaza;
            Elsif ls_flag_return = 'P102' Then
               Result_aux := ln_ton_brix_melaza;
            Elsif ls_flag_return = 'P276' Then
               Result_aux := ln_ton_pol_azucar_mielb;
            End If;

            Result := Result + nvl(Result_aux,0);

       End If;

  End Loop;

  return(Result);

end USF_LAB_AZUCAR_RUBIA_MIELB;
/

prompt
prompt Creating function USF_LAB_AZUCAR_UND
prompt ====================================
prompt
create or replace function cantabria.USF_LAB_AZUCAR_UND (ad_fecha1 in date,
  ad_fecha2 in date, as_cod in char)
  return number is

  /*
    Funcion que encuentra las unidades de azucar segun almacen de productos terminados

    ad_fecha1, fecha inicio
    ad_fecha2, fecha final
    as_cod, codigo del producto a evaluar
    as_periodo, 'D'=Diario, 'S'=Semanal, 'M'=Mensual, 'A'=Anual
  */

  ls_almacen           almacen.almacen%type;
  ln_kilos             number ;
  ln_count             number ;

begin

  -- Parametros
  Select l.almacen_pptt into ls_almacen
    from labparam l where reckey = '1';

   ln_kilos := 0 ;

   Select SUM( am.cant_procesada) into ln_kilos
    from vale_mov vm, articulo_mov am, articulo a, articulo_producto ap
    where (vm.cod_origen = am.cod_origen and
           vm.nro_vale = am.nro_vale)
      and vm.tipo_mov = (select oper_ing_prod from logparam where reckey='1')
      and vm.almacen = ls_almacen
      and am.flag_estado <> '0'
      and (vm.fec_registro between ad_fecha1 and ad_fecha2)
      and (am.cod_art = a.cod_art)
      and (am.cod_art = ap.cod_art)
      and ap.cod_prod = as_cod;
--        ;group by a.peso_und ;
   return(ln_kilos);

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      return (0);


end USF_LAB_AZUCAR_UND;
/

prompt
prompt Creating function USF_LAB_AZUCAR_UND_DET
prompt ========================================
prompt
create or replace function cantabria.USF_LAB_AZUCAR_UND_DET(ad_fecha1 in date,
  ad_fecha2 in date, as_cod_art in articulo.cod_art%type)
  return number is

  /*
    Funcion que encuentra las unidades de azucar segun almacen de productos terminados
    ad_fecha1, fecha inicio
    ad_fecha2, fecha final
    as_cod, codigo del producto a evaluar
    as_periodo, 'D'=Diario, 'S'=Semanal, 'M'=Mensual, 'A'=Anual
  */

  ls_almacen           almacen.almacen%type;
  ln_kilos             number;
  ls_ing_prod          labparam.ingreso_pptt%type ;

begin

  -- Parametros
  Select l.almacen_pptt, l.ingreso_pptt
    into ls_almacen, ls_ing_prod
    from labparam l
   where reckey = '1';

   ln_kilos := 0 ;

   Select SUM( am.cant_procesada) into ln_kilos
    from vale_mov vm, articulo_mov am
    where vm.cod_origen = am.cod_origen and
          vm.nro_vale = am.nro_vale and
          vm.almacen = ls_almacen and
          vm.flag_estado <> '0' and
          vm.tipo_mov = ls_ing_prod and
          ( vm.fec_registro between ad_fecha1 and ad_fecha2) and
          am.cod_art = as_cod_art and
          am.flag_estado <> '0' ;

   return(nvl(ln_kilos,0));

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      return (0);

end USF_LAB_AZUCAR_UND_DET;
/

prompt
prompt Creating function USF_LAB_CALCULA_PROM_PROD
prompt ===========================================
prompt
create or replace function cantabria.USF_LAB_CALCULA_PROM_PROD( ad_fini in date, ad_ffin in date,
   as_calculo1 in char, as_calculo2 in char)
return number is


CURSOR c_fecha
IS
SELECT distinct( trunc(lcc.fecha) ) as fechad
FROM   lab_calculo_prod lcc
WHERE  TRUNC(lcc.fecha) between TRUNC(ad_fini) and TRUNC(ad_ffin)
ORDER BY trunc(lcc.fecha) ;


CURSOR c_mov_calc1
 (ad_fecha      lab_calculo_prod.fecha%type )
 IS
  SELECT lcc.dia
    FROM lab_calculo_prod lcc
   WHERE TRUNC(lcc.fecha) = TRUNC(ad_fecha) and
         lcc.cod_calculo = as_calculo1 ;

CURSOR c_mov_calc2
 (ad_fecha      lab_calculo_prod.fecha%type )
 IS
  SELECT lcc.dia
    FROM lab_calculo_prod lcc
   WHERE TRUNC(lcc.fecha) = TRUNC(ad_fecha) and
         lcc.cod_calculo = as_calculo2 ;


ln_calculo         number ;
ln_calculo1        number ;
ln_calculo2        number ;
ln_calculo3        number ;
ln_calculo4        number ;

BEGIN

  -- Funcion que acumula los resultados de un calculo para
  -- un rango de fecha especificado, en funcion al producto de 02 codigos de caculo
ln_calculo  := 0 ;   -- Dato a calcular
ln_calculo1 := 0 ;   -- 1er dato del dia concepto para promedio
ln_calculo2 := 0 ;   -- 2do dato del dia concepto para promedio
ln_calculo3 := 0 ;   -- Suma del 1er dato concepto para promedio
ln_calculo4 := 0 ;   -- Multiplicacion de promedios (factor1 * factor2)

-- Calculo por rango de fecha
FOR c_f in c_fecha LOOP
    ln_calculo1 := 0 ;
    FOR c_m1 in c_mov_calc1(c_f.fechad) LOOP
        ln_calculo1 := NVL(c_m1.dia,0) ;
        ln_calculo3 := ln_calculo3 + NVL(c_m1.dia,0) ;
    END LOOP ;

    ln_calculo2 := 0 ;
    FOR c_m2 in c_mov_calc2(c_f.fechad) LOOP
        ln_calculo2 := c_m2.dia ;
    END LOOP ;

    ln_calculo4 := nvl(ln_calculo4,0) + ( ln_calculo1 * ln_calculo2 ) ;

END LOOP ;

IF ln_calculo3 > 0 THEN
    ln_calculo := ln_calculo4 / ln_calculo3 ;
ELSE
    ln_calculo := 0 ;
END IF ;

return(ln_calculo);

end USF_LAB_CALCULA_PROM_PROD;
/

prompt
prompt Creating function USF_LAB_CALIBRACION
prompt =====================================
prompt
