prompt
create or replace function cantabria.USF_LAB_CARACT_TEMPLA(as_templa in char,  as_caract in char) return number is
  Result number;
  CURSOR C_RESULTADO is
  SELECT to_number(NVL(rtd.resultado,'0')) as ln_dato
    FROM resultados_templa_det rtd
   where rtd.cod_templa=as_templa and
         rtd.cod_caract=as_caract and
