prompt
prompt Creating function USF_LAB_EVALUA_ESPECIFICACION
prompt ===============================================
prompt
create or replace function cantabria.USF_LAB_EVALUA_ESPECIFICACION
  (as_espec in char, as_resul in char)
 return integer is

  ln_Return       integer;
  ln_criterios    number;
  ls_crit1        char(10);
  ls_crit2        char(10);
  ls_oper1        char(2);
  ls_oper2        char(2);
  ls_cad          char(1);
  ln_crit1        number(14,4);
  ln_crit2        number(14,4);
  ln_result       number(14,4);

  v_ErrorNumber   number;
  v_ErrorText     varchar2(200);
begin
  ln_criterios := 0;
  ln_return := 0;
  -- Evalua si especificacion tiene uno o dos criterios
  For j in 1.. LENGTH(as_espec) loop
    IF SUBSTR( as_espec, j,1) = ',' then
       ln_criterios := j;
    end if;
  end loop;

  -- dos criterios
  if ln_criterios >0 then
     for j in 1..ln_criterios - 1loop
         ls_cad := SUBSTR( as_espec,j,1);
         if ls_cad = '<' or ls_Cad = '>' or ls_Cad = '=' then
            ls_oper1 := CONCAT(TRIM(ls_oper1), TRIM(ls_Cad));
         else
            ls_crit1 := CONCAT(TRIM(ls_crit1), TRIM(ls_Cad));
         end if;
     end loop;

     for j in (ln_criterios + 1).. LENGTH(as_espec) loop
         ls_cad := SUBSTR( as_espec,j,1);
         if ls_cad = '<' or ls_Cad = '>' or ls_Cad = '=' then
            ls_oper2 := CONCAT(TRIM(ls_oper2), TRIM(ls_Cad));
         else
            ls_crit2 := CONCAT(TRIM(ls_crit2), TRIM(ls_Cad));
         end if;
     end loop;

     ln_crit1 := TO_NUMBER(ls_crit1);
     ln_crit2 := TO_NUMBER(ls_crit2);
     ln_result := as_resul;

     if ls_oper1 = '>=' and ls_oper2 = '<=' then
        if ln_result >= ln_crit1 and ln_result <= ln_crit2 then
           ln_return := 1;
        end if;
     else
       raise_application_error( -20000, 'no cumplio: ' || ln_result || ' ' ||
         ls_oper1 || ' ' || ln_crit1 || ' and ' || ln_result || ' ' ||
         ls_oper2 || ' ' || ln_crit2 );
     end if;
     null;
  else  -- un solo criterio
     ls_crit1 := '';
     for j in 1..LENGTH(TRIM(as_espec))  loop
         ls_cad := SUBSTR( as_espec,j,1);
         if ls_cad = '<' or ls_Cad = '>' or ls_Cad = '=' then
            ls_oper1 := CONCAT(TRIM(ls_oper1), TRIM(ls_Cad));
         else
            ls_crit1 := CONCAT(TRIM(ls_crit1), TRIM(ls_Cad));
         end if;
     end loop;
     ln_crit1  := TO_NUMBER(ls_crit1);
     ln_result := TO_NUMBER(as_resul);

     if ls_oper1 = '<'  then
        if ln_result < ln_crit1 then
           ln_return := 1;
        end if;
     elsif ls_oper1 = '>'  then
        if ln_result > ln_crit1 then
           ln_return := 1;
        end if;
     elsif ls_oper1 = '<='  then
        if ln_result <= ln_crit1 then
           ln_return := 1;
        end if;
     elsif ls_oper1 = '>='  then
        if ln_result >= ln_crit1 then
           ln_return := 1;
        end if;
     else
       raise_application_error( -20000, 'no cumplio: ' || ln_result || ' ' ||
         ls_oper1 || ' ' || ln_crit1 );
     end if;
--     raise_application_error( -20000, ls_oper1 || ' - ' || ls_oper2 );
  end if;

  return(ln_return);
/*
  exception
    when others then
      v_Errornumber := sqlcode;
      v_Errortext := substr( sqlerrm,1,200);
      raise_application_error( -20000, 'Err: ' || v_Errortext || ' ' || ls_oper1 || ' ' || ls_crit1 || ' ' || as_resul || '  ' || an_vec);
--      raise_application_error(-20000, '.' || ls_crit1 || '.'); */
end USF_LAB_EVALUA_ESPECIFICACION;
/

prompt
prompt Creating function USF_LAB_CLASIFICACION_TEMPLAS
prompt ===============================================
prompt
create or replace function cantabria.USF_LAB_CLASIFICACION_TEMPLAS
(as_templa in templas.cod_templa%type) return varchar2 Is

ls_arubia   tipo_analisis.tipo_analisis%Type;
ls_arefin   tipo_analisis.tipo_analisis%Type;
ls_ablanca  tipo_analisis.tipo_analisis%Type;
ls_calidad  lab_calidad_pt.cod_calidad%Type;
ln_result   Number;
ln_nro_eval Number;
ln_cont     Number;

Cursor c_templa Is
Select lcc.cod_calidad, a.sub_cat_art, rtd.cod_caract, rtd.resultado, lcc.formula, lcp.flag_calidad,
       (Select count(*) From lab_calidad_caract Where cod_calidad = lcc.cod_Calidad) As nro_eval
  from templa_saldo ts, templas t, resultados_templa_det rtd, articulo a,
       lab_calidad_pt lcp, lab_calidad_caract lcc
 where ts.cod_templa   = t.cod_templa
   and ts.cod_templa   = rtd.cod_templa
   And ts.cod_art      = a.cod_art
   And a.sub_cat_art   = lcp.cod_sub_cat
   And lcp.cod_calidad = lcc.cod_calidad
   And lcc.cod_caract  = rtd.cod_caract
   and ts.saldo > 0
   and rtd.tipo_analisis in (ls_arubia, ls_arefin, ls_ablanca)
   And trim(ts.cod_templa) = trim(as_templa)
   And lcp.flag_estado = '1'
   And lcc.flag_estado = '1'
Group By lcc.cod_calidad, a.sub_cat_art, rtd.cod_caract, rtd.resultado, lcc.formula, lcp.flag_calidad
Order By lcp.flag_calidad Asc, nro_eval Desc, lcc.cod_calidad Asc;

c_t c_templa%Rowtype;

Result lab_calidad_pt.descripcion%Type;

Begin

Select l.ana_arubia, l.ana_ref_dom, l.ana_ablanca
  into ls_arubia, ls_arefin, ls_ablanca
  from labparam l where reckey = '1';

Result := 'SIN CLASIFICACION';

Begin
     Select lcp.descripcion
       Into Result
       From lab_calidad_pt_cambio l, lab_calidad_pt lcp
      Where l.cod_calidad = lcp.cod_calidad
        And trim(l.cod_templa) = trim(as_templa)
        And l.fecha = (Select max(fecha) From lab_calidad_pt_cambio Where cod_templa = as_templa);
Exception
     When NO_DATA_FOUND Then

     open c_templa;
     fetch c_templa into c_t;
     while c_templa%found Loop

         ln_cont     := 0;
         ls_calidad  := c_t.cod_calidad;
         ln_nro_eval := c_t.nro_eval;

         While ls_calidad = c_t.cod_calidad And c_templa%Found Loop

               ln_result := usf_lab_evalua_especificacion(c_t.formula,c_t.resultado);

               If ln_result = 1 Then
                  ln_cont := ln_cont + 1;
               End If;

         Fetch c_templa Into c_t;
         End Loop;

         If ln_cont = ln_nro_eval Then

            Select lcp.descripcion
              Into Result
              From lab_calidad_pt lcp
             Where lcp.cod_calidad = ls_calidad;

            Exit;

         End If;

     End Loop;

End;

return(Result);

end USF_LAB_CLASIFICACION_TEMPLAS;
/

prompt
prompt Creating function USF_LAB_CLASIFIC_TEMPLAS_COD
prompt ==============================================
prompt
create or replace function cantabria.USF_LAB_CLASIFIC_TEMPLAS_COD
(as_templa in templas.cod_templa%type) return Char Is

ls_arubia   tipo_analisis.tipo_analisis%Type;
ls_arefin   tipo_analisis.tipo_analisis%Type;
ls_ablanca  tipo_analisis.tipo_analisis%Type;
ls_calidad  lab_calidad_pt.cod_calidad%Type;
ln_result   Number;
ln_nro_eval Number;
ln_cont     Number;

Cursor c_templa Is
Select lcc.cod_calidad, a.sub_cat_art, rtd.cod_caract, rtd.resultado, lcc.formula, lcp.flag_calidad,
       (Select count(*) From lab_calidad_caract Where cod_calidad = lcc.cod_Calidad) As nro_eval
  from templa_saldo ts, templas t, resultados_templa_det rtd, articulo a,
       lab_calidad_pt lcp, lab_calidad_caract lcc
 where ts.cod_templa   = t.cod_templa
   and ts.cod_templa   = rtd.cod_templa
   And ts.cod_art      = a.cod_art
   And a.sub_cat_art   = lcp.cod_sub_cat
   And lcp.cod_calidad = lcc.cod_calidad
   And lcc.cod_caract  = rtd.cod_caract
   and ts.saldo > 0
   and rtd.tipo_analisis in (ls_arubia, ls_arefin, ls_ablanca)
   And trim(ts.cod_templa) = Trim(as_templa)
   And lcp.flag_estado = '1'
   And lcc.flag_estado = '1'
Group By lcc.cod_calidad, a.sub_cat_art, rtd.cod_caract, rtd.resultado, lcc.formula, lcp.flag_calidad
Order By lcp.flag_calidad Asc, nro_eval Desc, lcc.cod_calidad Asc;

c_t c_templa%Rowtype;

Result lab_calidad_pt.cod_calidad%Type;

Begin

Select l.ana_arubia, l.ana_ref_dom, l.ana_ablanca
  into ls_arubia, ls_arefin, ls_ablanca
  from labparam l where reckey = '1';

Begin
     Select l.cod_calidad
       Into Result
       From lab_calidad_pt_cambio l
      Where trim(l.cod_templa) = Trim(as_templa)
        And l.fecha = (Select max(fecha) From lab_calidad_pt_cambio Where cod_templa = as_templa);
Exception
     When NO_DATA_FOUND Then

     open c_templa;
     fetch c_templa into c_t;
     while c_templa%found Loop

         ln_cont     := 0;
         ls_calidad  := c_t.cod_calidad;
         ln_nro_eval := c_t.nro_eval;

         While ls_calidad = c_t.cod_calidad And c_templa%Found Loop

               ln_result := usf_lab_evalua_especificacion(c_t.formula,c_t.resultado);

               If ln_result = 1 Then
                  ln_cont := ln_cont + 1;
               End If;

         Fetch c_templa Into c_t;
         End Loop;

         If ln_cont = ln_nro_eval Then

            Result := ls_calidad;

            Exit;

         End If;

     End Loop;

End;

return(Result);

end USF_LAB_CLASIFIC_TEMPLAS_COD;
/

