prompt
prompt Creating function USF_LAB_DIAS_A_HORAS
prompt ======================================
prompt
create or replace function cantabria.usf_lab_dias_a_horas(ad_dia_may in date, ad_dia_men in date) return number is
  Result number(10,4);
begin
  Result := 24 * (ad_dia_may - ad_dia_men ) ;
  -- Solo considera dif. fechas de 10 anos como maximo
  return(Result);
end usf_lab_dias_a_horas;
/

prompt
prompt Creating function USF_LAB_DIAS_A_HORAS_INCID
prompt ============================================
prompt
create or replace function cantabria.usf_lab_dias_a_horas_incid(
  ad_dia_men in date, ad_dia_may in date,
  as_opcion in char) return number is

  ln_horas_totales   number(10,4) ;
  ln_horas_program   number(10,4) ;
  ln_horas_perdidas  number(10,4) ;

  Result number(10,4);

  /* as_opcion:
     T = tiempo total (P175)
     G = horas programadas  (P177)
     H = tiempo habil (P189)
     P = tiempo perdido
     M = tiempo de molienda
     D = dias de molienda
  */
begin

  -- Horas totales
  ln_horas_totales := 24 * (ad_dia_may + 1 - ad_dia_men ) ;

  -- horas perdidas programadas
 SELECT sum(nvl(inf.dia,0))
    INTO ln_horas_program
    FROM incidencias_fabrica inf, incidencias_dma ind
   WHERE inf.cod_incidencia = ind.cod_incidencia and
         ind.flag_grupo <> '1' and
         trunc(inf.fecha) between trunc(ad_dia_men) and trunc(ad_dia_may);

  -- horas perdidas no programadas
  SELECT sum(nvl(inf.dia,0))
    INTO ln_horas_perdidas
    FROM incidencias_fabrica inf, incidencias_dma ind
   WHERE inf.cod_incidencia = ind.cod_incidencia and
         ind.flag_grupo = '1' and
         trunc(inf.fecha) between trunc(ad_dia_men) and trunc(ad_dia_may) ;

  ln_horas_totales  := nvl(ln_horas_totales,0) ;
  ln_horas_program  := nvl(ln_horas_program,0) ;
  ln_horas_perdidas := nvl(ln_horas_perdidas,0) ;

  IF as_opcion='T' then
     -- tiempo total
     Return(ln_horas_totales);
  ELSIF as_opcion='G' then
     -- horas perdidas programadas
     RETURN( ln_horas_program ) ;
  ELSIF as_opcion='H' then
     -- tiempo habil
     RETURN( ln_horas_totales - ln_horas_program ) ;
  ELSIF as_opcion='P' then
     -- tiempo total perdido
--     RETURN( ln_horas_program + ln_horas_perdidas ) ;
     RETURN( ln_horas_perdidas ) ;
  ELSIF as_opcion='M' then
     -- tiempo molienda
     RETURN( ln_horas_totales - ln_horas_program - ln_horas_perdidas ) ;
  ELSIF as_opcion='D' then
     -- dias de molienda
     RETURN((ln_horas_totales - ln_horas_program )/24) ;
  END IF ;
  -- Solo considera dif. fechas de 10 anos como maximo
  --return(Result);
end usf_lab_dias_a_horas_incid;
/

prompt
prompt Creating function USF_LAB_DIAS_TRANSCURRIDOS
prompt ============================================
prompt
create or replace function cantabria.USF_LAB_DIAS_TRANSCURRIDOS(ad_fecha in date, as_tipo in char) return number is
  Result number;

  ln_sem                     calendario_produccion.semana%type;
  ln_mes                     calendario_produccion.mes%type;
  ln_ano                     calendario_produccion.ano%type;

  ln_dias                    number;
  ld_fecha                   date;

begin

  -- Encuentra los dias transcurridos dado una fecha, segun periodo (Semanal, mensual, anual)

  if as_tipo = 'S' then
     null;
  end if;
  if as_tipo = 'M' then
     ln_dias := TO_NUMBER( TO_CHAR(ad_fecha, 'DD'));
  end if;
  if as_tipo = 'A' then
     ld_fecha := TRUNC( TO_DATE( '01/01/' || TO_CHAR(ad_fecha, 'yyyy'), 'dd/mm/yyyy'));
     ln_dias :=  TRUNC( ad_fecha) - ld_fecha;
  end if;

  -- Busca semana, mes y a?o al que pertenece
/*  Select c.semana, c.mes, c.ano into ln_sem, ln_mes, ln_ano
     from calendario_produccion c
     where TRUNC( c.fecha_prod) = TRUNC(ad_fecha);

  -- Busca rango fechas de inicio y fin para la semana
  Select MIN(c.del_dia) into ld_sem_ini
     from calendario_produccion c Where c.semana = ln_sem;

  -- Busca rango fechas de inicio y fin para el mes
  Select MIN(c.del_dia) into ld_mes_ini
     from calendario_produccion c Where c.mes = ln_mes;

  -- Busca rango fechas de inicio y fin para el ano
  Select MIN(c.del_dia) into ld_ano_ini
     from calendario_produccion c Where c.ano = ln_ano;
  */

  return(ln_dias);
end USF_LAB_DIAS_TRANSCURRIDOS;
/

prompt
prompt Creating function USF_LAB_GET_CALC_CAMPO_GEN
prompt ============================================
prompt
create or replace function cantabria.USF_LAB_GET_CALC_CAMPO_GEN(
   ad_fecha in date, as_cod in char )
   return number is

  ln_res    lab_calculo_campo.dia%type;
  ln_count  number;
begin

  Select count(c.dia) into ln_count
        from lab_calculo_campo c
        where TRUNC(c.fecha) = TRUNC( ad_fecha) and
              c.cod_calculo = as_cod ;
  if ln_count > 0 then
     Select avg(c.dia) into ln_res
        from lab_calculo_campo c
        where TRUNC(c.fecha) = TRUNC( ad_fecha) and
              c.cod_calculo = as_cod ;
  else
    ln_res := 0;
  end if;
  return(ln_res);
  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN 0 ;
end USF_LAB_GET_CALC_CAMPO_GEN;
/

prompt
prompt Creating function USF_LAB_GET_CALC_CORTE_ALL
prompt ============================================
prompt
create or replace function cantabria.USF_LAB_GET_CALC_CORTE_ALL(
   ad_fecha in date, as_corr in char, as_cod in char, as_tipo in char,
   as_quemado in char,
   an_dia out number, an_sem out number,
   an_mes out number, an_ano out number)
   return number is

  ln_res    lab_calculo_campo.dia%type;
  ln_count  Number(2) ;
begin

     Select count(*) into ln_count
        from lab_calculo_campo c
        where TRUNC(c.fecha) = TRUNC(ad_fecha) and
        c.corr_corte = as_corr and c.cod_calculo = as_cod and
        c.flag_tipo = as_tipo and c.flag_campo_sin_qm = as_quemado;

     IF ln_count > 0 THEN
        Select nvl(c.dia,0), nvl(c.semana,0), nvl(c.mes,0), nvl(c.ano,0)
        into an_dia, an_sem, an_mes, an_ano
          from lab_calculo_campo c
          where TRUNC(c.fecha) = TRUNC(ad_fecha) and
                c.corr_corte = as_corr and c.cod_calculo = as_cod and
                c.flag_tipo = as_tipo and c.flag_campo_sin_qm = as_quemado;
     ELSE
        Select nvl(c.dia,0), nvl(c.semana,0), nvl(c.mes,0), nvl(c.ano,0)
        into an_dia, an_sem, an_mes, an_ano
         from lab_calculo_campo c
        where TRUNC(c.fecha) = TRUNC(ad_fecha) and
              c.corr_corte = as_corr and c.cod_calculo = as_cod and
              c.flag_tipo = 'M' and c.flag_campo_sin_qm = as_quemado;
     END IF ;

     return(ln_res);


  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN 0;

end USF_LAB_GET_CALC_CORTE_ALL;
/

prompt
prompt Creating function USF_LAB_GET_CALCULO_CAMPO
prompt ===========================================
prompt
create or replace function cantabria.USF_LAB_GET_CALCULO_CAMPO(
   ad_fecha in date, as_campo in char, as_cod in char, as_tipo in char,
   as_quemado in char )
   return number is

  ln_res    lab_calculo_campo.dia%type;
  ln_count  number;
begin

  Select count(c.dia) into ln_count
        from lab_calculo_campo c, campo_ciclo cc
        where TRUNC(c.fecha) = TRUNC( ad_fecha) and
        c.corr_corte = cc.corr_corte and
        cc.cod_campo = as_campo and c.cod_calculo = as_cod and
        c.flag_tipo = as_tipo and c.flag_campo_sin_qm = as_quemado;
  if ln_count = 1 then
     Select c.dia into ln_res
        from lab_calculo_campo c, campo_ciclo cc
        where TRUNC(c.fecha) = TRUNC( ad_fecha) and
        c.corr_corte = cc.corr_corte and
        cc.cod_campo = as_campo and c.cod_calculo = as_cod and
        c.flag_tipo = as_tipo and c.flag_campo_sin_qm = as_quemado;
  elsif ln_count > 1 then
--    raise_application_error( -20000, as_campo);
    ln_res := 0;
  end if;
  return(ln_res);
  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN 0 ;
end USF_LAB_GET_CALCULO_CAMPO;
/

prompt
prompt Creating function USF_LAB_GET_CALCULO_CAMPO_ALL
prompt ===============================================
prompt
create or replace function cantabria.USF_LAB_GET_CALCULO_CAMPO_ALL(
   ad_fecha in date, as_cod in char, as_tipo in char,
   as_corr in char, an_dia out number, an_sem out number,
   an_mes out number, an_ano out number)
   return number is

  CURSOR c_calculo is
  Select c.dia, c.semana, c.mes, c.ano
    into an_dia, an_sem, an_mes, an_ano
    from lab_calculo_campo c
   where TRUNC(c.fecha) = TRUNC( ad_fecha) and
         TRIM(c.cod_calculo) = TRIM(as_cod) and
         c.corr_corte = as_corr and c.flag_tipo = as_tipo;

begin

FOR c_c IN c_calculo LOOP
  an_dia := c_c.dia ;
  an_mes := c_c.mes ;
  an_sem := c_c.semana ;
  EXIT ;
END LOOP ;

-- Anteriormente estaba asi, solo el select, sin for
/*
  Select c.dia, c.semana, c.mes, c.ano into an_dia, an_sem,
     an_mes, an_ano from lab_calculo_campo c
       where TRUNC(c.fecha) = TRUNC( ad_fecha) and
       TRIM(c.cod_calculo) = TRIM(as_cod) and
       c.corr_corte = as_corr and c.flag_campo_sin_qm = as_tipo;
       -- c.flag_tipo
*/

  return(1);
  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN 0 ;
end USF_LAB_GET_CALCULO_CAMPO_ALL;
/

prompt
prompt Creating function USF_LAB_GET_CALCULO_CORTE
prompt ===========================================
prompt
create or replace function cantabria.USF_LAB_GET_CALCULO_CORTE(
   ad_fecha in date, as_corr in char, as_cod in char, as_tipo in char,
   as_periodo in char, as_quemado in char)
   return number is

  ln_res    lab_calculo_campo.dia%type;
  ln_count  Number(2) ;
begin

  if as_periodo = 'D' then

     Select count(*) into ln_count
        from lab_calculo_campo c
        where TRUNC(c.fecha) = TRUNC(ad_fecha) and
        c.corr_corte = as_corr and c.cod_calculo = as_cod and
        c.flag_tipo = as_tipo and c.flag_campo_sin_qm = as_quemado;

     IF ln_count > 0 THEN
        Select nvl(c.dia,0) into ln_res
          from lab_calculo_campo c
          where TRUNC(c.fecha) = TRUNC(ad_fecha) and
                c.corr_corte = as_corr and c.cod_calculo = as_cod and
                c.flag_tipo = as_tipo and c.flag_campo_sin_qm = as_quemado;
     ELSE
        Select nvl(c.dia,0) into ln_res
         from lab_calculo_campo c
        where TRUNC(c.fecha) = TRUNC(ad_fecha) and
              c.corr_corte = as_corr and c.cod_calculo = as_cod and
              c.flag_tipo = 'M' and c.flag_campo_sin_qm = as_quemado;
     END IF ;

     return(ln_res);

  end if;

  if as_periodo = 'S' then
     Select c.semana into ln_res
        from lab_calculo_campo c
        where TRUNC(c.fecha) = TRUNC(ad_fecha) and
        c.corr_corte = as_corr and c.cod_calculo = as_cod and
        c.flag_tipo = as_tipo and c.flag_campo_sin_qm = as_quemado;
     return(ln_res);
  end if;
  if as_periodo = 'M' then
     Select c.mes into ln_res
        from lab_calculo_campo c
        where TRUNC(c.fecha) = TRUNC( ad_fecha)  and
        c.corr_corte = as_corr and c.cod_calculo = as_cod and
        c.flag_tipo = as_tipo and c.flag_campo_sin_qm = as_quemado;
     return(ln_res);
  end if;
  if as_periodo = 'A' then
     Select c.ano into ln_res
        from lab_calculo_campo c
        where TRUNC(c.fecha) = TRUNC(ad_fecha) and
        c.corr_corte = as_corr and c.cod_calculo = as_cod and
        c.flag_tipo = as_tipo and c.flag_campo_sin_qm = as_quemado;
     return(ln_res);
  end if;

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN 0;

end USF_LAB_GET_CALCULO_CORTE;
/

prompt
prompt Creating function USF_LAB_GET_CALCULO_PROD
prompt ==========================================
prompt
create or replace function cantabria.USF_LAB_GET_CALCULO_PROD(
   ad_fecha in date, as_cod in char, as_tipo in char, as_modo in char)
   return number is

   ln_res    lab_calculo_prod.mes%type;

begin



--  Select c.dia, c.semana, c.mes, c.ano into an_dia, an_sem, an_mes, an_ano
  if as_modo = 'D' then
     Select c.dia into ln_res from lab_calculo_prod c
       where TRUNC(c.fecha) = TRUNC( ad_fecha) and
       TRIM(c.cod_calculo) = TRIM(as_cod) and
       c.flag_tipo = as_tipo;
  end if;
  if as_modo = 'S' then
     Select NVL(c.semana,0) into ln_res from lab_calculo_prod c
       where TRUNC(c.fecha) = TRUNC( ad_fecha) and
       TRIM(c.cod_calculo) = TRIM(as_cod) and
       c.flag_tipo = as_tipo;
  end if;
  if as_modo = 'M' then
     Select c.mes into ln_res from lab_calculo_prod c
       where TRUNC(c.fecha) = TRUNC( ad_fecha) and
       TRIM(c.cod_calculo) = TRIM(as_cod) and
       c.flag_tipo = as_tipo;
  end if;

  if as_modo = 'A' then
     Select c.ano into ln_res from lab_calculo_prod c
       where TRUNC(c.fecha) = TRUNC( ad_fecha) and
       TRIM(c.cod_calculo) = TRIM(as_cod) and
       c.flag_tipo = as_tipo;
  end if;
  return(ln_res);
  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN 0 ;
end USF_LAB_GET_CALCULO_PROD;
/

