prompt
prompt Creating function USF_LAB_HORAS_PERDIDAS
prompt ========================================
prompt
create or replace function cantabria.USF_LAB_HORAS_PERDIDAS(
  ad_fecha1 in date, ad_fecha2 in date)
  return number is

  ln_int   number(8);
  ln_dif   number(25,16);
  ln_res   number(8,2);
  ln_min   number(25,16);
  dif      number(25,16);
  ln_count       number;

begin

  Select count(r.cod_incidencia) INTO ln_count
    from ocurrencias r
    where r.fecha_ini between ad_fecha1 and ad_fecha2 ;
  if ln_count = 0 then
     insert into tt_lab_resul_proceso(observacion)
       values('Atencion, no existe informacion de incidencias de fabrica');
--     Raise_application_error( -20000, 'Atencion, no existe informacion de incidencias de fabrica');
     return 0;
  end if;
  Select sum(r.fecha_fin - r.fecha_ini) INTO dif
    from ocurrencias r
    where r.fecha_ini between ad_fecha1 and ad_fecha2 ;
/*
  ln_min := dif * 24;
  ln_int := trunc( ln_min,0);
  ln_dif := ln_min - ln_int;
  ln_res := ln_int + (ln_dif * .6);
*/
--  return(ln_res);
  return (dif);
end USF_LAB_HORAS_PERDIDAS;
/

prompt
prompt Creating function USF_LAB_ING_VARIOS_VALOR_RANGO
prompt ================================================
prompt
create or replace function cantabria.USF_LAB_ING_VARIOS_VALOR_RANGO
(ad_fec_ini in date,
 ad_fec_fin in date,
 as_producto in tipo_producto.cod_prod%Type) return number Is

Result number;
ln_contador       Number;
ln_cantidad       Number;
ln_cantidad_total Number;

Cursor c_fechas Is
Select * From tt_lab_rango_fechas;

begin

Select Count(*)
  Into ln_contador
  From unidades_producidas up
 Where up.cod_prod = as_producto;

ln_cantidad       := 0;
ln_cantidad_total := 0;

If ln_contador = 1 Then

   Insert Into tt_lab_rango_fechas ( fecha_prod, del_dia, al_dia )
   Select cp.fecha_prod, cp.del_dia, cp.al_dia
     From calendario_produccion cp
    Where cp.fecha_prod >= trunc(ad_fec_ini)
      And cp.fecha_prod <= trunc(ad_fec_fin);

   For c_f In c_fechas Loop

       Begin
            Select nvl(up.cantidad,0)
              Into ln_cantidad
              From unidades_producidas up
             Where up.fecha_prod >= c_f.del_dia
               And up.fecha_prod <= c_f.al_dia
               And up.cod_prod = as_producto;
       Exception
              When NO_DATA_FOUND Then
                   ln_cantidad := 0;
       End;

       If ln_cantidad > 0 Then
          Exit;
       End If;

   End Loop;

   Result := nvl(ln_cantidad,0);

Elsif ln_contador > 1 Then

  ln_contador := 0;

  Insert Into tt_lab_rango_fechas ( fecha_prod, del_dia, al_dia )
   Select cp.fecha_prod, cp.del_dia, cp.al_dia
     From calendario_produccion cp
    Where cp.fecha_prod >= trunc(ad_fec_ini)
      And cp.fecha_prod <= trunc(ad_fec_fin);

   For c_f In c_fechas Loop

       Begin
            Select nvl(up.cantidad,0)
              Into ln_cantidad
              From unidades_producidas up
             Where up.fecha_prod >= c_f.del_dia
               And up.fecha_prod <= c_f.al_dia
               And up.cod_prod = as_producto;
       Exception
              When NO_DATA_FOUND Then
                   ln_cantidad := 0;
       End;

   If ln_cantidad > 0 Then
      ln_contador := ln_contador + 1;
      ln_cantidad_total := ln_cantidad_total + ln_cantidad;
   End If;

   End Loop;

   Result := nvl(ln_cantidad_total / ln_contador,0);

End If;

return(Result);

end USF_LAB_ING_VARIOS_VALOR_RANGO;
/

prompt
prompt Creating function USF_LAB_INSERT_CALCULO_CAMPO
prompt ==============================================
prompt
create or replace function cantabria.USF_LAB_INSERT_CALCULO_CAMPO(
   ad_fecha in date, as_corr in char, as_cod in char,
   an_dia in number, as_propiedad in char, as_quema in char) return integer is

  ln_count   number;
begin

  Select count(corr_corte) into ln_count from
     lab_calculo_campo l where l.fecha = ad_fecha and
     l.corr_corte = as_corr and l.cod_calculo = as_cod and
     l.flag_campo_sin_qm = as_quema;

  if ln_count > 1 then
     raise_application_error( -20000, 'llave duplicada ' || as_corr || ' - calc. ' || as_cod);
  else
  insert into lab_calculo_campo(fecha, corr_corte,
    cod_calculo, dia, flag_tipo, flag_propiedad, flag_campo_sin_qm)
        values( ad_fecha, as_corr, as_cod, round(NVL(an_dia,0),7), 'P',
        as_propiedad, NVL( as_quema,0));
  end if;
  return(1);
end USF_LAB_INSERT_CALCULO_CAMPO;
/

prompt
prompt Creating function USF_LAB_INSERT_CALCULO_PROD_A
prompt ===============================================
prompt
create or replace function cantabria.USF_LAB_INSERT_CALCULO_PROD_A(
   ad_fecha in date, as_cod in char, an_dia in number, an_sem in number,
   an_mes in number, an_ano in number ) return integer is

  ln_dia       lab_calculo_prod.dia%type;
  ln_sem       lab_calculo_prod.semana%type;
  ln_mes       lab_calculo_prod.mes%type;
  ln_ano       lab_calculo_prod.ano%type;
begin

  -- Inserta o actualiza datos de producto en un solo registro (dia, sem, mes, fecha)
  ln_dia := NVL( an_dia,0);
  ln_sem := NVL( an_sem,0);
  ln_mes := NVL( an_mes,0);
  ln_ano := NVL( an_ano,0);

  UPDATE lab_calculo_prod l set dia = NVL( dia,0) + ln_dia, semana = NVL( semana,0) + ln_sem,
     mes = NVL( mes,0) + ln_mes, ano = NVL( ano,0) + ln_ano
     where TRUNC( fecha) = TRUNC( ad_fecha) and l.cod_calculo = as_cod and
     l.flag_tipo = 'P';
  IF SQL%NOTFOUND THEN
     insert into lab_calculo_prod(fecha, cod_calculo, dia, semana, mes, ano, flag_tipo)
        values( ad_fecha, as_cod, ln_dia, ln_sem, ln_mes, ln_ano, 'P');
  END IF;
  return(1);
end USF_LAB_INSERT_CALCULO_PROD_A;
/

prompt
prompt Creating function USF_LAB_INSERT_LAB_CALCULO
prompt ============================================
prompt
create or replace function cantabria.USF_LAB_INSERT_LAB_CALCULO(
   an_orden in number, an_nivel in number, as_desc_nivel in char,
   as_cod in char, ad_fecha in date )
   return integer is

  Result integer;
  ls_desc   lab_calculo.desc_calculo%type;
  ln_dia    lab_calculo_prod.dia%type;
  ln_sem    lab_calculo_prod.semana%type;
  ln_mes    lab_calculo_prod.mes%type;
  ln_ano    lab_calculo_prod.ano%type;
  ln_count  number;
begin

  Select COUNT(cl.dia) into ln_count
    from lab_calculo_prod cl
    where TRUNC( cl.fecha ) = ad_fecha and cl.cod_calculo = as_cod;
  if ln_count > 0 then
     Select l.desc_calculo, cl.dia, cl.semana, cl.mes, cl.ano
        into ls_desc, ln_dia, ln_sem, ln_mes, ln_ano
        from lab_calculo_prod cl, lab_calculo l
        where cl.cod_calculo = l.cod_calculo and
        TRUNC( cl.fecha ) = ad_fecha and
        cl.cod_calculo = as_cod;
     insert into tt_lab_calculo(orden, nivel, desc_nivel, concepto,
        diario, semanal, mensual, anual)
        values(an_orden, an_nivel, as_desc_nivel, ls_desc, ln_dia, ln_sem,
        ln_mes, ln_ano);
  else
     insert into tt_lab_resul_proceso(fecha, observacion)
       values(ad_fecha, 'No existe calculo ' || as_cod);
--     Raise_application_error( -20000, 'No existe calculo ' || as_cod);
  end if;
  return(1);
end USF_LAB_INSERT_LAB_CALCULO;
/

prompt
prompt Creating function USF_LAB_JAVARATIO
prompt ===================================
prompt
create or replace function cantabria.USF_LAB_JAVARATIO(an_pol in number)
  return number is

  ln_increm    number;
  ln_ret       number;
  ln_count     number;
begin

  Select Count( j.incremento) into ln_count
     from factor_java_ratio j
     where j.desde <= an_pol and j.hasta >= an_pol;
  if ln_count = 0 then
--     Raise_application_error( -20000, 'Atencion, No existe java ratio para este pol' || an_pol);
     insert into tt_lab_resul_proceso( observacion)
       values( 'No existe java ratio para este pol' || an_pol);
  else
     Select NVL( j.incremento, 0) into ln_increm
     from factor_java_ratio j
     where j.desde <= an_pol and j.hasta >= an_pol;
  end if;

  return(ln_increm);
end USF_LAB_JAVARATIO;
/

prompt
prompt Creating function USF_LAB_KG_AZUCAR_RES
prompt =======================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_LAB_KG_AZUCAR_RES(
   ad_fecha_ini in date, ad_fecha_fin in date ) return number is

-- Funcion que permite registrar las TON POL AZUCAR
CURSOR c1 is
SELECT distinct(rg.grupo) as cod_calculo
  FROM reportes r, rpt_grupo rg, rpt_subgrupo rsg, articulo a
 WHERE r.reporte = rg.reporte and
       rg.grupo = rsg.grupo and
       rsg.subgrupo = a.sub_cat_art and
       r.reporte='KGAZURES'
ORDER BY rg.grupo ;

CURSOR c2(as_grupo lab_calculo.cod_calculo%type) is
SELECT a.cod_art, rsg.descripcion
  FROM reportes r, rpt_grupo rg, rpt_subgrupo rsg, articulo a
 WHERE r.reporte = rg.reporte and
       rg.grupo = rsg.grupo and
       rg.grupo = as_grupo and
       rsg.subgrupo = a.sub_cat_art and
       r.reporte='KGAZURES'
ORDER BY a.cod_art ;

CURSOR c3(as_cod_art  articulo.cod_art%type, as_almacen  almacen.almacen%type, as_tipo_mov articulo_mov_tipo.tipo_mov%type) is
Select SUM( am.cant_procesada) * a.peso_und as kilos
  from vale_mov vm, articulo_mov am, articulo a
 where vm.cod_origen = am.cod_origen and
       vm.nro_vale = am.nro_vale and
       vm.tipo_mov = as_tipo_mov and
       vm.almacen = as_almacen and
       (vm.fec_registro between ad_fecha_ini and ad_fecha_fin) and
       am.flag_estado <> '0' and
       am.cod_art = a.cod_art and
       a.cod_art = as_cod_art
group by a.peso_und ;

ls_almacen               labparam.almacen_pptt%type ;
ls_tipo_mov              labparam.ingreso_pptt%type ;
ln_cantidad              articulo_mov.cant_procesada%type ;
ln_toneladas             articulo_mov.cant_procesada%type ;
ln_tot_ton               articulo_mov.cant_procesada%type ;
ln_dia                   lab_calculo_prod.dia%type ;
ln_count                 number(3) ;
ls_cod_calculo           lab_calculo.cod_calculo%type ;
ln_ton_pol_miel_b_azu    Number(17,7);

BEGIN

SELECT l.almacen_pptt, l.ingreso_pptt
  INTO ls_almacen, ls_tipo_mov
  FROM labparam l
 WHERE l.reckey='1' ;

ln_tot_ton := 0 ;

FOR rc1 IN c1 LOOP
    ln_toneladas := 0 ;
    FOR rc2 IN c2(rc1.cod_calculo) LOOP
        ln_cantidad := 0 ;
        ls_cod_calculo := SUBSTR(rc2.descripcion,1,4) ;
        FOR rc3 IN c3(rc2.cod_art, ls_almacen, ls_tipo_mov) LOOP
            ln_cantidad := ln_cantidad + rc3.kilos ;
        END LOOP ;
        ln_toneladas := ln_toneladas + ln_cantidad/1000 ;
    END LOOP ;

    SELECT count(*)
      INTO ln_count
      FROM lab_calculo_prod l
     WHERE l.fecha = ad_fecha_ini AND l.cod_calculo = rc1.cod_calculo ;

    IF ln_count > 0 THEN
       SELECT l.dia
         INTO ln_dia
         FROM lab_calculo_prod l
        WHERE l.fecha = ad_fecha_ini AND l.cod_calculo = rc1.cod_calculo ;
    ELSE
       ln_dia := 0 ;
    END IF ;

    UPDATE lab_calculo_prod l
    SET l.dia = ( nvl(l.dia,0) + ln_toneladas*ln_dia/100 )
    WHERE l.fecha = ad_fecha_ini AND l.cod_calculo = ls_cod_calculo ;

    IF SQL%NOTFOUND THEN
       INSERT INTO lab_calculo_prod(fecha, cod_calculo, dia, semana, mes, ano, flag_tipo)
       VALUES (ad_fecha_ini, ls_cod_calculo, ln_toneladas*ln_dia/100, 0, 0, 0, 'P' ) ;
    END IF ;

    ln_tot_ton := ln_tot_ton + ln_toneladas*ln_dia/100 ;

END LOOP ;

-- Calculo de Azucar rubia en miel b (a pedido de laboratorio se tenia que sumar con los demas calculos
-- que ya estaban involucrados en el calculo P280)
ln_ton_pol_miel_b_azu := nvl(USF_LAB_AZUCAR_RUBIA_MIELB(ad_fecha_ini, ad_fecha_fin, 'P276'),0);
-- Fin calculo

ln_tot_ton := ln_tot_ton + ln_ton_pol_miel_b_azu;

UPDATE lab_calculo_prod l
   SET l.dia = ( nvl(l.dia,0) + ln_tot_ton )
 WHERE l.fecha = ad_fecha_ini AND l.cod_calculo = 'P280' ;
-- ton pol azucar
IF SQL%NOTFOUND THEN
   INSERT INTO lab_calculo_prod(fecha, cod_calculo, dia, semana, mes, ano, flag_tipo)
   VALUES (ad_fecha_ini, 'P280', ln_tot_ton/100, 0, 0, 0, 'P' ) ;
END IF ;

return(ln_tot_ton);

end USF_LAB_KG_AZUCAR_RES;
/

prompt
prompt Creating function USF_LAB_KG_AZUCAR_X_TIPO
prompt ==========================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_LAB_KG_AZUCAR_X_TIPO
(as_tipo1  proveedor.flag_estado%type,
 as_tipo2  proveedor.flag_estado%type )
return number is

-- as_tipo1 => K=Kilogramos, P=Kilogramos Pol
-- as_tipo2 => T=total azucar, R=total refinada, U=total rubia, B=total blanca

CURSOR c_und_kgr is
SELECT tt.cod_calculo_und, tt.cod_calculo_kgr, tt.cod_calculo_kgr_pol,
       tt.cantidad_und, tt.cantidad_kgr, tt.cod_calculo_porc_pol
FROM tt_lab_calculo_dia_azucar tt ;

ln_cant_kgr              articulo_mov.cant_procesada%type ;

BEGIN

ln_cant_kgr := 0 ;
-- Registrando informacion de azucar, segun und y kgr
FOR c_uk IN c_und_kgr LOOP
    -- Caso kilogramos
    IF as_tipo1 = 'K' THEN
       -- total de azucar
       IF as_tipo2 = 'T' THEN
          ln_cant_kgr := ln_cant_kgr + c_uk.cantidad_kgr ;
       END IF ;

       -- total refinada
       IF as_tipo2 = 'R' THEN
          IF ( c_uk.cod_calculo_kgr='P331' OR
               c_uk.cod_calculo_kgr='P332' OR
               c_uk.cod_calculo_kgr='P333' OR
               c_uk.cod_calculo_kgr='P339' OR
               c_uk.cod_calculo_kgr='P344' ) THEN

               ln_cant_kgr := ln_cant_kgr + c_uk.cantidad_kgr ;
          END IF ;
       END IF ;

       -- total blanca
       IF as_tipo2 = 'B' THEN
          IF ( c_uk.cod_calculo_kgr='P341' OR
               c_uk.cod_calculo_kgr='P335' ) THEN

               ln_cant_kgr := ln_cant_kgr + c_uk.cantidad_kgr ;
          END IF ;
       END IF ;

       -- total rubia
       IF as_tipo2 = 'U' THEN
          IF ( c_uk.cod_calculo_kgr='P336' OR
               c_uk.cod_calculo_kgr='P342' OR
               c_uk.cod_calculo_kgr='P343' OR
               c_uk.cod_calculo_kgr='P338' ) THEN

               ln_cant_kgr := ln_cant_kgr + c_uk.cantidad_kgr ;
          END IF ;
       END IF ;
    END IF ;

    -- Caso kilogramos pol
    IF as_tipo1 = 'P' THEN
       -- total de azucar
       IF as_tipo2 = 'T' THEN
          ln_cant_kgr := ln_cant_kgr + c_uk.cantidad_kgr ;
       END IF ;

       -- total refinada
       IF as_tipo2 = 'R' THEN
          IF ( c_uk.cod_calculo_kgr='P331' OR
               c_uk.cod_calculo_kgr='P332' OR
               c_uk.cod_calculo_kgr='P333' OR
               c_uk.cod_calculo_kgr='P339' OR
               c_uk.cod_calculo_kgr='P344' ) THEN

               ln_cant_kgr := ln_cant_kgr + c_uk.cantidad_kgr ;
          END IF ;
       END IF ;

       -- total blanca
       IF as_tipo2 = 'B' THEN
          IF ( c_uk.cod_calculo_kgr='P341' OR
               c_uk.cod_calculo_kgr='P335' ) THEN

               ln_cant_kgr := ln_cant_kgr + c_uk.cantidad_kgr ;
          END IF ;
       END IF ;

       -- total rubia
       IF as_tipo2 = 'U' THEN
          IF ( c_uk.cod_calculo_kgr='P336' OR
               c_uk.cod_calculo_kgr='P342' OR
               c_uk.cod_calculo_kgr='P343' OR
               c_uk.cod_calculo_kgr='P338' ) THEN

               ln_cant_kgr := ln_cant_kgr + c_uk.cantidad_kgr ;
          END IF ;
       END IF ;
    END IF ;

END LOOP ;

RETURN(ln_cant_kgr);

END USF_LAB_KG_AZUCAR_X_TIPO;
/

prompt
prompt Creating function USF_LAB_RESULT_CARACT_X_TEMPLA
prompt ================================================
prompt
create or replace function cantabria.USF_LAB_RESULT_CARACT_X_TEMPLA
(as_templa in templas.cod_templa%Type,
 as_caract In caracteristicas.cod_caract%Type) return number Is

  Result number;
  ls_cod_ana_rubia tipo_analisis.tipo_analisis%Type;
  ls_cod_ana_refin tipo_analisis.tipo_analisis%Type;
  ls_cod_ana_blanc tipo_analisis.tipo_analisis%Type;
  ln_contador Number;

begin

Select l.ana_arubia, l.ana_ref_dom, l.ana_ablanca
  Into ls_cod_ana_rubia, ls_cod_ana_refin, ls_cod_ana_blanc
  From labparam l
 Where l.reckey = '1';

Select Count(*)
  Into ln_contador
  From resultados_templa rt, resultados_templa_det rtd, caracteristicas c
 Where rt.fecha          = rtd.fecha
   And rt.tipo_analisis  = rtd.tipo_analisis
   And rt.cod_templa     = rtd.cod_templa
   And rtd.cod_caract    = c.cod_caract
   And rt.cod_templa     = as_templa
   And rt.tipo_analisis  In (ls_cod_ana_rubia, ls_cod_ana_refin, ls_cod_ana_blanc)
   And rtd.cod_caract    = as_caract;

If ln_contador <= 1 Then

     Begin
          Select nvl(rtd.resultado,0)
            Into Result
            From resultados_templa rt, resultados_templa_det rtd, caracteristicas c
           Where rt.fecha          = rtd.fecha
             And rt.tipo_analisis  = rtd.tipo_analisis
             And rt.cod_templa     = rtd.cod_templa
             And rtd.cod_caract    = c.cod_caract
             And rt.cod_templa     = as_templa
             And rt.tipo_analisis  In (ls_cod_ana_rubia, ls_cod_ana_refin, ls_cod_ana_blanc)
             And rtd.cod_caract    = as_caract;
     Exception
          When NO_DATA_FOUND Then
               Result := 0;
     End;

Else

    Begin
          Select Avg(rtd.resultado)
            Into Result
            From resultados_templa rt, resultados_templa_det rtd, caracteristicas c
           Where rt.fecha          = rtd.fecha
             And rt.tipo_analisis  = rtd.tipo_analisis
             And rt.cod_templa     = rtd.cod_templa
             And rtd.cod_caract    = c.cod_caract
             And rt.cod_templa     = as_templa
             And rt.tipo_analisis  In (ls_cod_ana_rubia, ls_cod_ana_refin, ls_cod_ana_blanc)
             And rtd.cod_caract    = as_caract;
     Exception
          When NO_DATA_FOUND Then
               Result := 0;
     End;
End If;

return(Result);

end USF_LAB_RESULT_CARACT_X_TEMPLA;
/

