prompt Creating function USF_LAB_SUM_CALC_CAMPO
prompt ========================================
prompt
create or replace function cantabria.USF_LAB_SUM_CALC_CAMPO(
   ad_fecha1 in date, ad_fecha2 in date, as_campo in char,
   as_calculo in char) return number is

  ln_dia     number;
begin

  -- Funcion que acumula los resultados diarios de un campo y calculo
  -- especificado.

  Select SUM( lcc.dia) into ln_dia
     from lab_calculo_campo lcc, campo_ciclo cc, campo c
     where lcc.corr_corte = cc.corr_corte and
     cc.cod_campo = c.cod_campo and
     lcc.fecha between ad_fecha1 and ad_fecha2 and
     c.cod_campo = as_campo and
     lcc.cod_calculo = as_calculo;

  return(ln_dia);
end USF_LAB_SUM_CALC_CAMPO;
/

prompt
prompt Creating function USF_LAB_SUM_CALC_CAMPO_ALL
prompt ============================================
prompt
create or replace function cantabria.USF_LAB_SUM_CALC_CAMPO_ALL(
   ad_sem1 in date, ad_sem2 in date, ad_mes1 in date, ad_mes2 in date,
   ad_ano1 in date, ad_ano2 in date, an_sem out number, an_mes out number,
   an_ano out number,  as_calculo in char, as_corr in char,
   as_quemado in char) return number is

begin

  -- Funcion que acumula los resultados de un calculo para
  -- un rango de fecha especificado.

  -- Halla resultado de la semana
  Select SUM( NVL(lcc.dia,0)) into an_sem from lab_calculo_campo lcc
     where lcc.corr_corte = as_corr and lcc.cod_calculo = as_calculo
     and TRUNC(lcc.fecha) between TRUNC( ad_sem1) and TRUNC(ad_sem2)
     and lcc.flag_campo_sin_qm = as_quemado;

  -- Halla resultado del mes
  Select SUM( NVL(lcc.dia,0)) into an_mes from lab_calculo_campo lcc
     where lcc.corr_corte = as_corr and lcc.cod_calculo = as_calculo
     and TRUNC(lcc.fecha) between TRUNC( ad_mes1) and TRUNC(ad_mes2)
     and lcc.flag_campo_sin_qm = as_quemado;

  -- Halla resultado del a?o
  Select SUM( NVL(lcc.dia,0)) into an_ano from lab_calculo_campo lcc
     where lcc.corr_corte = as_corr and lcc.cod_calculo = as_calculo
     and TRUNC(lcc.fecha) between TRUNC( ad_ano1) and TRUNC(ad_ano2)
     and lcc.flag_campo_sin_qm = as_quemado;

  return(0);
end USF_LAB_SUM_CALC_CAMPO_ALL;
/

