prompt
prompt Creating function USF_LAB_SUM_CALC_PROD_ALL
prompt ===========================================
prompt
create or replace function cantabria.USF_LAB_SUM_CALC_PROD_ALL(
   ad_sem1 in date, ad_sem2 in date, ad_mes1 in date, ad_mes2 in date,
   ad_ano1 in date, ad_ano2 in date, an_sem out number, an_mes out number,
   an_ano out number,  as_calculo in char) return number is

--  ln_dia     number(17,7);
begin

  -- Funcion que acumula los resultados de un calculo para
  -- un rango de fecha especificado.

  -- Halla resultado de la semana
  Select SUM( NVL(lcp.dia,0)) into an_sem from lab_calculo_prod lcp
