prompt
prompt Creating function USF_LAB_SUM_CALC_PROM_SAC
prompt ===========================================
prompt
create or replace function cantabria.USF_LAB_SUM_CALC_PROM_SAC( ad_fini in date, ad_ffin in date,
   as_corr_corte campo_ciclo.corr_corte%type, as_calculo1 in char,
   as_calculo2 in char, as_quema in lab_calculo_campo.flag_campo_sin_qm%type) return number is

--  ln_dia     number(17,7);

CURSOR c_fecha
IS

SELECT distinct( trunc(lcc.fecha) ) as fechad
FROM   lab_calculo_campo lcc
WHERE  lcc.flag_campo_sin_qm = as_quema and
       ( TRUNC(lcc.fecha) between TRUNC(ad_fini) and TRUNC(ad_ffin) )
ORDER BY trunc(lcc.fecha) ;


CURSOR c_mov_calc1
 (ad_fecha      lab_calculo_prod.fecha%type )
 IS
  SELECT lcc.dia
    FROM lab_calculo_campo lcc
   WHERE lcc.flag_campo_sin_qm = as_quema AND
         TRUNC(lcc.fecha) = TRUNC(ad_fecha) and
         lcc.corr_corte = as_corr_corte and
         lcc.cod_calculo = as_calculo1 ;

CURSOR c_mov_calc2
 (ad_fecha      lab_calculo_prod.fecha%type )
 IS
  SELECT lcc.dia
    FROM lab_calculo_campo lcc
   WHERE lcc.flag_campo_sin_qm = as_quema and
         TRUNC(lcc.fecha) = TRUNC(ad_fecha) and
         lcc.corr_corte = as_corr_corte and
         lcc.cod_calculo = as_calculo2 ;


ln_calculo         number ;
ln_calculo1        number ;
ln_calculo2        number ;
ln_calculo3        number ;
ln_calculo4        number ;

BEGIN

  -- Funcion que acumula los resultados de un calculo para
  -- un rango de fecha especificado, en funcion al producto de 02 codigos de caculo
ln_calculo  := 0 ;   -- Dato a calcular
ln_calculo1 := 0 ;   -- 1er dato del dia concepto para promedio
ln_calculo2 := 0 ;   -- 2do dato del dia concepto para promedio
ln_calculo3 := 0 ;   -- Suma del 1er dato concepto para promedio
ln_calculo4 := 0 ;   -- Multiplicacion de promedios (factor1 * factor2)

-- Calculo semanal
FOR c_f in c_fecha LOOP
    ln_calculo1 := 0 ;
    FOR c_m1 in c_mov_calc1(c_f.fechad) LOOP
        ln_calculo1 := NVL(c_m1.dia,0) ;
        ln_calculo3 := ln_calculo3 + NVL(c_m1.dia,0) ;
    END LOOP ;

    ln_calculo2 := 0 ;
    FOR c_m2 in c_mov_calc2(c_f.fechad) LOOP
        ln_calculo2 := c_m2.dia ;
    END LOOP ;

    ln_calculo4 := nvl(ln_calculo4,0) + ( ln_calculo1 * ln_calculo2 ) ;

END LOOP ;

IF ln_calculo3 > 0 THEN
    ln_calculo := ln_calculo4 / ln_calculo3 ;
ELSE
    ln_calculo := 0 ;
END IF ;

return(ln_calculo);

end USF_LAB_SUM_CALC_PROM_SAC;
/

prompt
prompt Creating function USF_LAB_SUM_CORR_CORTE
prompt ========================================
prompt
create or replace function cantabria.USF_LAB_SUM_CORR_CORTE(
   as_corr in char, as_cod in char, as_flag_quema in char,
   as_periodo in char) return number is

   ln_res   number;

begin

  -- Funcion que acumula los resultados de un calculo para
  -- un correlativo de corte de todo su movimiento.

  if as_periodo = 'D' THEN
     Select SUM( NVL(lcc.dia,0)) into ln_res
        from lab_calculo_campo lcc
        where lcc.corr_corte = as_corr and
        lcc.flag_campo_sin_qm = as_flag_quema  and
        lcc.cod_calculo = as_cod;
  end if;
  if as_periodo = 'M' THEN
     Select SUM( NVL(lcc.mes,0)) into ln_res
        from lab_calculo_campo lcc
        where lcc.corr_corte = as_corr and
        lcc.flag_campo_sin_qm = as_flag_quema  and
        lcc.cod_calculo = as_cod;
  end if;

  return(ln_res);
end USF_LAB_SUM_CORR_CORTE;
/

