prompt
prompt Creating function USF_LAB_SUM_INCIDENCIAS_ALL
prompt =============================================
prompt
create or replace function cantabria.USF_LAB_SUM_INCIDENCIAS_ALL(
   ad_fecha in date, as_cod in char, an_turno1 out number, an_turno2 out number,
   an_turno3 out number, an_dia out number, an_sem out number,
   an_mes out number, an_ano out number) return number is

begin

  -- Halla resultado
  Select NVL(turno1,0), NVL(turno2,0), NVL(turno3,0), NVL(dia,0), NVL(semana,0), NVL(mes,0), NVL(ano,0)
     into an_turno1, an_turno2, an_turno3,
     an_dia, an_sem, an_mes, an_ano
     from incidencias_fabrica inf
     where cod_incidencia = as_cod and
     TRUNC(fecha) = ad_fecha;

  return(0);
end USF_LAB_SUM_INCIDENCIAS_ALL;
/

prompt
prompt Creating function USF_LAB_SUM_INCIDENCIAS_X_COD
prompt ===============================================
prompt
create or replace function cantabria.USF_LAB_SUM_INCIDENCIAS_X_COD(
   ad_fecha1 in date, ad_fecha2 in date, as_cod in char) return number is

  ln_minutos   number;
begin

  -- Funcion que acumula los resultados de un calculo para
  -- un rango de fecha especificado.

  Select NVL(sum((r.fecha_fin - r.fecha_ini) * 24),0) into ln_minutos
       from ocurrencias r
       where r.fecha_ini between ad_fecha1 and ad_fecha2
       and r.cod_incidencia = as_cod;

  return(ln_minutos);
end USF_LAB_SUM_INCIDENCIAS_X_COD;
/

prompt
prompt Creating function USF_LAB_TIEMPO_PERDIDO
prompt ========================================
prompt
create or replace function cantabria.usf_lab_tiempo_perdido(
  ad_dia_men in date, ad_dia_may in date,
  as_opcion in char) return number is

  ln_horas  number(10,4);

  /* as_opcion:
     A = Falta de ca?a (P186)
     B = Trafico de patio (P188)
     C = Piedras en ca?a (P190)
     D = Trapiche (P192)
     E = Elaboracion (P194)
     F = Electrico (P196)
     G = PTX (P198)
     H = Externos operativos (P200)
     I = Varios (P2002)
  */
begin

select sum(dia)
into ln_horas
from incidencias_dma id, incidencias_fabrica inf
where id.flag_uso='T' and
      id.cod_incidencia=inf.cod_incidencia and
      ( trunc(inf.fecha) between trunc(ad_dia_men) and trunc(ad_dia_may)) and
      id.tipo_incidencia = as_opcion ;

ln_horas := nvl(ln_horas,0) ;
-- Solo considera dif. fechas de 10 anos como maximo
return( round(ln_horas,3) );

end usf_lab_tiempo_perdido;
/

prompt
prompt Creating function USF_LAB_TON_CANA_SUCIA
prompt ========================================
prompt
create or replace function cantabria.USF_LAB_TON_CANA_SUCIA
  (ad_fecha1 in date, ad_fecha2 in date, as_modo in char)
 return number is

  ln_count               number;
  ln_cana_sucia_total    number := 0;
begin

  if ad_fecha1 is null then
     insert into tt_lab_resul_proceso( observacion)
       values('Fecha es nula para calcular ca?a');
--     Raise_application_error( -20002, 'Fecha es nula');
  end if;
  if as_modo = 'T' then
     -- Tns. ca?a sucia total, sale de balanza
     --========================================
     Select COUNT(cp.pesada) into ln_count
        from campo_pesaje cp
        where (cp.hora_tara between ad_fecha1 and ad_fecha2) and
              cp.flag_impurezas = '0';
     if ln_count > 0 then
        Select SUM(NVL(cp.pesada - cp.tara,0)) into ln_cana_sucia_total
           from campo_pesaje cp
           where (cp.hora_tara between ad_fecha1 and ad_fecha2) and
              cp.flag_impurezas = '0';
     else
        insert into tt_lab_resul_proceso( observacion)
       values('No existe informacion de ca?a');
--        Raise_application_error( -20002, 'No existe informacion de ca?a');
     end if;
  elsif as_modo = 'P' then
     -- Tns. ca?a sucia total, sale de balanza - Propio
     --=====================================================
     Select COUNT(cp.pesada) into ln_count
        from campo_pesaje cp, campo c, campo_ciclo cc
        where (cp.hora_tara between ad_fecha1 and ad_fecha2) and
          cp.corr_corte = cc.corr_corte and cc.cod_campo = c.cod_campo and
          c.flag_propiedad = 'P' and cp.flag_impurezas = '0';
     if ln_count > 0 then
        Select SUM(NVL(cp.pesada - cp.tara,0)) into ln_cana_sucia_total
           from campo_pesaje cp, campo c, campo_ciclo cc
           where (cp.hora_tara between ad_fecha1 and ad_fecha2) and
           cp.corr_corte = cc.corr_corte and cc.cod_campo = c.cod_campo and
           c.flag_propiedad = 'P' and cp.flag_impurezas = '0';
     else
        insert into tt_lab_resul_proceso( observacion)
       values('No existe informacion de ca?a para propios');
--        Raise_application_error( -20002, 'No existe informacion de ca?a para propios');
     end if;
  elsif as_modo = 'E' then
     -- Tns. ca?a sucia entrante, sale de balanza
     --==========================================
     Select COUNT(cp.pesada) into ln_count
        from campo_pesaje cp
        where (cp.hora_pesada between ad_fecha1 and ad_fecha2) and
              cp.flag_impurezas = '0';
     if ln_count > 0 then
        Select SUM(NVL(cp.pesada - cp.tara,0)) into ln_cana_sucia_total
           from campo_pesaje cp
           where (cp.hora_pesada between ad_fecha1 and ad_fecha2) and
              cp.flag_impurezas = '0';
     else
        insert into tt_lab_resul_proceso( observacion)
       values('No existe informacion de ca?a entrante');
--        Raise_application_error( -20002, 'No existe informacion de ca?a');
     end if;

  else
     -- Tns. ca?a sucia total, sale de balanza - Sembradores
     --=====================================================
     Select COUNT(cp.pesada) into ln_count
        from campo_pesaje cp, campo c, campo_ciclo cc
        where (cp.hora_tara between ad_fecha1 and ad_fecha2) and
        cp.corr_corte = cc.corr_corte and cc.cod_campo = c.cod_campo and
        c.flag_propiedad <> 'P' and cp.flag_impurezas = '0';
     if ln_count > 0 then
        Select SUM(NVL(cp.pesada - cp.tara,0)) into ln_cana_sucia_total
           from campo_pesaje cp, campo c, campo_ciclo cc
           where (cp.hora_tara between ad_fecha1 and ad_fecha2) and
           cp.corr_corte = cc.corr_corte and cc.cod_campo = c.cod_campo and
           c.flag_propiedad <> 'P' and cp.flag_impurezas = '0';
     else
        insert into tt_lab_resul_proceso( observacion)
       values('No existe informacion de ca?a de semb.');
--        Raise_application_error( -20002, 'No existe informacion de ca?a de semb.');
     end if;
  end if;
  return(ln_cana_sucia_total/1000);  -- esta expresado en kilos, devolver ton.
end USF_LAB_TON_CANA_SUCIA;
/

prompt
prompt Creating function USF_LAB_TON_CANA_SUCIA_GRCL
prompt =============================================
prompt
create or replace function cantabria.USF_LAB_TON_CANA_SUCIA_GRCL
(ad_fec_ini In Date,
 ad_fec_fin In Date,
 as_grupo   In Char) return number Is

Result number;

/*
==========================================================
Funcion creada para determinar Toneladas de ca?a por grupo
de clase, pedido de Josue Cruzado y Gerente de Fabrica
Federico Luna.
========================
14/06/2005 12:26:00 p.m.
jpomalaza
========================
*/

begin

     Begin
          Select nvl(Sum((cp.pesada - cp.tara)/1000),0)
            Into Result
            From campo_pesaje cp, campo_ciclo cc, campo c,
                 frente_cosecha fc, frente_cosecha_clase fcc
           Where cp.corr_corte = cc.corr_corte
             And cc.cod_campo = c.cod_campo
             And c.frente_cosecha = fc.frente_cosecha
             And fc.clase = fcc.clase
             And cp.hora_tara >= ad_fec_ini
             And cp.hora_tara <= ad_fec_fin
             And cp.flag_impurezas = '0'
             And fcc.grupo_clase = as_grupo
           Order By fcc.clase, fc.frente_cosecha;

     Exception
            When NO_DATA_FOUND Then
                 Result := 0;
     End;

Return(Result);

end USF_LAB_TON_CANA_SUCIA_GRCL;
/

prompt
prompt Creating function USF_LAB_UND_PRODUCIDAS
prompt ========================================
prompt
create or replace function cantabria.USF_LAB_UND_PRODUCIDAS
  (ad_fecha1 in date, as_cod in char, as_mens in char)
  return number is

  ln_count       number;
  ln_cantidad    number := 0;
begin

  -- Busca unidad producida
  --=======================
  Select COUNT(u.cantidad) into ln_count from unidades_producidas u
    where u.cod_prod = as_cod and
        TRUNC(u.fecha_prod) = TRUNC(ad_fecha1) ;
  if ln_count > 0 then
     Select u.cantidad into ln_cantidad from unidades_producidas u
        where u.cod_prod = as_cod and
        TRUNC(u.fecha_prod) = TRUNC(ad_fecha1) ;
  else
--     Raise_application_error( -20002, 'No existe ' || as_mens || ' para el dia ' || ad_fecha1);
     insert into tt_lab_resul_proceso( observacion)
       values( 'No existe ' || as_mens || ' para el dia ' || ad_fecha1);
  end if;

  return(ln_cantidad);
end USF_LAB_UND_PRODUCIDAS;
/

prompt
prompt Creating function USF_LAB_UPDATE_CALCULO_CAMPO
prompt ==============================================
prompt
create or replace function cantabria.USF_LAB_UPDATE_CALCULO_CAMPO(
   ad_fecha in date, as_cod in char, as_corr in char, an_sem in number,
   an_mes in number, an_ano in number, as_quema in char) return integer is

  ls_prop     campo.flag_propiedad%type;

begin

  -- Busca la propiedad
  Select c.flag_propiedad into ls_prop
     from campo_ciclo cc, campo c
     where cc.corr_corte = as_corr and cc.cod_campo = c.cod_campo;

  if NVL( an_sem,0) <> 0 then
     Update lab_calculo_campo l set semana = an_sem, mes = an_mes, ano = an_ano
     where TRUNC(fecha) = trunc( ad_fecha) AND cod_calculo = as_cod and
     l.corr_corte = as_corr and l.flag_campo_sin_qm = as_quema;
     IF SQL%NOTFOUND THEN
        INSERT INTO lab_calculo_campo(fecha, corr_corte, cod_calculo, dia, semana,
          mes, ano, flag_tipo, flag_campo_sin_qm, flag_propiedad)
          values(ad_fecha, as_corr, as_cod, 0, NVL(an_sem,0), NVL(an_mes,0),
          NVL(an_ano,0), 'P', as_quema, ls_prop);
     END IF;
  else
     Update lab_calculo_campo set mes = an_mes, ano = an_ano
     where TRUNC(fecha) = trunc( ad_fecha) AND cod_calculo = as_cod and
     corr_corte = as_corr and flag_campo_sin_qm = as_quema;
     IF SQL%NOTFOUND THEN
        INSERT INTO lab_calculo_campo(fecha, corr_corte, cod_calculo, dia, semana, mes, ano,
          flag_tipo, flag_campo_sin_qm, flag_propiedad)
          values(ad_fecha, as_corr, as_cod, 0, 0, NVL(an_mes,0),
          NVL(an_ano,0), 'P', as_quema, ls_prop);
     END IF;
  end if;
  return(1);
end USF_LAB_UPDATE_CALCULO_CAMPO;
/

