prompt Creating function USF_LAB_UPDATE_RESULTADOS
prompt ===========================================
prompt
create or replace function cantabria.USF_LAB_UPDATE_RESULTADOS(
    ad_fecha in date, an_brix in number, an_pol in number,
    an_pureza in number, an_reductor in number, as_user in char
    )return integer is

  Result integer;
  ls_analisis    tipo_analisis.tipo_analisis%type;
  ls_brix        caracteristicas.cod_caract%type;
  ls_pol         caracteristicas.cod_caract%type;
  ls_reductor    caracteristicas.cod_caract%type;
  ls_pureza      caracteristicas.cod_caract%type;

begin

  -- Busca en parametros
  Select l.ana_jprimero, l.cod_brix_cor, l.cod_pol, l.cod_pureza, l.cod_reductor
    into ls_analisis, ls_brix, ls_pol, ls_pureza, ls_reductor
    from labparam l where reckey = '1';

  delete from resultados_producto_det r
     where r.fecha = ad_fecha and tipo_analisis = ls_analisis;
  delete from resultados_producto r
     where r.fecha = ad_fecha and tipo_analisis = ls_analisis;

/*  Select count(r.cod_caract) into ln_count from resultados_producto_det r
     where r.fecha = ad_fecha and tipo_analisis = ls_analisis;

  if ln_count = 0 then
     delete from resultados_producto_det r
     where r.fecha = ad_fecha and tipo_analisis = ls_analisis;
  end if; */

  INSERT INTO resultados_producto(fecha, tipo_analisis, cod_usr)
    values(ad_fecha, ls_analisis, as_user);
  INSERT INTO resultados_producto_Det(fecha, tipo_analisis,Cod_Caract,
     Resultado, Tipo_Dato)
    values(ad_fecha, ls_analisis, ls_brix, an_brix, 'C');
  INSERT INTO resultados_producto_Det(fecha, tipo_analisis,Cod_Caract,
     Resultado, Tipo_Dato)
    values(ad_fecha, ls_analisis, ls_pol, an_pol, 'C');
  INSERT INTO resultados_producto_Det(fecha, tipo_analisis,Cod_Caract,
     Resultado, Tipo_Dato)
    values(ad_fecha, ls_analisis, ls_pureza, an_pureza, 'C');
  INSERT INTO resultados_producto_Det(fecha, tipo_analisis,Cod_Caract,
     Resultado, Tipo_Dato)
    values(ad_fecha, ls_analisis, ls_reductor, an_reductor, 'C');

  return(Result);
end USF_LAB_UPDATE_RESULTADOS;
/

prompt
prompt Creating function USF_LAST_DAY
prompt ==============================
prompt
create or replace function cantabria.usf_last_day(
 ad_fecha in date ) return date is

ld_Return date;
ln_mes    number;
ln_year   number;

BEGIN
  if ad_fecha is null then
     Return ad_fecha;
  end if;
  
  ln_mes  := to_number(to_char(ad_fecha, 'mm'));
  ln_year := to_number(to_char(ad_fecha, 'yyyy'));
  
  if ln_mes = 12 then
     ln_mes := 1;
     ln_year := ln_year + 1;
  else
     ln_mes := ln_mes + 1;
  end if;
  
  ld_Return := to_date('01/' || trim(to_char(ln_mes, '00')) || '/' || trim(to_char(ln_year, '0000')), 'dd/mm/yyyy') - 1;
  
  Return ld_Return;

END usf_last_day ;
/

prompt
prompt Creating function USF_MESES_GRATIF
prompt ==================================
prompt
create or replace function cantabria.usf_meses_gratif
  (  ad_fec_proceso control.fec_proceso%type,
     ad_fec_ingreso maestro.fec_ingreso%type
       )
  return number is
  --Declaro Variables Locales
  ld_fec_proceso control.fec_proceso%type;
  ld_fec_ingreso maestro.fec_ingreso%type;
  ln_nro_meses number(6,2);
  ln_dia number(2);

begin
 --Asignacion de Valores
 ld_fec_proceso := ad_fec_proceso;
 ld_fec_ingreso := ad_fec_ingreso;

 --Verificamos si el dia es diferente de uno
 ln_dia := to_char(ad_fec_ingreso,'DD');

 IF ln_dia <> 1 THEN
    ld_fec_ingreso := LAST_DAY(ad_fec_ingreso);
    ld_fec_proceso := LAST_DAY(ad_fec_proceso);
    ln_nro_meses := MONTHS_BETWEEN(ld_fec_proceso, ld_fec_ingreso);
 END IF;

 IF ln_dia = 1 THEN
    --Restamos un mes
    ld_fec_ingreso := ld_fec_ingreso - 1;
    ld_fec_proceso := LAST_DAY(ad_fec_proceso);
    ln_nro_meses := MONTHS_BETWEEN(ld_fec_proceso, ld_fec_ingreso);
 END IF;

 return( ln_nro_meses );
end usf_meses_gratif;
/

