prompt Creating function USF_MIG_PTO_SALDO
prompt ===================================
prompt
create or replace function cantabria.USF_MIG_PTO_SALDO(ln_mes in number,
   ln_ano in number, ls_cencos in char, ls_ctaprs in char,
   ln_import in number)
  return number is

begin

           IF ln_mes = 1 then
              Update presupuesto_partida set ejec_ene = NVL( ejec_ene,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 2 then
              Update presupuesto_partida set ejec_feb = NVL( ejec_feb,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 3 then
              Update presupuesto_partida set ejec_mar = NVL( ejec_mar,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 4 then
              Update presupuesto_partida set ejec_abr = NVL( ejec_abr,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 5 then
              Update presupuesto_partida set ejec_may = NVL( ejec_may,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 6 then
              Update presupuesto_partida set ejec_jun = NVL( ejec_jun,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 7 then
              Update presupuesto_partida set ejec_jul = NVL( ejec_jul,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 8 then
              Update presupuesto_partida set ejec_ago = NVL( ejec_ago,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 9 then
              Update presupuesto_partida set ejec_set = NVL( ejec_set,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 10 then
              Update presupuesto_partida set ejec_oct = NVL( ejec_oct,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 11 then
              Update presupuesto_partida set ejec_nov = NVL( ejec_nov,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
           IF ln_mes = 12 then
              Update presupuesto_partida set ejec_dic = NVL( ejec_dic,0) - ln_import
                 where ano = ln_ano and cencos = ls_cencos and
                 cnta_prsp = ls_ctaprs;
           end if;
  return (0);

end USF_MIG_PTO_SALDO;
/

