prompt
prompt Creating function USF_MM2HHMM
prompt =============================
prompt
create or replace function cantabria.usf_mm2hhmm(an_minutos in number)
  return string is

  -- se recepciona un nzmnero de minutos,
  -- se devuelve en formato 'hhhh:mm'
  ls_hhmm char(7);
  ln_horas integer ;
  ln_minutos integer ;

begin

  ln_horas := trunc( an_minutos / 60 ) ;
  ln_minutos := an_minutos - ( ln_horas * 60 )  ;
  ls_hhmm := substr( to_char( ln_horas , '9990' ), 2, 4) || ':' ||
             substr( to_char( ln_minutos, '00' ), 2, 2) ;

  return( ls_hhmm );
end usf_mm2hhmm;
/

prompt
prompt Creating function USF_MT_CAUSAS_PD_OT
prompt =====================================
prompt
create or replace function cantabria.usf_mt_causas_pd_ot(
       asi_nro_parte in pd_ot_det.nro_parte%TYPE,
       asi_nro_item  in pd_ot_det.nro_item%TYPE

) return string is

  Result     string(32767);
  ln_item    number;

  cursor c_causas is
    select t.causa_falla, t.obs
    from causa_fallas_ot t
    where t.nro_parte = asi_nro_parte
      and t.nro_item  = asi_nro_item;
begin

  Result := '';
  ln_item := 1;

  for lc_reg in c_causas loop
      Result := to_char(ln_item, '000') || '.- ' || lc_reg.causa_falla
             || ': ' || lc_reg.obs || chr(13);
      ln_item := 1;
  end loop;

  return(Result);
end usf_mt_causas_pd_ot;
/

prompt
prompt Creating function USF_MT_INCIDENCIAS_PD_OT
prompt ==========================================
prompt
create or replace function cantabria.usf_mt_incidencias_pd_ot(
       asi_nro_parte in pd_ot_det.nro_parte%TYPE,
       asi_nro_item  in pd_ot_det.nro_item%TYPE

) return string is

  Result     string(32767);

  cursor c_incidencias is
    select t.nro_incidencia, t.cod_incidencia, t.descripcion,
           t.fecha_inicio, t.fecha_fin
    from pd_ot_incidencias t
    where t.nro_parte = asi_nro_parte
      and t.nro_item  = asi_nro_item;
begin

  Result := '';

  for lc_reg in c_incidencias loop
      Result := to_char(lc_reg.nro_incidencia, '000') || '.- ' || lc_reg.cod_incidencia
             || ': ' || lc_reg.descripcion || ' Rango Incidencia: '
             || to_char(lc_reg.fecha_inicio, 'dd/mm/yyyy hh:mm') || ' - '
             || to_char(lc_reg.fecha_fin, 'dd/mm/yyyy hh:mm') || chr(13);
  end loop;

  return(Result);
end usf_mt_incidencias_pd_ot;
/

