prompt Creating function USF_MT_INSUMOS_PD_OT
prompt ======================================
prompt
create or replace function cantabria.usf_mt_insumos_pd_ot(
       asi_nro_parte in pd_ot_det.nro_parte%TYPE,
       asi_nro_item  in pd_ot_det.nro_item%TYPE

) return string is

  Result     string(32767);
