  cursor c_insumos is
    select t.cod_art, a.desc_art, a.und, t.cantidad
    from pd_ot_insumos t,
         articulo      a
    where a.cod_art = t.cod_art
      and t.nro_parte = asi_nro_parte
      and t.nro_item  = asi_nro_item;
begin

  Result := '';
