  for lc_reg in c_insumos loop
      Result := to_char(ln_item, '000') || '.- ' || lc_reg.cod_Art
             || ' ' || lc_reg.desc_art || ' ' || lc_reg.und
             || ' ' || to_char(lc_reg.cantidad) || chr(13);

      ln_item := ln_item +1;

  end loop;

  return(Result);
end usf_mt_insumos_pd_ot;
