prompt
prompt Creating function USF_MTO_COSTO_ART_X_OT
prompt ========================================
prompt
create or replace function cantabria.usf_mto_costo_art_x_ot(
       asi_nro_orden     in orden_trabajo.nro_orden%TYPE
) return number is

  ln_Result     number;
  ln_count      number;
  ls_dolares    logparam.cod_dolares%TYPE;
  ls_doc_ot     logparam.doc_ot%TYPE;

begin

  select doc_ot, cod_dolares
    into ls_doc_ot, ls_dolares
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
  from articulo_mov      am,
       vale_mov          vm,
       articulo_mov_proy amp
  where am.nro_vale        = vm.nro_vale
    and am.nro_mov_proy    = amp.nro_mov
    and am.origen_mov_proy = amp.cod_origen
    and amp.tipo_doc       = ls_doc_ot
    and amp.nro_doc        = asi_nro_orden
    and am.flag_estado     <> '0'
    and vm.flag_estado     <> '0';

  if ln_count = 0 then
     ln_Result := 0;
  else
      select Sum(NVL(am.cant_procesada,0)* usf_fl_conv_mon(NVL(am.precio_unit,0), am.cod_moneda, ls_dolares, vm.fec_registro) )
        into ln_Result
       from articulo_mov      am,
            vale_mov          vm,
            articulo_mov_proy amp
       where am.nro_vale        = vm.nro_vale
         and am.nro_mov_proy    = amp.nro_mov
         and am.origen_mov_proy = amp.cod_origen
         and amp.tipo_doc       = ls_doc_ot
         and amp.nro_doc        = asi_nro_orden
         and am.flag_estado     <> '0'
         and vm.flag_estado     <> '0';
  end if;

  return(ln_Result);
end usf_mto_costo_art_x_ot;
/

