prompt
prompt Creating function USF_MTT_CAL_ART_X_OPE
prompt =======================================
prompt
create or replace function cantabria.usf_mtt_cal_art_x_ope(
an_oper_sec  in operaciones.oper_sec%type ,
as_dias_dur  in operaciones.dias_duracion_proy%type,
as_dias_proc in operaciones.dias_duracion_proy%type,
ac_flag      in Char)

Return Number is
 ln_cant_cal_art  Number ;
 ln_total_cal_art Number ;

 CURSOR C_ART_OPE IS
 SELECT amp.cod_art,
        DECODE(ac_flag,'P',amp.cant_proyect,'R',amp.cant_procesada) AS cantidad
 FROM   articulo_mov_proy amp
 WHERE (amp.oper_sec = an_oper_sec);

 CURSOR C_COSTO_ART(ac_cod_art articulo.cod_art%type) IS
 SELECT art.costo_ult_compra,
        art.cod_art
 FROM   articulo art
 WHERE  (art.cod_art = ac_cod_art);


begin
  ln_total_cal_art := 0 ;
  FOR rc_art_ope IN C_ART_OPE LOOP
      ln_cant_cal_art := 0 ;
      ln_cant_cal_art := Round((Nvl(as_dias_proc,0) * Nvl(rc_art_ope.cantidad,0)) / Nvl(as_dias_dur,0),2);

      FOR rc_art_costo IN C_COSTO_ART(rc_art_ope.cod_art) LOOP
          --//Sumatoria
          ln_total_cal_art := Round(Nvl(ln_total_cal_art,0) + Nvl(ln_cant_cal_art,0),0) ;
      END LOOP;
  END LOOP;

  Return (ln_total_cal_art);
end ;
/

prompt
prompt Creating function USF_MTT_CAL_INS_OPE_OT
prompt ========================================
prompt
create or replace function cantabria.usf_mtt_cal_ins_ope_ot(
ac_tipo_orden    in Char ,
an_nro_orden     in Char,
an_oper_sec      in operaciones.oper_sec%type,
an_operacion     in operaciones.nro_operacion%type,
an_dias_dur      in operaciones.dias_duracion_proy%type,
an_dias_proc     in operaciones.dias_duracion_proy%type,
ac_tipo_ot       in Char,
ac_flag          in Char,
ac_cod_maquina   in Char,
ac_cod_origen    in Char)

Return number is
  ln_cant_cal_art number;
  ln_total_c_art  number (13,2) ;
  ln_dias_duracion  operaciones.dias_duracion_proy%type ;

CURSOR c_art is
SELECT artmp.cod_art,
       decode(ac_flag,'P',artmp.cant_proyect,'R',artmp.cant_procesada) as cantidad
FROM   articulo_mov_proy artmp
WHERE  artmp.oper_sec = an_oper_sec ;


CURSOR c_costo_art (as_cod_art articulo.cod_art%type) is
SELECT costo_ult_compra,
       art.cod_art
FROM   articulo art
WHERE  (art.cod_art = as_cod_art );


begin
  ln_total_c_art := 0 ;
  For rc_art in c_art Loop
      ln_dias_duracion := Nvl(an_dias_dur,1) ;

      IF ln_dias_duracion = 0 THEN
         ln_dias_duracion := 1 ;
      END IF ;

      ln_cant_cal_art := 0 ;
      ln_cant_cal_art := Round( Nvl(an_dias_proc,0) * Nvl(rc_art.cantidad,0) / ln_dias_duracion, 2);

          For rc_costo_art in c_costo_art (rc_art.cod_art) Loop
              /* Insercion de Detalle de Insumos*/
              INSERT INTO tt_oper_orden_trabajo_ins
              (tipo_orden,
               cod_origen,
               nro_orden,
               tipo_ot,
               oper_sec,
               nro_operacion,
               cod_art,
               cantidad,
               costo_unitario,
               cod_maquina)
              VALUES
              (ac_tipo_orden,
               ac_cod_origen,
               an_nro_orden,
               ac_tipo_ot,
               an_oper_sec,
               an_operacion,
               rc_art.cod_art,
               ln_cant_cal_art,
               Round(Nvl(rc_costo_art.costo_ult_compra,0),2),
               ac_cod_maquina);
              /*Acumulador de Costo Por Insumos*/
              ln_total_c_art := round(ln_total_c_art + (Nvl(ln_cant_cal_art,0) * Round(Nvl(rc_costo_art.costo_ult_compra,0),2)),2) ;

          End Loop;
  End Loop;

  Return(ln_total_c_art);
end usf_mtt_cal_ins_ope_ot;
/

prompt
prompt Creating function USF_MTT_COSTO_INSUMO_ESTIM
prompt ============================================
prompt
create or replace function cantabria.usf_mtt_costo_insumo_estim(an_oper_sec operaciones.oper_sec%type)
return number is
  ln_result number;
begin
  --Calculamos Total de Costo de Insumos Por Operacion
   SELECT ROUND(SUM(NVL(art_m_p.CANT_PROYECT,0) * NVL(art.COSTO_ULT_COMPRA,0)),2)
   INTO   ln_result
   FROM   ARTICULO art    ,
          ARTICULO_MOV_PROY art_m_p
   WHERE ( art.cod_art       = art_m_p.cod_art)    and
         ( art_m_p.oper_sec = an_oper_sec)  ;

   IF ln_result IS NULL THEN
      ln_result:= 0;
   END IF;

  return(ln_result);
end usf_mtt_costo_insumo_estim;
/

prompt
prompt Creating function USF_MTT_FECHA_HORA
prompt ====================================
prompt
create or replace function cantabria.USF_MTT_FECHA_HORA
(ld_fecha_inicio in Date,
 ld_fecha_final  in Date)

 return Number is
  ln_Result Number(12,2);

begin

  ln_result := Round((ld_fecha_final - ld_fecha_inicio) * 24 ,2) ;

  return(ln_result);
end USF_MTT_FECHA_HORA;
/

prompt
prompt Creating function USF_MTT_HORAS_DISPONIBLES
prompt ===========================================
prompt
create or replace function cantabria.usf_mtt_horas_disponibles(
       adi_Fecha  in date
) return number is
  Result number;
begin
   SELECT sum(nvl(dia,0))
     into Result
     FROM lab_calculo_prod
    WHERE cod_calculo='P189'
      AND trunc(fecha) = trunc(adi_fecha);

  return(NVL(Result,0));
end usf_mtt_horas_disponibles;
/

prompt
prompt Creating function USF_MTT_HORAS_DISPO_X_EST
prompt ===========================================
prompt
create or replace function cantabria.usf_mtt_horas_dispo_x_est(
       asi_maq_padre  in maquina.cod_maquina%TYPE,
       adi_fecha1     in date,
       adi_fecha2     in date

) return number is
  Result number;
begin
  SELECT sum(usf_mtt_horas_disponibles(trunc(mc.fecha)) * count(distinct md.cod_maquina))
    into Result
    FROM mt_pd_grupo_trab       mc,
         mt_pd_grupo_trab_det   md
   WHERE mc.nro_parte = md.nro_parte
     and mc.cod_maquina = asi_maq_padre
     AND trunc(mc.fecha) BETWEEN trunc(adi_fecha1) AND trunc(adi_fecha2)
   group by trunc(mc.fecha);

  return(NVL(Result,0));
end usf_mtt_horas_dispo_x_est;
/

prompt
prompt Creating function USF_MTT_HORAS_INC_X_MAQ
prompt =========================================
prompt
create or replace function cantabria.usf_mtt_horas_inc_x_maq(
       asi_cod_maquina  in maquina.cod_maquina %TYPE,
       adi_fecha       in date
) return number is
  Result number;
begin
   select sum(NVL(a.und_no_trabaj,0))
     into Result
    from mt_pd_grupo_incidencia a,
         mt_pd_grupo_trab       b
   where a.nro_parte = b.nro_parte
     and a.cod_maquina = asi_cod_maquina
     AND trunc(fecha) = trunc(adi_fecha);

  return(NVL(Result,0));
end usf_mtt_horas_inc_x_maq;
/

