prompt
create or replace function cantabria.usf_mtt_insert_operaciones_ot
(ac_tipo_orden        operaciones.tipo_orden%type ,
 ac_nro_orden         operaciones.nro_orden%type,
 an_oper_sec          operaciones.oper_sec%type,
 an_nro_operacion     operaciones.nro_operacion%type,
 ac_desc_operacion    operaciones.desc_operacion%type,
 ac_cod_labor         operaciones.cod_labor%type,
 ac_cod_ejecutor      operaciones.cod_ejecutor%type,
 ac_proveedor         operaciones.proveedor%type,
 an_cantidad          Number,
 an_costo_unitario    operaciones.costo_unit%type,
 an_dias              Number,
 an_costo_ins         Number,
 ac_tipo_ot           orden_trabajo.ot_tipo%type,
 ac_cod_maquina       maquina.cod_maquina%type,
 ac_cod_origen        origen.cod_origen%type  ,
 an_costo_oper        Number,
 ac_grupo_maq         grupo_maquina.grupo_maq%type)

return number is

begin

  INSERT INTO tt_oper_orden_trabajo
 (tipo_orden,         cod_origen,      nro_orden,
  oper_sec,        nro_operacion, desc_operacion,
  cod_labor,        cod_ejecutor,      proveedor,
  cantidad,       costo_unitario,       nro_dias,
  costo_insumo,          tipo_ot,     costo_oper,
  cod_maquina,         cod_grupo)
  VALUES
 (ac_tipo_orden,     ac_cod_origen,      ac_nro_orden,
  an_oper_sec,    an_nro_operacion, ac_desc_operacion,
  ac_cod_labor,    ac_cod_ejecutor,      ac_proveedor,
  an_cantidad,   an_costo_unitario,           an_dias,
  an_costo_ins,         ac_tipo_ot,     an_costo_oper,
  ac_cod_maquina,     ac_grupo_maq);

  Return 1;
END ;
/

