prompt
prompt Creating function USF_MTT_MAN_VERIF_ESTADO_OT
prompt =============================================
prompt
create or replace function cantabria.usf_mtt_man_verif_estado_ot
(ac_cod_origen in orden_trabajo.cod_origen%type,
 ac_nro_orden  in orden_trabajo.nro_orden%type)
return Number is
  ln_retorno Number := 0 ;
  ln_count Number := 0 ;
begin

  SELECT Count(*)
    INTO ln_count
    FROM orden_servicio
   WHERE nro_orden      =  ac_nro_orden  AND
         flag_estado    <> '0'           ;

  IF ln_count = 0 THEN
     SELECT Count(*)
       INTO ln_count
       FROM operaciones
      WHERE ((tipo_orden = 'OT'          ) AND
             (nro_orden  = ac_nro_orden  )) AND
             (cant_real  > 0             ) ;

      IF ln_count = 0 THEN
         SELECT Count(*)
           INTO ln_count
           FROM articulo_mov_proy
          WHERE ((tipo_doc        = 'OT'          )  AND
                 (nro_doc         = ac_nro_orden  )) AND
                 (cant_procesada  > 0             );

         IF ln_count > 0 THEN
            ln_retorno := 1 ;
         END IF ;
      ELSE
         ln_retorno := 1 ;
      END IF ;
  ELSE
     ln_retorno := 1 ;
  END IF ;


  return(ln_retorno);
end usf_mtt_man_verif_estado_ot;
/

