prompt
prompt Creating function USF_MTT_NUM_SOL
prompt =================================
prompt
create or replace function cantabria.USF_MTT_NUM_SOL
(ac_cod_origen origen.cod_origen%type)

 return varchar2 is
  lc_ult_nro_sol solicitud_ot.nro_solicitud%type ;

ln_ult_nro num_manten_prog.ult_nro%type ;

begin
  --numerador de operaciones
  select nso.ult_nro
    into ln_ult_nro
    from num_solicitud_ot nso
   where (nso.origen = ac_cod_origen)
   for update;

  --se concatena con origen
  lc_ult_nro_sol := rtrim(ltrim(ac_cod_origen))||LPAD(rtrim(ltrim(to_char(ln_ult_nro))),8,'0') ;

  --actualiza informacion e numeradores
  update num_solicitud_ot nso
     set nso.ult_nro = Nvl(nso.ult_nro,0) + 1
   where (nso.origen = ac_cod_origen ) ;

  return(lc_ult_nro_sol);

end  USF_MTT_NUM_SOL ;
/

prompt
prompt Creating function USF_MTT_PLANTILLA_OT
prompt ======================================
prompt
create or replace function cantabria.usf_mtt_plantilla_ot(
as_nro_orden  in orden_trabajo.nro_orden%type)

Return varchar2 is
 ls_plant varchar2(10);
 ls_lst_plant varchar2(300);


 CURSOR c_plant IS
 SELECT distinct ppl.cod_plantilla
 FROM   prod_plant_lanz ppl
 WHERE ppl.nro_orden = as_nro_orden;


begin
  ls_lst_plant := '';
  FOR rc_plant IN c_plant LOOP
      ls_plant := trim(rc_plant.cod_plantilla);
      ls_lst_plant := ls_lst_plant||ls_plant||',';
  END LOOP;
  ls_lst_plant := substr(ls_lst_plant,1,length(ls_lst_plant)-1);

  Return (ls_lst_plant);
end ;
/

prompt
prompt Creating function USF_MTT_RPT_COSTO_ART_X_MAQ
prompt =============================================
prompt
create or replace function cantabria.usf_mtt_rpt_costo_art_x_maq(
       asi_maquina    in maquina.cod_maquina%TYPE,
       adi_fecha1     in date,
       adi_fecha2     in date
) return number is

  ln_Result     number;
  ln_count      number;
  ls_dolares    logparam.cod_dolares%TYPE;
  ls_doc_ot     logparam.doc_ot%TYPE;

begin

  select doc_ot, cod_dolares
    into ls_doc_ot, ls_dolares
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
  from orden_Trabajo     ot,
       articulo_mov      am,
       vale_mov          vm,
       articulo_mov_proy amp,
       tt_mtt_ot_adm     tt1
  where ot.nro_orden       = amp.nro_doc
    and amp.tipo_doc       = ls_doc_ot
    and am.nro_vale        = vm.nro_vale
    and am.nro_mov_proy    = amp.nro_mov
    and am.origen_mov_proy = amp.cod_origen
    and tt1.ot_adm         = ot.ot_adm
    and ot.cod_maquina     = asi_maquina
    and trunc(vm.fec_registro) between trunc(adi_fecha1) and trunc(adi_fecha2)
    and am.flag_estado     <> '0'
    and vm.flag_estado     <> '0';

  if ln_count = 0 then
     ln_Result := 0;
  else
      select Sum(NVL(am.cant_procesada,0)* usf_fl_conv_mon(NVL(am.precio_unit,0), am.cod_moneda, ls_dolares, vm.fec_registro) )
        into ln_Result
        from orden_Trabajo     ot,
             articulo_mov      am,
             vale_mov          vm,
             articulo_mov_proy amp,
             tt_mtt_ot_adm     tt1
        where ot.nro_orden       = amp.nro_doc
          and amp.tipo_doc       = ls_doc_ot
          and am.nro_vale        = vm.nro_vale
          and am.nro_mov_proy    = amp.nro_mov
          and am.origen_mov_proy = amp.cod_origen
          and tt1.ot_adm         = ot.ot_adm
          and ot.cod_maquina     = asi_maquina
          and trunc(vm.fec_registro) between trunc(adi_fecha1) and trunc(adi_fecha2)
          and am.flag_estado     <> '0'
          and vm.flag_estado     <> '0';
  end if;

  return(ln_Result);

end usf_mtt_rpt_costo_art_x_maq;
/

prompt
prompt Creating function USF_MTT_RPT_COSTO_JOR_X_MAQ
prompt =============================================
prompt
create or replace function cantabria.usf_mtt_rpt_costo_jor_x_maq(
       asi_maquina    in maquina.cod_maquina%TYPE,
       adi_fecha1     in date,
       adi_fecha2     in date
) return number is
  ln_Result     number;
  ln_count      number;
  ls_soles      logparam.cod_soles%TYPE;
  ls_dolares    logparam.cod_dolares%TYPE;
begin

  select cod_soles, cod_dolares
    into ls_soles, ls_dolares
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
  from orden_Trabajo     ot,
       pd_ot             pd,
       pd_ot_det         pdd,
       pd_ot_asistencia  pda,
       tt_mtt_ot_adm     tt1
  where ot.nro_orden  = pdd.nro_orden
    and pd.nro_parte  = pdd.nro_parte
    and pda.nro_item  = pdd.nro_item
    and pda.no_parte  = pdd.nro_parte
    and ot.ot_adm     = tt1.ot_adm
    and pdd.cod_maquina = asi_maquina
    and trunc(pd.fecha) between trunc(adi_fecha1) and trunc(adi_fecha2);

  if ln_count = 0 then
     ln_Result := 0;
  else
      select Sum( NVL(pda.nro_horas,0)* usf_fl_conv_mon(NVL(pda.costo_horas,0), ls_soles, ls_dolares, pdd.hora_inicio) * NVL(pda.factor,0))
        into ln_Result
        from orden_Trabajo     ot,
             pd_ot             pd,
             pd_ot_det         pdd,
             pd_ot_asistencia  pda,
             tt_mtt_ot_adm     tt1
        where ot.nro_orden  = pdd.nro_orden
          and pd.nro_parte  = pdd.nro_parte
          and pda.nro_item  = pdd.nro_item
          and pda.no_parte  = pdd.nro_parte
          and ot.ot_adm     = tt1.ot_adm
          and pdd.cod_maquina = asi_maquina
          and trunc(pd.fecha) between trunc(adi_fecha1) and trunc(adi_fecha2);
  end if;


  return(ln_Result);
end usf_mtt_rpt_costo_jor_x_maq;
/

prompt
prompt Creating function USF_MTT_RPT_COSTO_MO_X_MAQ
prompt ============================================
prompt
create or replace function cantabria.usf_mtt_rpt_costo_mo_x_maq(
       asi_maquina    in maquina.cod_maquina%TYPE,
       adi_fecha1     in date,
       adi_fecha2     in date
) return number is
  ln_Result     number;
  ln_count      number;
  ls_soles      logparam.cod_soles%TYPE;
  ls_dolares    logparam.cod_dolares%TYPE;
begin

  select cod_soles, cod_dolares
    into ls_soles, ls_dolares
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
  from pd_ot             pd,
       pd_ot_det         pdd,
       pd_ot_asistencia  pda
  where pd.nro_parte  = pdd.nro_parte
    and pda.nro_item  = pdd.nro_item
    and pda.no_parte  = pdd.nro_parte
    and pdd.cod_maquina = asi_maquina
    and trunc(pd.fecha) between trunc(adi_fecha1) and trunc(adi_fecha2);

  if ln_count = 0 then
     ln_Result := 0;
  else
      select Sum( NVL(pda.nro_horas,0)* usf_fl_conv_mon(NVL(pda.costo_horas,0), ls_soles, ls_dolares, pdd.hora_inicio) * NVL(pda.factor,0))
        into ln_Result
        from pd_ot             pd,
             pd_ot_det         pdd,
             pd_ot_asistencia  pda
        where pd.nro_parte = pdd.nro_parte
          and pda.nro_item  = pdd.nro_item
          and pda.no_parte  = pdd.nro_parte
          and pdd.cod_maquina = asi_maquina
          and trunc(pd.fecha) between trunc(adi_fecha1) and trunc(adi_fecha2);
  end if;


  return(ln_Result);
end usf_mtt_rpt_costo_mo_x_maq;
/

prompt
prompt Creating function USF_MTT_RPT_COSTO_OS_X_MAQ
prompt ============================================
prompt
create or replace function cantabria.usf_mtt_rpt_costo_os_x_maq(
       asi_maquina    in maquina.cod_maquina%TYPE,
       adi_fecha1     in date,
       adi_fecha2     in date
) return number is
  ln_Result     number;
  ln_count      number;
  ls_dolares    logparam.cod_dolares%TYPE;

begin
  select cod_dolares
    into ls_dolares
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
    from orden_Trabajo      ot,
         operaciones        op,
         orden_servicio_det osd,
         orden_Servicio     os,
         tt_mtt_ot_adm      tt1
   where ot.nro_orden = op.nro_orden
     and os.nro_os    = osd.nro_os
     and op.oper_sec  = osd.oper_sec
     and tt1.ot_adm   = ot.ot_adm
     and ot.cod_maquina = asi_maquina
     and trunc(os.fec_registro) between trunc(adi_Fecha1) and trunc(adi_fecha2)
     and osd.flag_estado <> '0'
     and os.flag_estado <> '0';

  if ln_count = 0 then
     ln_Result := 0;
  else
    select sum( usf_fl_conv_mon( NVL(osd.importe,0) - NVL(osd.decuento,0), os.cod_moneda, ls_dolares, osd.fec_proyect) )
      into ln_Result
      from orden_Trabajo      ot,
           operaciones        op,
           orden_servicio_det osd,
           orden_Servicio     os,
           tt_mtt_ot_adm      tt1
     where ot.nro_orden = op.nro_orden
       and os.nro_os    = osd.nro_os
       and op.oper_sec  = osd.oper_sec
       and tt1.ot_adm   = ot.ot_adm
       and ot.cod_maquina = asi_maquina
       and trunc(os.fec_registro) between trunc(adi_Fecha1) and trunc(adi_fecha2)
       and osd.flag_estado <> '0'
       and os.flag_estado <> '0';
  end if;

  return(ln_Result);
end usf_mtt_rpt_costo_os_x_maq;
/

prompt
prompt Creating function USF_NOMBRE_MES
prompt ================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_NOMBRE_MES
(ac_mes IN CHAR)
RETURN VARCHAR IS
lv_result VARCHAR(10);

BEGIN
IF ac_mes = '01' THEN
   lv_result := 'ENERO';
END IF;
IF ac_mes = '02' THEN
   lv_result := 'FEBRERO';
END IF;
IF ac_mes = '03' THEN
   lv_result := 'MARZO';
END IF;
IF ac_mes = '04' THEN
   lv_result := 'ABRIL';
END IF;
IF ac_mes = '05' THEN
   lv_result := 'MAYO';
END IF;
IF ac_mes = '06' THEN
   lv_result := 'JUNIO';
END IF;
IF ac_mes = '07' THEN
   lv_result := 'JULIO';
END IF;
IF ac_mes = '08' THEN
   lv_result := 'AGOSTO';
END IF;
IF ac_mes = '09' THEN
   lv_result := 'SETIEMBRE';
END IF;
IF ac_mes = '10' THEN
   lv_result := 'OCTUBRE';
END IF;
IF ac_mes = '11' THEN
   lv_result := 'NOVIEMBRE';
END IF;
IF ac_mes = '12' THEN
   lv_result := 'DICIEMBRE';
END IF;

RETURN(lv_result);

END USF_NOMBRE_MES;
/

