prompt
prompt Creating function USF_OBTIENE_MESES_DE_TRABAJO
prompt ==============================================
prompt
create or replace function cantabria.USF_OBTIENE_MESES_DE_TRABAJO(
       AD_F_INGRESO IN CONTRATO_RRHH.FECHA_INICIO%TYPE,
       AD_F_CESE IN CONTRATO_RRHH.FECHA_FIN%TYPE
)Return number is

ln_Result number;

begin
     ln_Result := trunc((MONTHS_BETWEEN(AD_F_CESE + 1, AD_F_INGRESO)),0);
     RETURN ln_Result;

end USF_OBTIENE_MESES_DE_TRABAJO;
/

prompt
prompt Creating function USF_OBTIENE_PERIODO_PRUEBA
prompt ============================================
prompt
create or replace function cantabria.USF_OBTIENE_PERIODO_PRUEBA(
AD_F_INGRESO IN CONTRATO_RRHH.FECHA_INICIO%TYPE, AD_F_PRUEBA IN CONTRATO_RRHH.FECHA_FIN%TYPE)
return number is
Result number;
begin
result := ROUND((MONTHS_BETWEEN(AD_F_PRUEBA, AD_F_INGRESO)),0);
RETURN RESULT;
end USF_OBTIENE_PERIODO_PRUEBA;
/

prompt
prompt Creating function USF_OPE_ALMAC_ARTIC
prompt =====================================
prompt
create or replace function cantabria.USF_OPE_ALMAC_ARTIC
(as_origen        origen.cod_origen%type,
 as_cod_art       articulo.cod_art%type)

 return char is

  as_almacen      almacen.almacen%type ;
  an_count        number(2) ;

BEGIN

SELECT count(*)
  INTO an_count
  FROM articulo a, almacen_tacito alt
 WHERE a.cod_art      = as_cod_art and
       a.cod_clase    = alt.cod_clase and
       alt.cod_origen = as_origen ;

IF an_count > 0 THEN
    SELECT MIN(alt.almacen) INTO as_almacen
      FROM articulo a, almacen_tacito alt
     WHERE a.cod_art=as_cod_art and
          a.cod_clase = alt.cod_clase and
          alt.cod_origen= as_origen ;
ELSE
    RAISE_APPLICATION_ERROR( -20000, 'Defina almacen tacito para articulo '||as_cod_art||' - origen '|| as_origen ) ;
END IF ;

RETURN(as_almacen);

END USF_OPE_ALMAC_ARTIC ;
/

prompt
prompt Creating function USF_OPE_ANULA_OT
prompt ==================================
prompt
create or replace function cantabria.usf_ope_anula_ot(
       as_nro_orden in orden_trabajo.nro_orden%TYPE )
return number is

/*
Retorna :
 0 = No debe anularse orden de trabajo
 1 = Procede a anular orden de trabajo
*/

  Result    number;
  ls_doc_ot doc_tipo.tipo_doc%type ;
  ll_count  number;

BEGIN

result := 0 ;

SELECT l.doc_ot INTO ls_doc_ot FROM logparam l WHERE reckey='1' ;

--VERIFICA QUE OPERACIONES NO ESTEN ATENDIDOS
SELECT Count(*)
  INTO ll_count
  FROM operaciones
 WHERE nro_orden = as_nro_orden AND cant_real > 0 ;

IF ll_count>0  THEN
   RAISE_APPLICATION_ERROR( -20000, 'Operaciones tienen cantidad ejecutada ') ;
   return(Result) ;
END IF ;

--VERIFICA QUE LAS OPERACIONES NO ESTEN REGISTRADOS EN UNA ORDEN DE SERVICIO
SELECT count(*)
  INTO ll_count
  FROM operaciones o, orden_servicio_det os
where o.oper_sec=os.oper_sec and
      o.nro_orden = as_nro_orden and
      o.flag_estado <> '0' ;

IF ll_count>0  THEN
  RAISE_APPLICATION_ERROR( -20000, 'Operaciones estan registradas en ordenes de servicio ' );
  RETURN(Result) ;
END IF ;

--VERIFICAR QUE ARTICULOS NO ESTEN ATENDIDOS
SELECT Count(*)
  INTO ll_count
  FROM articulo_mov_proy
 WHERE tipo_doc = ls_doc_ot  AND nro_doc = as_nro_orden AND cant_procesada > 0 ;

IF ll_count > 0 THEN
  RAISE_APPLICATION_ERROR( -20000, 'Articulos de orden de trabajo estan atendidos ' );
  RETURN(Result) ;
END IF ;

Result := 1 ;

RETURN(Result) ;

END usf_ope_anula_ot;
/

prompt
prompt Creating function USF_OPE_COSTO_ART_X_OPERSEC
prompt =============================================
prompt
create or replace function cantabria.usf_ope_costo_art_x_opersec(
       asi_nro_orden     in orden_trabajo.nro_orden%TYPE,
       asi_opersec       in operaciones.oper_sec%TYPE
) return number is

  Result    number;
  ll_count  number;

begin

  select count(*)
    into ll_count
  from pd_ot_det      a,
       pd_ot_insumos  b
  where a.nro_item  = b.nro_item
    and a.nro_parte = b.nro_parte
    and a.nro_orden = asi_nro_orden
    and a.oper_sec  = asi_opersec;

  if ll_count = 0 then
     Result := 0;
  else
      select Sum(NVL(b.cantidad,0)* NVL(b.costo_insumo,0))
        into Result
      from pd_ot_det      a,
           pd_ot_insumos  b
      where a.nro_item  = b.nro_item
        and a.nro_parte = b.nro_parte
        and a.nro_orden = asi_nro_orden
        and a.oper_sec  = asi_opersec;
  end if;

  return(Result);
end usf_ope_costo_art_x_opersec;
/

