prompt
prompt Creating function USF_OPE_COSTO_HORA_PERSONAL
prompt =============================================
prompt
create or replace function cantabria.usf_ope_costo_hora_personal(
       as_cod_trabajador in maestro.cod_trabajador%type,
       as_cod_labor      in labor.cod_labor%type,
       as_cod_ejecutor   in ejecutor.cod_ejecutor%type,
       ad_fecha          in date
) return number is
  Result number;

  -- Objetivo: Debe calcular el costo horario del personal en soles

  ls_cod_moneda             moneda.cod_moneda%type ;
  ls_cod_dolares            logparam.cod_dolares%type ;
  ln_tipo_cambio            calendario.vnt_dol_libre%type ;
  ls_flag_costo_mo_pd       prod_param.flag_costo_mo_pd%type ;
  ln_dias_trab_hab_fijo     tipo_trabajador.dias_trab_hab_fijo%type ;
  ln_factor_costo_hr        tipo_trabajador.factor_costo_hr%type ;
  ls_grc_gnn_fija           rrhhparam.grc_gnn_fija%type ;
  ln_costo_unitario         labor_ejecutor.costo_unitario%type ;
  ln_ganancias_fijas        number ;
  ln_count                  number ;

BEGIN

Result := 0;

-- Verifico si el costo se obtiene por labor_ejecutor o planilla
SELECT NVL(p.flag_costo_mo_pd,'L'), l.cod_dolares, r.grc_gnn_fija
  INTO ls_flag_costo_mo_pd, ls_cod_dolares, ls_grc_gnn_fija
  FROM prod_param p, logparam l, rrhhparam r
 WHERE ( p.reckey = l.reckey )
   AND ( p.reckey = r.reckey )
   AND ( p.reckey = 1 ) ;

-- Hallando el tipo de cambio
ln_tipo_cambio := USF_CMP_TIPO_CAMBIO(ad_fecha) ;

-- Hallando el costo de la labor_ejecutor
IF ls_flag_costo_mo_pd = 'L' THEN

   SELECT le.cod_moneda, le.costo_unitario
     INTO ls_cod_moneda, ln_costo_unitario
     FROM labor_ejecutor le
    WHERE le.cod_labor = as_cod_labor
      AND le.cod_ejecutor = as_cod_ejecutor ;

   IF ls_cod_moneda = ls_cod_dolares THEN
      Result := ln_costo_unitario * ln_tipo_cambio ;
   ELSE
      Result := ln_costo_unitario ;
   END IF ;

-- Hallando el costo del trabajador
ELSE
   SELECT count(*)
     INTO ln_count
     FROM maestro m
    WHERE m.cod_trabajador = as_cod_trabajador ;

   IF ln_count = 0 THEN
      RETURN(0) ;
   END IF ;

   SELECT m.cod_moneda, t.dias_trab_hab_fijo, t.factor_costo_hr
     INTO ls_cod_moneda, ln_dias_trab_hab_fijo, ln_factor_costo_hr
     FROM maestro m, tipo_trabajador t
    WHERE m.tipo_trabajador = t.tipo_trabajador
      AND m.cod_trabajador = as_cod_trabajador ;

		SELECT Sum(Round( ln_factor_costo_hr * g.imp_gan_desc / (8 * ln_dias_trab_hab_fijo) ,2))
      INTO ln_ganancias_fijas
      FROM gan_desct_fijo g
     WHERE  ( g.cod_trabajador      = as_cod_trabajador ) AND
		        (( Substr(g.concep,1,2) = ls_grc_gnn_fija ) AND
		        ( g.flag_estado         = '1'   ) );
--  GROUP BY cod_trabajador  ;

  IF ln_ganancias_fijas is null then ln_ganancias_fijas := 0; end if;

  IF ls_cod_moneda = ls_cod_dolares THEN
     result := ln_ganancias_fijas * ln_tipo_cambio ;
  ELSE
     result := ln_ganancias_fijas ;
  END IF ;
END IF ;

RETURN(Result);

END usf_ope_costo_hora_personal ;
/

prompt
prompt Creating function USF_OPE_COSTO_JOR_X_OPERSEC
prompt =============================================
prompt
create or replace function cantabria.usf_ope_costo_jor_x_opersec(
       asi_nro_orden    in orden_trabajo.nro_orden%TYPE,
       asi_opersec      in operaciones.oper_sec%TYPE
) return number is

  Result    number;
  ll_count  number;
begin

  select count(*)
    into ll_count
  from pd_ot_det         a,
       pd_ot_asistencia  b
  where a.nro_item  = b.nro_item
    and a.nro_parte = b.no_parte
    and a.nro_orden = asi_nro_orden
    and a.oper_sec = asi_opersec;

  if ll_count = 0 then
     Result := 0;
  else
      select Sum(NVL(b.nro_horas,0)* NVL(b.costo_horas,0) * NVL(b.factor,0))
        into Result
      from pd_ot_det         a,
           pd_ot_asistencia  b
      where a.nro_item  = b.nro_item
        and a.nro_parte = b.no_parte
        and a.nro_orden = asi_nro_orden
        and a.oper_sec  = asi_opersec;
  end if;

  return(Result);
end usf_ope_costo_jor_x_opersec;
/

prompt
prompt Creating function USF_OPE_COSTO_JOR_X_OT
prompt ========================================
prompt
create or replace function cantabria.usf_ope_costo_jor_x_ot(
       asi_nro_orden    in orden_trabajo.nro_orden%TYPE
) return number is

  ln_Result     number;
  ln_count      number;
  ls_dolares    logparam.cod_dolares%TYPE;
  ls_soles      logparam.cod_soles%TYPE;

begin
  select cod_soles, cod_dolares
    into ls_soles, ls_dolares
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
  from pd_ot_det         a,
       pd_ot_asistencia  b
  where a.nro_item  = b.nro_item
    and a.nro_parte = b.no_parte
    and a.nro_orden = asi_nro_orden;

  if ln_count = 0 then
     ln_Result := 0;
  else
      select Sum( NVL(b.nro_horas,0)* usf_fl_conv_mon(NVL(b.costo_horas,0), ls_soles, ls_dolares, a.hora_inicio) * NVL(b.factor,0))
        into ln_Result
      from pd_ot_det         a,
           pd_ot_asistencia  b
      where a.nro_item  = b.nro_item
        and a.nro_parte = b.no_parte
        and a.nro_orden = asi_nro_orden;
  end if;

  return(ln_Result);
end usf_ope_costo_jor_x_ot;
/

prompt
prompt Creating function USF_OPE_COSTO_OS_X_OPERSEC
prompt ============================================
prompt
create or replace function cantabria.usf_ope_costo_os_x_opersec(
       asi_nro_orden      in orden_trabajo.nro_orden%TYPE,
       asi_opersec       in operaciones.oper_sec%TYPE
) return number is

  Result    number;
  ll_count  number;
begin

  select count(*)
    into ll_count
    from operaciones op,
         orden_servicio_det asd
   where op.oper_sec = asd.oper_sec
     and op.nro_orden = asi_nro_orden
     and op.oper_Sec = asi_opersec;

  if ll_count = 0 then
     Result := 0;
  else
    select sum(NVL(asd.importe,0))
      into Result
      from operaciones op,
           orden_servicio_det asd
     where op.oper_sec = asd.oper_sec
       and op.nro_orden = asi_nro_orden
       and op.oper_sec = asi_opersec;
  end if;

  return(Result);
end usf_ope_costo_os_x_opersec;
/

prompt
prompt Creating function USF_OPE_COSTO_OS_X_OT
prompt =======================================
prompt
create or replace function cantabria.usf_ope_costo_os_x_ot(
       asi_nro_orden      in orden_trabajo.nro_orden%TYPE
) return number is

  ln_Result     number;
  ln_count      number;
  ls_dolares    logparam.cod_dolares%TYPE;

begin
  select cod_dolares
    into ls_dolares
    from logparam
   where reckey = '1';

  select count(*)
    into ln_count
    from operaciones        op,
         orden_servicio_det osd,
         orden_Servicio     os
   where os.nro_os    = osd.nro_os
     and op.oper_sec  = osd.oper_sec
     and op.nro_orden = asi_nro_orden
     and osd.flag_estado <> '0'
     and os.flag_estado <> '0';

  if ln_count = 0 then
     ln_Result := 0;
  else
    select sum( usf_fl_conv_mon( NVL(osd.importe,0) - NVL(osd.decuento,0), os.cod_moneda, ls_dolares, osd.fec_proyect) )
      into ln_Result
      from operaciones        op,
           orden_servicio_det osd,
           orden_servicio     os
     where os.nro_os    = osd.nro_os
       and op.oper_sec  = osd.oper_sec
       and op.nro_orden = asi_nro_orden
       and osd.flag_estado <> '0'
       and os.flag_estado <> '0';
  end if;

  return(ln_Result);
end usf_ope_costo_os_x_ot;
/

prompt
prompt Creating function USF_OPE_COSTO_OT
prompt ==================================
prompt
create or replace function cantabria.usf_ope_costo_ot(
       asi_nro_orden   in orden_trabajo.nro_orden%TYPE
) return number is
  Result number;

  Cursor c_ot_cargos is
    select otdc.nro_orden, otdc.porcentaje
    from ot_distribucion_costo otdc
    where otdc.nro_ot_cargo = asi_nro_orden;
begin
  Result := 0;
  -- Sumo Los Materiales de la OT
  Result := usf_ope_costo_art_x_ot(asi_nro_orden);

  -- Sumo la Mano de Obra Jornal
  Result := Result + usf_ope_costo_jor_x_ot(asi_nro_orden);

  -- Sumo la Mano de Obra Destajo
  Result := Result + usf_ope_costo_dstj_x_ot(asi_nro_orden);

  -- Sumo los servicios de Terceros
  Result := Result + usf_ope_costo_os_x_ot(asi_nro_orden);

  --Sumo las Otras OT que estan cargadas
  for lc_reg in c_ot_cargos loop
      Result := Result + usf_ope_costo_ot(lc_reg.nro_orden) * lc_Reg.porcentaje / 100;
  end loop;


  return(Result);
end usf_ope_costo_ot;
/

prompt
prompt Creating function USF_OPE_COSTO_OTRAS_OT
prompt ========================================
prompt
create or replace function cantabria.usf_ope_costo_otras_ot(
       asi_nro_orden   in orden_trabajo.nro_orden%TYPE
) return number is
  Result number;

  Cursor c_ot_cargos is
    select otdc.nro_orden, otdc.porcentaje
    from ot_distribucion_costo otdc
    where otdc.nro_ot_cargo = asi_nro_orden;
begin
  Result := 0;

  --Sumo las Otras OT que estan cargadas
  for lc_reg in c_ot_cargos loop
      Result := Result + usf_ope_costo_ot(lc_reg.nro_orden) * lc_Reg.porcentaje / 100;
  end loop;


  return(Result);
end usf_ope_costo_otras_ot;
/

prompt
prompt Creating function USF_OPE_COSTO_X_MAQ
prompt =====================================
prompt
create or replace function cantabria.USF_OPE_COSTO_X_MAQ
(ac_cod_maquina in maquina.cod_maquina%type  ,
 ac_tipo_maq    in maquina.tipo_maquina%type ,
 ac_cod_labor   in labor.cod_labor%type       )

 return number is
  Result Number;

ln_count Number ;

begin

 select count(*) into ln_count
    from maquina_tipo_labor mtl
   where (mtl.tipo_maquina = ac_tipo_maq  ) and
         (mtl.cod_labor    = ac_cod_labor ) ;

  if ln_count > 0 then
     select mtl.costo_und into result
       from maquina_tipo_labor mtl
      where (mtl.tipo_maquina = ac_tipo_maq  ) and
            (mtl.cod_labor    = ac_cod_labor ) ;

  else
     select m.costo_x_und into result
       from maquina m
      where (m.cod_maquina = ac_cod_maquina) ;


  end if ;


  if result is null then
     result := 0 ;
  end if ;

  return(Result);
end USF_OPE_COSTO_X_MAQ;
/

prompt
prompt Creating function USF_OPE_COST_REAL_OPERSEC
prompt ===========================================
prompt
create or replace function cantabria.usf_ope_cost_real_opersec
(as_opersec operaciones.oper_sec%type)
return number is

  Result number;
Begin
  Select Sum((nvl(pdd.cant_labor,0) - nvl(pdd.horas_inciden,0))*nvl(le.costo_unitario,0))
  into Result
  from pd_ot_det pdd, labor_ejecutor le
  where pdd.oper_sec = as_opersec
  and pdd.cod_labor = le.cod_labor
  and pdd.cod_ejecutor = le.cod_ejecutor;

  return(Result);

end usf_ope_cost_real_opersec;
/

prompt
prompt Creating function USF_OPE_ESTADO_OPER_SEC
prompt =========================================
prompt
create or replace function cantabria.USF_OPE_ESTADO_OPER_SEC
(lc_nro_parte in pd_ot_det.nro_parte%type,
 ln_nro_item  in pd_ot_det.nro_item%type ,
 lc_oper_sec  in pd_ot_det.oper_sec%type  )


 return varchar2 is
 lc_flag_estado varchar2 (1);

Cursor c_pd_det is
SELECT nro_parte,nro_item,flag_terminado
  FROM pd_ot_det
 WHERE ((nro_parte NOT IN (lc_nro_parte))  or
	      (nro_item  NOT IN (ln_nro_item) )) and
        (oper_sec  =  lc_oper_sec  ) ;


begin

  lc_flag_estado := NULL ; --activo

  For rc_pd in c_pd_det Loop
      IF rc_pd.flag_terminado = '1' THEN
         lc_flag_estado := 1 ; --terminado
         EXIT  ;
      END IF ;
  End Loop ;

  return(lc_flag_estado);
end USF_OPE_ESTADO_OPER_SEC;
/

prompt
prompt Creating function USF_OPE_FEC_INICIAL
prompt =====================================
prompt
create or replace function cantabria.USF_OPE_FEC_INICIAL
(as_nro_orden    in orden_trabajo.nro_orden%type )


 return date is
  Result date;

ld_fec_reg_art_min Date ;
ld_fec_reg_lab_min Date ;


begin

--articulos
select Min(tta.fec_registro) into ld_fec_reg_art_min from tt_ope_det_art_costo tta
 where (tta.flag_inf  = 'AR'         ) and
       (tta.nro_orden = as_nro_orden ) ;

--labores
select Min(ttl.fec_inicio) into ld_fec_reg_lab_min from tt_ope_det_labor_costo ttl
 where (ttl.flag_inf  = 'LR'         ) and
       (ttl.nro_orden = as_nro_orden ) ;

--inicio de actividades

  if (ld_fec_reg_art_min is null) then
     Result := ld_fec_reg_lab_min ;
  elsif (ld_fec_reg_lab_min is null) then
     Result := ld_fec_reg_art_min ;
  elsif ld_fec_reg_art_min < ld_fec_reg_lab_min then
     Result := ld_fec_reg_art_min ;
  elsif ld_fec_reg_lab_min < ld_fec_reg_art_min then
     Result := ld_fec_reg_lab_min ;
  end if ;


  return(Result);
end USF_OPE_FEC_INICIAL;
/

prompt
prompt Creating function USF_OPE_FEC_MAXIMO
prompt ====================================
prompt
create or replace function cantabria.USF_OPE_FEC_MAXIMO
(as_nro_orden    in orden_trabajo.nro_orden%type )


 return date is
  Result date;

ld_fec_reg_art_max Date ;
ld_fec_reg_lab_max Date ;


begin

--articulos
select Max(tta.fec_registro) into ld_fec_reg_art_max from tt_ope_det_art_costo tta
 where (tta.flag_inf  = 'AR'         ) and
       (tta.nro_orden = as_nro_orden ) ;

--labores
select Max(ttl.fec_inicio) into ld_fec_reg_lab_max from tt_ope_det_labor_costo ttl
 where (ttl.flag_inf  = 'LR'         ) and
       (ttl.nro_orden = as_nro_orden ) ;


--final de actividades
if (ld_fec_reg_art_max is null) then
   result := ld_fec_reg_lab_max ;
elsif (ld_fec_reg_lab_max is null) then
   result := ld_fec_reg_art_max ;
elsif ld_fec_reg_art_max > ld_fec_reg_lab_max then
   result := ld_fec_reg_art_max ;
elsif ld_fec_reg_lab_max > ld_fec_reg_art_max then
   result := ld_fec_reg_lab_max ;
end if ;


  return(Result);
end USF_OPE_FEC_MAXIMO;
/

prompt
prompt Creating function USF_OPE_INGRESO_ALMACEN
prompt =========================================
prompt
create or replace function cantabria.usf_ope_ingreso_almacen(
as_opersec in operaciones.oper_sec%type,
as_cod_art in articulo.cod_art%type
) return number is
  Result    number;
  ls_doc_oc     logparam.doc_oc%TYPE;
begin

  select doc_oc
    into ls_doc_oc
    from logparam
   where reckey = '1';

/*Select sum(nvl(am.cant_procesada,0))
into Result
from vale_mov vm, articulo_mov am
where vm.cod_origen = am.cod_origen
and vm.nro_vale = am.nro_vale
and nvl(vm.flag_estado,'0') <> '0'
and vm.tipo_mov = (select l.oper_ing_oc from logparam l where reckey='1')
and nvl(am.flag_estado,'0') <> '0'
and am.cod_art = as_cod_art
and am.oper_sec = as_opersec;
*/
    select sum(am.cant_procesada)
        into Result
        from articulo_mov_proy amp,
             articulo_mov      am
       where am.nro_mov_proy    = amp.nro_mov
         and am.origen_mov_proy = amp.cod_origen
         and amp.oper_sec = as_opersec
         and amp.cod_art  = as_cod_art
         and amp.tipo_doc     = ls_doc_oc
         --and amp.almacen      = asi_almacen
         and amp.flag_estado <> '0'
         and am.flag_estado <> '0';


  return(Result);
end usf_ope_ingreso_almacen;
/

prompt
prompt Creating function USF_OPE_NUM_APROBACION_OT
prompt ===========================================
prompt
create or replace function cantabria.USF_OPE_NUM_APROBACION_OT
( as_origen       origen.cod_origen%type ) return varchar2 is

  lc_ult_nro      ot_aprobaciones.nro_aprob%TYPE;
  ln_ult_nro      number(10) ;
  ll_count        number;

begin

  select count(*)
    into ll_count
  from num_ot_aprobacion
  where origen = as_origen;

  if ll_count = 0 then
     insert into num_ot_aprobacion(origen, ult_nro)
     values (as_origen, 2);

     ln_ult_nro := 1;
  else
     select ult_nro
       into ln_ult_nro
     from num_ot_aprobacion
     where origen = as_origen
       for update;

     update num_ot_aprobacion
        set ult_nro = ult_nro + 1
      where origen = as_origen;

  end if;

  --se concatena con origen
  lc_ult_nro := trim(as_origen) || trim(to_char(ln_ult_nro,'00000000')) ;

  return trim(lc_ult_nro);
end USF_OPE_NUM_APROBACION_OT;
/

prompt
prompt Creating function USF_OPE_NUM_PD_OT
prompt ===================================
prompt
create or replace function cantabria.USF_OPE_NUM_PD_OT
(ac_cod_origen origen.cod_origen%type)

 return varchar2 is
  lc_ult_nro_parte pd_ot.nro_parte%type ;

ln_ult_nro num_pd_ot.ult_nro%type ;

begin
  --numerador de detraccion
  select npo.ult_nro into ln_ult_nro from num_pd_ot npo  where (npo.origen = ac_cod_origen) for update nowait;

  --se concatena con origen
  lc_ult_nro_parte := rtrim(ltrim(ac_cod_origen))||LPAD(rtrim(ltrim(to_char(ln_ult_nro))),8,'0') ;

  --actualiza informacion e numeradores
  update num_pd_ot npo
     set npo.ult_nro = Nvl(npo.ult_nro,0) + 1
   where (npo.origen = ac_cod_origen ) ;

  return(lc_ult_nro_parte);

end USF_OPE_NUM_PD_OT ;
/

prompt
prompt Creating function USF_OPE_NUM_RESERVADOS
prompt ========================================
prompt
create or replace function cantabria.USF_OPE_NUM_RESERVADOS(
       asi_origen origen.cod_origen%type
)
return varchar2 is

  ls_ult_nro        reservacion.nro_reservacion%type;
  ln_ult_nro        num_reservacion.ult_nro%type ;
  ln_count          number;

begin
  --numerador de operaciones
  select count(*)
    into ln_count
    from num_reservacion n
   where n.origen = asi_origen;

  if ln_count = 0 then
     insert into num_reservacion(origen, ult_nro)
     values(asi_origen, 1);
  end if;

  select ult_nro
    into ln_ult_nro
    from num_reservacion
   where origen = asi_origen for update;

  --se concatena con origen
  ls_ult_nro := trim(asi_origen) || LPAD(trim(to_char(ln_ult_nro)),8,'0') ;

  --actualiza informacion e numeradores
  update num_reservacion
     set ult_nro = Nvl(ult_nro,0) + 1
   where origen = asi_origen ;

  return trim(ls_ult_nro);

end USF_OPE_NUM_RESERVADOS;
/

