prompt
create or replace function cantabria.USF_OPE_OPERADOR_MAQUINA
(as_nro_parte pd_ot_det.nro_parte%type,
 as_nro_item  pd_ot_det.nro_item%type)

return  char is
  ls_nombre  proveedor.nom_proveedor%type ;
  ln_item    number ;

Cursor c_asistencia is
SELECT p.nom_proveedor
