prompt
prompt Creating function USF_OPERACIONES_FECHAS
prompt ========================================
prompt
create or replace function cantabria.usf_operaciones_fechas
       (ad_fec_inicio in date, ad_fec_final in date,
        ad_ope_fec_inicio in date,
        ad_ope_fec_final in date,
        ad_ope_dias_duracion_proy in number
        ) return integer is
        -- "ope_" por tabla "operaciones"
  kn_verdadero constant integer := 1;
  kn_falso     constant integer := 0;
  ld_fec_final date;
  ld_hoy date;
begin

  if ad_ope_fec_inicio > ad_fec_final Then
     -- se inicia posterior a la fecha solicitada
     return ( kn_falso ) ;
  end if;

  -- determina fecha actual
  select sysdate
     into ld_hoy from dual;

  -- determinar fecha final
  If ad_ope_fec_final is Not null Then
     ld_fec_final :=  ad_ope_fec_final;
  Else


     ld_fec_final :=  ad_ope_fec_inicio +  nvl( ad_ope_dias_duracion_proy, 0 );
     if ld_fec_final < ld_hoy Then
        -- aun no termina... asume termine hoy
        ld_fec_final := ld_hoy;
     End If;
  End if;

  If ld_fec_final < ad_fec_inicio Then
     -- termina antes de la fecha solicitada
     return ( kn_falso ) ;
  End If;

  return(kn_verdadero);
end usf_operaciones_fechas;
/

prompt
prompt Creating function USF_OPERACIONES_FECHAS_TRUNC
prompt ==============================================
prompt
create or replace function cantabria.usf_operaciones_fechas_trunc
       (ad_fec_inicio in date, ad_fec_final in date,
        ad_ope_fec_inicio in date,
        ad_ope_fec_final in date,
        ad_ope_dias_duracion_proy in number
        ) return integer is
        -- "ope_" por tabla "operaciones"
  kn_verdadero constant integer := 1;
  kn_falso     constant integer := 0;
  ld_fec_final date;
  ld_hoy date;
begin

  if ad_ope_fec_inicio > ad_fec_final Then
     -- se inicia posterior a la fecha solicitada
     return ( kn_falso ) ;
  end if;

  -- determina fecha actual
  select sysdate
     into ld_hoy from dual;

  -- determinar fecha final
  If ad_ope_fec_final is Not null Then
     ld_fec_final :=  ad_ope_fec_final;
  Else
     ld_fec_final :=  ad_ope_fec_inicio +
                      nvl( ad_ope_dias_duracion_proy, 0 );
  -- if ld_fec_final < ld_hoy Then
  --    -- aun no termina... asume termine hoy
  --    ld_fec_final := ld_hoy;
  -- End If;
  End if;

  If ld_fec_final < ad_fec_inicio Then
     -- termina antes de la fecha solicitada
     return ( kn_falso ) ;
  End If;

  return(kn_verdadero);
end usf_operaciones_fechas_trunc;
/

prompt
prompt Creating function USF_OPE_RESERV_AUT
prompt ====================================
prompt
create or replace function cantabria.USF_OPE_RESERV_AUT(
       asi_org_amp_ref     IN articulo_mov_proy.cod_origen%TYPE,
       ani_nro_amp_ref     IN articulo_mov_proy.nro_mov%TYPE,
       ani_cant_reserv     IN reservacion_det.cantidad%TYPE,
       asi_usuario         IN articulo_mov_proy.cod_usr%TYPE,
       adi_fecha           IN DATE
) return VARCHAR2 is

  --PRAGMA AUTONOMOUS_TRANSACTION;

  ln_ult_nro              num_reservacion.ult_nro%TYPE;
  ls_reservacion          reservacion.nro_reservacion%TYPE;
  ls_Result               VARCHAR2(1000);
  ld_date                 DATE  := adi_fecha;
  ln_count                NUMBER;
  ln_nro_item             NUMBER;
  ld_fec_vencim           reservacion_det.fec_vencimiento%TYPE;
  ln_dias_venc_reservac   logparam.dias_venc_reservac%TYPE;

BEGIN

  -- Obtengo los dias de vencimiento, por defecto 7
  SELECT NVL(dias_venc_reservac,7)
    INTO ln_dias_venc_reservac
    FROM logparam
   WHERE reckey = '1';

  -- Tener cuidado que esta funcion se llama del trigger TUB_ARTICULO_MOV_PROY, asi que hay
  -- tener cuidado con eso

  SELECT COUNT(*)
    INTO ln_count
    FROM reservacion r
   WHERE ano = to_number(to_char(ld_date, 'yyyy'))
     AND mes = to_number(to_char(ld_date, 'mm'))
     AND r.flag_automatico = '1'
     AND r.cod_origen = asi_org_amp_ref;

  IF ln_count >= 1 THEN
     SELECT MIN(r.nro_reservacion)
       INTO ls_reservacion
       FROM reservacion r
      WHERE ano = to_number(to_char(ld_date, 'yyyy'))
        AND mes = to_number(to_char(ld_date, 'mm'))
        AND r.flag_automatico = '1'
        AND r.cod_origen = asi_org_amp_ref;
  ELSE
     SELECT COUNT(*)
       INTO ln_count
       FROM num_reservacion
      WHERE origen = asi_org_amp_ref;

     IF ln_count = 0 THEN
        ln_ult_nro := 1;
        INSERT INTO num_reservacion(Origen, ult_nro)
        VALUES(asi_org_amp_ref, ln_ult_nro);
     ELSE
        SELECT ult_nro
          INTO ln_ult_nro
          FROM num_reservacion
         WHERE origen = asi_org_amp_ref FOR UPDATE;

     END IF;
     ls_reservacion := ltrim(rtrim(asi_org_amp_ref)) || ltrim(rtrim(to_char(ln_ult_nro, '00000000')));

     ln_ult_nro := ln_ult_nro + 1;

     UPDATE num_reservacion
        SET ult_nro = ln_ult_nro
      WHERE origen = asi_org_amp_ref;

     INSERT INTO reservacion(
            nro_reservacion, cod_usr, fecha, cod_origen, flag_estado, obs, flag_automatico,
            ano, mes)
     VALUES(
            ls_reservacion, asi_usuario, ld_date, asi_org_amp_ref, '2',
            'RESERVACION AUTOMATICA, POR APROBACION DE REQUERIMIENTO DE OT', '1',
            to_number(to_char(ld_date, 'yyyy')), to_number(to_char(ld_date, 'mm')) );

  END IF;

  SELECT NVL(MAX(nro_item),0)
    INTO ln_nro_item
    FROM reservacion_det
   WHERE nro_reservacion = ls_reservacion;

  ln_nro_item := ln_nro_item + 1;
  ld_fec_vencim := trunc(SYSDATE) + ln_dias_venc_reservac;

  INSERT INTO reservacion_det(
         nro_reservacion, nro_item, org_amp_ref,nro_amp_ref, cantidad, flag_estado,
         fec_registro, fec_vencimiento, cod_usr)
  VALUES(
         ls_reservacion, ln_nro_item, asi_org_amp_ref, ani_nro_amp_ref, ani_cant_reserv,
         '1', SYSDATE, ld_fec_vencim, asi_usuario);

  ls_result := NULL;

  RETURN (ls_Result);

end USF_OPE_RESERV_AUT;
/

prompt
prompt Creating function USF_OPE_SALDO_ALMACEN
prompt =======================================
prompt
create or replace function cantabria.usf_ope_saldo_almacen(
as_cod_art in articulo.cod_art%type
) return number is
  Result    number;
begin

  select Sum(NVL(aa.sldo_total,0)+nvl(aa.sldo_consignacion,0))
    into Result
    from articulo_almacen aa
   where aa.cod_art  = as_cod_art;


  return(Result);
