prompt
prompt Creating function USF_OPE_SALDO_RESERVADO
prompt =========================================
prompt
create or replace function cantabria.USF_OPE_SALDO_RESERVADO
(as_origen        articulo_mov_proy.cod_origen%type,
 an_nro_mov       articulo_mov_proy.nro_mov%type)

 return number is
  ln_cant_ing    articulo_mov.cant_procesada%type ;
  ln_cant_sal    articulo_mov.cant_procesada%type ;
  ln_cantidad    articulo_mov.cant_procesada%type ;
  ln_count       number ;

BEGIN

ln_cant_ing := 0 ;
ln_cant_sal := 0 ;
ln_cantidad := 0 ;

-- Calculando los ingresos por compra de un AMP
SELECT count(*)
  INTO ln_count
  FROM vale_mov vm, articulo_mov am
 WHERE vm.cod_origen = am.cod_origen and
       vm.nro_vale  = am.nro_vale and
       vm.tipo_mov = (select l.oper_ing_oc from logparam l where l.reckey='1' ) and
       vm.flag_estado <> '0' and
       am.flag_estado <> '0' and
       am.origen_mov_proy = as_origen and
       am.nro_mov_proy = an_nro_mov ;

IF ln_count > 0 THEN
  SELECT SUM( NVL(am.cant_procesada,0))
    INTO ln_cant_ing
    FROM vale_mov vm, articulo_mov am
   WHERE vm.cod_origen = am.cod_origen and
         vm.nro_vale =  am.nro_vale and
         vm.tipo_mov = (select l.oper_ing_oc from logparam l where l.reckey='1' ) and
         vm.flag_estado <> '0' and
         am.flag_estado <> '0' and
         am.origen_mov_proy = as_origen and
         am.nro_mov_proy = an_nro_mov ;
END IF ;

-- Calculando los salidas por consumo de un AMP
SELECT count(*)
  INTO ln_count
  FROM vale_mov vm, articulo_mov am
 WHERE vm.cod_origen = am.cod_origen and
       vm.nro_vale =  am.nro_vale and
       vm.tipo_mov = (select l.oper_cons_interno from logparam l where l.reckey='1' ) and
       vm.flag_estado <> '0' and
       am.flag_estado <> '0' and
       am.origen_mov_proy = as_origen and
       am.nro_mov_proy = an_nro_mov ;

IF ln_count > 0 THEN
  SELECT SUM( NVL(am.cant_procesada,0))
    INTO ln_cant_sal
    FROM vale_mov vm, articulo_mov am
   WHERE vm.cod_origen = am.cod_origen and
         vm.nro_vale =  am.nro_vale and
         vm.tipo_mov = (select l.oper_cons_interno from logparam l where l.reckey='1' ) and
         vm.flag_estado <> '0' and
         am.flag_estado <> '0' and
         am.origen_mov_proy = as_origen and
         am.nro_mov_proy = an_nro_mov ;
END IF ;

IF ln_cant_ing > ln_cant_sal THEN
   ln_cantidad := ln_cant_ing - ln_cant_sal ;
END IF ;

RETURN(ln_cantidad);

END USF_OPE_SALDO_RESERVADO ;
/

prompt
prompt Creating function USF_OPE_SERV_OPER_SEC
prompt =======================================
prompt
create or replace function cantabria.usf_ope_serv_oper_sec
(ac_oper_sec in operaciones.oper_sec%type)

 return number is
  Result number;

lc_origen  origen.cod_origen%type     ;
lc_nro_os  orden_servicio.nro_os%type ;
lc_soles   moneda.cod_moneda%type     ;
lc_dolares moneda.cod_moneda%type     ;
ln_count   number                     ;
lc_moneda  moneda.cod_moneda%type     ;
ln_importe caja_bancos.imp_total%type ;
ln_tasa_cambio caja_bancos.tasa_cambio%type  ;

begin

  ln_importe := 0 ;
  --parametros
  select l.cod_soles , l.cod_dolares into lc_soles,lc_dolares from logparam l where l.reckey = '1' ;

  select count(*) into ln_count from orden_servicio_det where (oper_sec = ac_oper_sec) ;

  if ln_count > 0 then
     select osd.cod_origen ,osd.nro_os into lc_origen ,lc_nro_os from orden_servicio_det osd where (oper_sec = ac_oper_sec) ;

     --BUSCAR MONEDA DE ORDEN DE SERVICIO
     select cod_moneda into lc_moneda from orden_servicio osd
      where (osd.cod_origen = lc_origen ) and
            (osd.nro_os     = lc_nro_os ) ;

     if lc_moneda = lc_soles then
        select sum(importe) into ln_importe  from orden_servicio_det  osd
         where (osd.oper_sec = ac_oper_sec )
         group by osd.oper_sec ;


        if ln_importe > 0 then
           ln_tasa_cambio := usf_fin_tasa_cambio(sysdate) ;
        end if ;

        ln_importe := Round(ln_importe / ln_tasa_cambio,2) ;

     elsif lc_moneda = lc_dolares then
        select sum(importe) into ln_importe  from orden_servicio_det  osd
         where (osd.oper_sec = ac_oper_sec )
         group by osd.oper_sec ;


     end if ;

  end if ;


  result := ln_importe ;

  return(Result);

end usf_ope_serv_oper_sec;
/

prompt
prompt Creating function USF_OPE_ULTIMA_MARCA
prompt ======================================
prompt
create or replace function cantabria.USF_OPE_ULTIMA_MARCA(AD_FECHA IN DATE) return varchar2 is
  Result Varchar2 (250);

  ln_count Number ;
  ld_fecha Date   ;
begin

  SELECT COUNT(*) INTO LN_COUNT FROM PESAJE_BALANZA_DSTJ
   WHERE to_char(FECHA,'yyyymmdd') = to_char(AD_FECHA,'yyyymmdd') ;

  if ln_count > 0 then
     SELECT max(fecha) INTO ld_fecha FROM PESAJE_BALANZA_DSTJ
      WHERE to_char(FECHA,'yyyymmdd') = to_char(AD_FECHA,'yyyymmdd') ;

     Result := 'Ultima Marcacion Realizada '||to_char(ld_fecha,'dd/mm/yyyy hh24:mi:ss' ) ;
  else
     Result := 'No Existen Marcaciones Realizadas en fecha final del reporte'  ;
  end if ;

  return(Result);
end USF_OPE_ULTIMA_MARCA;
/

prompt
prompt Creating function USF_OPE_X_OPERACION
prompt =====================================
prompt
create or replace function cantabria.USF_OPE_X_OPERACION
(ac_cod_labor    in operaciones.cod_labor%type ,
 ac_cod_ejecutor in operaciones.oper_sec%type  ,
 ac_nro_orden    in operaciones.nro_orden%type ,
 ac_und          in char            )




return number is
  Result number;

Cursor c_parte is
select Sum(pot.cant_labor)    as cant_labor ,
       Sum(pot.horas_inciden) as hrs_inc    ,
       Sum(pot.costo_labor)   as cost_lab
  from pd_ot_det pot
 where (pot.cod_labor    = ac_cod_labor    ) and
       (pot.cod_ejecutor = ac_cod_ejecutor ) and
       (pot.nro_orden    = ac_nro_orden    )
Group by pot.cod_labor,pot.cod_ejecutor ;


ln_tasa_cambio caja_bancos.tasa_cambio%type ;


begin

--tipo de cambio del dia
select c.vta_dol_prom into ln_tasa_cambio from calendario c where to_char(c.fecha,'yyyymmdd') = to_char(sysdate,'yyyymmdd') ;

Result := 0.00 ;


For rc_parte in c_parte Loop

    --de acuerdo a tipo de unidad x hora
    if ac_und = 'H' then
       result := result + Round(((rc_parte.cant_labor - rc_parte.hrs_inc) * rc_parte.cost_lab) / ln_tasa_cambio ,2)  ;
    else
       result := result + ((rc_parte.cant_labor - rc_parte.hrs_inc) * rc_parte.cost_lab)   ;
    end if;

End Loop ;




  return(Result);

end USF_OPE_X_OPERACION;
/

prompt
prompt Creating function USF_PARTE_MOLIE_GUARD_VAR
prompt ===========================================
prompt
create or replace function cantabria.usf_parte_molie_guard_var(
   as_corr_corte in string) return string is

   cursor c_variedad is
      Select sd.variedad
        from semilla_det sd
       where sd.corr_corte = as_corr_corte
       order by sd.has_sembradas desc;

   ls_variedad semilla_det.variedad%type ;

begin

   ls_variedad := NULL ;

   For rc_v in c_variedad
   Loop
      ls_variedad := rc_v.variedad ;
      exit ;
   End Loop ;

   return( ls_variedad );
end usf_parte_molie_guard_var;
/

