prompt Creating function USF_PLA_INA_TAR_FER
prompt =====================================
prompt
create or replace function cantabria.usf_pla_ina_tar_fer(
   ad_fecha in date, -- fecha a ser comparada
   ad_fer1 in date, ad_fer2 in date, ad_fer3 in date,
   ad_fer4 in date, ad_fer5 in date,
   as_tiptra in char -- Obrero pierde dominicales, empleado no
   ) return number is
  ln_dias number;
begin
   ln_dias := 1;
   If ad_fer1 is not null then
      If ad_fer1 > ad_fecha Then
         ln_dias := ln_dias + 1;
      End If;
   End IF;
   If ad_fer2 is not null then
      If ad_fer2 > ad_fecha Then
         ln_dias := ln_dias + 1;
      End If;
   End IF;
   If ad_fer3 is not null then
      If ad_fer3 > ad_fecha Then
         ln_dias := ln_dias + 1;
      End If;
   End IF;
   If ad_fer4 is not null then
      If ad_fer4 > ad_fecha Then
         ln_dias := ln_dias + 1;
      End If;
   End IF;
   If ad_fer5 is not null then
      If ad_fer5 > ad_fecha Then
         ln_dias := ln_dias + 1;
      End If;
   End IF;

  return(ln_dias);
end usf_pla_ina_tar_fer;
/

prompt
prompt Creating function USF_PTO_SLDO_ACUMULADO_ANUAL
prompt ==============================================
prompt
create or replace function cantabria.USF_PTO_SLDO_ACUMULADO_ANUAL(
   an_ano in number, as_cencos in char, as_cnta_prsp in char)
     return number is
  Result number;
begin

    --==========================
  -- Acumulado Anual
  --==========================
  Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
        NVL(p.proy_oct,0) + NVL( p.proy_nov,0) + NVL( p.proy_dic,0)) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
        NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0)) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) +
        NVL(p.var_oct,0) + NVL( p.var_nov,0) + NVL( p.var_dic,0))
        into result
     from presupuesto_partida p
     Where ano = an_ano and cencos = as_cencos
          and cnta_prsp = as_cnta_prsp;

  return(Result);
end USF_PTO_SLDO_ACUMULADO_ANUAL;
/

prompt
prompt Creating function USF_PTO_SLDO_ACUMULADO_FECHA
prompt ==============================================
prompt
create or replace function cantabria.USF_PTO_SLDO_ACUMULADO_FECHA(
    an_ano in number, an_mes in number, as_cencos in char, as_cnta_prsp in char)
      Return number is
  Result number;
begin

  if an_mes = 1 then
     Select NVL(p.proy_ene,0) + NVL(p.ejec_ene,0) + NVL(p.var_ene,0)
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 2 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) ) +
               (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) ) +
               (NVL(p.var_ene,0)  + NVL( p.var_feb,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 3 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0)) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 4 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 5 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) )
      into result
      from presupuesto_partida p
      Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 6 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 7 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 8 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 9 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 10 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
        NVL(p.proy_oct,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
        NVL(p.ejec_oct,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) +
        NVL(p.var_oct,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 11 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
        NVL(p.proy_oct,0) + NVL( p.proy_nov,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
        NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) +
        NVL(p.var_oct,0) + NVL( p.var_nov,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 12 then
     result := usf_pto_sldo_acumulado_anual(an_ano, as_cencos, as_cnta_prsp);
  end if ;
  return(Result);
end USF_PTO_SLDO_ACUMULADO_FECHA;
/

