prompt
prompt Creating function USF_PTO_SLDO_SEMESTRE
prompt =======================================
prompt
create or replace function cantabria.USF_PTO_SLDO_SEMESTRE(
     ani_ano       in number,
     ani_mes       in number,
     asi_cencos    in centros_costo.cencos%TYPE,
     asi_cnta_prsp in presupuesto_cuenta.cnta_prsp%TYPE
)return number IS

  ln_Result number;

begin

  if ani_mes BETWEEN 1 AND 6 then
     Select NVL(p.proy_ene,0) + NVL(p.proy_feb,0) +
            NVL(p.proy_mar,0) + NVL(p.proy_abr,0) +
            NVL(p.proy_may,0) + NVL(p.proy_jun,0) +
            NVL(p.var_ene,0)  + NVL(p.var_feb,0)  +
            NVL(p.var_mar,0)  + NVL(p.var_abr,0)  +
            NVL(p.var_may,0)  + NVL(p.var_jun,0)  +
            NVL(p.ejec_ene,0) + NVL(p.ejec_feb,0) +
            NVL(p.ejec_mar,0) + NVL(p.ejec_abr,0) +
            NVL(p.ejec_may,0) + NVL(p.ejec_jun,0)
       into ln_result
       from presupuesto_partida p
      Where ano       = ani_ano
        and cencos    = asi_cencos
        and cnta_prsp = asi_cnta_prsp;
  ELSIF ani_mes BETWEEN 7 AND 12 then
     Select NVL(p.proy_jul,0) + NVL(p.proy_ago,0) +
            NVL(p.proy_set,0) + NVL(p.proy_oct,0) +
            NVL(p.proy_nov,0) + NVL(p.proy_dic,0) +
            NVL(p.var_jul,0)  + NVL(p.var_ago,0)  +
            NVL(p.var_set,0)  + NVL(p.var_oct,0)  +
            NVL(p.var_nov,0)  + NVL(p.var_dic,0)  +
            NVL(p.ejec_jul,0) + NVL(p.ejec_ago,0) +
            NVL(p.ejec_set,0) + NVL(p.ejec_oct,0) +
            NVL(p.ejec_nov,0) + NVL(p.ejec_dic,0)
       into ln_result
       from presupuesto_partida p
      Where ano       = ani_ano
        and cencos    = asi_cencos
        and cnta_prsp = asi_cnta_prsp;
  END IF;
  return(ln_Result);
end USF_PTO_SLDO_SEMESTRE;
/

prompt
prompt Creating function USF_PTO_SLDO_TRIMESTRE
prompt ========================================
prompt
create or replace function cantabria.USF_PTO_SLDO_TRIMESTRE
(an_ano in number, an_mes in number, as_cencos in char, as_cnta_prsp in char)
Return number is
  -- Funcion que calcula el trimestre acumulado
  Result number;
begin

  -- Enero ,Febrero ,Marzo (1er Trimestre)
  if an_mes = 1 or an_mes = 2 or an_mes = 3 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) ) +
            (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) ) +
            (NVL(p.var_ene,0)  + NVL( p.var_feb,0)  + NVL( p.var_mar,0)  )
        into result
        from presupuesto_partida p
       Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;


  -- Abril ,Mayo ,Junio (2do Trimestre)
  if an_mes = 4 or an_mes = 5 or an_mes = 6 then
     Select (NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) ) +
            (NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) ) +
            (NVL(p.var_abr,0)  + NVL( p.var_may,0) + NVL( p.var_jun,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;

  -- Julio,Agosto ,Setiembre (3er Trimestre)
  if an_mes = 7 or an_mes = 8 or an_mes = 9 then
     Select (NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) ) +
            (NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) ) +
            (NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;

  -- Octubre ,Noviembre,Diciembre (4to Trimestre)
  if an_mes = 10 or an_mes = 11 or an_mes = 12 then
     Select (NVL(p.proy_oct,0) + NVL( p.proy_nov,0) + NVL( p.proy_dic,0) ) +
            (NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0) ) +
            (NVL(p.var_oct,0)  + NVL( p.var_nov,0)  + NVL( p.var_dic,0)  )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;


  return(Result);
end USF_PTO_SLDO_TRIMESTRE;
/

prompt
prompt Creating function USF_PPTO_SALDO_ACTUAL
prompt =======================================
prompt
create or replace function cantabria.USF_PPTO_SALDO_ACTUAL(
    ani_mes            in cntbl_asiento.mes%type,
    ani_ano            in cntbl_asiento.ano%type,
    asi_corr_corte     in campo_ciclo.corr_corte%type,
    asi_desc_campo     in campo.desc_campo%type,
    asi_frente_cosecha in frente_cosecha.frente_cosecha%type,
    asi_cencos         in centros_costo.cencos%type,
    asi_cnta_prsp      in presupuesto_cuenta.cnta_prsp%TYPE
)return number is

  -- Retorna saldo actual. Los que son sin control, retorna 0
  ln_reg         number;  -- Guarda numero de registro
  ln_ctrl        presupuesto_partida.flag_ctrl%type;
  ln_var         presupuesto_partida.prctg_var%type;
  ln_return      number;
begin

  ln_return := 0 ;

  -- Busca si existe partida, caso contrario devuelve error
  Select Count( cencos)
    into ln_reg
    from presupuesto_partida
    Where ano = ani_ano
      and cencos = asi_cencos
      and cnta_prsp = asi_cnta_prsp
      and flag_ingr_egr = 'E';

 -- raise_application_error( -20000, an_ano ||' ' || as_cencos || ' ' || as_cnta_prsp);
  if ln_reg = 0 then  -- No existe partida
    RAISE_APPLICATION_ERROR( -20000, 'No existe Partida presupuestal '||
      'para Corr. Corte ' || asi_corr_corte || ' Campo '||asi_desc_campo
       ||' Frente Cosecha '||asi_frente_cosecha||' C. Costo '||asi_cencos || ', '
       || asi_cnta_prsp || ', ano' || ani_ano ) ;
     return 0;
  end if;

  -- Evalua si tiene presupuesto segun flag de control
  -- Segun Partida presupuestal, halla la forma de procesar
  Select p.flag_ctrl, p.prctg_var
    into ln_ctrl, ln_var
    from presupuesto_partida p
    where p.ano = ani_ano
      and p.cencos = asi_cencos
      AND p.cnta_prsp = asi_cnta_prsp;

  -- Evalua que partida tenga flag de control
  if ln_ctrl is null then
     raise_application_error( -20004, ln_ctrl);
     return 0;
  end if;

  --==========================
   -- Sin control
  --==========================
  if ln_ctrl = 0 then
      return ln_return ;
  end if;
  --==========================
  -- Acumulado Anual
  --==========================
  if ln_ctrl = 1 then
     ln_return := usf_pto_sldo_acumulado_anual(ani_ano, asi_cencos, asi_cnta_prsp);
  end if;

  --==========================
  -- Acumulado a la Fecha
  --==========================
  if ln_ctrl = 2 then
     ln_return := usf_pto_sldo_acumulado_fecha(ani_ano, ani_mes, asi_cencos, asi_cnta_prsp);
  end if;

  --==========================
  -- Mensual
  --==========================
  if ln_ctrl = 3 then
     ln_return := usf_pto_sldo_mensual(ani_ano, ani_mes, asi_cencos, asi_cnta_prsp);
  end if;

  --==========================
  -- Ultimo Trimestre Acumulado
  --==========================
  if ln_ctrl = 4 then
     ln_return := usf_pto_sldo_trimestre(ani_ano, ani_mes, asi_cencos, asi_cnta_prsp);
  end if;

  --==========================
  -- Trimestre Centrado
  --==========================
  if ln_ctrl = 5 then
     ln_return := usf_pto_sldo_semestre(ani_ano, ani_mes, asi_cencos, asi_cnta_prsp);
  end if;

  -- Aplica porcentaje de variabilidad
  if NVL(ln_var,0) > 0 THEN
     ln_return := ln_return * ( 1 + (ln_var/100) );
  elsif NVL(ln_var,0) < 0 THEN
     ln_return := ln_return * ( 1 - (ln_var/100));
  END IF;

  return ln_return;

END USF_PPTO_SALDO_ACTUAL;
/

prompt
prompt Creating function USF_PR_ART_CANT_CONS
prompt ======================================
prompt
create or replace function cantabria.usf_pr_art_cant_cons(
       asi_nro_orden in orden_trabajo.nro_orden%TYPE,
       asi_cod_art   in articulo.cod_art%TYPE
       ) return number is

  Result        number;
  ln_count      number;

begin
  select Count(*)
     into ln_count
  from pd_ot_insumos pdi,
       pd_ot_det     pdd,
       operaciones op
  where pdd.nro_item   = pdi.nro_item
    and pdd.nro_parte  = pdi.nro_parte
    and op.oper_sec  = pdd.oper_sec
    and op.nro_orden = asi_nro_orden
    and pdi.cod_art   = asi_cod_art;

  if ln_count = 0 then
     Result := 0;
  else
    select Sum(pdi.cantidad)
       into Result
    from pd_ot_insumos pdi,
         pd_ot_det     pdd,
         operaciones op
    where pdd.nro_item   = pdi.nro_item
      and pdd.nro_parte  = pdi.nro_parte
      and op.oper_sec  = pdd.oper_sec
      and op.nro_orden = asi_nro_orden
      and pdi.cod_art   = asi_cod_art;
  end if;

  return(Result);
end usf_pr_art_cant_cons;
/

prompt
prompt Creating function USF_PR_ART_CANT_PROY
prompt ======================================
prompt
create or replace function cantabria.usf_pr_art_cant_proy(
       asi_nro_orden in orden_trabajo.nro_orden%TYPE,
       asi_cod_art   in articulo.cod_art%TYPE
       ) return number is

  Result        number;
  ln_count      number;

begin
  select Count(*)
     into ln_count
  from articulo_mov_proy am,
       operaciones op
  where op.oper_sec  = am.oper_sec
    and op.nro_orden = asi_nro_orden
    and am.cod_art   = asi_cod_art;

  if ln_count = 0 then
     Result := 0;
  else
    select Sum(am.cant_proyect)
       into Result
    from articulo_mov_proy am,
         operaciones op
    where op.oper_sec  = am.oper_sec
      and op.nro_orden = asi_nro_orden
      and am.cod_art   = asi_cod_art;
  end if;

  return(Result);
end usf_pr_art_cant_proy;
/

prompt
prompt Creating function USF_PR_COSTO_PD_OT
prompt ====================================
prompt
create or replace function cantabria.usf_pr_costo_pd_ot(
       asi_nro_parte in pd_ot.nro_parte%TYPE ) return number is

  Cursor c_pd_ot_det is
  SELECT pd.nro_item,
         la.flag_maq_mo,
         la.und,
         op.costo_unit,
         pd.hora_inicio,
         pd.hora_fin,
         le.costo_unitario,
         p.fecha
  FROM pd_ot_det        pd,
       labor            la,
       operaciones      op,
       labor_ejecutor   le,
       pd_ot            p
  WHERE pd.cod_labor     = la.cod_labor
    and pd.nro_parte     = asi_nro_parte
    and op.oper_sec      = pd.oper_sec
    and le.cod_labor     = pd.cod_labor
    and le.cod_ejecutor  = pd.cod_ejecutor
    and p.nro_parte      = pd.nro_parte
  ORDER BY pd.nro_item ;

  Result               number(13,2);
  ls_und_hr            prod_param.und_hr%TYPE;
  ln_costo_mo          number(13,2) default 0;                   -- Costo de la Mano de Obra
  ln_costo_maq         number(13,2) default 0;                   -- Costo de la Maquinaria
  ln_costo_ins         number(13,2) default 0;                   -- Costo de los insumos
  ln_costo_maq2        number(13,2) default 0;                   -- Costo de Utilizar el Equipo
  ln_costo_unit        operaciones.costo_unit%TYPE;        -- Costo Unit de la operacion
  ln_costo_le          labor_ejecutor.costo_unitario%TYPE; -- Costo del Labor_ejecutor por unidad
  ls_cod_soles         logparam.cod_soles%TYPE;
  ls_cod_dolares       logparam.cod_dolares%TYPE;
  ln_count             number;
  ln_nro_item          pd_ot_det.nro_item%TYPE;

begin

  select und_hr
      into ls_und_hr
  from prod_param
  where reckey = '1';

  Select cod_soles, cod_dolares
     into ls_cod_soles, ls_cod_dolares
  from logparam
  where reckey = '1';

  Result := 0;
  for v_reg in c_pd_ot_det loop
      ln_nro_item     := v_reg.nro_item;
      ln_costo_maq    := 0;
      ln_costo_mo     := 0;
      ln_costo_unit   := Nvl(v_reg.costo_unit,0);
      ln_costo_le     := Nvl(v_reg.costo_unitario,0);

      if v_reg.flag_maq_mo = 'O' AND v_reg.und = ls_und_hr then

         -- Costo de Mano de Obra (jornal)
         select count(*)
            into ln_count
         from pd_ot_asistencia a
         where a.nro_item = ln_nro_item
           and a.no_parte = asi_nro_parte;

         if ln_count > 0 then

            -- Costo x Hora * Numero de Horas * Factor = Costo de M.O. (Jornal)
            select sum(Nvl(a.costo_horas,0) * Nvl(a.costo_horas,0) * Nvl(a.factor,0))
              into ln_costo_mo
            from pd_ot_asistencia a
            where a.nro_item = ln_nro_item
              and a.no_parte = asi_nro_parte;

            if ln_costo_mo is null then
               ln_costo_mo := 0;
            end if;
         else
             ln_costo_mo := 0;
         end if;

      elsif v_reg.flag_maq_mo = 'O' AND v_reg.und <> ls_und_hr then

         -- Costo de Mano de Obra (Destajo)
         select count(*)
            into ln_count
         from pd_ot_asist_destajo a
         where a.nro_item = ln_nro_item
           and a.nro_parte = asi_nro_parte;

         if ln_count > 0 then

            -- Costo x Hora * Numero de Horas * Factor = Costo de M.O. (Jornal)
            select sum(Nvl(a.cant_destajada,0) * ln_costo_unit)
              into ln_costo_mo
            from pd_ot_asist_destajo a
            where a.nro_item = ln_nro_item
              and a.nro_parte = asi_nro_parte;

            if ln_costo_mo is null then
               ln_costo_mo := 0;
            end if;
         else
             ln_costo_mo := 0;
         end if;

      elsif v_reg.flag_maq_mo = 'M' AND v_reg.und = ls_und_hr then
            ln_costo_maq := usf_mtt_fecha_hora(v_reg.hora_inicio, v_reg.hora_fin) ;
            ln_costo_maq  := ln_costo_maq * ln_costo_le ;

            ln_costo_mo  := 0;
      end if;

      if v_reg.und = ls_und_hr then

         -- Costo de Maquinaria utilizada en esta operacion
         select count(*)
            into ln_count
         from pd_ot_det_maq a
         where a.nro_item = ln_nro_item
           and a.nro_parte = asi_nro_parte;

         if ln_count > 0 then

            -- Cantidad_trabajada * Costo_unit de la Operacion
            select sum( Nvl(a.cant_trabajada,0) * ln_costo_unit )
              into ln_costo_maq2
            from pd_ot_det_maq a
            where a.nro_item = ln_nro_item
              and a.nro_parte = asi_nro_parte;

            if ln_costo_maq is null then
               ln_costo_maq2 := 0;
            end if;
         else
             ln_costo_maq2 := 0;
         end if;

      end if;

      -- El Resultado esta en Soles, debo pasarlo a dolares
      Result := Result + usf_fl_conv_mon((ln_costo_mo + ln_costo_maq + ln_costo_maq2),
                       ls_cod_soles, ls_cod_dolares, v_reg.fecha);

      -- Ahora puedo sumar los insumos, ya que siempre estan dolarizados
      Select Count(*)
         into ln_count
      from pd_ot_insumos a
      where a.nro_item = ln_nro_item
        and a.nro_parte = asi_nro_parte;

      if ln_count > 0 then
         Select Sum( Nvl(a.cantidad,0) * Nvl(a.costo_insumo,0) )
            into ln_costo_ins
         from pd_ot_insumos a
         where a.nro_item = ln_nro_item
           and a.nro_parte = asi_nro_parte;

         if ln_costo_ins is null then
            ln_costo_ins := 0;
         end if;
      else
          ln_costo_ins := 0;
      end if;

      Result := Result + ln_costo_ins;

  end loop;

  return(Result);
end usf_pr_costo_pd_ot;
/

prompt
prompt Creating function USF_PR_COSTO_TOTAL_OT
prompt =======================================
prompt
create or replace function cantabria.usf_pr_costo_total_OT(
       asi_nro_orden  orden_trabajo.nro_orden%TYPE) return number is

  Result        number(13,2);
  ln_costo_mat  number(13,2);  -- Costo de los materiales
  ln_costo_ope  number(13,2);  -- Costo de la operacion
  ln_count      number(13,2);

begin

  --COSTO REAL
  --verifico que exista en parte diario de ot
  select count(*)
    into ln_count
   from pd_ot_det p,
        operaciones op
  where op.oper_sec = p.oper_sec
    and p.nro_orden    = asi_nro_orden;

  IF ln_count > 0 THEN
     --BUSCO MONTO REAL
     select Sum(Nvl(p.costo_labor,0))
       into ln_costo_ope
     from pd_ot_det p,
          operaciones op
     where op.oper_sec = p.oper_sec
       and p.nro_orden    = asi_nro_orden;
  else
     ln_costo_ope := 0.00;
  END IF;

  --COSTO MATERIALES REAL
  SELECT Count(*)
   INTO ln_count
   FROM pd_ot_det po,
        pd_ot_insumos pi,
        operaciones op
  WHERE po.nro_parte    = pi.nro_parte
    AND po.nro_item     = pi.nro_item
    and op.oper_sec     = po.oper_sec
    AND op.nro_orden    = asi_nro_orden;

  IF ln_count > 0 THEN
     SELECT Sum(Round(Nvl(pi.cantidad,0) * Nvl(pi.costo_insumo,0),2))
       INTO ln_costo_mat
       FROM pd_ot_det po,
            pd_ot_insumos pi,
            operaciones op
      WHERE po.nro_parte    = pi.nro_parte
        AND po.nro_item     = pi.nro_item
        and op.oper_sec     = op.oper_sec
        AND op.nro_orden    = asi_nro_orden;
  else
     ln_costo_mat := 0.00;
  END IF ;

  Result := ln_costo_ope + ln_costo_mat;

  return(Result);
end usf_pr_costo_total_OT;
/

prompt
prompt Creating function USF_PR_DATETIME_HORAS
prompt =======================================
prompt
create or replace function cantabria.usf_pr_DateTime_horas(
       adt_fecha1 in date,
       adt_fecha2 in date) return number is
  Result Number;
begin
  Result := Nvl(24 * (adt_fecha2 - adt_fecha1 ), 0) ;
  return(Result);
end usf_pr_DateTime_horas;
/

prompt
prompt Creating function USF_PR_DURACION_CERTIFICADO
prompt =============================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_PR_DURACION_CERTIFICADO(

       AD_FECHA_INI CERTIFICADO_PLANTA.FEC_INICIO%TYPE,
       AD_FECHA_FIN CERTIFICADO_PLANTA_DET.Fec_Vencimiento%TYPE)

  RETURN            VARCHAR2 IS
  RESULT            VARCHAR2(100);

  --ld_aux             CERTIFICADO_PLANTA.FEC_INICIO%TYPE;
  ln_ANO             Number (12,4);
  ln_MES             Number (13,2);
  ln_DIA             Number (13,2);
  --LC_RET             VARCHAR2 (50);

BEGIN

/** Calcula la diferencia entre dos fechas en:
* a?os, meses y dias
* Usa la funcion DiasDelMes()*/

/*IF AD_FECHA_INI > AD_FECHA_FIN THEN

    ldAux         := AD_FECHA_INI;
    AD_FECHA_INI  := AD_FECHA_FIN;
    AD_FECHA_FIN  := ldAux;

END IF;*/

  ln_ANO := TO_NUMBER(TO_CHAR(AD_FECHA_FIN, 'YYYY') - TO_NUMBER(TO_CHAR(AD_FECHA_INI, 'YYYY')));
  /*lnAnio = YEAR(tdFin) - YEAR(tdIni)
  ldAux = GOMONTH(tdIni, 12 * lnAnio)
  *--- No cumplio el a?o aun
  IF ldAux > tdFin
    lnAnio = lnAnio - 1
  ENDIF*/
  ln_Mes := TO_NUMBER(TO_CHAR(AD_FECHA_FIN, 'MM')) - TO_NUMBER(TO_CHAR(AD_FECHA_INI, 'MM'));
  IF ln_Mes < 0 THEN
    ln_Mes := ln_Mes + 12;
  END IF;

  ln_Dia := TO_NUMBER(TO_CHAR(AD_FECHA_FIN, 'DD')) - TO_NUMBER(TO_CHAR(AD_FECHA_INI, 'DD'));

  IF ln_Dia < 0 THEN
    ln_Dia := ln_Dia + (AD_FECHA_FIN - AD_FECHA_INI);
  END IF;
  --- Si el dia es mayor, no cumplio el mes

  IF TO_NUMBER(TO_CHAR(AD_FECHA_FIN, 'DD')) < TO_NUMBER(TO_CHAR(AD_FECHA_INI, 'DD')) THEN

    IF ln_Mes = 0 THEN
       ln_Mes := 11;
    ELSE
      ln_Mes := ln_Mes - 1;
    END IF;
  END IF;

  RESULT := (to_char(ln_ANO))||' A?os y' ||(to_char(ln_MES))||' Meses y'||to_char((ln_Dia))|| 'Dias';
  RETURN (RESULT);
end USF_PR_DURACION_CERTIFICADO;
/**-----------------------------------------------------
* FUNCTION DiasDelMes(dFecha)
*------------------------------------------------
* Retorna los dias de un mes. Usada por Dif_AMD
*------------------------------------------------
FUNCTION DiasDelMes(dFecha)
  LOCAL ld
  ld = GOMONTH(dFecha,1)
  RETURN DAY(ld - DAY(ld))
ENDFUNC*/
/

prompt
prompt Creating function USF_PR_DURACION_CERTIFICADO_1
prompt ===============================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_PR_DURACION_CERTIFICADO_1(

        AD_FECHA_FIN CERTIFICADO_PLANTA_DET.Fec_Vencimiento%TYPE)

  RETURN            VARCHAR2 IS
  RESULT            VARCHAR2(100);

  LN_DIAS           NUMBER(20,0);

BEGIN
        IF SYSDATE > AD_FECHA_FIN THEN

        LN_DIAS := ROUND((AD_FECHA_FIN - SYSDATE) + 1 ,0);

        RESULT := 'HACE '||LN_DIAS||' DIAS QUE VENCIO EL CERTIFICADO';

        ELSE

        LN_DIAS := ROUND((AD_FECHA_FIN - SYSDATE) + 1,0);

        RESULT := 'FALTAN  '||LN_DIAS||' DIAS PARA QUE VENZA EL CERTIFICADO';

        END IF;

 RETURN (RESULT);
END USF_PR_DURACION_CERTIFICADO_1;
/

prompt
prompt Creating function USF_PRECIO_VENTA
prompt ==================================
prompt
create or replace function cantabria.USF_PRECIO_VENTA
( an_precio_unit in articulo_mov_proy.precio_unit%type,
  an_descuento   in articulo_mov_proy.decuento%type   ,
  an_impuesto    in articulo_mov_proy.impuesto%type  )
  return number is
  Result number;

  ln_desc Number ;
  ln_imp Number ;

begin
  ln_desc := (Nvl(an_precio_unit,0) * Nvl(an_descuento,0) ) / 100 ;
  ln_imp  := ((Nvl(an_precio_unit,0) - Nvl(ln_desc,0)) * Nvl(an_impuesto,0) ) / 100 ;
  Result  := Round((Nvl(an_precio_unit,0) - Nvl(ln_desc,0)) + Nvl(ln_imp,0),2) ;


  return(Result);
end USF_PRECIO_VENTA;
/

prompt
prompt Creating function USF_PR_HORAS
prompt ==============================
prompt
create or replace function cantabria.usf_pr_horas(
       adi_fecha1          in date,
       adi_fecha2          in date,
       asi_hrs_diu_noc     in varchar2
) return number is

  
  ls_hora_ini_noc      asistparam.hora_inicio_noc%TYPE;
  ls_hora_fin_noc      asistparam.hora_fin_noc%TYPE;
  ld_hora_ini_noc      DATE;
  ld_hora_fin_noc      DATE;
  ld_hora_ini_dia      DATE;  -- Fecha y hora del inicio de horario diurno
  ls_fecha             varchar2(40);
  ld_fec_desde         date;
  ld_fec_hasta         date;
  
  ln_hrs_diu           NUMBER := 0;
  ln_hrs_noc           NUMBER := 0;
  
  ln_count             number;
  
begin
  
  -- Obtengo los datos del inicio y fin del horario nocturno
  SELECT COUNT(*)
    INTO ln_count
    FROM asistparam
   WHERE reckey = '1';

  IF ln_count = 0 THEN
     RAISE_APPLICATION_ERROR(-20000, 'Error, no existen parametros en ASISTPARAM');
  END IF;

  SELECT a.hora_inicio_noc, a.hora_fin_noc
    INTO ls_hora_ini_noc, ls_hora_fin_noc
    FROM asistparam a
   WHERE a.reckey = '1';


  -- Tengo que sacar la fecha de inicio y de fin de horario nocturno
  ls_fecha := to_char(adi_fecha1, 'dd/mm/yyyy') || ' ' || ls_hora_ini_noc;
  ld_hora_ini_noc := to_date(ls_fecha, 'dd/mm/yyyy hh24:mi:ss');

  IF ls_hora_fin_noc < ls_hora_ini_noc THEN
     -- Si la hora de fin de horario nocturno es menor que la hora de inicio
     -- entoncese se trata de dos dias diferentes
     ls_fecha := to_char(adi_fecha1 + 1, 'dd/mm/yyyy') || ' ' || ls_hora_fin_noc;
     ld_hora_fin_noc := to_date(ls_fecha, 'dd/mm/yyyy hh24:mi:ss');
  ELSE
     -- Si la hora de fin es mayor que la hora de inicio entonces son del
     -- mismo dia
     ls_fecha := to_char(adi_Fecha1, 'dd/mm/yyyy') || ' ' || ls_hora_fin_noc;
     ld_hora_fin_noc := to_date(ls_fecha, 'dd/mm/yyyy hh24:mi:ss');
  END IF;
  
  -- Para terminar saco la hora de fin de horario nocturno pero del mismo dia, esto es para aquellos personas que ingresan de madrugada
  -- y terminan antes del horario nocturno
  ls_fecha := to_char(adi_fecha1, 'dd/mm/yyyy') || ' ' || ls_hora_fin_noc;
  ld_hora_ini_dia := to_date(ls_fecha, 'dd/mm/yyyy hh24:mi:ss');
  
  ld_fec_desde := adi_fecha1;
  ld_fec_hasta := adi_Fecha2;

  -- Si la Fecha de inicio es menor que la hora de inicio del horario nocturno significa
  -- entonces que tiene horas diurnas
  IF ld_fec_desde <= ld_hora_ini_noc THEN
     -- Verifico si la fecha desde es menor que la hora de fin de horario nocturno pero de la misma fecha
     if ld_fec_desde < ld_hora_ini_dia THEN
        IF ld_fec_hasta > ld_hora_ini_dia THEN
           -- Si la fecha de ingreso es menor a la hora de fin de hora nocturna del mismo dia entonces ha hecho horas nocturnas
           -- Saco las horas nocturnas
           ln_hrs_noc := (ld_hora_ini_dia - ld_fec_hasta) * 24;
           ld_fec_desde := ld_hora_ini_dia;
        ELSE
           ln_hrs_noc := (ld_fec_hasta - ld_fec_desde) * 24;
           ld_fec_desde := ld_fec_hasta;
        END IF;
     end if;

     -- Tiene horas diurnas y posiblemente nocturnas
     IF ld_fec_hasta > ld_hora_ini_dia THEN
        IF ld_fec_hasta < ld_hora_ini_noc THEN
           ln_hrs_diu := (ld_fec_hasta - ld_fec_desde) * 24;
        ELSE
           -- Tiene horas diurnas y nocturnas, primero saco las horas diurnas
           ln_hrs_diu := (ld_hora_ini_noc - ld_fec_desde) * 24;

           -- Ahora verifico cuantas horas nocturnas ha hecho
           -- Verifico si la hora de fin de turno es mayor o menor que la hora de fin de horario nocturno
           IF adi_fecha2 < ld_hora_fin_noc THEN
              ld_fec_hasta := adi_fecha2;
           ELSE
              ld_fec_hasta := ld_hora_fin_noc;
           END IF;

           -- Obtengo las horas nocturnas
           ln_hrs_noc := (ld_fec_hasta - ld_hora_ini_noc) * 24;

           -- Luego verifico si la hora de salida es mayor a la hora de fin del horario nocturno
           IF adi_fecha2 > ld_hora_fin_noc THEN
              ln_hrs_diu := ln_hrs_diu + (adi_fecha2 - ld_hora_fin_noc)*24;
           END IF;
        END IF;
     END IF;
  ELSE
     -- No tiene horas diurnas
     ld_fec_desde := adi_fecha1;

     -- Verifico si la hora de fin de turno es mayor o menor que la hora de fin de horario nocturno
     IF adi_fecha2 < ld_hora_fin_noc THEN
        ld_fec_hasta := adi_fecha2;
     ELSE
        ld_fec_hasta := ld_hora_fin_noc;
     END IF;

     -- Obtengo las horas nocturnas
     ln_hrs_noc := (ld_fec_hasta - ld_fec_desde) * 24;

     -- Luego verifico si la hora de salida es mayor a la hora de fin del horario nocturno
     IF adi_fecha2 > ld_hora_fin_noc THEN
        ln_hrs_diu := ln_hrs_diu + (adi_fecha2 - ld_hora_fin_noc)*24;
     END IF;
  END IF;
  
  ln_hrs_diu := nvl(ln_hrs_diu, 0);
  ln_hrs_noc := NVL(ln_hrs_noc, 0);
  if ln_hrs_diu < 0 then ln_hrs_diu := 0; end if;
  if ln_hrs_noc < 0 then ln_hrs_noc := 0; end if;
  
  if asi_hrs_diu_noc = 'HD' then
     return (NVL(ln_hrs_diu, 0));
  else
     return (NVL(ln_hrs_noc, 0));
  end if;
end usf_pr_horas;
/

prompt
prompt Creating function USF_PR_HORAS_INCID
prompt ====================================
prompt
create or replace function cantabria.usf_pr_horas_incid(
       asi_cod_maquina in tg_parte_piso_tiempo_uso.cod_maquina%TYPE,
       asi_nro_parte   in tg_parte_piso_tiempo_uso.nro_parte%TYPE) return number is
  Result number;
begin
  -- Calcula el Numero de Horas de Incidencias del Equipo por Parte
  select Sum( usf_pr_datetime_horas( a.hora_inicio, a.hora_fin) )
    into Result
  from   tg_parte_piso_incidencias a
  where  a.nro_parte   = asi_nro_parte
    and  a.cod_maquina = asi_cod_maquina;

  return(Result);
end usf_pr_horas_incid;
/

prompt
prompt Creating function USF_PROD_CON_ENER_DET_PMP
prompt ===========================================
prompt
CREATE OR REPLACE FUNCTION CANTABRIA.USF_PROD_CON_ENER_DET_PMP(

      AD_FECHA_MOV IN prod_consumo_ener_det.fecha_consumo%TYPE

 )RETURN NUMBER IS
  ln_resul NUMBER;

BEGIN

SELECT  Round(SUM(ARTICULO_MOV.CANT_PROCESADA),2)
        INTO ln_resul
    FROM VALE_MOV,
         ARTICULO_MOV,
         ARTICULO
   WHERE ARTICULO_MOV.COD_ORIGEN = VALE_MOV.COD_ORIGEN and
         ARTICULO_MOV.NRO_VALE = VALE_MOV.NRO_VALE and
         ARTICULO_MOV.COD_ART = ARTICULO.COD_ART AND
         VALE_MOV.ALMACEN = 'PTCN01' AND
         VALE_MOV.TIPO_MOV = 'I09' AND
         trunc(VALE_MOV.FEC_REGISTRO) = AD_FECHA_MOV AND
         VALE_MOV."FLAG_ESTADO" <> '0'
         AND ARTICULO_MOV.CENCOS = 'PROHCN'
         AND ARTICULO_MOV.COD_ART = '092001.0001';

  RETURN ln_resul;

END USF_PROD_CON_ENER_DET_PMP;
/

prompt
prompt Creating function USF_PROD_COSTO_CANT_PPTT
prompt ==========================================
prompt
create or replace function cantabria.USF_PROD_COSTO_CANT_PPTT(
       asi_plantilla  IN plantilla_costo_det.cod_plantilla%TYPE,
       ani_nro_item   IN plantilla_costo_det.nro_item%TYPE,
       adi_fecha1     IN DATE,
       adi_fecha2     IN DATE
) return number IS

  ls_oper_ing_prod      logparam.oper_cons_interno%TYPE;
  ls_doc_ot             logparam.doc_ot%TYPE;
  ls_centro_benef       centro_beneficio.centro_benef%TYPE;
  ls_flag_cenbef        plantilla_costo_det.flag_centro_benef%TYPE;
  ln_Result             tt_prod_costo_hp_cab.cantidad_hp%TYPE;
  ll_cenbef_inc         NUMBER;
  ll_cenbef_exc         NUMBER;

BEGIN

  SELECT l.oper_ing_prod, l.doc_ot
    INTO ls_oper_ing_prod, ls_doc_ot
    FROM logparam l
   WHERE reckey = '1';

  SELECT COUNT(*)
    INTO ll_cenbef_inc
    FROM plant_costo_centro_benef p2
   WHERE p2.cod_plantilla = asi_plantilla
     AND p2.nro_item      = ani_nro_item
     AND p2.flag_incluir_excluir = 'I';

  SELECT COUNT(*)
    INTO ll_cenbef_exc
    FROM plant_costo_centro_benef p2
   WHERE p2.cod_plantilla = asi_plantilla
     AND p2.nro_item      = ani_nro_item
     AND p2.flag_incluir_excluir = 'I';

  SELECT t.centro_benef
    INTO ls_centro_benef
    FROM plantilla_costo t
   WHERE t.cod_plantilla = asi_plantilla;


  SELECT NVL(t.flag_centro_benef, '0')
    INTO ls_flag_cenbef
    FROM plantilla_costo_det t
   WHERE t.cod_plantilla = asi_plantilla
     AND t.nro_item      = ani_nro_item;

  -- ahora El Ingreso por produccion de la Harina de Pescado
  IF ls_flag_cenbef = '0' THEN
     SELECT NVL(SUM(am.cant_procesada), 0)
       INTO ln_result
       FROM vale_mov              vm,
            articulo_mov          am,
            articulo_mov_proy     amp,
            orden_trabajo         ot,
            centro_benef_articulo ca,
            articulo              a
      WHERE vm.nro_vale = am.nro_vale
        AND am.origen_mov_proy = amp.cod_origen
        AND am.nro_mov_proy    = amp.nro_mov
        AND ot.nro_orden       = amp.nro_doc
        AND amp.tipo_doc       = ls_doc_ot
        AND vm.flag_estado     <> '0'
        AND am.flag_estado     <> '0'
        AND trunc(vm.fec_registro) BETWEEN trunc(adi_fecha1) AND trunc(adi_fecha2)
        AND ca.cod_art             = am.cod_art
        AND a.cod_art              = am.cod_art
        AND ca.centro_benef        = ls_centro_benef
        AND ot.centro_benef        = ca.centro_benef
        AND vm.tipo_mov            = ls_oper_ing_prod;
  ELSIF ls_flag_cenbef = '1' AND ll_cenbef_inc > 0 THEN
     SELECT NVL(SUM(am.cant_procesada), 0)
       INTO ln_result
       FROM vale_mov                 vm,
            articulo_mov             am,
            articulo_mov_proy        amp,
            orden_trabajo            ot,
            centro_benef_articulo    ca,
            plant_costo_centro_benef p2,
            articulo                 a
      WHERE vm.nro_vale = am.nro_vale
        AND am.origen_mov_proy = amp.cod_origen
        AND am.nro_mov_proy    = amp.nro_mov
        AND ot.nro_orden       = amp.nro_doc
        AND amp.tipo_doc       = ls_doc_ot
        AND vm.flag_estado     <> '0'
        AND am.flag_estado     <> '0'
        AND trunc(vm.fec_registro) BETWEEN trunc(adi_fecha1) AND trunc(adi_fecha2)
        AND ot.centro_benef        = ca.centro_benef
        AND ca.cod_art             = am.cod_art
        AND a.cod_art              = am.cod_art
        AND ca.centro_benef        = p2.centro_benef
        AND p2.cod_plantilla       = asi_plantilla
        AND p2.nro_item            = ani_nro_item
        AND p2.flag_incluir_excluir  = 'I'
        AND vm.tipo_mov            = ls_oper_ing_prod;

  ELSIF ls_centro_benef = '1' AND ll_cenbef_exc > 0 THEN
     SELECT NVL(SUM(am.cant_procesada), 0)
       INTO ln_result
       FROM vale_mov              vm,
            articulo_mov          am,
            articulo_mov_proy     amp,
            orden_trabajo         ot,
            centro_benef_articulo ca,
            articulo              a
      WHERE vm.nro_vale = am.nro_vale
        AND am.origen_mov_proy = amp.cod_origen
        AND am.nro_mov_proy    = amp.nro_mov
        AND ot.nro_orden       = amp.nro_doc
        AND amp.tipo_doc       = ls_doc_ot
        AND vm.flag_estado     <> '0'
        AND am.flag_estado     <> '0'
        AND trunc(vm.fec_registro) BETWEEN trunc(adi_fecha1) AND trunc(adi_fecha2)
        AND ca.cod_art             = am.cod_art
        AND a.cod_art              = am.cod_art
        AND ca.centro_benef NOT IN ( SELECT p2.centro_benef
                                       FROM plant_costo_centro_benef p2
                                      WHERE p2.cod_plantilla = asi_plantilla
                                        AND p2.nro_item      = ani_nro_item
                                        AND p2.flag_incluir_excluir = 'E')
        AND ot.centro_benef        = ca.centro_benef
        AND vm.tipo_mov            = ls_oper_ing_prod;

  END IF;

  return(ln_Result);
end USF_PROD_COSTO_CANT_PPTT;
/

prompt
prompt Creating function USF_PROD_COSTO_PERIODO
prompt ========================================
prompt
create or replace function cantabria.USF_PROD_COSTO_PERIODO(
       asi_plantilla IN plantilla_costo.cod_plantilla%TYPE,
       ani_year      IN semanas.ano%TYPE,
       ani_semana    IN semanas.semana%TYPE,
       asi_moneda    IN moneda.cod_moneda%TYPE,
       adi_Fecha1    IN DATE,
       adi_fecha2    IN DATE
) return number is
  ln_Result   number;
  ls_dolar    logparam.cod_dolares%TYPE;
BEGIN
  SELECT cod_dolares
    INTO ls_dolar
    FROM logparam
   WHERE reckey = '1';

  SELECT NVL(SUM(usf_fl_conv_mon(a2.importe, ls_dolar, asi_moneda, a2.fecha)),0)
    INTO ln_Result
    from histor_plant_csts_det a2,
         semanas               s
	where trunc(a2.fecha) between trunc(s.fecha_inicio) and trunc(s.fecha_fin)
		and trunc(a2.fecha) between trunc(adi_fecha1) and trunc(adi_fecha2)
	  and a2.cod_plantilla = asi_plantilla
    AND s.ano = ani_year
    AND s.semana = ani_semana;

  return(ln_Result);
end USF_PROD_COSTO_PERIODO;
/

