prompt
prompt Creating function USF_PROD_RATIO_OPER_CANT
prompt ==========================================
prompt
create or replace function cantabria.usf_prod_ratio_oper_cant(
as_cod_plantilla in prod_ratio_oper.cod_plantilla%type,
as_cod_labor     in prod_ratio_oper.cod_labor%type,
as_cod_ejecutor  in  prod_ratio_oper.cod_ejecutor%type)
return number is
ln_cantidad number ;
begin

  SELECT SUM(pro.cantidad) / count(*)
  INTO   ln_cantidad
  FROM   prod_ratio_oper pro
  WHERE  (pro.cod_plantilla = as_cod_plantilla ) AND
         (pro.cod_labor     = as_cod_labor     ) AND
         (pro.cod_ejecutor  = as_cod_ejecutor  )
  GROUP BY cod_labor,
		       cod_ejecutor ;


  return(ln_cantidad);

  EXCEPTION
  WHEN NO_DATA_FOUND THEN
  return  1 ;


end ;
/

prompt
prompt Creating function USF_PROG_COSECHA
prompt ==================================
prompt
create or replace function cantabria.usf_prog_cosecha(
      ad_fec_ini in date,
      an_dias_proy in number
   ) return char is

   ls_cadena char(96);

   ls_mes     char(2) ;
   ld_proceso date ;
   ld_fec_fin date ;
 --ls_dias_por_mes char(50)  ;
   ls_dias_por_mes char(50)  ;
   ln_dias_en_mes  number(2) ;
   ln_numero_meses number(2) ;
   ls_porc_por_mes char(96)  ;
   ln_dias_acu     number(3) ;
   ln_pos          number(2) ;
   ln_porc         number(8,4) ;
   ls_porc         char(8) ;
   ls_contador     char(2) ;
begin
   -- 1) Obtener: Meses Mes_Dias Mes_Dias Mes_Dias ...
   --               99   99   99
   -- longitud Meses(2) + Mes=12(2) + Dias=12(2)    = 50
   -- determinando los dmas por mes
   ld_proceso := ad_fec_ini ;
   ld_fec_fin := ad_fec_ini + an_dias_proy - 1 ;
   ls_mes := to_char( ld_proceso, 'MM') ;
   ls_dias_por_mes := ls_mes ;
   ln_dias_en_mes  := 0 ;
   ln_numero_meses := 1 ;
   While ld_proceso <= ld_fec_fin
   Loop
     if to_char( ld_proceso, 'MM') <> ls_mes Then
        If ln_numero_meses = 1 Then
           ls_dias_por_mes :=
              Substr( to_char( ln_numero_meses, '00' ),2,2) ||
              ls_mes ||
              Substr( to_char( ln_dias_en_mes, '00'  ),2,2)  ;
        Else
           ls_dias_por_mes :=
              Substr( to_char( ln_numero_meses, '00' ),2,2) ||
              substr( ls_dias_por_mes, 3,
                 (ln_numero_meses - 1 ) * 4 ) ||
              ls_mes ||
              Substr( to_char( ln_dias_en_mes, '00'  ),2,2)  ;
        End if ;
        ln_dias_en_mes  := 0 ;
        ln_numero_meses := ln_numero_meses + 1 ;
        ls_mes := to_char( ld_proceso, 'MM') ;
     End If ;
     ln_dias_en_mes := ln_dias_en_mes + 1 ;
     ld_proceso := ld_proceso + 1 ;
   end loop;
   -- asegurandose de colocar el zltimo mes
   If ln_numero_meses = 1 Then
      ls_dias_por_mes :=
          Substr( to_char( ln_numero_meses, '00' ),2,2) ||
          ls_mes ||
          Substr( to_char( ln_dias_en_mes, '00'  ),2,2)  ;
   Else
      ls_dias_por_mes :=
          Substr( to_char( ln_numero_meses, '00' ),2,2) ||
          substr( ls_dias_por_mes, 3,
             (ln_numero_meses - 1 ) * 4 ) ||
          ls_mes ||
          Substr( to_char( ln_dias_en_mes, '00'  ),2,2)  ;
   End if ;

   -- 2) Obtener: Meses Mes_%          Mes_% Mes_% ...
   --               99  99_999.9999
   -- longitud Meses(2) + Mes=12(2) + Dias=12(8)    = 96

   -- Acumulando total de dmas
   ln_dias_acu :=0 ;
   For i in 1..to_number( substr( ls_dias_por_mes , 1, 2) )
   Loop
       ln_pos := ((i - 1) * 4 ) + 3 ;
       ln_dias_acu := ln_dias_acu +
          to_number( substr( ls_dias_por_mes, ln_pos+2, 2) ) ;
   End Loop ;
   -- Distribuyendo el total de dmas
   For i in 1..to_number( substr( ls_dias_por_mes , 1, 2) )
   Loop
       ln_pos := ((i - 1) * 4 ) + 3 ;
       ls_mes := substr( ls_dias_por_mes, ln_pos, 2) ;
       ln_dias_en_mes :=
          to_number( substr( ls_dias_por_mes, ln_pos+2, 2) ) ;
       if ln_dias_acu > 0 then
          ln_porc := ln_dias_en_mes * 100 / ln_dias_acu ;
       else
           ln_porc := 0 ;
       end if ;
       ls_porc := substr( to_char( ln_porc, '000.0000'), 2, 8) ;
       ls_contador := Substr( to_char( i, '00' ),2,2) ;
       If i = 1 Then
          ls_porc_por_mes :=
             ls_contador || ls_mes || ls_porc ;
       Else
          ls_porc_por_mes :=  ls_contador ||
          substr( ls_porc_por_mes, 3,
             (i - 1 ) * 10 ) ||
          ls_mes || ls_porc ;
       End if ;

   End Loop ;

   return(ls_porc_por_mes);
end usf_prog_cosecha;
/

prompt
prompt Creating function USF_PR_PARTE_PISO_DET_VAL
prompt ===========================================
prompt
create or replace function cantabria.usf_pr_parte_piso_det_val(
   asi_valor_lectura in string,
   ani_medicion_min in number,
   ani_medicion_max in number

) return char is
  aso_en_rango char(1);

begin

  if to_number(asi_valor_lectura) < ani_medicion_min or to_number(asi_valor_lectura) > ani_medicion_max then
     aso_en_rango := '0';
  else
     aso_en_rango := '1';
  end if;
  return(aso_en_rango);

end usf_pr_parte_piso_det_val;
/

prompt
prompt Creating function USF_PR_RANGO_HORAS
prompt ====================================
prompt
create or replace function cantabria.USF_PR_RANGO_HORAS
(ld_fecha_inicio in Date,
 ld_fecha_final  in Date)

 return Number is
  ln_Result Number(12,2);

begin

  ln_result := Round((ld_fecha_final - ld_fecha_inicio) * 24 ,2) ;

  return(ln_result);
end USF_PR_RANGO_HORAS;
/

prompt
prompt Creating function USF_PR_RPT_LOTES
prompt ==================================
prompt
create or replace function cantabria.usf_pr_rpt_lotes(
       adi_fecha           IN pd_jornal_campo.fecha%TYPE,
       asi_trabajador      IN pd_jornal_campo.cod_trabajador%TYPE,
       ani_nro_item        IN pd_jornal_campo.nro_item%TYPE
) return varchar2 IS

  ls_Result VARCHAR2(32000) := '';
  
  CURSOR c_datos IS
    SELECT a.nro_lote
      FROM pd_jornal_campo_lote a,
           lote_campo           lc
     WHERE a.nro_lote = lc.nro_lote
       AND a.fecha          = adi_fecha
       AND a.cod_trabajador = asi_trabajador
       AND a.nro_item       = ani_nro_item;
begin
  
  FOR lc_reg IN c_datos LOOP
      ls_Result := ls_Result ||  lc_reg.nro_lote || ', ' ;
  END LOOP;
  
  IF length(ls_Result) > 2 THEN
     ls_Result := substr(ls_Result, 1, length(ls_Result) - 2);
  END IF;

  return(ls_Result);
end usf_pr_rpt_lotes;
/

prompt
prompt Creating function USF_PR_TARIFA_DSTJ
prompt ====================================
prompt
create or replace function cantabria.usf_pr_tarifa_dstj(
       asi_cod_labor  in labor.cod_labor%TYPE,
       adi_fecha      in date
) return number is

  ln_ano       number;
  ln_semana     number;
  ln_count      number;
  Result        number;

begin

  select count(*)
     into ln_count
  from semanas s
  where trunc(s.fecha_inicio) <= Trunc(adi_fecha)
    and trunc( usf_fl_fecha_fin(s.fecha_inicio) ) >= Trunc(adi_fecha);

  if ln_count = 0 then
     Return (0);
  end if;

  select s.ano, s.semana
     into ln_ano, ln_semana
  from semanas s
  where trunc(s.fecha_inicio) <= Trunc(adi_fecha)
    and trunc( usf_fl_fecha_fin(s.fecha_inicio) ) >= Trunc(adi_fecha);

  select count(*)
    into ln_count
  from de_semana_par dsp
  where dsp.ano         = ln_ano
    and dsp.semana      = ln_semana
    and dsp.cod_labor   = asi_cod_labor;

  if ln_count = 0 then
     Return (0);
  end if;

  select Nvl(dsp.tarifa_normal, 0)
    into Result
  from de_semana_par dsp
  where dsp.ano         = ln_ano
    and dsp.semana      = ln_semana
    and dsp.cod_labor   = asi_cod_labor;

  return(Result);

end usf_pr_tarifa_dstj;
/

