prompt Creating function USF_PRY_ACTIV_AVANCE
prompt ======================================
prompt
create or replace function cantabria.USF_PRY_ACTIV_AVANCE
(as_nro_pry in pry_actividad.nro_proyecto%type,
 an_nro_actividad in pry_actividad.nro_actividad%type
) return number is

Result              number(5,2);

begin

Select sum(pcd.prct_avance)
  into Result
  from pry_periodo_control_det pcd
 where pcd.nro_proyecto = as_nro_pry
   and pcd.nro_actividad = an_nro_actividad;

return(Result);

end USF_PRY_ACTIV_AVANCE;
/

prompt
prompt Creating function USF_PRY_OT_GASTO
prompt ==================================
prompt
create or replace function cantabria.usf_pry_ot_gasto(
       as_ot orden_trabajo.nro_orden%type,
       tipo char
) return number is
  ln_importe number;

Begin
  If tipo = 'MO' then --Mano Obra
      --Select Sum(o.cant_real*o.costo_unit)
      Select Sum(o.cant_proyect * o.costo_unit)
       into ln_importe
       from operaciones o, labor l
      where o.nro_orden = as_ot
        and o.cod_labor = l.cod_labor
        and l.flag_maq_mo = 'O';
  elsif tipo = 'EQ' then --Equipo o Maquinari
     Select Sum(o.cant_proyect * o.costo_unit)
       into ln_importe
       from operaciones o, labor l
      where o.nro_orden = as_ot
        and o.cod_labor = l.cod_labor
        and l.flag_maq_mo = 'M';
  elsif tipo = 'IN' then -- Insumo o Material
     Select sum(amp.cant_proyect * amp.precio_unit)
       into ln_importe
       from operaciones o, articulo_mov_proy amp
      where o.oper_sec = amp.oper_sec
        and o.nro_orden = as_ot;
  elsif tipo = 'SE' then -- Servicios
     Select sum(osd.importe)
       into ln_importe
       from operaciones o, orden_servicio os, orden_servicio_det osd
      where os.cod_origen = osd.cod_origen
        and os.nro_os = osd.nro_os
        and osd.oper_sec = o.oper_sec
        and o.nro_orden = as_ot;
  else
      ln_importe := 0;
  end if;

  Return(ln_importe);

end usf_pry_ot_gasto;
/

prompt
prompt Creating function USF_PRY_OT_ESTRUCTURA
prompt =======================================
prompt
create or replace function cantabria.usf_pry_ot_estructura(
       as_ot orden_trabajo.nro_orden%type,
       as_tipo char
) return number is
  ln_Result number;

Begin
  Select sum(usf_pry_ot_gasto(oth.nro_orden,as_tipo))
    into ln_Result
    from ot_estructura ot, Orden_Trabajo oth
   where ot.ot_hijo = oth.nro_orden
     and oth.flag_estructura = '0'
   Start with ot.ot_padre = as_ot
 Connect by prior ot.ot_hijo = ot.ot_padre;
 Return(ln_Result);
End usf_pry_ot_estructura;
/

prompt
prompt Creating function USF_PTO_ACUM_TRIM_CENTRADO
prompt ============================================
prompt
create or replace function cantabria.USF_PTO_ACUM_TRIM_CENTRADO(
     an_mes in number, an_ano in number, as_cencos in char, as_cnta_prsp in char)
    return number is
  Result number;
begin

  if an_mes = 1 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) ) +
               (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) ) +
               (NVL(p.var_ene,0)  + NVL( p.var_feb,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 2 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0)) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 3 then
     Select ( NVL( p.proy_feb,0) + NVL( p.proy_mar,0) + NVL(p.proy_abr,0) ) +
            ( NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) + NVL(p.ejec_abr,0) ) +
            ( NVL( p.var_feb,0) + NVL( p.var_mar,0) + NVL(p.var_abr,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 4 then
     Select (NVL( p.proy_mar,0) + NVL(p.proy_abr,0) + NVL( p.proy_may,0) ) +
            (NVL( p.ejec_mar,0) + NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) ) +
            (NVL( p.var_mar,0) + NVL(p.var_abr,0) + NVL( p.var_may,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 5 then
     Select (NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) ) +
            (NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) ) +
            (NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) )
      into result
      from presupuesto_partida p
      Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 6 then
     Select (NVL( p.proy_may,0) + NVL( p.proy_jun,0) + NVL(p.proy_jul,0) ) +
            (NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) + NVL(p.ejec_jul,0) ) +
            (NVL( p.var_may,0) + NVL( p.var_jun,0) + NVL(p.var_jul,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 7 then
     Select (NVL( p.proy_jun,0) + NVL(p.proy_jul,0) + NVL( p.proy_ago,0) ) +
            (NVL( p.ejec_jun,0) + NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) ) +
            (NVL( p.var_jun,0) + NVL(p.var_jul,0) + NVL( p.var_ago,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 8 then
     Select (NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) ) +
            (NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) ) +
            (NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 9 then
     Select (NVL( p.proy_ago,0) + NVL( p.proy_set,0) + NVL(p.proy_oct,0) ) +
            (NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) + NVL(p.ejec_oct,0) ) +
            (NVL( p.var_ago,0) + NVL( p.var_set,0) + NVL(p.var_oct,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 10 then
     Select (NVL( p.proy_set,0) + NVL(p.proy_oct,0) + NVL( p.proy_nov,0) ) +
            (NVL( p.ejec_set,0) + NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) ) +
            (NVL( p.var_set,0) + NVL(p.var_oct,0) + NVL( p.var_nov,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 11 then
     Select (NVL(p.proy_oct,0) + NVL( p.proy_nov,0) + NVL( p.proy_dic,0) ) +
            (NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0) ) +
            (NVL(p.var_oct,0) + NVL( p.var_nov,0) + NVL( p.var_dic,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 12 then
     Select (NVL( p.proy_nov,0) + NVL( p.proy_dic,0) ) +
            (NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0) ) +
            (NVL( p.var_nov,0) + NVL( p.var_dic,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if ;

  return(Result);
end USF_PTO_ACUM_TRIM_CENTRADO;
/

prompt
prompt Creating function USF_PTO_ACUMULADO_ANUAL
prompt =========================================
prompt
create or replace function cantabria.USF_PTO_ACUMULADO_ANUAL(
   an_ano         in number,
   as_cencos      in centros_costo.cencos%TYPE,
   as_cnta_prsp   in presupuesto_cuenta.cnta_prsp%TYPE
)
  return number is
  Result        number;
  ln_prsp       presupuesto_partida.proy_ene%TYPE;
  ln_ejec       presupuesto_partida.ejec_ene%TYPE;
  ln_prctg_var  presupuesto_partida.prctg_var%TYPE;
begin

  --================================================
  -- Obtener el % de variacion
  --================================================
  SELECT NVL(prctg_var,0)
    INTO ln_prctg_var
    FROM presupuesto_partida
   WHERE ano       = an_ano
     AND cencos    = as_cencos
     AND cnta_prsp = as_cnta_prsp ;

  --==========================
  -- Presupuestado Anual
  --==========================
  Select NVL(p.proy_ene,0) + NVL(p.proy_feb,0) + NVL(p.proy_mar,0) +
         NVL(p.proy_abr,0) + NVL(p.proy_may,0) + NVL(p.proy_jun,0) +
         NVL(p.proy_jul,0) + NVL(p.proy_ago,0) + NVL(p.proy_set,0) +
         NVL(p.proy_oct,0) + NVL(p.proy_nov,0) + NVL(p.proy_dic,0) +
         NVL(p.var_ene,0)  + NVL(p.var_feb,0)  + NVL(p.var_mar,0)  +
         NVL(p.var_abr,0)  + NVL(p.var_may,0)  + NVL(p.var_jun,0)  +
         NVL(p.var_jul,0)  + NVL(p.var_ago,0)  + NVL(p.var_set,0)  +
         NVL(p.var_oct,0)  + NVL(p.var_nov,0)  + NVL(p.var_dic,0)
    into ln_prsp
    from presupuesto_partida p
   Where ano = an_ano
     and cencos = as_cencos
     and cnta_prsp = as_cnta_prsp;


  Select NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
         NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
         NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
         NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0)
    into ln_ejec
    from presupuesto_partida p
   Where ano       = an_ano
     and cencos    = as_cencos
     and cnta_prsp = as_cnta_prsp;

  if ln_prctg_var > 0 then
     ln_prsp := ln_prsp + (1+ ln_prctg_var/100);
  end if;

  Result := ln_prsp + ln_ejec;
  return(Result);
end USF_PTO_ACUMULADO_ANUAL;
/

prompt
prompt Creating function USF_PTO_ACUMULADO_A_LA_FECHA
prompt ==============================================
prompt
create or replace function cantabria.USF_PTO_ACUMULADO_A_LA_FECHA(
       an_mes in number,
       an_ano in number,
       as_cencos in char,
       as_cnta_prsp in char)
Return number is
  ln_prsp       presupuesto_partida.proy_ene%TYPE;
  ln_ejec       presupuesto_partida.ejec_ene%TYPE;
  ln_prctg_var  presupuesto_partida.prctg_var%TYPE;
  Result        number;

begin

  --================================================
  -- Obtener el % de variacion
  --================================================
  SELECT NVL(prctg_var,0)
    INTO ln_prctg_var
    FROM presupuesto_partida
   WHERE ano       = an_ano
     AND cencos    = as_cencos
     AND cnta_prsp = as_cnta_prsp ;


  if an_mes = 1 then
     Select NVL(p.proy_ene,0) + NVL(p.var_ene,0)
       into ln_prsp
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_ene,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

  elsif an_mes = 2 then

     Select NVL(p.proy_ene,0) + NVL(p.proy_feb,0) +
            NVL(p.var_ene,0)  + NVL(p.var_feb,0)
       into ln_prsp
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_ene,0) + NVL(p.ejec_feb,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

  elsif an_mes = 3 then

     Select NVL(p.proy_ene,0) + NVL(p.proy_feb,0) + NVL(p.proy_mar,0) +
            NVL(p.var_ene,0)  + NVL(p.var_feb,0)  + NVL(p.var_mar,0)
       into ln_prsp
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_ene,0) + NVL(p.ejec_feb,0) + NVL(p.ejec_mar,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano       = an_ano
        and cencos    = as_cencos
        and cnta_prsp = as_cnta_prsp;

  elsif an_mes = 4 then

     Select NVL(p.proy_ene,0) + NVL(p.proy_feb,0) + NVL(p.proy_mar,0) + NVL(p.proy_abr,0) +
            NVL(p.var_ene,0)  + NVL(p.var_feb,0)  + NVL(p.var_mar,0)  + NVL(p.var_abr,0)
       into ln_prsp
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_ene,0) + NVL(p.ejec_feb,0) + NVL(p.ejec_mar,0) + NVL(p.ejec_abr,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano       = an_ano
        and cencos    = as_cencos
        and cnta_prsp = as_cnta_prsp;

  elsif an_mes = 5 then

     Select NVL(p.proy_ene,0) + NVL(p.proy_feb,0) + NVL(p.proy_mar,0) +
            NVL(p.proy_abr,0) + NVL(p.proy_may,0) +
            NVL(p.var_ene,0)  + NVL(p.var_feb,0)  + NVL(p.var_mar,0) +
            NVL(p.var_abr,0)  + NVL(p.var_may,0)
       into ln_prsp
       from presupuesto_partida p
       Where ano       = an_ano
         and cencos    = as_cencos
         and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_ene,0) + NVL(p.ejec_feb,0) + NVL( p.ejec_mar,0) +
            NVL(p.ejec_abr,0) + NVL(p.ejec_may,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

  elsif an_mes = 6 then

     Select NVL(p.proy_ene,0) + NVL(p.proy_feb,0) + NVL(p.proy_mar,0) +
            NVL(p.proy_abr,0) + NVL(p.proy_may,0) + NVL(p.proy_jun,0) +
            NVL(p.var_ene,0)  + NVL(p.var_feb,0)  + NVL(p.var_mar,0)  +
            NVL(p.var_abr,0)  + NVL(p.var_may,0)  + NVL(p.var_jun,0)
       into ln_prsp
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_ene,0) + NVL(p.ejec_feb,0) + NVL(p.ejec_mar,0) +
            NVL(p.ejec_abr,0) + NVL(p.ejec_may,0) + NVL(p.ejec_jun,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

  elsif an_mes = 7 then

     Select NVL(p.proy_ene,0) + NVL(p.proy_feb,0) + NVL(p.proy_mar,0) +
            NVL(p.proy_abr,0) + NVL(p.proy_may,0) + NVL(p.proy_jun,0) +
            NVL(p.proy_jul,0) +
            NVL(p.var_ene,0)  + NVL(p.var_feb,0)  + NVL(p.var_mar,0) +
            NVL(p.var_abr,0)  + NVL(p.var_may,0)  + NVL(p.var_jun,0) +
            NVL(p.var_jul,0)
       into ln_prsp
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_ene,0) + NVL(p.ejec_feb,0) + NVL(p.ejec_mar,0) +
