            NVL(p.var_ene,0)  + NVL(p.var_feb,0) + NVL(p.var_mar,0) +
            NVL(p.var_abr,0)  + NVL(p.var_may,0) + NVL(p.var_jun,0) +
            NVL(p.var_jul,0)  + NVL(p.var_ago,0) + NVL(p.var_set,0) +
