            NVL(p.var_jul,0)  + NVL( p.var_ago,0) + NVL(p.var_set,0) +
            NVL(p.var_oct,0)  + NVL( p.var_nov,0)
       into ln_prsp
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_ene,0) + NVL(p.ejec_feb,0) + NVL(p.ejec_mar,0) +
            NVL(p.ejec_abr,0) + NVL(p.ejec_may,0) + NVL(p.ejec_jun,0) +
            NVL(p.ejec_jul,0) + NVL(p.ejec_ago,0) + NVL(p.ejec_set,0) +
            NVL(p.ejec_oct,0) + NVL(p.ejec_nov,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano = an_ano
        and cencos = as_cencos
        and cnta_prsp = as_cnta_prsp;

  elsif an_mes = 12 then

     Result := usf_pto_acumulado_anual(an_ano, as_cencos, as_cnta_prsp);
     Return (Result);

  end if ;

    if ln_prctg_var > 0 then
     ln_prsp := ln_prsp + (1+ ln_prctg_var/100);
  end if;

  Result := ln_prsp + ln_ejec;

  return(Result);
end USF_PTO_ACUMULADO_A_LA_FECHA;
