prompt
create or replace function cantabria.USF_PTO_ACUMULADO_MENSUAL (
   an_mes in number, an_ano in number, as_cencos in char, as_cnta_prsp in char)
    return number is
  Result number;
begin

  if an_mes = 1 then
     Select NVL(p.proy_ene,0) + NVL(p.ejec_ene,0) + NVL(p.var_ene,0)
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 2 then
     Select NVL(p.proy_feb,0) + NVL(p.ejec_feb,0) + NVL(p.var_feb,0)
