  end if;
  if an_mes = 9 then
     Select NVL(p.proy_set,0) + NVL(p.ejec_set,0) + NVL(p.var_set,0)
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
