  if an_mes = 10 then
     Select NVL(p.proy_oct,0) + NVL(p.ejec_oct,0) + NVL(p.var_oct,0)
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 11 then
     Select NVL(p.proy_nov,0) + NVL(p.ejec_nov,0) + NVL(p.var_nov,0)
