prompt
prompt Creating function USF_PTO_ACUMULADO_SEMESTRAL
prompt =============================================
prompt
create or replace function cantabria.USF_PTO_ACUMULADO_SEMESTRAL(
    an_mes in number,
    an_ano in number,
    as_cencos in char,
    as_cnta_prsp in char

) Return number is

  Result        number;
  ln_prsp       presupuesto_partida.proy_ene%TYPE;
  ln_ejec       presupuesto_partida.ejec_ene%TYPE;
  ln_prctg_var  presupuesto_partida.prctg_var%TYPE;

begin

  --================================================
  -- Obtener el % de variacion
  --================================================
  SELECT NVL(prctg_var,0)
    INTO ln_prctg_var
    FROM presupuesto_partida
   WHERE ano       = an_ano
     AND cencos    = as_cencos
     AND cnta_prsp = as_cnta_prsp ;

  --================================================
  -- Calcular el presupuesto y su ejecucion
  --================================================
  if an_mes BETWEEN 1 AND 6 then
     Select NVL(p.proy_ene,0) + NVL(p.proy_feb,0) + NVL(p.proy_mar,0) +
            NVL(p.proy_abr,0) + NVL(p.proy_may,0) + NVL(p.proy_jun,0) +
            NVL(p.var_ene,0)  + NVL(p.var_feb,0)  + NVL(p.var_mar,0)  +
            NVL(p.var_abr,0)  + NVL(p.var_may,0)  + NVL(p.var_jun,0)
       into ln_prsp
       from presupuesto_partida p
      Where ano       = an_ano
        and cencos    = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_ene,0) + NVL(p.ejec_feb,0) + NVL(p.ejec_mar,0) +
            NVL(p.ejec_abr,0) + NVL(p.ejec_may,0) + NVL(p.ejec_jun,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano       = an_ano
        and cencos    = as_cencos
        and cnta_prsp = as_cnta_prsp;

  ELSIF an_mes BETWEEN 7 AND 12 THEN

     Select NVL(p.proy_jul,0) + NVL(p.proy_ago,0) + NVL(p.proy_set,0) +
            NVL(p.proy_oct,0) + NVL(p.proy_nov,0) + NVL(p.proy_dic,0) +
            NVL(p.var_jul,0)  + NVL(p.var_ago,0)  + NVL(p.var_set,0)  +
            NVL(p.var_oct,0)  + NVL(p.var_nov,0)  + NVL(p.var_dic,0)
       into ln_prsp
       from presupuesto_partida p
      Where ano       = an_ano
        and cencos    = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_jul,0) + NVL(p.ejec_ago,0) + NVL(p.ejec_set,0) +
            NVL(p.ejec_oct,0) + NVL(p.ejec_nov,0) + NVL(p.ejec_dic,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano       = an_ano
        and cencos    = as_cencos
        and cnta_prsp = as_cnta_prsp;
  end if ;

  --================================================
  -- Calcular el % de variabilidad
  --================================================
  if ln_prctg_var > 0 then
     ln_prsp := ln_prsp + (1+ ln_prctg_var/100);
  end if;
  Result := ln_prsp + ln_ejec;

  return(Result);
end USF_PTO_ACUMULADO_SEMESTRAL;
/

