      Where ano       = an_ano
        and cencos    = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_set,0) + NVL(p.ejec_oct,0) + NVL(p.ejec_nov,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano       = an_ano
        and cencos    = as_cencos
        and cnta_prsp = as_cnta_prsp;

  elsif an_mes = 12 then

     Select NVL(p.proy_oct,0) + NVL(p.proy_nov,0) + NVL(p.proy_dic,0) +
            NVL(p.var_oct,0)  + NVL(p.var_nov,0)  + NVL(p.var_dic,0)
       into ln_prsp
       from presupuesto_partida p
      Where ano       = an_ano
        and cencos    = as_cencos
        and cnta_prsp = as_cnta_prsp;

     Select NVL(p.ejec_oct,0) + NVL(p.ejec_nov,0) + NVL(p.ejec_dic,0)
       into ln_ejec
       from presupuesto_partida p
      Where ano       = an_ano
        and cencos    = as_cencos
        and cnta_prsp = as_cnta_prsp;

  end if ;

  --================================================
  -- Calcular el % de variabilidad
  --================================================
  if ln_prctg_var > 0 then
     ln_prsp := ln_prsp + (1+ ln_prctg_var/100);
  end if;
  Result := ln_prsp + ln_ejec;

  return(Result);
end USF_PTO_ACUMULADO_TRIMESTRE;
/

prompt
prompt Creating function USF_PTO_AFECTA_EJECUCION
prompt ==========================================
prompt
create or replace function cantabria.USF_PTO_AFECTA_EJECUCION (
    ad_fecha      in date,
    an_ano        in number,
    as_cencos     in centros_costo.cencos%TYPE,
    as_cnta_prsp  in presupuesto_cuenta.cnta_prsp%TYPE,
    an_importe    in NUMBER
) return number is

  ln_mes         number;
  ln_reg         number;  -- Guarda numero de registro
  ln_ctrl        presupuesto_partida.flag_ctrl%type;
  ln_total_pto   number;

  e_NoExistePartida    EXCEPTION;
  e_ExcedePartida      EXCEPTION;
begin
  -- Segun la fecha dada, halla el mes
  ln_mes := to_number( TO_CHAR(ad_fecha, 'MM'));

  -- Busca si existe partida, caso contrario devuelve error
  Select Count( cencos) into ln_reg from presupuesto_partida
    Where ano = an_ano and cencos = as_cencos
          and cnta_prsp = as_cnta_prsp;
  if ln_reg = 0 then  -- No existe partida
     RAISE_APPLICATION_ERROR( -20000, 'No existe Partida presupuestal '||
       'para ' || as_cencos || ', ' || as_cnta_prsp) ;
     return 0;  -- Fallo
  end if;

  -- Evalua si tiene presupuesto segun flag de control
   -- Segun Partida presupuestal, halla la forma de procesar
  Select p.flag_ctrl into ln_ctrl from presupuesto_partida p
    where p.ano = an_ano and p.cencos = as_cencos and
    p.cnta_prsp = as_cnta_prsp;

  --==========================
  -- Acumulado Anual
  --==========================
  if ln_ctrl = 1 then
     ln_total_pto := usf_pto_sldo_acumulado_anual(an_ano, as_cencos, as_cnta_prsp);
  end if;

  --==========================
  -- Acumulado a la Fecha
  --==========================
  if ln_ctrl = 2 then
     ln_total_pto := usf_pto_sldo_acumulado_fecha(an_ano, ln_mes, as_cencos, as_cnta_prsp);
  end if;

  --==========================
  -- Mensual
  --==========================
  if ln_ctrl = 3 then
     ln_total_pto := usf_pto_sldo_mensual(an_ano, ln_mes,as_cencos, as_cnta_prsp);
  end if;

  --==========================
  -- Ultimo Trimestre Acumulado
  --==========================
  if ln_ctrl = 4 then
     ln_total_pto := usf_pto_sldo_trimestre(an_ano, ln_mes, as_cencos, as_cnta_prsp);
  end if;

  --==========================
  -- Semestre
  --==========================
  if ln_ctrl = 5 then
     ln_total_pto := usf_pto_sldo_semestre(an_ano, ln_mes, as_cencos, as_cnta_prsp);
  end if;

  IF ln_total_pto < an_importe then
     RAISE_APPLICATION_ERROR( -20001, 'Excede la Partida presupuestal '||
     'de: ' || as_cencos || ', ' || as_cnta_prsp || ' Saldo Actual: ' ||
     ln_total_pto) ;
     return 0;  -- Fallo
  end if;

  -- Actualiza importes ejecutados
  update presupuesto_partida  set
     ejec_ene = DECODE( ln_mes, 1, ejec_ene + an_importe, ejec_ene),
     ejec_feb = DECODE( ln_mes, 2, ejec_feb + an_importe, ejec_feb),
     ejec_mar = DECODE( ln_mes, 3, ejec_mar + an_importe, ejec_mar),
     ejec_abr = DECODE( ln_mes, 4, ejec_abr + an_importe, ejec_abr),
     ejec_may = DECODE( ln_mes, 5, ejec_may + an_importe, ejec_may),
     ejec_jun = DECODE( ln_mes, 6, ejec_jun + an_importe, ejec_jun),
     ejec_jul = DECODE( ln_mes, 7, ejec_jul + an_importe, ejec_jul),
     ejec_ago = DECODE( ln_mes, 8, ejec_ago + an_importe, ejec_ago),
     ejec_set = DECODE( ln_mes, 9, ejec_set + an_importe, ejec_set),
     ejec_oct = DECODE( ln_mes, 10, ejec_oct + an_importe, ejec_oct),
     ejec_nov = DECODE( ln_mes, 11, ejec_nov + an_importe, ejec_nov),
     ejec_dic = DECODE( ln_mes, 12, ejec_dic + an_importe, ejec_dic)
          Where ano = an_ano and cencos = as_cencos
          and cnta_prsp = as_cnta_prsp;

  return(1);
end USF_PTO_AFECTA_EJECUCION;
/

prompt
prompt Creating function USF_PTO_AMPLIAC_ACUM
prompt ======================================
prompt
create or replace function cantabria.USF_PTO_AMPLIAC_ACUM(
    an_ano in number, an_mes_ini in number, an_mes_fin in number, as_cencos in char,
    as_cnta_prsp in char )
 Return number is
 Result number;
 ln_count  number ;
BEGIN

select count(*)
  into ln_count
  from presup_variacion
 where ano = an_ano and tipo_variacion = 'A' and
       cencos_origen = as_cencos and cnta_prsp_origen = as_cnta_prsp and
       mes_origen <= an_mes_fin ;

IF ln_count>0 THEN
   select sum(nvl(importe,0))
     into result
     from presup_variacion
    where ano = an_ano and tipo_variacion = 'A' and
          cencos_origen = as_cencos and cnta_prsp_origen = as_cnta_prsp and
          mes_origen <= an_mes_fin ;
    result := nvl(result,0) ;
ELSE
   result := 0 ;
END IF ;

return(Result);

END USF_PTO_AMPLIAC_ACUM;
/

prompt
prompt Creating function USF_PTO_AMPL_REST_X_TIPO
prompt ==========================================
prompt
create or replace function cantabria.USF_PTO_AMPL_REST_X_TIPO(
    an_ano in number, an_mes_ini in number, an_mes_fin in number, as_cencos in char,
    as_cnta_prsp in char )
 Return number is
 Result number;
BEGIN

IF an_mes_fin < 12 THEN
   select sum(nvl(importe,0))
     into result
     from presup_variacion
    where ano = an_ano and tipo_variacion = 'A' and
          cencos_origen = as_cencos and cnta_prsp_origen = as_cnta_prsp and
          mes_origen > an_mes_fin ;
   result := nvl(result,0) ;
ELSE
   result := 0 ;
END IF ;

return(Result);

END USF_PTO_AMPL_REST_X_TIPO;
/

prompt
prompt Creating function USF_PTO_EJECUCION_ACUMULADO
prompt =============================================
prompt
create or replace function cantabria.USF_PTO_EJECUCION_ACUMULADO(
   an_ano in number, an_mes in number, as_cencos in char, as_cnta_prsp in char)
     return number is
  Result number;
begin

  --==========================
  -- Ejecucion Acumulada
  --==========================
  if an_mes = 1 then
     Select NVL(p.ejec_ene,0)
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 2 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 3 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0))
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 4 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 5 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) )
      into result
      from presupuesto_partida p
      Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 6 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 7 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 8 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 9 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 10 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
        NVL(p.ejec_oct,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 11 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
        NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 12 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
        NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0))
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if ;
  return(Result);
end USF_PTO_EJECUCION_ACUMULADO;
/

prompt
prompt Creating function USF_PTO_EJECUCION_ANUAL
prompt =========================================
prompt
create or replace function cantabria.USF_PTO_EJECUCION_ANUAL(
   ani_year       in number,
   asi_cencos     in centros_costo.cencos%TYPE,
   asi_cnta_prsp  in presupuesto_cuenta.cnta_prsp%TYPE
)return number is
  ln_Result number;
begin

 --==========================
  -- Ejecucion Acumulada Anual
  --==========================
  Select NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
         NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
         NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
         NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0)
    into ln_Result
    from presupuesto_partida p
   Where ano = ani_year
     and cencos = asi_cencos
     and cnta_prsp = asi_cnta_prsp;

  return(ln_Result);
end USF_PTO_EJECUCION_ANUAL;
/

prompt
prompt Creating function USF_PTO_EJECUCION_MENSUAL
prompt ===========================================
prompt
create or replace function cantabria.USF_PTO_EJECUCION_MENSUAL (
       ani_year      in number,
       ani_mes       in number,
       asi_cencos    in centros_costo.cencos%TYPE,
       asi_cnta_prsp in presupuesto_cuenta.cnta_prsp%TYPE
) return number is

/*
  Funcion que retorna lo ejecutado para un mes dado
*/

  -- Declaracion de variables
  ln_ejecuc      number;    -- importe de ejecucion

begin

    if ani_mes = 1 then
       SELECT NVL(ejec_ene,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 2 then

       SELECT NVL(ejec_feb,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 3 then

       SELECT NVL(ejec_mar,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 4 then

       SELECT NVL(ejec_abr,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 5 then

       SELECT NVL(ejec_may,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 6 then

       SELECT NVL(ejec_jun,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 7 then

       SELECT NVL(ejec_jul,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 8 then

       SELECT NVL(ejec_ago,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 9 then

       SELECT NVL(ejec_set,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 10 then

       SELECT NVL(ejec_oct,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 11 then

       SELECT NVL(ejec_nov,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 12 then

       SELECT NVL(ejec_dic,0)
         into ln_ejecuc
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    end if;
  return(ln_ejecuc);
end USF_PTO_EJECUCION_MENSUAL;
/

prompt
prompt Creating function USF_PTO_FOUND_SALDOS
prompt ======================================
prompt
create or replace function cantabria.USF_PTO_FOUND_SALDOS(
   as_cnta1 in char, as_cnta2 in char, as_cnta3 in char, as_cnta4 in char,
   an_ano in number, as_mes in char, as_modo in char)
   return number is

  Result number;

begin
  -- EJECUCION
  if as_modo = '1E' then
     SELECT SUM( PE.IMPORTE) into result
       FROM PRESUPUESTO_EJEC PE, PRESUPUESTO_CUENTA pc
       WHERE pe.cnta_prsp = pc.cnta_prsp and
       pc.niv1 = as_cnta1 and
       pe.ano = an_ano and TRIM(to_char(pe.fecha, 'MM')) like as_mes;
  end if;
  if as_modo = '2E' then
     SELECT SUM( PE.IMPORTE) into result
       FROM PRESUPUESTO_EJEC PE, PRESUPUESTO_CUENTA pc
       WHERE pe.cnta_prsp = pc.cnta_prsp and
       pc.niv1 = as_cnta1 and pc.niv2 = as_cnta2 and
       pe.ano = an_ano and TRIM(to_char(pe.fecha, 'MM')) like as_mes;
  end if;
  if as_modo = '3E' then
     SELECT SUM( PE.IMPORTE) into result
       FROM PRESUPUESTO_EJEC PE, PRESUPUESTO_CUENTA pc
       WHERE pe.cnta_prsp = pc.cnta_prsp and
       pc.niv1 = as_cnta1 and pc.niv2 = as_cnta2 and pc.niv3 = as_cnta3 and
       pe.ano = an_ano and TRIM(to_char(pe.fecha, 'MM')) like as_mes;
  end if;
  if as_modo = '4E' then
     SELECT SUM( PE.IMPORTE) into result
       FROM PRESUPUESTO_EJEC PE
       WHERE PE.CNTA_PRSP = as_cnta4 AND
       pe.ano = an_ano and TRIM(to_char(pe.fecha, 'MM')) like as_mes;
  end if;

  -- PRESUPUESTADO
  if as_modo = '1P' then
     if as_mes = '01' then
       SELECT SUM(NVL(proy_ene,0)) into result
         FROM presupuesto_partida p, presupuesto_cuenta pc
         WHERE p.flag_estado <> '0' and ano = an_ano and
         p.cnta_prsp = pc.cnta_prsp and pc.niv1 = as_cnta1;
     end if;
     if as_mes = '02' then
       SELECT SUM(NVL(proy_feb,0)) into result
         FROM presupuesto_partida p, presupuesto_cuenta pc
         WHERE p.flag_estado <> '0' and ano = an_ano and
         p.cnta_prsp = pc.cnta_prsp and pc.niv1 = as_cnta1;
     end if;
     if as_mes = '03' then
       SELECT SUM(NVL(proy_mar,0)) into result
         FROM presupuesto_partida p, presupuesto_cuenta pc
         WHERE p.flag_estado <> '0' and ano = an_ano and
         p.cnta_prsp = pc.cnta_prsp and pc.niv1 = as_cnta1;
     end if;
     if as_mes = '04' then
       SELECT SUM(NVL(proy_abr,0)) into result
         FROM presupuesto_partida p, presupuesto_cuenta pc
         WHERE p.flag_estado <> '0' and ano = an_ano and
         p.cnta_prsp = pc.cnta_prsp and pc.niv1 = as_cnta1;
     end if;
     if as_mes = '05' then
       SELECT SUM(NVL(proy_may,0)) into result
         FROM presupuesto_partida p, presupuesto_cuenta pc
         WHERE p.flag_estado <> '0' and ano = an_ano and
         p.cnta_prsp = pc.cnta_prsp and pc.niv1 = as_cnta1;
     end if;
     if as_mes = '06' then
       SELECT SUM(NVL(proy_jun,0)) into result
         FROM presupuesto_partida p, presupuesto_cuenta pc
         WHERE p.flag_estado <> '0' and ano = an_ano and
         p.cnta_prsp = pc.cnta_prsp and pc.niv1 = as_cnta1;
     end if;
     if as_mes = '07' then
       SELECT SUM(NVL(proy_jul,0)) into result
         FROM presupuesto_partida p, presupuesto_cuenta pc
         WHERE p.flag_estado <> '0' and ano = an_ano and
