prompt
prompt Creating function USF_PTO_GET_SUELDO_FIJO
prompt =========================================
prompt
create or replace function cantabria.usf_pto_get_sueldo_fijo(
       asi_trabajador IN maestro.cod_trabajador%TYPE
) return number is
  ln_Result number;
begin
  SELECT NVL(SUM(t.imp_gan_desc),0)
    INTO ln_Result
    FROM gan_desct_fijo t
   WHERE t.cod_trabajador = asi_trabajador
     AND t.concep LIKE '1%';

  return(ln_Result);
end usf_pto_get_sueldo_fijo;
/

prompt
prompt Creating function USF_PTO_PREC_X_ART
prompt ====================================
prompt
create or replace function cantabria.usf_pto_prec_x_art(
       asi_cod_art         in articulo.cod_art%TYPE,
       asi_almacen         in almacen.almacen%TYPE,
       adi_fecha           IN DATE
) return number is

  -- Retorna el precio unitario en dolares

  ln_Result            number;
  ln_count             number;
  ln_prc_cmp_ref       logparam.precio_cmp_ref%TYPE;
  ls_origen            origen.cod_origen%TYPE;
  li_year              NUMBER;
  li_mes               NUMBER;
  is_dolar             logparam.cod_dolares%TYPE;

BEGIN

   li_year := to_number(to_char(adi_fecha, 'yyyy'));
   li_mes  := to_number(to_char(adi_fecha, 'mm'));

   SELECT precio_cmp_ref, cod_dolares
     INTO ln_prc_cmp_ref, is_dolar
     FROM logparam
    WHERE reckey = '1';

   SELECT cod_origen
     INTO ls_origen
     FROM almacen
    WHERE almacen = asi_almacen;

   SELECT COUNT(*)
     INTO ln_count
     FROM prsp_proy_prec_art t
    WHERE t.ano = li_year
      AND t.mes = li_mes
      AND t.cod_origen = ls_origen
      AND t.cod_art    = asi_cod_art;

   IF ln_count = 1 THEN
      SELECT usf_fl_conv_mon(precio_proyect, cod_moneda, is_dolar, adi_fecha)
        INTO ln_result
        FROM prsp_proy_prec_art t
       WHERE t.ano = li_year
         AND t.mes = li_mes
         AND t.cod_origen = ls_origen
         AND t.cod_art    = asi_cod_art;

      RETURN (ln_result);

   END IF;

   select count(*)
     into ln_count
    from articulo_almacen aa
    where aa.cod_art = asi_cod_art
      and aa.almacen = asi_almacen;

   if ln_count = 0 then
      select count(*)
        into ln_count
        from articulo
       where cod_art = asi_cod_art;

      if ln_count = 0 then
         ln_result := ln_prc_cmp_ref;
      else
         select nvl(costo_ult_compra,0)
           into ln_Result
           from articulo
          where cod_art = asi_cod_art;
      end if;
   else
      select nvl(costo_ult_compra,0)
       into ln_Result
      from articulo_almacen aa
      where aa.cod_art = asi_cod_art
        and aa.almacen = asi_almacen;

      if ln_Result = 0 then
         select nvl(costo_ult_compra,0)
           into ln_Result
           from articulo
          where cod_art = asi_cod_art;
      end if;
   end if;

   -- Si el precio de ultima compra es el mismo que en Parametros entonces
   -- Busco el ultimo precio de cotizacion
   IF ln_Result = ln_prc_cmp_ref OR ln_Result <= 0 THEN
      ln_Result := usf_cmp_ult_prec_cotiz(asi_cod_art);
   END IF;

  return(ln_Result);
end usf_pto_prec_x_art;
/

prompt
prompt Creating function USF_PTO_PRESUP_ACUMULADO
prompt ==========================================
prompt
create or replace function cantabria.USF_PTO_PRESUP_ACUMULADO(
   an_ano in number, an_mes in number, as_cencos in char, as_cnta_prsp in char)
     return number is
  Result number;
begin

  --==========================
  -- Presupuesto Acumulado Anual
  --==========================
  if an_mes = 1 then
     Select NVL(p.proy_ene,0)
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 2 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 3 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0))
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 4 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 5 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) )
      into result
      from presupuesto_partida p
      Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 6 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 7 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 8 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 9 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 10 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
        NVL(p.proy_oct,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 11 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
        NVL(p.proy_oct,0) + NVL( p.proy_nov,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 12 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
        NVL(p.proy_oct,0) + NVL( p.proy_nov,0) + NVL( p.proy_dic,0))
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if ;
  return(Result);
end USF_PTO_PRESUP_ACUMULADO;
/

prompt
prompt Creating function USF_PTO_PRESUP_ANUAL
prompt ======================================
prompt
create or replace function cantabria.USF_PTO_PRESUP_ANUAL(
   ani_year       in number,
   asi_cencos     in centros_costo.cencos%TYPE,
   asi_cnta_prsp  in presupuesto_cuenta.cnta_prsp%TYPE
)return number is
  ln_Result number;
begin

  --==========================
  -- Presupuesto Acumulado Anual
  --==========================
  Select NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
         NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
         NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
         NVL(p.proy_oct,0) + NVL( p.proy_nov,0) + NVL( p.proy_dic,0)
    into ln_Result
    from presupuesto_partida p
   Where ano       = ani_year
     and cencos    = asi_cencos
     and cnta_prsp = asi_cnta_prsp;

  return(ln_Result);
end USF_PTO_PRESUP_ANUAL;
/

prompt
prompt Creating function USF_PTO_PRESUP_INICIAL
prompt ========================================
prompt
create or replace function cantabria.USF_PTO_PRESUP_INICIAL(
   an_ano in number, as_cencos in char, as_cnta_prsp in char)
     return number is
  Result number;
begin

    --==========================
  -- Presupuesto Inicial
  --==========================
  Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
        NVL(p.proy_oct,0) + NVL( p.proy_nov,0) + NVL( p.proy_dic,0))
        into result
     from presupuesto_partida p
     Where ano = an_ano and cencos = as_cencos
          and cnta_prsp = as_cnta_prsp;

  return(Result);
end USF_PTO_PRESUP_INICIAL;
/

prompt
prompt Creating function USF_PTO_PRESUP_MENSUAL
prompt ========================================
prompt
create or replace function cantabria.USF_PTO_PRESUP_MENSUAL (
       an_ano in number, an_mes in number, as_cencos in char,
       as_cnta in char )
    return number is

/*
  funcion que devuelve el presupuesto de un mes dado
*/
  -- Declaracion de variables
  ln_presup      number;

begin
    if an_mes = 1 then
       SELECT NVL(proy_ene,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 2 then
       SELECT NVL(proy_feb,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 3 then
       SELECT NVL(proy_mar,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 4 then
       SELECT NVL(proy_abr,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 5 then
       SELECT NVL(proy_may,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 6 then
       SELECT NVL(proy_jun,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 7 then
       SELECT NVL(proy_jul,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 8 then
       SELECT NVL(proy_ago,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 9 then
       SELECT NVL(proy_set,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 10 then
       SELECT NVL(proy_oct,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 11 then
       SELECT NVL(proy_nov,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
    if an_mes = 12 then
       SELECT NVL(proy_dic,0) into ln_presup
         FROM presupuesto_partida p
         WHERE flag_estado <> '0' and ano = an_ano and
         cencos = as_cencos and cnta_prsp = as_cnta;
    end if;
  return(ln_presup);
end USF_PTO_PRESUP_MENSUAL;
/

prompt
prompt Creating function USF_PTO_PRESUP_PERIODO
prompt ========================================
prompt
create or replace function cantabria.USF_PTO_PRESUP_PERIODO(
       ani_year       in number,
       asi_cencos     in centros_costo.cencos%TYPE,
       asi_cnta_prsp  in presupuesto_cuenta.cnta_prsp%TYPE,
       ln_mes1        in number,
       ln_mes2        in number
) return number is
  ln_Result number;
begin

select CASE when 1 >= ln_mes1 and 1 <= ln_mes2 THEN
				    proy_ene
			 ELSE
				    0
			 END +
       CASE when 2 >= ln_mes1 and 2 <= ln_mes2 THEN
				    pp.proy_feb
			 ELSE
				    0
			 END +
       CASE when 3 >= ln_mes1 and 3 <= ln_mes2 THEN
				    pp.proy_mar
			 ELSE
				    0
			 END +
       CASE when 4 >= ln_mes1 and 4 <= ln_mes2 THEN
				    pp.proy_abr
			 ELSE
				    0
			 END +
       CASE when 5 >= ln_mes1 and 5 <= ln_mes2 THEN
				    pp.proy_may
			 ELSE
				    0
			 END +
       CASE when 6 >= ln_mes1 and 6 <= ln_mes2 THEN
				    pp.proy_jun
			 ELSE
				    0
			 END +
       CASE when 7 >= ln_mes1 and 7 <= ln_mes2 THEN
				    pp.proy_jul
			 ELSE
				    0
			 END +
       CASE when 8 >= ln_mes1 and 8 <= ln_mes2 THEN
				    pp.proy_ago
			 ELSE
				    0
			 END +
       CASE when 9 >= ln_mes1 and 9 <= ln_mes2 THEN
				    pp.proy_set
			 ELSE
				    0
			 END +
       CASE when 10 >= ln_mes1 and 10 <= ln_mes2 THEN
				    pp.proy_oct
			 ELSE
				    0
			 END +
       CASE when 11 >= ln_mes1 and 11 <= ln_mes2 THEN
				    pp.proy_nov
			 ELSE
				    0
			 END +
       CASE when 12 >= ln_mes1 and 12 <= ln_mes2 THEN
				    pp.proy_dic
			 ELSE
				    0
			 END
  into ln_Result
  from presupuesto_partida pp
 where pp.ano = ani_year
   and pp.cencos = asi_cencos
   and pp.cnta_prsp = asi_cnta_prsp;

  return(ln_Result);
end USF_PTO_PRESUP_PERIODO;
/

prompt
prompt Creating function USF_PTO_PRESUP_VARIACION
prompt ==========================================
prompt
create or replace function cantabria.usf_pto_presup_variacion(
       ani_year      in number,
       ani_mes       in number,
       asi_cencos    in centros_costo.cencos%TYPE,
       asi_cnta_prsp in presupuesto_cuenta.cnta_prsp%TYPE
) return number is

  ln_Result     number;
  ln_Temporal   number;

begin

  ln_Result := 0;

  -- Sumo Todas Las Ampliaciones
  SELECT sum(NVL(pv.importe,0))
    into ln_Temporal
    FROM presup_variacion pv
   WHERE pv.ano              = ani_year
     and pv.mes_origen       = ani_mes
     and pv.cencos_origen    = asi_cencos
     and pv.cnta_prsp_origen = asi_cnta_prsp
     and pv.tipo_variacion   = 'A';

  if ln_temporal is null then ln_temporal := 0; end if;

  ln_Result := ln_Result + ln_temporal;

  -- Sumo todas las transferencias que aumenten presupuesto
  SELECT sum(NVL(pv.importe,0))
    into ln_Temporal
    FROM presup_variacion pv
   WHERE pv.ano               = ani_year
     and pv.mes_destino       = ani_mes
     and pv.cencos_destino    = asi_cencos
     and pv.cnta_prsp_destino = asi_cnta_prsp
     and pv.tipo_variacion = 'T';

  if ln_temporal is null then ln_temporal := 0; end if;
  ln_Result := ln_Result + ln_Temporal;

  -- Ahora resto todas las reducciones
  SELECT sum(NVL(pv.importe,0))
    into ln_Temporal
    FROM presup_variacion pv
   WHERE pv.ano              = ani_year
     and pv.mes_origen       = ani_mes
     and pv.cencos_origen    = asi_cencos
     and pv.cnta_prsp_origen = asi_cnta_prsp
     and pv.tipo_variacion   = 'R';

  if ln_temporal is null then ln_temporal := 0; end if;
  ln_Result := ln_Result - ln_Temporal;

  -- Ahora resto todas las transferencias que disminuyan presupuesto
  SELECT SUM(NVL(pv.importe,0))
    into ln_Temporal
    FROM presup_variacion pv
   WHERE pv.ano              = ani_year
     and pv.mes_origen       = ani_mes
     and pv.cencos_origen    = asi_cencos
     and pv.cnta_prsp_origen = asi_cnta_prsp
     and pv.tipo_variacion   = 'T';

  if ln_temporal is null then ln_temporal := 0; end if;
  ln_Result := ln_Result - ln_Temporal;

  return(NVL(ln_Result,0));
end usf_pto_presup_variacion;
/

prompt
prompt Creating function USF_PTO_PRSP_DISPONIBLE
prompt =========================================
prompt
create or replace function cantabria.usf_pto_prsp_disponible(
       asi_cencos      in centros_costo.cencos%TYPE,
       asi_cnta_prsp   in presupuesto_cuenta.cnta_prsp%TYPE,
       adi_fecha       in date
) return number is
    -- Proyectado
    ln_proy_ene       presupuesto_partida.proy_ene%TYPE;
    ln_proy_feb       presupuesto_partida.proy_feb%TYPE;
    ln_proy_mar       presupuesto_partida.proy_mar%TYPE;
    ln_proy_abr       presupuesto_partida.proy_abr%TYPE;
    ln_proy_may       presupuesto_partida.proy_may%TYPE;
    ln_proy_jun       presupuesto_partida.proy_jun%TYPE;
    ln_proy_jul       presupuesto_partida.proy_jul%TYPE;
    ln_proy_ago       presupuesto_partida.proy_ago%TYPE;
    ln_proy_set       presupuesto_partida.proy_set%TYPE;
    ln_proy_oct       presupuesto_partida.proy_oct%TYPE;
    ln_proy_nov       presupuesto_partida.proy_nov%TYPE;
    ln_proy_dic       presupuesto_partida.proy_dic%TYPE;

    -- Variacion
    ln_var_ene        presupuesto_partida.var_ene%TYPE;
    ln_var_feb        presupuesto_partida.var_feb%TYPE;
    ln_var_mar        presupuesto_partida.var_mar%TYPE;
    ln_var_abr        presupuesto_partida.var_abr%TYPE;
    ln_var_may        presupuesto_partida.var_may%TYPE;
    ln_var_jun        presupuesto_partida.var_jun%TYPE;
    ln_var_jul        presupuesto_partida.var_jul%TYPE;
    ln_var_ago        presupuesto_partida.var_ago%TYPE;
    ln_var_set        presupuesto_partida.var_set%TYPE;
    ln_var_oct        presupuesto_partida.var_oct%TYPE;
    ln_var_nov        presupuesto_partida.var_nov%TYPE;
    ln_var_dic        presupuesto_partida.var_dic%TYPE;

    -- Ejecucion
    ln_ejec_ene       presupuesto_partida.ejec_ene%TYPE;
    ln_ejec_feb       presupuesto_partida.ejec_feb%TYPE;
    ln_ejec_mar       presupuesto_partida.ejec_mar%TYPE;
    ln_ejec_abr       presupuesto_partida.ejec_abr%TYPE;
    ln_ejec_may       presupuesto_partida.ejec_may%TYPE;
    ln_ejec_jun       presupuesto_partida.ejec_jun%TYPE;
    ln_ejec_jul       presupuesto_partida.ejec_jul%TYPE;
    ln_ejec_ago       presupuesto_partida.ejec_ago%TYPE;
    ln_ejec_set       presupuesto_partida.ejec_set%TYPE;
    ln_ejec_oct       presupuesto_partida.ejec_oct%TYPE;
    ln_ejec_nov       presupuesto_partida.ejec_nov%TYPE;
    ln_ejec_dic       presupuesto_partida.ejec_dic%TYPE;

    -- Otros
    ln_limite         presupuesto_partida.ejec_dic%TYPE;
    ln_ejecut         presupuesto_partida.ejec_dic%TYPE;
    ln_disponible     number;
    ln_mes            NUMBER(2);
    ln_year           number(4);
    ln_count          number;
    ln_prctg_var      presupuesto_partida.prctg_var%TYPE;

    -- Flag de Controles
    ls_flag_estado    presupuesto_partida.flag_estado%TYPE;
    ls_flag_ctrl      presupuesto_partida.flag_ctrl%TYPE;
    ls_flag_ingr_egr  presupuesto_partida.flag_ctrl%TYPE;

begin

    ln_year := to_number(to_char(adi_fecha, 'yyyy'));
    ln_mes  := to_number(to_char(adi_fecha, 'mm'));

    select count(*)
      into ln_count
      FROM presupuesto_partida
     WHERE ano       = ln_year
       AND cencos    = asi_cencos
       AND cnta_prsp = asi_cnta_prsp;

    IF ln_count = 0 then
/*       RAISE_APPLICATION_ERROR(-20000, 'No existe partida presupuestal: '
                             || chr(13) || 'A?o: '        || to_char(ln_year)
                             || chr(13) || 'Cencos: '     || asi_cencos
                             || chr(13) || 'Cnta Prsp: '  || asi_cnta_prsp);*/
       return 0;
    end if;

    SELECT NVL(prctg_var,0), NVL(flag_estado,'0'), NVL(flag_ctrl,''), NVL(flag_ingr_egr, ''),
           NVL(proy_ene,0), NVL(proy_feb,0), NVL(proy_mar,0), NVL(proy_abr,0),
           NVL(proy_may,0), NVL(proy_jun,0), NVL(proy_jul,0), NVL(proy_ago,0),
           NVL(proy_set,0), NVL(proy_oct,0), NVL(proy_nov,0), NVL(proy_dic,0),
           NVL(var_ene,0),  NVL(var_feb,0),  NVL(var_mar,0),  NVL(var_abr,0),
           NVL(var_may, 0), NVL(var_jun, 0), NVL(var_jul, 0), NVL(var_ago, 0),
           NVL(var_set,0),  NVL(var_oct,0),  NVL(var_nov, 0), NVL(var_dic, 0),
           NVL(ejec_ene,0), NVL(ejec_feb,0), NVL(ejec_mar,0), NVL(ejec_abr,0),
           NVL(ejec_may,0), NVL(ejec_jun,0), NVL(ejec_jul,0), NVL(ejec_ago,0),
           NVL(ejec_set,0), NVL(ejec_oct,0), NVL(ejec_nov,0), NVL(ejec_dic,0)
      INTO ln_prctg_var, ls_flag_estado, ls_flag_ctrl, ls_flag_ingr_egr,
           ln_proy_ene, ln_proy_feb, ln_proy_mar, ln_proy_abr, ln_proy_may, ln_proy_jun,
           ln_proy_jul, ln_proy_ago, ln_proy_set, ln_proy_oct, ln_proy_nov, ln_proy_dic,
           ln_var_ene, ln_var_feb, ln_var_mar, ln_var_abr, ln_var_may, ln_var_jun,
           ln_var_jul, ln_var_ago, ln_var_set, ln_var_oct, ln_var_nov, ln_var_dic,
           ln_ejec_ene, ln_ejec_feb, ln_ejec_mar, ln_ejec_abr, ln_ejec_may, ln_ejec_jun,
           ln_ejec_jul, ln_ejec_ago, ln_ejec_set, ln_ejec_oct, ln_ejec_nov, ln_ejec_dic
      FROM presupuesto_partida
     WHERE ano       = ln_year
       AND cencos    = asi_cencos
       AND cnta_prsp = asi_cnta_prsp;

    If ls_flag_ctrl = '' then
       RAISE_APPLICATION_ERROR( -20000, 'Partida presupuestal no tiene Flag de Control '
               || chr(13) || 'Centro de Costo    : ' || trim(asi_cencos)
               || chr(13) || 'Cuenta Presupuestal: ' || trim(asi_cnta_prsp) );
    end if;

    IF ls_flag_estado NOT IN ('1', '2') THEN
       RAISE_APPLICATION_ERROR( -20000, 'Partida con Flag de estado Desactivado '
               || chr(13) || 'Centro de Costo    : ' || trim(asi_cencos)
               || chr(13) || 'Cuenta Presupuestal: ' || trim(asi_cnta_prsp) );
    END IF;

    ln_limite := 0 ;
    ln_disponible := 0;

    IF ls_flag_ctrl = '0' THEN
       Return ln_disponible ;
    END IF;

    --=========================
    -- Total Anual
    --=========================
    IF ls_flag_ctrl = '1' THEN
       ln_limite := ln_proy_ene + ln_proy_feb + ln_proy_mar + ln_proy_abr +
                    ln_proy_may + ln_proy_jun + ln_proy_jul + ln_proy_ago +
                    ln_proy_set + ln_proy_oct + ln_proy_nov + ln_proy_dic +
                    ln_var_ene  + ln_var_feb  + ln_var_mar  + ln_var_abr +
                    ln_var_may  + ln_var_jun  + ln_var_jul  + ln_var_ago +
                    ln_var_set  + ln_var_oct  + ln_var_nov  + ln_var_dic;

       ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar + ln_ejec_abr +
                    ln_ejec_may + ln_ejec_jun + ln_ejec_jul + ln_ejec_ago +
                    ln_ejec_set + ln_ejec_oct + ln_ejec_nov + ln_ejec_dic ;

       GOTO Comparacion_Saldo ;
    END IF ;

    --=========================
    -- Acumulado a la fecha
    --=========================
    IF ls_flag_ctrl = '2' THEN
      IF ln_mes = 1 THEN
         ln_limite := ln_proy_ene + ln_var_ene ;
         ln_ejecut := ln_ejec_ene ;
      ELSIF ln_mes = 2 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb ;
         ln_ejecut := ln_ejec_ene + ln_ejec_feb;
      ELSIF ln_mes = 3 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar ;
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar;
      ELSIF ln_mes = 4 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr ;
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                      ln_ejec_abr;
      ELSIF ln_mes = 5 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may ;
         ln_ejecut := ln_ejec_ene + ln_ejec_feb +
                      ln_ejec_mar + ln_ejec_abr + ln_ejec_may ;
      ELSIF ln_mes = 6 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun ;
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                      ln_ejec_abr + ln_ejec_may + ln_ejec_jun ;
      ELSIF ln_mes = 7 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul ;
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                      ln_ejec_abr + ln_ejec_may + ln_ejec_jun +
                      ln_ejec_jul ;
      ELSIF ln_mes = 8 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul + ln_proy_ago +
                      ln_var_ago ;
         ln_ejecut := ln_ejec_ene + ln_ejec_feb +
                      ln_ejec_mar + ln_ejec_abr + ln_ejec_may +
                      ln_ejec_jun + ln_ejec_jul + ln_ejec_ago ;
      ELSIF ln_mes = 9 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul + ln_proy_ago +
                      ln_var_ago + ln_proy_set + ln_var_set ;
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                      ln_ejec_abr + ln_ejec_may + ln_ejec_jun +
                      ln_ejec_jul + ln_ejec_ago + ln_ejec_set ;
      ELSIF ln_mes = 10 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul + ln_proy_ago +
                      ln_var_ago + ln_proy_set + ln_var_set +
                      ln_proy_oct + ln_var_oct ;
         ln_ejecut := ln_ejec_ene +
                      ln_ejec_feb + ln_ejec_mar + ln_ejec_abr +
                      ln_ejec_may + ln_ejec_jun + ln_ejec_jul +
                      ln_ejec_ago + ln_ejec_set + ln_ejec_oct  ;
      ELSIF ln_mes = 11 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul + ln_proy_ago +
                      ln_var_ago + ln_proy_set + ln_var_set +
                      ln_proy_oct + ln_var_oct + ln_proy_nov +
                      ln_var_nov ;
         ln_ejecut := ln_ejec_ene + ln_ejec_feb +
                      ln_ejec_mar + ln_ejec_abr + ln_ejec_may +
                      ln_ejec_jun + ln_ejec_jul + ln_ejec_ago +
                      ln_ejec_set + ln_ejec_oct + ln_ejec_nov  ;
      ELSE
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul + ln_proy_ago +
                      ln_var_ago + ln_proy_set + ln_var_set +
                      ln_proy_oct + ln_var_oct + ln_proy_nov +
                      ln_var_nov + ln_proy_dic + ln_var_dic ;
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                      ln_ejec_abr + ln_ejec_may + ln_ejec_jun +
                      ln_ejec_jul + ln_ejec_ago + ln_ejec_set +
                      ln_ejec_oct + ln_ejec_nov + ln_ejec_dic ;
      END IF;
      GOTO Comparacion_Saldo ;
    END IF ;

    --=========================
    -- Mensual
    --=========================
    IF ls_flag_ctrl = '3' THEN

       IF ln_mes = 1 THEN
          ln_limite := ln_proy_ene + ln_var_ene ;
          ln_ejecut := ln_ejec_ene;
       ELSIF ln_mes = 2 THEN
          ln_limite := ln_proy_feb + ln_var_feb ;
          ln_ejecut := ln_ejec_feb;
       ELSIF ln_mes = 3 THEN
          ln_limite := ln_proy_mar + ln_var_mar ;
          ln_ejecut := ln_ejec_mar;
       ELSIF ln_mes = 4 THEN
          ln_limite := ln_proy_abr + ln_var_abr ;
          ln_ejecut := ln_ejec_abr;
       ELSIF ln_mes = 5 THEN
          ln_limite := ln_proy_may + ln_var_may ;
          ln_ejecut := ln_ejec_may;
       ELSIF ln_mes = 6 THEN
          ln_limite := ln_proy_jun + ln_var_jun ;
          ln_ejecut := ln_ejec_jun;
       ELSIF ln_mes = 7 THEN
          ln_limite := ln_proy_jul + ln_var_jul ;
          ln_ejecut := ln_ejec_jul;
       ELSIF ln_mes = 8 THEN
          ln_limite := ln_proy_ago + ln_var_ago ;
          ln_ejecut := ln_ejec_ago ;
       ELSIF ln_mes = 9 THEN
          ln_limite := ln_proy_set + ln_var_set ;
          ln_ejecut := ln_ejec_set ;
       ELSIF ln_mes = 10 THEN
          ln_limite := ln_proy_oct + ln_var_oct ;
          ln_ejecut := ln_ejec_oct ;
       ELSIF ln_mes = 11 THEN
          ln_limite := ln_proy_nov + ln_var_nov ;
          ln_ejecut := ln_ejec_nov ;
       ELSE
          ln_limite := ln_proy_dic + ln_var_dic ;
          ln_ejecut := ln_ejec_dic ;
       END IF;
       GOTO Comparacion_Saldo ;
    END IF  ;

    --======================================
    -- Ultimos 3 Meses (Trimestre Acumulado)
    --======================================
    IF ls_flag_ctrl = '4' THEN
       IF ln_mes = 1 then
          ln_limite := ln_proy_ene + ln_var_ene;
          ln_ejecut := ln_ejec_ene;
       ELSIf ln_mes = 2 then
          ln_limite := ln_proy_ene + ln_var_ene
                     + ln_proy_feb + ln_var_feb;
          ln_ejecut := ln_ejec_ene + ln_ejec_feb;
       ELSIF ln_mes = 3 then
           ln_limite := ln_proy_ene + ln_var_ene
                      + ln_proy_feb + ln_var_feb
                      + ln_proy_mar + ln_var_mar ;
           ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar;
       ELSIF ln_mes = 4 then
           ln_limite := ln_proy_feb + ln_var_feb
                      + ln_proy_mar + ln_var_mar
                      + ln_proy_abr + ln_var_abr;
           ln_ejecut := ln_ejec_feb + ln_ejec_mar + ln_ejec_abr;
       ELSIF ln_mes = 5 then
           ln_limite := ln_proy_mar + ln_var_mar
                      + ln_proy_abr + ln_var_abr
                      + ln_proy_may + ln_var_may;
           ln_ejecut := ln_ejec_mar + ln_ejec_abr + ln_ejec_may;
       ELSIF ln_mes = 6 then
           ln_limite := ln_proy_abr + ln_var_abr
                      + ln_proy_may + ln_var_may
                      + ln_proy_jun + ln_var_jun;
           ln_ejecut := ln_ejec_abr + ln_ejec_may + ln_ejec_jun;
       ELSIF ln_mes = 7 then
           ln_limite := ln_proy_may + ln_var_may
                      + ln_proy_jun + ln_var_jun
                      + ln_proy_jul + ln_var_jul;
           ln_ejecut := ln_ejec_may + ln_ejec_jun + ln_ejec_jul;
       ELSIF ln_mes = 8 then
           ln_limite := ln_proy_jun + ln_var_jun
                      + ln_proy_jul + ln_var_jul
                      + ln_proy_ago + ln_var_ago;
           ln_ejecut := ln_ejec_jun + ln_ejec_jul + ln_ejec_ago;
       ELSIF ln_mes = 9 then
           ln_limite := ln_proy_jul + ln_var_jul
                      + ln_proy_ago + ln_var_ago
                      + ln_proy_set + ln_var_set;
           ln_ejecut := ln_ejec_jul + ln_ejec_ago + ln_ejec_set;
       ELSIF ln_mes = 10 then
           ln_limite := ln_proy_ago + ln_var_ago
                      + ln_proy_set + ln_var_set
                      + ln_proy_oct + ln_var_oct;
           ln_ejecut := ln_ejec_ago + ln_ejec_set + ln_ejec_oct;
       ELSIF ln_mes = 11 then
           ln_limite := ln_proy_set + ln_var_set
                      + ln_proy_oct + ln_var_oct
                      + ln_proy_nov + ln_var_nov;
           ln_ejecut := ln_ejec_set + ln_ejec_oct + ln_ejec_nov;
       ELSIF ln_mes = 12 then
           ln_limite := ln_proy_oct + ln_var_oct
                      + ln_proy_nov + ln_var_nov
                      + ln_proy_dic + ln_var_dic;
           ln_ejecut := ln_ejec_oct + ln_ejec_nov + ln_ejec_dic;
       END IF;
    END IF;

    --==============================
    -- Comparacion de Disponibilidad
    --==============================
    <<Comparacion_Saldo>>

    IF ln_prctg_var > 0 THEN
       ln_limite := ln_limite * (1+ ln_prctg_var/100);
    END IF;

    ln_disponible := ln_limite - ln_ejecut;

    return(ln_disponible);
end usf_pto_prsp_disponible;
/

prompt
prompt Creating function USF_PTO_PRSP_EJEC
prompt ===================================
prompt
create or replace function cantabria.usf_pto_prsp_ejec(
       asi_cencos      in centros_costo.cencos%TYPE,
       asi_cnta_prsp   in presupuesto_cuenta.cnta_prsp%TYPE,
       adi_fecha       in date
)  return number is

  -- Ejecucion
  ln_ejec_ene       presupuesto_partida.ejec_ene%TYPE;
  ln_ejec_feb       presupuesto_partida.ejec_feb%TYPE;
  ln_ejec_mar       presupuesto_partida.ejec_mar%TYPE;
  ln_ejec_abr       presupuesto_partida.ejec_abr%TYPE;
  ln_ejec_may       presupuesto_partida.ejec_may%TYPE;
  ln_ejec_jun       presupuesto_partida.ejec_jun%TYPE;
  ln_ejec_jul       presupuesto_partida.ejec_jul%TYPE;
  ln_ejec_ago       presupuesto_partida.ejec_ago%TYPE;
  ln_ejec_set       presupuesto_partida.ejec_set%TYPE;
  ln_ejec_oct       presupuesto_partida.ejec_oct%TYPE;
  ln_ejec_nov       presupuesto_partida.ejec_nov%TYPE;
  ln_ejec_dic       presupuesto_partida.ejec_dic%TYPE;

  -- Otros
  ln_ejecut         presupuesto_partida.ejec_dic%TYPE;
  ln_mes            NUMBER(2);
  ln_year           number(4);
  ln_prctg_var      presupuesto_partida.prctg_var%TYPE;

  -- Flag de Controles
  ls_flag_estado    presupuesto_partida.flag_estado%TYPE;
  ls_flag_ctrl      presupuesto_partida.flag_ctrl%TYPE;
  ls_flag_ingr_egr  presupuesto_partida.flag_ctrl%TYPE;
  ln_count          number;


begin
    ln_year := to_number(to_char(adi_fecha, 'yyyy'));
    ln_mes  := to_number(to_char(adi_fecha, 'mm'));

    select count(*)
      into ln_count
      FROM presupuesto_partida
     WHERE ano       = ln_year
       AND cencos    = asi_cencos
       AND cnta_prsp = asi_cnta_prsp;

    IF ln_count = 0 then
       RAISE_APPLICATION_ERROR(-20000, 'No existe partida presupuestal: '
                             || chr(13) || 'A?o: '        || to_char(ln_year)
                             || chr(13) || 'Cencos: '     || asi_cencos
                             || chr(13) || 'Cnta Prsp: '  || asi_cnta_prsp);
    end if;

    SELECT NVL(prctg_var,0), NVL(flag_estado,'0'), NVL(flag_ctrl,''), NVL(flag_ingr_egr, ''),
           NVL(ejec_ene,0), NVL(ejec_feb,0), NVL(ejec_mar,0), NVL(ejec_abr,0),
           NVL(ejec_may,0), NVL(ejec_jun,0), NVL(ejec_jul,0), NVL(ejec_ago,0),
           NVL(ejec_set,0), NVL(ejec_oct,0), NVL(ejec_nov,0), NVL(ejec_dic,0)
      INTO ln_prctg_var, ls_flag_estado, ls_flag_ctrl, ls_flag_ingr_egr,
           ln_ejec_ene, ln_ejec_feb, ln_ejec_mar, ln_ejec_abr, ln_ejec_may, ln_ejec_jun,
           ln_ejec_jul, ln_ejec_ago, ln_ejec_set, ln_ejec_oct, ln_ejec_nov, ln_ejec_dic
      FROM presupuesto_partida
     WHERE ano       = ln_year
       AND cencos    = asi_cencos
       AND cnta_prsp = asi_cnta_prsp;

    If ls_flag_ctrl = '' then
       RAISE_APPLICATION_ERROR( -20000, 'Partida presupuestal no tiene Flag de Control '
               || chr(13) || 'Centro de Costo    : ' || trim(asi_cencos)
               || chr(13) || 'Cuenta Presupuestal: ' || trim(asi_cnta_prsp) );
    end if;

    IF ls_flag_estado NOT IN ('1', '2') THEN
       RAISE_APPLICATION_ERROR( -20000, 'Partida con Flag de estado Desactivado '
               || chr(13) || 'Centro de Costo    : ' || trim(asi_cencos)
               || chr(13) || 'Cuenta Presupuestal: ' || trim(asi_cnta_prsp) );
    END IF;

    ln_ejecut := 0 ;

    IF ls_flag_ctrl = '0' THEN
        Return(ln_ejecut) ;
    END IF;

    --=========================
    -- Total Anual
    --=========================
    IF ls_flag_ctrl = '1' THEN
       ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar + ln_ejec_abr +
                    ln_ejec_may + ln_ejec_jun + ln_ejec_jul + ln_ejec_ago +
                    ln_ejec_set + ln_ejec_oct + ln_ejec_nov + ln_ejec_dic ;
    END IF ;

    --=========================
    -- Acumulado a la fecha
    --=========================
    IF ls_flag_ctrl = '2' THEN
      IF ln_mes = 1 THEN
         ln_ejecut := ln_ejec_ene ;
      ELSIF ln_mes = 2 THEN
         ln_ejecut := ln_ejec_ene + ln_ejec_feb;
      ELSIF ln_mes = 3 THEN
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar;
      ELSIF ln_mes = 4 THEN
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                      ln_ejec_abr;
      ELSIF ln_mes = 5 THEN
         ln_ejecut := ln_ejec_ene + ln_ejec_feb +
                      ln_ejec_mar + ln_ejec_abr + ln_ejec_may ;
      ELSIF ln_mes = 6 THEN
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                      ln_ejec_abr + ln_ejec_may + ln_ejec_jun ;
      ELSIF ln_mes = 7 THEN
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                      ln_ejec_abr + ln_ejec_may + ln_ejec_jun +
                      ln_ejec_jul ;
      ELSIF ln_mes = 8 THEN
         ln_ejecut := ln_ejec_ene + ln_ejec_feb +
                      ln_ejec_mar + ln_ejec_abr + ln_ejec_may +
                      ln_ejec_jun + ln_ejec_jul + ln_ejec_ago ;
      ELSIF ln_mes = 9 THEN
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                      ln_ejec_abr + ln_ejec_may + ln_ejec_jun +
                      ln_ejec_jul + ln_ejec_ago + ln_ejec_set ;
      ELSIF ln_mes = 10 THEN
         ln_ejecut := ln_ejec_ene +
                      ln_ejec_feb + ln_ejec_mar + ln_ejec_abr +
                      ln_ejec_may + ln_ejec_jun + ln_ejec_jul +
                      ln_ejec_ago + ln_ejec_set + ln_ejec_oct  ;
      ELSIF ln_mes = 11 THEN
         ln_ejecut := ln_ejec_ene + ln_ejec_feb +
                      ln_ejec_mar + ln_ejec_abr + ln_ejec_may +
                      ln_ejec_jun + ln_ejec_jul + ln_ejec_ago +
                      ln_ejec_set + ln_ejec_oct + ln_ejec_nov  ;
      ELSE
         ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                      ln_ejec_abr + ln_ejec_may + ln_ejec_jun +
                      ln_ejec_jul + ln_ejec_ago + ln_ejec_set +
                      ln_ejec_oct + ln_ejec_nov + ln_ejec_dic ;
      END IF;
    END IF ;

    --=========================
    -- Mensual
    --=========================
    IF ls_flag_ctrl = '3' THEN

       IF ln_mes = 1 THEN
          ln_ejecut := ln_ejec_ene;
       ELSIF ln_mes = 2 THEN
          ln_ejecut := ln_ejec_feb;
       ELSIF ln_mes = 3 THEN
          ln_ejecut := ln_ejec_mar;
       ELSIF ln_mes = 4 THEN
          ln_ejecut := ln_ejec_abr;
       ELSIF ln_mes = 5 THEN
          ln_ejecut := ln_ejec_may;
       ELSIF ln_mes = 6 THEN
          ln_ejecut := ln_ejec_jun;
       ELSIF ln_mes = 7 THEN
          ln_ejecut := ln_ejec_jul;
       ELSIF ln_mes = 8 THEN
          ln_ejecut := ln_ejec_ago ;
       ELSIF ln_mes = 9 THEN
          ln_ejecut := ln_ejec_set ;
       ELSIF ln_mes = 10 THEN
          ln_ejecut := ln_ejec_oct ;
       ELSIF ln_mes = 11 THEN
          ln_ejecut := ln_ejec_nov ;
       ELSE
          ln_ejecut := ln_ejec_dic ;
       END IF;
    END IF  ;

    --======================================
    -- Ultimos 3 Meses (Trimestre Acumulado)
    --======================================
    IF ls_flag_ctrl = '4' THEN
       IF ln_mes = 1 then
          ln_ejecut := ln_ejec_ene;
       ELSIf ln_mes = 2 then
          ln_ejecut := ln_ejec_ene + ln_ejec_feb;
       ELSIF ln_mes = 3 then
           ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar;
       ELSIF ln_mes = 4 then
           ln_ejecut := ln_ejec_feb + ln_ejec_mar + ln_ejec_abr;
       ELSIF ln_mes = 5 then
           ln_ejecut := ln_ejec_mar + ln_ejec_abr + ln_ejec_may;
       ELSIF ln_mes = 6 then
           ln_ejecut := ln_ejec_abr + ln_ejec_may + ln_ejec_jun;
       ELSIF ln_mes = 7 then
           ln_ejecut := ln_ejec_may + ln_ejec_jun + ln_ejec_jul;
       ELSIF ln_mes = 8 then
           ln_ejecut := ln_ejec_jun + ln_ejec_jul + ln_ejec_ago;
       ELSIF ln_mes = 9 then
           ln_ejecut := ln_ejec_jul + ln_ejec_ago + ln_ejec_set;
       ELSIF ln_mes = 10 then
           ln_ejecut := ln_ejec_ago + ln_ejec_set + ln_ejec_oct;
       ELSIF ln_mes = 11 then
           ln_ejecut := ln_ejec_set + ln_ejec_oct + ln_ejec_nov;
       ELSIF ln_mes = 12 then
           ln_ejecut := ln_ejec_oct + ln_ejec_nov + ln_ejec_dic;
       END IF;
    END IF;

    Return(ln_ejecut);


end usf_pto_prsp_ejec;
/

prompt
prompt Creating function USF_PTO_PRSP_VAR
prompt ==================================
prompt
create or replace function cantabria.usf_pto_prsp_var(
       asi_cencos       in centros_costo.cencos%TYPE,
       asi_cnta_prsp    in presupuesto_cuenta.cnta_prsp%TYPE,
       adi_fecha        in date
) return number is

  -- Proyectado
  ln_proy_ene       presupuesto_partida.proy_ene%TYPE;
  ln_proy_feb       presupuesto_partida.proy_feb%TYPE;
  ln_proy_mar       presupuesto_partida.proy_mar%TYPE;
  ln_proy_abr       presupuesto_partida.proy_abr%TYPE;
  ln_proy_may       presupuesto_partida.proy_may%TYPE;
  ln_proy_jun       presupuesto_partida.proy_jun%TYPE;
  ln_proy_jul       presupuesto_partida.proy_jul%TYPE;
  ln_proy_ago       presupuesto_partida.proy_ago%TYPE;
  ln_proy_set       presupuesto_partida.proy_set%TYPE;
  ln_proy_oct       presupuesto_partida.proy_oct%TYPE;
  ln_proy_nov       presupuesto_partida.proy_nov%TYPE;
  ln_proy_dic       presupuesto_partida.proy_dic%TYPE;

  -- Variacion
  ln_var_ene        presupuesto_partida.var_ene%TYPE;
  ln_var_feb        presupuesto_partida.var_feb%TYPE;
  ln_var_mar        presupuesto_partida.var_mar%TYPE;
  ln_var_abr        presupuesto_partida.var_abr%TYPE;
  ln_var_may        presupuesto_partida.var_may%TYPE;
  ln_var_jun        presupuesto_partida.var_jun%TYPE;
  ln_var_jul        presupuesto_partida.var_jul%TYPE;
  ln_var_ago        presupuesto_partida.var_ago%TYPE;
  ln_var_set        presupuesto_partida.var_set%TYPE;
  ln_var_oct        presupuesto_partida.var_oct%TYPE;
  ln_var_nov        presupuesto_partida.var_nov%TYPE;
  ln_var_dic        presupuesto_partida.var_dic%TYPE;

  -- Otros
  ln_limite         presupuesto_partida.ejec_dic%TYPE;
  ln_prctg_var      presupuesto_partida.prctg_var%TYPE;

  -- Flag de Controles
  ls_flag_estado    presupuesto_partida.flag_estado%TYPE;
  ls_flag_ingr_egr  presupuesto_partida.flag_ctrl%TYPE;
  ls_flag_ctrl      presupuesto_partida.flag_ctrl%TYPE;
  ln_count          number;
  ln_year           number;
  ln_mes            number;

begin
    ln_year := to_number(to_char(adi_fecha, 'yyyy'));
    ln_mes  := to_number(to_char(adi_fecha, 'mm'));

    select count(*)
      into ln_count
      FROM presupuesto_partida
     WHERE ano       = ln_year
       AND cencos    = asi_cencos
       AND cnta_prsp = asi_cnta_prsp;

    IF ln_count = 0 then
       RAISE_APPLICATION_ERROR(-20000, 'No existe partida presupuestal: '
                             || chr(13) || 'A?o: '        || to_char(ln_year)
                             || chr(13) || 'Cencos: '     || asi_cencos
                             || chr(13) || 'Cnta Prsp: '  || asi_cnta_prsp);
    end if;

    SELECT NVL(prctg_var,0), NVL(flag_estado,'0'), NVL(flag_ctrl,''), NVL(flag_ingr_egr, ''),
           NVL(proy_ene,0), NVL(proy_feb,0), NVL(proy_mar,0), NVL(proy_abr,0),
           NVL(proy_may,0), NVL(proy_jun,0), NVL(proy_jul,0), NVL(proy_ago,0),
           NVL(proy_set,0), NVL(proy_oct,0), NVL(proy_nov,0), NVL(proy_dic,0),
           NVL(var_ene,0),  NVL(var_feb,0),  NVL(var_mar,0),  NVL(var_abr,0),
           NVL(var_may, 0), NVL(var_jun, 0), NVL(var_jul, 0), NVL(var_ago, 0),
           NVL(var_set,0),  NVL(var_oct,0),  NVL(var_nov, 0), NVL(var_dic, 0)
      INTO ln_prctg_var, ls_flag_estado, ls_flag_ctrl, ls_flag_ingr_egr,
           ln_proy_ene, ln_proy_feb, ln_proy_mar, ln_proy_abr, ln_proy_may, ln_proy_jun,
           ln_proy_jul, ln_proy_ago, ln_proy_set, ln_proy_oct, ln_proy_nov, ln_proy_dic,
           ln_var_ene, ln_var_feb, ln_var_mar, ln_var_abr, ln_var_may, ln_var_jun,
           ln_var_jul, ln_var_ago, ln_var_set, ln_var_oct, ln_var_nov, ln_var_dic
      FROM presupuesto_partida
     WHERE ano       = ln_year
       AND cencos    = asi_cencos
       AND cnta_prsp = asi_cnta_prsp ;

    If ls_flag_ctrl = '' then
       RAISE_APPLICATION_ERROR( -20000, 'Partida presupuestal no tiene Flag de Control '
               || chr(13) || 'Centro de Costo    : ' || trim(asi_cencos)
               || chr(13) || 'Cuenta Presupuestal: ' || trim(asi_cnta_prsp) );
    end if;

    IF ls_flag_estado NOT IN ('1', '2') THEN
       RAISE_APPLICATION_ERROR( -20000, 'Partida con Flag de estado Desactivado '
               || chr(13) || 'Centro de Costo    : ' || trim(asi_cencos)
               || chr(13) || 'Cuenta Presupuestal: ' || trim(asi_cnta_prsp) );
    END IF;

    ln_limite := 0 ;

    IF ls_flag_ctrl = '0' THEN
       ln_limite  := 0;
       Return(ln_limite);
    END IF;

    --=========================
    -- Total Anual
    --=========================
    IF ls_flag_ctrl = '1' THEN
       ln_limite := ln_proy_ene + ln_proy_feb + ln_proy_mar + ln_proy_abr +
                    ln_proy_may + ln_proy_jun + ln_proy_jul + ln_proy_ago +
                    ln_proy_set + ln_proy_oct + ln_proy_nov + ln_proy_dic +
                    ln_var_ene  + ln_var_feb  + ln_var_mar  + ln_var_abr +
                    ln_var_may  + ln_var_jun  + ln_var_jul  + ln_var_ago +
                    ln_var_set  + ln_var_oct  + ln_var_nov  + ln_var_dic;
    END IF ;

    --=========================
    -- Acumulado a la fecha
    --=========================
    IF ls_flag_ctrl = '2' THEN
      IF ln_mes = 1 THEN
         ln_limite := ln_proy_ene + ln_var_ene ;
      ELSIF ln_mes = 2 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb ;
      ELSIF ln_mes = 3 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar ;
      ELSIF ln_mes = 4 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr ;
      ELSIF ln_mes = 5 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may ;
      ELSIF ln_mes = 6 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun ;
      ELSIF ln_mes = 7 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul ;
      ELSIF ln_mes = 8 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul + ln_proy_ago +
                      ln_var_ago ;
      ELSIF ln_mes = 9 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul + ln_proy_ago +
                      ln_var_ago + ln_proy_set + ln_var_set ;
      ELSIF ln_mes = 10 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul + ln_proy_ago +
                      ln_var_ago + ln_proy_set + ln_var_set +
                      ln_proy_oct + ln_var_oct ;
      ELSIF ln_mes = 11 THEN
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul + ln_proy_ago +
                      ln_var_ago + ln_proy_set + ln_var_set +
                      ln_proy_oct + ln_var_oct + ln_proy_nov +
                      ln_var_nov ;
      ELSE
         ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                      ln_var_feb + ln_proy_mar + ln_var_mar +
                      ln_proy_abr + ln_var_abr + ln_proy_may +
                      ln_var_may + ln_proy_jun + ln_var_jun +
                      ln_proy_jul + ln_var_jul + ln_proy_ago +
                      ln_var_ago + ln_proy_set + ln_var_set +
                      ln_proy_oct + ln_var_oct + ln_proy_nov +
                      ln_var_nov + ln_proy_dic + ln_var_dic ;
      END IF;
    END IF ;

    --=========================
    -- Mensual
    --=========================
    IF ls_flag_ctrl = '3' THEN

       IF ln_mes = 1 THEN
          ln_limite := ln_proy_ene + ln_var_ene ;
       ELSIF ln_mes = 2 THEN
          ln_limite := ln_proy_feb + ln_var_feb ;
       ELSIF ln_mes = 3 THEN
          ln_limite := ln_proy_mar + ln_var_mar ;
       ELSIF ln_mes = 4 THEN
          ln_limite := ln_proy_abr + ln_var_abr ;
       ELSIF ln_mes = 5 THEN
          ln_limite := ln_proy_may + ln_var_may ;
       ELSIF ln_mes = 6 THEN
          ln_limite := ln_proy_jun + ln_var_jun ;
       ELSIF ln_mes = 7 THEN
          ln_limite := ln_proy_jul + ln_var_jul ;
       ELSIF ln_mes = 8 THEN
          ln_limite := ln_proy_ago + ln_var_ago ;
       ELSIF ln_mes = 9 THEN
          ln_limite :=  ln_proy_set + ln_var_set ;
       ELSIF ln_mes = 10 THEN
          ln_limite := ln_proy_oct + ln_var_oct ;
       ELSIF ln_mes = 11 THEN
          ln_limite := ln_proy_nov + ln_var_nov ;
       ELSE
          ln_limite :=  ln_proy_dic + ln_var_dic ;
       END IF;
    END IF  ;

    --======================================
    -- Ultimos 3 Meses (Trimestre Acumulado)
    --======================================
    IF ls_flag_ctrl = '4' THEN
       IF ln_mes = 1 then
          ln_limite := ln_proy_ene + ln_var_ene;
       ELSIf ln_mes = 2 then
          ln_limite := ln_proy_ene + ln_var_ene
                     + ln_proy_feb + ln_var_feb;
       ELSIF ln_mes = 3 then
           ln_limite := ln_proy_ene + ln_var_ene
                      + ln_proy_feb + ln_var_feb
                      + ln_proy_mar + ln_var_mar ;
       ELSIF ln_mes = 4 then
           ln_limite := ln_proy_feb + ln_var_feb
                      + ln_proy_mar + ln_var_mar
                      + ln_proy_abr + ln_var_abr;
       ELSIF ln_mes = 5 then
           ln_limite := ln_proy_mar + ln_var_mar
                      + ln_proy_abr + ln_var_abr
                      + ln_proy_may + ln_var_may;
       ELSIF ln_mes = 6 then
           ln_limite := ln_proy_abr + ln_var_abr
                      + ln_proy_may + ln_var_may
                      + ln_proy_jun + ln_var_jun;
       ELSIF ln_mes = 7 then
           ln_limite := ln_proy_may + ln_var_may
                      + ln_proy_jun + ln_var_jun
                      + ln_proy_jul + ln_var_jul;
       ELSIF ln_mes = 8 then
           ln_limite := ln_proy_jun + ln_var_jun
                      + ln_proy_jul + ln_var_jul
                      + ln_proy_ago + ln_var_ago;
       ELSIF ln_mes = 9 then
           ln_limite := ln_proy_jul + ln_var_jul
                      + ln_proy_ago + ln_var_ago
                      + ln_proy_set + ln_var_set;
       ELSIF ln_mes = 10 then
           ln_limite := ln_proy_ago + ln_var_ago
                      + ln_proy_set + ln_var_set
                      + ln_proy_oct + ln_var_oct;
       ELSIF ln_mes = 11 then
           ln_limite := ln_proy_set + ln_var_set
                      + ln_proy_oct + ln_var_oct
                      + ln_proy_nov + ln_var_nov;
       ELSIF ln_mes = 12 then
           ln_limite := ln_proy_oct + ln_var_oct
                      + ln_proy_nov + ln_var_nov
                      + ln_proy_dic + ln_var_dic;
       END IF;
    END IF;

    --==============================
    -- Comparacion de Disponibilidad
    --==============================
    <<Comparacion_Saldo>>

    IF ln_prctg_var > 0 THEN
       ln_limite := ln_limite * (1+ ln_prctg_var/100);
    END IF;

  return(ln_limite);
end usf_pto_prsp_var;
/

prompt
prompt Creating function USF_PTO_RANGO_INICIAL
prompt =======================================
prompt
create or replace function cantabria.USF_PTO_RANGO_INICIAL( as_delmes in char,
     as_almes in char, as_meses in char, an_ini out integer, an_fin out integer)
  return integer is
  Result integer;

  ln_veces    number;
  ln_del      number;
  ln_al       number;
  ln_cont     number;
begin

  ln_del := TO_NUMBER( as_delmes);
  ln_al  := TO_NUMBER( as_almes);

  -- Encuentra posicion de inicio
  ln_veces := 0;
  if ln_del = 1 and ln_al = 1 then
     an_ini := 1;
     an_fin := 3;
  else
      if ln_del = 1 then
         an_ini := 1;
      else
         ln_cont := 1;
         For j in 1..50 loop
            if SUBSTR( as_meses, ln_cont,1) = ',' then
               ln_veces := ln_veces + 1;
            end if;
            if ln_veces = ln_del - 1 then
               an_ini := ln_cont + 1;
               exit;
            end if;
            ln_cont := ln_cont + 1;
         end loop;
      end if;
      -- Encuentra posicion final
      ln_veces := 0;
      if ln_al = 12 then
         an_fin := 47;
      else
         ln_cont := 1;
         For j in 1..50 loop
            if SUBSTR( as_meses, ln_cont,1) = ',' then
               ln_veces := ln_veces + 1;
            end if;
            if ln_veces =  ln_al - 1 then
               an_fin := (ln_cont + 4) - an_ini;
               exit;
            end if;
            ln_cont := ln_cont + 1;
         end loop;
      end if;
  end if;

  return(Result);
end USF_PTO_RANGO_INICIAL;
/

prompt
prompt Creating function USF_PTO_RANGO_INI_FIN
prompt =======================================
prompt
create or replace function cantabria.USF_PTO_RANGO_INI_FIN( as_delmes in char,
     as_almes in char, as_meses in char, an_ini out integer, an_fin out integer)
  return integer is
  Result integer;

-- Determina la posicion inicial y final de una cadena

  ln_veces    number;
  ln_del      number;
  ln_al       number;
  ln_cont     number;
begin

  ln_del := TO_NUMBER( as_delmes);
  ln_al  := TO_NUMBER( as_almes);

  -- Encuentra posicion de inicio
  ln_veces := 0;
  if ln_del = 1 and ln_al = 1 then
     an_ini := 1;
     an_fin := 3;
  else
      if ln_del = 1 then
         an_ini := 1;
      else
         ln_cont := 1;
         For j in 1..50 loop
            if SUBSTR( as_meses, ln_cont,1) = ',' then
               ln_veces := ln_veces + 1;
            end if;
            if ln_veces = ln_del - 1 then
               an_ini := ln_cont + 1;
               exit;
            end if;
            ln_cont := ln_cont + 1;
         end loop;
      end if;
      -- Encuentra posicion final
      ln_veces := 0;
      if ln_al = 12 then
         an_fin := 47;
      else
         ln_cont := 1;
         For j in 1..50 loop
            if SUBSTR( as_meses, ln_cont,1) = ',' then
               ln_veces := ln_veces + 1;
            end if;
            if ln_veces =  ln_al - 1 then
               an_fin := (ln_cont + 4) - an_ini;
               exit;
            end if;
            ln_cont := ln_cont + 1;
         end loop;
      end if;
  end if;

  return(Result);
end USF_PTO_RANGO_INI_FIN;
/

prompt
prompt Creating function USF_PTO_RANGOS
prompt ================================
prompt
create or replace function cantabria.USF_PTO_RANGOS( as_cencos1 in char,
   as_cencos2 in char, as_cencos3 in char, as_cencos4 in char,
   as_cnta1 in char, as_cnta2 in char, as_cnta3 in char,
   as_cnta4 in char, as_modo in char, as_delmes in char,
   as_almes in char, an_ano in number ) return number is

  Result        number;
  ls_CursorId   integer;
  ls_select     varchar2(500);
  ls_meses      varchar2(200);
  ln_ini        integer;
  ln_fin        integer;

  ln_total      number;
  v_ret         number;
  ln_ret        number;
begin

  ls_meses := 'ene,feb,mar,abr,may,jun,jul,ago,set,oct,nov,dic,';
  ln_ret := USF_pto_rango_ini_fin(as_delmes, as_almes, ls_meses, ln_ini, ln_fin);

  ls_meses := SUBSTR( ls_meses, ln_ini, ln_fin + 1);

  ls_Cursorid := DBMS_SQL.OPEN_CURSOR;
  -- Arma el select
  ln_ini := 1;
  ls_select := 'SELECT SUM(';
  For j in 1..50 loop
      if SUBSTR( ls_meses, j,1) = ',' then
         if ln_ini <> 1 then
            ls_select := ls_select || ' + ';
         end if;
         ls_select := ls_select || 'proy_' || SUBSTR( ls_meses, ln_ini, j - ln_ini);
         ln_ini := j + 1;
      end if;
  End loop;

  IF as_modo = '1_1' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC, centros_costo cc  ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND pe.cencos = cc.cencos and ' ||
                  ' pe.ano = :m1 and cc.cod_n1 = :m2 and PC.NIV1 = :m3 ';
  END IF;
  IF as_modo = '1_2' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC, centros_costo cc  ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND pe.cencos = cc.cencos and ' ||
                  ' pe.ano = :m1 and cc.cod_n1 = :m2 and PC.NIV1 = :m3 AND ' ||
                  ' PC.NIV2 = :m4 ' ;
  END IF;
  IF as_modo = '1_3' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC, centros_costo cc  ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND pe.cencos = cc.cencos and ' ||
                  ' pe.ano = :m1 and cc.cod_n1 = :m2 and PC.NIV1 = :m3 AND ' ||
                  ' PC.NIV2 = :m4 and pc.niv3 = :m5' ;
  END IF;
  IF as_modo = '1_4' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, centros_costo cc  ' ||
                  ' WHERE pe.cencos = cc.cencos and ' ||
                  ' pe.ano = :m1 and cc.cod_n1 = :m2 and pe.cnta_prsp = :m3';
  END IF;

  IF as_modo = '2_1' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC, centros_costo cc  ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND pe.cencos = cc.cencos and ' ||
                  ' pe.ano = :m1 and cc.cod_n1 = :m2 and cc.cod_n2 = :m3  and PC.NIV1 = :m4';
  END IF;
  IF as_modo = '2_2' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC, centros_costo cc  ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND pe.cencos = cc.cencos and ' ||
                  ' pe.ano = :m1 and cc.cod_n1 = :m2 and cc.cod_n2 = :m3 and  ' ||
                  ' PC.NIV1 = :m4 AND PC.NIV2 = :m5 ' ;
  END IF;
  IF as_modo = '2_3' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC, centros_costo cc  ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND pe.cencos = cc.cencos and ' ||
                  ' pe.ano = :m1 and cc.cod_n1 = :m2 and cc.cod_n2 = :m3 and ' ||
                  ' PC.NIV1 = :m4 AND PC.NIV2 = :m5 and pc.niv3 = :m6' ;
  END IF;
  IF as_modo = '2_4' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, centros_costo cc  ' ||
                  ' WHERE pe.cencos = cc.cencos and pe.ano = :m1 and ' ||
                  ' cc.cod_n1 = :m2 and cc.cod_n2 = :m3  and pe.cnta_prsp = :m4';
  END IF;

  IF as_modo = '3_1' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC, centros_costo cc  ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND pe.cencos = cc.cencos and ' ||
                  ' pe.ano = :m1 and cc.cod_n1 = :m2 and cc.cod_n2 = :m3  and ' ||
                  ' cc.cod_n3 = :m4 and PC.NIV1 = :m5';
  END IF;
  IF as_modo = '3_2' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC, centros_costo cc  ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND pe.cencos = cc.cencos and ' ||
                  ' pe.ano = :m1 and cc.cod_n1 = :m2 and cc.cod_n2 = :m3 and  ' ||
                  ' cc.cod_n3 = :m4 and PC.NIV1 = :m5 AND PC.NIV2 = :m6 ' ;
  END IF;
  IF as_modo = '3_3' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC, centros_costo cc  ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND pe.cencos = cc.cencos and ' ||
                  ' pe.ano = :m1 and cc.cod_n1 = :m2 and cc.cod_n2 = :m3 and ' ||
                  ' cc.cod_n3 = :m4 and PC.NIV1 = :m5 AND PC.NIV2 = :m6 and pc.niv3 = :m7';
  END IF;
  IF as_modo = '3_4' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, centros_costo cc  ' ||
                  ' WHERE pe.cencos = cc.cencos and pe.ano = :m1 and ' ||
                  ' cc.cod_n1 = :m2 and cc.cod_n2 = :m3 and cc.cod_n3 = :m4 and ' ||
                  ' pe.cnta_prsp = :m5';
  END IF;

  IF as_modo = '4_1' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND ' ||
                  ' pe.ano = :m1 and pe.cencos = :m2 and PC.NIV1 = :m3';
  END IF;
  IF as_modo = '4_2' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND ' ||
                  ' pe.ano = :m1 and pe.cencos = :m2 and PC.NIV1 = :m3 AND PC.NIV2 = :m4' ;
  END IF;
  IF as_modo = '4_3' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE, PRESUPUESTO_CUENTA PC ' ||
                  ' WHERE PE.CNTA_PRSP = PC.CNTA_PRSP AND  ' ||
                  ' pe.ano = :m1 and pe.cencos = :m2 and PC.NIV1 = :m3 AND ' ||
                  ' PC.NIV2 = :m4 and pc.niv3 = :m5';
  END IF;
  IF as_modo = '4_4' then
     ls_select := ls_select || ') FROM PRESUPUESTO_PARTIDA PE ' ||
                  ' WHERE pe.ano = :m1 and  pe.cencos = :m2 and ' ||
                  ' pe.cnta_prsp = :m3';
  END IF;

  DBMS_SQL.PARSE( ls_cursorId, ls_select, DBMS_SQL.V7);

  -- Acopla variables
  DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m1', an_ano);
  IF as_modo = '1_1' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cnta1);
  END IF;
  IF as_modo = '1_2' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cnta1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cnta2);
  END IF;
  IF as_modo = '1_3' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cnta1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cnta2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m5', as_cnta3);
  END IF;
  IF as_modo = '1_4' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cnta4);
  END IF;

  IF as_modo = '2_1' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cencos2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cnta1);
  END IF;
  IF as_modo = '2_2' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cencos2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cnta1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m5', as_cnta2);
  END IF;
  IF as_modo = '2_3' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cencos2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cnta1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m5', as_cnta2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m6', as_cnta3);
  END IF;
  IF as_modo = '2_4' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cencos2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cnta4);
  END IF;

  IF as_modo = '3_1' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cencos2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cencos3);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m5', as_cnta1);
  END IF;
  IF as_modo = '3_2' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cencos2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cencos3);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m5', as_cnta1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m6', as_cnta2);
  END IF;
  IF as_modo = '3_3' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cencos2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cencos3);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m5', as_cnta1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m6', as_cnta2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m7', as_cnta3);
  END IF;
  IF as_modo = '3_4' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cencos2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cencos3);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m5', as_cnta4);
  END IF;

  IF as_modo = '4_1' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos4);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cnta1);
  END IF;
  IF as_modo = '4_2' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos4);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cnta1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cnta2);
  END IF;
  IF as_modo = '4_3' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos4);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cnta1);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m4', as_cnta2);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m5', as_cnta3);
  END IF;
  IF as_modo = '4_4' then
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m2', as_cencos4);
     DBMS_SQL.BIND_VARIABLE( ls_cursorid, ':m3', as_cnta4);
  END IF;
  -- Define variable de salida
  DBMS_SQL.DEFINE_COLUMN( ls_cursorid,1, ln_total);

  -- Ejecuta cursor
  v_ret := DBMS_SQL.EXECUTE( ls_cursorid);

  LOOP
     IF DBMS_SQL.FETCH_ROWS( ls_cursorid) = 0 then
        EXIT;
     END IF;
     -- Recupero informacion del cursor
     DBMS_SQL.COLUMN_VALUE( ls_cursorid,1, ln_total);
  END LOOP;
  DBMS_SQL.CLOSE_CURSOR(ls_cursorid);

  return(ln_total);
end USF_PTO_RANGOS;
/

prompt
prompt Creating function USF_PTO_SALDO_ACTUAL
prompt ======================================
prompt
create or replace function cantabria.USF_PTO_SALDO_ACTUAL(
    an_mes        in cntbl_asiento.mes%type,
    an_ano        in cntbl_asiento.ano%TYPE,
    as_cencos     in centros_costo.cencos%type,
    as_cnta_prsp  in presupuesto_cuenta.cnta_prsp%TYPE
)return number is

  -- Retorna saldo actual. Los que son sin control, retorna 0
  ln_reg         number;  -- Guarda numero de registro
  ln_ctrl        presupuesto_partida.flag_ctrl%type;
  ln_var         presupuesto_partida.prctg_var%type;
  ln_return      number;
begin

  ln_return := 0 ;

  -- Busca si existe partida, caso contrario devuelve error
  Select Count( cencos) into ln_reg from presupuesto_partida
    Where ano = an_ano and cencos = as_cencos
          and cnta_prsp = as_cnta_prsp and flag_ingr_egr = 'E';

 -- raise_application_error( -20000, an_ano ||' ' || as_cencos || ' ' || as_cnta_prsp);
  if ln_reg = 0 then  -- No existe partida
    --ln_return := -1;
    RAISE_APPLICATION_ERROR( -20000, 'No existe Partida presupuestal '||
      'para ' || as_cencos || ', ' || as_cnta_prsp || ', ano' || an_ano ) ;
     return 0;
  end if;

  -- Evalua si tiene presupuesto segun flag de control
  -- Segun Partida presupuestal, halla la forma de procesar
  Select p.flag_ctrl, p.prctg_var into ln_ctrl, ln_var
    from presupuesto_partida p
    where p.ano = an_ano and p.cencos = as_cencos and
    p.cnta_prsp = as_cnta_prsp;

  -- Evalua que partida tenga flag de control
  if ln_ctrl is null then
     raise_application_error( -20004, ln_ctrl);
     return 0;
  end if;

  --==========================
   -- Sin control
  --==========================
  if ln_ctrl = 0 then
      return ln_return ;
  end if;
  --==========================
  -- Acumulado Anual
  --==========================
  if ln_ctrl = 1 then
     ln_return := usf_pto_sldo_acumulado_anual(an_ano, as_cencos, as_cnta_prsp);
  end if;

  --==========================
  -- Acumulado a la Fecha
  --==========================
  if ln_ctrl = 2 then
     ln_return := usf_pto_sldo_acumulado_fecha(an_ano, an_mes, as_cencos, as_cnta_prsp);
  end if;

  --==========================
  -- Mensual
  --==========================
  if ln_ctrl = 3 then
     ln_return := usf_pto_sldo_mensual(an_ano, an_mes, as_cencos, as_cnta_prsp);
  end if;

  --==========================
  -- Ultimo Trimestre Acumulado
  --==========================
  if ln_ctrl = 4 then
     ln_return := usf_pto_sldo_trimestre(an_ano, an_mes, as_cencos, as_cnta_prsp);
  end if;

  --==========================
  -- Trimestre Centrado
  --==========================
  if ln_ctrl = 5 then
     ln_return := usf_pto_sldo_semestre(an_ano, an_mes, as_cencos, as_cnta_prsp);
  end if;

  -- Aplica porcentaje de variabilidad
  if NVL(ln_var,0) > 0 THEN
     ln_return := ln_return * ( 1 + (ln_var/100) );
  elsif NVL(ln_var,0) < 0 THEN
     ln_return := ln_return * ( 1 - (ln_var/100));
  END IF;

  return ln_return;

END USF_PTO_SALDO_ACTUAL;
/

prompt
prompt Creating function USF_PTO_SELECTS_OTS
prompt =====================================
prompt
create or replace function cantabria.usf_pto_selects_ots(
       asi_nada in varchar2
) return varchar2 is

  cursor c_selec is
  select tipo_doc || nro_doc as doc
  from tt_pto_selec_ots;

  ls_Result varchar2(1000);
begin

  ls_result := '';

  for rc1 in c_selec loop
      ls_result := ls_result || rc1.doc;
  end loop;

  if length(ls_result) > 0 then
     ls_result := substr(ls_result, 1,length(ls_result) -1);
  end if;

  return(ls_Result);
end usf_pto_selects_ots;
/

