prompt
prompt Creating function USF_PTO_SLDO_PRT_PRSP
prompt =======================================
prompt
create or replace function cantabria.USF_PTO_SLDO_PRT_PRSP(
       ani_year            in number,
       ani_mes             in number,
       asi_cencos          in centros_costo.cencos%TYPE,
       asi_cnta_prsp       in presupuesto_cuenta.cnta_prsp%TYPE
) return number is
  ln_Return     number;
  ln_count      number;
  ls_flag_cntrl presupuesto_partida.flag_ctrl%TYPE;
begin
  select count(*)
    into ln_count
    from presupuesto_partida pp
   where pp.ano       = ani_year
     and pp.cencos    = asi_cencos
     and pp.cnta_prsp = asi_cnta_prsp
     and NVL(pp.flag_estado, '0') <> '0';

  if ln_count = 0 then
     RAISE_APPLICATION_ERROR(-20000, 'No existe partida presupuestal'
                       || chr(13) || 'A?o: ' || to_char(ani_year)
                       || chr(13) || 'Cencos: ' || asi_cencos
                       || chr(13) || 'Cnta_prsp: ' || asi_cnta_prsp);
  end if;

  select flag_ctrl
    into ls_flag_cntrl
    from presupuesto_partida pp
   where pp.ano       = ani_year
     and pp.cencos    = asi_cencos
     and pp.cnta_prsp = asi_cnta_prsp
     and NVL(pp.flag_estado, '0') <> '0';

  ln_return := 0;

  --==========================
  -- Acumulado Anual
  --==========================
  if ls_flag_cntrl = '1' then
     ln_return := usf_pto_sldo_acumulado_anual(ani_year, asi_cencos, asi_cnta_prsp);
  end if;

  --==========================
  -- Acumulado a la Fecha
  --==========================
  if ls_flag_cntrl = 2 then
     ln_return := usf_pto_sldo_acumulado_fecha(ani_year, ani_mes, asi_cencos, asi_cnta_prsp);
  end if;

  --==========================
  -- Mensual
  --==========================
  if ls_flag_cntrl = 3 then
     ln_return := usf_pto_sldo_mensual(ani_year, ani_mes, asi_cencos, asi_cnta_prsp);
  end if;

  --==========================
  -- Ultimo Trimestre Acumulado
  --==========================
  if ls_flag_cntrl = 4 then
     ln_return := usf_pto_sldo_trimestre(ani_year, ani_mes, asi_cencos, asi_cnta_prsp);
  end if;

  --==========================
  -- Trimestre Centrado
  --==========================
  if ls_flag_cntrl = 5 then
     ln_return := usf_pto_sldo_semestre(ani_year, ani_mes, asi_cencos, asi_cnta_prsp);
  end if;

  return(ln_Return);
end USF_PTO_SLDO_PRT_PRSP;
/

