prompt Creating function USF_PTO_SLDO_REST_X_TIPO
prompt ==========================================
prompt
create or replace function cantabria.USF_PTO_SLDO_REST_X_TIPO(
    an_ano in number, an_mes_ini in number, an_mes_fin in number, as_cencos in char,
    as_cnta_prsp in char )
 Return number is
 Result number;
begin

if an_mes_fin = 1 then
   Select NVL(p.proy_feb,0) + NVL(p.proy_mar,0) + NVL(p.proy_abr,0) + NVL(p.proy_may,0) +
          NVL(p.proy_jun,0) + NVL(p.proy_jul,0) + NVL(p.proy_ago,0) + NVL(p.proy_set,0) +
          NVL(p.proy_oct,0) + NVL(p.proy_nov,0) + NVL(p.proy_dic,0)
     into result
     from presupuesto_partida p
    Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 2 then
   Select NVL(p.proy_mar,0) + NVL(p.proy_abr,0) + NVL(p.proy_may,0) + NVL(p.proy_jun,0) +
          NVL(p.proy_jul,0) + NVL(p.proy_ago,0) + NVL(p.proy_set,0) + NVL(p.proy_oct,0) +
          NVL(p.proy_nov,0) + NVL(p.proy_dic,0)
     into result
     from presupuesto_partida p
    Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 3 then
   Select NVL(p.proy_abr,0) + NVL(p.proy_may,0) + NVL(p.proy_jun,0) + NVL(p.proy_jul,0) +
          NVL(p.proy_ago,0) + NVL(p.proy_set,0) + NVL(p.proy_oct,0) + NVL(p.proy_nov,0) +
          NVL(p.proy_dic,0)
     into result
     from presupuesto_partida p
    Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 4 then
  Select NVL(p.proy_may,0) + NVL(p.proy_jun,0) + NVL(p.proy_jul,0) + NVL(p.proy_ago,0) +
         NVL(p.proy_set,0) + NVL(p.proy_oct,0) + NVL(p.proy_nov,0) + NVL(p.proy_dic,0)
    into result
    from presupuesto_partida p
   Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 5 then
  Select NVL(p.proy_jun,0) + NVL(p.proy_jul,0) + NVL(p.proy_ago,0) + NVL(p.proy_set,0) +
         NVL(p.proy_oct,0) + NVL(p.proy_nov,0) + NVL(p.proy_dic,0)
    into result
    from presupuesto_partida p
   Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 6 then
  Select NVL(p.proy_jul,0) + NVL(p.proy_ago,0) + NVL(p.proy_set,0) + NVL(p.proy_oct,0) +
         NVL(p.proy_nov,0) + NVL(p.proy_dic,0)
    into result
    from presupuesto_partida p
   Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 7 then
  Select NVL(p.proy_ago,0) + NVL(p.proy_set,0) + NVL(p.proy_oct,0) + NVL(p.proy_nov,0) +
         NVL(p.proy_dic,0)
       into result
       from presupuesto_partida p
      Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 8 then
  Select NVL(p.proy_set,0) + NVL(p.proy_oct,0) + NVL(p.proy_nov,0) + NVL(p.proy_dic,0)
       into result
       from presupuesto_partida p
      Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 9 then
  Select NVL(p.proy_oct,0) + NVL(p.proy_nov,0) + NVL(p.proy_dic,0)
    into result
    from presupuesto_partida p
   Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 10 then
  Select NVL(p.proy_nov,0) + NVL(p.proy_dic,0)
    into result
    from presupuesto_partida p
   Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 11 then
  Select NVL(p.proy_dic,0)
    into result
    from presupuesto_partida p
   Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
elsif an_mes_fin = 12 then
   result := 0 ;
end if;

  return(Result);
end USF_PTO_SLDO_REST_X_TIPO;
/

