     an_ano in number, an_mes in number, as_cencos in char, as_cnta_prsp in char)
    return number is
  Result number;
begin

  if an_mes = 1 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) ) +
               (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) ) +
               (NVL(p.var_ene,0)  + NVL( p.var_feb,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 2 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0)) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 3 then
     Select ( NVL( p.proy_feb,0) + NVL( p.proy_mar,0) + NVL(p.proy_abr,0) ) +
            ( NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) + NVL(p.ejec_abr,0) ) +
            ( NVL( p.var_feb,0) + NVL( p.var_mar,0) + NVL(p.var_abr,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 4 then
     Select (NVL( p.proy_mar,0) + NVL(p.proy_abr,0) + NVL( p.proy_may,0) ) +
            (NVL( p.ejec_mar,0) + NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) ) +
            (NVL( p.var_mar,0) + NVL(p.var_abr,0) + NVL( p.var_may,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 5 then
     Select (NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) ) +
            (NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) ) +
            (NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) )
      into result
      from presupuesto_partida p
      Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 6 then
     Select (NVL( p.proy_may,0) + NVL( p.proy_jun,0) + NVL(p.proy_jul,0) ) +
            (NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) + NVL(p.ejec_jul,0) ) +
            (NVL( p.var_may,0) + NVL( p.var_jun,0) + NVL(p.var_jul,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 7 then
     Select (NVL( p.proy_jun,0) + NVL(p.proy_jul,0) + NVL( p.proy_ago,0) ) +
            (NVL( p.ejec_jun,0) + NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) ) +
            (NVL( p.var_jun,0) + NVL(p.var_jul,0) + NVL( p.var_ago,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 8 then
     Select (NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) ) +
            (NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) ) +
            (NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 9 then
     Select (NVL( p.proy_ago,0) + NVL( p.proy_set,0) + NVL(p.proy_oct,0) ) +
            (NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) + NVL(p.ejec_oct,0) ) +
            (NVL( p.var_ago,0) + NVL( p.var_set,0) + NVL(p.var_oct,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 10 then
     Select (NVL( p.proy_set,0) + NVL(p.proy_oct,0) + NVL( p.proy_nov,0) ) +
            (NVL( p.ejec_set,0) + NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) ) +
            (NVL( p.var_set,0) + NVL(p.var_oct,0) + NVL( p.var_nov,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 11 then
     Select (NVL(p.proy_oct,0) + NVL( p.proy_nov,0) + NVL( p.proy_dic,0) ) +
            (NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0) ) +
            (NVL(p.var_oct,0) + NVL( p.var_nov,0) + NVL( p.var_dic,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 12 then
     Select (NVL( p.proy_nov,0) + NVL( p.proy_dic,0) ) +
            (NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0) ) +
            (NVL( p.var_nov,0) + NVL( p.var_dic,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if ;

  return(Result);
end USF_PTO_SLDO_TRIM_CENTRADO;
