  elsif an_mes_fin = 12 then
     Select (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
            NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
            NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
            NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0))
       into result
       from presupuesto_partida p
      Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;

END IF ;

-- Saldos
IF as_flag_tipo='S' then
  if an_mes_fin = 1 then
     Select NVL(p.proy_ene,0) + NVL(p.ejec_ene,0) + NVL(p.var_ene,0)
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 2 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) ) +
               (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) ) +
               (NVL(p.var_ene,0)  + NVL( p.var_feb,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 3 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0)) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 4 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 5 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) )
      into result
      from presupuesto_partida p
      Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 6 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 7 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 8 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 9 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 10 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
        NVL(p.proy_oct,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
        NVL(p.ejec_oct,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) +
        NVL(p.var_oct,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 11 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
        NVL(p.proy_oct,0) + NVL( p.proy_nov,0) ) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
        NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) ) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) +
        NVL(p.var_oct,0) + NVL( p.var_nov,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  elsif an_mes_fin = 12 then
     Select (NVL(p.proy_ene,0) + NVL( p.proy_feb,0) + NVL( p.proy_mar,0) +
        NVL(p.proy_abr,0) + NVL( p.proy_may,0) + NVL( p.proy_jun,0) +
        NVL(p.proy_jul,0) + NVL( p.proy_ago,0) + NVL( p.proy_set,0) +
        NVL(p.proy_oct,0) + NVL( p.proy_nov,0) + NVL( p.proy_dic,0)) +
        (NVL(p.ejec_ene,0) + NVL( p.ejec_feb,0) + NVL( p.ejec_mar,0) +
        NVL(p.ejec_abr,0) + NVL( p.ejec_may,0) + NVL( p.ejec_jun,0) +
        NVL(p.ejec_jul,0) + NVL( p.ejec_ago,0) + NVL( p.ejec_set,0) +
        NVL(p.ejec_oct,0) + NVL( p.ejec_nov,0) + NVL( p.ejec_dic,0)) +
        (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) +
        NVL(p.var_oct,0) + NVL( p.var_nov,0) + NVL( p.var_dic,0))
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
END IF ;

  return(Result);
end USF_PTO_VARIAC_ACUM;
/

prompt
prompt Creating function USF_PTO_VARIACION_ACUMULADO
prompt =============================================
prompt
create or replace function cantabria.USF_PTO_VARIACION_ACUMULADO(
   an_ano in number, an_mes in number, as_cencos in char, as_cnta_prsp in char)
     return number is
  Result number;
begin

  --==========================
  -- Variacion Acumulada
  --==========================
  if an_mes = 1 then
     Select NVL(p.var_ene,0)
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 2 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 3 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0))
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 4 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 5 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) )
      into result
      from presupuesto_partida p
      Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 6 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 7 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 8 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 9 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
     end if;
  if an_mes = 10 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) +
        NVL(p.var_oct,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 11 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) +
        NVL(p.var_oct,0) + NVL( p.var_nov,0) )
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if;
  if an_mes = 12 then
     Select (NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
        NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
        NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) +
        NVL(p.var_oct,0) + NVL( p.var_nov,0) + NVL( p.var_dic,0))
        into result
        from presupuesto_partida p
        Where ano = an_ano and cencos = as_cencos and cnta_prsp = as_cnta_prsp;
  end if ;
  return(Result);
end USF_PTO_VARIACION_ACUMULADO;
/

prompt
prompt Creating function USF_PTO_VARIACION_ANUAL
prompt =========================================
prompt
create or replace function cantabria.USF_PTO_VARIACION_ANUAL(
   ani_year       in number,
   asi_cencos     in centros_costo.cencos%TYPE,
   asi_cnta_prsp  in presupuesto_cuenta.cnta_prsp%TYPE
)return number is
  ln_Result number;
begin

 --==========================
  -- Variacion Acumulada Anual
  --==========================
  Select NVL(p.var_ene,0) + NVL( p.var_feb,0) + NVL( p.var_mar,0) +
         NVL(p.var_abr,0) + NVL( p.var_may,0) + NVL( p.var_jun,0) +
         NVL(p.var_jul,0) + NVL( p.var_ago,0) + NVL( p.var_set,0) +
         NVL(p.var_oct,0) + NVL( p.var_nov,0) + NVL( p.var_dic,0)
    into ln_Result
    from presupuesto_partida p
   Where ano       = ani_year
     and cencos    = asi_cencos
     and cnta_prsp = asi_cnta_prsp;

  return(NVL(ln_Result,0));
end USF_PTO_VARIACION_ANUAL;
/

prompt
prompt Creating function USF_PTO_VARIACION_MENSUAL
prompt ===========================================
prompt
create or replace function cantabria.USF_PTO_VARIACION_MENSUAL (
       ani_year      in number,
       ani_mes       in number,
       asi_cencos    in centros_costo.cencos%TYPE,
       asi_cnta_prsp in presupuesto_cuenta.cnta_prsp%TYPE
) return number is

/*
  funcion que devuelve la variacion de un mes dado
*/
  -- Declaracion de variables
  ln_variac      number;    -- importe de ejecucion

begin
    if ani_mes = 1 then

       SELECT NVL(var_ene,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano      = ani_year
           and cencos   = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 2 then

       SELECT NVL(var_feb,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 3 then

       SELECT NVL(var_mar,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 4 then

       SELECT NVL(var_abr,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 5 then

       SELECT NVL(var_may,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 6 then

       SELECT NVL(var_jun,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
            and ano = ani_year
            and cencos = asi_cencos
            and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 7 then

       SELECT NVL(var_jul,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 8 then

       SELECT NVL(var_ago,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 9 then

       SELECT NVL(var_set,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 10 then

       SELECT NVL(var_oct,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 11 then

       SELECT NVL(var_nov,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;

    elsif ani_mes = 12 then

       SELECT NVL(var_dic,0)
         into ln_variac
         FROM presupuesto_partida p
         WHERE flag_estado <> '0'
           and ano = ani_year
           and cencos = asi_cencos
           and cnta_prsp = asi_cnta_prsp;
    end if;

  return(ln_variac);
end USF_PTO_VARIACION_MENSUAL;
/

prompt
prompt Creating function USF_PTO_VARIACION_PERIODO
prompt ===========================================
prompt
create or replace function cantabria.USF_PTO_VARIACION_PERIODO(
       ani_year       in number,
       asi_cencos     in centros_costo.cencos%TYPE,
       asi_cnta_prsp  in presupuesto_cuenta.cnta_prsp%TYPE,
       ln_mes1        in number,
       ln_mes2        in number
) return number is
  ln_Result number;
begin

select CASE when 1 >= ln_mes1 and 1 <= ln_mes2 THEN
				    var_ene
			 ELSE
				    0
			 END +
       CASE when 2 >= ln_mes1 and 2 <= ln_mes2 THEN
				    pp.var_feb
			 ELSE
				    0
			 END +
       CASE when 3 >= ln_mes1 and 3 <= ln_mes2 THEN
				    pp.var_mar
			 ELSE
				    0
			 END +
       CASE when 4 >= ln_mes1 and 4 <= ln_mes2 THEN
				    pp.var_abr
			 ELSE
				    0
			 END +
       CASE when 5 >= ln_mes1 and 5 <= ln_mes2 THEN
				    pp.var_may
			 ELSE
				    0
			 END +
       CASE when 6 >= ln_mes1 and 6 <= ln_mes2 THEN
				    pp.var_jun
			 ELSE
				    0
			 END +
       CASE when 7 >= ln_mes1 and 7 <= ln_mes2 THEN
				    pp.var_jul
			 ELSE
				    0
			 END +
       CASE when 8 >= ln_mes1 and 8 <= ln_mes2 THEN
				    pp.var_ago
			 ELSE
				    0
			 END +
       CASE when 9 >= ln_mes1 and 9 <= ln_mes2 THEN
				    pp.var_set
			 ELSE
				    0
			 END +
       CASE when 10 >= ln_mes1 and 10 <= ln_mes2 THEN
				    pp.var_oct
			 ELSE
				    0
			 END +
       CASE when 11 >= ln_mes1 and 11 <= ln_mes2 THEN
				    pp.var_nov
			 ELSE
				    0
			 END +
       CASE when 12 >= ln_mes1 and 12 <= ln_mes2 THEN
				    pp.var_dic
			 ELSE
				    0
			 END
  into ln_Result
  from presupuesto_partida pp
 where pp.ano = ani_year
   and pp.cencos = asi_cencos
   and pp.cnta_prsp = asi_cnta_prsp;

  return(ln_Result);
end USF_PTO_VARIACION_PERIODO;
/

prompt
prompt Creating function USF_PTO_VERIFICA_PARTIDA
prompt ==========================================
prompt
create or replace function cantabria.USF_PTO_VERIFICA_PARTIDA(
    ani_mes       in number,
    ani_ano       in number,
    asi_cencos    in centros_costo.cencos%TYPE,
    asi_cnta_prsp in presupuesto_cuenta.cnta_prsp%TYPE,
    ani_importe   in number
) return number is

  ln_reg         number;  -- Guarda numero de registro
  ln_ctrl        presupuesto_partida.flag_ctrl%type;
  ln_total_pto   number;
  ln_var         presupuesto_partida.prctg_var%type;
  ln_return      number;
begin
  -- Busca si existe partida, caso contrario devuelve error
  Select Count( cencos)
    into ln_reg
    from presupuesto_partida
   Where ano = ani_ano
     and cencos = asi_cencos
     and cnta_prsp = asi_cnta_prsp
     and flag_ingr_egr = 'E';

 -- raise_application_error( -20000, an_ano ||' ' || as_cencos || ' ' || as_cnta_prsp);
  if ln_reg = 0 then  -- No existe partida
     RAISE_APPLICATION_ERROR( -20000, 'No existe Partida presupuestal '||
       'para ' || asi_cencos || ', ' || asi_cnta_prsp || ', ano' || ani_ano ) ;
     return 0;
  end if;

  -- Evalua si tiene presupuesto segun flag de control
  -- Segun Partida presupuestal, halla la forma de procesar
  Select p.flag_ctrl, p.prctg_var
    into ln_ctrl, ln_var
    from presupuesto_partida p
   where p.ano = ani_ano
     and p.cencos = asi_cencos
     AND p.cnta_prsp = asi_cnta_prsp;

  -- Evalua que partida tenga flag de control
  if ln_ctrl is null then
     raise_application_error( -20004, ln_ctrl);
     return 0;
  end if;

  if ln_ctrl = 0 then   -- Sin control
     return 1;
  end if;

--  raise_application_error( -20000, ln_ctrl);
  ln_return := 1;
  IF NVL(ani_importe,0) >= 0 THEN
     --==========================
     -- Acumulado Anual
     --==========================
     if ln_ctrl = 1 then
        ln_total_pto := usf_pto_sldo_acumulado_anual(ani_ano, asi_cencos, asi_cnta_prsp);
     end if;

    --==========================
    -- Acumulado a la Fecha
    --==========================
    if ln_ctrl = 2 then
       ln_total_pto := usf_pto_sldo_acumulado_fecha(ani_ano, ani_mes, asi_cencos, asi_cnta_prsp);
    end if;

    --==========================
    -- Mensual
    --==========================
    if ln_ctrl = 3 then
       ln_total_pto := usf_pto_sldo_mensual(ani_ano, ani_mes, asi_cencos, asi_cnta_prsp);
    end if;

    --==========================
    -- Ultimo Trimestre Acumulado
    --==========================
    if ln_ctrl = 4 then
       ln_total_pto := usf_pto_sldo_trimestre(ani_ano, ani_mes, asi_cencos, asi_cnta_prsp);
    end if;

    --==========================
    -- Trimestre Centrado
    --==========================
    if ln_ctrl = 5 then
       ln_total_pto := usf_pto_sldo_semestre(ani_ano, ani_mes, asi_cencos, asi_cnta_prsp);
    end if;

    -- Aplica porcentaje de variabilidad
    if NVL(ln_var,0) > 0 THEN
       ln_total_pto := ln_total_pto + (ln_total_pto * (ln_var/100));
    elsif NVL(ln_var,0) < 0 THEN
       ln_total_pto := ln_total_pto - (ln_total_pto * (ln_var/100));
    END IF;

    IF NVL( ln_total_pto,0) = 0 and ln_ctrl > 0 then
       RAISE_APPLICATION_ERROR( -20002, 'No tiene saldo en presupuesto' ) ;
       ln_return := 0;
    end if;

    IF NVL(ln_total_pto,0) < NVL(ani_importe,0) then
       RAISE_APPLICATION_ERROR( -20001, 'Excede la Partida presupuestal '||
                                'de: ' || asi_cencos || ', ' || asi_cnta_prsp
                                || ' Saldo Actual: ' || ln_total_pto) ;
       ln_return := 0;
    END IF;
  END IF ;
  return ln_return;
end USF_PTO_VERIFICA_PARTIDA;
/

prompt
prompt Creating function USF_PTX_BALANZA
prompt =================================
prompt
create or replace function cantabria.usf_ptx_balanza (
  ad_fec_proceso in date, as_formula in char ) return number is

ln_verifica        integer ;
ls_cod_articulo    varchar2(20) ;
ad_fec_desde       date ;
ad_fec_hasta       date ;
ln_valor           number(13,3) ;

begin

--  *****************************************************
--  ***   CAPTURA INFORMACION DEL MODULO DE BALANZA   ***
--  *****************************************************

ls_cod_articulo := null ;
for x in 1 .. length(as_formula) loop
  ls_cod_articulo := ls_cod_articulo||substr(as_formula,x,1) ;
end loop ;

ad_fec_hasta := ad_fec_proceso + 1 ;
ad_fec_desde := to_date(to_char(ad_fec_proceso,'dd/mm/yyyy')||' 06:00:00','dd/mm/yyyy hh:mi:ss') ;
ad_fec_hasta := to_date(to_char(ad_fec_hasta,'dd/mm/yyyy')||' 05:59:59','dd/mm/yyyy hh:mi:ss') ;

ln_verifica := 0 ; ln_valor := 0 ;
select count(*) into ln_verifica from salida_pesada s
  where trim(s.cod_art) = ls_cod_articulo and
        s.fecha_pesada between ad_fec_desde and ad_fec_hasta ;

if ln_verifica > 0 then
  select sum(((s.pesada - s.tara) / 1000)) into ln_valor from salida_pesada s
    where trim(s.cod_art) = ls_cod_articulo and
          s.fecha_pesada between ad_fec_desde and ad_fec_hasta ;
end if ;

return (ln_valor) ;

end usf_ptx_balanza ;
/

prompt
prompt Creating function USF_PTX_CALCULO_CALDEROS
prompt ==========================================
prompt
create or replace function cantabria.usf_ptx_calculo_calderos (
  as_formula in char, ad_fec_proceso in date ) return number is

ln_verifica           integer ;
ls_dato               varchar2(20) ;
ls_operacion          varchar2(20) ;
ls_maquina            varchar2(20) ;
ls_linea              varchar2(20) ;
ls_columna            varchar2(20) ;

ls_cadena             varchar2(600) ;
ln_sw                 integer ;
ln_importe_1          number(13,3) ;
ln_importe_2          number(13,3) ;
ls_operador           char(1) ;
ln_valor              number(19,6) ;
ln_resultado          number(13,3) ;

begin

--  *********************************************************
--  ***   REALIZA CALCULO DE PRODUCCION DE LOS CALDEROS   ***
--  *********************************************************

--  Determina valores para realizar calculos
ls_cadena := null ; ls_dato := null ;
for x in 1 .. length(as_formula) loop

  if substr(as_formula,x,1) = ']' then

    if ls_columna is null then ls_columna := ls_dato ; end if ;
    ln_verifica := 0 ; ln_valor := 0 ;
    select count(*) into ln_verifica from ptx_resultados r
      where trim(r.operacion) = ls_operacion and trim(r.cod_maquina) = ls_maquina and
            r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
            trunc(r.fecha) = ad_fec_proceso ;
    if ln_verifica > 0 then
      select nvl(r.valor,0) into ln_valor from ptx_resultados r
        where trim(r.operacion) = ls_operacion and trim(r.cod_maquina) = ls_maquina and
              r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
              trunc(r.fecha) = ad_fec_proceso ;
    end if ;
    ls_operacion := null ; ls_maquina := null ;
    ls_linea     := null ; ls_columna := null ; ls_dato := null ;
    ls_cadena    := ls_cadena||to_char(ln_valor)||'@' ;

  elsif substr(as_formula,x,1) = '%' then

    ls_cadena := ls_cadena||ls_dato||'%' ;
    ls_dato := null ;

  elsif substr(as_formula,x,1) = ')' then

    ls_cadena := ls_cadena||ls_dato||'@' ;
    ls_dato := null ;

  elsif substr(as_formula,x,1) = ',' then

    if ls_operacion is null then ls_operacion := ls_dato ;
    elsif ls_maquina is null then ls_maquina := ls_dato ;
    elsif ls_linea is null then ls_linea := ls_dato ;
    end if ;
    ls_dato := null ;

  else

    if substr(as_formula,x,1) <> '[' then
      ls_dato := ls_dato||substr(as_formula,x,1) ;
    end if ;

  end if ;

end loop ;

--  Realiza calculos de los valores de la cadena
ln_valor     := 0 ;    ln_sw        := 0 ;
ls_dato      := null ; ls_operador  := null ;
ln_importe_1 := null ; ln_importe_2 := null ;

for x in 1 .. length(ls_cadena) loop

  if ln_sw = 0 then

    if substr(ls_cadena,x,1) = '@' then
      if ln_importe_1 is null then
        ln_importe_1 := to_number(ls_dato) ;
      elsif ln_importe_2 is null then
        ln_importe_2 := to_number(ls_dato) ;
        if ls_operador = '+' then
          ln_valor := ln_importe_1 + ln_importe_2 ;
        elsif ls_operador = '-' then
          if nvl(ln_importe_1,0) = 0 then
            ln_valor := 0 ;
          else
            if nvl(ln_importe_1,0) < nvl(ln_importe_2,0) then
              if nvl(ln_importe_2,0) > 100000 then
                ln_importe_1 := ln_importe_1 + 1000000 ;
              else
                ln_importe_1 := ln_importe_1 + 100000 ;
              end if ;
            end if ;
            ln_valor := ln_importe_1 - ln_importe_2 ;
          end if ;
        elsif ls_operador = '*' then
          ln_valor := ln_importe_1 * ln_importe_2 ;
        elsif ls_operador = '/' then
          if nvl(ln_importe_2,0) > 0 then
            ln_valor := ln_importe_1 / ln_importe_2 ;
          end if ;
        end if ;
        ln_sw := 1 ; ln_importe_1 := 0 ; ln_importe_2 := 0 ; ls_operador := null ;
      end if ;
      ls_dato := null ;
    elsif substr(ls_cadena,x,1) = '%' then
      ls_operador := ls_dato ;
      ls_dato     := null ;
    else
      ls_dato := ls_dato||substr(ls_cadena,x,1) ;
    end if ;

  else

    if substr(ls_cadena,x,1) = '%' then
      ls_operador := ls_dato ;
      ls_dato     := null ;
    elsif substr(ls_cadena,x,1) = '@' then
      ln_importe_1 := to_number(ls_dato) ;
        if ls_operador = '+' then
          ln_valor := ln_valor + ln_importe_1 ;
        elsif ls_operador = '-' then
          ln_valor := ln_valor - ln_importe_1 ;
        elsif ls_operador = '*' then
          ln_valor := ln_valor * ln_importe_1 ;
        elsif ls_operador = '/' then
          if nvl(ln_importe_1,0) > 0 then
            ln_valor := ln_valor / ln_importe_1 ;
          end if ;
        end if ;
      ls_dato      := null ;
      ln_importe_1 := 0 ;
    else
      ls_dato := ls_dato||substr(ls_cadena,x,1) ;
    end if ;

  end if ;

end loop ;

ln_resultado := round(ln_valor,3) ;

return (ln_resultado) ;

end usf_ptx_calculo_calderos ;
/

prompt
prompt Creating function USF_PTX_CALCULO_MULTOMETRO
prompt ============================================
prompt
create or replace function cantabria.usf_ptx_calculo_multometro (
  as_formula in char, ad_fec_proceso in date, as_operacion in char,
  as_maquina in char ) return number is

ln_verifica           integer ;
ls_dato               varchar2(20) ;
ls_contometro         varchar2(20) ;
ls_nro_placa          varchar2(20) ;
ls_linea              varchar2(20) ;
ls_columna            varchar2(20) ;
ln_horas              number(13,3) ;
ln_placa              number(13,2) ;
ln_valor              number(13,3) ;

begin

--  **********************************************************
--  ***   REALIZA CALCULO PARA CADA PLACA DEL MULTOMETRO   ***
--  **********************************************************

ls_dato  := null ; ls_contometro := null ; ls_nro_placa := null ;
ls_linea := null ; ls_columna    := null ;

for x in 1 .. length(as_formula) loop
  if substr(as_formula,x,1) = '@' then
    if ls_contometro is null then ls_contometro := ls_dato ;
    elsif ls_nro_placa is null then ls_nro_placa := ls_dato ;
    elsif ls_linea is null then ls_linea := ls_dato ;
    elsif ls_columna is null then ls_columna := ls_dato ;
    end if ;
    ls_dato := null ;
  else
    ls_dato := ls_dato||substr(as_formula,x,1) ;
  end if ;
end loop ;

--  Determina horas de trabajo de la placa del multometro
ln_verifica := 0 ; ln_horas := 0 ;
select count(*) into ln_verifica from ptx_resultados r
  where r.operacion = as_operacion and r.cod_maquina = as_maquina and
        r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
        r.fecha = ad_fec_proceso ;
if ln_verifica > 0 then
  select nvl(r.valor,0) into ln_horas from ptx_resultados r
    where r.operacion = as_operacion and r.cod_maquina = as_maquina and
          r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
          r.fecha = ad_fec_proceso ;
end if ;

--  Determina numero de placa del multometro
ln_verifica := 0 ; ln_placa := 0 ;
select count(*) into ln_verifica from ptx_gen_contometro_det d
  where trim(d.contometro) = ls_contometro and trim(d.nro_placa) = ls_nro_placa ;
if ln_verifica > 0 then
  select nvl(d.nro_horas,0) into ln_placa from ptx_gen_contometro_det d
    where trim(d.contometro) = ls_contometro and trim(d.nro_placa) = ls_nro_placa ;
end if ;

ln_valor := nvl(ln_placa,0) * nvl(ln_horas,0) ;

return (ln_valor) ;

end usf_ptx_calculo_multometro ;
/

prompt
prompt Creating function USF_PTX_FACTOR_CORRECCION
prompt ===========================================
prompt
create or replace function cantabria.usf_ptx_factor_correccion (
  as_formula in char, as_maquina in char, ad_fec_proceso in date )
  return number is

ln_verifica        integer ;
ls_cadena          varchar2(600) ;
ln_valor           number(13,3) ;
ls_codigo          varchar2(100) ;
ls_llave           varchar2(100) ;
ls_cod_factor      char(3) ;
ln_presion         number(4) ;
ln_temperatura     number(4) ;

ls_fact_corr       varchar2(100) ;
ls_factor          varchar2(100) ;
ls_presion         varchar2(100) ;
ls_temperatura     varchar2(100) ;

begin

--  *************************************************************
--  ***   DETERMINA FACTOR DE CORRECCION DE LOS CONTOMETROS   ***
--  *************************************************************

for x in 1 .. length(as_formula) loop
  if substr(as_formula,x,1) <> '@' then
    ls_cadena := ls_cadena||substr(as_formula,x,1) ;
  else
    if ls_codigo is null then ls_codigo := ls_cadena ;
    elsif ls_llave is null then ls_llave := ls_cadena ;
    elsif ls_fact_corr is null then ls_fact_corr := ls_cadena ;
    elsif ls_factor is null then ls_factor := ls_cadena ;
    elsif ls_presion is null then ls_presion := ls_cadena ;
    elsif ls_temperatura is null then ls_temperatura := ls_cadena ;
    end if ;
    ls_cadena := null ;
  end if ;
end loop ;

--  Determina codigo de factor de correccion
ls_cadena := 'select '||ls_codigo||' from ptxparam where ' ;
ls_cadena := ls_cadena||ls_llave||' = :1' ;
execute immediate ls_cadena
  into ls_cod_factor
  using '1' ;

--  Determina presion y temperatura del dia en el caldero
ln_verifica := 0 ; ln_presion := 0 ; ln_temperatura := 0 ;
select count(*) into ln_verifica from ptx_gen_energia_pd e
  where e.cod_maquina = as_maquina and fecha = ad_fec_proceso ;
if ln_verifica > 0 then
  select nvl(e.presion,0), nvl(e.temperatura,0) into ln_presion, ln_temperatura
    from ptx_gen_energia_pd e
    where e.cod_maquina = as_maquina and fecha = ad_fec_proceso ;
end if ;

--  Determina factor de correccion de presion o temperatura del caldero
ln_verifica := 0 ; ln_valor := 0 ; ls_cadena := null ;
ls_cadena := 'select '||'count(*)'||' from ptx_factor_correccion_det where ' ;
ls_cadena := ls_cadena||ls_factor||' = :1 and '||ls_presion||' = :2 and ' ;
ls_cadena := ls_cadena||ls_temperatura||' = :3' ;
execute immediate ls_cadena
  into ln_verifica
  using ls_cod_factor, ln_presion, ln_temperatura ;
if ln_verifica > 0 then
  ls_cadena := 'select '||ls_fact_corr||' from ptx_factor_correccion_det where ' ;
  ls_cadena := ls_cadena||ls_factor||' = :1 and '||ls_presion||' = :2 and ' ;
  ls_cadena := ls_cadena||ls_temperatura||' = :3' ;
  execute immediate ls_cadena
    into ln_valor
    using ls_cod_factor, ln_presion, ln_temperatura ;
end if ;

return (ln_valor) ;

end usf_ptx_factor_correccion ;
/

prompt
prompt Creating function USF_PTX_FACTOR_PETROLEO
prompt =========================================
prompt
create or replace function cantabria.usf_ptx_factor_petroleo (
  as_formula in char ) return number is

ln_verifica        integer ;
ld_fecha           date ;
ls_valor           varchar2(100) ;
ls_tabla           varchar2(100) ;
ls_fecha           varchar2(100) ;
ls_cadena          varchar2(200) ;
ln_valor           number(13,3) ;
ln_result          number(9,6) ;

begin

--  *****************************************************
--  ***   CAPTURA FACTOR DEL CONTOMETRO DEL CALDERO   ***
--  *****************************************************

ln_verifica := 0 ; ld_fecha := null ;
select count(*) into ln_verifica
  from ptx_factor_petroleo p ;
if ln_verifica > 0 then
  select max(p.fecha) into ld_fecha
    from ptx_factor_petroleo p ;
end if ;

ls_valor  := null ; ls_tabla := null ; ls_fecha := null ;
ls_cadena := null ;

for x in 1 .. length(as_formula) loop
  if substr(as_formula,x,1) <> '@' then
    ls_cadena := ls_cadena||substr(as_formula,x,1) ;
  else
    if ls_valor is null then ls_valor := ls_cadena ;
    elsif ls_tabla is null then ls_tabla := ls_cadena ;
    elsif ls_fecha is null then ls_fecha := ls_cadena ;
    end if ;
    ls_cadena := null ;
  end if ;
end loop ;

ls_cadena := 'select '||'count(*)'||' from '||ls_tabla||' where ' ;
ls_cadena := ls_cadena||ls_fecha||' = :1' ;
ln_verifica := 0 ; ln_result := 0 ; ln_valor := 0 ;
execute immediate ls_cadena
  into ln_verifica
  using ld_fecha ;
if ln_verifica > 0 then
  ls_cadena := 'select '||ls_valor||' from '||ls_tabla||' where ' ;
  ls_cadena := ls_cadena||ls_fecha||' = :1' ;
  execute immediate ls_cadena
    into ln_result
    using ld_fecha ;
end if ;

ln_valor := ln_result * 1000000 ;
return (ln_valor) ;

end usf_ptx_factor_petroleo ;
/

prompt
prompt Creating function USF_PTX_IMPORTA_VALOR
prompt =======================================
prompt
create or replace function cantabria.usf_ptx_importa_valor (
  as_formula in char, ad_fec_proceso in date ) return number is

ln_verifica           integer ;
ls_dato               varchar2(20) ;
ls_operacion          varchar2(20) ;
ls_maquina            varchar2(20) ;
ls_linea              varchar2(20) ;
ls_columna            varchar2(20) ;
ln_valor              number(13,3) ;

begin

--  *****************************************************
--  ***   REALIZA CALCULO DE IMPORTACION DE VALORES   ***
--  *****************************************************

ls_dato := null ;
for x in 1 .. length(as_formula) loop

  if substr(as_formula,x,1) = ']' then

    if ls_columna is null then ls_columna := ls_dato ; end if ;
    ln_verifica := 0 ; ln_valor := 0 ;
    select count(*) into ln_verifica from ptx_resultados r
      where trim(r.operacion) = ls_operacion and trim(r.cod_maquina) = ls_maquina and
            r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
            trunc(r.fecha) = ad_fec_proceso ;
    if ln_verifica > 0 then
      select nvl(r.valor,0) into ln_valor from ptx_resultados r
        where trim(r.operacion) = ls_operacion and trim(r.cod_maquina) = ls_maquina and
              r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
              trunc(r.fecha) = ad_fec_proceso ;
    end if ;

  elsif substr(as_formula,x,1) = ',' then

    if ls_operacion is null then ls_operacion := ls_dato ;
    elsif ls_maquina is null then ls_maquina := ls_dato ;
    elsif ls_linea is null then ls_linea := ls_dato ;
    end if ;
    ls_dato := null ;

  else

    if substr(as_formula,x,1) <> '[' then
      ls_dato := ls_dato||substr(as_formula,x,1) ;
    end if ;

  end if ;

end loop ;

return (ln_valor) ;

end usf_ptx_importa_valor ;
/

