prompt
prompt Creating function USF_PTX_LECTURA_DIA_AYER
prompt ==========================================
prompt
create or replace function cantabria.usf_ptx_lectura_dia_ayer (
  as_formula in char, as_operacion in char, as_maquina in char,
  ad_fec_proceso in date ) return number is

ln_verifica        integer ;
ld_new_fecha       date ;
ls_linea           varchar2(100) ;
ls_columna         varchar2(100) ;
ls_cadena          varchar2(600) ;
ln_valor           number(13,3) ;

begin

--  **************************************************************
--  ***   CAPTURA LA LECTURA DEL CONTOMETRO DEL DIA ANTERIOR   ***
--  **************************************************************

ls_linea  := null ; ls_columna := null ;
ls_cadena := null ;

for x in 1 .. length(as_formula) loop
  if substr(as_formula,x,1) <> '@' then
    ls_cadena := ls_cadena||substr(as_formula,x,1) ;
  else
    if ls_linea is null then ls_linea := ls_cadena ;
    elsif ls_columna is null then ls_columna := ls_cadena ;
    end if ;
    ls_cadena := null ;
  end if ;
end loop ;

ln_verifica := 0 ; ln_valor := 0 ;
select count(*) into ln_verifica from ptx_resultados r
  where r.operacion = as_operacion and r.cod_maquina = as_maquina and
        r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
        trunc(r.fecha) = (ad_fec_proceso) -1 ;

if ln_verifica > 0 then

  select nvl(r.valor,0) into ln_valor from ptx_resultados r
    where r.operacion = as_operacion and r.cod_maquina = as_maquina and
          r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
          trunc(r.fecha) = (ad_fec_proceso) -1 ;
  if nvl(ln_valor,0) = 0 then
    select max(r.fecha) into ld_new_fecha from ptx_resultados r
      where r.operacion = as_operacion and r.cod_maquina = as_maquina and
            r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
            nvl(r.valor,0) <> 0 and trunc(r.fecha) < ad_fec_proceso ;
    select nvl(r.valor,0) into ln_valor from ptx_resultados r
      where r.operacion = as_operacion and r.cod_maquina = as_maquina and
            r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
            trunc(r.fecha) = trunc(ld_new_fecha) ;
  end if ;

else

  select max(r.fecha) into ld_new_fecha from ptx_resultados r
    where r.operacion = as_operacion and r.cod_maquina = as_maquina and
          r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
          nvl(r.valor,0) <> 0 and trunc(r.fecha) < ad_fec_proceso ;
  select nvl(r.valor,0) into ln_valor from ptx_resultados r
    where r.operacion = as_operacion and r.cod_maquina = as_maquina and
          r.linea = to_number(ls_linea) and r.columna = to_number(ls_columna) and
          trunc(r.fecha) = trunc(ld_new_fecha) ;

end if ;

return (ln_valor) ;

end usf_ptx_lectura_dia_ayer ;
/

