    end if ;
    ls_cadena := null ;
  end if ;
end loop ;

select nvl(e.item,0) into ln_eficiencia from ptx_efic_diaria_caldero e
  where trim(e.cod_maquina) = trim(ls_maquina_bus) and trunc(e.fecha) = trunc(ad_fec_proceso) ;

if ln_eficiencia = 1 then
  ln_columna := to_number(ls_columna_1) ;
elsif ln_eficiencia = 2 then
  ln_columna := to_number(ls_columna_2) ;
elsif ln_eficiencia = 3 then
