ls_cadena := ls_cadena||ls_linea||' = :3 and '||ls_columna||' = :4 and ' ;
ls_cadena := ls_cadena||ls_fecha||' = :5' ;
ln_verifica := 0 ; ln_valor := 0 ;
execute immediate ls_cadena
  into ln_verifica
  using ls_operacion_bus, ls_maquina_bus, to_number(ls_linea_bus), ln_columna, ad_fec_proceso ;
