  execute immediate ls_cadena
    into ln_valor
    using ad_fec_proceso, ls_dato_maquina, ls_dato_articulo ;
end if ;

return (ln_valor) ;

end usf_ptx_valor_pd_caldero ;
/

prompt
prompt Creating function USF_PTX_VAPOR_PRODUCIDO
prompt =========================================
prompt
create or replace function cantabria.usf_ptx_vapor_producido (
  as_formula in char, ad_fec_proceso in date ) return number is

ln_verifica        integer ;
ls_valor           varchar2(100) ;
ls_tabla           varchar2(100) ;
ls_operacion       varchar2(100) ;
ls_maquina         varchar2(100) ;
ls_linea           varchar2(100) ;
ls_columna         varchar2(100) ;
ls_fecha           varchar2(100) ;
ls_dato_operacion  varchar2(100) ;
ls_dato_maquina    varchar2(100) ;
ls_dato_linea      varchar2(100) ;
ls_dato_columna    varchar2(100) ;

ls_cadena          varchar2(200) ;
ln_valor           number(13,3) ;

begin

--  *********************************************************
--  ***   DETERMINA VAPOR PRODUCIDO EM MBTU POR CALDERO   ***
--  *********************************************************

ls_valor      := null ; ls_tabla          := null ; ls_operacion    := null ;
ls_maquina    := null ; ls_linea          := null ; ls_columna      := null ;
ls_fecha      := null ; ls_dato_operacion := null ; ls_dato_maquina := null ;
ls_dato_linea := null ; ls_dato_columna   := null ;
ls_cadena     := null ;

for x in 1 .. length(as_formula) loop
  if substr(as_formula,x,1) <> '@' then
    ls_cadena := ls_cadena||substr(as_formula,x,1) ;
  else
    if ls_valor is null then ls_valor := ls_cadena ;
    elsif ls_tabla is null then ls_tabla := ls_cadena ;
    elsif ls_operacion is null then ls_operacion := ls_cadena ;
    elsif ls_maquina is null then ls_maquina := ls_cadena ;
    elsif ls_linea is null then ls_linea := ls_cadena ;
    elsif ls_columna is null then ls_columna := ls_cadena ;
    elsif ls_fecha is null then ls_fecha := ls_cadena ;
    elsif ls_dato_operacion is null then ls_dato_operacion := ls_cadena ;
    elsif ls_dato_maquina is null then ls_dato_maquina := ls_cadena ;
    elsif ls_dato_linea is null then ls_dato_linea := ls_cadena ;
    elsif ls_dato_columna is null then ls_dato_columna := ls_cadena ;
    end if ;
    ls_cadena := null ;
  end if ;
end loop ;

ls_cadena := 'select '||'count(*)'||' from '||ls_tabla||' where ' ;
ls_cadena := ls_cadena||ls_operacion||' = :1 and '||ls_maquina||' = :2 and ' ;
ls_cadena := ls_cadena||ls_linea||' = :3 and '||ls_columna||' = :4 and ' ;
ls_cadena := ls_cadena||ls_fecha||' = :5' ;
ln_verifica := 0 ; ln_valor := 0 ;
execute immediate ls_cadena
  into ln_verifica
  using ls_dato_operacion, ls_dato_maquina, ls_dato_linea, ls_dato_columna, ad_fec_proceso ;
if ln_verifica > 0 then
  ls_cadena := 'select '||ls_valor||' from '||ls_tabla||' where ' ;
  ls_cadena := ls_cadena||ls_operacion||' = :1 and '||ls_maquina||' = :2 and ' ;
  ls_cadena := ls_cadena||ls_linea||' = :3 and '||ls_columna||' = :4 and ' ;
  ls_cadena := ls_cadena||ls_fecha||' = :5' ;
  execute immediate ls_cadena
    into ln_valor
    using ls_dato_operacion, ls_dato_maquina, ls_dato_linea, ls_dato_columna, ad_fec_proceso ;
end if ;

return (ln_valor) ;

end usf_ptx_vapor_producido ;
/

