prompt
prompt Creating function USF_RESTAFECHAS2HORAS
prompt =======================================
prompt
create or replace function cantabria.usf_restafechas2horas(
   ad_fecha_inicial in date,
   ad_fecha_final in date) return string is

   -- resta dos fechas, devuelve en 'hhhh:mm'
   -- fecha_inicial < fecha_final

   ln_dias_a_horas  number;  -- resta de las dos fechas
   li_horas integer ;
   li_minutos integer ;
   ls_hora_minuto char(7) ;
   ls_hora_ini char(20) ;
   ls_hora_fin char(20) ;
begin

   ls_hora_ini := to_char( ad_fecha_inicial, 'dd/mm/yyyy hh24:mi' ) ;
   ls_hora_fin := to_char( ad_fecha_final, 'dd/mm/yyyy hh24:mi' ) ;

   ln_dias_a_horas := ( ad_fecha_final - ad_fecha_inicial ) * 24 ;
--   ln_dias_a_horas := ( ad_fecha_final - ad_fecha_inicial ) ;
--   ln_dias_a_horas := ln_dias_a_horas * 24 ;
   ln_dias_a_horas := nvl( ln_dias_a_horas, 0) ;
   li_horas   := trunc( ln_dias_a_horas ) ;
   li_minutos := trunc( ( ln_dias_a_horas - li_horas ) * 60 ) ;
   ls_hora_minuto := substr( to_char( li_horas, '9990'), 2, 4) || ':' ||
                     substr( to_char( li_minutos, '00' ), 2, 4) ;
  return( ls_hora_minuto );
end usf_restafechas2horas;
/

prompt
prompt Creating function USF_RETORNA_SUM_CHR
prompt =====================================
prompt
create or replace function cantabria.usf_retorna_sum_chr( as_cadena in char )
   return number is
   ln_sum number(10) ;
   ln_pos number(7) ;
   ls_sum varchar2(11) ;
   -- nuevo requerimiento para obviar chr(10) y chr(13)
   ln_ascii number(3) ;
begin
  ln_sum := 0 ;
  ln_pos := 0 ;
  if as_cadena is null or length( trim( as_cadena )) is null then
     return 0 ;
  else
     for ln_pos in 1 .. length( trim( as_cadena ))
     loop
         ln_ascii := Ascii( Substr(as_cadena, ln_pos, 1) ) ;
         if ln_ascii <> 10 and ln_ascii <> 13 then
            ln_sum := ln_sum +  ln_ascii ;
         end if;
     end loop;
     ls_sum := trim( to_char( ln_sum ));
     ln_sum := to_number( substr( ls_sum, length( ls_sum ) - 3, 3) );
  end if;
  return(ln_sum);
end usf_retorna_sum_chr;
/

prompt
prompt Creating function USF_RETORNA_SUM_NUM
prompt =====================================
prompt
create or replace function cantabria.USF_RETORNA_SUM_NUM
( as_name_table  in  user_tab_columns.table_name%type )
  return number is
  Result number;

  cursor c_cur ( ls_table_name in user_tab_columns.table_name%type ) is
         select a.table_name, a.column_name
         from user_tab_columns a
         where a.data_type like 'NUM%'  and a.table_name = ls_table_name
                         and a.table_name || a.column_name not in (
                                                    select t.table_name || t.column_name
                                                       from user_cons_columns t
                                                        where substr(t.constraint_name,1,3) in ('PK_', 'FK_') )
         order by a.table_name asc ;

  ln_sum_total number(10) ;
  ln_sum_parcial number(10) ;
begin
  ln_sum_parcial := 0 ;
  ln_sum_total := 0 ;

  for rc_t in c_cur(as_name_table) loop
      execute immediate  ' select sum ( '|| rc_t.column_name ||' ) from '|| as_name_table  into ln_sum_parcial ;
      ln_sum_total := nvl(ln_sum_total,0) +   nvl(ln_sum_parcial,0) ;
  end loop;
  Result  := ln_sum_total ;
  return(Result);

end USF_RETORNA_SUM_NUM;
/

prompt
prompt Creating function USF_RH_CALC_DIAS_GRUPO
prompt ========================================
prompt
create or replace function cantabria.usf_rh_calc_dias_grupo
(
       asi_codtra          in maestro.cod_trabajador%TYPE ,
       asi_origen          in origen.cod_origen%TYPE,
       asi_tip_trab        in tipo_trabajador.tipo_trabajador%type,
       ani_dias_mes        in number,
       adi_desde           in date,
       adi_hasta           in date
)return number is

ls_grp_dias_inasis         rrhhparam_cconcep.dias_inasis_dsccont%TYPE;
ls_cnc_vacaciones          concepto.concep%TYPE;
ln_dias                    number;
ln_dias_JOR                NUMBER;
ln_dias_DES                number;
ln_dias_campo              NUMBER;
ln_dias_trip               number;
ln_dias_motorista          number;
ls_flag_tipo_sueldo        tipo_trabajador.flag_ingreso_boleta%TYPE;
ls_tipo_trip               rrhhparam.tipo_trab_tripulante%TYPE;
ls_tipo_des                rrhhparam.tipo_trab_destajo%TYPE;
ls_tipo_ser                rrhhparam.tipo_trab_servis%TYPE;
ls_tipo_emp                rrhhparam.tipo_trab_empleado%TYPE;

ln_tot_dias_trabaj         number;




begin

--  ***********************************************************************
--  ***   REALIZA CALCULO DE DIAS TRABAJADOS PARA CALCULO DE PLANILLA   ***
--  ***********************************************************************

  -- Determinar si el pago es por jornal o fijo
  select t.flag_ingreso_boleta
    into ls_flag_tipo_sueldo
    from tipo_trabajador t
   where t.tipo_trabajador = asi_tip_trab;
   
  select c.dias_inasis_dsccont
    into ls_grp_dias_inasis
    from rrhhparam_cconcep c
   where c.reckey = '1' ;
  
  select r.tipo_trab_tripulante, r.tipo_trab_destajo, r.tipo_trab_servis, r.tipo_trab_empleado
    into ls_tipo_trip, ls_tipo_des, ls_tipo_ser, ls_tipo_emp
    from rrhhparam r
   where r.reckey = '1' ;
     
  -- Obtengo el concepto de vacaciones
  select gc.concepto_gen
    into ls_cnc_vacaciones
    from grupo_calculo gc
   where gc.grupo_calculo = (select t.gan_fij_calc_vacac from rrhhparam_cconcep t);
  
  -- Dias como tripulante
  select count(distinct fa.fecha)
    into ln_dias_trip
    from fl_asistencia fa
   where fa.tripulante = asi_codtra
     and trunc(fa.fecha) BETWEEN trunc(adi_desde) AND trunc(adi_hasta);
    
  -- Dias como motorista
  select sum(fa.nro_dias)
    into ln_dias_motorista
    from fl_dias_motorista fa
   where fa.cod_motorista = asi_codtra
     and trim(to_char(fa.anio, '0000')) || trim(to_char(fa.mes, '00'))  BETWEEN to_char(adi_desde, 'yyyymm') AND to_char(adi_hasta, 'yyyymm');

  -- Dias como jornalero
  SELECT COUNT(DISTINCT a.fec_movim)
    INTO ln_dias_JOR
    FROM asistencia a
   WHERE a.cod_trabajador = asi_codtra
     AND trunc(a.fec_movim) BETWEEN trunc(adi_desde) AND trunc(adi_hasta);

  SELECT COUNT(DISTINCT a.fecha)
    INTO ln_dias_campo
    FROM pd_jornal_campo a
   WHERE a.cod_trabajador = asi_codtra
     AND trunc(a.fecha) BETWEEN trunc(adi_desde) AND trunc(adi_hasta);

  -- Dias como destajo
  select count(distinct a.fec_parte)
    into ln_dias_DES
    from tg_pd_destajo     a,
         tg_pd_destajo_det b
   where a.nro_parte = b.nro_parte
     and a.flag_estado <> '0'
     and b.cod_trabajador = asi_codtra
     AND trunc(a.fec_parte) BETWEEN trunc(adi_desde) AND trunc(adi_hasta);
     
  /*select nvl(sum(dias),0)
    into ln_dias_DES
    from (
         select nvl(sum(distinct hc.dias_trabaj),0) as dias
           from historico_calculo hc
          where hc.cod_trabajador = asi_codtra
            and hc.concep         in ('1107', '1201')
            and trunc(hc.fec_calc_plan) between adi_desde and adi_hasta
          union all
          select nvl(sum(distinct c.dias_trabaj),0)
           from calculo c
          where c.cod_trabajador = asi_codtra
            and c.concep         in ('1107', '1201')
            and trunc(c.fec_proceso) between adi_desde and adi_hasta
          );
  */  
  -- Dias como empleado
  if asi_tip_trab = ls_tipo_emp then
     select nvl(sum(dias),0)
       into ln_dias
       from (
             select nvl(sum(hc.dias_trabaj),0) as dias
               from historico_calculo hc
              where hc.cod_trabajador = asi_codtra
                and hc.concep         in ('1001', '1463', '1459')
                and trunc(hc.fec_calc_plan) between adi_desde and adi_hasta
              union all
              select nvl(sum(c.dias_trabaj),0)
               from calculo c
              where c.cod_trabajador = asi_codtra
                and c.concep         in ('1001', '1463', '1459')
                and trunc(c.fec_proceso) between adi_desde and adi_hasta
              );
  else
     ln_dias := 0;
  end if;
             
  ln_tot_dias_trabaj := nvl(ln_dias_campo,0) + nvl(ln_dias_DES,0) + nvl(ln_dias_JOR, 0) + NVL(ln_dias,0) + case when NVL(ln_dias_trip,0)= 0 then NVL(ln_dias_motorista, 0) else NVL(ln_dias_trip, 0) end;
  
  if ln_tot_dias_trabaj > ani_dias_mes then ln_tot_dias_trabaj := ani_dias_mes; end if;
  
  return(nvl(ln_tot_dias_trabaj,0)) ;

end usf_rh_calc_dias_grupo ;
/

prompt
prompt Creating function USF_RH_CALC_DIAS_TRABAJ
prompt =========================================
prompt
create or replace function cantabria.usf_rh_calc_dias_trabaj(
       adi_fecha1          in DATE, 
       adi_fecha2          IN DATE
) return number is
  ln_Result     number;
  ld_fec_ini    DATE;
  ld_fec_fin    DATE;
  ln_mes        NUMBER;
  ln_year       NUMBER;
BEGIN
  -- Inicializo el acumulador
  ln_result := 0;
  
  -- Esta funcion calcula los dias trabajados basandose en meses completos de 30 dias  
  ln_mes  := to_number(to_char(adi_fecha1, 'mm'));
  ln_year := to_number(to_char(adi_fecha1, 'yyyy'));
  
  -- Obtengo la fecha inicial del mes
  ld_fec_ini := to_date('01/' || to_char(ln_mes, '00') || '/' || to_char(ln_year), 'dd/mm/yyyy');
  
  IF ld_fec_ini < adi_fecha1 THEN
     ld_fec_ini := adi_Fecha1;
  END IF;
  
  -- ahora calculo la fecha final del mes
  ln_mes  := to_number(to_char(ld_fec_ini, 'mm'));
  ln_year := to_number(to_char(ld_fec_ini, 'yyyy'));
  
  IF ln_mes = 12 THEN
     ln_year := ln_year +1;
     ln_mes := 1;
  ELSE
     ln_mes := ln_mes + 1;
  END IF;
  
  ld_fec_fin := to_date('01/' || to_char(ln_mes, '00') || '/' || to_char(ln_year), 'dd/mm/yyyy') - 1;
  
  WHILE ld_fec_fin <= adi_Fecha2 LOOP
        IF to_char(ld_fec_ini, 'dd') = '01' THEN
           ln_Result := ln_Result + 30;
        ELSE
           if to_char(ld_fec_fin, 'mm') = '02' then
              ln_Result := ln_Result + ld_fec_fin - ld_fec_ini + 2;
           else
              ln_Result := ln_Result + ld_fec_fin - ld_fec_ini;
           end if;
           
        END IF; 
        ld_fec_ini := ld_fec_fin + 1;

        -- ahora calculo la fecha final del mes
        ln_mes  := to_number(to_char(ld_fec_ini, 'mm'));
        ln_year := to_number(to_char(ld_fec_ini, 'yyyy'));    
  
        IF ln_mes = 12 THEN
           ln_year := ln_year +1;
           ln_mes := 1;
        ELSE
           ln_mes := ln_mes + 1;
        END IF;
  
        ld_fec_fin := to_date('01/' || to_char(ln_mes, '00') || '/' || to_char(ln_year), 'dd/mm/yyyy') - 1;
             
  END LOOP;
  
  ln_Result := ln_Result + adi_fecha2 - ld_fec_ini + 1;
  
  return(ln_Result);
end usf_rh_calc_dias_trabaj;
/

prompt
prompt Creating function USF_RH_CAL_DIAS_TRABAJADOS
prompt ============================================
prompt
create or replace function cantabria.usf_rh_cal_dias_trabajados(
       asi_codtra          in maestro.cod_trabajador%TYPE ,
       asi_origen          in origen.cod_origen%TYPE,
       asi_tip_trab        in tipo_trabajador.tipo_trabajador%type,
       ani_dias_mes        in number,
       adi_fec_proceso     in date,
       asi_tipo_planilla   in calculo.tipo_planilla%TYPE
)return number is

ls_grp_dias_inasis         rrhhparam_cconcep.dias_inasis_dsccont%TYPE;
ls_tipo_trabaj             maestro.tipo_trabajador%TYPE;
ls_cnc_vacaciones          concepto.concep%TYPE;
ln_dias                    number;
ld_fec_desde               date ;
ld_fec_hasta               date ;
ln_dias_trabajados         number(4,2) ;
ln_faltas                  number ;
ln_count                   number;
ln_dias_obrero             NUMBER;
ln_dias_campo              NUMBER;
ln_dias_destajo            number;
ld_fec_ing_trab            maestro.fec_ingreso%TYPE;
ld_fec_cese                maestro.fec_cese%TYPE;
ls_flag_tipo_sueldo        tipo_trabajador.flag_ingreso_boleta%TYPE;

--  Cursor de inasistencias a descontar
cursor c_inasistencias is
  select i.dias_inasist 
    from inasistencia i
   where i.cod_trabajador = asi_codtra
     and (i.concep in ( select d.concepto_calc
                         from grupo_calculo_det d
                        where d.grupo_calculo = ls_grp_dias_inasis ) 
          or i.concep = ls_cnc_vacaciones)    
     and trunc(i.fec_movim) between trunc(ld_fec_desde) and trunc(ld_fec_hasta)
     and i.flag_vacac_adelantadas = '0' ;

begin

  --  ***********************************************************************
  --  ***   REALIZA CALCULO DE DIAS TRABAJADOS PARA CALCULO DE PLANILLA   ***
  --  ***********************************************************************

  -- Determinar si el pago es por jornal o fijo
  select t.flag_ingreso_boleta, t.tipo_trabajador
    into ls_flag_tipo_sueldo, ls_tipo_trabaj
    from tipo_trabajador t
   where t.tipo_trabajador = asi_tip_trab;
   
  select c.dias_inasis_dsccont
    into ls_grp_dias_inasis
    from rrhhparam_cconcep c
   where c.reckey = '1' ;
  
  -- Obtengo el concepto de vacaciones
  select gc.concepto_gen
    into ls_cnc_vacaciones
    from grupo_calculo gc
   where gc.grupo_calculo = (select t.gan_fij_calc_vacac from rrhhparam_cconcep t);
  
  select count(*)
    into ln_count
   from rrhh_param_org p
   where p.origen          = asi_origen
     and p.tipo_trabajador = asi_tip_trab
     and trunc(p.fec_proceso) = trunc(adi_fec_proceso)
     and p.tipo_planilla      = asi_tipo_planilla;

  if ln_count = 0 then
       RAISE_APPLICATION_ERROR(-20000, 'Error, no ha especificado parametros para el origen ' || asi_origen ||
                                       ', fecha proceso: ' || to_char(adi_fec_proceso, 'dd/mm/yyyy') ||
                                       ', tipo_trabajador: ' || asi_tip_trab ||
                                       ', Tipo Planilla: ' || asi_tipo_planilla);
  end if;

  select trunc(t.fec_inicio), trunc(t.fec_final)
    into ld_fec_desde, ld_fec_hasta
    from rrhh_param_org t
   where trunc(t.fec_proceso) = trunc(adi_fec_proceso)
     and t.origen             = asi_origen
     and t.tipo_trabajador    = asi_tip_trab
     and t.tipo_planilla      = asi_tipo_planilla;

  -- Obtengo la fecha de inicio de trabajo del trabajador
  select m.fec_ingreso, m.fec_cese
    into ld_fec_ing_trab, ld_fec_cese
    from maestro m
   where m.cod_trabajador = asi_codtra;
  
  if ld_fec_hasta < ld_fec_ing_trab then
     -- El trabajador ha ingresado despues del rango por lo que no corresponde nada
     return 0;
  end if;
  
  -- Verifico si la fecha de inicio de calculo es mayor o menor de la fecha de inicio de trabajo
  if ld_fec_desde < ld_fec_ing_trab then
     ld_fec_desde := ld_fec_ing_trab;
  end if;

  --Fecha de cese
  if ld_fec_cese is not null then
     if ld_fec_cese < ld_fec_desde then return 0; end if;
     if ld_fec_cese < ld_fec_hasta then
        ld_fec_hasta := ld_fec_cese;
     end if;
  end if;

  if ld_fec_desde > ld_fec_hasta then
     RAISE_APPLICATION_ERROR(-20000, 'Error, la fecha de inicio es mayor a la fecha de fin ' || asi_codtra);
  end if;
  
  if asi_tip_trab = USP_SIGRE_RRHH.is_tipo_trip then
     
     if asi_tipo_planilla = 'B' then
        -- Calculo los días fijos
        select nvl(sum(f.nro_dias),0)
          into ln_dias_trabajados 
          from fl_dias_motorista f
         where f.anio            = to_number(to_char(adi_fec_proceso, 'yyyy'))
           and f.mes             = to_number(to_char(adi_fec_proceso, 'mm'))
           and f.cod_motorista   = asi_codtra;
     else 
        -- Si el flag de bonificacion de pesca no esta activa entoces no lo calculo nada mas
        select count(distinct fa.fecha)
          into ln_dias_trabajados
          from fl_asistencia fa
         where fa.tripulante = asi_codtra
           and trunc(fa.fecha) BETWEEN trunc(ld_fec_desde) AND trunc(ld_fec_hasta);
     end if;
     
  elsif asi_tip_trab in (USP_SIGRE_RRHH.is_tipo_des, USP_SIGRE_RRHH.is_tipo_ser) then
  
     select count(distinct p.fec_parte)
       into ln_dias_trabajados
       from tg_pd_destajo p,
            tg_pd_destajo_det pd
      where p.nro_parte = pd.nro_parte
        and pd.cod_trabajador = asi_codtra
        and trunc(p.fec_parte) BETWEEN trunc(ld_fec_desde) AND trunc(ld_fec_hasta)
        and p.flag_estado <> '0';
      
  else
      IF ls_tipo_trabaj in (USP_SIGRE_RRHH.is_tipo_des, USP_SIGRE_RRHH.is_tipo_jor) or ls_flag_tipo_sueldo = 'J' THEN
         -- Dias Trabajados
         SELECT COUNT(DISTINCT a.fec_movim)
           INTO ln_dias_obrero
           FROM asistencia a
          WHERE a.cod_trabajador = asi_codtra
            AND trunc(a.fec_movim) BETWEEN trunc(ld_fec_desde) AND trunc(ld_fec_hasta);

         SELECT COUNT(DISTINCT a.fecha)
           INTO ln_dias_campo
           FROM pd_jornal_campo a
          WHERE a.cod_trabajador = asi_codtra
            AND trunc(a.fecha) BETWEEN trunc(ld_fec_desde) AND trunc(ld_fec_hasta);

         SELECT COUNT(DISTINCT a.fec_parte)
           INTO ln_dias_destajo
           FROM tg_pd_destajo a,
                tg_pd_destajo_det b
          WHERE a.nro_parte      = b.nro_parte
            and b.cod_trabajador = asi_codtra
            AND trunc(a.fec_parte) BETWEEN trunc(ld_fec_desde) AND trunc(ld_fec_hasta)
            and a.flag_estado <> '0';
         
         ln_dias_trabajados := ln_dias_campo + ln_dias_obrero + ln_dias_destajo;
      ELSE
         ln_faltas := 0 ;
         for rc_ina in c_inasistencias loop
           ln_faltas := ln_faltas + nvl(rc_ina.dias_inasist,0) ;
         end loop ;
         
         ln_dias := ld_fec_hasta - ld_fec_desde + 1;
         
         if to_char(adi_fec_proceso, 'mm') = '02' then 
            if trunc(ld_fec_hasta) = trunc(Last_day(adi_fec_proceso)) then
               --ln_dias := trunc(usf_last_day(adi_fec_proceso)) - trunc(to_date('01/02/' || trim(to_char(adi_fec_proceso, 'yyyy')), 'dd/mm/yyyy')) + 1;
               ln_dias := 30;
            end if;
         end if;
         
         if ln_dias > ani_dias_mes then
            ln_dias := ani_dias_mes;
         end if;

         if ln_dias < ln_faltas then
            ln_dias_trabajados := 0;
         else
            ln_dias_trabajados := ln_dias - ln_faltas ;
         end if;

      END IF;
  end if;
  
  if ln_dias_trabajados > ln_dias then
     ln_dias_trabajados := ln_dias ;
  end if ;

  if ln_dias_trabajados > ani_dias_mes then
     ln_dias_trabajados := ani_dias_mes;
  end if;

  return(nvl(ln_dias_trabajados,0)) ;

end usf_rh_cal_dias_trabajados ;
/

prompt
prompt Creating function USF_RH_CAL_DIA_TRA_SUN
prompt ========================================
prompt
create or replace function cantabria.usf_rh_cal_dia_tra_sun (
  as_codtra in char, an_dias_mes in rrhhparam.dias_mes_obrero%type,
  as_origen in char, ac_tip_trab in maestro.tipo_trabajador%type   )

  return calculo.dias_trabaj%type is

--  Buscar conceptos de inasistencias a descontar
lk_descontar    constant char(3) := '076' ;
ls_tipo_ina     char(3) ;
ld_fec_desde    date ;
ld_fec_hasta    date ;
ln_diatra       calculo.dias_trabaj%type ;
ln_faltas       number ;

cursor c_inasistencias  is
  select i.fec_movim, i.dias_inasist
  from inasistencia i
  where i.cod_trabajador = as_codtra and i.concep in ( select d.concepto_calc
        from grupo_calculo_det d where d.grupo_calculo = ls_tipo_ina ) and
        i.fec_movim between ld_fec_desde and ld_fec_hasta ;

begin

select p.fec_inicio, p.fec_final
  into ld_fec_desde, ld_fec_hasta
  from rrhh_param_org p
  where (p.origen          = as_origen   ) and
        (p.tipo_trabajador = ac_tip_trab ) ;


ln_diatra := an_dias_mes ;

--  Determina faltas a descontar
ln_faltas := 0 ;
ls_tipo_ina := lk_descontar ;
for rc_ina in c_inasistencias loop
  ln_faltas := ln_faltas + nvl(rc_ina.dias_inasist,0) ;
end loop ;
if ln_faltas > ln_diatra then
  ln_faltas := ln_diatra ;
end if ;
ln_diatra := ln_diatra - ln_faltas ;

-- los dias trabajados no deben ser mayor a los dias
-- del registro de parametros de rr.hh. (30 0 31)
if ln_diatra > an_dias_mes then
  ln_diatra := an_dias_mes ;
end if ;

return(ln_diatra) ;

end usf_rh_cal_dia_tra_sun ;
/

prompt
prompt Creating function USF_RH_COMP_HORAS_REV
prompt =======================================
prompt
create or replace function cantabria.usf_rh_comp_horas_rev(
   asi_tipo_doc in string,
   adi_ini in date,
   adi_fin in date,
   adi_proc in date

) return integer is
   ano_error_eliminando integer;

   ln_sobret number(10);
   ln_inasist number(10);
   ln_dominical number(10);

begin

   delete
      from sobretiempo_turno st
      where st.tipo_doc = asi_tipo_doc
         and trunc(st.fec_movim) between adi_ini and adi_fin;

   delete
      from inasistencia i
      where i.tipo_doc = asi_tipo_doc
     	   and trunc(i.fec_movim) between adi_ini and adi_fin;

   delete
      from gan_desct_variable gdv
      where gdv.tipo_doc = asi_tipo_doc
         and trunc(gdv.fec_movim) = adi_proc;

   commit;

   select count(*)
      into ln_sobret
      from sobretiempo_turno st
      where st.tipo_doc = asi_tipo_doc
         and trunc(st.fec_movim) between adi_ini and adi_fin;

   select count(*)
      into ln_inasist
      from inasistencia i
      where i.tipo_doc = asi_tipo_doc
     	   and trunc(i.fec_movim) between adi_ini and adi_fin;

   select count(*)
      into ln_dominical
      from gan_desct_variable gdv
      where gdv.tipo_doc = asi_tipo_doc
         and trunc(gdv.fec_movim) = adi_proc;

   if ln_dominical > 0 or ln_inasist > 0 or ln_sobret > 0 then
      ano_error_eliminando := 1;
   else
      ano_error_eliminando := 0;
   end if;

   return(ano_error_eliminando);
end usf_rh_comp_horas_rev;
/

prompt
prompt Creating function USF_RH_COMPHR_COMPENSA
prompt ========================================
prompt
create or replace function cantabria.usf_rh_comphr_compensa (

   adi_periodo_ini in date,
   adi_periodo_fin in date,
   asi_concep_sobret_sab in string,
   asi_concep_sobret_dom in string,
   asi_concep_sobret_fer in string,
   asi_tipo_doc in string,
   asi_cod_tipo_mov in string

) return integer is aio_msg integer;
   ld_ini_periodo date;
   ld_fin_periodo date;
   ld_ini_falta date;
   ld_fin_falta date;
   ld_fec_movimiento date;
   ld_fec_sobretiempo date;
   ld_new_fec_hasta date;
   ld_ini_turno date;
   ld_fin_turno date;
   ld_fec_turno date;

   ln_tiempo_inasistencia number;
   ln_tiempo_sobretiempo number;
   ln_tiempo_inas_pendiente number;
   ln_item number;
   ln_new_dias_inasist number;
   ln_jornada_laboral number;

   ls_sabado char(1);
   ls_domingo char(1);
   ls_feriado char(1);
   ls_concep concepto.concep%type;
   ls_turno turno.turno%type;
   ls_cod_trabajador maestro.cod_trabajador%type;

   cursor lc_trabajador is
      select distinct i.cod_trabajador
         from inasistencia i
         where trunc(i.fec_movim) between ld_ini_periodo and ld_fin_periodo
            and trim(i.tipo_doc) = trim(asi_tipo_doc)
         order by trim(i.cod_trabajador);

   cursor lc_inasistencia is
      select distinct i.fec_movim
         from inasistencia i
         where trunc(i.fec_movim) between ld_ini_periodo and ld_fin_periodo
            and trim(i.cod_trabajador) = trim(ls_cod_trabajador)
            and trim(i.tipo_doc) = trim(asi_tipo_doc)
            order by i.fec_movim;

   cursor lc_movimiento is
      select i.fec_desde, i.fec_hasta
         from inasistencia i
         where trunc(i.fec_movim) = ld_fec_movimiento
            and trim( i.cod_trabajador) = trim(ls_cod_trabajador)
            and trim(i.tipo_doc) = trim(asi_tipo_doc)
            order by i.fec_desde;

   cursor lc_concep_sobret is
      select chd.concep, chd.item
         from rh_grp_cmp_hrs_det chd
            inner join rh_grp_cmp_hrs_trab cht on chd.grp_cmps_hrs = cht.grp_cmps_hrs
         where trim(cht.cod_trabajador) = trim(ls_cod_trabajador)
         order by chd.item desc;

   cursor lc_sobret_trab is
      select chc.concep
         from tt_rh_cmps_hrs_concep chc
         order by chc.item;

   cursor lc_sobretiempo is
      select st.fec_movim, st.concep, st.horas_sobret
         from sobretiempo_turno st
         where trunc(st.fec_movim) between ld_ini_periodo and ld_fin_periodo
            and trim(st.cod_trabajador) = trim(ls_cod_trabajador)
            and trim(st.concep) = trim(ls_concep)
            and st.horas_sobret > 0
            and trim(st.tipo_doc) = trim(asi_tipo_doc)
         order by st.fec_movim;

begin
   aio_msg := 1;
   ld_ini_periodo := trunc(adi_periodo_ini);
   ld_fin_periodo := trunc(adi_periodo_fin);

   for rs_it in lc_trabajador loop -- trabjadores que tienen inasistencias
      ls_cod_trabajador := rs_it.cod_trabajador;
      ln_item := 0;
      -- creando arreglo de conceptos de sobretirmpo para descuento
      -- el item 1 es el primer concepto a descontar
      for rs_cs in lc_concep_sobret loop
         ln_item := ln_item + 1;
         insert into tt_rh_cmps_hrs_concep (item, concep)
            values (ln_item, rs_cs.concep);
      end loop;

      if trim(asi_concep_sobret_sab) <> trim('----') then
         ln_item := ln_item + 1;
         insert into tt_rh_cmps_hrs_concep (item, concep)
            values (ln_item, asi_concep_sobret_sab);
      end if;
      if trim(asi_concep_sobret_dom) <> trim('----') then
         ln_item := ln_item + 1;
         insert into tt_rh_cmps_hrs_concep (item, concep)
            values (ln_item, asi_concep_sobret_dom);
      end if;
      if trim(asi_concep_sobret_fer) <> trim('----') then
         ln_item := ln_item + 1;
         insert into tt_rh_cmps_hrs_concep (item, concep)
            values (ln_item, asi_concep_sobret_fer);
      end if;

      for rs_if in lc_inasistencia loop -- buscando la fehca de movimietno de las inasistencias
         ld_fec_movimiento := trunc(rs_if.fec_movim);
         for rs_mi in lc_movimiento loop -- buscando el tiempo de inasistencia
            ld_ini_falta := rs_mi.fec_desde;
            ld_fin_falta := rs_mi.fec_hasta;
            ln_tiempo_inasistencia := to_number(ld_fin_falta - ld_ini_falta) * 24;
            ln_tiempo_inas_pendiente := ln_tiempo_inasistencia; -- horas a compensar
            for rs_ct in lc_sobret_trab loop -- buscando los cocneptos de sobretiempo
               ls_concep := rs_ct.concep;
               for rs_st in lc_sobretiempo loop -- buscando los sobretirmpos
                  ld_fec_sobretiempo := rs_st.fec_movim;
                  ln_tiempo_sobretiempo := rs_st.horas_sobret; -- horas de sobretiempo
                  if ln_tiempo_inas_pendiente > 0 then
                     if ln_tiempo_inas_pendiente > ln_tiempo_sobretiempo then
                        ln_tiempo_inas_pendiente := ln_tiempo_inas_pendiente - ln_tiempo_sobretiempo;
                        ln_tiempo_sobretiempo := 0;
                     else
                        if ln_tiempo_inas_pendiente < ln_tiempo_sobretiempo then
                           ln_tiempo_sobretiempo := ln_tiempo_sobretiempo - ln_tiempo_inas_pendiente;
                           ln_tiempo_inas_pendiente := 0;
                        else
                           ln_tiempo_inas_pendiente := 0;
                           ln_tiempo_sobretiempo := 0;
                        end if;
                     end if;

                     -- actualizanod inasistencias
                     if ln_tiempo_inas_pendiente = 0 then
                        delete from inasistencia i
                           where i.cod_trabajador = ls_cod_trabajador
                              and i.fec_desde = ld_ini_falta;
                     else
                        ld_fec_turno := ld_fin_periodo;

                        select nvl(min(a.turno), '----')
                              into ls_turno
                              from asistencia a
                              where trunc(a.fec_movim) = trunc(ld_fec_movimiento)
                                 and trim(a.cod_trabajador) = trim(ls_cod_trabajador)
                                 and trim(a.cod_tipo_mov) = trim(asi_cod_tipo_mov);

                        while ls_turno = '----' loop
                           select nvl(min(a.turno), '----')
                              into ls_turno
                              from asistencia a
                              where trunc(a.fec_movim) = trunc(ld_fec_turno)
                                 and trim(a.cod_trabajador) = trim(ls_cod_trabajador)
                                 and trim(a.cod_tipo_mov) = trim(asi_cod_tipo_mov);

                           ld_fec_turno := ld_fec_turno - 1;

                           if ld_fec_turno < ld_ini_periodo then
                              select min(a.turno)
                                 into ls_turno
                                 from asistencia a
                                 where trim(a.cod_trabajador) = trim(ls_cod_trabajador)
                                 and trim(a.cod_tipo_mov) = trim(asi_cod_tipo_mov);
                           end if;
                           end loop;

                        select t.sabado, t.domingo
                           into ls_sabado, ls_domingo
                           from tt_rh_comp_hora t
                           where trunc(t.fecha) = trunc(ld_fec_movimiento);

                        if ls_sabado = '1' then
                           select t.hora_ini_cmps_sab, t.hora_fin_cmps_sab
                              into ld_ini_turno, ld_fin_turno
                              from turno t
                              where trim(t.turno) = trim(ls_turno);
                        else
                           if ls_domingo = '1' then
                              select t.hora_ini_cmps_dom, t.hora_fin_cmps_dom
                                 into ld_ini_turno, ld_fin_turno
                                 from turno t
                                 where trim(t.turno) = trim(ls_turno);
                           else
                              select t.hora_ini_cmps_norm, t.hora_fin_cmps_norm
                                 into ld_ini_turno, ld_fin_turno
                                 from turno t
                                 where trim(t.turno) = trim(ls_turno);
                           end if;
                        end if;

                        if ld_ini_turno > ld_fin_turno then
                           ld_fin_turno := to_date(to_char(ld_ini_falta, 'dd/mm/yyyy') || ' ' || to_char(ld_fin_turno, 'hh24:mi'), 'dd/mm/yyyy hh24:mi');
                        else
                           ld_fin_turno := to_date(to_char(ld_ini_falta + 1, 'dd/mm/yyyy') || ' ' || to_char(ld_fin_turno, 'hh24:mi'), 'dd/mm/yyyy hh24:mi');
                        end if;
                        ld_ini_turno := to_date(to_char(ld_ini_falta, 'dd/mm/yyyy') || ' ' || to_char(ld_ini_turno, 'hh24:mi'), 'dd/mm/yyyy hh24:mi');

                        ln_jornada_laboral := to_number(ld_fin_turno - ld_ini_turno);

                        ld_new_fec_hasta := ld_ini_falta + (ln_tiempo_inas_pendiente / 24);
                        ln_new_dias_inasist := round(round(to_number(ld_new_fec_hasta - ld_ini_falta), 4) / ln_jornada_laboral,2);

                        update inasistencia i
                           set i.fec_hasta = ld_new_fec_hasta,
                               i.dias_inasist = ln_new_dias_inasist
                            where i.cod_trabajador = ls_cod_trabajador
                              and i.fec_desde = ld_ini_falta
                              and trim(i.tipo_doc) = trim(asi_tipo_doc);
                     end if;

                     commit;

                     -- actualizando sobretiempos
                     if ln_tiempo_sobretiempo = 0 then
                        delete from sobretiempo_turno st
                           where st.cod_trabajador = ls_cod_trabajador
                              and trim(st.concep) = trim(ls_concep)
                              and st.fec_movim = ld_fec_sobretiempo
                              and trim(st.tipo_doc) = trim(asi_tipo_doc);
                     else
                        update sobretiempo_turno st
                           set st.horas_sobret = ln_tiempo_sobretiempo
                           where st.cod_trabajador = ls_cod_trabajador
                              and trim(st.concep) = trim(ls_concep)
                              and st.fec_movim = ld_fec_sobretiempo
                              and trim(st.tipo_doc) = trim(asi_tipo_doc);
                     end if;

                     commit;

                  end if;
               end loop;
            end loop;
         end loop;
      end loop;
   end loop;

   aio_msg := 0;
   return(aio_msg);

end usf_rh_comphr_compensa;
/

prompt
prompt Creating function USF_RH_COMPHR_INASIST
prompt =======================================
prompt
create or replace function cantabria.usf_rh_comphr_inasist (

   asi_cod_usr in string,
   asi_tipo_doc in string,
   adi_fec_movim in date,
   adi_ini in date,
   adi_fin in date,
   asi_inasist in string,
   asi_cod_tipo_mov in string

) return integer is ano_msg integer;

   ls_cod_trabajador maestro.cod_trabajador%type;
   ls_hora_ini char(5);
   ls_hora_fin char(5);
   ls_sabado char(1);
   ls_domingo char(1);
   ls_feriado char(1);
   ls_inasistencia  char(1);

   ld_fecha_falta date;
   ld_ini_turno date;
   ld_fin_turno date;
   ld_new_fin date;

   ln_horas_jornada number;
   ln_horas_inas number;
   ln_dias_inasist number;
   ln_cuenta number;
   ld_new_ini date;


   cursor lc_asistencia is
      select a.cod_trabajador, a.fec_desde, a.fec_hasta, a.fec_movim, a.turno
         from asistencia a
         where trunc(a.fec_movim) between trunc(adi_ini) and trunc(adi_fin)
            and trim(a.cod_tipo_mov) = trim(asi_cod_tipo_mov)
         order by a.cod_trabajador, a.fec_movim;

   cursor lc_trabajador is
      select distinct a.cod_trabajador, a.turno
         from asistencia a
         where a.fec_movim between trunc(adi_ini) and trunc(adi_fin)
            and trim(a.cod_tipo_mov) = trim(asi_cod_tipo_mov)
         order by a.cod_trabajador;

   cursor lc_faltas is
      select distinct t.fecha
         into ld_fin_turno
         from tt_rh_comp_hora t
         where trunc(t.fecha) not in (
            select trunc(a.fec_movim)
               from asistencia a
               where a.cod_trabajador = ls_cod_trabajador
                  and trim(a.cod_tipo_mov) = trim(asi_cod_tipo_mov))
         order by t.fecha;
begin
   ano_msg := 0;

   for rs_at in lc_asistencia loop

      -- definiendo tipo de dia
      select tcm.sabado, tcm.domingo, tcm.feriado, tcm.inasistencia
         into ls_sabado, ls_domingo, ls_feriado, ls_inasistencia
         from tt_rh_comp_hora tcm
         where trunc(tcm.fecha) = trunc(rs_at.fec_movim);

      if ls_sabado = '1' then
         -- definiendo hora de ingreso y salida en domingo
         select t.hora_ini_cmps_sab, t.hora_fin_cmps_sab
            into ld_ini_turno, ld_fin_turno
            from turno t
            where trim(t.turno) = trim(rs_at.turno);
      else
         if ls_domingo = '1' then
            -- definiendo hora de ingreso y salida en sabado
            select t.hora_ini_cmps_dom, t.hora_fin_cmps_dom
               into ld_ini_turno, ld_fin_turno
               from turno t
               where trim(t.turno) = trim(rs_at.turno);
         else
            -- definiendo hora de ingreso y salida en dias normales (no domingo ni sabado)
            select t.hora_ini_cmps_norm, t.hora_fin_cmps_norm
               into ld_ini_turno, ld_fin_turno
               from turno t
               where trim(t.turno) = trim(rs_at.turno);
         end if;
      end if;

      if ls_inasistencia = '1' then
         ls_hora_ini := to_char(ld_ini_turno, 'hh24:mi');
         ls_hora_fin := to_char(ld_fin_turno, 'hh24:mi');

         ld_ini_turno := to_Date(to_char(rs_at.fec_desde, 'dd/mm/yyyy') || ' ' || ls_hora_ini, 'dd/mm/yyyy hh24:mi');
         ld_fin_turno := to_Date(to_char(rs_at.fec_hasta, 'dd/mm/yyyy') || ' ' || ls_hora_fin, 'dd/mm/yyyy hh24:mi');

         ln_horas_inas := 0;

         ln_horas_jornada := round(to_number(ld_fin_turno - ld_ini_turno) * 24, 2);

         -- inasistencias antes de su hora de entrada
         if rs_at.fec_desde > ld_ini_turno then
            ln_horas_inas := ln_horas_inas + to_number(rs_at.fec_desde - ld_ini_turno);
            if ln_horas_inas > 0 then
               ld_new_ini := ld_ini_turno + ln_horas_inas;

               ln_dias_inasist := round(to_number(ld_new_ini - ld_ini_turno) * 24 , 2) / ln_horas_jornada;

               insert into inasistencia(cod_trabajador, concep, fec_desde, fec_hasta, fec_movim, cod_usr, tipo_doc, flag_replicacion, dias_inasist)
                  values (rs_at.cod_trabajador, asi_inasist, ld_ini_turno, ld_new_ini, trunc(rs_at.fec_movim), asi_cod_usr, asi_tipo_doc, '1', ln_dias_inasist);
            end if;
         end if;

         -- inasistencias antes de su hora de salida
         if rs_at.fec_hasta < ld_fin_turno then
            ln_horas_inas := to_number(ld_fin_turno - rs_at.fec_hasta);
            if ln_horas_inas > 0 then
               ld_new_fin := ld_fin_turno - ln_horas_inas;

               ln_dias_inasist := round(to_number(ld_fin_turno - ld_new_fin) * 24 , 2) / ln_horas_jornada;

               insert into inasistencia(cod_trabajador, concep, fec_desde, fec_hasta, fec_movim, cod_usr, tipo_doc, flag_replicacion, dias_inasist)
                  values (rs_at.cod_trabajador, asi_inasist, ld_new_fin, ld_fin_turno, trunc(rs_at.fec_movim), asi_cod_usr, asi_tipo_doc, '1', ln_dias_inasist);
            end if;
         end if;
      end if;
   end loop;

   select count(distinct a.cod_trabajador)
      into ln_cuenta
      from asistencia a
      where a.fec_movim between trunc(adi_ini) and trunc(adi_fin)
         and trim(a.cod_tipo_mov) = trim(asi_cod_tipo_mov)
      order by a.cod_trabajador;

   for rs_ap in lc_trabajador loop -- fata el dia completo a trabajar
      ls_cod_trabajador := rs_ap.cod_trabajador;

      for rs_fp in lc_faltas loop

         ld_fecha_falta := trunc(rs_fp.fecha);

         select tcm.sabado, tcm.domingo, tcm.feriado, tcm.inasistencia
            into ls_sabado, ls_domingo, ls_feriado, ls_inasistencia
            from tt_rh_comp_hora tcm
            where trunc(tcm.fecha) = trunc(ld_fecha_falta);

         if ls_inasistencia = '1' then
            if ls_sabado = '1' then
               -- definiendo hora de ingreso y salida en domingo
               select t.hora_inicio_sab, t.hora_fin_cmps_sab
                  into ld_ini_turno, ld_fin_turno
                  from turno t
                  where trim(t.turno) = trim(rs_ap.turno);
            else
               if ls_domingo = '1' then
                  -- definiendo hora de ingreso y salida en sabado
                  select t.hora_inicio_dom, t.hora_fin_cmps_dom
                     into ld_ini_turno, ld_fin_turno
                     from turno t
                     where trim(t.turno) = trim(rs_ap.turno);
               else
                  -- definiendo hora de ingreso y salida en dias normales (no domingo ni sabado)
                  select t.hora_ini_cmps_norm, t.hora_fin_cmps_norm
                     into ld_ini_turno, ld_fin_turno
                     from turno t
                     where trim(t.turno) = trim(rs_ap.turno);
               end if;
            end if;

            ls_hora_ini := to_char(ld_ini_turno, 'hh24:mi');
            ls_hora_fin := to_char(ld_fin_turno, 'hh24:mi');

            ld_ini_turno := to_Date(to_char(ld_fecha_falta, 'dd/mm/yyyy') || ' ' || ls_hora_ini, 'dd/mm/yyyy hh24:mi');
            ld_fin_turno := to_Date(to_char(ld_fecha_falta, 'dd/mm/yyyy') || ' ' || ls_hora_fin, 'dd/mm/yyyy hh24:mi');

            insert into inasistencia(cod_trabajador, concep, fec_desde, fec_hasta, fec_movim, cod_usr, tipo_doc, flag_replicacion, dias_inasist)
               values (ls_cod_trabajador, asi_inasist, ld_ini_turno, ld_fin_turno, ld_fecha_falta, asi_cod_usr, asi_tipo_doc, '1', 1);

         end if;
      end loop;
   end loop;

   commit;
   return(ano_msg);

exception
   when others then
   ano_msg := 1;
   return(ano_msg);

end usf_rh_comphr_inasist;
/

prompt
prompt Creating function USF_RH_COMPHR_SOBRET
prompt ======================================
prompt
create or replace function cantabria.usf_rh_comphr_sobret(
   asi_cod_usr in string,
   asi_tipo_doc in string,
   adi_fec_movim in date,
   adi_ini in date,
   adi_fin in date,
   asi_sobret_sabado in string,
   asi_sobret_domingo in string,
   asi_sobret_feriado in string,
   asi_cod_tipo_mov in string

) return integer is ano_msg integer;

   ls_hora_ini     char(5) ;
   ls_hora_fin     char(5) ;
   ld_ini          date ;
   ld_fin          date ;
   ln_valida       number;
   ln_acumulado    number;
   ln_horas_sobret number;
   ln_horas_pagar  number;
   ls_sabado       char(1);
   ls_domingo      char(1);
   ls_feriado      char(1) ;
   ls_sobretiempo  char(1) ;
   ls_concep concepto.concep%type;
   ls_cod_trabajador maestro.cod_trabajador%type;
   ln_count        number  ;

   cursor lc_asistencia is
      select a.cod_trabajador, a.fec_desde, a.fec_hasta, a.fec_movim, a.turno
         from asistencia a
         where trunc(a.fec_movim) between trunc(adi_ini) and trunc(adi_fin)
            and trim(a.cod_tipo_mov) = trim(asi_cod_tipo_mov);

   cursor lc_concep_sobret is
      select chd.concep, chd.nro_horas
         from rh_grp_cmp_hrs_det chd
         where chd.grp_cmps_hrs = (
            select cht.grp_cmps_hrs
              from rh_grp_cmp_hrs_trab cht
              where cht.cod_trabajador = ls_cod_trabajador)
         order by chd.item;

begin

   ano_msg := 0;

   for rs_at in lc_asistencia loop
      ls_cod_trabajador := rs_at.cod_trabajador;

      -- definiendo tipo de dia
      select tcm.sabado, tcm.domingo, tcm.feriado, tcm.sobretiempo
         into ls_sabado, ls_domingo, ls_feriado, ls_sobretiempo
         from tt_rh_comp_hora tcm
         where trunc(tcm.fecha) = trunc(rs_at.fec_movim);
      if ls_sobretiempo = '1' then
         if ls_sabado = '1' then
            -- definiendo hora de ingreso y salida en domingo
            select t.hora_ini_cmps_sab, t.hora_fin_cmps_sab
               into ld_ini, ld_fin
               from turno t
               where trim(t.turno) = trim(rs_at.turno);
         else
            if ls_domingo = '1' then
               -- definiendo hora de ingreso y salida en sabado
               select t.hora_ini_cmps_dom, t.hora_fin_cmps_dom
                  into ld_ini, ld_fin
                  from turno t
                  where trim(t.turno) = trim(rs_at.turno);
            else
               -- definiendo hora de ingreso y salida en dias normales (no domingo ni sabado)
               select t.hora_ini_cmps_norm, t.hora_fin_cmps_norm
                  into ld_ini, ld_fin
                  from turno t
                  where trim(t.turno) = trim(rs_at.turno);
            end if;
         end if;

         ls_hora_ini := to_char(ld_ini, 'hh24:mi');
         ls_hora_fin := to_char(ld_fin, 'hh24:mi');

         ld_ini := to_Date(to_char(rs_at.fec_desde, 'dd/mm/yyyy') || ' ' ||
ls_hora_ini, 'dd/mm/yyyy hh24:mi');
         ld_fin := to_Date(to_char(rs_at.fec_hasta, 'dd/mm/yyyy') || ' ' ||
ls_hora_fin, 'dd/mm/yyyy hh24:mi');

         ln_horas_sobret := 0;

         if ls_domingo = '1' then

            ln_horas_sobret := to_number(rs_at.fec_hasta - rs_at.fec_desde) * 24;

         else
            -- sobretiempo antes de su hora de entrada
            if rs_at.fec_desde < ld_ini then
               ln_horas_sobret := ln_horas_sobret + to_number(ld_ini -
rs_at.fec_desde);
            end if;

            -- sobretiempo antes de su hora de salida
            if rs_at.fec_hasta > ld_fin then
               ln_horas_sobret := ln_horas_sobret + to_number(rs_at.fec_hasta -
ld_fin);
            end if;

            ln_horas_sobret := ln_horas_sobret * 24;

         end if;

         if ln_horas_sobret > 0 then

            -- Definiendo cocnepto de pago
            if ls_sabado = '1' then
               --verificar registro
               select count(*) into ln_count from sobretiempo_turno
                where (cod_trabajador   = rs_at.cod_trabajador  ) and
(trunc(fec_movim) = trunc(rs_at.fec_movim)) and
                      (concep           = asi_sobret_sabado     ) ;

               if ln_count = 0 then
                  --sobretiempo en sabado
                  insert into sobretiempo_turno (cod_trabajador, fec_movim, concep,
horas_sobret, cod_usr, tipo_doc, flag_replicacion)
                       values (rs_at.cod_trabajador, trunc(rs_at.fec_movim),
asi_sobret_sabado, ln_horas_sobret, asi_cod_usr, asi_tipo_doc, '1');
               end if ;

            else
               if ls_domingo = '1' then
                  --verificar registro
                  select count(*) into ln_count from sobretiempo_turno
                   where (cod_trabajador   = rs_at.cod_trabajador  ) and
(trunc(fec_movim) = trunc(rs_at.fec_movim)) and
                         (concep           = asi_sobret_domingo    ) ;

                  if ln_count = 0 then
                     --sobretiempo de domingo
                     insert into sobretiempo_turno (cod_trabajador, fec_movim, concep,
horas_sobret, cod_usr, tipo_doc, flag_replicacion)
                     values (rs_at.cod_trabajador, trunc(rs_at.fec_movim),
asi_sobret_domingo, ln_horas_sobret, asi_cod_usr, asi_tipo_doc, '1');
                  end if ;
               else
                  if ls_feriado = '1' then
                     --verificar registro
                     select count(*) into ln_count from sobretiempo_turno
                      where (cod_trabajador   = rs_at.cod_trabajador  ) and
(trunc(fec_movim) = trunc(rs_at.fec_movim)) and
                            (concep           = asi_sobret_feriado    ) ;

                      if ln_count = 0 then
                         --sobretiempo en feriado
                         insert into sobretiempo_turno (cod_trabajador, fec_movim,
concep, horas_sobret, cod_usr, tipo_doc, flag_replicacion)
                         values (rs_at.cod_trabajador, trunc(rs_at.fec_movim),
asi_sobret_feriado, ln_horas_sobret, asi_cod_usr, asi_tipo_doc, '1');
                      end if ;
                  else
                     --sobretiempo en dia orfinario
                     for rs_cs in lc_concep_sobret loop
                        if ln_horas_sobret > 0 then
                           if rs_cs.nro_horas < ln_horas_sobret then
                              ln_horas_pagar := rs_cs.nro_horas;
                              ln_horas_sobret := ln_horas_sobret - rs_cs.nro_horas;
                           else
                              ln_horas_pagar := ln_horas_sobret;
                              ln_horas_sobret := 0;
                           end if;

                           select count(*)
                              into ln_valida
                              from sobretiempo_turno st
                              where trim(st.cod_trabajador) =
trim(rs_at.cod_trabajador)
                                 and trunc(st.fec_movim) = trunc(rs_at.fec_movim)
                                 and trim(st.concep) = trim(rs_cs.concep);

                           if ln_valida = 0 then
                              insert into sobretiempo_turno (cod_trabajador,
fec_movim, concep, horas_sobret, cod_usr, tipo_doc, flag_replicacion)
                                 values (rs_at.cod_trabajador, trunc(rs_at.fec_movim),
rs_cs.concep, ln_horas_pagar, asi_cod_usr, asi_tipo_doc, '1');
                           else
                              select nvl(sum(st.horas_sobret), 0)
                                 into ln_acumulado
                                 from sobretiempo_turno st
                                 where trim(st.cod_trabajador) =
trim(rs_at.cod_trabajador)
                                    and trunc(st.fec_movim) = trunc(rs_at.fec_movim)
                                    and trim(st.concep) = trim(rs_cs.concep);

                              ln_horas_pagar := ln_horas_pagar + ln_acumulado;

                              update sobretiempo_turno st
                                 set st.horas_sobret = ln_horas_pagar
                                 where trim(st.cod_trabajador) =
trim(rs_at.cod_trabajador)
                                    and trunc(st.fec_movim) = trunc(rs_at.fec_movim)
                                    and trim(st.concep) = trim(rs_cs.concep);
                           end if;
                        end if;
                     end loop;
                  end if;
               end if;
            end if;
         end if;
      end if;
   end loop;
   commit;
   return(ano_msg);

exception
   when others then
   ano_msg := 1;
   RAISE_APPLICATION_ERROR(-20000,  SQLERRM );
   return(ano_msg);

end usf_rh_comphr_sobret;
/

prompt
prompt Creating function USF_RH_FECHA_CERRADA
prompt ======================================
prompt
create or replace function cantabria.usf_rh_fecha_cerrada (
       pi_fec in date,
       pi_codtra in MAESTRO.COD_TRABAJADOR%type 
       
) RETURN varchar2 IS

v_feccal       date;
v_fec          date;
v_tiptra       rrhh_param_org.tipo_trabajador%type;
v_codori       maestro.cod_origen%type;
v_cont         pls_integer;

BEGIN

    /* 
     3 = trabajador no existe
     2 = fecha solicitada no esta parametrizada
     1 = fecha cerrada
     0 = fecha abierta
    */
    
    if pi_codtra is null then
        RAISE_APPLICATION_ERROR(-20000, 'Debe especificar un codigo de trabajador, por favor verifique!');
    end if;
    
    begin
        select tipo_trabajador, cod_origen
          into v_tiptra, v_codori
          from maestro
         where cod_trabajador = pi_codtra;
         
    exception
      when NO_DATA_FOUND then
          RAISE_APPLICATION_ERROR(-20000, 'Código de Trabajador ' || pi_codtra || ', por favor verifique!');
    end;
    
    v_fec := trunc(pi_fec);
    
    if v_fec is null then
        v_fec := trunc(sysdate);
    end if;

    begin    
        select fec_proceso
          into v_feccal
          from rrhh_param_org
         where origen = v_codori
           and trunc(fec_inicio) <= v_fec
           and trunc(fec_final) >= v_fec 
           and tipo_trabajador = v_tiptra
           and rownum = 1;
    exception
      when NO_DATA_FOUND then
        RAISE_APPLICATION_ERROR(-20000, 'No existe fecha de calculo en tabla de parametros de fecha, por favor verifique! '
                                  || chr(13) || ' Fecha: ' || to_char(v_fec, 'dd/mm/yyyy')
                                  || chr(13) || ' Tipo de Trabajador: ' || v_tiptra);
    end;
    
    select count(1)
      into v_cont
      from historico_calculo
     where cod_trabajador = pi_codtra
       and fec_calc_plan  = v_feccal;
    
    if v_cont = 0 then
        return '0';
    else
        return '1';
    end if;

END;
/

prompt
prompt Creating function USF_RH_FIN_PERIODO_PRUEBA
prompt ===========================================
prompt
create or replace function cantabria.usf_rh_fin_periodo_prueba(
       adi_fec_inicio      in date,
       ani_periodo_prueba  in number,
       asi_dias_meses      in varchar2
) return date is
  ln_Result date;
begin
  case 
      when substr(upper(asi_dias_meses),1,1) = 'D' then
           ln_Result := adi_fec_inicio + ani_periodo_prueba;
      when substr(upper(asi_dias_meses),1,1) = 'M' then
           ln_Result := ADD_MONTHS(adi_fec_inicio, ani_periodo_prueba);
      ELSE 
           ln_Result := adi_fec_inicio;
  end case;
  
  return(ln_Result);
end usf_rh_fin_periodo_prueba;
/

prompt
prompt Creating function USF_RH_GANANCIA_FIJA
prompt ======================================
prompt
create or replace function cantabria.usf_rh_ganancia_fija (
  as_cod_trabajador in maestro.cod_trabajador%type )
  return varchar2 is

ln_monto number ;

begin

select sum(g.imp_gan_desc)
into ln_monto
from gan_desct_fijo g
where g.cod_trabajador=as_cod_trabajador
  and substr(g.concep,1,1)='1' ;

  return(ln_monto) ;

