prompt
prompt Creating function USF_RH_IS_DIA_DESCANSO
prompt ========================================
prompt
create or replace function cantabria.USF_RH_IS_DIA_DESCANSO(
       asi_trabajador IN maestro.cod_trabajador%TYPE,
       adi_fecha      IN DATE
) return boolean is
  lb_Result           BOOLEAN := FALSE;  -- Por defecto es falso
  ln_count            NUMBER;
  ls_flag_dia_fijo    grp_dia_descanso.flag_dia_dijo%TYPE;
  ln_dia_descanso     grp_dia_descanso.dia_descanso%TYPE;

begin

  -- Esta funcion determina si la fecha enviada como parametro es dia de descanso para el tabajador
  SELECT COUNT(*)
    INTO ln_count
    FROM grp_dia_descanso a,
         grp_dia_descanso_trabaj b
   WHERE a.cod_grupo = b.cod_grupo
     AND b.cod_trabajador = asi_trabajador;

  IF ln_count = 0 THEN
     -- Si no hay registros entonces la fecha por defecto es el dia domingo (1)
     IF to_number(to_char(adi_fecha, 'd')) = 1 THEN
        lb_Result := TRUE;
     END IF;
  ELSIF ln_count > 1 THEN
     RAISE_APPLICATION_ERROR(-20000, 'El trabajador no puede estar en mas de un grupo, por favor verificar');
  ELSE
     SELECT a.flag_dia_dijo, a.dia_descanso
       INTO ls_flag_dia_fijo, ln_dia_descanso
       FROM grp_dia_descanso a,
            grp_dia_descanso_trabaj b
      WHERE a.cod_grupo = b.cod_grupo
        AND b.cod_trabajador = asi_trabajador;

     IF ls_flag_dia_fijo = '1' THEN
        -- si el flag fijo es 1 entonces tieie un dia fijo
        IF to_number(to_char(adi_fecha, 'd')) = ln_dia_descanso THEN
           lb_Result := TRUE;
        END IF;
     ELSE
        -- Si el flag es '0' entonces el dia fijo esta en la tabla grp_dia_descanso_fechas
        SELECT COUNT(*)
          INTO ln_count
          FROM grp_dia_descanso_fechas a,
               grp_dia_descanso_trabaj b
         WHERE a.cod_grupo      = b.cod_grupo
           AND b.cod_trabajador = asi_trabajador
           AND a.fecha          = adi_fecha;

        IF ln_count > 0 THEN
           lb_Result := TRUE;
        END IF;
     END IF;
  END IF;

  return(lb_Result);
end USF_RH_IS_DIA_DESCANSO;
/

prompt
prompt Creating function USF_RH_IS_DIA_DESCANSO_INT
prompt ============================================
prompt
create or replace function cantabria.USF_RH_IS_DIA_DESCANSO_INT(
       asi_trabajador IN maestro.cod_trabajador%TYPE,
       adi_fecha      IN DATE
) return number is
  ln_Result number;
begin
  
  if usf_rh_is_dia_descanso(asi_trabajador, adi_Fecha) then
     ln_Result := 1;
  else
     ln_Result := 0;  
  end if;
  
  return(ln_Result);
end USF_RH_IS_DIA_DESCANSO_INT;
/

prompt
prompt Creating function USF_RH_IS_DIA_FERIADO
prompt =======================================
prompt
create or replace function cantabria.usf_rh_is_dia_feriado(
       asi_origen in origen.cod_origen%TYPE,
       adi_fecha  in date
) return boolean is
  lb_Result boolean;
  ln_count  number;
begin
  SELECT COUNT(*)
     INTO ln_count
     FROM calendario_feriado cf
    WHERE cf.origen = asi_origen
      AND cf.mes    = to_number(to_char(adi_fecha, 'mm'))
      AND cf.dia    = to_number(to_char(adi_fecha, 'dd'));

  if ln_count > 0 then
     lb_Result := true;
  else
     lb_Result := false;
  end if;
  return(lb_Result);
end usf_rh_is_dia_feriado;
/

prompt
prompt Creating function USF_RH_LIQ_DIAS_TRUNCOS
prompt =========================================
prompt
create or replace function cantabria.usf_rh_liq_dias_truncos (
  ad_fec_desde in date, ad_fec_hasta in date ) return number is

ld_fec_inicio           date ;
ln_sw                   integer ;
ln_nro_dias             number(5,2) ;
ln_dias                 number(5,2) ;

begin

--  **********************************************************************
--  ***   CALCULA DIAS TRUNCAS - C.T.S. VACACIONES Y GRATIFICACIONES   ***
--  **********************************************************************

ld_fec_inicio := trunc(ad_fec_desde) ;

ln_sw := 0 ; ln_nro_dias := 0 ;
for x in 1 .. 100 loop

  if to_char(ld_fec_inicio,'mm/yyyy') = to_char(ad_fec_hasta,'mm/yyyy') then
    if to_number(to_char(ad_fec_hasta,'dd')) >= to_number(to_char(ld_fec_inicio,'dd')) and
       ln_sw = 0 then
      if to_number(to_char(ad_fec_hasta,'dd')) > 30 then
        ln_dias := 30 ;
      elsif to_char(ad_fec_hasta,'dd/mm') = '29/02' then
        ln_dias := 30 ;
      elsif to_char(ad_fec_hasta,'dd/mm') = '28/02' then
        ln_dias := 30 ;
      else
        ln_dias := to_number(to_char(ad_fec_hasta,'dd')) ;
      end if ;
      ln_nro_dias := ln_nro_dias + ( ln_dias - to_number(to_char(ld_fec_inicio,'dd')) ) + 1 ;
    else
      if to_number(to_char(ad_fec_hasta,'dd')) > 30 then
        ln_dias := 30 ;
      else
        ln_dias := to_number(to_char(ad_fec_hasta,'dd')) ;
      end if ;
      ln_nro_dias := ln_nro_dias +  ln_dias ;
    end if ;
    exit ;
  end if ;

  if ln_sw = 0 then
    if to_char(ld_fec_inicio,'dd') = '01' then
      ln_nro_dias := 30 ;
    else
      ln_nro_dias := ( 30 - to_number(to_char(ld_fec_inicio,'dd')) ) + 1 ;
    end if ;
    ln_sw := 1 ;
  else
    ln_nro_dias := ln_nro_dias + 30 ;
  end if ;

  ld_fec_inicio := add_months(ld_fec_inicio,1) ;

end loop ;

return(ln_nro_dias) ;

end usf_rh_liq_dias_truncos ;
/

prompt
prompt Creating function USF_RH_NOMBRE_TRABAJADOR
prompt ==========================================
prompt
create or replace function cantabria.usf_rh_nombre_trabajador (
  as_cod_trabajador in maestro.cod_trabajador%type )
  return varchar2 is

ls_cadena varchar2(100) ;

begin

select rtrim(apel_paterno)||' '||rtrim(apel_materno)||' '||
       nvl(rtrim(nombre1),' ')||' '||nvl(rtrim(nombre2),' ')
  into ls_cadena
  from maestro
  where cod_trabajador = as_cod_trabajador ;

  return(ls_cadena) ;

end usf_rh_nombre_trabajador;
/

prompt
prompt Creating function USF_RH_NRO_DIAS_TT
prompt ====================================
prompt
create or replace function cantabria.usf_rh_nro_dias_tt(
       asi_codtra in maestro.cod_trabajador%TYPE,
       adi_fecha1 in date,
       adi_fecha2 in date
) return number is
  ln_Result number;
begin
  select NVL(sum(s.dias_trabaj),0)
       into ln_Result 
       from (select distinct hc.dias_trabaj, hc.fec_calc_plan
               from historico_calculo hc
              where hc.cod_trabajador = asi_codtra
                and hc.dias_trabaj  is not null
                and trunc(hc.fec_calc_plan) between adi_fecha1 and adi_fecha2) s;
  
  if ln_Result > adi_fecha2 - adi_Fecha1 + 1 then
     ln_Result := adi_Fecha2 - adi_fecha1;
  end if;       
  
  return(ln_Result);
end usf_rh_nro_dias_tt;
/

prompt
prompt Creating function USF_RH_RESULT_EVAL_TRABAJADOR
prompt ===============================================
prompt
create or replace function cantabria.usf_rh_result_eval_trabajador (
  an_ano in number, an_mes in number, as_codigo maestro.cod_trabajador%type)
  return number is

ln_cont         number ;
ln_cont_scalif  number;
ln_result       number;
Begin
--No interesa quien lo evaluo
Select count(*)
  into ln_cont
  from rrhh_eval_trab_desempeno e
 where e.ano = an_ano
   and e.mes = an_mes
   and e.cod_trabajador = as_codigo;

If ln_cont = 0 then
   Return(null);
end if;

-- Registros sin calificar
Select count(*)
  into ln_cont_scalif
  from rrhh_eval_trab_desempeno e
 where e.ano = an_ano
   and e.mes = an_mes
   and e.cod_trabajador = as_codigo
   and e.calif_valor is null;

If ln_cont_scalif > 0 then
   Return(null);
end if;

-- Si no ha retornado entonces ya esta evaluado
Select sum((Nvl(c.porcentaje,0)/100)*e.calif_valor)
  into ln_result
  from rrhh_eval_trab_desempeno e, rrhh_calificacion_desempeno c
 where e.condes = c.condes
   and e.calif_concepto = c.calif_concepto
   and e.ano = an_ano
   and e.mes = an_mes
   and e.cod_trabajador = as_codigo;


return(ln_result) ;

end usf_rh_result_eval_trabajador ;
/

prompt
prompt Creating function USF_RH_SALDOS_DISPONIBLES_CTS
prompt ===============================================
prompt
create or replace function cantabria.usf_rh_saldos_disponibles_cts (
  as_cod_trabajador in char ) return number is

ln_verifica          integer ;
ld_min_fecha         date ;
ld_max_fecha         date ;
ln_max_factor        number(9,6) ;
ln_fac_prdo          number(9,6) ;
ln_fac_emplear       number(9,6) ;
ln_deposito          number(13,2) ;
ln_interes           number(13,2) ;
ln_adelantos         number(13,2) ;
ln_int_adel          number(13,2) ;
ln_saldos            number(13,2) ;

--  Cursor para halar saldo disponible
cursor c_saldos is
  select c.fec_prdo_dpsto, c.imp_prdo_dpsto
  from cnta_crrte_cts c
  where c.cod_trabajador = as_cod_trabajador
  order by c.cod_trabajador, c.fec_prdo_dpsto ;

--  Lectura de adelantos a cuenta de C.T.S. para calculo de intereses
cursor c_adelantos is
  select a.fec_proceso, a.imp_a_cuenta
  from adel_cnta_cts a
  where a.cod_trabajador = as_cod_trabajador
  order by a.cod_trabajador, a.fec_proceso ;

begin

--  **********************************************************
--  ***   DETERMINA SALDO DISPONIBLE AL 50% DE LA C.T.S.   ***
--  **********************************************************

--  Determina factor de C.T.S. a la ultima fecha
ld_max_fecha := null ; ln_max_factor := 0 ;
select max(f.fec_calc_int) into ld_max_fecha from factor_planilla f ;
select nvl(f.fact_cts,0) into ln_max_factor from factor_planilla f
  where trunc(f.fec_calc_int) = trunc(ld_max_fecha) ;

--  Verifica saldos disponible del 50% del trabajador
ln_deposito := 0 ; ln_interes := 0 ;
for rc_s in c_saldos loop
  ln_verifica := 0 ;
  select count(*) into ln_verifica from factor_planilla f
    where trunc(f.fec_calc_int) = (trunc(rc_s.fec_prdo_dpsto) - 1) ;
  if ln_verifica > 0 then
    select nvl(f.fact_cts,0) into ln_fac_prdo from factor_planilla f
      where trunc(f.fec_calc_int) = (trunc(rc_s.fec_prdo_dpsto) - 1) ;
  else
    select min(f.fec_calc_int) into ld_min_fecha from factor_planilla f ;
    select nvl(f.fact_cts,0) into ln_fac_prdo from factor_planilla f
      where trunc(f.fec_calc_int) = trunc(ld_min_fecha) ;
  end if ;
  ln_fac_emplear := (nvl(ln_max_factor,0) / nvl(ln_fac_prdo,0)) - 1 ;
  ln_deposito    := ln_deposito + (nvl(rc_s.imp_prdo_dpsto,0) / 2 ) ;
  ln_interes     := ln_interes + (nvl(rc_s.imp_prdo_dpsto,0) / 2 * nvl(ln_fac_emplear,0)) ;
end loop ;

--  Determina adelantos a cuenta de C.T.S.
ln_adelantos := 0 ; ln_int_adel := 0 ;
for rc_ade in c_adelantos loop
  select nvl(f.fact_cts,0) into ln_fac_prdo from factor_planilla f
    where trunc(f.fec_calc_int) = trunc(rc_ade.fec_proceso) ;
  ln_fac_emplear  := (nvl(ln_max_factor,0) / nvl(ln_fac_prdo,0)) - 1 ;
  ln_adelantos    := ln_adelantos + nvl(rc_ade.imp_a_cuenta,0) ;
  ln_int_adel     := ln_int_adel + (nvl(rc_ade.imp_a_cuenta,0) * nvl(ln_fac_emplear,0)) ;
end loop ;

ln_saldos := (ln_deposito + ln_interes) - (ln_adelantos + ln_int_adel) ;

return (ln_saldos) ;

end usf_rh_saldos_disponibles_cts ;
/

prompt
prompt Creating function USF_RH_STATUS_EVAL_TRABAJADOR
prompt ===============================================
prompt
create or replace function cantabria.usf_rh_status_eval_trabajador (
  an_ano in number, an_mes in number, as_codigo maestro.cod_trabajador%type)
  return char is

ln_cont         number ;
ln_cont_scalif  number;
ln_cont_aprob   number;
ls_status       char(1);
Begin
-- Status:
-- 0 No Evaluado
-- 1 Evaluado Parcial
-- 2 Evaluado Pero No Aprobado
-- 3 Evaluado ok(Aprobado)
--No interesa quien lo evaluo
Select count(*)
  into ln_cont
  from rrhh_eval_trab_desempeno e
 where e.ano = an_ano
   and e.mes = an_mes
   and e.cod_trabajador = as_codigo;

If ln_cont = 0 then
   ls_status := '0';
   Return(ls_status);
end if;

-- Registros sin calificar
Select count(*)
  into ln_cont_scalif
  from rrhh_eval_trab_desempeno e
 where e.ano = an_ano
   and e.mes = an_mes
   and e.cod_trabajador = as_codigo
   and e.calif_valor is null;

If ln_cont_scalif > 0 then
   ls_status := '1';
   Return(ls_status);
end if;

-- Registros Aprobados
Select count(*)
  into ln_cont_aprob
  from rrhh_eval_trab_desempeno e
 where e.ano = an_ano
   and e.mes = an_mes
   and e.cod_trabajador = as_codigo
   and e.flag_estado = '1';

If ln_cont_aprob > 0 then
   ls_status := '3';
   Return(ls_status);
else
   ls_status := '2';
   Return(ls_status);
end if;


--return(ln_faltas) ;

end usf_rh_status_eval_trabajador ;
/

prompt
prompt Creating function USF_RRHH_CADENA_TIEMPO
prompt ========================================
prompt
create or replace function cantabria.usf_rrhh_cadena_tiempo
(ac_cadena Varchar2)
 return Varchar2 is
  Result Varchar2(5);
begin

  Result := Trim(ac_cadena) ;

  IF Instr(Result,':',1) = 0 THEN
     Result := Result || ':00' ;
  END IF ;

  IF length(Trim(Substr(Result,Instr(Result,':',1) + 1))) = 1 THEN

     Result := Result || '0' ;
  ELSE
     Result := Result ;
  END IF ;


  return(Result);
end usf_rrhh_cadena_tiempo;
/

prompt
prompt Creating function USF_RRHH_DESCRIPCION_UBICACION
prompt ================================================
prompt
create or replace function cantabria.USF_RRHH_DESCRIPCION_UBICACION
(ac_cod_pais   in ciudad.cod_pais%type    ,
 ac_cod_dep    in ciudad.cod_dpto%type    ,
 ac_cod_prov   in ciudad.cod_prov%type    ,
 ac_cod_dist   in distrito.cod_distr%type ,
 ac_cod_ciudad in ciudad.cod_ciudad%type  ,
 ac_tipo       in char )

  return varchar2 is
  Result varchar2 (30);

begin

  if ac_tipo = '1'    then --pais
     select p.nom_pais into result from pais p where (p.cod_pais = ac_cod_pais) ;
  elsif ac_tipo = '2' then --departamento
     select dp.desc_dpto into result  from departamento_estado dp where (dp.cod_pais = ac_cod_pais) and
                                                                        (dp.cod_dpto = ac_cod_dep ) ;
  elsif ac_tipo = '3' then --provincia
     select pc.desc_prov into result from provincia_condado pc where (pc.cod_pais = ac_cod_pais ) and
                                                                     (pc.cod_dpto = ac_cod_dep  ) and
                                                                     (pc.cod_prov = ac_cod_prov ) ;
  elsif ac_tipo = '4' then --distrito
     select d.desc_distrito into result from distrito d where (d.cod_pais  = ac_cod_pais ) and
                                                              (d.cod_dpto  = ac_cod_dep  ) and
                                                              (d.cod_prov  = ac_cod_prov ) and
                                                              (d.cod_distr = ac_cod_dist ) ;
  elsif ac_tipo = '5' then --ciudad
     select cd.descr_ciudad into result from ciudad cd where (cd.cod_pais   = ac_cod_pais   ) and
                                                             (cd.cod_dpto   = ac_cod_dep    ) and
                                                             (cd.cod_prov   = ac_cod_prov   ) and
                                                             (cd.cod_ciudad = ac_cod_ciudad ) ;

  end if;





  return(Result);
end USF_RRHH_DESCRIPCION_UBICACION;
/

prompt
prompt Creating function USF_RRHH_FECHA_LIC
prompt ====================================
prompt
create or replace function cantabria.USF_RRHH_FECHA_LIC
(ac_anomes         in varchar2                     ,
 ac_cod_trabajador in maestro.cod_trabajador%type  ,
 ac_origen         in maestro.cod_origen%type      ,
 ac_ttrab          in maestro.tipo_trabajador%type ) return date is
  Result date;

ld_fecha_inicio Date ;
ld_fecha_final  Date ;

ln_count        Number ;

begin

--busco informacion en el historico
select Count(*) into ln_count from historico_calculo hc
 where (hc.cod_trabajador                   = ac_cod_trabajador ) and
       (to_char(hc.fec_calc_plan,'yyyymm')  = ac_anomes         ) ;

if ln_count = 0 then

    select Min(i.fec_desde) into Result from inasistencia i
     where (i.concep in (select concepto_calc from grupo_calculo_det gcd where gcd.grupo_calculo = '803') ) and
           (i.cod_trabajador = ac_cod_trabajador       ) and
           (to_char(i.fec_desde,'yyyymm') = ac_anomes  )
   group by i.cod_trabajador       ;
else

   select Min(hi.fec_desde) into Result from historico_inasistencia hi
    where (hi.concep in (select concepto_calc from grupo_calculo_det gcd where gcd.grupo_calculo = '803') ) and
          (hi.cod_trabajador = ac_cod_trabajador      ) and
          (to_char(hi.fec_desde,'yyyymm') = ac_anomes )
   group by hi.cod_trabajador       ;

end if ;


  return(Result);
end USF_RRHH_FECHA_LIC;
/

prompt
prompt Creating function USF_RRHH_FECHA_LICENCIA
prompt =========================================
prompt
create or replace function cantabria.USF_RRHH_FECHA_LICENCIA
(ad_fecha_proceso  in date                         ,
 ac_cod_trabajador in maestro.cod_trabajador%TYPE       ,
 ac_origen         in maestro.cod_origen%type      ,
 ac_ttrab          in maestro.tipo_trabajador%type ) return date is
  Result date;

ld_fecha_inicio Date ;
ld_fecha_final  Date ;
ld_fecha_min    Date ;
/*Cursor c_licencia is
select Min(i.fec_desde) as fecha_inicio from inasistencia i
 where (i.concep in (select concepto_calc from grupo_calculo_det gcd where gcd.grupo_calculo = '515') ) and
       (i.cod_trabajador = ac_cod_trabajador                  ) and
       (i.fec_movim between ld_fecha_inicio and ld_fecha_final)
group by i.cod_trabajador       ;*/
begin

select fec_inicio,fec_final into ld_fecha_inicio,ld_fecha_final from  rrhh_param_org rhp
 where trunc(rhp.fec_proceso) = ad_fecha_proceso and rhp.origen = ac_origen and tipo_trabajador = ac_ttrab ;


select Min(i.fec_desde) into ld_fecha_min from inasistencia i
 where (i.concep in (select concepto_calc from grupo_calculo_det gcd where gcd.grupo_calculo = '515') ) and
       (i.cod_trabajador = ac_cod_trabajador                  ) and
       (i.fec_movim between ld_fecha_inicio and ld_fecha_final)
group by i.cod_trabajador       ;



  return(Result);
end USF_RRHH_FECHA_LICENCIA;
/

