prompt
create or replace function cantabria.USF_RRHH_FECHA_VAC
(ac_anomes         in varchar2                     ,
 ac_cod_trabajador in maestro.cod_trabajador%type  ,
 ac_origen         in maestro.cod_origen%type      ,
