ld_fecha_inicio Date ;
ld_fecha_final  Date ;

ln_count        Number ;

begin

--busco informacion en el historico
select Count(*) into ln_count from historico_calculo hc
 where (hc.cod_trabajador = ac_cod_trabajador ) and
       (to_char(hc.fec_calc_plan,'yyyymm')  = ac_anomes  ) ;

if ln_count = 0 then
    select Min(i.fec_desde) into Result from inasistencia i
     where (i.concep in (select concepto_calc from grupo_calculo_det gcd where gcd.grupo_calculo = '515') ) and
