prompt
prompt Creating function USF_RRHH_MONTO_CTS
prompt ====================================
prompt
create or replace function cantabria.usf_rrhh_monto_cts (ac_cod_trabajador  in maestro.cod_trabajador%type  ,
                                               ac_tipo_trabajador in maestro.tipo_trabajador%type ,
                                               ad_fecha_inicio in date,ad_fecha_final in date)
return Number is
  Result Number (13,2);


lc_tipo_trip tipo_trabajador.tipo_trabajador%type ;

Cursor c_tripulantes_cts is
select Sum(c.liquidacion) as monto from cts_decreto_urgencia c
 where (c.cod_trabajador = ac_cod_trabajador                            ) and
       (trunc(c.fec_proceso) between ad_fecha_inicio and ad_fecha_final )
Group by c.cod_trabajador       ;


Cursor c_trabajadores is
select Sum(Nvl(p.prov_cts_01,0) + Nvl(p.prov_cts_02,0) + Nvl(p.prov_cts_03,0) + Nvl(p.prov_cts_04,0) + Nvl(p.prov_cts_05,0) + Nvl(p.prov_cts_06,0)) as monto
 from prov_cts_gratif p
where (p.cod_trabajador = ac_cod_trabajador)
group by p.cod_trabajador ;

begin

result := 0.00 ;

select r.tipo_trab_tripulante into lc_tipo_trip from rrhhparam r where reckey = '1' ;

if ac_tipo_trabajador = lc_tipo_trip then
  For rc_tripulante in c_tripulantes_cts Loop
      result := rc_tripulante.monto ;
  End Loop ;
else
  For rc_trabajadores in c_trabajadores Loop
      result := rc_trabajadores.monto ;
  End Loop ;
end if ;

  return(Result);
end ;
/

prompt
prompt Creating function USF_RRHH_NUM_MAESTRO
prompt ======================================
prompt
create or replace function cantabria.USF_RRHH_NUM_MAESTRO(
       asi_origen origen.cod_origen%type
)return varchar2 is

  ls_ult_nro maestro.cod_trabajador%type ;
  ln_ult_nro num_maestro.ult_nro%type ;
  
  ln_count   number;
begin
  -- Verifico si hay un numerador para ese origen
  select count(*)
    into ln_count
    from num_maestro np
   where (np.origen = asi_origen);
   
  if ln_count = 0 then
     RAISE_APPLICATION_ERROR(-20000, 'NO EXISTE UN NUMERADOR PARA EL ORIGEN ' || asi_origen 
                                     || ', POR FAVOR VERIFIQUE');
  end if;
  --numerador de detraccion
  select NVL(np.ult_nro,0)
    into ln_ult_nro
    from num_maestro np
   where (np.origen = asi_origen)
   for update;

  --se concatena con origen
  ls_ult_nro := rtrim(ltrim(to_char(ln_ult_nro))) ;
  
  
  --actualiza informacion e numeradores
  update num_maestro np
     set np.ult_nro = ln_ult_nro + 1
   where (np.origen = asi_origen ) ;

  return(ls_ult_nro);

end USF_RRHH_NUM_MAESTRO ;
/

prompt
prompt Creating function USF_RRHH_NUM_SUBSIDIO
prompt =======================================
prompt
create or replace function cantabria.USF_RRHH_NUM_SUBSIDIO
(ac_cod_origen origen.cod_origen%type)

 return varchar2 is
  lc_ult_nro_op rrhh_subsidio.nro_subsidio%type ;

ln_ult_nro num_subsidio_rrhh.ult_nro%type ;

begin
  --numerador de detraccion
  select np.ult_nro
    into ln_ult_nro
    from num_subsidio_rrhh np
   where (np.origen = ac_cod_origen)
   for update nowait;

  --se concatena con origen
  lc_ult_nro_op := rtrim(ltrim(ac_cod_origen))||LPAD(rtrim(ltrim(to_char(ln_ult_nro))),8,'0') ;

  --actualiza informacion e numeradores
  update num_subsidio_rrhh np
     set np.ult_nro = Nvl(np.ult_nro,0) + 1
   where (np.origen = ac_cod_origen ) ;

  return(lc_ult_nro_op);

end USF_RRHH_NUM_SUBSIDIO ;
/

