prompt
prompt Creating function USF_SALDO_TOTAL_X_ALM
prompt =======================================
prompt
create or replace function cantabria.usf_saldo_total_x_alm(

       asi_cod_art   in articulo.cod_art%TYPE,
       asi_almacen   in almacen.almacen%TYPE

) return number is
  Result number;

BEGIN

  select sum(NVL(aa.sldo_total,0)+ nvl(aa.sldo_consignacion,0))
    into Result
    from articulo_Almacen aa
   where aa.cod_art = asi_cod_Art
     and aa.almacen = asi_almacen;

  return(Result);

end usf_saldo_total_x_alm;
