prompt
prompt Creating function USF_SIG_CC_PORC_IGV
prompt =====================================
prompt
create or replace function cantabria.usf_sig_cc_porc_igv(
       as_tipo_doc         cntas_cobrar_det.tipo_doc%type,
       as_nro_doc          cntas_cobrar_det.nro_doc%type,
       an_item         cntas_cobrar_det.item%type
 ) return number is

  ln_count             number;
  ln_tasa_impuesto     impuestos_tipo.tasa_impuesto%type ;
begin

  ln_tasa_impuesto := 0 ;

  SELECT count(*)
  INTO ln_count
  FROM cc_doc_det_imp cc
  WHERE cc.tipo_doc = as_tipo_doc AND
        cc.nro_doc = as_nro_doc AND
        cc.item = an_item ;

  IF ln_count > 0 THEN
      SELECT i.tasa_impuesto
        INTO ln_tasa_impuesto
        FROM cc_doc_det_imp cc, impuestos_tipo i
       WHERE cc.tipo_impuesto = i.tipo_impuesto AND
             cc.tipo_doc = as_tipo_doc AND
             cc.nro_doc = as_nro_doc AND
             cc.item = an_item ;
  END IF ;

  return(ln_tasa_impuesto);

end usf_sig_cc_porc_igv;
/

prompt
prompt Creating function USF_SIG_CNTA_COB_PEND_X_CODREL
prompt ================================================
prompt
create or replace function cantabria.usf_sig_cnta_cob_pend_x_codrel(
       as_codrel         cntas_cobrar_det.tipo_doc%type,
       as_moneda         cntas_cobrar_det.nro_doc%type
 ) return number is

  ln_count             number;
  ln_total             number;
  ls_soles             moneda.cod_moneda%type ;
begin

  SELECT count(*)
    INTO ln_count
    from cntas_cobrar cc, doc_pendientes_cta_cte dp
   where (cc.cod_relacion = dp.cod_relacion and
         cc.tipo_doc = dp.tipo_doc and
         cc.nro_doc = dp.nro_doc) and
         cc.flag_estado<>'0' and
         (dp.cod_relacion = as_codrel) and
         cc.nro_libro = (select f.libro_ventas from finparam f where reckey='1') and
         (dp.fecha_vencimiento < = sysdate) and
        ((dp.cod_moneda=(select l.cod_soles from logparam l where reckey='1') and dp.sldo_sol > 0) or
         (dp.cod_moneda=(select l.cod_dolares from logparam l where reckey='1') and dp.saldo_dol > 0)) ;

  IF ln_count > 0 THEN
      SELECT l.cod_soles
        INTO ls_soles
        FROM logparam l
       WHERE l.reckey='1' ;

      IF as_moneda=ls_soles THEN
          select sum(dp.sldo_sol*dp.factor)
            into ln_total
            from cntas_cobrar cc, doc_pendientes_cta_cte dp
           where (cc.cod_relacion = dp.cod_relacion and
                 cc.tipo_doc = dp.tipo_doc and
                 cc.nro_doc = dp.nro_doc) and
                 cc.flag_estado<>'0' and
                 (dp.cod_relacion = as_codrel) and
                 cc.nro_libro = (select f.libro_ventas from finparam f where reckey='1') and
                 (dp.fecha_vencimiento < = sysdate) and
                 dp.sldo_sol > 0 ;
      ELSE
          select sum(dp.saldo_dol*dp.factor)
            into ln_total
            from cntas_cobrar cc, doc_pendientes_cta_cte dp
           where (cc.cod_relacion = dp.cod_relacion and
                 cc.tipo_doc = dp.tipo_doc and
                 cc.nro_doc = dp.nro_doc) and
                 cc.flag_estado<>'0' and
                 (dp.cod_relacion = as_codrel) and
                 cc.nro_libro = (select f.libro_ventas from finparam f where reckey='1') and
                 (dp.fecha_vencimiento < = sysdate) and
                 dp.saldo_dol > 0 ;
      END IF;
  END IF ;

  return(ln_total);

end usf_sig_cnta_cob_pend_x_codrel;
/

prompt
prompt Creating function USF_SIG_FECHA_PERIODO
prompt =======================================
prompt
create or replace function cantabria.usf_sig_fecha_periodo
(ad_fecha  in date,
 ac_tipo   in cntbl_asiento.flag_estado%type,
 ac_inicio in cntbl_asiento.flag_estado%type )

-- ac_tipo => M=Mensual, T=Trimestre, A=Acumulado
-- ac_inicio => I=Inicio, F=Final
return date is

ld_fecha    date ;
lc_mes      char(2) ;
lc_ano      char(4) ;

BEGIN

select trim(to_char( ad_fecha,'mm')) into lc_mes from dual ;

select trim(to_char( ad_fecha,'yyyy')) into lc_ano from dual ;

select trunc(ad_fecha,'month') into ld_fecha from dual ;

IF ac_tipo='M' THEN
   select trunc(ad_fecha,'month') into ld_fecha from dual ;

ELSIF ac_tipo='T' THEN
  -- Rango de fechas trimestrales

  IF to_number(lc_mes) < 4 THEN
    -- Primer trimestre
    IF ac_inicio='I' THEN
       ld_fecha := to_date( '01/01/'|| lc_ano ,'dd/mm/yyyy');
    ELSE
       ld_fecha := ad_fecha ;
    END IF ;
  --
  ELSIF to_number(lc_mes) > 3 AND to_number(lc_mes) < 7 THEN
   	-- Segundo trimestre
    IF ac_inicio='I' THEN
       ld_fecha := to_date( '01/01/'|| lc_ano ,'dd/mm/yyyy');
    ELSE
       ld_fecha := to_date( '31/03/'|| lc_ano ,'dd/mm/yyyy');
    END IF ;

  ELSIF to_number(lc_mes) > 6 AND to_number(lc_mes) < 10 THEN
  	-- Tercer trimestre
    IF ac_inicio = 'I' THEN
       ld_fecha := to_date( '01/04/'|| lc_ano ,'dd/mm/yyyy');
    ELSE
       ld_fecha := to_date( '30/06/'|| lc_ano ,'dd/mm/yyyy');
    END IF ;

  ELSIF to_number(lc_mes) > 9 AND to_number(lc_mes) < 12 THEN
  	-- Cuarto trimestre
    IF ac_inicio = 'I' THEN
       ld_fecha := to_date( '01/07/'|| lc_ano ,'dd/mm/yyyy');
    ELSE
       ld_fecha := to_date( '30/09/'|| lc_ano ,'dd/mm/yyyy');
    END IF ;

  ELSE

      IF ac_inicio = 'I' THEN
       ld_fecha := to_date( '01/10/'|| lc_ano ,'dd/mm/yyyy');
    ELSE
       ld_fecha := to_date( '31/12/'|| lc_ano ,'dd/mm/yyyy');
    END IF ;
  END IF ;

ELSIF ac_tipo='A' THEN
  select trunc(ad_fecha,'year') into ld_fecha from dual ;

END IF ;

RETURN(ld_fecha);

end usf_sig_fecha_periodo ;
/

prompt
prompt Creating function USF_SIG_PEND_ENTREGA_PRODUCTO
prompt ===============================================
prompt
create or replace function cantabria.usf_sig_pend_entrega_producto(
 as_cod_art       in articulo.cod_art%type,
 as_cod_origen    in origen.cod_origen%type ) return number is

  ln_cantidad   number;
  ln_count      number;
  ls_doc_ov     doc_tipo.tipo_doc%type ;

BEGIN

select doc_ov into ls_doc_ov from logparam where reckey='1' ;

SELECT count(*)
  INTO ln_count
  FROM articulo_mov_proy amp, almacen al, articulo a
 WHERE amp.almacen = al.almacen and
       al.cod_origen = as_cod_origen and
       amp.cod_art = a.cod_art and
       amp.cod_art = as_cod_art and
       amp.tipo_doc = ls_doc_ov and
       amp.flag_estado='1' ;

ln_cantidad := 0 ;

IF ln_count > 0 THEN
    SELECT sum(amp.cant_proyect-amp.cant_procesada)
      INTO ln_cantidad
      FROM articulo_mov_proy amp, almacen al, articulo a
 WHERE amp.almacen = al.almacen and
       al.cod_origen = as_cod_origen and
       amp.cod_art = a.cod_art and
       amp.cod_art = as_cod_art and
       amp.tipo_doc = ls_doc_ov and
       amp.flag_estado='1' ;
END IF ;

RETURN(ln_cantidad );

end usf_sig_pend_entrega_producto ;
/

prompt
prompt Creating function USF_SIG_SDO_ART_ALM_ANT
prompt =========================================
prompt
create or replace function cantabria.USF_SIG_SDO_ART_ALM_ANT(
        as_cod_art in articulo.cod_art%TYPE,
        as_almacen in almacen.almacen%TYPE,
        ad_fecha   in date,
        as_val_ret in char
) return number is

  ln_sldo_total   articulo_almacen.sldo_total%TYPE;
  ln_ret          number;   -- Valor de retorno
  ln_pus          number;   -- Precio Unitario en Soles
  ln_cps          articulo_almacen.costo_prom_sol%TYPE;   -- Precio Promedio Dolares
  ln_sldo_und2    articulo_almacen.sldo_total_und2%TYPE;   -- Saldo Total 2 Unidad

/*
   funcion que retorna un dato referente al saldo de un mes.
   Parametros:  mes anterior
                cod. articulo
                valor retorno ( S = Saldo
                                L = Soles
                                2UND = Saldo Total en 2Und
*/

  Cursor c1(as_codigo in char) is
    Select vm.fec_registro,
           vm.tipo_mov,
           am.cod_art,
           am.cant_procesada,
           am.precio_unit,
           am.cod_moneda ,
           am.decuento,
           am.cant_proc_und2,
           NVL(amt.flag_ajuste_valorizacion, '0') as flag_ajuste_valorizacion,
           NVL(amt.factor_sldo_total, 0) as factor_sldo_total
      from vale_mov          vm,
           articulo_mov      am,
           articulo_mov_tipo amt
     Where vm.cod_origen = am.cod_origen
       and vm.nro_vale   = am.nro_vale
       and amt.tipo_mov  = vm.tipo_mov
       and vm.flag_estado <> '0'
       and am.flag_estado <> '0'
       and am.cod_art = as_codigo
       and vm.almacen = as_almacen
       and trunc( vm.fec_registro) <= trunc(ad_fecha)
    order by vm.fec_registro;


begin
  -- encuentra el saldo de acuerdo los movimientos
  ln_sldo_total := 0;
  ln_cps        := 0;
  ln_sldo_und2  := 0;

  for rc1 in c1(as_cod_art) loop
      if rc1.factor_sldo_total = 1 and rc1.flag_ajuste_valorizacion = '0' then
         -- Ingresos, Costo promedio
         ln_pus := rc1.precio_unit;

         -- Calculo del costo promedio
         if (ln_sldo_total + NVL(rc1.cant_procesada,0)) <> 0 then
              ln_cps := ((abs(ln_sldo_total) * ln_cps) + (NVL(rc1.cant_procesada,0) * ln_pus))/
                        (abs(ln_sldo_total) + NVL(rc1.cant_procesada,0));
         end if;
         ln_sldo_total := ln_sldo_total + NVL(rc1.cant_procesada,0);
         ln_sldo_und2  := ln_sldo_und2 + NVL(rc1.cant_proc_und2, 0);

      elsif rc1.flag_ajuste_valorizacion = '1' then

         if ln_sldo_total <> 0 then
            ln_cps := (abs(ln_sldo_total) * ln_cps + ln_pus * rc1.factor_sldo_total )/abs(ln_sldo_total);
         end if;

      elsif rc1.factor_sldo_total = -1 and rc1.flag_ajuste_valorizacion = '0' then
         -- Salidas
         ln_sldo_total := ln_sldo_total - NVL(rc1.cant_procesada,0);
         ln_sldo_und2  := ln_sldo_und2 - NVL(rc1.cant_proc_und2,0);
      end if;
  end loop;

  if as_val_ret = 'S' then         -- saldo Total
     ln_ret := ln_sldo_total;
  elsif as_val_ret = '2UND' then   -- Saldo en Segunda Unidad
     ln_ret := ln_sldo_und2;
  elsif as_val_ret = 'L' then   --Soles
     ln_ret := ln_cps;
  else
     ln_ret := 0;
  end if;

  return(ln_ret);
end USF_SIG_SDO_ART_ALM_ANT;
/

prompt
prompt Creating function USF_SIG_STK_FISICO_PROD_FECHA
prompt ===============================================
prompt
create or replace function cantabria.usf_sig_stk_fisico_prod_fecha(
 as_cod_art       in articulo.cod_art%type,
 as_cod_origen    in origen.cod_origen%type,
 ad_fecha         in date ) return number is

ln_cantidad        number;


BEGIN

SELECT nvl(sum( decode(amt.factor_sldo_total, 1, nvl(am.cant_procesada,0), nvl(am.cant_procesada,0)*-1)),0)
  INTO ln_cantidad
  FROM vale_mov vm, articulo_mov am, articulo_mov_tipo amt, almacen a
 WHERE ( vm.cod_origen = am.cod_origen and
        vm.nro_vale = am.nro_vale )
   AND ( vm.tipo_mov = amt.tipo_mov )
   AND ( vm.almacen = a.almacen )
   AND ( vm.flag_estado <> '0' and
         am.flag_estado <> '0' and
         am.cod_origen = as_cod_origen and
         am.cod_art = as_cod_art and
         a.flag_tipo_almacen = 'T' and
         amt.flag_ajuste_valorizacion='0' And
         a.cod_origen = as_cod_origen)
   AND (trunc(vm.fec_registro) <= trunc(ad_fecha) ) ;

RETURN(ln_cantidad );

end usf_sig_stk_fisico_prod_fecha ;
/

prompt
prompt Creating function USF_SIG_STK_TRANSITO_PRODUCTO
prompt ===============================================
prompt
create or replace function cantabria.usf_sig_stk_transito_producto(
 as_cod_art       in articulo.cod_art%type,
 as_cod_origen    in origen.cod_origen%type ) return number is

  Result        number;
  ln_cantidad   number;
  ln_count      number;

BEGIN

SELECT count(*)
  INTO ln_count
  FROM articulo_mov_proy amp
 WHERE amp.cod_art = as_cod_art
   AND amp.cod_origen = as_cod_origen
   AND amp.tipo_doc=(select l.doc_otr from logparam l where reckey='1')
   AND amp.tipo_mov=(select oper_sal_otr from logparam where reckey='1')
   AND amp.flag_estado='1'
   AND ( nvl(amp.cant_procesada,0) - nvl(amp.cant_facturada,0) ) > 0 ;

ln_cantidad := 0 ;

IF ln_count > 0 THEN
    SELECT sum(NVL(amp.cant_procesada,0) - NVL(amp.cant_facturada,0) )
      INTO ln_cantidad
      FROM articulo_mov_proy amp
     WHERE amp.cod_art = as_cod_art
       AND amp.cod_origen = as_cod_origen
       AND amp.tipo_doc=(select l.doc_otr from logparam l where reckey='1')
       AND amp.tipo_mov=(select oper_sal_otr from logparam where reckey='1')
       AND amp.flag_estado='1'
       AND ( nvl(amp.cant_procesada,0) - nvl(amp.cant_facturada,0) ) > 0 ;
END IF ;

RETURN(ln_cantidad );

end usf_sig_stk_transito_producto ;
/

prompt
prompt Creating function USF_SIG_STOCK_FISICO_PRODUCTO
prompt ===============================================
prompt
create or replace function cantabria.usf_sig_stock_fisico_producto(
 as_cod_art       in articulo.cod_art%type,
 as_cod_origen    in origen.cod_origen%type ) return number is

  Result        number;
  ln_cantidad   number;
  ln_count      number;

BEGIN

SELECT count(*)
  INTO ln_count
  FROM articulo_almacen aa, almacen a
 WHERE aa.almacen = a.almacen
   AND a.flag_tipo_almacen='T'
   AND aa.cod_art = as_cod_art
   AND a.cod_origen = as_cod_origen ;

ln_cantidad := 0 ;

IF ln_count > 0 THEN
    SELECT sum(nvl(aa.sldo_total,0))
      INTO ln_cantidad
      FROM articulo_almacen aa, almacen a
     WHERE aa.almacen = a.almacen
       AND a.flag_tipo_almacen='T'
       AND aa.cod_art = as_cod_art
       AND a.cod_origen = as_cod_origen ;
END IF ;

RETURN(ln_cantidad );

end usf_sig_stock_fisico_producto ;
/

prompt
prompt Creating function USF_SIG_TIPO_DESPACHO_CC
prompt ==========================================
prompt
create or replace function cantabria.usf_sig_tipo_despacho_cc
(ac_cod_relacion in cntas_cobrar.cod_relacion%type,
 ac_tipo_doc     in cntas_cobrar.tipo_doc%type,
 ac_nro_doc      in cntas_cobrar.nro_doc%type )

  return char is

  ls_nro_orden  orden_venta.nro_ov%type ;
  ls_origen_ref origen.cod_origen%type ;
  ls_doc_ref    doc_tipo.tipo_doc%type ;
  ls_nro_ref    cntas_cobrar.nro_doc%type ;
  ls_doc_ov     doc_tipo.tipo_doc%type ;
  ls_doc_gr     doc_tipo.tipo_doc%type ;
  ls_despacho   forma_embarque.forma_embarque%type ;
  ln_count      number ;
BEGIN

ls_despacho := '00' ;

SELECT count(*)
INTO ln_count
FROM doc_referencias dr
WHERE dr.cod_relacion = ac_cod_relacion AND
      dr.tipo_doc = ac_tipo_doc AND
      dr.nro_doc = ac_nro_doc ;

SELECT l.doc_ov
 INTO ls_doc_ov
 FROM logparam l
WHERE l.reckey='1' ;

SELECT l.doc_gr
 INTO ls_doc_gr
 FROM logparam l
WHERE l.reckey='1' ;

IF ln_count > 0 THEN

   SELECT distinct(dr.tipo_ref)
     INTO ls_doc_ref
     FROM doc_referencias dr
    WHERE dr.cod_relacion = ac_cod_relacion AND
          dr.tipo_doc = ac_tipo_doc AND
          dr.nro_doc = ac_nro_doc ;

   IF ls_doc_ref = ls_doc_gr THEN

      SELECT count(*)
        INTO ln_count
        FROM orden_venta o, vale_mov v,
             guia_vale gv, doc_referencias dr, cntas_cobrar cc
       WHERE ( o.nro_ov =v.nro_refer and
               v.tipo_refer=ls_doc_ov ) and
             ( v.cod_origen=gv.origen_vale and
               v.nro_vale=gv.nro_vale ) and
             ( gv.origen_guia = dr.origen_ref and
               gv.nro_guia = dr.nro_ref and
               dr.tipo_ref = ls_doc_gr ) and
             ( dr.cod_relacion = cc.cod_relacion and
               dr.tipo_doc = cc.tipo_doc and
               dr.nro_doc = cc.nro_doc ) and
             ( cc.cod_relacion = ac_cod_relacion AND
               cc.tipo_doc = ac_tipo_doc AND
               cc.nro_doc = ac_nro_doc ) ;

       IF ln_count > 0 THEN
       SELECT distinct(MAX(o.nro_ov))
         INTO ls_nro_orden
         FROM orden_venta o, vale_mov v,
              guia_vale gv, doc_referencias dr, cntas_cobrar cc
        WHERE ( o.nro_ov =v.nro_refer and
                v.tipo_refer=ls_doc_ov ) and
              ( v.cod_origen=gv.origen_vale and
                v.nro_vale=gv.nro_vale ) and
              ( gv.origen_guia = dr.origen_ref and
                gv.nro_guia = dr.nro_ref and
                dr.tipo_ref = ls_doc_gr ) and
               ( dr.cod_relacion = cc.cod_relacion and
                 dr.tipo_doc = cc.tipo_doc and
                 dr.nro_doc = cc.nro_doc ) and
              cc.cod_relacion = ac_cod_relacion AND
              cc.tipo_doc = ac_tipo_doc AND
              cc.nro_doc = ac_nro_doc ;
       ELSE
          return(ls_despacho);
       END IF ;
   ELSIF ls_doc_ref = ls_doc_ov THEN
         SELECT distinct(MAX(dr.nro_ref))
           INTO ls_nro_orden
           FROM doc_referencias dr
          WHERE dr.cod_relacion = ac_cod_relacion AND
                dr.tipo_doc = ac_tipo_doc AND
                dr.nro_doc = ac_nro_doc AND
                dr.tipo_ref = 'OV' ;
   END IF ;

   IF NVL(ls_nro_orden,' ') <> ' ' THEN
       -- Buscando la condicion de traslado
       SELECT count(*)
         INTO ln_count
         FROM orden_venta o
        WHERE o.nro_ov = ls_nro_orden ;
       IF ln_count > 0 THEN
           SELECT o.forma_embarque
             INTO ls_despacho
             FROM orden_venta o
            WHERE o.nro_ov = ls_nro_orden ;
        ELSE
          RETURN(ls_despacho) ;
        END IF ;
   END IF ;

END IF ;

RETURN(ls_despacho);

end usf_sig_tipo_despacho_cc ;
/

prompt
prompt Creating function USF_SIG_TRASLADO_PRODUCTO
prompt ===========================================
prompt
create or replace function cantabria.usf_sig_traslado_producto(
 as_cod_art       in articulo.cod_art%type,
 as_cod_origen    in origen.cod_origen%type,
 ad_fecha_ini     in date,
 ad_fecha_fin     in date ) return number Is

  ln_cantidad   Number;
  ln_count      number;

BEGIN

SELECT count(*)
  INTO ln_count
  From orden_traslado ot, articulo_mov_proy amp,
       articulo_mov am, vale_mov vm, articulo_mov_tipo amt
 Where ot.nro_otr             = amp.nro_doc
   And amp.cod_origen         = am.origen_mov_proy
   And amp.nro_mov            = am.nro_mov_proy
   And am.cod_origen          = vm.cod_origen
   And am.nro_vale            = vm.nro_vale
   And vm.tipo_mov            = amt.tipo_mov
   And amp.tipo_doc           = (select l.doc_otr from logparam l where reckey='1')
   And vm.fec_registro        >= ad_fecha_ini
   And vm.fec_registro        <= ad_fecha_fin
   And vm.cod_origen          = as_cod_origen
   And amp.cod_art            = as_cod_art
   And amt.factor_sldo_total  = -1;

ln_cantidad := 0 ;

IF ln_count > 0 Then

     Select sum(am.cant_procesada)
       Into ln_cantidad
       From orden_traslado ot, articulo_mov_proy amp,
            articulo_mov am, vale_mov vm, articulo_mov_tipo amt
      Where ot.nro_otr             = amp.nro_doc
        And amp.cod_origen         = am.origen_mov_proy
        And amp.nro_mov            = am.nro_mov_proy
        And am.cod_origen          = vm.cod_origen
        And am.nro_vale            = vm.nro_vale
        And vm.tipo_mov            = amt.tipo_mov
        And amp.tipo_doc           = (select l.doc_otr from logparam l where reckey='1')
        And vm.fec_registro        >= ad_fecha_ini
        And vm.fec_registro        <= ad_fecha_fin
        And vm.cod_origen          = as_cod_origen
        And vm.flag_estado         <> '0'
        And amp.cod_art            = as_cod_art
        And amt.factor_sldo_total  = -1;

END IF ;

RETURN(ln_cantidad );

end usf_sig_traslado_producto ;
/

prompt
prompt Creating function USF_SIG_VENTA_PRODUCTO
prompt ========================================
prompt
create or replace function cantabria.usf_sig_venta_producto(
 as_origen        in origen.cod_origen%type,
 as_cod_art       in articulo.cod_art%type,
 ad_fecha_ini     in date,
 ad_fecha_fin     in date ) return number is

  ln_cantidad   number;
  ln_count      number;

BEGIN

   SELECT count(*)
     INTO ln_count
     FROM cntas_cobrar cc, cntas_cobrar_det ccd, articulo a
    WHERE cc.tipo_doc      = ccd.tipo_doc and
          cc.nro_doc       = ccd.nro_doc and
          ccd.cod_art      = a.cod_art and
          cc.origen        = as_origen and
          cc.flag_estado   <> '0' And
          ccd.cod_art      = as_cod_art and
          trunc(cc.fecha_registro) BETWEEN trunc(ad_fecha_ini) and trunc(ad_fecha_fin) ;

ln_cantidad := 0 ;

IF ln_count > 0 Then

   SELECT sum(nvl(ccd.cantidad,0))
     INTO ln_cantidad
     FROM cntas_cobrar cc, cntas_cobrar_det ccd, articulo a
    WHERE cc.tipo_doc      = ccd.tipo_doc and
          cc.nro_doc       = ccd.nro_doc and
          ccd.cod_art      = a.cod_art and
          cc.origen        = as_origen and
          cc.flag_estado   <> '0' And
          ccd.cod_art      = as_cod_art and
          trunc(cc.fecha_registro) BETWEEN trunc(ad_fecha_ini) and trunc(ad_fecha_fin);

END IF ;

RETURN(ln_cantidad );

end usf_sig_venta_producto ;
/

prompt
prompt Creating function USF_SUMAR_SALDO_CNTA
prompt ======================================
prompt
create or replace function cantabria.usf_sumar_saldo_cnta(
     an_ano       in cntbl_cnta_sdo.ano%type,
     an_mes       in cntbl_cnta_sdo.mes%type,
     as_cuenta    in cntbl_cnta_sdo.cnta_ctbl%type,
     as_flag      in cntbl_asiento_det.flag_debhab%type,
     adc_impsol   in cntbl_asiento_det.imp_movsol%type,
     adc_impdol   in cntbl_asiento_det.imp_movdol%type,
     adc_impaju   in cntbl_asiento_det.imp_movaju%type)
return number is

 ln_rc number := 0;
 ldc_sldo_soldeb       cntbl_cnta_sdo.sldo_soldeb%type ;
 ldc_sldo_solhab       cntbl_cnta_sdo.sldo_solhab%type ;
 ldc_sldo_doldeb       cntbl_cnta_sdo.sldo_doldeb%type ;
 ldc_sldo_dolhab       cntbl_cnta_sdo.sldo_dolhab%type ;
 ldc_sldo_ajudeb       cntbl_cnta_sdo.sldo_ajudeb%type ;
 ldc_sldo_ajuhab       cntbl_cnta_sdo.sldo_ajuhab%type ;
 ldc_sldo_acusoldeb    cntbl_cnta_sdo.sldo_acusoldeb%type ;
 ldc_sldo_acusolhab    cntbl_cnta_sdo.sldo_acusolhab%type ;
 ldc_sldo_acudoldeb    cntbl_cnta_sdo.sldo_acudoldeb%type ;
 ldc_sldo_acudolhab    cntbl_cnta_sdo.sldo_acudolhab%type ;

begin
-------------------------------------
-- Edgar Morante Miercoles 10Jul2002, replicacion
If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
    return 0;
end if;

-- Verifica si existe cuenta contable
select count(*)
  into ln_rc
  from cntbl_cnta
 where cnta_ctbl = as_cuenta ;

IF ln_rc < 1 then
   return( ln_rc );
END IF;
--------------------------------------

-- Verifica si existe Registro de Saldo
select count(*)
  into ln_rc
  from cntbl_cnta_sdo
 where (ano = an_ano and
        mes = an_mes and
        cnta_ctbl = as_cuenta) ;
-- lectura de saldo mensual de la cuenta si existe el registro
IF ln_rc > 0 THEN
   select sldo_soldeb, sldo_solhab,
          sldo_doldeb, sldo_dolhab,
          sldo_ajudeb, sldo_ajuhab,
          sldo_acusoldeb, sldo_acusolhab,
          sldo_acudoldeb, sldo_acudolhab
     into ldc_sldo_soldeb, ldc_sldo_solhab,
          ldc_sldo_doldeb, ldc_sldo_dolhab,
          ldc_sldo_ajudeb, ldc_sldo_ajuhab,
          ldc_sldo_acusoldeb, ldc_sldo_acusolhab,
          ldc_sldo_acudoldeb, ldc_sldo_acudolhab
     from cntbl_cnta_sdo
     where (ano = an_ano and
           mes = an_mes and
           cnta_ctbl = as_cuenta)  for update ;
else
   ldc_sldo_soldeb := 0;
   ldc_sldo_solhab := 0;
   ldc_sldo_doldeb := 0;
   ldc_sldo_dolhab := 0;
   ldc_sldo_ajudeb := 0; ldc_sldo_ajuhab := 0;
   ldc_sldo_acusoldeb := 0; ldc_sldo_acusolhab := 0;
   ldc_sldo_acudoldeb := 0; ldc_sldo_acudolhab := 0;              
END IF ;
-- Calculo de Nuevos saldos
IF Upper(as_flag) = 'D' THEN
   ldc_sldo_soldeb    := NVL(ldc_sldo_soldeb,0) + NVL(adc_impsol,0) ;
   ldc_sldo_doldeb    := NVL(ldc_sldo_doldeb,0) + NVL(adc_impdol,0) ;
   ldc_sldo_ajudeb    := NVL(ldc_sldo_ajudeb,0) + NVL(adc_impaju,0) ;
   ldc_sldo_acusoldeb := NVL(ldc_sldo_acusoldeb,0) + NVL(adc_impsol,0) ;
   ldc_sldo_acudoldeb := NVL(ldc_sldo_acudoldeb,0) + NVL(adc_impdol,0) ;
ELSE
   ldc_sldo_solhab    := NVL(ldc_sldo_solhab,0) + NVL(adc_impsol,0) ;
   ldc_sldo_dolhab    := NVL(ldc_sldo_dolhab,0) + NVL(adc_impdol,0) ;
   ldc_sldo_ajuhab    := NVL(ldc_sldo_ajuhab,0) + NVL(adc_impaju,0) ;
   ldc_sldo_acusolhab := NVL(ldc_sldo_acusolhab,0) + NVL(adc_impsol,0) ;
   ldc_sldo_acudolhab := NVL(ldc_sldo_acudolhab,0) + NVL(adc_impdol,0) ;
END IF ;

-- Actualizar CNTBL_CNTA_SDO si existe registro, si no crearlo
IF ln_rc > 0 THEN

/*****************************************************
**** REPLICACION
*****************************************************/
   Update cntbl_cnta_sdo
      set sldo_soldeb = nvl(ldc_sldo_soldeb,0),
          sldo_solhab = nvl(ldc_sldo_solhab,0),
          sldo_doldeb = nvl(ldc_sldo_doldeb,0),
          sldo_dolhab = nvl(ldc_sldo_dolhab,0),
          sldo_ajudeb = nvl(ldc_sldo_ajudeb,0),
          sldo_ajuhab = nvl(ldc_sldo_ajuhab,0),
          sldo_acusoldeb = nvl(ldc_sldo_acusoldeb,0),
          sldo_acusolhab = nvl(ldc_sldo_acusolhab,0),
          sldo_acudoldeb = nvl(ldc_sldo_acudoldeb,0),
          sldo_acudolhab = nvl(ldc_sldo_acudolhab,0),
          flag_replicacion = '0'
    where ano = an_ano and
          mes = an_mes and
          cnta_ctbl   = as_cuenta ;
/*****************************************************/
ELSE
/*****************************************************
**** REPLICACION
*****************************************************/
    INSERT INTO cntbl_cnta_sdo(
           ano, mes, cnta_ctbl,
           sldo_soldeb, sldo_solhab,
           sldo_doldeb,sldo_dolhab,
           sldo_ajudeb, sldo_ajuhab,
           sldo_acusoldeb,sldo_acusolhab,
           sldo_acudoldeb, sldo_acudolhab,
           flag_replicacion)
    VALUES(
           an_ano, an_mes, as_cuenta,
           nvl(ldc_sldo_soldeb,0), nvl(ldc_sldo_solhab,0),
           nvl(ldc_sldo_doldeb,0), nvl(ldc_sldo_dolhab,0),
           nvl(ldc_sldo_ajudeb,0), nvl(ldc_sldo_ajuhab,0),
           nvl(ldc_sldo_acusoldeb,0), nvl(ldc_sldo_acusolhab,0),
           nvl(ldc_sldo_acudoldeb,0), nvl(ldc_sldo_acudolhab,0),
           '0' );
/*****************************************************/
END IF ;
return( ln_rc );
end usf_sumar_saldo_cnta;
/

prompt
prompt Creating function USF_TC
prompt ========================
prompt
create or replace function cantabria.USF_TC
(ad_fecha in date,
 as_flag_tipo in char) return number is

Result calendario.vta_dol_prom%type;
-- Esta funcion devuelve el maximo tipo de cambio utilizado en un a?o y un mes determinado
Begin
      Select Decode(as_flag_tipo,'V',max(vta_dol_prom),'C',max(c.cmp_dol_prom))
        into Result
        from calendario c
       where to_char(fecha,'dd/mm/yyyy')= to_char(ad_fecha,'dd/mm/yyyy');

  Return(Result);

end USF_TC;
/

