prompt Creating function USF__TEMPO_500
prompt ================================
prompt
create or replace function cantabria.usf__tempo_500 return integer is
  Result integer;
  ln_contador integer;
  ln_tope integer;
begin
  ln_tope := 5000 ;
  For ln_contador in 1 .. ln_tope Loop
      Result := 1 ;
  End Loop;
  For ln_contador in 1 .. ln_tope Loop
      Result := 1 ;
  End Loop;
  return(Result);
end usf__tempo_500;
/

prompt
prompt Creating function USF_TOTALES_PROGRAMA_PAGOS_DOL
prompt ================================================
prompt
create or replace function cantabria.USF_TOTALES_PROGRAMA_PAGOS_DOL
(ac_nro_programa programacion_pagos.nro_prog_pago%type,ac_flag_estado in char)
 return number is
  Result number;
begin

SELECT SUM(DECODE (BC.COD_MONEDA,'US$',TT.IMPORTE,Round(TT.IMPORTE / TT.TASA_CAMBIO,2)))
  INTO Result
  FROM TT_FIN_PPDD TT,PROGRAMACION_PAGOS_DET PP,BANCO_CNTA BC
  WHERE (TT.NRO_PROG_PAGO = PP.NRO_PROG_PAGO   ) AND
        (TT.ITEM           = PP.ITEM            ) AND
        (PP.COD_CTABCO     = BC.COD_CTABCO      ) AND
       (PP.FLAG_ESTADO      = ac_flag_estado  ) AND
       (TT.NRO_PROG_PAGO    = AC_NRO_PROGRAMA ) ;


  IF Result IS NULL THEN
     Result := 0.00 ;
  END IF ;

  return(Result);
end USF_TOTALES_PROGRAMA_PAGOS_DOL ;
/

prompt
prompt Creating function USF_TOTALES_PROGRAMA_PAGOS_SOL
prompt ================================================
prompt
create or replace function cantabria.USF_TOTALES_PROGRAMA_PAGOS_SOL
(ac_nro_programa programacion_pagos.nro_prog_pago%type,ac_flag_estado in programacion_pagos_det.flag_estado%type)
 return number is
  Result number;
begin

SELECT SUM(DECODE (BC.COD_MONEDA,'S/.',TT.IMPORTE,Round(TT.IMPORTE * TT.TASA_CAMBIO,2)))
  INTO Result
  FROM TT_FIN_PPDD TT,PROGRAMACION_PAGOS_DET PP,BANCO_CNTA BC
  WHERE (TT.NRO_PROG_PAGO = PP.NRO_PROG_PAGO   ) AND
        (TT.ITEM           = PP.ITEM            ) AND
        (PP.COD_CTABCO     = BC.COD_CTABCO      ) AND
       (PP.FLAG_ESTADO      = ac_flag_estado  ) AND
       (TT.NRO_PROG_PAGO    = AC_NRO_PROGRAMA ) ;


  IF Result IS NULL THEN
     Result := 0.00 ;
  END IF ;

  return(Result);

end USF_TOTALES_PROGRAMA_PAGOS_SOL ;

