prompt
prompt Creating function USF_VEN_NUM_EMBARQUE
prompt ======================================
prompt
create or replace function cantabria.USF_VEN_NUM_EMBARQUE
(ac_cod_origen origen.cod_origen%type)

 return varchar2 is
  lc_ult_nro_op detraccion.nro_detraccion%type ;

ln_ult_nro num_detraccion.ult_nro%type ;

begin
  --numerador de detraccion
  select no.ult_nro
    into ln_ult_nro
    from num_embarque no
   where (no.origen = ac_cod_origen)
   for update nowait;

  --se concatena con origen
  lc_ult_nro_op := rtrim(ltrim(ac_cod_origen))||LPAD(rtrim(ltrim(to_char(ln_ult_nro))),8,'0') ;

  --actualiza informacion e numeradores
  update num_embarque no
     set no.ult_nro = Nvl(no.ult_nro,0) + 1
   where (no.origen = ac_cod_origen ) ;

  return(lc_ult_nro_op);
end USF_VEN_NUM_EMBARQUE ;
/

